insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2022-06-13','Hola, los pacientes Sebastián Paredes Dicha y Almudena Correyero Parejo van a realizar un viaje a Lourdes del 22 al 27 de Junio de 2022,por lo que han hecho un abono de 285 euros que corresponde a la cuantía del viaje. Al margen de este dinero, llevarán dinero de bolsillo para sus gastos personales. Gracias. Un saludo. Manuela Domínguez Flores. Trabajadora Social. Centro Sociosanitario "Adolfo Díaz Ambrona". Ctra. Valverde, km. 2. 06800 Mérida. Tel.: 924 38 80 81. Ext.: 24012','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-06-14','Ana: Envío correo a Toni-Futuex: "En relación a JESÚS MANUEL RAMOS BARGÓN, queríamos pediros que, en cuanto podáis, nos remitáis informe de los últimos seguimientos y, si notáis algo fuera de lo común o sus delirios más activos, por favor hacerlo constar en el mismo. No sabemos si estará descompensado, pero los últimos correos que él mismo ha remitido, nos hace pensar, que su patología está activa. Por cierto, en relación al último correo que te envié, sobre las quejas de la vecina de arriba, ¿habéis podido averiguar algo? Ya nos informáis también sobre este asunto. ..." ·························· Envío nuevo correo a Toni-Futuex: "En relación a la crema que le recetó el Médico de Atención Primaria a JESÚS MANUEL RAMOS BARGÓN, que no entra por la seguridad social, me plantean desde la sección económica la posibilidad de abonarla directamente a la farmacia mediante transferencia, en lugar de que él saque el efectivo para comprarla. ¿Podríais, por favor, mediar con la farmacia en la que la compra, para ver si lo aceptan y en tal caso, confirmar a dicha sección e informar a Jesús Manuel de la nueva forma de proceder?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-06-14','Ana: en relación al documento "Información en cumplimiento de la normativa de protección de datos personales" remitido ayer por Pilar, Res. de Mayores (pilarcortcer@gmail.com), le envío correo: "Buenos días Pilar, Según mi compañera Miguel, Asesor Jurídico de la CTAEX, en base a al nueva Ley 8/21, y a la propia sentencia de incapacitación parcial de Juan José, éste tiene capacidad para firmar por sí mismo el documento que nos remitís. Ante cualquier otra cuestión, no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-06-14','Ana: Reenvío a Miguel, Certificado de Residencia en el CRR, que nos remiten desde el centro. ········ Guardo también en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-06-14','Amalia , envio email a Aprosuba 3 : buenas ,el juicio ha ido bien . He conseguido el cdo. a través de las compañeras de discapacidad , el cdo. que le enviáis a ellas cuando ingresa el usuario. Te envio reconocimiento de PNC concedida , con parte de ese dinero se pagará la salida de vacaciones . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-06-14','Amalia , envio email a Aprosuba 3 : buenas ,el juicio ha ido bien . He conseguido el cdo. a través de las compañeras de discapacidad , el cdo. que le enviáis a ellas cuando ingresa el usuario. Te envio reconocimiento de PNC concedida , con parte de ese dinero se pagará la salida de vacaciones . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-06-14','Ana: Inés, Admvo. secc. jurídica, me comunica que el juicio de Juan Carlos se ha suspendido, puesto que no se ha podido nombrar abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-06-14','Ana: Correo de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): "Hola Ana, tenemos noticias sobre cómo se encuentra Aaron. Han informado a mi compañera que le han hecho analítica y han comprobado que el ácido valproico tenía que estar entre 50 y 100 y lo tiene a 58, entonces le han ajustado tratamiento y le realizarán otra analítica el jueves o viernes para ver si ha subido. Ha presentado alteración de conducta después de hablar con el padre el fin de semana y están observando cómo mejora con el nuevo tratamiento y a la espera de que aumente el ácido valproico. Te iremos informando"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-06-14','Ana: Llamada de Nuria, TS del EVD-Trujillo (54513): Ayer acudió a valorar a Valentina. Ha dado GRADO II. ········ Nos enviará las negociaciones PIA. Se aceptará Prestación Ecca. Vinculada al Servicio Residencial y Servicio de Plaza Residencial. Percibirá la primera hasta que pueda acceder a plaza pública. *Una vez firmado lo devolveré a la Gerencia de CC por SIREX. ·············· Conversación con Pilar, Directora Res. Logrosán: Tratamos la conveniencia de que Valentina tenga una pequeña asignación semanal para gastos de bolsillo. Y que para la compra de ropa, dada la ubicación de la localidad, y que sólo hay una tienda de ropa, nos enviarán un sólo presupuesto a tal fin. *La compra de flores anual para la tumba de sus padres también se autorizará mientras puede permitírselo. ········ Envío correo a Óscar, Secc. ecca.: "Cuando puedas, porfa, mira la situación económica de Valentina Fdez. Trejo. Me dicen la Directora del centro que actualmente no tiene asignación para gastos de bolsillo y sería bueno para ella asignarle una pequeña cuantía (3-4 € / semana). Para entregarle ésta, en lugar de retirada de efectivo en la sucursal, planteamos transferirla a la Residencia para que la directora se la administre. Ésta va a consultarlo, y si se lo permiten, nos pasarán los datos para hacerlo así. De momento, dime si sería factible. Por otra parte, comunicaros que próximamente variará su situación económica a mejor, pues ya han ido a valorarle de Dependencia y ha dado Grado II, con lo que le van a ofrecer Prestación Económica Vinculada al Servicio Residencial hasta que puedan darle plaza pública en la misma residencia (no queremos cambiarla a otra, mientras podamos evitarlo). Te voy diciendo." ··················· Respuesta de Óscar: "A nivel eco no habría problema. Tiene más de 28.000 € de ahorro, aunque si es cierto que últimamente tiene gastos de 600 € de fisio cada dos meses (total de 2400 €), cuando el presupuesto inicial era de 600 € únicamente." ·········· *Le indico que ha sido necesario ampliar tratamiento, pero que gracias a ello ha vuelto a caminar. *No obstante preguntaré a Pilar la previsión de duración del tratamiento de fisioterapia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-06-14','Ana: Llamada de Nuria, TS del EVD-Trujillo (54513): Ayer acudió a valorar a Valentina. Ha dado GRADO II. ········ Nos enviará las negociaciones PIA. Se aceptará Prestación Ecca. Vinculada al Servicio Residencial y Servicio de Plaza Residencial. Percibirá la primera hasta que pueda acceder a plaza pública. *Una vez firmado lo devolveré a la Gerencia de CC por SIREX. ·············· Conversación con Pilar, Directora Res. Logrosán (639 58 54 89): Tratamos la conveniencia de que Valentina tenga una pequeña asignación semanal para gastos de bolsillo. Y que para la compra de ropa, dada la ubicación de la localidad, y que sólo hay una tienda de ropa, nos enviarán un sólo presupuesto a tal fin. *La compra de flores anual para la tumba de sus padres también se autorizará mientras puede permitírselo. ········ Envío correo a Óscar, Secc. ecca.: "Cuando puedas, porfa, mira la situación económica de Valentina Fdez. Trejo. Me dicen la Directora del centro que actualmente no tiene asignación para gastos de bolsillo y sería bueno para ella asignarle una pequeña cuantía (3-4 € / semana). Para entregarle ésta, en lugar de retirada de efectivo en la sucursal, planteamos transferirla a la Residencia para que la directora se la administre. Ésta va a consultarlo, y si se lo permiten, nos pasarán los datos para hacerlo así. De momento, dime si sería factible. Por otra parte, comunicaros que próximamente variará su situación económica a mejor, pues ya han ido a valorarle de Dependencia y ha dado Grado II, con lo que le van a ofrecer Prestación Económica Vinculada al Servicio Residencial hasta que puedan darle plaza pública en la misma residencia (no queremos cambiarla a otra, mientras podamos evitarlo). Te voy diciendo." ··················· Respuesta de Óscar: "A nivel eco no habría problema. Tiene más de 28.000 € de ahorro, aunque si es cierto que últimamente tiene gastos de 600 € de fisio cada dos meses (total de 2400 €), cuando el presupuesto inicial era de 600 € únicamente." ·········· *Le indico que ha sido necesario ampliar tratamiento, pero que gracias a ello ha vuelto a caminar. *No obstante preguntaré a Pilar la previsión de duración del tratamiento de fisioterapia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-06-14','Ana: Correo de Toni-Futuex: "Notificación Agencia Tributaria: Contacta Felipe para comunicar que ha recibido una notificación certificada para recoger una carta en correos, ya le ocurrió la semana pasada, cuando se acudió a visitarlo y le devolvieron la carta para atrás por no haber ido a recogerla a tiempo, por lo que se le dice que vaya de forma urgente y, después, la auxiliar haga fotos y se las pase a la educadora. Así lo hace, al enviar las fotos (se adjuntan en documento aparte), se comprueba que es una nueva notificación de embargo por la relación con la empresa de Dependencia, parece ser que el asunto no quedé zanjado del todo... La auxiliar lleva la carta a su jefe y éste envía la documentación pertinente, según comunica, y establece que no es necesario dar parte a la CTAEX, se le dice que se tiene que comunicar pues son sus tutores y porque la vez anterior, cuando su jefe, comunicó a CTAEX que ya estaba todo solucionado, a la vista está que no ha sido así. Se adjunta también la diligencia facilitada por la empresa de Dependencia con la respuesta a dicha notificación." ············ Lo paso a Estrella, secc. ecca., y a Miguel, A. Jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-06-14','Ana: Llamada de Valentina, TS del CS Aldea Moret: Están notando a Abraham, hijo de Pilar, muy "alborotado" y con muchas quejas sobre el control que la CTAEx ejerce sobre el dinero de su madre. *"Manipula a la madre" y "quiere manejar su dinero". ···· Aparte se ha comprado un coche el 29 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-15','miguel, tras conversación ayer con servicios jurídicos de banca pueyo (Gregoria Rebanal del dpto jurídico 924 84 60 08 Ext 356) e intento sin éxito de comunicación telefónica con la abogada de la tutelada(Maria Nuria Ledo Barrado 924456714 617325223 email 1873@icaba.com), para que me informe, remito email a la parte social, Amalia y Maite: Buenos días, quedó pendiente que hablemos de este expediente que es urgente. Estuve hablando con los servicios jurídicos de banca Pueyo y me comentaron que las deudas que han dado lugar a la ejecución hipotecaria comenzaron en 2013 y el procedimiento de ejecución hipotecaria en 2014. Me comentaron desde servicios jurídicos del banco que ya han solicitado que pase a subasta el inmueble. Tanto Iciar como el banco me dicen que la vivienda no tiene buenas condiciones de habitabilidad. Por lo que me comenta Iciar como el banco ella no quiere abandonar el domicilio por lo que desde la parte social entiendo que deberíais plantearos una solicitud de internamiento involuntario que iniciemos lo antes posible. Le he comentado a la del banco que necesitamos tiempo para trasladar a esta señora a una residencia, y según me comenta no hay problema de que esperen unos meses para hacer uso de la vivienda. Comenta que los trámites para el desalojo pueden ser al menos hasta fin de año. Por tanto, si ella no quiere ir a algún centro, piso, etc que decidáis voluntariamente habría que solicitar internamiento involuntario para lo cual tenéis que facilitarnos, como siempre informes médicos y sociales de Justa Diaz, intentad agilizarlo para que no se nos eche el tiempo encima. Por otro lado intenté hablar con la abogada que representa a nuestra tutelada pero por ahora no lo he logrado. Cualquier duda la vemos. ****************************************************** Tras consultar al Colegio de abogados de Badajoz me indican posible email y el teléfono móvil. Envío email a la abogada Mª Nuria Ledo Barrado al email 1873@icaba.com Buenos días, nos han dado este email en el colegio de abogados de Badajoz, que nos indican que corresponde a Maria Nuria Ledo Barrado. Necesitamos se ponga en contacto con esta Comisión Tutelar de Adultos, en relación con el procedimiento arriba indicado para saber el estado del mismo y las opciones sobre el mismo, ya que su cliente Justa Diaz Borreguero está tutelada por esta Comisión Tutelar de Adultos, y cuyo acuerdo de aceptación del cargo se adjunta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-06-09','Maite: Ana y yo hemos visitado a Juan José en el centro de menores de Trujillo.Nos hemos reunido con él, su padre y una educadora. El padre tiene una actitud muy colaboradora y se implica en todo lo relacionado con Juan José. El verano lo pasará con su familia en Torrejón el Rubio. Desde el centro están viendo la posibilidad de que pueda asistir a un campamento alguna semana del verano. Desde el centro le daban 300€ para ayuda a su manutención en casa durante las vacaciones. Una vez consultado su saldo valoraremos la posibilidad de darle algo mas. Juan José permanecerá en el centro de menores hasta que se le adjudique plaza de residencia en centro de atención a personas con discapacidad. Solicitaremos plaza de Centro Ocupacional para que acuda hasta que pueda ir a residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2022-06-15','Hola Angel, te explico para que te vaya sonando. German Jose Montero Moreno, está en Cr Maria Jesús López Herrero ( Plasencia) En una cuenta en la que está solo el tutelado se están abonando gastos de vivienda en Plasencia, Av España 70 esc 4 0A. Al parecer el padre de German sigue en la vivienda, los padres se han separado y aun no se ha hecho la liquidación de la sociedades gananciales con el reparto y adjudicación del matrimonio. Hay un abogado tratando el tema, y por lo que me dicen, tu estabas con ello. Hemos decidido no dar de baja los suministros de esta vivienda, hasta que tú nos informes al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-15','Buenos días, quedó pendiente que hablemos de este expediente que es urgente. Estuve hablando con los servicios jurídicos de banca Pueyo y me comentaron que las deudas que han dado lugar a la ejecución hipotecaria comenzaron en 2013 y el procedimiento de ejecución hipotecaria en 2014. Me comentaron desde servicios jurídicos del banco que ya han solicitado que pase a subasta el inmueble. Tanto Iciar como el banco me dicen que la vivienda no tiene buenas condiciones de habitabilidad. Por lo que me comenta Iciar como el banco ella no quiere abandonar el domicilio por lo que desde la parte social entiendo que deberíais plantearos una solicitud de internamiento involuntario que iniciemos lo antes posible. Le he comentado a la del banco que necesitamos tiempo para trasladar a esta señora a una residencia, y según me comenta no hay problema de que esperen unos meses para hacer uso de la vivienda. Comenta que los trámites para el desalojo pueden ser al menos hasta fin de año. Por tanto, si ella no quiere ir a algún centro, piso, etc que decidáis voluntariamente habría que solicitar internamiento involuntario para lo cual tenéis que facilitarnos, como siempre informes médicos y sociales de Justa Diaz, intentad agilizarlo para que no se nos eche el tiempo encima. Por otro lado intenté hablar con la abogada que representa a nuestra tutelada pero por ahora no lo he logrado. Cualquier duda la vemos. Saludos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-15','Amalia : empiezo a gestionar con Futuex y SSASB alternativas residenciales ante el inminente desahucio. Buenos días , y calurosos , a ver si pasa ya la ola ésta . Te comento sobre Justa , te envío directamente email de nuestro asesor jurídico. La vivienda va a salir a subasta en breve . Ella en principio no quería ingreso en centro .. pero económicamente no veo otra posibilidad . Con su pensión tampoco podría pagar alquiler + gastos . Este nietísimo con el que convive entiendo que no podemos contar con él . No recuerdo cómo va el tema de dependencia de esta señora , se le ha pedido ?? si no lo miro en SIDEX . Si no tiene dependencia , lo tendría que solicitar por decreto y por emergencia social . Eso supone que la plaza es en cualquier sitio de la comunidad , no podemos elegir zona. Habría que plantearla la situación ,podéis leerle el email . Tiene unos meses para ir preparando la salida . Querría entrar voluntariamente ??? si no tendríamos que pedir Intern. involuntario. Necesitamos algunos informes médicos y del SSASB . He quedado para hablar con la TS dentro de unas horas , que no podía antes . Tenemos algún informe médico actual del ESM ?? tenía cita programada. La TS me comentó que tiene un hijo , a ver si puedo localizar su tf para comentarle la situación por si a nivel familiar tienen alguna alternativa. Seguimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-06-01','Ana: correo de Sonia Bernabé, TS/Directora Asindi: "Hola Ana, quería informarte que han dado el alta a Aarón Rosado. Regresa esta tarde con un pequeño ajuste en el tratamiento. Mañana la psicóloga valorará cómo se encuentra y se valora la posibilidad de que vaya a casa como está acostumbrado cada 15 días."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2022-06-01','Ana: Correo de Toni-Futuex al ctutelar con copia a mí: "Área económica (facturas ropa pendientes de pago): En lo relativo a la gestión encomendada para esta tutelada, se solicita se pueda abonar a la tienda Confecciones la Torre, la cantidad, para retirar la ropa. Y que se abone tambien, por favor, en la tienda Tara, que aunque nos permiten retiras las prendas sin pagar, está también pendiente de pago. Se acude a la tienda de TARA, comercio en el que se compra habitualmente para otros tutelados/as y facilita mucho el proceso; ahí se cogen las camisetas de exterior y los pantalones, prendas que proporcionan y no tienen problema en que se retiren de la tienda sin que hayan recibido el pago (se adjunta factura en documento a parte). Para la ropa interior y los camisones, los cuales al solicitar de tipo hospital cuesta mucho encontrar y más para talla pequeña, se acaba acudiendo a una tienda a la que no se había ido nunca, aunque aceptan el pago por transferencia y el modo de proceder, establecen que al no conocer a la persona que acude y no haberlo hecho previamente, no pueden facilitar los enseres hasta que no se reciba el pago o, en su defecto, se les haga llegar el justificante de haber realizado la transferencia. Se adjunta en documento a parte también." ········ Lourdes, secc. ecca. se encarga del abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-05-31','Ana: correo de Sonia, Asindi (trabajosocial@asindi.e.telefonica.net): "Aaron Rosado, continua ingresado. Le van a hacer analítica para comprobar que el nivel en sangre de algunos medicamentos es el adecuado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-06-15','Ana: Llamada de Marisa, TS ESM-Coria (70841): Han concedido plaza a Julia, en el CRR-Plas. Ya se lo ha comunicado ella a Julia y ésta se ha puesto contentísima. ·············· Informo a Toni-Futuex, para que Gloria le ayude a prepararse. ······ Llamo a Blanca, Directora del CRR (673 225 527) para preguntar acerca de la entrevista previa y posible fecha de ingreso, pero no obtengo respuesta. ··········· Envío correo a Blanca (direccion.crrplasencia@grupo5.net) y Carolina, Psicóloga CRR (psicologia.crrplasencia@grupo5.net): "...os escribo por aquí para preguntaros por la entrevista que soléis realizar con carácter previo al ingreso en vuestro centro, relativa a JULIA MORÓN HERNÁNDEZ, ya que nos han comunicado que se ha movido la lista de espera y le conceden plaza en vuestro centro. No sé si la realizaréis por videollamada o si será presencial y para qué fecha lo tenéis previsto. Ya me decís cuando podáis. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-06-15','Ana: Recibo correo-e de Modesto, Res. Casas de Don Antonio (administracion@centrodemayoressierradesanpedro.es): "Feliciano Borreguero Cambero está bastante más malino, y no sabemos que debemos hacer en caso de fallecimiento. Llámanos cuando puedas por favor." ············· Llamo a Modesto y le informo del modo de proceder. ···· Le remito al correo la póliza del seguro de decesos de Santa Lucía.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-06-15','Ana: Recibo correo-e de Modesto, Res. Casas de Don Antonio (administracion@centrodemayoressierradesanpedro.es): "Feliciano Borreguero Cambero está bastante más malino, y no sabemos que debemos hacer en caso de fallecimiento. Llámanos cuando puedas por favor." ············· Llamo a Modesto y le informo del modo de proceder. ···· Le remito al correo la póliza del seguro de decesos de Santa Lucía. ·························································· Hablo con la enfermera de la residencia, me explica que ha empeorado mucho en cuestión de 2 días, los ha pasado con muchos temblores y fiebre, no saben si está relacionado con el aneurisma cerebral. El médico le ha subido la medicación. Está muy delicado. *Lo sorprendente es lo bien que ha estado los meses anteriores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-06-15','miguel, me llaman del juzgado Datos identificativos: El juzgado de lo Penal de Plasencia, procedimiento Ejecutoria 268/22 (Guadalupe 927-427-341), envío email con lo que me piden a Soraya, Maite y Ana: Buenos días, me acaban de llamar del juzgado indicándome que les urge les mandemos un certificado del centro indicando si allí se puede cumplir la condena. También tiene que recoger ese certificado del centro donde se encuentra la fecha y la causa por la que ingresó y desde cuándo, ya que si el motivo fue a raíz del procedimiento por el que se le ha condenado, se le restaría de la condena que le queda pendiente. Cualquier duda decídmelo. Hay que intentar que esté contestado antes de finalizar la semana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-06-15','Ana: envío un correo a Rosa Bravo, CSS-Plas.: "En relación a CIPRIANO MIGUEL BAZAGA, me pide mi compañero Miguel, Asesor Jurídico, que nos remitáis cuando os sea posible, Certificado de Ingreso en vuestro centro, pues lo requiere para remitirlo al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-06-15','-Amalia , contrato con Hostal Ana en Merida otra salida terapéutica en el mismo hostal que el mes pasado .Noche + desayuno 36,5 Tf hostal 924311113 ( Tania)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-06-15','-Amalia, envio email a CRR . os paso los datos del hostal donde se le han reservado 3 noches con desayuno . Es el mismo que el de la última vez , que ya lo conoce . He hablado con ella y la veo muy bloqueada y muy nerviosa. Hostal Ana en Mérida Tf hostal 924311113 ( Tania','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-06-15','Ana: Pilar Cerrillo, TS Grupo Ciudad Jardín, nos remite resolución municipal, han regularizado el precio de la plaza en relacion a la subida del IPC (desde 2016, fecha a la que corresponde el precio que tenía cuando ingresó). A partir de este 2022 tiene que abonar 784,46€/mes, por lo que desde enero le corresponde pagar la diferencia = 1437,10€ en total. ······················· Óscar, secc. ecca., que informa que tiene que abonar a Hacienda, por el ejercicio del IRPF 2021, más de 2.000€. ··················· Hablo con Ángel, Asesor Jurídico: Insistirá en la solicitud de abogado de oficio, en relación a la pensión de alimentos que continúa pasando a los hijos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-06-15','-Amalia, envio email a CRR . os paso los datos del hostal donde se le han reservado 3 noches con desayuno . Es el mismo que el de la última vez , que ya lo conoce . He hablado con ella y la veo muy bloqueada y muy nerviosa. Hostal Ana en Mérida Tf hostal 924311113 ( Tania','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2022-06-15','Email de Angel : Buenos días, En catastro, nuestro tutelado no tiene ninguna propiedad inscrita a su nombre. He pedido Nota Simple al Registro de la Propiedad, en cuanto la tenga os digo. Os cuento del caso. Los padres de Germán José se separaron judicialmente. En la sentencia se acordó la atribución limitada y temporal de la que fuera vivienda familiar, sita en Avda. de España, 70-3º-A, de Plasencia al padre, hasta que se procediera a la liquidación de la sociedad de gananciales, que hasta la fecha, que yo sepa, aún no se ha producido. En aquel proceso, había varias cuentas: Liberbank 20481001993000061417, titulares, el padre, la madre, nuestro tutelado, nosotros y un sobrino como apoderado. En esta cuenta también se cargaban los gastos de la vivienda. ES1920481001943900130188, titulares, la madre (aquí cobra la pensión), el tutelado (aquí cobra su pensión), nosotros y el sobrino apoderado. Desde la cuenta 1 a la 2, la madre traspasaron 115.000 euros, según ella, era un dinero que sus abuelos le dieron como donación. De las dos cuentas que os comento, ¿en cuál se están cargando los gastos de la vivienda? ¿Las abona nuestro tutelado? Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2022-06-15','Angel : En catastro, nuestro tutelado no tiene ninguna propiedad inscrita a su nombre. He pedido Nota Simple al Registro de la Propiedad, en cuanto la tenga os digo. Os cuento del caso. Los padres de Germán José se separaron judicialmente. En la sentencia se acordó la atribución limitada y temporal de la que fuera vivienda familiar, sita en Avda. de España, 70-3º-A, de Plasencia al padre, hasta que se procediera a la liquidación de la sociedad de gananciales, que hasta la fecha, que yo sepa, aún no se ha producido. En aquel proceso, había varias cuentas: Liberbank 20481001993000061417, titulares, el padre, la madre, nuestro tutelado, nosotros y un sobrino como apoderado. En esta cuenta también se cargaban los gastos de la vivienda. ES1920481001943900130188, titulares, la madre (aquí cobra la pensión), el tutelado (aquí cobra su pensión), nosotros y el sobrino apoderado. Desde la cuenta 1 a la 2, la madre traspasaron 115.000 euros, según ella, era un dinero que sus abuelos le dieron como donación. De las dos cuentas que os comento, ¿en cuál se están cargando los gastos de la vivienda? ¿Las abona nuestro tutelado? Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-15','-Amalia : pido a Sole informes médicos que nos solicita el juzgado para revision de sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-06-10','Ana: Paso a Julio, oficio con Anexo de elección de pensión solicitada: PNC, para remitirlo por SIREX al SS.TT. de Sanidad y Servicios Sociales de CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-06-15','Ana: Envío correo a Felipe, Ed. CAM Trujillo (cam.franciscopizarro@salud-juntaex.es): "Buenas tardes Felipe, ¿qué tal? Tan sólo confirmaros, por si se lo queréis comunicar vosotros a Eloy, que finalmente se le hará una transferencia de 400€ en concepto de manutención durante los meses de verano que pasará en su domicilio familiar más los 68,10 € correspondientes al tique de la cena de graduación. Ante cualquier cuestión, seguimos en contacto. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-15','miguel, recibo email de Rocio Gracian (Abogada de Damian rociogracian_@hotmail.com> 607650498 - 952600772 para el desahucio del piso de Málaga Hoy se ha celebrado el juicio de Damián y tengo malas noticias. Como recordarás, en el correo que te envié el día 24/3/2021 te decía que era necesario que vosotros solicitarais la autorización judicial para interponer el procedimiento de desahucio en base al art. 217 de la LEC , al que me respondisteis que al ser una curatela y no una tutela no hacía falta, incluso recuerdo que por teléfono me decíais también que en otros casos no os lo habían exigido. Pues bien, hoy lo ha alegado la parte demandada en el juicio y la jueza se ha admitido la alegación con lo cual el procedimiento queda SUSPENDIDO HASTA OBTENER LA AUTORIZACION JUDICIAL. Como también os indiqué en ese correo, el Juzgado competente para conceder la autorización judicial es el del domicilio donde está residiendo Damián, así que tenéis que tramitarla allí. Son de aplicación los Arts. 61 y ss. de la Ley de Jurisdicción Voluntaria 15/2015 de 2 de junio. No hace falta Abogado ni Procurador porque la cuantía del procedimiento es inferior a 6.000 euros. Eso hay que hacerlo ya, de forma inmediata, porque hasta que no lo tengamos el desahucio queda suspendido. Por favor, hablad con vuestros asesores jurídicos y si hace falta por que tengan mucho trabajo os envío yo la demanda para que la presentéis inmediatamente . Todo esto hay que hablarlo con Damián, que está muy nervioso con el tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-16','miguel, contesto a la abogada Rocio Gracian: Buenos días Rocío, no entiendo en base a qué, pues la sentencia de incapacitación de Damián no establecía que fuera necesario la aplicación del antiguo artículo 271 CC. Debido a la imposibilidad de ponernos a ello con la inmediatez que nos indicas, porfavor, envíanos tú la demanda e indicame si es necesario acompañarlo de algún poder o basta la firma electrónica del representante de la Comisión Tutelar de Adultos, Vicepresidente ( y con funciones delegadas del Presidente (Consejero de la Junta)) Si necesitas que te llame dimelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-06-16','Ana: Correo de Carolina, Psicóloga, ayer por la tarde: "Hemos contactado hoy con ella y la hemos citado para el lunes 20 a las 10.00 de la mañana realizar la entrevista presencial, si todo va bien y ella quiere venir a vivir al CRR ese mismo día fijaríamos la fecha de entrada." ··············· Lo comunico a Toni-Futuex, para proponer que Gloria le acompañe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-06-16','Ana: Envío correo a Blanca, Directora (direccion.crrplasencia@grupo5.net) y Carolina, Psicóloga (psicologia.crrplasencia@grupo5.net) del CRR: "Buenos días, a las dos, Hemos recibido un par de correos electrónicos de Isabel Cano, entendemos que ha regresado al CRR, pero nadie nos ha comunicado nada, ¿podríais confirmárnoslo?" ····························· Respuesta de Blanca, Directora: "Si, siento no haberos informado. Volvió el lunes, tras coodinación con psiquiatra de referencia para que estuviera unos días en la UHB." ··························································· Llamada de Isabel (649 642 635), pregunta si le podemos dar ya a su madre los 700€ para que se vaya a vivir a Plasencia. Le explico que actualmente no es posible, pues la idea que tenían era irse a vivir los dos (madre y pareja) a Plasencia y teniendo en cuenta lo ocurrido desde aquí no se va a facilitar. ··· Me comunica que a la pareja de su madre le ha llegado ya la carta del Jdo.; tiene que declarar en Trujillo el día 5/07/22. ························································ Se autoriza visita de Francisca, madre de Isabel el próximo fin de semana, dada la subida de precio del combustible, se conceden 25€ a tal fin (Se encarga Óscar, secc. ecca.) ······· Llamo a Francisca (639 019 336), se le comunica que el Plan de Visitas al CRR que se establece, para ver a Isabel, tendrá carácter quincenal, se le hará transferencia una semana sí una no. Se muestra conforme. Le informo también de las otras cuestiones tratadas con Isabel. ······································································································································ Envío nuevo correo al CRR (Carolina y Blanca): "teníamos pendiente confirmar el PLAN DE VISITAS de la madre de Isabel. Desde el Gabinete Técnico de la CTAEX, acordamos que las visitas tendrán carácter quincenal. De modo que se le hará una transferencia cada dos semanas, para que vaya a visitarla fines de semana alternos. Ya lo se lo he comunicado a las dos y ambas se muestran conforme."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-06-08','Ana: Llamada de Sonia, TS del C. Penitenciario CC (927 18 14 07): El cargo está recién aceptado, de hecho esta misma mañana Julio, Aux. Admtvo. ha enviado los oficios solicitando documentación a las distintas instituciones/recursos. ········ La madre se llama Julia Luján Álvarez (924 62 65 57). Reside en Siruela (Badajoz). Ella es quién hace el ingreso en cuenta peculio. ··········· El pasado fin de semana Sergio salió de permiso 3 días, con el apoyo de la PASTORAL PENITENCIARIA (son personas voluntarias las que realizan la labor). No hacen control sobre ellos, pero sí les acogen 3 días, comen con ellos y les brindan otros apoyos. **El tercer día, el lunes, Sergio fue al banco y retiró 1.000€ que se gastó en máquinas tragaperras y creen que en prostíbulos. ········· Tiene otro permiso concedido para el día 24 de junio, otros 3 días. **La fecha de excarcelación es el 7/01/2023. *Sonia dice que tiene asumido que se tiene que ir a un centro. *Tiene reconocido un grado del 51% de Discapacidad por el CADEX. Con diagnóstico de - Trastorno Mixto de la Personalidad, - Epilepsia, - Ludopatía y - Consumo de Tóxicos, aunque parece que lleva años sin consumir. ··············· *Hay que intentar bloquear su cuenta ante de la salida del 24. ····························· Llamo a la madre sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NELSON JOSE'and edp.apellido1='CAMPOS'and apellido2='DIAZ'),'2022-06-16','Amalia . escribo email a CSS Buenos días , Nelson mantiene la incapacitación parcial que tenía fijada . Te adjunto documento 1 . No se ha producido revisión de sentencia por el juzgado. La derivación a otras unidades o externalización ha de ser motivada por motivos clínicos exclusivamente , la Comisión Tutelar no tiene competencias ni capacidad para determinar estas decisiones . En el último informe social emitido por la Trabajadora Social de ese centro , se mencionaba justamente lo contrario , que no se valoraba derivación. Documento 2. A tener en cuenta además de su estado clínico , su inexistencia red social y familiar de apoyo , consumo de drogas y sus ingresos económicos ( percibe PNC de 421€ /mes). Un saludo ------------------------------------------------ email desde CSS : Me comentan las compañeras que este paciente desea el alta voluntaria. Entendemos que, al carecer de red de apoyo, no sería fácil. El equipo de valoración del centro determinaría si, antes de salir al exterior, ingresaría en URH o en la Vivienda Supervisada. También cabría la posibilidad de derivarle en un futuro a un CRR. Ya te digo, siempre y cuando, el equipo de valoración lo considere oportuno. No sé si en la actualidad continúa con la incapacitación legal o si ya se ha iniciado el proceso para la curatela. ¿Qué me puedes decir? ¿Crees que la Comisión Tutelar de Adultos estaría de acuerdo con que el paciente fuese derivado a otras unidades y que en un futuro se le pudiera solicitar plaza pública en CRR? Hasta ahora. M.ª Ángeles Galindo Barrena. Trabajadora Social. ​Centro Sociosanitario de Mérida Ctra. de Valverde Km. 2. 06800 Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-06-16','Ana: Llamada conjunta (Miguel, Estrella y yo) a Carmen, empresa FERNANDO BRAVO CALVO (622 72 41 78), actualmente "Servicios Asistenciales": El cargo del 23/03/22 a nombre de Fernando Bravo, ha debido ser un error bancario. El resto de mensualidades, que pasan a mes vencido, los están pasando a nombre de la nueva empresa ya. ········· Carmen nos enviarán todas las facturas de este año y continuará haciéndolo a partir de ahora todos los meses. ············· Cuando las tengamos, Miguel se encargará de contestar a la Agencia Tributaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-06-16','Ana: Llamo a Julia, madre de Sergio (924 62 65 57): Facilita el nº de cuenta de su hijo, como titulares están los dos. se lo paso a Icíar, sección ecca. ··················· En relación al fin de semana que salió de permiso, me informa además de sacar y gastarse 1.000€, tuvo un Incidente con una chica, pero no ha querido poner denuncia. *Es un problema que se han encontrado muchas veces, que la gente no quiere denunciar. Expresa también que su hijo tiene autocontrol. Llevan con estos problemas de falta de control de impulsos desde los 7 años. ················ La TS de Siruela, envió Informe Social a Fiscalía. ·········· Cree que su hijo necesita estar en Centro. ·········· Se muestra muy colaboradora. Pero no quiere que Sergio lo sepa, pues luego manipula y éste ahora piensa que no puede contar con ella. Cree que la única forma en que puede ayudar es de esta manera. *Rompe a llorar, se nota es una emoción sincera de impotencia y sufrimiento. Ya no puede más. ·············· Sergio estuvo 8 años en la Casa de la Misericordia de Alcuéscar. Cuando se marchó después estuvo en el Centro de Personas sin hogar de Caritas de CC. ········· Aquí, un tiempo después, valoraron que estaba mejor, y aunque volvían a aceptarlo en Alcuéscar, Mamen, la TS de Cáritas consideró que no necesitaba ya este recurso con lo que había evolucionado y así se lo hizo saber a él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2022-06-16','.Email de Angel : buenos días, Germán José tampoco tiene propiedades inscritas a su nombre en el Registro de la Propiedad. Por tanto, tal y como os comentaba en el anterior correo, todos los gastos relacionados con el inmueble donde vive el padre, deben ser abonados por éste y no por nuestro tutelado. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2022-06-16','TERESA . Los gatos semanales que tiene son: tabaco y algo de dinero de bolsillo para tomar un refresco o para cualquier gasto pequeño que le surgiera. Tiene que recargar el móvil con 10€ mensuales de la compañía Symio y poco más. Por lo que se podría establecer una cantidad de unos 25€ semanales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-06-16','INFORMACIÓN: EN SU CCC HABITUAL NO DISPONE APENAS DE SALDO. EN LA CCC QUE ELLA NO CONOCE AÚN DISPONEMOS DE ALGO MÁS DE 19.019 €....DE ESTE DINERO ES DE LO QUE VAMOS TIRANDO CUANDO NO QUEDA SALDO EN SU CCC. LOS PROBLEMAS DERIVAN BÁSICAMENT DEL DESCONTROL CON LA LUZ.. REINTEGROS...MUY POCO...BÁSICAMENTE 50 €/MES CON RECARGA MÓVIL OS RECUERDO QUE, INICIALMENTE, IBAMOS A INTENTAR ARREGLARLE LA BOCA (AUNQUE ELLA NO RECLAMA ESTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-06-16','Maite: Reunión: MARÍA TERESA GÓMEZ MARTÍN, ANA MATAMOROS GÓMEZ, ÁNGEL MARÍN MARTÍNEZ, ALBERTO MARTÍN ROSETE. REUNIÓN SOBRE SITUACIÓN DE TUTELADO MATEO RUANO MORENO. SE DECIDE: • DEJAR DE ABONAR LA TRANSFERENCIA PERMANENTE DE 100 € PARA CANCELACIÓN DEUDA PENDIENTE CON RESIDENCIA VIRGEN DE LA MONTAÑA DE CASAR DE CÁCERES. o ANA SE LO CUMUNICARÁ AL CENTRO, ASÍ COMO QUE SE REAUNDARÁ EL PAGO DE LA DEUDA, EN CUENTO LA SITUACIÓN ECONÓMICA DEL TUTELADO LO PERMITA. • CONTINUAR ABONANDO LA NUEVA CUOTA DEL CENTRO DE RESIDENCIA DEL TUTELADO, RESIDENCIA AMADA CORRAL DE ALCUESCAR, X IMPORTE DE 784,46 €/MES. o ANA SE ENCARGARÁ DE COMUNICAR A CENTRO QUE DEBEN DE MINORAR AL MÁXIMO LOS GASTOS DEL TUTELADO EN EL CENTRO. ACTUALMENTE LA MEDIA MENSUAL ES DE 90 €/MES. • CON RESPECTO A LA NUEVA DEUDA CON RESIDENCIA AMADA CORRAL DE ALCUESCAR, X IMPORTE DE 1.429,77 €, SE COMUNICARÁ AL CENTRO QUE NO SE PODRÁ ABONAR LA MISMA DADA LA SITUACIÓN ECONÓMICA ACTUAL DEL TUTELADO. o ANA SE LO COMUNICARÁ AL CENTRO, ASÍ COMO QUE SE PROCEDERÁ AL PAGO DE LA MISMA, EN CUANTO LA SITUACIÓN ECONÓMICA DEL TUTELADO LO PERMITA. • ÁNGEL INFORMA DE QUE SE HA DENEGADO ABOGADO DE OFICIO Y POR TANTO: o BUSCARÁ PRESUPUESTOS DE ABOGADOS VÍA PRIVADA. DESDE UN PUNTO DE VISTA ECONÓMICO EL ABOGADO QUE PUDIERA HACERSE CARGO DE ESTA CUESTIÓN DEBE TENER CLARO QUE EL COBRO X SUS SERVICIOS PODRÍA DILATARSE MUCHO EN EL TIEMPO. • CON RESPECTO A LA DEUDA DE 2.222,38 € CON HACIENDA, VAMOS A REMITIR DOCUMENTACIÓN SOBRE SENTENCIA INDEMNIZACIÓN TUTELADO QUE AFECTA A SU PENSIÓN, A LA GESTORÍA ENCARGADA DE HACER EL IRPF PARA INTENTAR CONSEGUIR QUE SE DESGRAVE LA MISMA. o ÁNGEL LE REMITIRÁ A OSCAR DICHA SENTENCIA, ASÍ COMO CUALQUIER DOCUMENTACIÓN ANEXA QUE PUEDA TENER RELEVANCIA PARA HACIENDA. o OSCAR REMITIRÁ LA DOCUMENTACIÓN Y MANTENDRÁ EL CONTACTO CON LA ASESORÍA. ········································································································································ Llamo a Pilar Cerrillo: le explico como está la situación económica. *Ella está indignada con el Ayto. pues ha comenzado a reclamar ahora porque han perdido una subvención, gracias a la cuál la cuota era más baja. ············· Hablará con Daniel, su coordinador y pondrá de nuevo en contacto conmigo. ······························································································································································································· En la Asesoría informan a Óscar, secc. ecca., que "la pensión es de alimentos no se la puede desgravar en la declaración de IRPF. Si fuera compensatoria, si podría."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-06-16','INFORMACIÓN: EN SU CCC HABITUAL NO DISPONE APENAS DE SALDO. EN LA CCC QUE ELLA NO CONOCE AÚN DISPONEMOS DE ALGO MÁS DE 19.019 €....DE ESTE DINERO ES DE LO QUE VAMOS TIRANDO CUANDO NO QUEDA SALDO EN SU CCC. LOS PROBLEMAS DERIVAN BÁSICAMENT DEL DESCONTROL CON LA LUZ.. REINTEGROS...MUY POCO...BÁSICAMENTE 50 €/MES CON RECARGA MÓVIL OS RECUERDO QUE, INICIALMENTE, IBAMOS A INTENTAR ARREGLARLE LA BOCA (AUNQUE ELLA NO RECLAMA ESTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-16','Buenas! que tal? Te paso información obtenida hasta el momento, con esta tutela en función de lo que preguntabas. En primer lugar, referente al ingreso en centro, la tutelada no es una opción que contemple, las veces que se ha abordado dicha cuestión se niega rotundamente. Por lo que a día de hoy tendría que ser internamiento involuntario. No obstante como el viernes se la vuelve a ver, se volveria a indicar, debido a la irreversibilidad de la ejecución hipotecaria. Es cierto que no se le ha planteado la situación ni circunstancias actuales referentes a su vivienda y la subasta en breve del inmueble. Esto podría provocar un cambio en su actitud y originar su colaboración.Ojalá! En cuanto al tema de dependencia, aun no se le había solicitado, por ello, se retomó las consultas médicas y así poder obtener informes médicos. Próxima cita médico familia este viernes 17 de junio 22. Intentaremos mañana que la médico pueda rellenar el informe de salud , ya que en las consultas anteriores decia que no tenia información suficiente, pq no acudia nunca por alli. Además, se le solicitó cita preferente en salud mental, en la próxima consulta del 17 volveremos a preguntar sobre ello. En segundo lugar, el nieto con el que convive no colabora económicamente en nada relacionado con la vivienda y la manutención. Trabaja esporádicamente en el campo y a pesar que indica que la relación ha mejorado, la relación entre ambos no es buena. Ni creemos que vaya a colaborar ahora, incluso en esta nueva situación. Justa tiene tres hijos pero solo tiene relación con dos. De los cuales nos ha facilitado los números de teléfono: - Alonso Ramón Díaz 681 188 756 - Jorge Ramón Díaz 634 746 174 Finalmente, como se menciona anteriormente, el próximo viernes 17 de junio tiene consulta médica a la cual se realizará mediante acompañamiento y se abordará: - Ingreso voluntario en centro debido a su situación urgente referente a la vivienda. - Informes médicos solicitud dependencia. - Estado de solicitud revisión en ESM','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-16','-Amalia : hablo por tf con M. Angeles , TS del SSASB . Enviará I.S. para dar a Miguel para la solicitud de internamiento involuntario. Su email es : ssbase.montijo@salud-juntaex.es Hablo con su hijo Ramón ( abogado , actualmente reside en Madrid ) para comentarle lo de la vivienda y preguntar qué tipo de relación tiene con la madre y si tiene alguna alternativa residencial para ella . No quiere saber nada de la madre , ya sabía lo de la vivienda . Quedo pte. informes médicos pedidos a Futuex y todo se lo envio a Miguel para pedir Internam. Involuntario. El viernes irá Futuex a visitarla , por si cambia de opinión y voluntariament quiere ingresar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-16','-Amalia : hablo por tf con M. Angeles , TS del SSASB . Enviará I.S. para dar a Miguel para la solicitud de internamiento involuntario. Su email es : ssbase.montijo@salud-juntaex.es Hablo con su hijo Ramón ( abogado , actualmente reside en Madrid ) para comentarle lo de la vivienda y preguntar qué tipo de relación tiene con la madre y si tiene alguna alternativa residencial para ella . No quiere saber nada de la madre , ya sabía lo de la vivienda . Quedo pte. informes médicos pedidos a Futuex y todo se lo envio a Miguel para pedir Internam. Involuntario. El viernes irá Futuex a visitarla , por si cambia de opinión y voluntariament quiere ingresar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-16','Buenas tardes, Amalia. Fue como esperábamos. Miguel estuvo asistido por un abogado de oficio. Tuvimos que esperar mucho tiempo hasta que llegara, reconoció los hechos. Entramos con él cuando se le tomó declaración. La Jueza no va a dictar la orden de alejamiento que solicitaba el abogado de la compañera que interpuso la denuncia pero supongo que dictará medidas para con él . Estamos a la espera. No nos dieron copia de su declaración. Con respecto a los informes médicos, veré los que tenemos. Estamos con bastante trabajo y hay compañeros con COVID. Acabo de terminar una valoración de de dependencia que han realizado en el Centro. Cuando pueda te envío los que tengamos. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-06-16','Ana: Recibimos Resolución de la D.G. SS.SS. Infancia y Familia: Dado que le han concedido la P. Orfandad = 348 € con fecha de efecto: 1/02/22 (se la tramitó la hermana y no nos ha llegado resolución) no le corresponde la PNC completa. Se le reduce a 262,32 €. Y le reclaman el cobro indebido de 636,32€ desde el 1/2/22 hasta 31/5/22. ··················································································· Llamo a Toni; Jefa Secc. - P. Orfandad - INSS (927 62 00 56): La base reguladora del padre era alta y por tanto sí le le corresponde esa cuantía por la P. Orfandad Simple. **Me enviará a mi correo la resolución de la P. Orfandad. ············ *Lo guardo en su expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-17','Amalia : escribo email a Angel , CTAEX : Buenos días , adjunto los informes médicos que solicita el juzgado para la revisión de sentencia. Tras la agresión cometida por Miguel en el centro contra una cuidadora , expresa su deseo de que sea su hermana Gema la que asuma su tutela . Por si consideras comunicarlo al juzgado y que resuelva al respecto . Nosotros no nos oponemos a su voluntad . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-17','Amalia : escribo email a Angel , CTAEX : Buenos días , adjunto los informes médicos que solicita el juzgado para la revisión de sentencia. Tras la agresión cometida por Miguel en el centro contra una cuidadora , expresa su deseo de que sea su hermana Gema la que asuma su tutela . Por si consideras comunicarlo al juzgado y que resuelva al respecto . Nosotros no nos oponemos a su voluntad . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-06-17','Amalia : respondo a la consulta de la TS acerca de servicios funerarios llegado el día al no tener seguro decesos. Buenos días , a día de hoy tiene ahorros suficientes . Si fallece tenéis que avisar a una funeraria , solicitando un entierro digno y económico. No habría traslado porque entiendo se enterraría en Cáceres . El primer día hábil posible si ocurriese en fin de semana tenéis que comunicarlo a la Comisión. El caso ya ha pasado en seguimiento a la zona de Ana , es la T.S. que lleva la zona de Cáceres. Su tf es 924930245 Y el de la jefa de sección , Mayte 924006057. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-17','Amalia : ha vuelto a amenazar a otra cuidadora , con hacerle lo mismo que le ha hecho a la anterior ( le ha tirado una piedra )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-06-17','Ana: Icíar me solicita que intente conseguir copia del DNI, para poder hacer los trámites con el banco. ·········· Escribo a Sonia, TS C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es): "En relación a Sergio Solanilla Luján, ¿podríais facilitarnos copia del DNI? Aún no tenemos nada en el expediente y mis compañeros de la sección económica lo necesitan para poder solicitar al banco el bloqueo de la cuenta. Decirte también, que la entidades bancaria es una de las “menos colaboradoras”, te iremos informando."','2');
