insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-06-17','OSCAR: PROCEDEMOS A DEVOLUCIÓN DE LOS SIGUIENTES RECIBOS, ASÍ COMO A SOLICITAR QUE NO SE ADMITAN NUEVAS DOMICILIACIONES. LEGÁLITAS. MAPFRE. MOVISTAR. PROSEGUR. TE ADJUINTO DOCUMENTOS.','2');
