insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-06-17','Ana: Llamo a Daniel Núñez, Coordinador de todas las Residencias del Grupo Ciudad Jardín (605 37 01 54): La semana que viene tendrá una reunión con el Ayto. de Alcuéscar. El SEPAD le ha retirado la subvención porque los PP.TT. no cumplen los requisitos exigidos. *El Ayto. está poniendo los medios para subsanar las deficiencias (obras de adecuación). *Pide que no hagamos nada de momento, con respecto a los pagos y a la transferencia de 100€ acordada. Me llamará para informar de los acuerdos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2022-06-17','Ana: Recibo llamada de Carmen (633 61 61 67): se irá de excursión con el CRR un día a Jaraíz de la Vera y el día 20 a a pasar tres días a Malpartida de CC para estar con sus hijos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2022-06-17','Amalia , escribo a : merida.negextra@policia.es Buenos días , desde la Comisión Tutelar queremos solicitar cita e información para renovar el permiso de residencia y el pasaporte de una señora tutelada por la Junta de Extremadura , Dña. Vera Lucia Da Conceicao Bezerra. Se encuentra ingresada en el Centro Socio-sanitario de Mérida desde hace años , con una enfermedad mental y física grave , que la hace dependiente para Actividades de la Vida Diaria. Es brasileña de origen , mantuvo una relación con un señor español con el que no se llegó a casar pero con el que tuvo un hijo , actualmente menor de edad. Se adjunta documentación sobre su situación jurídica y socio sanitaria . Un saludo . Amalia Díaz Trabajadora Social de Comisión Tutelar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2022-06-17','CONTACTO DE MARLI ( AMIGA ) tf. 654020512 marli_brasil75@hotmail.com Contacto con ella , me comenta que Vera no puede volver a Brasil , no tiene contacto con su familia de origen desde hace años. Su familia era muy pobre , su madre muy mayor , es posible que haya fallecido. Sin relacion con sus hermanos. Vera tiene 2 hijas mayores , pero sin vínculos con ellas. En Brasil quedaría en la calle. No se llegó a casar con el padre de su hijo en España , en Brasil está divorciada. Tiene alguna pequeña propiedad , que el padre del niño quiso vender.','2');
