insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-16','Ana: Correo de Toni-Futuex, con información de los últimos seguimientos (guardo en el expdte.): Saturnino y dispone de nueva tarjeta de teléfono: 689 937 787. ······ Está más tranquilo que la semana anterior en CC. ············ Dice no estar consumiendo alcohol ni otras sustancias. Recibe el apoyo de su primo Miguel, quien regenta el Mesón de su calle. El día 14/06, tras gestiones por parte de la educadora, acudió a cita al ESM con la Dra. Cristina Donoso; la consulta se basa en una entrevista inicial donde le pregunta por los antecedentes y la situación actual, niño responde a todas las cuestiones sin alteraciones visibles, manifiesta está tomando el tratamiento desde el pasado viernes que acudió al CS de Alcuéscar para que se le activara la medicación en la receta electrónica, la doctora decide mantener la pauta de tratamiento y lo citará en 2 meses. ··················· La vivienda presenta carencias, si se hace una adecuada limpieza y se dan de alta los suministros de luz y agua, podría servir. *Según Saturnino los hermanos están haciendo gestiones para dar de alta los suministros. ······························································································································································································· Según informan desde la secc. ecca., sigue retirando efectivo del banco a diario sin autorización.','2');
