insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-06-17','Ana: Tras recibir correo de Futuex (guardado en el expdte.), envío correo a Alberto, Jefe secc. ecca.: "Buenas Alberto, Te reenvío correo de Futuex, subrayo en amarillo lo relativo a la farmacia y al consumo de la crema para tratar la erupción cutánea. Nos facilitan datos de la farmacia para abonarlo mediante transferencia. Desde la sección ecca. os podéis poner en contacto para concretar el modo de proceder. En cuanto a Jesús Manuel, parece estar más tranquilo. Los correos en los que parecía más alterado de lo normal, los remitió en fecha próxima a la siguiente dosis de su inyectable, debe ser que ya le hacía falta. Por último, al final del correo de Toni, subrayo también en amarillo las demandas de dinero extra que realiza, es verdad que suele hacer estas peticiones él mismo por mail. Tampoco sé si es factible aumentar un poco su asignación periódica o darle un extra ahora para el verano. Ya nos decís, porque entiendo que con el gasto de la pomada su cuenta no debe dar mucho más de sí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2022-06-17','TERESA ARCHIVO RESOLCUON DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-06-20','Ana: Correo de la Res. Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): "Lamentamos comunicarles que Feliciano Borreguero Cambero con DNI: 06959282-B, falleció éste pasado Sábado día 18 de Junio de 2022."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2022-06-20','Te comento, del ultimo seguimiento presencial, el dia 24 M. En la visita se acude al centro de salud para preguntar a la médico de Francisco el estado de su cita de psiquiatría, nos indica que está aceptada pero que aún no tiene establecida cita concreta. Quedamos en volver a llamarla pasado un par de semanas. Nos indica que cumple correctamente el tto. farmacológico correspondiente al inyectable (cada 3 meses), el último inyectable corresponde al día 16 de marzo y que el próximo le toca en el mes de junio. Después se intenta en el ayuntamiento hablar con la trabajadora social pero no se encuentra. Se le pregunta a la policía local por Francisco y nos indican que hace una hora estaba en un bar de la localidad tomando café. Recorremos las calles del pueblo, la plaza y miramos en los veladores de los bares pero no le vemos, nos dirigimos a su “casa” le llamamos pero tampoco nos responde, finalmente nos tenemos que ir de la localidad sin encontrarle. En esta ocasión nos fue imposible hablar con Francisco, pero tras la información obtenida en anteriores seguimientos presenciales tanto del tutelado personalmente como de los profesionales de referencia (Tsocial de los SSB y Policía Local), Francisco exterioriza que quiere ingresar en un centro, si expresa que no quiere un centro como los anteriores (centro Sociosanitario Mérida y Plasencia) pero si un centro residencial pues es consciente que no puede continuar en la situación actual viviendo durante mucho más tiempo. Por lo tanto, aparentemente si muestra voluntariedad para el ingreso en centro, lo que no sabemos con certeza es la durabilidad de su estancia en el mismo dado que, según expresan los profesionales anteriormente mencionados, en ingresos anteriores después de un par de semanas siempre decide volverse a la localidad. La proxima visita presencial, la haremos coincidir con el inyectable (sobre el 16 de Junio) para asegurarnos verle y poderle trasladar lo del centro con mas certeza, imagino que te habrian comentado ya para estas fechas si le aceptarian y demas. ------------------------------------------------------------ Parece que sí aceptaría ingresar en centro . Me dicen las compañeras que en Pinofranqueado no hay plazas .Lo que sí se podría solicitar es CRR desde el ESM por emergencia social .Las compañeras de Futuex van a acompañarlo en la próxima cita.','2');
