insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MONTAÑA'and apellido2='SANTOS'),'2022-06-20','Ana: Según Informe Social de la rendición anual: Ingresado en la Unidad de Larga Estancia del CSS-Plas. Padres fallecidos. Escasa relación con los hermanos. Última visita de su hermano Pedro en diciembre de 2021. ··· No realiza salidas al exterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-16','miguel, emails de Damian: Hola buenas tardes señor Miguel le ha mandado rocío un correo que mientras antes se gestione mejor porque es para que usted pida al juzgado de Cáceres la autorización creo que me dijo rocío que usted le tiene que mandar un papel para que pueda celebrarse el juicio para poder hacer el desahucio del piso y poder por fin que se quede libre pero me ha dicho rocío que va para largo le pediría por favor que le agilice el papeleo lo antes posible a rocío para que nos puedan dar otra fecha de juicio muchas gracias *************************************** Buenos días señor Miguel le he llamado ésta mañana ahora mismo por si ya tiene en trámite el pedir la autorización al juzgado para que se celebre el juicio gracias espero su contestación que pase buen dia *************************************************** He pensado y lo he hablado con mi prima que es la que mejor me puede cuidar el piso cuando consigamos echar a los inquilinos alquilarselo por 300 euros y que ella pague la reforma del piso gracias por su ayuda a ver si conseguimos por fin echar a los inquilinos.que pase buen dia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-06-20','TERESA Nos notifican desde el programa de familia la situación en la que se encuentran, ya presentan problemas de salubridad además hay quejas vecinales por discusión a altas horas de la madrugada. No dejan acceder a la vivienda a las chicas del programa, tan solo lo ven el día que le acompañan a hacer la compra. Entiendo que el área jurídica debe volver a comunicar la situación con este nuevo informe que adjunto y pedir que agilicen el internamiento… como no se solucione en julio, en agosto el juzgado es inhábil y esto se nos va a septiembre…. Teléfono progr atec familia es 609 382 439','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2022-06-13','Buenos días Teresa, a falta de saber si Claudia tiene alguna copia de su documentación argentina, necesitamos que el certificado del SEPAD, respecto al grado de discapacidad de Claudia, además de estar actualizado, deje constancia del impedimento para desplazarse al consulado de Madrid. Una vez tengamos respuesta, enviaremos un sobre con el kit para que Claudia ponga las huellas y firma (si puede) y nos lo devuelvan para realizarle el pasaporte de emergencia, que tiene una duración de un año y un coste de 40 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2022-06-20','TERESA ENVIO INFORME MEDICO Y COPIA DEL PASAPORTE A LA EMBAJADA A LA ESPERA QUE CON ESTA DOCUMENTACION NOS ENVIEN EL KIT PARA PODER HACER DE NUEVO EL PASAPORTE','2');
