insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-05-31','Ana: Informe Social emitido por Pilar Cerrillo, TS Res. Virgen de la Montaña, para rendición anual: Martín ingresa en el C. Residencial el pasado 20 de abril, con 57 años, procedente del Hospital, con plaza T3, por necesitar cuidados sanitarios. A pesar de su brote (Trastorno Bipolar) desde el hptal. no pueden derivarlo al CSS por requerir cuidados sanitarios específicos. ······· Red de apoyo social escasas (divorciado y sin hijos. Tiene un hermano con el que sí mantiene relación y del que recibe su único apoyo). ···· La evolución, desde su ingreso, ha sido positiva. Sólo necesita un mínima ayuda para algunas de las ABVD. ···· Se ha adaptado bien al recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='RECIO'and apellido2='GARCIA'),'2022-06-01','Ana: Informe Social para la rendición anual, emitido por Emilia, TS del CSS-Plas.: ingresa en el centro por primera vez en 1955 y de forma ininterrumpida desde 1982. No se le conocen familiares. No recibe visitas ni llamadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-20','miguel, llega email de Damian: Era para comentarle que al final el piso en un futuro no se lo alquilo a nadie ni a mi prima porque he reflexionado que cuando me coja unos días de vacaciones puedo bajar a mi casa de Málaga y voy a mi casa.una preguntilla cómo va el tema del papel para la autorización del juicio? Espero su contestación he intentado hablar con usted pero no cogía el teléfono gracias una respuesta suya me saca de dudas y me alivia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-06-20','Ana: Correo de Alberto, jefe secc. ecca. a Óscar: "Se ha acordado con Ana que vamos a hacer una aportación extraordinaria a centro x 600 €...concepto" Compensación Coste Plaza" ········· Óscar se encarga de la gestión bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-06-20','Ana: Recibimos Documentos de Aceptación PIA para Prestación Ecca. SAR y Aceptación PIA solicitud del SAR. ····· *Pongo ambos y el alta de terceros a la firma del Presidente CTAEX. ····················· Solicito a Pilar, Directora de la residencia de Logrosán (639 58 54 89) el Contrato de la misma con Valentina, pues no lo tenemos en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2022-06-20','Ana: Correo de Carolina, Psicóloga CRR (psicologia.crrplasencia@grupo5.net): "Por otro lado, informaros que tenemos brote COVID en la residencia y que tanto Isabel Cano como José Manuel Moreno han dado positivos. Los dos han tenido fiebre durante el fin de semana, hoy parece que están un poco mejor . El régimen actual es de semiaislamiento pudiendo salir a fumar y a dar paseos. Os iremos informando de cualquier cosa"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-06-20','Ana: Correo de Carolina, Psicóloga CRR (psicologia.crrplasencia@grupo5.net): "Por otro lado, informaros que tenemos brote COVID en la residencia y que tanto Isabel Cano como José Manuel Moreno han dado positivos. Los dos han tenido fiebre durante el fin de semana, hoy parece que están un poco mejor . El régimen actual es de semiaislamiento pudiendo salir a fumar y a dar paseos. Os iremos informando de cualquier cosa" ··················································································································································································································· Nos comunican también: "...citación judicial que ha recibido Isabel Cano para declaración en calidad de perjudicada por el delito de abusos sexuales. Es para el día 5 de Julio a las 11.30"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-06-20','Ana: Llamada de Flora (687 316 191): dice que no se encuentra a gusto en el CRR y se quiere trasladar al de Mérida. *Le indico que la solicitud deben hacerla desde el CRR. Que hable con las profesionales del mismo. ······· Llegado el momento de ir a Residencia de Mayores, dice que quiere ir a una de San Sebastián. ········ Y en cuanto a su herencia, quiere dejarlo hecho ante notario, pues quiere dejar todo a ASPACE de San Sebastián (Guipúzcoa). ·········· Se lo comunico a Ángel y Miguel, Asesores Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-06-20','Ana: Correo de Carolina, Psicóloga CRR (psicologia.crrplasencia@grupo5.net): "Hola Ana! Hoy hemos realizado la entrevista de incorporación a Julia Morón, todo ha ido bien y hemos fijado la fecha de ingreso en el CRR para el lunes 27 de junio por la mañana. Ha venido acompañada por su padre y su madre y también por Gloria de Futuex. Una vez hecha la entrevista y tras la realización del presupuesto mensual, teniendo en cuenta tabaco, gastos personales y viajes al pueblo, hemos determinado la cantidad de 350€ mensuales. Estaría genial que hasta que cobre, pudiese disponer de tabaco y dinero suficiente. (5 paquetes de tabaco y al menos 20 €, Julia no ha sabido decirnos sí disponía de ellos)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-06-20','Ana: Llamada de Pilar, TS ESM-CC: Hoy ha estado José Manuel en su despacho. Pilar propone reactivar el PIA y solicitar C. Día. Plantea que le atiendan en REVITAL, Clínica Neurológica y de Daño Cerebral, dice que atiende también a personas con Trastorno Límite de la Personalidad. ···· Llamará para preguntar. ··········· Yo llamaré al IMAS, para solicitar SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2022-06-21','Mérida-Negociado de Extranjería >merida.negextra@policia.es> Se reenvía la consulta a los compañeros de expedición de tarjetas, ya que al ser titular de Residencia de Larga Duración, sólo tendría que renovar la tarjeta, cuando obtenga respuesta le comento, de todas formas si se alarga el tiempo por favor recuerdamelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-06-21','Ana: Envío correo al Alberto, Jefe Secc. Ecca., comunicando la variación en la pensiones y la reclamación del cobro indebido. Le remito el documento con el número de cuenta al que deben hacer la devolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-06-21','Ana: Llamada de Toni, TS CR Cervantes (22270): Mª Eugenia ayer estaba muy nerviosa, decía con más insistencia que nunca que quería irse a Hervás, a la Residencia en que reside Pedro, su novio. Le habían dicho que hay una plaza libre allí. ···· Le tratan de explicar que tanto Pedro como ella tienen pedido traslado a Plasencia. Si se va a Hervás y luego conceden traslado a Pedro, volvería a empezar de nuevo con la solicitud. *Al ser curatela para el ámbito patrimonial en exclusiva. *Hoy ha ido Gloria, Ed. Futuex a visitarla y acompañarla fuera del centro. Hablarán con ella para que aborde también este asunto con Mª Eugenia. ···· *Plantean la posibilidad de que vaya a visitar a Pedro. Desde la CTAEX no hay inconveniente, quienes no quieren que tengan contacto son los familiares de Pedro. ···· Enviarán presupuesto para visita si, tras hablarlo con ella, le convence la idea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2022-06-20','Ana: Correo-e de María Gía., Directora del C.R. Fco. de Asís, Aldea del Cano (centrofranciscodeasis@gmail.com): "Comentarte que desde el jueves, Inés está ingresada en el Hospital Universitario de Cáceres por una fractura en la meseta tibial. Hoy se ha puesto en contacto conmigo el traumatólogo y ha decidido no operarla por lo que mañana le darán el alta con una férula. Va a esperar a ver la evolución antes de intervenirla. No sabemos exactamente cómo se ha hecho la fractura ya que no ha habido caída. Salió con los demás compañeros el viernes anterior y parece que dio un mal paso en la furgoneta, aún así estaba bien, a lo largo de los días empezó a quejarse y la pierna a hincharse por lo que se decidió llevarla a Urgencias, quedó ingresada para operarla pero según lo que nos han dicho hoy ya no."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2016-03-16','Contactamos con Charo (Dra. Aprosuba 1), nos informa de la próxima salida de 26 de Junio a 3 de Julio de 2016 al Albergue Nonte do Gozo. Actividad organizada por AD El Bellotín (asociación de Aprosuba), donde participa la tutelada. El coste del viaje son 200€ pensión completa y el autobús corre a cargo de la Asociación. La Comisión acepta el viaje siempre y cuando tenga capacidad económica para asumir el coste en su momento. Acordamos con Charo que la autorización valdría con la trimestral y que nos enviarán documentación redactada del viaje y sus actividades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-06-21','Ana: correo de la Res. Mayores Femar (residenciafemar2019@gmail.com): "La cuantía que le corresponde pagar a Valentina Fernández Trejo por la mensualidad en la Residencia de Mayores Femar pasa a ser a partir del mes de julio de 2022 que se paga ahora el 25 de junio a 1240€. Debido a la valoración de la dependencia que la realizó el SEPAD el 13 de junio de 2022." ·············· Les recuerdo que seguimos a la espera de que nos envíen la copia del contrato de la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-06-21','Ana: Correo de la Res. Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): "Muy buenos días Ana, adjunto enviamos documentación que nos pasa María, Trabajadora Social del Centro, acerca de Juan Sanguino Lancho." ··· Adjuntan - Índice de Barthel, - Historia Clínica Resumida e Informe de Salud (Anexo II). Para solicitar la revisión del grado de dependencia. ················ *Cumplimento la solicitud y la pongo para la firma del Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-06-21','miguel, tras conversación con la abogada Josefina Santana (de abogacía) me indica que estamos nombrados como curadores provisionales y que ahora tiene una procedimiento penal donde lo ha denunciado su padre. Hemos quedado que será abogacía quién le represente pues entendemos que ambos procedimientos están intimamente relacionados','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-06-21','miguel, asisto por videoconferencia a vista del procedimiento abreviado 30/2022 del jzdo nº3 de Cáceres, donde reconoce que pegó y rompió los dientes al denunciante. Nombran abogado de oficio de defensa y queda visto para sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2022-06-21','Ana: Paula, me comunica que ha dado positivo en COVID. De momento los síntomas son leves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-06-21','miguel, llega email de la abogada (María Nuria Ledo Barrado): Buenos días: A los efectos del requerimiento que se me hace acerca de la información del procedimiento hipotecario contra Dª Justa, vengo a informarle de lo siguiente: Que la designación que se me realiza es la tercera hecha por el Colegio, en 2015, para asistir a la cliente, si bien, la misma, desde el principio, se oponía a cualquier acuerdo con el ejecutante encaminado a retomar el pago normal del préstamo, alegando que la Banca Pueyo debía condonarle las cantidades que le debía a ella (en este argumento se basa el recurso realizado por Dª Justa contra la Diligencia de Ordenación de 23 de abril de 2015 por el que se le comunica mi designación y los 7 días de plazo restante para oponerse) . Fuera de plazo para oponernos, sin causa legal para hacerlo, no obstante, y, siendo la única opción para Dª Justa llegar a un acuerdo con el banco ejecutante, esta letrada se puso en contacto con el director de la sucursal bancaria, así como con la familia de la ejecutada, la cual se negó a asumir pago ninguno. Posteriormente, se hizo evidente la incapacidad de la ejecutada para regir su vida, suspendiéndose el procedimiento a la espera del nombramiento de defensor judicial. La suspensión está levantada y el proceso a la espera de que el defensor venga a personarse y, en su caso, designar el letrado que considere apropiado, sin que esta letrada tenga ningún inconveniente en proporcionar la venia correspondiente o continuar en la defensa de los intereses de Dª Justa, según se me indique, si bien ya les adelanto que la ejecución continuará por haberse establecido así en el auto que me remite de 23 de septiembre de 2021. Lo que entiendo es que, si, en un futuro, se solicita el lanzamiento, podría acogerse como parte del colectivo vulnerable a la suspensión de lanzamientos de vivienda habitual por procesos hipotecarios prorrogados por decreto de 2020 hasta 2024. Quedo a su disposición para lo que necesite respecto de este procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-06-21','Ana: Envío correo a Blanca, Carolina y Paula, CRR-Plas.: "En relación a Flora Gutiérrez García, comentaros que ayer me llamó por teléfono. Me comentó varias cuestiones: - Quieres pedir traslado de CRR, me decía que ya os lo ha solicitado. Nos gustaría saber vuestra opinión al respecto y si habéis llegado a solicitar el traslado o si lo contempláis. - Plantea que quiere dejar constancia ante notario que todos sus bines, una vez fallezca, quiere dejárselos en herencia a, y cito textualmente, “los niños minusválidos de ASPACE de San Sebastián”. Con respecto a esta cuestión le hice consulta a mis compañeros jurídicos y podéis leer su respuesta en el hilo del correo. ¿Sería posible, para cumplir su deseo, que pudieseis solicitar cita en una notaría? Ya he tratado ambos asuntos con Paula, mediante conversación telefónica. Del primero, ya nos decís si se mantiene en esta solicitud de cambio y si finalmente se solicita. En cuanto al segundo, ya nos comunicaréis también cuándo le dan cita en Notaría." ···································································································································································································· En cuanto a la herencia de su madre, envío correo a Ángel y Miguel preguntando cómo van los trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-06-21','Ana: En relación a la Controladora Pioneer 800 que solicita Saturnino, hablo con Paula, TO CRR-Plas. Acordamos que hablarán con él. La otra controladora sólo tienen unos meses. Intentarán posponer esta petición a septiembre-octubre para unirlo a los objetivos a conseguir en el plan de intervención. Además le plantarán la venta de la controladora que tiene para invertir el dinero que obtenga en pagar parte de la controladora nueva pues el precio ese elevado (900 €).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-06-21','Ana: Envío correo a Alberto, jefe secc. ecca.: "En relación a JULIA MORÓN HERNÁNDEZ, comunicarte que le han concedido PLAZA EN CRR de PLASENCIA, ingresará el día 27 de este mes. Desde el centro me comunican: “Una vez hecha la entrevista y tras la realización del presupuesto mensual, teniendo en cuenta tabaco, gastos personales y viajes al pueblo, hemos determinado la cantidad de 350€ mensuales.” “Estaría genial que hasta que cobre, pudiese disponer de tabaco y dinero suficiente. (5 paquetes de tabaco y al menos 20 €, Julia no ha sabido decirnos sí disponía de ellos)”. *He llamado a Julia, en relación a los 20€ y el tabaco que piden, pero dice que ya se ha gastado toda la asignación... También he hablado con Paula, TO del CRR, e insisten en la conveniencia de que lo tenga los primeros días para una mejor adaptación. Hemos acordado, que para una mejor gestión, si os parece bien, se realizará una autorización de un extra de 24€ para gastos de bolsillo y tabaco, para que puedan retirarlo la semana que viene (a partir del lunes 27). Las retiradas en Plasencia serán acompañadas de Félix, Administrativo del CRR, Paula enviará un correo con los datos del mismo. *Si se aprueba la cuantía que proponen en el CRR, hacer la autorización periódica, con acompañamiento. *Hay que anular todas las autorizaciones que tenga hechas en su pueblo (a ella y/o su madre, no recuerdo cómo era) Pongo en copia a Julio para que modifique el domicilio en la base de datos a partir de la fecha indicada.."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-06-22','miguel, contesto a Ana, al centro CRR Plasencia y Angel: Buenos días, no otorgó testamento Modesta García Piñero por lo que habría que hacer la declaración de herederos, una vez lo cual tendremos que contratar los servicios de un abogado y una gestoría para los trámites ya que dispone de capacidad económica la tutelada FLORA GUTIÉRREZ GARCÍA para la aceptación de herencia judicial, la posterior firma de adjudicación de herencia notarial (con la correspondiente tramitación por parte de la gestoría de los trámites de liquidación de impuesto de sucesiones e inscripción en el registro de la propiedad del único bien inmueble que veo en la rendición final de cuentas) y posteriormente la aprobación de herencia judicial. Si es posible a ver si el centro tuviera el libro de familia, caso contrario a ver si supiera decirnos si hay más hijos o no. Según el certificado de defunción estaba viuda. Del padre se ha tramitado el testamento? Necesitaríamos el dni del padre, que desconocemos cómo se llama. Por tanto debemos hablar con la notaria de Plasencia para que vayan preparando la declaración de herederos ya que el último domicilio conocido de Modesta (madre) fue el CSS Plasencia. Y para ello necesitamos que el centro vaya localizando dos testigos. Por nuestra parte iremos recabando los certificados del registro civil que nos vaya requiriendo la notaria: certificado de matrimonio, de nacimiento de nuestra tutelada, de defunción de los padres. Iremos buscando abogado y gestoría que tramite esta herencia. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-06-21','En reunión mantenida el 21/06/2022, estando presente María Teresa Gómez Martín, Amalia Díaz González, Ángel Marín Martínez y Alberto Martín Rosete: • El asunto a tratar en esta reunión es la forma de actuación y gestión de la CTAEX, sobre el patrimonio de Dª. María Mercedes Perez Pinna, debido a la falta de acuerdo entre las 3 áreas sobre esta cuestión. • No es posible alcanzar un acuerdo con un criterio común de actuación, así como tampoco sobre el concepto de libre voluntad de Dª Mercedes o el concepto de "gastos de bolsillo". • Se adopta la decisión de solicitar a la Fiscalía el establecimiento de los criterios de actuación de la CTAEX, en cuanto a la gestión económica y patrimonial de los bienes de Dª. Mercedes. • A su vez, ante la falta de acuerdo y en tanto en cuanto se recibe la resolución de la Fiscalía, se opta por mantener la forma de gestión del patrimonio de Dª Mercedes, tal y como se viene realizando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-06-22','En reunión mantenida el 21/06/2022, estando presente María Teresa Gómez Martín, Amalia Díaz González, Ángel Marín Martínez y Alberto Martín Rosete: El asunto a tratar en esta reunión es la forma de actuación y gestión de la CTAEX, sobre el patrimonio de Dª. María Mercedes Perez Pinna, debido a la falta de acuerdo entre las 3 áreas sobre esta cuestión. No es posible alcanzar un acuerdo con un criterio común de actuación, así como tampoco sobre el concepto de libre voluntad de Dª Mercedes o el concepto de "gastos de bolsillo". Se adopta la decisión de solicitar a la Fiscalía el establecimiento de los criterios de actuación de la CTAEX, en cuanto a la gestión económica y patrimonial de los bienes de Dª. Mercedes. A su vez, ante la falta de acuerdo y en tanto en cuanto se recibe la resolución de la Fiscalía, se opta por mantener la forma de gestión del patrimonio de Dª Mercedes, tal y como se viene realizando. Alberto Cualquier cuestión que queráis aclarar o añadir a lo expuesto, contestad a este correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='MULERO'and apellido2='SALGUERO'),'2022-06-22','TERESA ENVIO POR REGISTRO SOLICITUD CAMBIO CUENTA DEPENDENCIA ACOMPAÑA ALTA A TERCEROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-06-22','Ana: Conversación con José Manuel: Pregunta por la tarjeta de autobús, le digo que hasta que no tenga que acudir a algún recurso de forma regular no se le va autorizar. *Dice que no si tiene que pagar el Centro de Día que le propuso Pilar, TS ESM, no quiere ir, a no ser que le den también de comer y se pudiera dejar el cáterin. Pilar le ha dicho que cuesta 300€. ··· Al CRPS dice que no quiere ir, que ya estuvo en su día y que no le gusta. ··········· Por otra parte, desde una tienda de colchones nos han remitido presupuesto para colchón y somier ("tapiflex") nuevos adecuados a su peso y tamaño. Su cama está en malas condiciones, su hermano lo corroboró. El somier no puede ser de láminas porque los rompe. ········· *Valorarán el presupuesto en la sección económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-17','miguel, Inés remite vía lexnet comunicaciones al jzdo nº2 Caceres, al nº6 de Cáceres y días después por sirex al Defensor del Pueblo (contestación al 3º escrito)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-22','miguel, tras el requerimiento por la ctaex al jzdo nº6 sobre si ha comparecido o no el día 8/6/22 conforme se indicó en el mandamiento de libertad provisional, llega hoy el fax desde el juzgado indicando que no compareció','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-06-22','miguel, recibo email de Josefa Santano (abogacia general)consultado el asunto en el Juzgado de Instrucción 1 de Badajoz, el tutelado ANTONIO FRAIRE ROMAN, tiene Letrado de designación particular JUAN PABLO GARCIA DE CASTRO MARTINEZ DE ACUÑA. A nosotros la CTAEX, estaremos informados de todo el proceso. Os iré informando de todos los trámites procesales, por si hay vista oral y os apetece estar presente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-06-22','Ana: Entrego a Julio, Aux. Amtvo. CTAEX, para registro, oficio-solicitud de certificado actualizado de pensión de Incapacidad Permanente Absoluta. En el mismo solicito que hagan constar en su registro la dirección de la CTAEX a efectos de comunicaciones. ······························································································································································································ *Entrego también a Julio para registro en SIREX, Solicitud de REVISIÓN DEL GRADO DEPENDENCIA (se adjunta Informe de Salud, Índice de Barthel e Historia Clínica Resumida).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-06-23','miguel, contestacion del centro ocupacional Crr plasencia, Paula Terapia Ocupacional CRR Plasencia >tocupacional.crrplasencia@grupo5.net>: Hola, respecto a la documentación que solicitáis, Flora no dispone del libro de familia ni tiene el DNI de su padre. Flora tiene dos hermanas, Modesta y Juana María Gutiérrez García. Flora quiere facilitaros los teléfonos de su hermana Modesta: 673972619 y 938606605 para que podáis contactar con ella si lo consideráis oportuno. Ambas hermanas tienen contacto entre ellas y en ocasiones con Flora. Respecto a Modesta y la posibilidad de que haya testigos ella no residía en nuestro centro, sino en el Centro Sociosanitario de Plasencia, por lo que podéis contactar con la trabajadora social y que ver si ella puede realizar dicha gestión. Si tuviéramos conocimiento de alguna otra información que pudiera ser relevante os informamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-06-23','Ana: Envío correo a Miguel, Asesor Jurídico CTAEX: "Buenos días Miguel, Te reenvío el correo que nos remitió ayer el CRR con las nuevas incidencias protagonizadas por JUAN MARIO SAN ROMÁN BLASCO. Continúa consumiendo alcohol y cannabis, pide dinero para consumo y muestra agresividad hacia otras personas residentes en el centro. No sé si has comunicado ya al Juzgado, si no ha sido así, añade este correo también." ····················· *Guardo el correo del CRR en PDF. ································································································································································································· Recibimos nuevo correo con incidencias de ayer mismo. *Desde urgencias de Att. Primaria tuvieron que derivar al hospital por "intoxicación etílica, vómitos e hipoglucemia" ······ *A la última cita de Psiquiatría en ESM se negó a acudir. ····· *En el hptal. le dan el alta con la recomendación de no tomar alcohol ni consumir sustancias tóxicas. ············· **Desde el CRR mantienen que no cumple criterios para permanecer en el centro. ········· *Reenvío a Maite y Miguel, CTAEX, y guardo el correo y los documentos adjuntos (Informe de Alta del HUC + Hoja de Interconsultas Urgencia Att. Primaria).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-06-23','Ana: Correo de ayer de Ángela, Directora PLACEAT: "Te comento porque no se si puede ser, si seguis teniendo concierto con Cruz Roja para tema traslado de usuarios. De todas formas te informo del tema vacaciones de Cristofer. Cristofer marcha al domicilio de su tia Belén en Montijo desde el día 1 de agosto hasta el 23/24 de agosto que la familia le traería al centro, pero no pueden venir a recogerle. Y ese es el tema si lo podeis gestionar a traves de Cruz Roja, o contratar un taxi.... porque en transporte público no es viable. Ya me dices para ver cómo podemos gestionarlo." ······················· Respondo: "Pongo en copia a Belén, compañera de las Sección de Acceso a Recursos de Discapacidad que lleva los traslados de Cruz Roja, no sé si habrá disponibilidad, creo que está complicado. Si Belén nos dice que no es posible, habría que enviar un presupuesto de taxi a la sección económica de la CTAEX (ctutelar@salud-juntaex.es), podéis ponerme en copia, para que valoren si Cristofer puede asumirlo. Si fuera así, por mi parte no habría ningún problema." ······························································································································································································ Respuesta de Belén Gutiérrez: "Actualmente no disponemos de presupuesto para que Cruz Roja pueda realizar este viaje. El presupuesto está cerrado y normalmente cuando se produce una baja es cuando se puede incorporar a un usuario nuevo. Eso es lo que os puedo decir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-06-23','Ana: Recibimos Informe de PADRÓN MUNICIPAL de habitantes de Cáceres, acreditando que Felipe está empadronado en el centro de Novaforma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2022-06-23','Ana: Recibimos Informe de PADRÓN MUNICIPAL de habitantes de Cáceres, acreditando que Eduardo Rodrigo está empadronado en el centro de Novaforma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2022-06-23','Ana: Recibimos Informe de PADRÓN MUNICIPAL de habitantes de Cáceres, acreditando que Álvaro está empadronado está empadronado en la C/ Trajano, nº7 de Cáceres. (*NO está empadronado en Novaforma).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-06-23','Ana: Envío correo a Paula, CRR, en relación al cargo que le siguen haciendo en cuenta de Vodafone, tras haber confirmado con ella que el número que habitualmente utiliza es de prepago. "Buenos días, de nuevo, Paula, Desde el departamento correspondiente de Vodafone, nos indican que para dar de baja cualquier línea o contrato, necesitan que le indiquemos el número de teléfono. Puesto que aquí no llegan esas facturas y sólo tenemos la información por los cargos bancarios que le pasan en su cuenta, necesitaríamos que nos digáis el número para que la compañera pueda proceder a dar de baja dicha línea/contrato. Quedamos a la espera."','2');
