insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-06-24','Ana: Envío correo a Paula, TO CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Buenos días Paula, En relación a las líneas móviles de Ceferino, desde Vodafone nos informan de los dos posible números que puede tener contratados, éstos son: 697 729 *** / 667 015 ***, si la numeración coincide, nos indican que la única forma de dar de baja, es llamando él mismo al número: 22123 si llama desde una línea de Vodafone y si es desde otro operador al: 607 123 000, a posteriori le enviarán un sms con un enlace y un código de baja. ¿Podríais desde el centro informarle y apoyarle en esta gestión? A ver si en esta ocasión se consigue la baja y dejan de pasarle cargos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-06-24','Ana: Envío correo a Teresa, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com): "En relación a las autorizaciones para el viaje a Chipiona, te adjunto los documentos firmados digitalmente por el Representante Legal. En cuanto a la de Felipe Blanco Guisado, teniendo la CTAEX una curatela, si él comprende el significado del viaje y lo que conlleva, no necesitaría la autorización firmada. Con que él quiera ir es suficiente. No obstante, como en la Sentencia no especifica bien el alcance de la Curatela, tras hablarlo con el compañero jurídico, hemos decidido ponerla también a la firma, pero en principio, como decimos, no sería necesario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-24','Ana: Envío correo a Óscar y Alberto, secc. ecca.: "En relación a Saturnino Miguel Salgado, como sabes, hay que fijar una autorización semanal de retirada de efectivo. Lo hemos hablado esta mañana Maite y yo y proponemos 50€/semana. Seguramente le resulte poco, pero ya le van a pasar suministros por la cuenta, como tú nos dijiste, le han pasado ya el alta del suministro de agua, que deben haber gestionado finalmente sus hermanos, viendo que en Alcuéscar está estable, o eso parece."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-06-24','Amalia : Inicio Plan de Intervención inicial . Para el estudio del caso además de la documentación expuesta en su expediente , solicito a Futuex visita domiciliaria para contrastar cierta información que no concuerda con inventario: Buenos días , te comento un poco este caso y empezamos como siempre Plan de Intervención. Se llama ANTONIO FRAIRE ROMAN, tiene 53 años y vive en una vivienda cedida por los padres en Villar del Rey. ( adjunto I .social ) La tutela la tiene su padre , pero hay malas relaciones familiares y cautelarmente y hasta que se finalice el proceso de medidas de apoyo ya iniciado por el padre , el juzgado nos nombra curador provisional . El padre ha solicitado la remoción del cargo para que se designe a un hermano de Antonio. Tiene un G. D. del 68% ( lo adjunto ) por tno. bipolar , alteración conductual y otras enfermedades. Percibe PNC . En el I. Social él indica que está pagando un préstamo , en el inventario no aparece . En las cuentas que se han rastreado no hay nada . Tenemos que averiguar información sobre ésto. El saldo está a 0 , hay que elaborar presupuesto de gastos e ingresos . De momento y a peticion del SSASB se le va a dar durante este mes la pensión íntegra , pero necesitamos cuadrar pto. Cómo paga los suministros de agua , luz ?? tiene solicitado minimos vitales en el Ayto ? la vivienda tiene condiciones de habitabilidad ? el Informe social es un poco escueto , no menciona nada de ésto. Cuando podáis , habria que realizar visita domiciliaria . Podéis contactar con el SSASB para un encuadre inicial y apoyo en el estudio del caso. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-06-24','Amalia : Inicio Plan de Intervención inicial . Para el estudio del caso además de la documentación expuesta en su expediente , solicito a Futuex visita domiciliaria para contrastar cierta información que no concuerda con inventario: Buenos días , te comento un poco este caso y empezamos como siempre Plan de Intervención. Se llama ANTONIO FRAIRE ROMAN, tiene 53 años y vive en una vivienda cedida por los padres en Villar del Rey. ( adjunto I .social ) La tutela la tiene su padre , pero hay malas relaciones familiares y cautelarmente y hasta que se finalice el proceso de medidas de apoyo ya iniciado por el padre , el juzgado nos nombra curador provisional . El padre ha solicitado la remoción del cargo para que se designe a un hermano de Antonio. Tiene un G. D. del 68% ( lo adjunto ) por tno. bipolar , alteración conductual y otras enfermedades. Percibe PNC . En el I. Social él indica que está pagando un préstamo , en el inventario no aparece . En las cuentas que se han rastreado no hay nada . Tenemos que averiguar información sobre ésto. El saldo está a 0 , hay que elaborar presupuesto de gastos e ingresos . De momento y a peticion del SSASB se le va a dar durante este mes la pensión íntegra , pero necesitamos cuadrar pto. Cómo paga los suministros de agua , luz ?? tiene solicitado minimos vitales en el Ayto ? la vivienda tiene condiciones de habitabilidad ? el Informe social es un poco escueto , no menciona nada de ésto. Cuando podáis , habria que realizar visita domiciliaria . Podéis contactar con el SSASB para un encuadre inicial y apoyo en el estudio del caso. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-06-24','Oscar informa : Buenos días. Ana María Rosco no va a poder pagar el recibo de Vodafone porque saca todo lo que ingresa y a veces más. Hay limitación de reintegro, pero el banco no lo respeta y le da lo que pide, por lo que no ahorra nada. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2022-06-24','Amalia , hago nueva propuesta eco. Buenos días , revisadas las ultimas rendiciones anuales de los dos hermanos : Jorge , percibe PNC de 421 € ( 14 pagas ) , saldo en cuenta 17249€ Minerva , 588€ ( 14 pagas ) , saldo en cuenta 37.163€. Teniendo en cuenta que los dos hermanos conviven con la madre ( desconozco la cuantía exacta de su pensión de viudedad , pero será la mínima porque su marido no cotizó los años suficientes ) , que ambos están en centro ocupacional del que no hay copago por la plaza , que acuden diariamente al domicilio , que es la madre quien cubre todos los gastos de manutención, vivienda, suministros , ropa ... mi propuesta es : No pedir la devolución del cobro indebido ( puedo garantizaros que ya no lo tienen ) . Solicitar al banco que anulen las peticiones anteriores , con la inflación y subida de los precios con 300€ no cubren gastos . He calculado aproximadamente la mitad de los ingresos sin extras de cada uno , 200 de Jorge y 300 de Minerva y solicitar al banco una autorización nueva para que pueda retirar 500€ al mes . Ahorrarían una cantidad cada mes, más las extras . Esta es mi propuesta desde la parte social , velando por el bienestar de los tutelados , a ver cómo lo valora Alberto. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2022-06-24','Ana: Envío a Teresa, TS Novaforma (trabajadorasocial.novaforma@gmail.com) autorización para el viaje a Chipiona firmada digitalmente por el Representante Legal.','2');
