insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-06-24','Ana: Recibimos Resolución de la Dirección General de Serv. Soc, Infancia y Familia. Habiendo tenido comunicación de la variación en la unidad de convivencia (reside con su cónyuge, con el que contrajo matrimonio a fecha de 6/08/2011) y teniendo en cuenta los rendimientos de trabajo de su marido (Jacinto Sánchez Villar) proceden de oficio a EXTINGUIR EL DERECHO A LA PERCIBIR LA PNC de Invalidez. **Le reclaman un cobro indebido total de 22.281,70€ que habrá de devolver en un plazo de 30 días. ··············· Se lo reenvío a Alberto, jefe secc. ecca., con copia a Maite y Óscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-06-27','Ana: Llamo a Nuria Carrasco, TS EVD Trujillo (54513 / nuria.carrascos@salud-juntaex.es) varias veces, pero no obtengo respuesta. ··· Le envío un correo-e solicitando se pongo en contacto conmigo en relación a Juan José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-06-27','Ana: Remiten el DNI renovado de Mateo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-06-27','Amalia . Envio respuesta al email enviado por la concejala del Ayto : Buenos días Laura , soy una de las trabajadoras sociales de la Comisión Tutelar , le contesto al email que ha escrito en referencia a Dña. Angela Rodríguez Figueredo , en ausencia de la Jefa de Sección. Esta señora tiene una resolución judicial con medidas de apoyo del día 17 de mayo de 2022. La aceptación del cargo de la Comisión Tutelar es del día 19 de mayo de 2022. Establece el Código Civil , para todos los casos obligatorio , realizar un inventario de la situación personal , social , económica... que se ha de enviar al juzgado . Para ello , tenemos un plazo de 60 días , y es en ese momento en el que nos encontramos. Por protección de datos no podemos facilitarle la sentencia , pero le adjunto la aceptación del cargo . El viernes día 24 de junio , mantuve conversación telefónica con la nueva trabajadora social que se incorpora hoy. Ya le informé de cómo vamos a realizar el plan de intervención y se quedó pendiente fijar lo antes posible , una visita domiciliaria con la delegada tutelar. Si es posible , se hará esta semana. A nivel económico , le informo, que Angela hizo una retirada en efectivo el día 2 de junio de la entidad bancaria de 1000€. En mayo , retiró 1000€ el día 4 y otros 600€ el día 12 de mayo. Tendría que tener dinero de sobra para sus gastos de manutención y farmacia. Hasta que no se termine el inventario y se realice un plan de gastos no se le puede autorizar a sacar más dinero para este mes . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-06-24','Amalia . Hablo con la nueva TS , Estrella ( email eferboc@hotmail.com / tf 652563461 ) , planifico la intervencion. Paso el caso a Futuex para planificar visita cuanto antes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-06-27','-Amalia : Coordino con Futuex plan de intervención y visita domiciliaria. Buenos días , qué tal ?? te he llamado por tf , luego lo vuelvo a intentar para hablar de este caso. Es una señora de 78 años que vive sola en Villanueva del Fresno . Sin red familiar de apoyo. Sí tiene una vecina que la ayuda en tareas domesticas , Joaquina. Tiene 67% Gº Discapacidad por sindrome depresivo , alteración conductual . Valorada con Grado I de dependencia. Percibe PFHC ( 417€ ) y P. Orfandad de 767€. Entre las medidas de apoyo tenemos una curatela representativa , tanto personal como económica . Este mes ha sacado el día 2 , 1000€ y vemos que normalmente saca a primeros de mes 1000€ y a mediados otros 600€ . Nos ha escrito la concejala diciendo que le están dando comida de los Pisos tutelados pq tiene bloqueada las cuentas. Hasta que no se haga pto. de gastos e ingresos no se le puede autorizar más . Vamos a tener suerte que Maria , la TS está de baja maternal , hoy entra EStrella , una chica nueva . Te paso su tf 652563461 y su email eferboc@hotmail.com , ya le he explicado cómo vamos a intervenir. Por favor , si es posible esta semana concertar visita a domicilio , Estrella irá con la delegada aun no la conoce claro. Y como siempre empezamos a trabajar . Te adjunto documentación de Angela , mañana te paso el Informe Social que no está informatizado. Ver como se cuadra el pto. de gastos , si quisiera la comida a domicilio sería más facil . Cita con su medico , para ver tratamiento pautado , citas para acompañarla .. En el banco ya conocen el caso, pondremos para el mes que viene una limitación. Valorar ingreso en residencia de mayores , publica o privada siempre que sea voluntaria. En la sentencia el Fiscal no adminte el internamiento involuntario. Gracias , cualquier cosa me llamas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-06-24','Amalia . Hablo con la nueva TS , Estrella ( email eferboc@hotmail.com / tf 652563461 ) , planifico la intervencion. Paso el caso a Futuex para planificar visita cuanto antes.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-06-20','Amalia : He pedido a Cati , un cdo. del centro con la deuda contraida por Antonia cuando estuvo ingresada , antes de estar tutelada . Y que Antonia firme un documento en el que admite la deuda . Pendiente de recibirlo para darselo a Lourdes.','2');
