insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FERNANDEZ'and apellido2='RAMOS'),'2022-06-27','INCIDENCIA A LA APERTURA DEL EXPTE. Se procede a la aceptación y apertura del expte. con f/ 27/06/2022. No se había recibido notificación alguna anterior a esta f/, a pesar de que el Auto de nombramiento es de 11/03/2020. Conocía de la defensa judicial Curro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELESTINO'and edp.apellido1='NAVARRETE'and apellido2='MURGA'),'2022-06-27','TERESA RECIBO LLAMDADA DE PAQUI DE LA RESINDENCIA HERNANDO DE SOTO 21781, NOS COMUNICA QUE CELETINO ESTA EMPEZANDO A ACUMULAR SUCIEDAD EN LA VIVIENDA PUES A PESAR DE QUE VIVE EN LA RESIDENCIA VA MUCHO A SU CASA, TENEMOS QUEJAS VECINALES POR EL OLOR QUE DESPRENDE LA VIVIENDA ACUERDO CON PAQUI QUE VAN A IR A VISTIAR LA VIVIENDA JUNTO CON LOS SERVICIOS SOCIALE Y VALARAR SI ES NECESARIO QUE VAYA UN EMPRESA DE LIMPIEZA QUEDO A LA ESPERA DE PRESPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-06-27','Ana: Envío correo-e a Paula y Carolina, CRR Plas: "Buenos días Paula y Carolina, En relación a la propuesta de asignación mensual para JULIA MORÓN HERNÁNDEZ, comunicaros que se autoriza REINTEGRO de 350 €/mes con acompañamiento (administrativo del centro). Oficina de Liberbank de la Avda. Alfonso VII, nº 29. Así mismo, podrá retirar este miércoles, ahí en Plasencia, en la misma oficina, un extra de 25 € para que pueda tener para los dos primeros días para tabaco y otros gastos de bolsillo. También tendrá que retirarlo acompañada. Por otra parte, Alberto, Jefe Sección Económica, insiste en esto, y copio literalmente: “CENTRO TIENE QUE TENER CLARO QUE PRÁCTICAMENTE NO HAY POSIBILIDAD DE EXTRAS....TIENE UN SALDO BANCARIO MUY POBRE Y LAS PERSPECTIVAS AHORRO SON BAJAS.” Espero que la situación en el centro vaya mejorando poco a poco. Y que Julia comience con buen pie y se adapte pronto, pues verdaderamente necesita el recurso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-06-27','Ana: Recibimos resolución del INSS, tras revisar su PFHC, resuelven concederle el complemento de tercera persona, pasando a percibir 626,60€. Fecha de efectos:01/07/22. ·········· Se lo comunico a Alberto, Jefe Secc. Ecca. ············· Lo comunico también a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-27','Ana: envío correo a Toni, Futuex, con copia a Miguel, Asesor Jurídico CTAEX: "Adjunto Cédula de citación relativa a Saturnino Miguel Salgado Jiménez. Deberá comparecer el próximo día 05/07/22 a las 10:00 h, para que la compañera pueda trasladarle esta información a Saturnino y facilitarle copia del docuemnto, pues según se indica, debe presentar la cédula y el documento de identidad al personarse en el Órgano Judicial. Pongo en copia a Miguel, Asesor Jurídico, entiendo que quiénes tienen que conectarse online es alguno de los compañeros jurídicos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-23','miguel, recibo email de Damian: Los inquilinos llevan ya 4 años y quería saber si ya le ha mandado el papel a rocío del tema de echar a los inquilinos ya estoy nervioso porque están abusando de mi y no recibo ninguna contestación suya que va a pasar con el piso gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-27','miguel, contesto a Damian (previamente remito via email la documentación presentada para la solicitud de autorización para demanda de desahucio enviada a Rocio Gracian: Buenos días, sí hemos remitido la solicitud que nos indicó su abogada Rocío. Lo remitimos el día 23-6-22 y hoy he reenviado a Rocio la documentación de dicha solicitud. Ahora bien, lo que tarde el juzgado decano en asignar juzgado y por tanto en conocer el procedimiento y el tiempo que tardarán en resolver lo desconocemos y depende de dicho juzgado ************************************************ Recibo emails de Damian: Buenos días señor Miguel a través de la sicologa y me dicen ellos que le pregunte a la comisión cada vez soy más autónomo y la sicóloga yo y el centro para que Amalia le escriba un correo al centro que me ven capacitado para yo poder administrarme yo mi medicación para que la comisión se ponga en contacto con el centro y el centro me ve capacitado para administrarme yo mismo la medicación es un paso más hacia mi autonomia y esa era la pregunta pensaba que usted estaba enfadado conmigo y por eso no me cogía el teléfono y el director me ha dicho que yo de el paso de preguntar a la comisión y que la comisión le pregunte al centro cómo me ven para administrarme yo la medicación yo todo lo que sea dar un paso más hacia mi autonomia es importante gracias**************************** Le contesto: Buenos días, acabo de ver sus emails. Al ser un tema social, se lo he reenviado a su trabajadora social Amalia.**********************Reenvío a Amalia: Buenos días, adjunto el último de los emails recibido de Damian…por si necesitas hablar de este tema con el centro. ******************************************** Recibo email de la abogada Rocio Gracian: Buenos días Miguel, Recibido tu correo. Esperemos que no vayan con mucho retraso porque por aquí poco puedo hacer. La jueza ni siquiera ha dictado resolución en forma ni lo va a hacer según me informa el oficial, da por suspendido el procedimiento con lo dicho en la vista. Me parece una aberración el modo de actuar que están teniendo los juzgados llevándonos a una situación de indefensión intolerable. Solo quedaría interponer recursos por nulidad de actuaciones y conculcación de derechos fundamentales a la tutela judicial efectiva, etc, etc,... pero todo eso conlleva un mayor retraso dilatando todavía más el procedimiento (años) hasta que se resolviesen esos recursos , y lo que nos interesa es solventar esto lo antes posible. Así que solo queda presionar en los juzgados de Mérida para que resuelvan rápido. Por favor, cuando os llegue la admisión de la demanda, facilítame el Juzgado y el número de procedimiento para llamar y exponer nuestro caso, a ver si se apiadan de nosotros. Gracias Saludos Rocío Gracián Fernández ABOGADA C/ Alameda de Colón, 34, 2º-6 29001 Málaga Tlfs: 607650498 - 952600772','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-06-27','miguel, recibo email de Loli del Jzdo de Trujillo nº2 (927-321014)y comunico a Ana y a Inés la citación para revisión de sentencia: Buenos días, acaban de llamarme por teléfono del juzgado de 1º instancia nº2 de Trujillo acerca del procedimiento de revisión de sentencia de Felipe Rodriguez Solis, procedimiento DT 5ª Ley 8/21 nº 230/22. Envian notificación a abogacía para nuestra constancia: Ana.- El día 11-7-22 a las 11h en el juzgado de trujillo tendrá que comparecer ante el forense, que pregunte y allí le indicarán donde es. Asegurate que le acompaña alguien. Inés.-El día 26-7-22 a las 12,15h será el juicio, como no sabemos si abogacía nos enviará la citación, apuntate que hay que pedir videoconferencia, pero no abogado puesto que abogacía es quién debe asistir pues se trata de una revisión de sentencia.','2');
