insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-06-27','miguel, recibo email de la abogada Ana de Pablo: Estimado Miguel Angel, vuelvo a contactar con usted para comunicarle que se va a proceder a la venta de una nueva finca de la herencia de los hermanos Murillo Horrillo y también extinguir el condominio existente entre los cuatro hermanos. Hasta ahora, de la Escritura Nº 151, Escritura de Liquidación de Gananciales, de Aceptación y Adjudicación de Herencias de D. Luis Murillo Ocampos y Dña. Inés Horrillo Carmona, se han vendido: 1º Finca urbana Piso Primero de kale Nagusia Nº 30 de Azkoitia. 71.600€ 2º Finca Urbana Casa número 47 de la calle Malavé de Valle de la Serena.45.000€ -Ahora se va a vender la número 3º Finca Rústica Tierra Agraria en el paraje de Viña de los Carniceros en Valle de la Serena (Badajoz) El comprador es el hijo de Mª Jose Murillo Horrillo, D. Xabier Alberdi Murillo. (19.000€la vivienda y 1.713€ el terreno)Le adjunto el borrador de la Notaría de Azkoitia para esta venta. -Después de escriturar esta última venta (3º) se procederá a una compraventa y extinción de condominio existente entre los cuatro hermanos sobre las restantes 4 fincas rústicas, adjudicándose José Luis Murillo Horrillo los porcentajes de titularidad de sus tres hermanos María Josefa, Andrés e Inés María. Las cuatro fincas son las siguientes, según numeración de la herencia: 4º Finca Rústica.- Tierra agraria en la Solana en Valle de la Serena (Badajoz). 2.861,10€ 5º Finca Rústica.- Tierra agraria en el Paraje de los Moros en Valle de la Serena (Badajoz).1.713,18€ 6º UNA MITAD INDIVISA de la siguiente Finca: Rústica.- Tierra agraria en el Paraje de Cerro Simón en Valle de la Serena (Badajoz).814,16€ 7º Finca Rústica.- Tierra agraria en el Paraje de Sierras Gordas en Valle de la Serena (Badajoz).820€ Le adjunto también el borrador de dicha escritura: José Luis compra a sus tres hermanos las fincas números 5,6 y 7, y se extingue el condominio sobre la finca número 4. Para cualquier duda no dude en preguntarme. También puede contactar con Nagore, de Notaría de Azkoitia, teléfono 943851258 y dirección de correo electrónico notaria@notariazkoitia.com. El comprador de la finca 3º Finca Rústica Tierra Agraria en el paraje de Viña de los Carniceros, D. Xabier Alberdi Murillo, va a abonar el precio mediante transferencia bancaria, por lo que deberá usted indicar a Nagore a qué cuenta deberá realizarle la transferencia de la parte correspondiente a D. José Luis Murillo. Precio total= 20.713€ (corresponde a cada hermano: 5.178,25€) Por otra parte, a la firma de la segunda Escritura el Sepad deberá realizar tres transferencias a nombre de cada unos de los tres hermanos, Mª Josefa, Andrés e Inés María, por importe de 1.552,11€ a cada uno, las tres transferencias al siguiente número de cuenta de Bankinter: IBAN ES 0201280353260100021932. Ninguna de las citadas fincas rústicas está inscrita, pero después de realizar la consulta al registro de Castuera (Badajoz) me aseguraron que no habrá ningún problema en inscribirlas por primera vez, después de que se escrituren las ventas y se envíe toda la documentación. **************************************************** mi respuesta: Buenos días, 1) necesitaré los datos de contacto de la persona que está tramitando la escritura en la notaria de Azkoitia (teléfono e email= 2) hay una cantidad retenida de todos los hermanos que habrá que ver cómo queda repartida después de gastos 3) Estamos de acuerdo con la venta de la finca 3º rústica, para lo cual deberá la notaria tener el número de cuenta de nuestro tutelado como veces anteriores. 4) No se puede proceder a extinción de condominio alguno ya que la autorización judicial era para venta no para extinción de condominio. Pero además el tutelado no está interesado, pues nadie ha consultado a esta comisión en relación a que se adjudique ninguna finca. ******************************** la respuesta de la abogada Ana de Pablo: Buenos días Miguel, si no está autorizada judicialmente la extinción del condominio, se puede hacer la compraventa de las cuatro fincas rústicas (terrenos 4º a 7º). En conversación telefónica mantenida con usted hace tiempo, con anterioridad a la primera venta, ya le comuniqué la intención de mis representados de vender las cuatro fincas rústicas (terrenos 4º a 7º) a su hermano José Luis y le planteé la posibilidad de una extinción de condominio de esa manera. Usted me dijo que sería la Notaría la que tendría que decir cómo se podía efectuar y que si era posible se haría como dijeran desde la Notaría. Consultada por esta parte a la Notaría nos proponen el borrador que le he enviado. Confío en que si no se acepta la forma de extinción de condominio y compraventa, se pueda aceptar por la Junta la compraventa de los cuatro terrenos. Yo misma le comenté a usted la posibilidad de vender a D. José Luis los terrenos y poder extinguir así la copropiedad, respondiéndome usted que sería la Notaría la que estableciera el modo de llevarlo a cabo. Ahora se lo proponemos concretamente mediante el borrador enviado y reitero que, si no es posible hacerlo así por no estar autorizada la extinción de condominio, sí que es posible la venta de los cuatro terrenos al hermano tutelado. En cuanto a los gastos, en base a los movimientos bancarios y facturas de gastos de las fincas heredadas, voy a realizar una liquidación que le enviaré en cuanto pueda. Quedando a la espera de su respuesta, reciba un cordial saludo ************************************************ mi respuesta: Buenos días, la comisión tutelar de adultos no decide la forma de transmisión, si no que a petición de los interesados se solicita a los juzgados. En este caso se solicitó compraventa por lo cual es compraventa el modo en que debe transmitirse. En cuanto a la aceptación de dicha transmisión a favor del tutelado no soy yo quien lo decide, ya que no soy la persona competente, por lo tanto la conversación de la que habla y yo no recuerdo debió de ser mal entendida. Si ustedes tienen la propuesta de compraventa a favor del tutelado tendrá que ser estudiado y ya se les responderá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-06-27','miguel, recibo email de la abogada Ana de Pablo: Estimado Miguel Angel, vuelvo a contactar con usted para comunicarle que se va a proceder a la venta de una nueva finca de la herencia de los hermanos Murillo Horrillo y también extinguir el condominio existente entre los cuatro hermanos. Hasta ahora, de la Escritura Nº 151, Escritura de Liquidación de Gananciales, de Aceptación y Adjudicación de Herencias de D. Luis Murillo Ocampos y Dña. Inés Horrillo Carmona, se han vendido: 1º Finca urbana Piso Primero de kale Nagusia Nº 30 de Azkoitia. 71.600€ 2º Finca Urbana Casa número 47 de la calle Malavé de Valle de la Serena.45.000€ -Ahora se va a vender la número 3º Finca Rústica Tierra Agraria en el paraje de Viña de los Carniceros en Valle de la Serena (Badajoz) El comprador es el hijo de Mª Jose Murillo Horrillo, D. Xabier Alberdi Murillo. (19.000€la vivienda y 1.713€ el terreno)Le adjunto el borrador de la Notaría de Azkoitia para esta venta. -Después de escriturar esta última venta (3º) se procederá a una compraventa y extinción de condominio existente entre los cuatro hermanos sobre las restantes 4 fincas rústicas, adjudicándose José Luis Murillo Horrillo los porcentajes de titularidad de sus tres hermanos María Josefa, Andrés e Inés María. Las cuatro fincas son las siguientes, según numeración de la herencia: 4º Finca Rústica.- Tierra agraria en la Solana en Valle de la Serena (Badajoz). 2.861,10€ 5º Finca Rústica.- Tierra agraria en el Paraje de los Moros en Valle de la Serena (Badajoz).1.713,18€ 6º UNA MITAD INDIVISA de la siguiente Finca: Rústica.- Tierra agraria en el Paraje de Cerro Simón en Valle de la Serena (Badajoz).814,16€ 7º Finca Rústica.- Tierra agraria en el Paraje de Sierras Gordas en Valle de la Serena (Badajoz).820€ Le adjunto también el borrador de dicha escritura: José Luis compra a sus tres hermanos las fincas números 5,6 y 7, y se extingue el condominio sobre la finca número 4. Para cualquier duda no dude en preguntarme. También puede contactar con Nagore, de Notaría de Azkoitia, teléfono 943851258 y dirección de correo electrónico notaria@notariazkoitia.com. El comprador de la finca 3º Finca Rústica Tierra Agraria en el paraje de Viña de los Carniceros, D. Xabier Alberdi Murillo, va a abonar el precio mediante transferencia bancaria, por lo que deberá usted indicar a Nagore a qué cuenta deberá realizarle la transferencia de la parte correspondiente a D. José Luis Murillo. Precio total= 20.713€ (corresponde a cada hermano: 5.178,25€) Por otra parte, a la firma de la segunda Escritura el Sepad deberá realizar tres transferencias a nombre de cada unos de los tres hermanos, Mª Josefa, Andrés e Inés María, por importe de 1.552,11€ a cada uno, las tres transferencias al siguiente número de cuenta de Bankinter: IBAN ES 0201280353260100021932. Ninguna de las citadas fincas rústicas está inscrita, pero después de realizar la consulta al registro de Castuera (Badajoz) me aseguraron que no habrá ningún problema en inscribirlas por primera vez, después de que se escrituren las ventas y se envíe toda la documentación. **************************************************** mi respuesta: Buenos días, 1) necesitaré los datos de contacto de la persona que está tramitando la escritura en la notaria de Azkoitia (teléfono e email= 2) hay una cantidad retenida de todos los hermanos que habrá que ver cómo queda repartida después de gastos 3) Estamos de acuerdo con la venta de la finca 3º rústica, para lo cual deberá la notaria tener el número de cuenta de nuestro tutelado como veces anteriores. 4) No se puede proceder a extinción de condominio alguno ya que la autorización judicial era para venta no para extinción de condominio. Pero además el tutelado no está interesado, pues nadie ha consultado a esta comisión en relación a que se adjudique ninguna finca. ******************************** la respuesta de la abogada Ana de Pablo: Buenos días Miguel, si no está autorizada judicialmente la extinción del condominio, se puede hacer la compraventa de las cuatro fincas rústicas (terrenos 4º a 7º). En conversación telefónica mantenida con usted hace tiempo, con anterioridad a la primera venta, ya le comuniqué la intención de mis representados de vender las cuatro fincas rústicas (terrenos 4º a 7º) a su hermano José Luis y le planteé la posibilidad de una extinción de condominio de esa manera. Usted me dijo que sería la Notaría la que tendría que decir cómo se podía efectuar y que si era posible se haría como dijeran desde la Notaría. Consultada por esta parte a la Notaría nos proponen el borrador que le he enviado. Confío en que si no se acepta la forma de extinción de condominio y compraventa, se pueda aceptar por la Junta la compraventa de los cuatro terrenos. Yo misma le comenté a usted la posibilidad de vender a D. José Luis los terrenos y poder extinguir así la copropiedad, respondiéndome usted que sería la Notaría la que estableciera el modo de llevarlo a cabo. Ahora se lo proponemos concretamente mediante el borrador enviado y reitero que, si no es posible hacerlo así por no estar autorizada la extinción de condominio, sí que es posible la venta de los cuatro terrenos al hermano tutelado. En cuanto a los gastos, en base a los movimientos bancarios y facturas de gastos de las fincas heredadas, voy a realizar una liquidación que le enviaré en cuanto pueda. Quedando a la espera de su respuesta, reciba un cordial saludo ************************************************ mi respuesta: Buenos días, la comisión tutelar de adultos no decide la forma de transmisión, si no que a petición de los interesados se solicita a los juzgados. En este caso se solicitó compraventa por lo cual es compraventa el modo en que debe transmitirse. En cuanto a la aceptación de dicha transmisión a favor del tutelado no soy yo quien lo decide, ya que no soy la persona competente, por lo tanto la conversación de la que habla y yo no recuerdo debió de ser mal entendida. Si ustedes tienen la propuesta de compraventa a favor del tutelado tendrá que ser estudiado y ya se les responderá. ************************************************ Reenvío email a Oscar y Ana Ts: Buenos días adjunto la propuesta de venta de una finca rustica (ya autorizada por el juzgado). El problema viene en que quedarían 4 minifincas rústicas más por vender y los hermanos quieren que se las quede nuestro tutelado. Creo que debemos reunirnos y hablarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2022-06-28','-Amalia . Envio petición a sección eco. Buenas tardes María Teresa. Con motivo de un próxima salida de larga ´duración que Gustavo tiene pendiente de autorizar, , para disfrutarla con su madre, se solicita una transferencia extraordinaria de 500 euros. Seguimos en contacto. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-06-28','EMAIL DE FUTUEX SOBRE JUICIOS Hola de nuevo, Amalia, al respecto de lo que me comentas del señalamiento del proximo juicio de Emlia... pues es que lo tenemos francamente mal para el acompañamiento, se podria intentar pero realmente es un desproposito, a nivel jurido esto. El del otro dia se suspendio para el 21 de julio, y ahora este también y es una frustración porque no sirve para nada mas alla de para generar carga en el juzgado.. alli se desdice de lo dicho.. presenta descarrilamiento, ni siquiera la abogada puede hacer nada.. en fin, te trato de explicar, lo acontecido en otro dia, en Badajoz para tomar constacia.. Está claro, que puede estar en una situación de vulnerabiliad con respecto a esta persona, pero tal y como estructurado, el sistema de juicios en esta materia, pueden encadenarse varios.. no sabemos si podrian valorarla a ella debido a patologia de una forma concreta, o que se establezca de alguna manera. Tal vez ella pueda tener una valoración por el equipo de la clincia forense... que asiste también a las victimas en el juzgado,. Es que terminar por hablar de que "necesita dinero para comprarse brgas" pero no puede hablar de fechas o datos concretos, porque descarrilla. Gestiones Realizadas: Se realiza acompañamiento a cita planificada por una cédula de citación en el juzgado de lo penal nº 1 de Badajoz, citada como testigo en el supuesto quebrantamiento de condena y media cautelar por parte de Miguel Ángel Mateos, (anterior pareja de Emilia). Emilia ha llegado a Badajoz en autobús desde Olivenza y ha sido recogida por este equipo de apoyo social comunitario de Badajoz. En el juzgado, una vez confirmada su asistencia, ha sido informada por su abogada Abdona Maria Cortés Jiménez que, como Emilia en una fecha anterior, libremente ha acudido al juzgado de Olivenza para solicitar que se retire la acusación, Abdona María no puede realizar preguntas a su defendida, sí puede estar presente en sala, nada más. Se nos comunica que, se va a intentar llegar a un acuerdo de conformidad con Miguel Ángel, en caso de reconocerse culpable del quebrantamiento de dicha medida cautelar, tendría una condena de 10 meses de prisión. Como no se encontraba de forma presencial, se procedía a iniciar video conferencia con centro penitenciario. En conversación con él, ha negado los hechos y no acepta conformidad alguna, por tanto, se debe realizar la vista oral. Se le recuerda a Emilia, que le van a preguntar el abogado de Miguel Ángel, el fiscal y puede que también la jueza que preside la sala. Se encuentra citados también como testigos dos monitores de CRR Olivenza, que cuenta que ellos no conocen personalmente a Miguel ángel y que solo saben de la situación lo que Emilia cuenta. Lo que, si podemos afirmar y observar, es que Emilia se muestra muy nerviosa, muy dispersa de pensamiento y descarrilamiento en el lenguaje. No logra poner en claro ni en orden, fechas, horas o cómo fue la situación que se pretende juzgar. Por momento pide que sea juzgado, pero ya presentó renuncia a ello, según confirma la abogada. Es muy vulnerable y Miguel Ángel sigue ejerciendo sobre ella, aun en la distancia, presión y dominio. Siendo Emilia muchas veces la que ha buscado su encuentro o contacto telefónico, o bien Miguel Ángel a través de otros usuarios. La misma situación se vivió el 20 de diciembre de 2021 en el juzgado de Olivenza por la denuncia a Miguel Ángel al presentar se en Olivenza y pegar a un usuario amigo de Emilia, fue imposible que pudiera responder adecuadamente a las preguntas del juez, mostrándose alterada y sin poder exponer la situación real. Como al inicio del interrogatorio de Miguel Ángel, el sistema de video conferencia presenta problemas de audio, la jueza suspende el juicio, con lo que Emilia y los testigos citados ni siquiera entran en sala, siendo citados de nuevo para el 21 de julio de 2022 a las 9:45 horas. Este día, sí estará presencialmente Miguel Ángel en sala, aunque dicen que tendrá un panel de separación, pero quizás puedan verse, algo que no sería conveniente para Emilia, entendiendo que deben evitar su encuentro. Este asunto de quebrantamiento de medidas cautelares, puede ser eterno, ya que Emilia, aquí en Olivenza ha acudido y ha llamado, muchas veces al 112 o a la guardia civil, por el tema de Miguel Ángel. Es cierto que él ha venido, hecho que fue juzgado ya en Olivenza en diciembre. Que Emilia también se ha ido voluntariamente y que, también voluntariamente establece con él comunicación. Y que luego es muy complicado que pueda exponer los hechos tal como han ocurrido, pues es evidente que es inestable y vulnerable. Al final, como sucedió con Almudena Correyero, la relación basada en la violencia machista, que Miguel tenía con ella, solo se pudo cortar cuando ella se institucionalizó en el socio sanitario. No se si cabe interponer algun recurso a nivel juridico, para este procedimiento, o para el del 21 de julio o si igualmente tiene qeu ir.. el esta en este momento en la carcel, asique eso no constituye un peligro para ella.. pero como te digo no terminamos de ver la viaiblidad de poder acompañarla de nuevo, por lo que se desarrolla alli.. no puede ni ser defendida por su abogada de oficio, vamos un desproposito... Ya me dices lo que sea, y si no queda otra, veremos como lo podemos encajar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-06-28','Ángel. Volvemos a contactar con la Notaría de Zafra, para retomar la escritura de aceptación de herencia. Nos indican que Mila ya no trabaja en la Notaría, desde hace 3 años... Envío documentación a notaria.zafra@notariado.org. El oficial se llama Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-06-28','Ana: Me devuelven registrada a fecha de hoy la Solicitud de PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-06-28','Ana: Me devuelven registrada a fecha de hoy la solicitud de PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-06-28','miguel, envío email a Tere y Ana con documentación recibida del juzgado hace menos de una semana requiriéndonos para que en 20 días enviemos la solicitud de revisión de sentencia. Buenos días, hace unos días, me ha llegado requerimiento del Juzgado nº4 de Plasencia requiriéndonos para que les solicitemos la revisión de sentencia: Os adjunto la documentación que han remitido así como el modelo que teníamos para enviar y completar. Echad un vistazo a lo que nos envían y si lo creeis conveniente que desde el centro os remitan los informes médicos y sociales que acrediten si debe modificarse o no la sentencia que en su día se dicto. Si queréis nos sentamos y lo hablamos, pero antes de final de semana necesito que lo tengamos cerrado.','2');
