insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-06-28','miguel, recibimos Angel y yo de Amalia la suspensión del procedimiento abreviado 106/2022 del Jzdo de lo Penal 1 de Badajoz. Reenvío email a Inés para que lo apunte y solicite videoconferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2022-06-28','TERESA Referente a las suspensión del juicio de Juana Nieto. Me dicen que aún no tienen nuevo señalamiento, porque siguen sin forense. El procedimiento es de Revisión de Medidas, pero al parecer, habrá cambio de situación de la curatelada y de ahí lo de la Remoción, que entrará dentro del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-06-28','miguel, envío email a Amalia, Angel, Ines: Buenos días Inés, necesito que apuntes esta nueva citación de Emi. Habla con el juzgado porque el nombre del abogado está creo que cortado o mal (asegúrate que tiene abogado) y solicita por favor videoconferencia Amalia, la cita que tiene mañana es en Don Benito, esta citación es de otro procedimiento en Badajoz, y donde habrán de acompañarla mañana. Adjunto el email que nos comunicaron…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-06-28','TERESA ME LLAMA MARIA ANTONIA PARA PEDIRME IRSE TODO EL MES DE AGOSTO A ZAFRA CON SU PRIMA Y SU TIA HABLO CON M CARMEN SU PRIMA 606044448 Y ME COMENTA QUE SU MADRE ESTA MUY GRAVE EN EL HOSPITAL, QUE SI FALLECE ELLA YA NO SE HARIA CARGO DE MARIA ANTONIA SE LO COMENTO A MARIA TS DE LA PROVIDENCIA Y QUEDAMOS A LA ESEPRA DE VER COMO EVOLUCIONA LA PRIMA ANTES DE TOMAR UNA DECISION MARIA ANTONIA NO ES CONSCIENTE DE LA SITUACION Y PIENSA QUE VA A SEGUIR LA RELACION CON SU PRIMA PERO LA PRIMA LO MANIFIETA CLARAMENTE QUE UNA VEZ FALLEZCA SU MADRE NO QUIERE SABER NADA DE MARIA ANTONIA','2');
