insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-06-28','Amalia : Gastos según cuentas : SEGÚN FICHA DE JUNIO 2022, SE ADOPTAN LAS SIGUIENTES ACTUACIONES INICIALES: COBRA DEPENDENCIA: 87 €/MES APROX. NO PAGA DEPENDENCIA DOMICILIADA...HAY 2 PAGOS X TRANSFERENCIA QUE SUMAN 1.000 €, PERO SE DESCONOCE DESTINATARIO. TIENE GASTOS ASOCIADOS A VIVIENDA X 117 €/MES. AMALIA DISPONE DE UN MÁXIMO DE 1.200 €/MES PARA AYUDA A DOMICILIO Y REINTEGROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-06-28','Ana: Envío correo a Pilar Cerrillo, TS y responsable Calidad Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "Buenas tardes Pilar, Como sabes, el día 17 hablé con Daniel Núñez. Me pidió que esperara pues la semana siguiente él tendría cita con el Alcalde para mantener una reunión en relación a las personas afectadas por la subida de las plazas de los Pisos Tutelados. Le he llamado hoy y me ha emplazado a hablar con al Trabajadora Social del Ayuntamiento de Alcuéscar, pues es lo que acordó con el Alcalde. He llamado a María, pero me informan en el Ayto. que está de vacaciones hasta el día 6 de julio. Por tanto, desde la sección económica, me indican que os traslade, que al menos de momento, se suspenden las transferencias periódicas de 100 € a vuestra entidad, para saldar la deuda de Mateo con la Residencia del Casar de Cáceres, por imposibilidad para hacer frente a todos los gastos. *Conforme evolucione su situación económica se volverá a valorar y se retomarán los abonos en cuanto sea posible. Así mismo, por favor, solicita a las compañeras de la residencia Amada Corral, que se reduzcan todo lo posible los gastos de bolsillo de Mateo, pues aunque no es demasiado, asciende a una media de 90€/mes y tampoco lo puede asumir a partir de ahora."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-06-28','miguel, me escribe Puerto (hermana de la tutelada puertopaniagua@hotmail.com) Estimado Miguel: ya casi van a cumplirse dos meses y aún no sabemos nada, contacté con el abogado hace un par de semanas y me confirmaba que aún no estaba la autorización, no sé si podría informarse de ello. Está todo aplazado esperando la autorización judicial... los demás hermanos de mi madre me preguntan pero les informé que aún no sé nada. ************************************** mi contestación: Buenos días Puerto, te adjunto email y teléfono del abogado que está tramitando este asunto en el juzgado para que te informe de su estado de tramitación: jesusbueno@buenoabogados.com>927 42 26 28 / 606 572 537. *************************************************** recibo email de Jesús Bueno: Jesus Bueno >jesusbueno@buenoabogados.com>:Miguel, habiendo concluido el asunto, por la presente te adjunto mi Minuta de Honorarios a cargo de la tutelada Doña MARIA JESUS MARTIN CALLE, por su importe de Cuatrocientos veintitrés euros con cincuenta céntimos (423, 50 €), a fin de que procedáis a su abono mediante ingreso o transferencia en mi cuenta en CAIXABANK ES57 2100 5422 3713 0011 3197 ***************************************************** escribo a Jesús (Abogado): Buenos días, traslado a la parte económica para que abonen tus honorarios. Pero entonces qué queda pendiente de este expediente? Todavía no me has enviado la firmeza de la resolución no?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2022-06-28','Amalia: se menciona actuación a seguir. Cuando me faciliten nueva CCC en B. Pueyo hago cambio en pensiones , en P.V.S. de dependencia y en domiciliación de la empresa SAD . Llamaré a Juan cuando esté hecho para comunicarle que se le hará transferencia de 800€ al mes sin ningun extra más . Nos tiene que decir en qué cuenta . Se le dará de baja a J.Mª en todas las demas cuentas , él sería conveniente que tb lo hiciera para q no le cobren comisiones. Actualmente saca 1000€ de J. Mª y de ellos abona 700 por SAD . Se le van a dar 100€ más para cubrir manutención y todos los gastos del hermano. Juan seguirá abonando tf y seguro de decesos , asegurar que lo abona. Se le van a ahorra de los 921 - 800 de reintegro , unos 121€ al mes , no tiene ahorros . LLamar a la TS para que lo cite y se lo decimos. ACTUACIÓN: APERTURA CCC EN BANCA PUEYO SÓLO TUTELADO + FACILITAR A AMALIA ESTA CCC + ALTA TERCEROS ORIGINAL: OSCAR EN NUEVA CCC SE DOMICILIARÁN: OAR: OSCAR PENSIONES: AMALIA SEPAD: AMALIA PAGO AYUDA DOMICILIO: AMALIA TRANSFERENCIA PERMANENTE MENSUAL X 800 €/MES (NO SE AUTORIZARÁ NINGÚN GASTO EXTRA) EN EL NÚMERO QUE NOS FACILITE: AMALIA + DECIDIR FECHA A PARTIR DE LA CUAL SE INICIA. DECESO: AMALIA: AVERIGUAR DONDE SE ESTA ABONANDO Y X QUIEN. CCC: AMALIA DEBE INFORMAR A JUAN (HERMANO), QUE DEBERÍA CANCELAR TODAS LAS CCC QUE NO SEAN OPERATIVAS PARA QUE NO LE PASEN COMISIONES. EN ESTA NUEVA CCC NO SE ADMITIRÁ NINGÚN GASTO DISTINTO DE LOS ANTERIORES HAY QUE TENER EN CUENTA QUE NO DISPONEMOS DE SALDO YA QUE GESTIÓN HERMANO HA GENERADO QUE TODAS LAS CCC ESTÁN EN NEGATIVO O EN "0". AHORRO: SE SUPONE QUE AHORRAREMOS AL REDEDOR DE 120 €/MES.','2');
