insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2022-06-29','Ángel. Envío correo electrónico a Amalia: "Buenas, compi, Me ha llamado la cuñada de Ángel. Se llama Ana María Jiménez Morales, con DNI 8822119-D (teléfono 638389678). Me comenta que su suegra, la madre de Ángel, falleció en febrero de este año y que su marido, el hermano de Ángel, ha renunciado a la herencia de su madre, para que, según dice, Ángel tenga un piso donde ir el día de mañana... Mañana va a acercarse a tu oficina, son de Badajoz, para llevarte las llaves del piso, el certificado de defunción de la madre y la renuncia del marido. Llevará un escrito para que le firmes un recibí de lo que te entregue. Ya me cuentas".','2');
