insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-06-29','Ana: Llamada de José Manuel (627 788 797): dice que Pilar Martín, TS del ESM-CC, nos ha enviado un documento para solicitar el "Centro de Día" ········ *Le informo que la secc. ecca. ha aprobado el presupuesto para la compra de colchón en tapiflex. ······· Dice que ha comenzado a usar la dentadura postiza y que necesita pegamento, que con su asignación no le da. Enviará presupuestos de farmacia. ···························································································································································································· Llamo a Guadalupe, TS del SAD del IMAS-CC (927 212 335 / Ext. 4422) para la solicitud del SAD municipal, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-06-07','Ana: Aurora, TS Mancomunidad Comarca de Trujillo (mancomunidadaurora@hotmail.com), nos remite Informe Social para Inventario: "No recibe visitas ni llamadas", "No cuenta con ningún apoyo familiar", "no se relaciona con nadie, deambula por la residencia" "no es problemático, es un usuario tranquilo", "Físicamente no tiene ningún problema de movilidad. El deterioro cognitivo es moderado, si le duele algo, se queja, pero la enfermera tiene que averiguar qué es exactamente porque no sabe comunicarlo. No utiliza pañal, va al baño solo. En las actividades básicas de la vida diaria, con respecto al aseo, se asea pero necesita supervisión del personal de la residencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-06-29','Ana: Aurora, TS Mancomunidad Comarca de Trujillo (mancomunidadaurora@hotmail.com), me remite Informe de Enfermería, Informe de Fisioterapia e Historia Clínica Resumida (MAP).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-06-30','Ana: Aurora, TS Mancomunidad Comarca de Trujillo (mancomunidadaurora@hotmail.com) con copia a Estrella, TS del SSASB de Malpartida de CC (ssb@malpartidadecaceres.es): "Acabo de leer con detenimiento los informes actualizados que me remitiste ayer. Y me temo que de momento no vamos a poder solicitar la revisión del grado de Dependencia, ya que no ha habido un agravamiento en la situación ni un deterioro en sus capacidades. Por experiencia sé que en Dependencia ni siquiera le valorarían. De acuerdo, a los Informes de Fisioterapia y a la Historia Clínica Resumida: “Andrés es un usuario independiente para las ABVD y AIVD, pero debido a su deterioro cognitivo necesita supervisión en algunas tareas” / “independiente para las AVD, aunque dado el deterioro cognitivo precisa supervisión”/ “Barthel: 82 (Dependencia leve). Realiza por sí mismo todas las AVD, excepto el baño.”. E incluso ha recuperado movilidad: “A su llegada al centro utilizaba un bastón para caminar, pero actualmente no utiliza ningún tipo de ayuda (escalas valoradas sin ayuda)” Por tanto habrá que esperar para poder solicitar nueva valoración. Pongo en copia a Estrella, compañera del SSASB de Malpartida de Cáceres, para que esté informada, dado que en la Residencia de Malpartida aún mantienen a Andrés en lista de espera. Es una pena, la verdad, pues su deseo era ingresar en dicho centro y económicamente no se lo puede permitir de forma privada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-06-30','miguel, envío email a la parte social (Amalia y Maite), parte económica (Oscar) y Angel: Buenos días, adjunto borrador para ser completado por la parte social a efectos de solicitar la revisión de sentencia Mercedes, antes de que se nos eche encima el verano. Para ello la parte social debe hacerse con los habituales informes sociales y médicos posibles. Y si la parte económica considera que debe aportar alguna propuesta, pues que nos envíe un informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-06-30','email de Eva trabajadorasocialco@plenainclusionmontijo.org> Buenas tardes. Ayer fuimos a consultar al juzgado cómo iba el tema de la autorización para el cambio de nombre de Joaquín (Cristina) González Millón en el DNI. Me dicen en el juzgado que allí no consta nada de que hayáis solicitado esa autorización. Me ha facilitado un número de teléfono para que lo llaméis y le digáis cuándo se hizo esta solicitud. El número de teléfono es 924459304 *************************************************** contestación jurídica: Buenos días, El cambio de nombre de Joaquín/Cristina no lo hemos solicitado, porque, conforme a la Ley 3/2007, de 15 de marzo, reguladora de la rectificación registral de la mención relativa al sexo de las personas, en su artículo 4, se regulan los requisitos para solicitar la rectificación de la mención registral del sexo, que conllevará el cambio del nombre propio de la persona. La rectificación registral de la mención del sexo se acordará una vez que la persona solicitante acredite que ha sido tratada médicamente durante al menos dos años para acomodar sus características físicas a las correspondientes al sexo reclamado. La acreditación del cumplimiento de este requisito se efectuará mediante informe del médico colegiado bajo cuya dirección se haya realizado el tratamiento o, en su defecto, mediante informe de un médico forense especializado. El Juzgado de Primera Instancia e Instrucción nº 2, de Montijo (Badajoz), dictó Auto, de fecha 24 de noviembre de 2020, autorizando el tratamiento hormonal para cambio de sexo del tutelado don Joaquín González Millón. Contra ese Auto cabía recurso en 20 días. Si no hubo recurso, la firmeza del Auto sería a partir del 22 de diciembre de 2020. De acuerdo a todo lo anterior, los dos años que exige la ley se cumplirían en diciembre de este año, que será cuando podamos solicitar el cambio de nombre en el Registro Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2022-06-30','Amalia : revisado este expediente . Es todo correcto , percibe PFHC + P. Orfandad + Ingresos por trabajo en una empresa de limpieza . Es todo compatible , sólo tiene reducido el complemento a mínimos de la P. Orfandad. Seguimos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2022-06-30','Amalia : revisado este expediente . Es todo correcto , percibe PFHC + P. Orfandad + Ingresos por trabajo en una empresa de limpieza . Es todo compatible , sólo tiene reducido el complemento a mínimos de la P. Orfandad. Seguimos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-11-24','SOBRE EL CAMBIO DEL DNI De: MIGUEL FERNANDEZ DE LLERA Enviado el: miércoles, 30 de junio de 2021 12:21 Para: Eva Álvarez >trabajadorasocialco@plenainclusionmontijo.org> Asunto: GONZALEZ MILLON Buenos días, hemos solicitado en reiteradas ocasiones al juzgado de Montijo nº2 que nos remita la resolución firme de la autorización judicial para el tratamiento hormonal. Hoy mismo he solicitado de nuevo dicha resolución. Con lo cual no es necesario firmar ninguna autorización si ya lo está autorizando el juzgado. Por lo tanto, una vez que recibamos la firmeza del juzgado os la trasladaremos a efectos de que inicieis el tratamiento hormonal. Una vez se finalice dicho tratamiento necesitaremos informe médico acreditando la finalización del cambio de sexo y a partir de ahí con vuestra ayuda procederemos al cambio de nombre en Dni, tarjeta sanitaria, etc. Un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-06-30','Ana: Correo de Felipe, Ed. CAM Fco. Pizarro (educadores.cam.franciscopizarro@salud-juntaex.es): "...comunicarte que habíamos solicitado un campamento para Juan José González Casares desde 23 julio al 28 julio. Mandamos toda la documentación que exigía el campamento y han comprobado que es mayor de edad, y lo han rechazado."','2');
