insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-06-30','TERESA ACUERDO CTAEX (TERESA/MIGUEL/ALBERTO): ABONAR EL COSTE DE LA OBRA DE LA VIVIENDA: 2.333 € (IVA INCLUIDO) TERE: HABLA CON LA EMPRESA CONSTRUCTORA PARA ORGANIZAR OBRA Y PAGOS. TERE. DEBE RECABAR CONFORMIDAD X ESCRITO DE TUTELADO....MIGUEL: ES VÁLIDO QUE EL TUTELADO LE FIRME A TERE UN "ACEPTO Y CONFORME" EN EL PRESUPUESTO??? MIGUEL: LA DEUDA DE COFIDIS SEGUIRÁ SU CURSO HASTA QUE EL JUZGADO DETERMINE CUANTO Y CUANDO. ESTRELLA: ABONAMOS LA FACTURA CONFORME A LO QUE NOS VAYA PASANDO TERE, CON EL LÍMITE YA MENCIONADO. ________________________________________','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2022-06-29','Ana: Correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es): "Buenas tardes, desdes el CEAPAT nos envían información de un estudio que se está llevando a cabo desde la fundación ONCE para que personas con problemas de habla puedan participar en un banco de muestras para adecuar el reconocimiento de voz a todos tipos de habla y así poder facilitar este recurso a todas las personas que presenten problemas a este nivel. Nos invitan a participar en el proyecto, pues cuantas más muestras se consigan, mejores resultados se obtendrán. Si pinchas en el enlace https://docs.google.com/forms/d/e/1FAIpQLSc9tkmL5VwSP88nGHULo6NauivSLgEBxgR3vO9knc1P4cvsUA/viewform?resourcekey=0-nNMgUv0K876UAOCbu7i2zw se explica muy brevemente en qué consiste el proyecto. Se lo he comentado a Mabel y le parece muy buena idea, pero una de las personas que he considerado que puede participar es Maribel Debón y me ha dicho que te lo comente por si hay que informar a sus tutores al estar tutelada. La recogida de muestras sería leer 1300 frases. Es pesado y llevaría una total de 7 horas aproximadamente la grabación con cada uno de ellos (según tienen estimado), pero cuantas más muestras, mayor facilidad para que google pueda reconocer estos tipos de habla. Si los participantes terminan toda la grabación, le regalarían una tarjeta regalo de 300 Euros por haber participado en el proyecto (Esto no se lo he dicho a Maribel, porque no se si acabará todo el proyecto, si será cierto.... y por no hacer ilusiones)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2022-06-30','Ana: En relación al correo de ayer, y tras intercambiar correos al respecto con Felisa Custodio y Asesores Jurídicos CTAEX, confirmo a Felisa que Maribel, si es su deseo, puede participar, sin ser necesaria autorización del Representante Legal ni comunicación al Juzgado.','2');
