insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-06-30','TERESA CITA PARA VALORACION DEPENDENCIA EL 7 DE JULIO SE LO COMUNICO A FUTUEX PARA QUE ESTE ACOMNPAÑADP EMIAL FUTUEX está "remataito" ultimamente, llamando muy enfadado, acordandose de las gallinas.. y amenzando con no ir a la farmacia a tomarse la mediacion (estan colaborando en que vaya alli a tomarsela por suerte) esperemos que no siga por este camino, porque en el momento que deje de tomarse la medicación es muy probable que vuelva a beber','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-07-01','Ana: Paso a Julio, Aux. Amtvo. CTAEX, para que de REGISTRO en SIREX, las Aceptaciones PIA de Valentina: Servicio de Atención Residencial y Prestación Ecca. vinculada al SAR. Éste último con el Alta de Terceros, Contratos de la Residencia (2013 y 2022) y Tarifa de Precios y Servicios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-07-01','miguel, Buenos días, os doy la buena noticia del día. Acabo de hablar con el Juzgado nº1 de Jerez de los Caballeros, y justo estaban preparando una resolución para preguntarnos cómo devolvernos el sobrante de lo que se le retuvo para la famosa ejecución de Cofidis (previa a nuestra asignación como tutores). Les he dado el número de cuenta de Anastasio Vaquerizo de Ibercaja que tenéis parte económica en la hoja excell: ES41 2085 4511 9103 3248 2021 Le van a devolver unos 1.541,40€, lo cual entiendo soluciona los problemas que decía Tere. El ingreso de este dinero no será antes de 3 semanas porque la Secretaria Judicial, que tiene que dar la orden está de vacaciones las próximas dos semanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2022-07-01','Ana: Llamada de Mª José Polo, TS SSASB de Zarza de Granadilla (664 018 209). Florencia lleva mucho tiempo sin poder ver y estar con su madre, Marcelina Martín Mateo, cuya tutela finalmente concedieron a la hermana de Florencia. *Mª José me informa que Marcelina ha ingresado recientemente en la Residencia de Mayores Los Molinos de Montehermoso y pregunta constantemente por su hija Florencia, puesto que han vivido siempre juntas, no se han separado hasta que Florencia ingresó en la Residencia. *Propone el traslado de residencia de Florencia con su madre. **Ha hablado con Pedro, TS de la Gerencia Territorial y dada la situación y puesto que hay plazas libres, dice que enviemos la solicitud a su correo. ·············· Llamo a Fermina, Directora de la Res. de Aldea del Cano (646 437 879): según las Auxiliares, Florencia no suele preguntar directamente por su madre, pero cuando habla con su hermana, quien le llama muy de vez en cuando, sí le pregunta cuándo se la va a llevar de allí. ··································································································································· Pongo para la firma de la Directora General de SSSS, por Suplencia, la SOLICITUD DE TRASLADO de residencia vía decreto por reagrupamiento familiar. ································ A petición de Pedro Sánchez, TS Gerencia Territorial, llamo y envío correo a Fermina (ferminasanchezgarcia@gmail.com): "Tal y como hemos hablado, quedo a la espera del Informe Médico de Atención Primaria. * Por cierto, sería necesario que el médico especifique en el mismo que en la actualidad Florencia está ESTABLE A NIVEL PSICOPATOLÓGICO y NO PRESENTA ALTERACIONES DE CONDUCTA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-07-01','Ana: Envío a Julio, Aux. Adtvo. CTAEX, oficio y solicitud de SAD municipal para que le dé registro en SIREX, para remitir al IMAS-CC, junto a toda la documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2022-07-01','miguel, me llama el tutelado informando que tiene una vivienda que está a nombre de su padre fallecido y hay que hacer la herencia. Tras asesorarle de los pasos notariales y judiciales que habrá que hacer, y viendo el dinero que tiene acordamos que se centralice en la gestoria gefiscal el trámite, así que pedirá cita y llevará lo que tiene y les dará mi teléfono para nos den precio y coordinemos con ellos todo el trámite','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-07-01','TERESA El programa de familia me comunica que Aitor se ha abierto una nueva cuenta, que ha contratado wi-fi y televisión y alguna cosilla más Desde el programa de familia no le pueden hacer seguimiento pues no les deja acceder a la vivienda, tan solo les acompaña a realizar la compa semanal al supermercado Coviran. Ya he comunicado también a la sección eco para que gestionen en tema de la cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-07-01','miguel, asisto por videoconferencia al procedimiento DPA Diligencias previas de Procedimiento abreviado 581/2021 del jzdo nº5 de Cáceres, donde le nombran un abogado de oficio para la defensa, pero él no acude. Desde el juzgado no le han notificado la citación directamente, sino que lo hicieron a nosotros. Doy los datos de la actual residencia donde reside a la juez: Centro de acogida temporal Centro Vida, Avda Juan Pablo II, 4, Cáceres (tlfno 927-23-50-82 y 927-239398). El juzgado enviará orden de detención a la policía. Se suspende el procedimiento hasta que nos avisen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-07-01','TERESA Acabo de hablar con el Juzgado nº1 de Jerez de los Caballeros, y justo estaban preparando una resolución para preguntarnos cómo devolvernos el sobrante de lo que se le retuvo para la famosa ejecución de Cofidis (previa a nuestra asignación como tutores). Les he dado el número de cuenta de Anastasio Vaquerizo de Ibercaja que tenéis parte económica en la hoja excell: ES41 2085 4511 9103 3248 2021 Le van a devolver unos 1.541,40€, lo cual entiendo soluciona los problemas que decía Tere. El ingreso de este dinero no será antes de 3 semanas porque la Secretaria Judicial, que tiene que dar la orden está de vacaciones las próximas dos semanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-07-01','TERESA Ya ha hablado previamente con el dueño del Bar, Toni (625 66 65 95) sobre la transferencia periódica de 200€ que realizará la comisión para el abono del servicio y le ha parecido muy buena idea. que el pasado 20 de Junio se conversó telefónicamente con María Gordillo (665 61 26 77) una mujer de Villafranca que tiene experiencia como auxiliar de ayuda a domicilio y de la que se sabe que está acostumbrada a trabajar con perfiles complicados por Marisa de los SSB, de hecho fue ella la que facilitó su teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-07-01','Ana: Correo de Icíar, secc. ecca: "Mira, me ha llamado la trabajadora social de Aliseda, Eva Jiménez 655093822 – evajimenez@tajosalor.es, en relación con una persona nueva que ha entrado, tan nueva que yo no tengo aun carpetilla, igual me la ha dejado en estos días Julio en mi mesa, se llama Miguel Ángel Ramos Andrés, curatela representativa. Comenta la TS que no nos puede enviar ningún dato porque esta persona no vive actualmente en la localidad, ha estado de ocupa en algún edificio derruido, y ahora ella cree que está en la cárcel, pero no está segura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-07-04','TERESA NOS LLEGA DENUNCIA DE QUE MARIA HA ROTO UN CRITAL QUE HABIN EN LA CALLE, ACEPTAMOS PAGAR ANTE LA DENUNCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-06-30','Ana: Correo de Carolina, Psicógologa CRR (psicologia.crrplasencia@grupo5.net): "Hola Ana! Hoy hemos realizado la entrevista de incorporación de Javier Agudo, todo ha ido bien y él ha mostrado muchas ganas de venir al CRR. Hemos acordado como fecha de ingreso el martes 5, respecto a la asignación mensual hemos planificado 400 €, que incluyen dinero de bolsillo, higiene, tabaco, farmacia y compras cotidianas y necesarias. Él considera que puede ser autónomo para la retirada del mismo, aunque se lo custodiariamos en el centro. No precisa acompañamiento, aunque al principio haremos entrenamiento para tal fin." ················································· Raquel Gómez, Enfermera Secc. Acceso a RR Salud Mental, me entrega la resolución del PIA, reconociendo a Javier el Serv. de Promoción de la Autonomía Personal, adjudicándole plaza, por emergencia social, en el CRR-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-06-30','Ana: Correo de Carolina, Psicógologa CRR (psicologia.crrplasencia@grupo5.net): "Ayer se incorporó Julia Morón, estuvo Gloria de Futuex, sin incidiencias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-06-30','Ana: correo de Óscar, sección ecca. a Ángela, Placeat: "Se acepta el presupuesto “verbal” de 200€ aprox. Nos enviáis la factura con el número de cuenta para realizar la transferencia." ············ el presupuesto de taxi es para acudir de vacaciones unos días al domicilio de su tía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELESTINO'and edp.apellido1='NAVARRETE'and apellido2='MURGA'),'2022-07-04','TERESA RECIBO LLAMADA DE VANESA LA DIRECTORA DE HERNANDO DE SOTO 21781 COMUNICA QUE CELESTINO LLEVA VARIOS DIAS SIN ACUDIR A DORMIR PASA POR LA RESIDENCIA PERO SE VUELVE A IR ME COEMENTA QUE HAN ENTRADO EN LA VIVIENDA Y HAY UNA GRAN ACUMULACION DE ENSERES QUE HA TRAIDO DE LA CALLA ESTA EN COMUNICACION CON EL CONCEJAL PARA DAR UNA SOLUCION A LA LIMPIEZA DE LA VIVIENDA LE SOLICITO INFORME SOCIAL DE LA SITUACIO PARA ENVIAR AL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-07-04','TERESA EMAIL FUTUEX Se ha conversado telefónicamente en las últimas semanas con María Murillo Delgado que reside en un piso de alquiler en Monesterio. Se la ha encontrado bastante estable, ya que se levanta sobre las 11 y saca a pasear a Nerón un par de veces al día. Por conversaciones con la tutelada y con el servicio de salud mental de Llerena, se tiene conocimiento de que las citas con su psiquiatra, el Dr. Idilio, son telefónicas y relativamente frecuentes, cada tres meses más o menos. En esas conversaciones, María se limita a pedirle la medicación que en ese momento le apetece tomar, ya sean antidepresivos, o ansiolíticos,... y el psiquiatra se lo dispensa sin hacerle muchas preguntas. María también ha comentado que a veces se toma la medicación y a veces no, no hay una norma establecida para ella, además consume alcohol y fuma maría. María estuvo recibiendo llamadas de la psicóloga del CEDEX de Llerena porque tuvo un buen apego con ella pero al cabo de unos meses se cansó de estar pendiente del teléfono y no ha vuelto a coger más llamadas suyas. María tiene un perfil muy complicado, ya que tiende a la delincuencia habitualmente, es caótica y al mismo tiempo es bastante agresiva y de carácter fuerte, como sabeis. Está acostumbrada a manejar su dinero a su antojo y se cree que si se hace un intento de rebajar su asignación, puede descontrolarse de una manera inimaginable. No se intenta justificar con esto su mal comportamiento y el vandalismo que ejerce en las calles de su localidad, solamente se intenta plasmar la visión del equipo social comunitario que la visita con regularidad. Y que en esta situación la gestión restrictiva de su dinero, no serviria para controlar la conducta, sino para acrecentarla, porque seguiría actuando de modo similiar.. pero sacando el dinero, de forma ilicita.. por ej.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-07-04','Ana: Envío correo a Carolina, Psicóloga CRR: "En cuanto a la documentación que remites relativa a Julia Morón Hernández: - El de “Derechos de la personas atendidas” no me permite abrirlo ni descargarlo - El “Contrato de rehabilitación” te lo envío adjunto, ya firmado y sellado - La Autorización para procedimientos médicos de urgencia, te lo adjunto también, firmado digitalmente - Y los otros dos: o Derechos de imagen o Autorización de salidas De acuerdo a la actual Ley 8/21 de 2 de junio, si Julia entiende los términos de los mismos, que en este caso creemos que así es, es suficiente con su firma. Ya no es necesario que los firme su representante legal. Con respecto a esto último, si te viene bien, podemos llamarte Miguel, Asesor Jurídico, y yo y si tenéis alguna duda él está encantado de solventarla."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-07-01','Ana: Correo de Blanca, Directora CRR Plas (direccion.crrplasencia@grupo5.net): "Buenas tardes, os informamos que Concepción Fernández Muñoz ha dado positivo en covid. Se encuentra bien de síntomas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-07-04','Ana: Envío correo a Toni-Futuex: "En relación a FELIPE RODRÍGUEZ SOLÍS, la semana pasada llamaron a Miguel, Asesor Jurídico, desde el Juzgado de 1º instancia nº2 de Trujillo acerca del procedimiento de revisión de sentencia, (procedimiento DT 5ª Ley 8/21 nº 230/22). El día 11-7-22 a las 11h, en el juzgado de Trujillo, Felipe tendrá que comparecer ante el forense. Que pregunte y allí le indicarán donde es. Es imprescindible que acuda acompañado, ¿podríais confírmanos que la Educadora podrá ir con él?" ··································· Respuesta de Toni: "Hola Ana, buenas, si lo acompañará Gloria que es la educadora que lleva su seguimiento.. lo dejamos anotado ya."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-06-27','Ana: correo de Toni, TS C.R. Cervantes (antonia.dediego@salud-juntaex.es): "Eugenia Pacheco Vicente el día 28 de junio del 22, se marcha en autobús a Plasencia a ver a Pedro (su pareja), como te comunique el martes de la semana pasada por teléfono. Marcha en el autobús de las 11h (Cáceres- Plasencia) y regresa en el autobús de las 15h (Plasencia -Cáceres). Cada billete le supone 8,25€, pero nos comenta que ella tiene ahorrado dinero y que no necesita pedir a la comisión dinero para realizar el viaje."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-07-04','Ana: correo de Toni, TS C.R. Cervantes (antonia.dediego@salud-juntaex.es): "Con respecto al viaje de Eugenia todo salió perfecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2022-07-04','Ana: Correo de Ángela, Directora Placeat (directora@placeat.org): "Te comento que María desea lógicamente ir a visitar a Benedicta a la residencia Masside en Aldeanueva del Camino, hasta ahora la hemos estado llevándola desde el centro, graciablemente, pero tenemos más usuarios en situaciones parecidas, y cada uno abona su gasto. Hemos contactado con un taxista de Plasencia, y nos ha comentado que el coste sería 45€, ida y vuelta y permanecer una hora en espera. La visita está concertada para este jueves 7 de julio a las 12h. En caso de efectuarse mandaría la factura del Taxista con número de cuenta para el abono de la misma. En otro orden de cosas también te comento que Maria ha sido invitada por la familia de un usuario del centro , "su novio" a pasar una semana de vacaciones en Guadalajara en casa de la hermana de éste, ( tiene casa con piscina), la recogerían los padres del chico . Sería del 13 al 21 de agosto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-07-04','Ana: Alberto, jefe secc. ecca., da "OK A 400 €/MES REINTEGRO PARA TUTELADO A PARTIR 01/07/2022."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-07-04','Ana: Correo de Ana Benavente, TS ESM Plas: "Te envío el justificante del pago de alquiler del piso de María Antonia. Si tienes cualquier duda o algo que consultar me lo dices" ·············· Lo paso a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-07-04','miguel, envío de email de la hermana del curatelado a Amalia: Hola Amalia buenos días, Alberto ha recibido una nota judicial que dice que en tres días tiene que ingresar en prisión. Podemos hablar por favor. Lo ideal sería en todo caso que entrara en el centro sociosanitario de Mérida. Reciban un cordial saludo. Muchas gracias. El 24 may. 2022 19:13, anusky ramos blanco >IMCEAEX-_O=FIRST+20ORGANIZATION_OU=EXCHANGE+20ADMINISTRATIVE+20GROUP+28FYDIBOHF23SPDLT+29_CN=RECIPIENTS_CN=0006BFFD99EE5925@sct-15-20-4755-11-msonline-outlook-91991.templateTenant> escribió: Buenas Tardes Amalia, Alberto quiere irse a Holanda, dice que ha trabajar, pero no está del todo bien y quisiéramos saber si se le puede impedir. ¿Podrías llamarme por favor? Le dejo mi número de teléfono, 605805277. Muchas gracias. Reciba un cordial saludo. Ana Ramos Blanco *********************************************** recibo email de Amalia: Buenos días , os remito notificación judicial que envia su hermana. Parece que tiene que ingresar en prision en 3 días . La hermana pregunta si es posible ingresar en CSS . Le he pedido que nos remita la notificación y es lo que os paso. Es curatela económica . Por favor , ponedme en copia a la respuesta que deis a la hermana para que yo también lo sepa . Un saludo **************************************************** mi contestación a Amalia: Hola Amalia, este procedimiento está en ejecución como sabes, y dieron la suspensión del mismo, pero por reincidencia durante el periodo de suspensión le harán pagar la deuda. A estas alturas sólo queda que hablen con el abogado que les representó. Entiendo que por ahora no hay nada que se pueda hacer. No obstante si su abogado estima que podemos aportar algún informe que facilite su posterior traslado a un centro adecuado a su patología, que se pongan en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2022-07-04','miguel, email de Tere: MIGUEL ES IMPORTANTE ESTE CASO QUE SE HA PEDIDO LA REMOCION, YA VA PARA TRES MESES, A VER SI TE PUEDEN DECIR ALGO PORQUE CARMELO AMENAZA CON PONERSE EN HULEGA DE HAMBRE¡¡¡ ESTE CASO ESTA MAS QUE CLARO Y JUSTIFICADO QUE DEBE RECUPERAR SU CAPACIDAD NO NECESITA MEDIDAS DE APOYO ********************************************* mi contestación: Tere, acabo de hablar con el juzgado, pensaban que el escrito que hicimos era solo solicitud de rendición anual de cuentas. Dice que tiene que verlo el letrado de justicia (antes secretario) y hasta la segunda quincena de julio no viene con lo que no nos puede contestar nada al respecto. Habla con él y dile que si quiere recuperar su capacidad tendrá que demostrar estar tranquilo y tener paciencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-07-04','Ana: Tras haberlo valorado con la secc. ecca., se considera necesario solicitar el Complemento a tercera persona de la PFHC. ··········· Cumplimento la Comunicación de Variaciones indicando la valoración de Grado II de Dependencia y lo subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-07-05','Ana: Llevo al registro del SES comunicación de variaciones para SOLICITAR COMPLEMENTO ATP de la PFHC, junto con Cdo. de Discapacidad y Resolución del Grado de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FERNANDEZ'and apellido2='RAMOS'),'2022-07-05','Buenos días, compi, Han citado a Francisca Fernández Ramos en el Juzgado de Primera Instancia e Instrucción, nº 1, de Mérida, para el día 11/10/22, a las 10:15. Es para entrevistarla personalmente. Creo que está en el Sociosanitario de Mérida, no?. Es para que alguien del centro la lleve ese día al Juzgado. Un saludo. -------------------------------------------------- Amalia , lo comunico al CSS con la cita del señalamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FERNANDEZ'and apellido2='RAMOS'),'2022-07-05','Buenos días, compi, Han citado a Francisca Fernández Ramos en el Juzgado de Primera Instancia e Instrucción, nº 1, de Mérida, para el día 11/10/22, a las 10:15. Es para entrevistarla personalmente. Creo que está en el Sociosanitario de Mérida, no?. Es para que alguien del centro la lleve ese día al Juzgado. Un saludo. ------------------------------------- Se lo reenvío al CSS','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-07-05','Psicologia CRR Merida Buenos días, en referencia a Damián Granados, quería informaros de que ha pasado a pisos supervisados esta misma semana. En lo sucesivo, irá aumentando su gestión autónoma de medicación, así como manteniendo su gestión económica. Seguimos en contacto, Un saludo,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2022-06-24','Ana: Según informe social para la rendición anual "Dª Luisa Rey Campón ingresó en el Centro Residencial San Francisco tras resolución de ingreso por grado II de dependencia, encontrándose en ese momento ya tutelada por la Comisión Tutelar de Adultos de Extremadura. La relación con sus hermanos es muy esporádica, en alguna ocasión han venido a verla o han llamado por teléfono.", "...dependiente en la mayoría de sus ABVD, puede deambular, pero bajo supervisión y con apoyos.En la actualidad su trastorno mental, le han producido importantes cambios conductuales, con agresividad hacia todo su entorno, por lo que ha sido necesario su derivación a la unidad de Salud Mental para reajustar tratamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-06-24','Ana: Según informe social para la rendición: "No constan relaciones actuales de familiares, ni recibe visitas ni llamadas de ninguno.", "Recibe visitas esporádicas de trabajadores de su anterior residencia en Jaraicejo.", "En la residencia sí se relaciona con todos así como con los vecinos del pueblo, de forma normal. Les hace visitas a sus casas a los trabajadores, mantiene buena relación con todos, no es conflictiva, al menos de momento, ya que en la anterior residencia sí tuvo algún altercado. Tiene un grupo de amigas, con las que suele ir a misa, y además se relaciona con todo el mundo, es muy sociable y le gusta mucho hablar.", "...Actividades básicas de la vida diaria todo por ella misma, e incluso a veces te pide la fregona para limpiar cualquier cosa que se le ha caído.", "Actualmente tiene una úlcera en la pierna. Hace poco le han detectado que tiene el azúcar un poco elevado.", **"no quiere regresar a Jaraicejo y que quiere quedarse en la Residencia de Torrecillas de la Tiesa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-07-05','miguel, recibo email de Amalia: Buenas , Miguel te reevío email de la hermana de Alberto . Siguiendo tus indicaciones ha contactado con un abogado , pero tienen alguna duda jurídica. Tienes su tf en la intranet para que te pongas en contacto con ella. *************************** email que mandó Ana Ramos a Amalia: Buenas tardes Amalia, Nos hemos puesto en contacto con un abogado, José Antonio Romero Porro. Cuando puedan, ponerse en contacto conmigo. *********************************************** Hablo con Ana Ramos tlfno 605805277, me pregunta si es posible que cumpla la sentencia en un centro de la junta, le explico que está en ejecución y por tanto tiene ya que entrar en la cárcel. Han puesto el caso en manos del abogado José Antonio Porro. Le doy mi número de teléfono email para que se lo de al abogado a efectos de nos vaya solicitando lo que vaya necesitando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-06-27','Ana: El informe social del SSASB de Navas del Madroño para la rendición, hacer un recorrido por la historia familiar más relevante. Además hace mención a la situación actual: "...aunque tiene plaza en Adiser Castuera se encuentra desde hace unos días en Navas del Madroño, en la vivienda de su madre, con una pareja, situación que ha ocasionado conflictos entre todos ellos, aunque principalmente entre su pareja y la de su madre, situación en la que han tenido que intervenir las fuerzas del orden público". "Cuenta con una vivienda social en régimen de alquiler... con todos los servicios que garantizan unas buenas condiciones de habitabilidad y a fecha actual la ocupa su hijo, y la pareja de éste.", "Felisa goza de buena salud, y acude periódicamente a consulta de ginecología, planificación familiar, oftalmología y odontología, acogiéndose al plan de salud bucodental para personas con discapacidad, con lo cual se ha beneficiado de un tratamiento dental restaurador gratuito". "La relación madre-hijo, es de mucha afectividad, pero la discapacidad que presenta afecta a la relación, entendiéndose que se trata más de una relación entre iguales, que materno-filial, siendo Aitor el miembro dominante", "...buena relación con los vecinos de la localidad, aunque nunca ha contado con un grupo de amigos definido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-06-28','Ana: Informe social para la rendición anual: "...sus dos hermanas vienen a visitarla de vez en cuanto, la última vez ha sido el 16 de mayo. Y mantiene contacto telefónico con ellas." "Este año ha tenido varios conflictos con residentes con intercambio de insultos. Sus compañeros han manifestado en varias ocasiones que les ha increpado. Sigue pidiendo dinero y tabaco tanto a residentes como a trabajadores. ... desde el centro se ha trabajado con ella sin obtener resultados" "...la residente está cada vez menos adaptada al centro manifestando en reiteradas ocasiones su deseo de traslado a otra residencia".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2022-07-05','Ana: correo de Pedro Sánchez, TS SS.TT. (pedro.sanchezsanchez@salud-juntaex.es): "Buenos días Ana Te paso Aceptación PIA para la firma del DG Esta señora ingresó vía Decreto (art´. 18), que regula el procedimiento de EMERGENCIA SOCIAL, pero tiene reconocido GII, por lo que vamos a intentar resolver la plaza vía dependencia para que el IMSERSO pueda sufragar el coste de la misma" ··················· Le devuelvo la Aceptación PIA firmada y sellada por el Representante Legal. ······························································································································································································ Llamada de Pedro Sánchez, TS SSTT CC (64729): El traslado y la concesión de plaza se hace finalmente vía Dependencia, si no envían el informe médico, no pasa nada. *En cuanto esté la resolución me la enviarán y me pondrán en contacto con la TS de Monte Hermoso para organizar el traslado. *Habrá que contratar un taxi. ··· El plazo para el ingreso es de 15 días. ···························································································································································································· La Resolución del Grado de Dependencia NO está subida a SIDEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-06-07','-Amalia , escribo a Julio . Buenas , ha fallecido en DOMUSVI , está en medicina forense , era joven . Tenía seguro decesos que se encargará del funeral . La residencia va a cargar en cuenta todo lo que se debe , lleva sólo un par de meses allí , ha sido trasladada desde Caser . Lo harán en unos días y luego se puede proceder a la declaración final de cuentas.','2');
