insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-06-07','-Amalia , escribo a Julio . Buenas , ha fallecido en DOMUSVI , está en medicina forense , era joven . Tenía seguro decesos que se encargará del funeral . La residencia va a cargar en cuenta todo lo que se debe , lleva sólo un par de meses allí , ha sido trasladada desde Caser . Lo harán en unos días y luego se puede proceder a la declaración final de cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-07-05','At. Cliente Ciudad de Badajoz >atcliente.cbadajoz@domusvi.es> Buenos días Amalia, Imposible poder comentarte como se gestionó el sepelio de M. Ángeles. No aparece nada en su expediente y he preguntado a un par de compañeras que tampoco me ha sabido aclarar nada. Sí te puedo dar el contacto de su familiar más cercano; Juana Macedo Blanco 685888046 La próxima semana regresa de sus vacaciones Carmen (TS), a quien pongo en copia de este correo para que esté informada. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-07-05','At. Cliente Ciudad de Badajoz >atcliente.cbadajoz@domusvi.es> Buenos días Amalia, Imposible poder comentarte como se gestionó el sepelio de M. Ángeles. No aparece nada en su expediente y he preguntado a un par de compañeras que tampoco me ha sabido aclarar nada. Sí te puedo dar el contacto de su familiar más cercano; Juana Macedo Blanco 685888046 La próxima semana regresa de sus vacaciones Carmen (TS), a quien pongo en copia de este correo para que esté informada. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-07-05','At. Cliente Ciudad de Badajoz >atcliente.cbadajoz@domusvi.es> Buenos días Amalia, Imposible poder comentarte como se gestionó el sepelio de M. Ángeles. No aparece nada en su expediente y he preguntado a un par de compañeras que tampoco me ha sabido aclarar nada. Sí te puedo dar el contacto de su familiar más cercano; Juana Macedo Blanco 685888046 La próxima semana regresa de sus vacaciones Carmen (TS), a quien pongo en copia de este correo para que esté informada. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2022-07-05','Ana: Tras trasladar a Ángel, Asesor Jurídico, la consulta telefónica que me hizo Mariví Clemente, TS CSS-Plas. (victoria.clemente@salud-juntaex.es): Le envío un correo: "En relación a MARÍA TERESA GÓMEZ NEVADO, Ángel, Asesor Jurídico, me transmite que es una cuestión complicada, hace bastantes años que estuvo con esto. El principal problema para la resolución de la herencia, es las malas relaciones existentes entre los numerosos hermanos y hermanas. Al parecer en su día se solicitó y concedió abogado de oficio para Teresa. Pero éste terminó agotado con el caso, decía que era imposible, pues les pedía información y documentación y no colaboraban, se planteó solicitar los documentos vía judicial, pero desconocemos si llegó a hacerlo. Finalmente este abogado ya no está en el turno de oficio, pero igualmente Ángel le preguntará. Según Ángel, lo primero es que pongan de acuerdo entre las y los hermanos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-06-29','Ana: A petición de Miguel, envío correo a Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "En relación a Andrés Silva Bonifacio, nos solicitan desde el Juzgado que instemos el procedimiento de revisión de su sentencia en base a la nueva Ley 8/21, de 2 de junio. Para ello, es necesario que presentemos Informe Médico de Psiquiatría actualizado e Informe Social del Recurso en que reside. A parte de estos dos, si lo considera la coordinadora de la UHDAC, se podría añadir Informe Psicológico, yo creo que sería conveniente. Como ya sabéis, con la actual ley, en la nueva sentencia habrán de especificar muy bien los términos en los que la persona requiere medidas de apoyos, por lo que, cuanto más específicos sean los informes al respecto mejor, pues en ellos se van a basar en el Juzgado para redactarla. Por supuesto, en el escrito que se redacte desde el Gabinete Técnico de la CTAEX, se tendrá muy en cuenta el criterio clínico y técnico que se desprenda de vuestros informes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-07-05','Ana: Llamada de Ana, TS de la Mancomunidad de Hurdes (927 122 367 / J y V en Azabal: 927 436 073). El padre de José Aº falleció hace unos 4 años apróx. y quieren solicitarle la P. de Orfandad. *Según nuestros datos percibe una Pensión de Incapacidad Absoluta, pero no tenemos Cdo. actualizado, no hemos recibido cartas de revalorización. *No sé si le corresponderá dicha pensión. ·········· *Su madre aún vive, percibe una P. Viudedad. ····· *Ana, TS, intentará recabar los datos y Cdo. de Defunción para que podamos solicitar la Pensión de Orfandad. ················· Me enviará también copia del DNI actualizado para el expdte. ································································································································································································ La Resolución del Grado de Dependencia no está subida a SIDEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2022-07-05','Amalia . Envio a Leonor por correo ordinario la solicitud de plaza por decreto para que Antonia lo firme si quiere ingresar voluntariamente . Tengo en la carpte del ingreso los informes médicos . El i. social tendria que hacerlo yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-07-05','Amalia : escribo a la TS de Montijo ( ssbmontijo@...) , para pedirle ésto. Buenos días , vamos a solicitar plaza residencial por emergencia social para Justa Diaz Borreguero . Hemos solicitado internamiento involuntario via judicial a la espera de respuesta. Te adjunto la solicitud para que por favor cuando puedas me cumplimentes el informe social en este modelo . Como podemos pasarle a su médico el informe médico ?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2022-07-06','Ana: Confirmo a Ángela - Directora Placeat, que se aprueba el presupuesto de taxi para que María Rosa visite a Benedicta en la Residencia de Mayores de Aldeanueva. ············· Envío correo a Ángela (directora@placeat.org): "En relación a la propuesta de que María Rosa acuda con "su novio" a pasar una semana de vacaciones en Guadalajara en casa de la hermana de éste, siendo el deseo de María el de ir, si desde el equipo técnico de Placeat, que conocéis a la familia, no veis inconveniente en que vaya de vacaciones con ellos, por parte de la sección social de este gabinete técnico de la CTAEX se acepta la solicitud."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-07-06','Ana: Envío correo a Pilar Cerrillo, TS Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "...seguimos a la espera del Informe de la Psicóloga con las modificaciones propuestas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-07-06','Ana: Envío correo a Pilar Cerrillo, TS Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "...ya hablé con María, compañera del SSASB de Alcuéscar. Desde el Ayto. no proponen ninguna medida para ayudarle económicamente, no le van a reducir la cuota ni similar. Por tanto, la única opción que encontramos es volver a trasladar a Mateo a otros pisos de las mismas características, de algún municipio que sí mantenga la subvención. Seguramente se le traslade a Aldea del Cano, donde en principio abonaría los mismo que estaba abonando anteriormente en Alcuéscar y en cuanto sea posible, se retomará de nuevo el abono de la deuda contraída con vuestro centro del Casar. En el centro abordarán el asunto con el propio Mateo para explicarle la situación." ··································································································································································································· Envío correo a Toni-Futuex, para que la Educadora apoye en el proceso de comunicación de la situación a Mateo así como en el posterior traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-07-05','EXITUS El centro informa de su fallecimiento, que tuvo lugar el 05/07/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-07-06','Ana: Llamada de Cristina, Ed. Asoc. Vera (681 143 911): Adrián ayer volvió a agredir a otros 2 residentes sin mediar palabra, sólo porque se lo había dicho su novia. ··· Una de las familias irá a denunciar, pero la otra no quiere. ·········· Nos enviarán informe de incidencia y la denuncia para que podamos comunicarlo al Jdo. ·································································································································································································· El día 19/07 tiene cita en ESM. Se la pospusieron porque cuando le tocaba dio positivo en Covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-07-06','Ana: Envío correo a Toni-Futuex: "...quería preguntarte si la compañera ha vuelto a visitarla y si es así, que nos informéis sobre cómo sigue. Desde que ha vuelto al Casar con Jesús, no ha vuelto a llamarte, mientras que estando sola en su casa me llamaba prácticamente a diario. Y la última vez que le llamé yo, me lo cogió directamente Jesús y aunque después le pasó el teléfono a ella, puso el manos libre. De nuevo está condicionada por él. Por cierto, según me comunican desde la sección económica, Felisi no ha ido a retirar su asignación con la tarjeta y resulta un tanto extraño."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-07-06','Ana: Óscar, acuerda con Adela Molina, Secc. Prestaciones - PNC, D.G. SS.SS., que nos amplían el plazo para abonar los cobros indebidos hasta el 30 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-07-06','TERESA EMAILAyer estuve con Beatriz, venía muy angustiada por las amenazas, insultos y acosos que está recibiendo de su pareja, ella comenta que quiere dejar la relación y que lo ha bloqueado y no quiere saber nada de él. Dice que siente mucho miedo y que no quiere salir a la calle. Ha llamado varias veces al 016 y ha hablado con una psicologa que la orienta a llamar a la Guardia Civil, que lo ha hecho varias veces; en las primeras ocasiones le han dicho que no puede poner denuncia (supongo que será por las veces que se han denunciado los dos), y la ultima vez mandaron una patrulla para que rondase la casa, pero no vieron a nadie. Al ver lo angustiada que estaba, se me ha ocurrido solicitar ayuda a la Oficina de Igualdad, para que valoren la situacion, aunque le he dicho que la relacion es conflictiva por varias partes y ha habido denuncias por daños materiales agresion por parte de ella. Me han comentado que hablarán con la Guardia Civil y despues con ella, para ver como está la situacion. Te mantendré informada. Muchas gracias y feliz tarde. CRPS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-07-06','Ana: Recibimos 2 correos-e, de Tomás, hermano de Saturnino. *Guardo en el expdte. digital. ······························································································································································································ Envío a Miguel, Asesor Jurídico, propuesta de solicitud de REVISIÓN DE SENTENCIA conforme a la Ley 8/21 de 2 de junio, y que nombren a su hermano Tomás como Curador Asistencial para que le preste los apoyos necesarios. *Creamos una carpeta dentro de la carpeta >>Juzgado>> al efecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2022-07-06','Ana: reenvío correo de Ángel, Asesor Jurídico CTAEX, a Mariví Clemente, TS CSS-Plas. (victoria.clemente@salud-juntaex.es): "He hablado con María Jesús, hermana de María Teresa, en relación con la herencia del padre. Ponemos en marcha la maquinaria…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-07-06','Ana: Blanca, Directora CRR, me remite auto, acordado ayer, del orden alejamiento de la pareja de la madre hacia ella. ········· Se lo reenvío a Miguel. ·········· Respuesta de Miguel, con copia a blanca: "no nos ha llegado todavía esta notificación del juzgado. Pasamos a solicitar abogado de oficio para personarnos en la causa, ya que no se renuncia ni a las acciones civiles y penales. Por parte del centro que nos vayan informando cualquier incidencia."','2');
