insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-07-07','Ana: Correo de Sonia, TS del C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es): "Buenas tardes Ana, le adjunto la siguiente documentación requerida por la Comisión Tutelar de Adultos de Extremadura para completar expediente de Incapacitación del interno D. SERGIO SOLANILLA LUJAN: • Informe Social • DNI • Tarjeta sanitaria • Carné de discapacidad • Informe revalorización pensiones 2021 de la Seguridad social. Como ves, nosotros apenas tenemos documentación. Su madre nos ha confirmado que seguro de decesos y carné de conducir no tiene. En referencia al nº de ccc (libretas de ahorro…) tendréis que dirigiros a ella para que os proporcione toda la información. En el centro solamente tiene una tarjeta de crédito, que es la que hacía uso cuando salía de permiso."','2');
