insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2022-07-07','LOURDES: OK AL ACOMPAÑAMIENTO X 30 €...PAGA DESDE LA CCC 7110 OSCAR: TIENE 2 CCC EN IBERCAJA: 7110 (JUNTO CON UNA PERSONA FALLECIDA) SALDO 29/06/2022: 6.606,38----EVOLUCIÓN ANUAL: -4.036,72 € INGRESOS: SOLO PN ORFANDAD DE 220,70 €/MES X 14 GASTOS: CENTRO: 583,38 €/MES. NORTEHISPANIA: 12,19 €/MES. FARAMACIA Y POCOLOGIA: 4 €/MES. 8981 (SOLO TUTELADO) SALDO 29/06/2022: 13229,36 € INGRESOS: PRXHCARGO: 626,60 €/MES X 12 GASTOS: NO TIENE ACTUACIÓN: ASEGURARNOS DE QUE PASA A COBRAR LA PENSIÓN ORFANDAD DE 220,70 € EN LA CCC (SOLO TUTELADO) ES58 2085 4511 91 0332498981 MANTENEMOS LOS GASTOS CARGADOS EN CCC CON FALLECIDA Y REVISAMOS DENTRO DE 6 O 7 MESES YA QUE EN ESA CCC NO HAY INGRESOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-07-07','TERESA Marta empieza las prácticas del curso de limpieza que está haciendo, el próximo viernes día 8 de julio. Por cierto, está súper contenta y motivada con el curso. Para poder cuadrar el horario de las prácticas tendrán que desplazarse a Cabeza del Buey , desde Peñalsordo, en transporte público ya que el transporte de nuestro servicio viene más tarde. Y las prácticas las tiene que hacer aquí en Cabeza del Buey. Es por ello que desde el curso, le van a dar una beca de transporte, para pagarse el billete del autobús, entonces cuando le hagan ese ingreso en su cuenta, ya sabéis vosotros de lo que es y nos lo mandáis a la cuenta nuestra de siempre para que Marta pueda disponer de ese dinero y pagarse su billete del bus. Además, cuando finalice las prácticas le van a ingresar en su cuenta, unos 200€ aproximadamente, porque las prácticas son remuneradas. Me pide Marta que ese dinero se lo deis luego en septiembre para llevarlo a la playa como dinero de bolsillo, para que pueda comprar lo que quiera o tomar algo y demás.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2022-07-07','TERESA David ha terminado el curso y hemos cerrado con él que aunque ya no esté haciendo las prácticas del curso en Llerena que tiene que seguir viniendo al centro, vendrá de martes a viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2022-07-07','TERESA Ha terminado el curso de Cocina que ha hecho en Zafra. Ya ha terminado las prácticas y ha ido todo muy bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-07-07','TERESA comentarte que el pasado 20 de Junio se conversó telefónicamente con María Gordillo (665 61 26 77) una mujer de Villafranca que tiene experiencia como auxiliar de ayuda a domicilio y de la que se sabe que está acostumbrada a trabajar con perfiles complicados por Marisa de los SSB, de hecho fue ella la que facilitó su teléfono. Se habló con María durante un buen rato y se le explicó en qué consistiría su trabajo: limpieza de la vivienda, y sobre todo de la habitación de Adolfo, conseguir un cierto apego con el tutelado para que ella pueda influir en sus hábitos de higiene, cambios de ropa limpia y mucho más. María comentó que le parecía bien y que ella tenía disponibilidad por las mañanas, a partir de las 10:00h. También dejó bastante claro que le gustaría no tener que trabajar a través de ninguna empresa de dependencia privada, que prefería cobrar 8€ la hora en transferencias a su cuenta directamente. Como se desconoce la cuantía económica que tiene Adolfo en el banco para poder asumir un gasto así, se propuso de antemano que María fuera a su casa tres veces en semana, los lunes, miércoles y viernes una hora cada día, que serían 24€ a la semana y 96€ al mes. Pero se podría reducir a dos días por semana, que serían 64€ al mes, todo dependiendo de la economía del tutelado. VOY A SOLICITAR ORFANDAD PARA PODER ASUMIER EL GASTO DE LIMPIEZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-07-07','Ana: Envío correo a Toni-Futuex, solicitando información actualizada de la situación (suministros, avances en la vivienda, comidas en el mesón, apoyos que recibe...) más Informe Firmado para la futura revisión de la sentencia. ·········· Solicito también, si hay previsión de que permanezca residiendo en Alcuéscar, que le apoyen, si lo requieren, en el alta del suministro eléctrico (el del agua ya lo han hecho sin apoyo ni comunicación previa a la CTAEX). ···· Le informo de la autorización bancaria de 50€/semana (por fin el banco parece atender a los escritos) y de que aún existen deudas pendientes. ··· Y pido nuevo presupuesto (gastos de comida, suministros y de bolsillo), para cuando sea posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTIBALIZ'and edp.apellido1='MENDEZ'and apellido2='CARRASCO'),'2022-07-07','Buenas Sole , adjunto requerimiento de PNC , solicita las nominas de Estibaliz. Como estaré de vacaciones las próximas 2 semanas , si puedes y para evitar que se pase el plazo , puedes registrarlo tú . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-07-07','Ana: Sonia, TS del C.P. (trabajosocialcpcaceres@dgip.mir.es)','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-07-07','Ana: Correo del CRR-CC (crr@grupociudadjardin.com): "Trasladamos incidencia recogida sobre la situación ocurrida en el día de ayer sobre la persona usuaria Esteve Pascual Ramos: "A las 14 h del día 6.07.2022 se recibe en sala monitores una llamada telefónica al CRR de una persona agitada, con voz entrecortada, entre sollozos y con lenguaje incoherente en el que se entiende "quiero morir, no puedo más". Tras mantener a la persona al teléfono conseguimos identificar que se trata de Esteve Pascual Ramos, se le mantiene al teléfono y se hablaba con él a la vez que se sube corriendo a la habitación intentando que nos diga donde se encuentra. Al llegar a la habitación la puerta se encuentra atrancada, impidiendo el acceso a la misma, habiendo colocado todo el mobiliario en la puerta de forma estratégica que impide poder abrir la puerta. No teniendo mas acceso. Desde fuera de la habitación se escuchan golpes, llantos y continuos delirios referenciales. Cristina indica activación de protocolo 112 para valoración de urgencia psiquiátrica mientras intenta acceder a la habitación, y mantener a Esteve hablando desde el interior mientras esperamos la llegada de sanitarios y fuerzas de seguridad. Ya que por más intento y esfuerzo no podemos acceder a la habitación y el riesgo valorado de autolesión lo considera elevado. Acude la policía que realizan un primer intento de abrir la puerta comprobando que no pueden acceder. Al no llegar los sanitarios aún y considerar que la intervención que está realizando la psicóloga va consiguiendo calmar el estado del paciente que no parece estar herido en dicho momento y no deja de hablar con ella ya en todo momento, comenzando a expresar su malestar, siguiendo la conversación, cesando los golpes y contactando cada vez más con la realidad. Poco a poco Esteve, va confiando y retirando muebles, y tras 40 minutos abre la puerta sin que tenga que intervenir la policía, que custodian al equipo en todo momento como prevención. Se comprueba que no tiene heridas. Esteve expresa y entrega cinturón y cordones con los cuales expresa haber intentado ahorcarse para dejar de escuchar las voces, ya que no encuentra otra salida, pero haberse agobiado y no haber podido terminar de hacerlo sintiéndose un "cobarde" por no haber podido hacerlo y sentirse culpable porque su sufrimiento no parará por su propia culpa. Durante toda la intervención se dan delirios referenciales. Se aprecia un golpe en la frente, Esteve explica haber estado dando cabezazos en la pared. A la llegada del PAC, la puerta ya se encuentra abierta y Cristina y un monitor se encuentra interviniendo dentro mientras la policía custodia en la puerta por si hubiera que contener. Cristina explica situación, estado del paciente, las últimas valoraciones a urgencias (la última el sábado 2.07.2022), los cambios de medicación ineficaces y las dificultades de contención del paciente. Los sanitarios realizan orden de traslado por emergencia psiquiátrica y esperan junto con el equipo la llegada de la ambulancia, ya que la policía debe marcharse a otro servicio y valorar, no alteración de usuario en dicho momento, y que si fuera necesario por alteración previa al traslado se debería volver a activar y volverían a acudir. Se recibe llamada de vuelta de la no existencia de ambulancias disponibles y se nos indica que traslademos al paciente por otros medios. Al estar aún la doctora en el centro, realiza las llamadas necesarias expresando el riesgo del paciente y la necesidad de traslado urgente e inminente. Tras varias llamadas confirman la movilización de ambulancia. Acude acompañado por un monitor en ambulancia al HSPA para valoración. Tras exploración se valora alto riesgo y se procede al ingreso. Esteve se muestra mas tranquilo pero no estar conforme con el ingreso. Al mismo tiempo el equipo del CRR, llama desde el centro a la unidad de psiquiatría para informar de la situación al psiquiatra de guardia y facilitar toda la información necesaria, antes de la llegada del usuario a urgencias." Os seguiremos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-07-07','miguel, hablo con Estefanía, y ante la imposibilidad de que la tutelada pueda asumir el gasto de un abogado y procurador por los gastos que le conlleva vivir en centro, unido a que no tiene derecho a justicia gratuita ya que gana mensualmente más de 1.500€, por lo cual ella hará las autorizaciones judiciales de solicitud de aceptación, aprobación de herencia y autorización de venta, y buscará procurador y me enviará un presupuesto de honorarios y gastos. Paralelamente quedamos en que envio email a notaria con copia a ella solicitando declaracion de herederos e indicando que vayan preparando adjudicación de herencia: Buenos días Loli, necesito nos remitas por esta vía la declaración de herederos que hace meses esta pendiente. En caso de que no esté firmada porfavor indícame el problema para lo solucionemos rápidamente ya que queremos que vayáis preparando la liquidación de gananciales y adjudicación de herencia de Agustin y su hermano Juan Felipe, para lo cual te adjunto la escritura de herencia de su padre fallecido. Como sabes la madre de Agustin y Juan Felipe, Alfonsa es tutelada por esta Comisión Tutelar de Adultos, siendo Mercedes (viuda de Juan Felipe) la otra heredera y ambas usufructuarias. Se pondrá en contacto con vosotros la abogada, Estefanía Fernández, desde Asturias, que está tramitando esta herencia y que va a pedir las correspondientes autorizaciones judiciales de estas dos herencias para que le enviéis la declaración de herederos de Agustin, y para que os informe de los datos que preciséis para dichas adjudicaciones de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-07-07','miguel, envío email a notaria de azkoitia, Nagore, notaria@notariazkoitia.com, conforme instrucciones de ana de pablo (adepablo8@gmail.com): Buenos días Nagore, conforme instrucciones de la abogada Ana de Pablo, le indico que el número de cuenta del tutelado D. José Luis Murillo Horrillo es ES9021037100590030009155. En cuanto a la ratificación de la compraventa que se firmará el día 21-7-22 confirmar que estaremos en la notaria de Mérida de D. Francisco de Borja Igartua Fesser, D. Gonzalo Fernández Pugnaire, y D. Francisco Javier Hernández Telléz. Pueden ponerse en contacto con el oficial de dicha notaria en el email joseluis@notariaromeroleal24.com, para concretar todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-07-06','miguel, recibo email de ana de pablo (abogada de los hermanos): Buenos días Miguel, ya le dije que era posible escriturar la venta de los cuatro terrenos (sin extinción de condominio), pero si la comisión tutelar de adultos no quiere adquirir esas tierras, se procederá únicamente a la venta de la finca de Viña de los Carniceros(Finca número 3 de la escritura de herencia) cuyo borrador ya le envié en el correo electrónico de 27 de junio, y cuyo pago se va a realizar mediante 4 transferencias, debiendo indicar usted el número de cuenta, con el IBAN correspondiente, a donde hay que realizar la correspondiente a José Luis Murillo Horrillo. Precio total= 20.713€ (corresponde a cada hermano: 5.178,25€). En la Notaría de Azkoitia proponen la firma de esta escritura el próximo jueves. día 21 de julio a las 12:00 horas, y posteriormente firmaría el representante de la Junta desde la Notaría de Mérida, verdad? Para concretar estos extremos puede contactar con NAGORE, de la Notaría de Azkoitia, que es quien lleva el asunto: Teléfono 943851258 y dirección de correo electrónico notaria@notariazkoitia.com. Queda pendiente que yo le envíe a usted la liquidación de los ingresos y gastos derivados de la masa hereditaria. Agradeciendo su atención, quedo a la espera de su respuesta. Reciba un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2022-07-07','Alberto : REALIZAMOS REINTEGRO PUNTUAL 600 € EXTRA VERANO A LA HIJA DEL TUTELADO---SE REALIZARÁ PARA LA SEMANA DEL 11/07/2022---AVISAS TU AL HERMANO DEL TUTELADO.( aviso a su hija , no sabía nada de lo que se le estaba cargando en la cuenta del padre . ) ESTRELLA: REINTEGRO PUNTUAL 600 € A HIJA TUTELADO (TIENES MODELO EN EXPEDIENTE) EN LA SEMANA DEL 11/07/2022. ESTRELLA: MUY IMPORTANTE: A PARTIR DE 01/08/2022 SE DEVOLVERÁ CUALQUIER RECIBO QUE ENTRE EN LA CUENTA DEL TUTELADO (YA QUE ES SU HERMANO QUIEN LO HA DOMICILIADO SIN AUTORIZACIÓN)-----AMALIA YA LE HA ADVERTIDO QUE CUALQUIERA DE LOS RECIBOS QUE INCLUYO ABAJO Y QUE ENTRE EN AGOSTO SERÁ DEVUELTO: COMUNIDAD VECINOS. OAR. TELÉFONO','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-07-07','Ana: Ante la petición que realiza Mª Luisa de incremento de su asignación semanal, envío correo a Toni, TS del C.R. Cervantes (antonia.dediego@salud-juntaex.es): "...se autoriza la subida a 50€ semanales a partir del 11 de julio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-07-07','Ana: Llamada de José Manuel, comunica que Virgina, Ed. Futuex, remitirá presupuesto para pegamento y utensilios para la dentadura postiza. ···················· En relación al Cáterin, llamó para decir que esta semana no le llevaran comida hasta mañana, pues tenía aún en el frigorífico. ············· Y en cuanto a la posible asistencia al centro REVITAL, dice que si tiene que pagar, NO quiere acudir. ············· El Servicio de Teleasistencia, si es gratis o tuviera que pagar poco sí, sino tampoco. ·············','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2022-07-07','Alberto : REALIZAMOS REINTEGRO PUNTUAL 600 € EXTRA VERANO A LA HIJA DEL TUTELADO---SE REALIZARÁ PARA LA SEMANA DEL 11/07/2022---AVISAS TU AL HERMANO DEL TUTELADO.( aviso a su hija , no sabía nada de lo que se le estaba cargando en la cuenta del padre . ) ESTRELLA: REINTEGRO PUNTUAL 600 € A HIJA TUTELADO (TIENES MODELO EN EXPEDIENTE) EN LA SEMANA DEL 11/07/2022. ESTRELLA: MUY IMPORTANTE: A PARTIR DE 01/08/2022 SE DEVOLVERÁ CUALQUIER RECIBO QUE ENTRE EN LA CUENTA DEL TUTELADO (YA QUE ES SU HERMANO QUIEN LO HA DOMICILIADO SIN AUTORIZACIÓN)-----AMALIA YA LE HA ADVERTIDO QUE CUALQUIERA DE LOS RECIBOS QUE INCLUYO ABAJO Y QUE ENTRE EN AGOSTO SERÁ DEVUELTO: COMUNIDAD VECINOS. OAR. TELÉFONO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-07-07','Buenas , he contactado nuevamente con la TS de Aprosuba 3 porque no he recibido respuesta de la documentación solicitada . Os aclaro algunas consultas que me preguntaba Alberto : -Actualmente Antonia ocupa plaza de Centro Ocupacional , es de caracter gratuito para los usuarios . -La deuda que reclama el centro es de cuando estuvo ocupando plaza residencial , la tutora era su madre. Al plantearle que esta deuda con el centro ( 5000€) no podemos abonarla sin orden judicial me comenta que ellos ya la reclamaron al juzgado . Les he pedido alguna documentación al respecto y es el documento que adjunto. Mi opinión es que dado el caso , sea el juzgado el que se pronuncie sobre el abono y cómo hacerlo . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-07-06','Ana: Recibimos Certificado de P. Orfandad actualizado: 220,70 € x 14.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-07-07','Buenas , he contactado nuevamente con la TS de Aprosuba 3 porque no he recibido respuesta de la documentación solicitada . Os aclaro algunas consultas que me preguntaba Alberto : -Actualmente Antonia ocupa plaza de Centro Ocupacional , es de caracter gratuito para los usuarios . -La deuda que reclama el centro es de cuando estuvo ocupando plaza residencial , la tutora era su madre. Al plantearle que esta deuda con el centro ( 5000€) no podemos abonarla sin orden judicial me comenta que ellos ya la reclamaron al juzgado . Les he pedido alguna documentación al respecto y es el documento que adjunto. Mi opinión es que dado el caso , sea el juzgado el que se pronuncie sobre el abono y cómo hacerlo . Un saludo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-07-07','TF HNO JUAN MANUEL 64328175 Me informa que el sepelio se gestionó con Ocaso , la madre lo estaba pagando para Mª Angeles. Le aviso que tienen que dar de baja a la pensión que tiene que devolver la que ya le han ingresado . Le paso tf. de Cele de Mahpre para que gestione la devolución del dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-07-07','Ana: Envío correo a Modesto, Res. Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): "Buenas tardes Modesto, Esta mañana llamé a la casa y efectivamente, no había nadie. Ahora he conseguido hablar con María, la mujer de Miguel, me dice que Miguel tiene un campo, al que se va todas mañana antes de las 8 de la mañana y no llega hasta las 15:30 aproximadamente. Me informa que la casa de Juan está “destrozada”, con lo cuál es imposible que vaya a la misma. Y en la suya no se puede quedar. Le he preguntado por alojamiento y dice que hay un hotel que está muy bien: “Hotel Peña Cruz”. Mañana llamaré para preguntar. Dime si puedes las fechas que os planteabais. Y también habría que pedir presupuesto a algún taxista de confianza, que tengáis de referencia en la resi. Decirte que dadas las circunstancias y siendo la primera vez, se podría probar una primera visita de 2-3 días y en función de cómo vaya esta valorar otra más adelante."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-07-07','Ana: Tras varios correos de Ceferino diciendo que se le ha roto el móvil y pidiendo autorización para comprar otro, envío un correo a Paula, TO CRR, al respecto. ················ Respuesta de Paula: "Hola Ana, comentarte dos cosillas de Cefe: • Una que seguramente durante el fin de semana se le apoyará para la realización de los trámites para anular una línea. • Otra que he revisado con él su móvil. El estado es que tiene quebrada la pantalla, si bien el móvil aún funciona. Esto significa que, podemos ver opciones con él para un móvil, pero que no está en una situación "crítica" o de incomunicación. En este momento está especialmente revuelto porque ha tenido un conflicto con su pareja y ha roto con ella (Cefe mantenía una relación paralela con una amiga común). Esto ha influido en su malestar y se muestra especialmente insistente y tenso. Te lo cuento por si contacta con vosotros, puesto que mañana voy a orientar a que pida un presupuesto de un teléfono con la idea de que a lo largo de la semana que viene se pudiera evaluar si es posible o no."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-07-08','Ana: Planteo a Paula la posibilidad de cambiar la pantalla al móvil, si sólo se hubiera dañado ésta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-07-08','Ana: Recibimos informe de las últimas incidencias protagonizadas con Adrián en la Asoc. Vera. Aportan también, - Denuncia, - Parte de Lesiones e - Informe SOAP de Medicina. ············· Guardado todo en el expdte. papel y digital. ·········· Lo han remitido también a la U.PP.AA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-07-08','Ana: Comunico a Pilar, TS ESM-CC (54612), que de momento no vamos a tramitar la solicitud de Revisión PIA para solicitar la Prestación Vinculada al Servicio de REVITAL, pues dice que si hay que pagar no quiere ir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-07-08','Ana: correo a Modesto, Residencia: "He llamado al Hotel Peña Cruz de Malpartida (927 27 62 92), me dicen que ya has llamado tú, jeje, y que la Gerente no está, que igual a Juan pueden hacerle precio para pasar 3 noches con pensión completa (menos días tendría que ser sólo alojamiento). Como la gerente no está, dicen que llame en otro momento o que escribamos a la siguiente dirección de correos: info@hotelpenacruz.com No obstante las tarifas normales para julio y agosto son: 62€ / media pensión 72 € / pensión completa Puesto que me voy de vacaciones y las dos próximas semanas no voy a estar, y ya que tú también te has puesto ya en contacto, ¿podrías encargarte de solicitar presupuesto en firme (por escrito) para 3 noches, bien a finales de julio, bien a primeros de agosto (que el precio no varía me han dicho), y yo creo que en días de diario mejor, por si surgiera alguna cosa, y remitírselo a las sección económica para que den el visto bueno? Puedes poner en copia a Maite, Jefa de sección. Yo la he puesto en copia en este correo para que esté al corriente. Agradeceríamos que pidas también presupuesto a Taxista de confianza para el traslado y lo remitas también junto con el del hotel. Maite, en la Intranet hay anotaciones al respecto y puedes hablar con Modesto si fuera necesario. Modesto, el número de Maite es: 924 00 60 57 A ver si se puede organizar para que finalmente Juan pueda pasar unos días en su pueblo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2022-03-23','Maite. He hablado con la trabajadora social de la residencia de Deleitosa ( Guadalupe) para aclarar el tema de la póliza de deceso. Le he explicado que debido a su edad no se hace, que llegado el momento tienen que enviarnos un presupuesto y desde aquí se autoriza. Respecto a la visita que nos habian solicitado, me dice que de momento no es necesario, ya que han conseguido contactar con una sobrina de Sofia, con la que habla periodicamente y esto la mantiene tranqnuila. Guadalupe me comtenta que les resulta complicado que se tome la medicacón y quizá haya posibilidad de que pueda desastibilizarse. Hemos quedado de en que si necesitan que vayamos nos lo dirán desde el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2022-07-11','TERESA RECIOBO LLAMADA DE GUADALUPE LA TRABAJADORA SOCIAL DE DELEITOSA PARA COMUNICARME EL FALLECIMIENTO DE SOFIA EL PASADO SABADO HA MANDADO EMIAL A MAITE PARA APROBAR PRESUPUESTO QUE NOS ENVIA LA FUNERARIA PUES NO TIENE SEGURO DE DECESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2022-07-09','EXITUS Falleció el 09/07/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-07-12','TERESAMe acaba de llamar Beatriz que se le ha roto el móvil y necesita uno, la noto alterada. Dice que ha ido la trabajadora social para rellenar unos papeles que le ha pedido el juez y que en septiembre recupera su capacidad, desde la comisión tutelar no tenemos noticias al respecto. Le he dicho que me envíe presupuesto para que la sección económica lo apruebe y ya le dio uno de sus arrebatos que la tenemos sin dinero y sin ropa que nos va a denunciar ante la policía y al juzgado de como la tenemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-07-12','TERESA EMAI CRPS Beatriz esta fatal. Ma ha llamado varias veces, ha discutido con su familia, con su tía de Barcelona, ha vuelto con Toni y está muy nerviosa. La tenía citada hoy, pero me ha llamado ahora para decirme que no puede venir, que ha llamado a urgencias y la psiquiatra de guardia le ha cambiado la medicación y se encuentra muy sedada. Esta centrada en el móvil, en el dinero que necesita y no se le dá, que va a renunciar a la pensión y a trabajar en el tarot. En cuanto al procedimiento judicial, se que ha hablado con el juez y éste le ha dicho que están intentando apresurarse lo máximo posible. Tiene que citarla el forense, he sido yo la que le he dicho que como muy pronto la citarían en septiembre, ya que ahora con las vacaciones no pensaba que lo hicieran. Esta pendiente de una entrevista con la Trabajadora social del SSASB de Zafra, ya que le han solicitudo un informe desde el juzgado, pero no ha acudido varias veces a a la cita. No se que saldrá de aquí, ya que yo la veo muy inestable y muy alterada. Su psicologa está de vacaciones, así que yo la estoy llamando todos los días, para hablar un rato con ella y contenerla un poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-07-13','TERESA EMAIL CRPS Ha venido Beatriz cabreadisima a vernos. Había estado en el Equipo de Salud Mental y se ha puesto el inyectable, la ha visto la psiquiatra. Venía muy enfadada con vosotros; se ha comprado un movil y no sabía utilizarlo; la hemos ayudado y tranquilizado. Esperemos que con el cambio de medicación y el inyectable se tranquilice un poco. Te envio la factura del movil (ya le he dicho que se hace al reves, primero se manda el presupuesto y despues se compra el movil, pero me ha dicho que legalmente ella ya no está tutelada y que nadie se lo puede impedir).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-07-13','TERESA RECIBO LLAMADA DE LA HERMANA DE BEATRIZ dice que no tiene dinero para comer ya que se ha gastado el dinero de la asignación en la compra del teléfono. Yo no puedo autorizar esa compra hasta que lo vea las sección económica ni puedo autorizar darle mas dinero, Alberto el jefe de sección esta de vacaciones y no viene hasta el lunes, le he dicho a la hermana que el lunes se lo planteo pero dudo que se autorice esta compra pues lleva mucho dinero gastado y más que no ha hecho lo que le hemos indicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2022-07-13','TERESA RECIBO RESOLUCION PNC','2');
