insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2022-07-12','TERESA SOLICITUD ACREDITACION CONDICION DE PESNSIONISTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-07-14','TERESA ME LLAMA M ANTONIA 644854878 PARA PEDIR QUE SE QUIERE IR EL MES ENTERO DE AGOSTO A CASA DE SU PRIMA, HABLO CON LA PRIMA Y TAL Y COMO HABLAMOS LA ULTIMA VEZ SE HARA CARGO DE ELLA SEMANAS ALTENRNAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-07-14','TERESA Acabo de hablar con M Antonia y con su prima para el tema de las vacaciones ya que M Antonia insiste que su prima quiere que se vaya el mes entero. Tras conversación con la prima, las cosas siguen igual ella no quiere que se vaya todo el mes, le parece bien la propuesta de semanas alternas, la madre sigue ingresada y el pronóstico es grave. Tras comunicar a Mª Antonia las condiciones se ha enfadado mucho y manifiesta que se va a poner en el huelga de hambre y que no se va a tomar la medicación hasta que consiga lo que quiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2022-07-14','RENDICION ANULA NEREA CONTINUA EN ADISER HORIZONTES, INGRESO EN FEBRERO DE 2021 MATIENE CONTACTO TELEFONICO CON SU MADRE Y SU TIA SEMANALMENTE PARTICIPA EN LAS ACITIVIDADES DEL CENTRO PERO SU DIFICULTAD EN EL LUENGUAJE LE HACE TENER MUCHOS PROBLEMAS DE COMUNICACION CON SUS COMPAÑEROS LO CUAL LE GENERA MUCHA FRUSTACION Y POR ENDE ALTERACIONES DE CONCUCTA PERCIBE UNA PNC 632,10, SADLO 17000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-07-14','RENDICON ANUAL JOSE ANTONIO RESIDE SOLO DESDE EL FALLECIMIENTO DE SU MADRE EN EL DOMICILIO FAMILIAR SIGUE EN TRAMITE LA HERENCIA CON LA GESTORIA DEL CID Y VILLAFAINA ACUDE A LAS CONSULTAS Y TIENE ADERENCIA LA TRATAMIETNO LO QUE HACE QUE SE ENCUENTRE BASTANTE ESTABLE Y TRANQUILO PERCIBE ORFANDAD 917,09€ ( SE PIDE CERTIFICADO DE REVALORACION )SALDO 33000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2022-07-14','TERESA MARGARITA RESIDE EN PISO SUPERVISADO DE DON BENITO DESDE EL AÑO 2008 A PESAR DE TENER EL ALTA EL CRPS SIGUE ACUDIENDO AL TALLER LABORAL SE ENCUENTRA ESTABLE AUNQUE SE OBSERVA UN RETROCESO EN SU CAPACIDAD COGINITIVA SE PUEDE CONSIDERAR QUE HA LLEGADO AL TECHO TERAPEUTICO PERCIBE ORFANDAD 767,50€ Y PF 417,70€ SALDO 30000','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2022-07-15','TERESA FELICIANO RESIDEN EL PISO SUPERVISADO DE SALUD MENTAL DE DON BENITO DESDE EL 2015 ESTA MUY BIEN ADAPTADO Y ESTABLE NO TIENE RELACION CON SU FAMILIA ACUDE AL CRPS AL PROGRAMA LABORAL PERCIBE ORFADAD 767,50€ Y PF 417,70€','2');
