insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-07-11','miguel, email de Blanca (direccion.crrplasencia@grupo5.net) Buenas Miguel, Soy Blanca Conejero González, directora del CRR de Plasencia. Lo primero disculparme por no haber podido contactar con nosotras la semana pasada, mi compañera estaba de vacaciones. Os ruego, que me pongáis en copia a mi y a Paula, la terapeuta ocupacional para asegurarnos que recibimos los mensajes. (tocupacional.crrplasencia@grupo5.net) Respecto a Isabel Cano, te adjunto la denuncia que puso el viernes a Yasmina Pardo Mir usuaria del recurso, en situación actual de expulsión. Estamos pendientes de que Yasmina tenga un traslado a otro recurso y que no vuelva al CRR de Plasencia y poder evitar así cualquier riesgo de expulsión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-07-14','miguel, recibo por ctutelar email de Mely: Buenas tardes Miguel. Soy Mely Serrano,hermana de vuestro tutelado José Lara Serrano. He intentado ponerme en contacto contigo por teléfono pero no he podido para comentarte que ya hay una persona interesada en la compra del piso, la chica de la inmobiliaria me dice que hace falta que firmemos un contrato de arras para la reserva. Le he dado tu número y correo para que ella se ponga en contacto contigo y así entre vosotros os ponéis de acuerdo para la firma. Igualmente te mando el número de teléfono de la inmobiliaria por si tú la puedes llamar El número es 609155518,la chica se llama Angela. Me gustaría me confirmaras la llegada de este correo, gracias','2');
