insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-07-20','TERESA EMAIL DE EVA Acabo de hablar con mi madre que se encuentra en el pueblo, y me dice que le ha dicho el albañil, que la fachada no entra en el presupuesto como comprenderá esto no puede ser, pues afecta a la estética de nuestra vivienda, cual es el motivo por el que no esta presupuestada, un saludo LE RESPONDO Se está haciendo el arreglo de lo que causa daño a su vivienda, la estética no es una justificación suficiente para arreglarla ya que la situación económica actual de Francisco no le permite asumir más gastos, aunque se hubiera presupuestado no se habría podido arreglar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2022-07-20','Maite: la semana pasada gestioné el traslado de residencia de Florencia. Ha ingresado el 18 de Julio en la Residencia de Mayores de Montehermoso. Fué acompañada por Virginia ( educadora social de FUTUEX). Ayer dia 19 hablé con Marta, ( 660858095) directora de la residencia. Me dijo que Florencia está bien, y que el reencuentro con su madre fue muy emotivo. Pedí el certificado de ingreso y lo subí a su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-07-19','miguel, recibo email de Ana de Pablo:Estimado Miguel Angel, le comunico que se ha suspendido la firma de la venta del próximo jueves, día 21, a las 12:00h, en la Notaría de Azkoitia. En cuanto los tres hermanos Murillo Horrillo puedan de nuevo acudir a firmar, le avisaré con la antelación suficiente para contactar con la Notaría de Mérida. Le agradezco si puede comunicar a ésta la suspensión. *************************************** comunico a José Luis de Notaria de Mérida: José Luis, me acaban de comunicar que se ha suspendido la firma de la venta hasta nuevo aviso. Cuando la retomen te avisaré para ir a ratificarla. *************************************************** contestación de notaria de Mérida, José Luis: Para la ratificación no te olvides de presentar el auto de declaración de incapacidad, aceptación del cargo y autorización para la firma por tu parte, como siempre. Hay que adjuntarlo todo a la ratificación, además de la autorización para la venta, que ya me has remitido. ****************************************** Otra cosa, Miguel. Como se ha aplazado sin fecha concreta, tendrás que verlo con Ana, pues yo estaré todo el mes de agosto de vacaciones','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-07-20','miguel, solicito certificado de nacimiento (donde conste la inscripción de la incapacidad del tutelado vía electrónica), cuya contestación nos llegará por carta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-20','TERESA Me ha llamado Estrella trabajadora social de Villanueva del Fresno(621044808/ 924427000) referente a este persona. No puede disponer de dinero y está generando deudas en la farmacia y en la tienda de comestibles por este motivo ha acudido desesperada a la trabajadora social. Le he autorizado un reintegro extra de cien euros para que pueda comprar hasta que puedas gestionar su dinero de bolsillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-07-21','Maite:han comunciado incidencia de Pascual Esteve Ramos, desde el CRR. Buenos días, trasladamos incidencia recogidas sobre el estado de Esteve Pascual Ramos del día 21.07.2022. Se continua en supervisión estrecha su estado dentro de las posibilidades que se tienen en el CRR de Cáceres. Adjuntamos informe de urgencias. "Mantiene atención con psicóloga donde se muestra tranquilo y abordable. Expresa que cuando está con ella se siente mas tranquilo con la voz de Antonio. Se marcha mas tarde a la habitación. Tras atención psicóloga nos da la indicación de supervisión estrecha, ya que Esteve no tiene la capacidad en estos momentos para poder hacer frente a la voz (alucinaciones) sin acompañamiento profesional, generándole una intensa angustia y sensación de desesperanza por no poder realizar ninguna actividad de su día a día sin la presencia de la voz. Existen momentos a lo largo del día donde en función de la experiencia y sentimientos de Esteve recibe unos mensajes más peyorativos hacia su persona y otros momentos donde expresa le hacen menos daño. Se considera paciente de alto riesgo, al no tener habilidades ni capacidad en el momento actual para hacer frente a la sintomatología sin contención continua. Y en los momentos de desesperanza y angustia y sensación de vacío e inutilidad intenta quitarse las voces de la manera que encuentre en ese momento, existiendo riesgo de autolesión y heteroagresión si percibe peligro. Al rato, llama Esteve al teléfono del centro llorando refiriendo continuamente que "no puede mas con Antonio. Le ofrecemos medicación de rescate y lo acepta. Pasamos un rato con él, se queda viendo una película. Durante la tarde se queda dormido en numerosas ocasiones en zonas comunes. Hay que despertarle para rellenar pastillero y ayudarle a llegar al comedor ya que se tambalea y se muestra bastante somnoliento. En la hora de la merienda continuaba con el mismo estado. A última hora del turno llama al teléfono del centro, haciendo referencia a que no consigue madurar y que la única forma de conseguirlo es "matar a Antonio". Al inicio del turno de noche se escuchan golpes, se sube a la planta y se comprueba que es Esteve dando puñetazos en la mesa de su habitación. Se muestra nervioso y verbalmente muy agresivo en las contestaciones a monitores, refiriendo que va a matar a Antonio porque no le deja en paz, y hasta que no acabe con él no se va a quedar tranquilo. le indicamos que se baje a zonas comunes y le ofrecemos la medicación de rescate (zypresa 5mg), le aconsejamos que se quede en zonas comunes pero se niega y se sube a la habitación. Al observar el comportamiento y que no baja en intensidad, no haciendo caso a las indicaciones, y por prevención tras indicación de E.T, se activa protocolo llamando al 112. Se personan en el CRR el PAC junto con la Policía Nacional, subimos a su habitación, se observa que sigue nervioso y enfadado, no hace caso ni a monitores nia las indicaciones de los sanitarios y policía, negándose en rotundo a acudir al hospital. Conseguimos que acceda finalmente. Al baja por las escaleras sale corriendo en dirección a la puerta principal, teniendo que actuar la Policía para contenerle en dicha puerta, ya que estaba dando golpes a la puerta para poder salir. Se lo llevan en ambulancia al HSPA, allí nos llama dos veces al CRR para decir que no quiere quedarse en el hospital y que se va a venir andando, se habla con él y se le tranquiliza. Nos llama Sara Baños (psiquiatra) desde el hospital para preguntar acerca del motivo de la consulta y el estado observado de Esteve. Llama por segunda vez para indicar que le van a dar el alta, y que no le van a modificar tratamiento al tener cita mañana con su psiquiatra, para que sea ella quien el modifique el tratamiento, comprobamos que su cita será el día 22 viernes y no mañana 21 jueves. Regresa en ambulancia sobre la 1:20h. Nos dan el informe de alta y un documento que se firma como que Esteve ha llegado al centro. Antes de su llegada, se sube a la habitación y por prevención se retiran aquellos objetos que pueden ser de riesgo en su estado. Durante la noche llama por teléfono en numerosas ocasiones al teléfono del centro desde la habitación con diferentes temas. A las 2:30 baja indicando no poder dormir, se comprueba en el inform de lata que se le ha suministrado una ampolla de haloperidol por lo cual se le ofrece su medicación para el insomnio y la acepta. Se le pregunta si se encuentra mas tranquilo a lo que responde que sí, y se marcha a la habitación. A las 7:15 observamos que se levanta dirigiéndose en ropa interior a a los servicio comunes. Subimos a ver que le ocurre e indicarle que se vista, expresa que quería bajar a beber agua y tenía mucha prisa por eso no estaba vestido. Se le observa que lleva la ropa interior manchada de orina, se le indica que se duche y se cambie lo acepta y así lo hace." El informe de psiquiatra de urgencias está en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-07-21','miguel, llega a ctutelar email de Escalona remitiendo documentación del jzdo 2 de Cáceres, donde IML(instituto de medicina legal) comunica que no ha comparecido ante el forense a la cita que tenía. Le han vuelto a dar cita para el 14-9-22 a las 10h. Pongo email a Inés y Ana: Inés ya he guardado en su expediente este email, pero necesito que guardes en la tabla excell citaciones la citación que le dan para ir al forense para el 14-9-22 a las 10h. Nosotros no asistiremos por lo que no tienes que pedir ni abogado ni procurador.','2');
