insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATIAS'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2022-07-22','TERESA En relación al tutelado Matías Fernández Cerecinos, informarte que su hermana Rosario, con domicilio en Galicia, tiene previsto venir a Extremadura, en concreto provincia de Cáceres, del 3 al 7 de septiembre. En dicho viaje pretende estar con Matías y su hermano Jorge, atendido en Nuño Moral. Para facilitar esta convivencia entre los tres hermanos, es conveniente que Matías se traslade durante esos día al centro Nuño Moral. Este traslado se realizará en taxi, a cuenta de Matías. Se ha contactado con Leticia, directora de Nuño Moral para valorar la estancia de Matías en dicho centro, la cual no tiene objeción. Ambas consideramos muy favorable para los hermanos estos días de convivencia.','2');
