insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-07-25','Respuesta de Mahpre> Buenos días Amalia. Para tu información, estoy en contacto con el hermano de Maria Angeles y estamos tramitando todo para que Mapfre le reembolse el capital asegurado en nuestra póliza, ya que han utilizado otra compañía para realizar el entierro. Recibiréis en el SEPAD una carta de MAPFRE con la documentación necesaria, pero no te preocupes, ya que se la he enviado también a su hermano y entre nosotros nos encargamos de todo. Un saludo. CELESTINO ALPISTE MEJIAS | alpic@mediador.mapfre.com . Asesor comercial Movil: 670976260 MANUEL GALLANA AGENCIA SEGUROS, S.L. MAPFRE CALLE Practicante Alfonso González, 14 PUEBLA DE LA CALZADA - 06490 (BADAJOZ) 924459077 / mgallan@mapfre.com http://www.mapfre.es/oficinas/0668','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-07-25','TERESA Buenos días Teresa. Este fin de semana ha sido terrible con Natalia. La cuidadora la pilló robando los vasos de la cocina y envolviéndolos en papel para guardarlos en su maleta. Al pillarla ha estado todo el fin de semana amenazando e insultando a todos los compañeros y a la cuidadora. Intimida a una compañera con TEA. Sería posible adelantar la salida al domicilio a hoy o mañana si su abuela está conforme? Dime algo por favor. Un saludo SE AUTORIZA ADELANTAR LA SALIDA','2');
