insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-07-25','miguel, me llama la sobrina (Pilar Rodriguez Rosado 927-212138//645909526; email de su marido Angel apinero@unex.es) de Doña Mª Angeles que se encuentra residiendo en Malpartida de Cáceres, en la Residencia de Mayores "Santa Ana"(tlfno 927-276471). Tras conversación con Maite y conmigo (Ana está de vacaciones) quedamos en comunicarle la incidencias que comentan: 1.-El centro habría hecho firmar un documento a Doña Mª Angeles, donde se indicaría el deseo de ella de seguir residiendo en la misma (pese a que Ana ya le habría buscado otro centro del que está en lista de espera) 2.-La avisa una trabajadora del centro de que tiene que personarse en el juzgado de Malpartida de Cáceres (sin identificar procedimiento y juzgado)del que tiene desconocimiento la Ctaex, estando su tía imposibilitada de hablar según nos comenta Pilar, su sobrina, y de lo que en principio no puede demostrar con documentos médicos, y nos dice que sean nuestras trabajadoras sociales las que se personen y comprueben su estado de que no puede hablar y tiene muchas escaras. Doy nuestros emails de la Ctaex (ctutelar y el mio)para cualquier incidencia','2');
