insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-07-25','Buenos días, Ayer volvieron a ingresar a Mercedes en el Infanta cristina. Me llamo la policía por que llevaba tres días la alarma sonando y los vecinos estaban asustados. Ella estaba encerrada en una habitación muy nerviosa y tuvieron que entrar los bomberos. Se la llevaron en una silla atada, intentaron sedarla pero por lo que se veía hizo poco efecto. La casa estaba preocupantemente insalubre. Mucho peor que otras veces. Suelo lleno de comida sucio restos de comida por toda la casa todas las habitaciones todo desordenado. Mando algún video de la situación. Me cuentan los vecinos que tira cosas por la ventana huevos jarras de cristal... Intentare organizar la limpieza de la vivienda. Al respecto de las mascotas, intentare llevar al perro a alguna empresa que lo cuide. Gato y tortuga se quedaran en la casa con comida. Pasare una vez a la semana a intentar darle de comer. Jesús Pérez de Acevedo Pinna. CASTILLO, PINILLA & PEREZ DE ACEVEDO, S.L. Abogados Tfno: 924 22 90 48 Fax: 924 24 83 03 email: menacho12@abacolegal.es C/ Menacho, 12, 2º 06001 BADAJOZ Se autoriza para que contrate servicio de limpieza y un sitio donde cuidar al perro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-07-26','TERESA REPARACION FACHADADA DE LA VIVIENDA se solicitó presupuestos referentes a los desperfectos que las humedades de la vivienda del tutelado estaban causando en la vivienda colindante (Calle Francisco Rubio 18). Por ello, ambas empresas, presupuestaron el arreglo del tejado y de la pared e incluyeron lo necesario para dar solución al problema de humedades ocasionado a la vivienda colindante. El motivo por el que la fachada no se incluyó en el presupuesto es, al igual que se pudo observar en otras estancias de la vivienda, que los desperfectos solo se visualizaron en la vivienda del tutelado (C/ Francisco Rubio 16) y tal como se puede observar en las fotos adjuntas enviadas por Eva, la fachada que está deteriorada corresponde a la vivienda del tutelado Calle Francisco Rubio 16. Es decir, son daños estéticos, que solo afectan a la vivienda del tutelado, dificilmente puede obligarse por via judicial a este arreglo, que no afecta a la vivienda colindante. No obstante cuando nos pasen el presupuesto te lo haría llegar! se vuelven a adjuntar las fotos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-07-26','Ana: Llamada de Pilar Cerrillo (618 908 506): propone el traslado de Mateo a los PP.TT. de Montánchez, también gestionados por Grupo Ciudad Jardín. El Ayto. mantiene la subvención y si se envía un escrito bien justificado por los Jurídicos en que se explique la situación económica de Martín y sus ingresos netos reales, se le podría conceder plaza con el mismo coste que del año pasado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-07-26','-Visita y presupuesto , no se limitará su cuenta. Respecto de Antonio Fraile, te cuento el seguimiento que se llevó a cabo, mañana se le va a visitar otra vez: Visita 26-06-2022: Desde el equipo de apoyo social comunitario nos desplazamos al domicilio de Antonio en Villar del Rey. No podemos avisarle de la visita ya que no tenemos su teléfono móvil, pero en una llamada mantenida con la trabajadora social de la localidad nos indica que normalmente se encuentra en su domicilio. Al llegar nos presentamos y nos invita a entrar a su casa donde responde a nuestras preguntas, aunque muestra una actitud defensiva en algunas de las cuestiones. Persiste mucho en la necesidad de encontrar empleo, por la falta de medios económicos para subsistir. Está inscrito en la Bolsa de Empleo de Cocemfe, donde le ayuda a la inserción laboral Estela. Y al parecer paga autonomo y gestoria... suponemos que no podra acogersee a alguna otra prestación?? dado que dificilmente parece por su patologia que pueda trabajar. Para una oferta de empleo, la cual no salió adelante necesitó hacerse autónomo, indica que tiene que seguir dado de alta porque se lo requieren si trabaja ya que las opciones que valora son de comercial.... Gastos mensuales: Autónomo: 90 euros Gestor: 60 euros (José Manuel - Villar del Rey) Móvil: 20 euros (657 71 46 90) Préstamo bancario: lo solicitó para viajar a Colombia (500 euros). Dice que ya ha pagado 8 meses unas cuotas aproximadas de 100 euros pero que lleva abonados unos 355 euros. No sabe con exactitud cuando le tienen que cobrar en los próximos meses, durante la conversación va cambiando de cifras. Resto del dinero: comida y tabaco (1 paquete diario) Ingresos: PNC: 421,80 euros. (Domiciliación Banco Santander) Indica que mantiene una relación sentimental con una chica de Colombia. En enero se desplazó al país para conocer a una mujer que conoció por internet, allí pasó 15 días y refiere que no salió bien pero que conoció a otra chica y que en la actualidad esta es su pareja. Su objetivo es que ella se venga a España. Alegando la difícil situación económica de ella le manda ocasionalmente dinero, afirmando que el día anterior le había realizado una transferencia de 100 euros. La relación con su familia es muy conflictiva, teniendo orden de alejamiento de su padre por las denuncias de amenazas entre ambos. La madre indica que está diagnosticada de Alzheimer. Según indica Antonio su padre siempre ha sido muy severo con él. Ambos progenitores viven en una finca de la localidad y el padre está jubilado de la Policía Nacional. Al igual que con los padres, la relación con sus hermanos es mala. En la casa de al lado vive su tía María, la cual le ayuda en ocasiones con comida. En el pueblo reside su primo Casimiro con el que ocasionalmente se toma algo en los bares de la localidad. La casa del Villar del Rey es propiedad de sus padres, además de tener otro piso en propiedad en Badajoz. Los padres se encargan de pagar todos los suministros. La casa se encuentra en buen estado de habitabilidad, tiene dos plantas, pero solo utiliza la planta baja donde tiene habitaciones, cocina, comedor y baño. Indica que la única necesidad que tiene en el domicilio es arreglar la lavadora. Falta de consciencia de enfermedad mental, indica que pasa por un momento de inestabilidad emocional por los problemas familiares y que las limitaciones para trabajar son físicas (hernia discal) y económicas (no tiene dinero para combustible). En relación a su tratamiento indica que solo toma zyprexa y analgésicos. Sin embargo, en un informe del último ingreso en salud mental refleja que su tratamiento es xeplion 150g, depakine y diazepam (se pudo ver a traves de denuncia de guardia civil, cuando hubo la denuncia del padre por uso de armas o algo asi, no tenemos copia) Tiene vehículo propio, ahora dice no poder utilizarlo por falta de medios económicos. Sin embargo, en la guardia civil indica que tiene una multa de tráfico reciente (aprox. un mes) por dar positivo en alcoholemia. No asiste a consultas en Salud Mental, dice que le tiene que llegar la citación para su psiquiatra (Antonio González). Tiene consumo habitual de alcohol, manifiesta que puede beber grandes cantidades porque a él no le afecta indicando que cuando tiene dinero se toma cervezas y copas porque es algo que le gusta. Su médico de familia es Belén, la intentamos localizar en el centro de salud para contrastar datos sanitarios y seguimientos médicos pero ese día no puede atendernos. Por último, vamos al cuartel de la Guardia Civil, nos indican que los conflictos de Antonio son únicamente con su unidad familiar. Que esa misma mañana ha estado el hermano a denunciar el robo de animales en su finca y que Antonio le estaba llamando alterado al no poder retirar dinero de su entidad bancaria. Mañana volveremos para verlo, nos dice que a sacado 284 euros.... no sabemos si esta es la cantidad que se ha considerado, pero si que dado el perfil creemos que no se le puede limitar mucho mas, porque por el perfil que es, si tiene menos dinero, muy probablemente tendra muchos mas problemas de conducta. Seguimos en contacto!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-07-26','TERESA , Natalia ha salido hoy para Badajoz. Hablé con la abuela y me dijo que sin problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2022-07-26','En referencia a este correo Ceferina Amelia está en Caser Centro Residencial Guadiana,. Les ha llegado una carta de la comunidad de vecinos, donde les indican que por ley hay que añadir los contadores a los radiadores, se tiene que poner un contador por radiador. El tema es que tienen que entrar en la vivienda, antes que nada les gustaría ver que tipo de radiadores tiene, pues lo mismo habría que cambiarlos o adaptarlos, ya que una vez que hayan puesto el contador en el radiador si se rompe, no solo cambiarían radiador, sino también todo los contadores. Lo de los contadores es porque el edificio tiene calefacción central. Al hablar con el centro, Gloria me indica que esta señora no tiene hijos, que tiene un hermano, que ya es mayor y que tiene la llave de la vivienda. EL HERMANO SE LLAMA JUAN Y SU MOVIL DE CONTACTO ES 651883433. ---------------------------------- Contacto con Mª Luisa , esposa de Juan y le facilito el tf para que acudan con la llave del piso . Me comenta que si se está haciendo declaracion de la renta , pq ha visto alguna carta al respecto y cree que no y que le han embargado algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2022-07-26','En referencia a este correo Ceferina Amelia está en Caser Centro Residencial Guadiana,. Les ha llegado una carta de la comunidad de vecinos, donde les indican que por ley hay que añadir los contadores a los radiadores, se tiene que poner un contador por radiador. El tema es que tienen que entrar en la vivienda, antes que nada les gustaría ver que tipo de radiadores tiene, pues lo mismo habría que cambiarlos o adaptarlos, ya que una vez que hayan puesto el contador en el radiador si se rompe, no solo cambiarían radiador, sino también todo los contadores. Lo de los contadores es porque el edificio tiene calefacción central. Al hablar con el centro, Gloria me indica que esta señora no tiene hijos, que tiene un hermano, que ya es mayor y que tiene la llave de la vivienda. EL HERMANO SE LLAMA JUAN Y SU MOVIL DE CONTACTO ES 651883433. ---------------------------------- Contacto con Mª Luisa , esposa de Juan y le facilito el tf para que acudan con la llave del piso . Me comenta que si se está haciendo declaracion de la renta , pq ha visto alguna carta al respecto y cree que no y que le han embargado algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-26','Buenos días Amalia, soy Estrella, la Trabajadora Social de VVa del Fresno, tengo entendido que el lunes 25 te incorporas de las vacaciones, me gustaría poder hablar contigo cuando tengas un momento en relación a la situación en la que se encuentra ANGELA RODRIGUEZ FIGUEREDO. Puedes contactar conmigo llamando al 924427000 o bien al 621044808. Gracias. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-07-26','Hola de nuevo, respecto de Antonio Fraile, te cuento el seguimiento que se llevó a cabo, mañana se le va a visitar otra vez: Visita 26-06-2022: Desde el equipo de apoyo social comunitario nos desplazamos al domicilio de Antonio en Villar del Rey. No podemos avisarle de la visita ya que no tenemos su teléfono móvil, pero en una llamada mantenida con la trabajadora social de la localidad nos indica que normalmente se encuentra en su domicilio. Al llegar nos presentamos y nos invita a entrar a su casa donde responde a nuestras preguntas, aunque muestra una actitud defensiva en algunas de las cuestiones. Persiste mucho en la necesidad de encontrar empleo, por la falta de medios económicos para subsistir. Está inscrito en la Bolsa de Empleo de Cocemfe, donde le ayuda a la inserción laboral Estela. Y al parecer paga autonomo y gestoria... suponemos que no podra acogersee a alguna otra prestación?? dado que dificilmente parece por su patologia que pueda trabajar. Para una oferta de empleo, la cual no salió adelante necesitó hacerse autónomo, indica que tiene que seguir dado de alta porque se lo requieren si trabaja ya que las opciones que valora son de comercial.... Gastos mensuales: Autónomo: 90 euros Gestor: 60 euros (José Manuel - Villar del Rey) Móvil: 20 euros (657 71 46 90) Préstamo bancario: lo solicitó para viajar a Colombia (500 euros). Dice que ya ha pagado 8 meses unas cuotas aproximadas de 100 euros pero que lleva abonados unos 355 euros. No sabe con exactitud cuando le tienen que cobrar en los próximos meses, durante la conversación va cambiando de cifras. Resto del dinero: comida y tabaco (1 paquete diario) Ingresos: PNC: 421,80 euros. (Domiciliación Banco Santander) Indica que mantiene una relación sentimental con una chica de Colombia. En enero se desplazó al país para conocer a una mujer que conoció por internet, allí pasó 15 días y refiere que no salió bien pero que conoció a otra chica y que en la actualidad esta es su pareja. Su objetivo es que ella se venga a España. Alegando la difícil situación económica de ella le manda ocasionalmente dinero, afirmando que el día anterior le había realizado una transferencia de 100 euros. La relación con su familia es muy conflictiva, teniendo orden de alejamiento de su padre por las denuncias de amenazas entre ambos. La madre indica que está diagnosticada de Alzheimer. Según indica Antonio su padre siempre ha sido muy severo con él. Ambos progenitores viven en una finca de la localidad y el padre está jubilado de la Policía Nacional. Al igual que con los padres, la relación con sus hermanos es mala. En la casa de al lado vive su tía María, la cual le ayuda en ocasiones con comida. En el pueblo reside su primo Casimiro con el que ocasionalmente se toma algo en los bares de la localidad. La casa del Villar del Rey es propiedad de sus padres, además de tener otro piso en propiedad en Badajoz. Los padres se encargan de pagar todos los suministros. La casa se encuentra en buen estado de habitabilidad, tiene dos plantas, pero solo utiliza la planta baja donde tiene habitaciones, cocina, comedor y baño. Indica que la única necesidad que tiene en el domicilio es arreglar la lavadora. Falta de consciencia de enfermedad mental, indica que pasa por un momento de inestabilidad emocional por los problemas familiares y que las limitaciones para trabajar son físicas (hernia discal) y económicas (no tiene dinero para combustible). En relación a su tratamiento indica que solo toma zyprexa y analgésicos. Sin embargo, en un informe del último ingreso en salud mental refleja que su tratamiento es xeplion 150g, depakine y diazepam (se pudo ver a traves de denuncia de guardia civil, cuando hubo la denuncia del padre por uso de armas o algo asi, no tenemos copia) Tiene vehículo propio, ahora dice no poder utilizarlo por falta de medios económicos. Sin embargo, en la guardia civil indica que tiene una multa de tráfico reciente (aprox. un mes) por dar positivo en alcoholemia. No asiste a consultas en Salud Mental, dice que le tiene que llegar la citación para su psiquiatra (Antonio González). Tiene consumo habitual de alcohol, manifiesta que puede beber grandes cantidades porque a él no le afecta indicando que cuando tiene dinero se toma cervezas y copas porque es algo que le gusta. Su médico de familia es Belén, la intentamos localizar en el centro de salud para contrastar datos sanitarios y seguimientos médicos pero ese día no puede atendernos. Por último, vamos al cuartel de la Guardia Civil, nos indican que los conflictos de Antonio son únicamente con su unidad familiar. Que esa misma mañana ha estado el hermano a denunciar el robo de animales en su finca y que Antonio le estaba llamando alterado al no poder retirar dinero de su entidad bancaria. Mañana volveremos para verlo, nos dice que a sacado 284 euros.... no sabemos si esta es la cantidad que se ha considerado, pero si que dado el perfil creemos que no se le puede limitar mucho mas, porque por el perfil que es, si tiene menos dinero, muy probablemente tendra muchos mas problemas de conducta. Seguimos en contacto!! -- Antonia María Ramírez Cruceras. Psicóloga. Coordinadora Área Psicosocial email: areasocial3@futuex.es FUTUEX: Fundación para la Promoción y Apoyo a las Personas con Discapacidad Tel.: 924491914 - Fax: 924492051 Plaza Santa María 5 - Apartado 84. 06100 Olivenza (Badajoz) www.futuex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2022-07-26','Ángel Pinilla ha ingresado hoy en UHB. Lleva semanas con mucha sintomatología delirante, con mucho sufrimiento y sin apenas dormir. El ingreso finalmente ha sido voluntario. Os vamos informando,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-07-26','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "- Aaron Rosado Alarcón. Está ingresado en la Unidad de Salud Mental del Hospital de Cáceres desde el hace una semana. Nos acaban de comunicar que, si sigue igual, mañana le darán el alta. En este tiempo ingresado ha fallecido su padre, el viernes 22. A él se lo comunicaron en el Hospital y está en proceso de aceptar la nueva situación sin su referente. Nos ha pedido ir a por su ropa y otras pertenencias a su casa, quiere seguir yendo a Navas a casa de una prima pero un compañero que ha hablado con ella me dice que va a ser complicado. Las visitas tendrán que ser de ir un rato y regresar al centro. Nos han informado que está el primero en la lista de espera para ingresar en la UDAC, pero no pueden decirnos una previsión de fecha para ingreso. Esperemos que en el proceso de duelo podamos prestarle apoyo y lo lleve de la mejor manera posible. Ha sido un golpe duro para él. Cuestiones que surgen: - Seguro de decesos, estaba en la póliza con su padre y ahora la familia nos pregunta si la va a seguir pagando porque llevará tiempo con él. Lo he consultado a los compañeros de la sección económica y me dicen que quien lleva este tema está de vacaciones. - Tema de pensión orfandad, herencia,...no sé cómo proceder. Iremos haciendo según nos digáis los trámites, documentación que hace falta,..... - Tenía ayer cita con el médico forense y se aplazó al estar ingresado. Nos han dicho que comuniquemos cuando es alta y le asignarán otra cita." ················ Indico a Sonia que envíen la póliza del seguro de deceso a Estrella, secc. ecca., que se incorpora la semana que viene y podrá encargarse de las gestiones. ·········· Del tema herencias se encargarán los compañeros de la secc. jurídica. ·········· En relación a la pensión de orfandad, valoraremos la pertinencia de solicitarla y en tal caso me encargaré de las gestiones. ······························································································································································································· Óscar, Secc. ecca., me informa que tiene un saldo de casi 17.000 € y un saldo anual positivo. ··········· Valoro con Maite, Jefa Secc.: Teniendo en cuenta que actualmente la cuantía de PNC es de 484€/mes, y que habría que cambiar la PNC por la PFHC (417€/mes x 12) para pedirle la Orfandad Simple (220€/mes x 14) y que abona al centro el 75% de sus ingresos (a excepción de la extras), al año le quedaría menos dinero que ahora. *De momento, NO solicitaremos la P. Orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2022-07-26','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "También ha fallecido su padre, y me hacen la misma pregunta sobre el seguro de decesos. Está en la misma póliza que su padre desde que tenía 12 años. Con él también imagino que habrá que ver tema de pensión de orfandad, herencia,... Su sobrina, me decía ayer que si es preciso os llama ella o va a veros para aclarar todo lo antes posible." ········ Indico a Sonia que envíen la póliza del seguro de deceso a Estrella, secc. ecca., que se incorpora la semana que viene y podrá encargarse de las gestiones. ·········· Del tema herencias se encargarán los compañeros de la secc. jurídica. ·········· En relación a la pensión de orfandad, valoraremos la pertinencia de solicitarla y en tal caso me encargaré de las gestiones. ···································································································································································································· Óscar, Secc. ecca., me informa que tiene un saldo de casi 17.000 € y un saldo anual positivo. ··········· Valoro con Maite, Jefa Secc.: Teniendo en cuenta que actualmente la cuantía de PNC es de 484€/mes, y que habría que cambiar la PNC por la PFHC (417€/mes x 12) para pedirle la Orfandad Simple (220€/mes x 14) y que abona al centro el 75% de sus ingresos (a excepción de la extras), al año le quedaría menos dinero que ahora. *De momento, NO solicitaremos la P. Orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-07-27','Ana: Llamada del Cuartel de la Guardia Civil de Ibahernando, preguntan por le paradero de Javier, pues han recibido un escrito del Juzgado preguntándoles. ············ Les facilito nombre, dirección y nº de telf. del CRR. Así como las dirección y teléfonos a efectos de notificaciones de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2022-07-27','TERESA Nerea sí que quiere ir. Pensamos que le vendría bien esta salida, dado que es la única usuaria que no tiene otra posibilidad de salir del centro. Nuestra duda es si en esta salida tendrá alguna de sus crisis. Ahora está muy controlada y ella sabe lo que tiene en juego, sabemos por su comportamiento y por los informes de psiquiatría, que sus crisis son conductuales, son pataletas cuando no consigue algo o algo no le cuadra. De todas formas creo que tenemos que darle esa oportunidad. La tía me cuenta que serían en un principio muy pocos días para probar a ver que tal. El coste sería 0 €. Nerea tiene dinero aquí de su asignación mensual, los 60 euros del mes de agosto, que cubriría el coste del billete de ida y vuelta. Su tía dice que ella vendría a por Nerea en el tren o bus (lo que le salga más barato) y que después ella igualmente la traería. De todas formas Teresa, si finalmente se va y por algo no se adapta o tuviera algún problema, desde ADISER no tenemos ningún problema en ir con nuestra furgoneta a por la niña. Nos da un poco de pena porque ni su madre ni su hermana muestran interés en llevarla a casa. Nerea está como te he dicho antes muy controla con sus crisis, lo que no quiere decir que no le de alguna si finalmente va al domicilio de su tía, pero es que es la única posibilidad de salida fuera del centro que tiene esta usuaria. Pero como te digo siempre Teresa, vosotros que conocéis mejor la trayectoria y la familia de Nerea, sois los que tenéis la última palabra. SE AUTORIZA LA SALIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2022-07-27','TERESA RECIBO LLAMADA SOBRINA DE LUCIA PORRO 667530931 EN LA QUE ME COMUNICA QEU ESTA INGRESADA EN EL HOSPITAL DE ZAFRA DESDE EL DOMINGO DIA 24. NOS SOLICITA UNA PERSONA PARA QUE LE ACOMPAÑE EN EL HOSPITAL PERO LUCIA NO TIENE DINERO PARA PODER PAGAR ACOMPAÑAMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-07-27','miguel, me llamó ayer la sobrina Pilar (927-212138 y 645909526) para decirme y enviarme por email de su esposo (ÁNGEL PINERO SÁNCHEZ >apinero@unex.es>) la citación del juzdo de paz de Malpartida de Cáceres. Finalmente la ha acompañado ella y dicha citación es para que el día 18-9-22 la acompañará ella al forense','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-07-28','TERES DEL VIERNES 29 DE JULIO AL LUNES 8 DE AGOSTO. SALIDA FAMILIAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2022-07-27','TERESA DEL LUNES 1 DE AGOSTO AL DOMINTO 7 DE AGOSTO.SALIA FAMILIAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-07-27','miguel, enviamos por lexnet alegaciones ya que no localizan a Ana Mª, a efectos de que no archiven el procedimiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-07-27','miguel, enviamos por lexnet alegaciones ante el posible archivo de la revisión de sentencia, en base al informe donde el forense hace un informe que no se ajusta a los emails recibidos por Amalia y que incorporamos, al tiempo que trasladamos el deseo y no nos oponemos a que nos concedan la remoción y se nombre tutora a su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-05-05','Ana: Correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Isabel está bien, sale de paseo a la calle con el Monitor de Terapia, precisamente ha estado a verme porque se quiere comprar un reloj que cuesta aproximadamente 40 euros porque el que tiene se le ha roto y no funciona bien del todo....Ya me dirá si le damos el dinero para tal fin...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-04-20','Ana: Correo de Estrella, TS CSS: "El número de teléfono de la madre de Andrés es: 747486852 y se llama Dolores."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JESUS'and edp.apellido1='DE LA OSA'and apellido2='DE LA OSA'),'2022-07-26','Ana: correo del CRR-CC (crr@grupociudadjardin.com): "Confirmar el positivo en Covid 19 confirmado en la mañana de hoy de la persona usuaria Francisco de la Osa de la Osa. No presenta síntomas en estos momentos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-07-27','Ana: Puesto que seguimos sin recibir los informes solicitados al CSS, Maite y yo llamamos a Mª Paz, Psicóloga y Coordinadora de la UHDAC (24180): le recordamos que estamos a la espera de Informe Psicológico que Andrés, pues lo ha solicitado el Jdo. *Dice que lo está elaborando de forma conjunta con el Psiquiatra Daniel. Intentará remitírselo a Miguel, Asesor Jurídico, esta misma semana. ················ Puesto que Estrella, TS, está de vacaciones, llamamos a Inés, TS en sustitución (24146): no obtenemos respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-07-05','Ana: Tras hablar con Estrella, TS CSS (24146), envío un correo a Miguel, Asesor Jurídico: "Acabo de hablar con Estrella, TS del CSS. Me dice que su informe ya lo tiene (el Informe Social), pero que está esperando el de la Coordinadora/Psicóloga de la UHDAC, que está ya en ello, para enviarnos los dos juntos. Seguramente mañana nos lo podrá enviar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2022-07-28','Ana: en relación al correo recibido ayer, del CRR-CC (crr@grupociudadjardin.com): comunicando incidencia de agresión y amenazas por parte de Félix a 2 usuarios del centro. *Las consecuencias/medidas adoptadas son: "- Adelanto de cita con su psiquiatra para revisión. (Cita adelantada para 28.07.2022). - Los refuerzos económicos que tiene acordados en su presupuesto mensual se verán afectados por las conductas de agresividad sucedidas. Por tanto, en esta ocasión los extras correspondientes al domingo 31 julio y miércoles de 3 de agosto, NO serán recibidos, por incumplimiento de las normas básicas de convivencia en el centro. - La siguiente situación de las mismas características que pueda surgir en el futuro implicará una medida disciplinaria que implicaría una estancia terapéutica fuera del centro durante los días que se determinen en su momento. - De estas y otras situaciones se procede a informar al SEPAD y la Comisión Tutelar de Adultos." , respondo: "Buenos días, Ante todo, gracias por informar y, una vez más, por vuestro trabajo e implicación con las personas residentes, en particular, con aquellas cuyo cargo ostenta la CTAEX. Lamentamos que se produzcan este tipo de incidencias y que otras personas tengan que soportar este trato por parte de Félix. Queríamos preguntaros, si las personas agredidas y/o sus familiares/representantes legales, han denunciado los hechos. Desde el equipo técnico de la CTAEX, entendemos que es fundamental para que las personas con este tipo de conductas vean además otras consecuencias y tomen mayor conciencia de la gravedad de los ocurrido. *Desde aquí siempre animamos a denunciar. Pongo en copia a Maite, Jefa de Sección." *Guardo el correo con la comunicación de la incidencia en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='BUENO'and apellido2='SANTOS'),'2022-07-28','Después de consultar la cuenta bancaria, hemos podido comprobar que a Juan Pablo no le cobran el móvil por esta vía. Podría ser que el tlf fuese de prepago. La encargada del pabellón está de vacaciones. Hablaré con ella la semana que viene y le comentaré también la posibilidad de reducir gastos del paciente. ---------------------------- No hay que limitar el movil por uso indebido dado que es de prepago. Hay que reducir el gasto en el centro , email de Oscar : De móvil no paga nada, al menos en la cuenta bancaria donde cobra las pensiones. Cuestiones a tener en cuenta y comentar con el centro: Desde septiembre de 2021 paga centro 65% de las pensiones. Gastos centro MUY ELEVADOS: media de 418€ mes. Esta situación era sostenible porque no pagaba centro, pero ahora habría que reducir considerablemente sus gastos. Evolución negativa de 2.000€ año. A este ritmo de gasto se queda sin dinero en 4 años y tiene sólo 44 años. Pongo en copia a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='BUENO'and apellido2='SANTOS'),'2022-07-28','Después de consultar la cuenta bancaria, hemos podido comprobar que a Juan Pablo no le cobran el móvil por esta vía. Podría ser que el tlf fuese de prepago. La encargada del pabellón está de vacaciones. Hablaré con ella la semana que viene y le comentaré también la posibilidad de reducir gastos del paciente. ---------------------------- No hay que limitar el movil por uso indebido dado que es de prepago. Hay que reducir el gasto en el centro , email de Oscar : De móvil no paga nada, al menos en la cuenta bancaria donde cobra las pensiones. Cuestiones a tener en cuenta y comentar con el centro: Desde septiembre de 2021 paga centro 65% de las pensiones. Gastos centro MUY ELEVADOS: media de 418€ mes. Esta situación era sostenible porque no pagaba centro, pero ahora habría que reducir considerablemente sus gastos. Evolución negativa de 2.000€ año. A este ritmo de gasto se queda sin dinero en 4 años y tiene sólo 44 años. Pongo en copia a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='MACHIO'),'2022-07-28','He hablado con la óptica y me dicen que algunos seguros del hogar cubren la rotura de gafas, pero no del asegurado, sino de terceros, es decir, el seguro está a mi nombre y cubre la rotura de gafas de otra persona. Si tú te puedes informar de cómo contratar este tipo de seguros de otra manera, házmelo saber, por favor. --------------------------- No se le hace seguro de gafas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-07-28','Buenos días, de esa deuda se ha pedido información a EOS, es por un importe de 1889,09€. Estamos a la espera de recibir contestación por parte de EOS.---------------------------------- Tiene otra deuda , la parte económica está con ello','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-07-28','Buenos días, de esa deuda se ha pedido información a EOS, es por un importe de 1889,09€. Estamos a la espera de recibir contestación por parte de EOS.---------------------------------- Buenos días, muchas gracias. Ayer estuve leyendo en Internet, EOS es una empresa que compra deudas que no han podido cobrarse por las razones que sean. Debe ser una deuda antigua. -Email de su hijo Flavio : Por otro lado informarles de que en breve nos reuniremos de nuevo todos los agentes implicados en el tema de mi madre para informar a fiscalía de la situación en casa de mi madre y poder tomar medidas más contundentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-07-28','Respuesta de Miguel a su sobrina que nos reclama documentación que le pide la abogada para el tema de la herencia. Hola, los abogados de los seguros de decesos, suelen intentar captar clientes, para lo cual cuando te llaman para recoger los certificados de defunción, aprovechan para indicarte que pueden tramitarte la herencia del fallecido, para lo cual te piden todo lo que puedas darles (notas simples, certificados de saldo de cuentas a o los datos de las mismas para poder calcular el impuesto de sucesiones) Paralelamente ellos suelen ir tramitando certificado de últimas voluntades, testamento… Lógicamente cobran por ese servicio. La cuantía de honorarios depende del importe de la masa hereditaria. Por tanto, deberás indicar a la sobrina que desde que se produce el fallecimiento de la persona se extingue el cargo, que por la ley de protección de datos no podemos facilitar información, y que tendrá que ponerse en contacto con el juzgado donde se entregue la rendición final, pero que aunque debería presentarse en los juzgados de Olivenza, no sabemos si finalmente la parte económica habrá de remitirla al jzdo de 1º instancia e instrucción nº4 de Badajoz, procedimiento de incapacitación 499/2001 Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-07-28','Respuesta de Miguel a su sobrina que nos reclama documentación que le pide la abogada para el tema de la herencia. Hola, los abogados de los seguros de decesos, suelen intentar captar clientes, para lo cual cuando te llaman para recoger los certificados de defunción, aprovechan para indicarte que pueden tramitarte la herencia del fallecido, para lo cual te piden todo lo que puedas darles (notas simples, certificados de saldo de cuentas a o los datos de las mismas para poder calcular el impuesto de sucesiones) Paralelamente ellos suelen ir tramitando certificado de últimas voluntades, testamento… Lógicamente cobran por ese servicio. La cuantía de honorarios depende del importe de la masa hereditaria. Por tanto, deberás indicar a la sobrina que desde que se produce el fallecimiento de la persona se extingue el cargo, que por la ley de protección de datos no podemos facilitar información, y que tendrá que ponerse en contacto con el juzgado donde se entregue la rendición final, pero que aunque debería presentarse en los juzgados de Olivenza, no sabemos si finalmente la parte económica habrá de remitirla al jzdo de 1º instancia e instrucción nº4 de Badajoz, procedimiento de incapacitación 499/2001 Saludos','2');
