insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-07-28','Email de Miguel , respecto a la posibilidad de solicitar internamiento involuntario. Hola, su sentencia dice literalmente: “ Y en el ámbito personal, tendrá también el curador la función de cuidar, por sí mismo o por medio de una tercera persona, el seguimiento por el incapacitado del tratamiento médico y pauta terapéuticas a las que ha de continuar sometido”. En mi opinión en base a esto se puede solicitar el internamiento involuntario, si entendemos que ante el incumplimiento de ella de tomarse la medicación supone una alteración de conducta, etc. Ahora bien, al estar ya ingresada y cumpliendo la finalidad de estabilizarla no se puede solicitar ingreso involuntario. Ahí lo que cabe es que se realice su traslado de un centro a otro.. Otra cosa sería cuando vuelva a salir donde para solicitar dicho internamiento debemos fundamentarlo en informes médicos y sociales… Por eso, sería adecuado ir solicitando la revisión de su sentencia, para que el juzgado dictara las medidas de apoyo que entendiese y paralelamente nos nombre curadores asistenciales o amplíe su protección a curatela representativa. Y si lo estima el juez, indicar que hay que internarlo en un centro adecuado. Ya sabes que para la revisión de sentencia también se necesitan los informes médicos y sociales. Cualquier duda dimelo y lo veo…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-28','Amalia : contacto con Jorge de dependencia y solicito que corten el pago de los 86,31 € que se le abona por P.V.S y nos calcularan el cobro indebido ( son 24 meses los que hay que devolver ) . Para volver a retomarlo , hay que hacer una solicitud PIA inicial , éste se extingue , y harán una revisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-28','Amalia : contacto con Jorge de dependencia y solicito que corten el pago de los 86,31 € que se le abona por P.V.S y nos calcularan el cobro indebido ( son 24 meses los que hay que devolver ) . Para volver a retomarlo , hay que hacer una solicitud PIA inicial , éste se extingue , y harán una revisión.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-28','Buenos días, he estado reunida con el Jefe de Sección de dependencia que lleva esa zona para confirmar que efectivamente Angela está percibiendo P. Vinculada a Servicio y que no hay empresa contratada. He realizado las gestiones con la sección de prestaciones económicas del SEPAD y he solicitado cortar el pago y nos pasarán el cobro indebido que serán 24 meses de 86.31€ que hay que devolver . Para iniciar otro servicio hay que volver a solicitarlo todo de nuevo . Pero vamos a ver si pudiéramos ingresar a esta señora en residencia. ¿ha vuelto a pasar por tu despacho ? está más tranquila ? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='VARGAS'and apellido2='SUAREZ'),'2022-07-28','TERESA ENVIO ESCRITO PNC PARA ALTA EN EL SUBSISTEMA DE TERCEROS CON NUEVA CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2022-07-28','Ana: Óscar, secc. ecca, me comunica que a Conchi le han ingresado en julio dinero de Dependencia. Suponemos que es la Prestación Vinculada al SAR que se solicitó. Aquí no hemos recibido la Resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-07-28','Ana: Óscar, secc. ecca., me comunica que a Mª del Mar, ya le han ingresado la PFHC. ················','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-07-28','miguel, llega email del jzdo nº4 Plasencia y tras conversación telefónica con dicho juzgadonº4 Plasencia en relación con el procedimiento Ejecutoria 9/22, que reenvío email del jzdo de Plasencia nº4 a Ana, Oscar e Inés, donde disponen para Alfonso Marin de Caceres: 1.-Continúo el tratamiento psiquiátrico donde le corresponda, aunque mencionan el Luis Pastor de Plasencia, puede seguir yendo al que viniera haciendolo. 2.-Oscar, la condena de indemnización de los 3.000€ me dicen en el juzgado que ya ha sido abonada, aunque no me ha dicho quién la ha abonado. Por tanto Ana: desde la parte social hay que tener un seguimiento de las visitas al psiquiatra que haga. Estos meses tienes que lograr que el equipo médicos psiquiatras que le atiendan, nos manden justificante o informes pasen algunos meses o esté terminando la condena, poderlo comunicar al juzgado. Como veis la liquidación de la condena viene en documento adjunto (del 12-7-22 a 9-10-22), donde la fecha de comienzo es la que el tutelado ha firmado el requerimiento del cumplimiento. Inés, porfavor súbelo al expte/juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-07-28','Amalia : escribo email a Mar , TS del ESM , Juanjo TS de la UHB y Mayte ( jefa seccion CTAEX ) para informar del ultimo ingreso en la UHB . Solicito valoren desde psiquiatria si procede ingreso en CSS dada la situación en la que se encuentra la usuaria con peligro real para ella y terceros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-07-28','Ana: Ante la petición reiterada de Isabel, de acudir al domicilio familiar del 5-8 de agosto, fecha en que no estará la pareja de su madre por irse unos días a casa de su hermana. Teniendo en cuenta su necesidad emocional y que Francisca nos ha enviado un escrito firmado, indicando que Jesús, pareja, no estará y que se responsabiliza de que no haya proximidad entre Jesús e Isabel, se autoriza dicha salida. ············· Se lo comunica a Paula, TO CRR. ······································ *Envío correo a Toni-Futuex, exponiendo la situación y derivando a Isabel a programa, para solicitando que acudan a visitarla el viernes 5 al domicilio, para asegurarse que no hay nada raro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-07-25','Ana: correo del CRR: "Comunicar la confirmación del positivo en Covid 19 de la persona usuaria Juan Mario San Román Blasco. En estos momentos se encuentra en situación de aislamiento en el CRR con síntomas leves. Bastante intranquilo y agitado debido a la situación. Os seguiremos informando de su estado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2022-07-29','TERESA ENVIO RESOLCUCION INCAPACIDADD AL CRPS TAL Y COMO NOS HA SOLICITADO SE ARCHIVA EN SU EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-29','-Email de la TS del SSASB : Buenos días Amalia, ayer estuvo Ángela en mi despacho, estaba más calmada, le expliqué como vamos a proceder hasta que se le conceda el presupuesto mensual con el tema de las compras en el Super y en la farmacia, parece que lo entendió y se mostró conforme. Le insisití en que me dijera a quien había entregado los 3000 euros del " préstamo personal que ella refería" y me dijo que se los había dado a los testigos de Jehova, no se si esto es cierto o es algo consensuado entre Quini, su auxiliar, y ella. El caso es que Ángela,me dijo ayer que todos los domingos solía ir a Jerez de los caballeros a reuniones de los testigos de jehova, la llevaba un taxi desde Villanueva que le cobraba 45 euros. Otra cosa que quería comentarte es que ayer traía la cartilla del banco y me dejó echarle un vistazo, y no son 4000 euros lo que sacó en Junio, sino 5000 euros!! 1000 el día 2/6 1000 el día 27/6 3000 el día 30/6 Ójala y se puediera ingresar a esta señora en una residencia, sería el recurso más adecuado para ella viendo lo que estamos viendo, cualquier cosa no dudes en llamarme. Un saludo. --------------------------------------- lo derivo a la seccion eco y juridica por si procede denunciar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2022-07-29','TERESA AVISO AL CENTRO SOCIOSANITAIO PARA INDCARLE QUE YA TIENE LA PNC EN LA CUENTA Y PUEDEN COMPRARLE LO QUE NECESITE, LE PASO EL CASO A AMALIA PUES HA TERMINADO EL PLAN DE INTERVENCON','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-07-29','Ana: Llamada de Mª del Mar (648 625 099): le ha facilitado a Gloria la documentación relativa al Régimen de Separacion de Bienes para que Gloria, Ed. Futuex, me los envíe. Le explico que los guardaremos en el expdte. para lo que puedan servir, pero que eso no influye para la resolución de la pensión. ········ *Le informo que ya le han ingresado la primera mensualidad de la PFHC que le solicité.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-07-28','Ana: Llamada de Julia, dice haberse adaptado bien al centro y estar muy contenta con compañeros y profesionales. ··· Agradece el esfuerzo realizado para que ella pudiera acceder al recurso. ···· Se aprecia buen estado de ánimo, agradecimiento sincero y ganas de esforzarse para continuar bien en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-07-29','Ana: Correo de Paula, TO CRR: "sería necesario gestionar un extra económico, puesto que no estaba contemplada una salida en este momento. Podría tener un extra de unos 50 euros sobre el dinero mensual, con la posibilidad de retirarlo cuando cobre el dinero del mes. Pongo en copia a tus compañeros de la sección económica." ················· *Desde la secc. ecca. se aprueba dicho extra. Podrán retirarlo del 1-5 de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-07-29','miguel, llega por email del abogado jesus bueno testimonio de aceptacion de herencia y lo remite al abogado de la otra parte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-07-29','Ana: correo del CRR-CC: "Trasladamos incidencias de la persona usuaria Esteve Pascual Ramos, a partir del 10.05.2022 (las anteriores se enviaron en informe anterior). Como hemos comentado, desde su llegada al centro continua mostrando inestabilidad y alteraciones de conducta que no remiten a pesar de los cambios de medicación y las diferentes intervenciones realizadas, no adecuándose al perfil del centro en estos momentos." ···················· *Guardo documento con la relación de incidencias en el expdte. digital. ················ Envían después también desde el CRR, un PDF, con Informes de Psiquiatría, Urgencias así como Notas de Tratamiento y Enfermería. ······· Lo guardo en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-07-29','Ana: Correo de Ceferino en el ctutelar@: "Buenos días Ana soy ceferina Mariscal Crespo te hablo porque esto me urge. Mi novia Yasmina Pardo MIR la an trasladado al Crr de Cáceres y quisiera irme con ella y pedir un traslado lo antes que sea posible espero que puedas ponerte en contacto conmigo esta mañana antes de que coja vacaciones lo tengo muy claro quiero irme al CRR de Cáceres donde me espera mi novia Ceferino Mariscal Crespo" ·············· Recibo su llamada insistiendo en el mismo asunto. *Ya lo ha hablado con Carolina, Psicóloga, y ésta le ha dicho que la semana que viene tiene que volver a confirmarle esta decisión y las siguientes tres semanas también, pues no es la primera vez que lo demanda y luego cambia de opinión. ···· Le digo que si Carolina le ha dicho eso es por algo y tendrá que tener paciencia y aceptarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-08-01','miguel, contesto a la parte social y económica al email de Amalia: Buenos días, lo primero que necesitamos es que se aclaren los hechos (hubo alguien que sacara con ella el dinero?, la acompañaba alguien? Alguien ha visto algo?, hay que averiguar todo lo que se pueda) y una vez que sepamos con certeza lo que ha sucedido habrá de interponerse una denuncia (robo (con o sin fuerza), pérdida…) Dicha denuncia deberá ser realizada por ella misma y habrá de ser acompañada por alguien. Nosotros no podemos interponer denuncia por hechos que desconocemos ya que no estábamos presente. Una vez que esté interpuesta dicha denuncia la comunicaremos a su juzgado a los efectos oportunos. Si es posible hay que vigilar que no se repita, hablando por la parte económica por la entidad para vigilar posteriores intentos de sacar dinero… Cualquier duda me decís. ************************************************* email de Amalia a las 3 secciones: Buenos días , os paso email de la TS del SSASB del Vva. del Fresno. La señora ha sacado 5000€ en junio , es una tutela reciente. No sabemos con certeza a quién le ha dado el dinero , si es voluntariamente o se lo han robado. Sospechamos de una vecina que es la única persona con la que se relaciona . Pero hoy ha verbalizado que se los ha dado a los Testigos de Jehová. El caso es que insiste en que no tiene para comer , hemos hecho una transferencia de 150€ a un supermercado para que acuda allí a comprar comida ;hasta que se aclare esta situación. Area jurídica , procede interponer denuncia ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-08-01','TERESA EMAIL PROGRAMA FAMILIA TAJO SALOR Según nos dice están viviendo en la casa de la abuela de su pareja en Badajoz pero no sabemos mucho más','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-07-29','Ana: Correo de Toni - Futuex: "Nos contacta Belén, gerente del hotel, para comunicar que no ha recibido el pago de la factura correspondiente al mes de julio. Como siempre, todo discurre sin inconveniente alguno, se mantiene el mismo coste y con las coberturas como hasta el momento. Además, todo aquello que Jose precisa se lo proporcionan sin inconveniente alguno. Hemos seguido preguntando por las posibles otras opciones de alojamiento pero por nada, no hay nada disponible y algunas pensiones ademas cierran julio y agosto. Esta pendiente de reocoger el certificado de empadronamiento en el pueblo, nos dijo que lo cogeria cuando fuera para allá y luego te lo hacemos llegar." ·········· Envío factura a Óscar, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-08-01','miguel, llega email de Alberto con copia a Oscar y Ana en relación al email de Oscar de 5-5-22: Situación tutelada: • Ya cobra la pensión por la nueva cuenta. • Atrasos y cuota centro hasta abril por la cuenta que tiene junto a su hermano. En mayo aún no la han pasado por ninguna de las dos cuentas. • Depósitos que tiene con hermano a interés 0%: o 20.000 € vence 17/04/2024. o 90.000 € vence 14/05/2022. o 20.000 € vence 23/07/2022. Ver qué hacemos con ellos. La cuenta de abono es la que comparte con el hermano. Podemos cancelar y traspasar la mitad del dinero a cuenta de tutelada, antes de que se lo gaste el hermano ********************* TOD@S: VER CORREO ANTERIOR DE OSCAR. • HERMANO, SIN CONTAR CON AUTORIZACIÓN CTAEX HA RESCATADO EL DEPOSITO DE 20.000 DEL 23/07/2022...DESDE AREA ECO (OSCAR), VAMOS A TRAMITAR TRANSFERENCIA X 10.000 € A CCC TUTELADA...NO SABEMOS SI SERÁ POSIBLE YA QUE HERMANO TUTELADO PODRÍA HABER DISPUESTO YA DE ESE DINERO. • LOS OTROS 2 DEPOSITOS DE 20.000 € Y 90.000 €: DESDE ÁREA ECONÓMICA, SI HERMANO NO HA REALIZADO NINGUNA OPERACIÓN, VAMOS A SOLICITAR EL RESCATE DEL 50 % DE LOS MISMOS Y SU INGRESO EN CCC TUTELADA...DADO QUE EL HERMANO HA PODIDO HACERLO SUPONEMOS QUE BANCO NOS AUTORIZARÁ.......MIGUEL: VES ALGÚN PROBLEMA CON ESTO??? • ANA: VAMOS A DOMICILIAR EL GASTO DEL CENTRO EN LA CCC DE LA HERMANA....HASTA AHORA ESTABA DOMICILIADO EN LA CCC COMUN CON SU HERMANO. ________________________________________ ************************************************** mi contestación a los 3: Hola, como sabéis ya tenemos abogada que está tramitando en el juzgado la reclamación dispuesta por el hermano cuando asumimos la tutela. Los datos de ella son mariaflorianocampon@gmail.com tlfno 927580392 Si me enviáis los justificantes (movimientos de cuenta de dinero dispuesto irregularmente por el hermano) se lo remito a esta abogada para que los una a la causa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-08-01','miguel, recibo email del abogado Jose Miguel Mateos Calvo >jmateos@icac.es> Buenos días, nos ponemos en contacto con ustedes en relación con la autorización judicial solicitada para que la tutelada, doña María Jesús Martín Calle, pueda aceptar, sin beneficio de inventario, las herencias de sus padres junto con sus hijos y sus hermanos, ya que somos los letrados a los que estos últimos nos han encargado realizar los trabajos, las gestiones y las actuaciones oportunas a tal fin. Según nos ha indicado nuestro compañero don Jesús Bueno Clemente, parece ser que ya se ha dictado el Auto autorizando dicha aceptación, que es el único documento que estaba pendiente para poder formalizar notarialmente las referidas herencias, por lo que, si les parece bien, les rogamos que nos hagan llegar una copia del citado Auto para poder llevarlo a la notaría o, si así lo prefiriesen, les facilitaríamos el contacto de la notaría de Plasencia para que se lo hicieran llegar directamente a ella. Una vez que estuviera preparada la escritura pública de aceptación, se lo comunicaríamos para organizar la fecha y la hora, que les viniera bien a ustedes y a todos los demás interesados, para proceder a su firma. Quedamos a la espera de sus noticias y, en cualquier caso, a su disposición para cualquier cuestión o comentario que estimen oportuno trasladarnos. Gracias, un saludo. Francisco Mateos Roco Calle Rey, 17, 1º-A 10600 Plasencia Cáceres Tlf: 927411525 ****************************************** Le respondo adjuntandole el testimonio de autorización de herencia: Buenos días conforme su email le remito el testimonio para incorporarlo en la notaria al resto de documentación. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-07-29','Ana: Correos de Raquel, TS del SSASB (ssasbrpa@gmail.com): "Buenos días Ana, el motivo de escribirte es comunicaros que en el día de hoy he hablado con la nueva directora de la residencia de Santiago de Alcántara, donde está Florencia Davila, ya que en reiteradas veces el hermano de ésta a acudido a mi despacho, interesado en que trasladen a su hermana a una residencia más cercana del domicilio familiar. Tras llamar a la residencia me han contado que el otro día ha ido a verla y ha intentado llevarsela, vamos que la ha montado en el coche y personal de la residencia ha tenido que salir y evitar lo que Cesario quería hacer. Simplemente es comunicarlo, y que lo pongas en conocimiento del departamente que corresponda" ············· "Disculpa nuevamente, tras hablar nuevamente con la residencia me comentan que el intento de montarla en el coche ocurrió otro día que fue el hermano al verla. Y la semana pasada o la anterior, les dijo que se quería llevar a su hermana al pueblo, al decirle que no podía, llegó un señor más joven que él y preguntó que si estaba tutelada por la junta, y le explicaron. Para cualquier aclaración al respecto, lo ideal es que se contacte con la residencia para que os expliquen." ···· Agradezco la información comunicada, pues desconocíamos los hechos. ···············','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2022-04-29','Ana: Correo de Toni-Futuex: "Hola de nuevo, en relación a Juan Chamorro y el móvil, estás han sido las gestiones realizadas: Se ha procedido, según estaba autorizado, la compra de un terminal con nuevo número móvil para Juan Chamorro Holguín, por importe presupuestado de 104,99, que incluye además tarjeta prepago de 5 euros, que debe ir cargando cada mes. Se adjunta fotografía del modelo, y factura a nombre de Juan Chamorro, donde viene el número de cuenta para realizar el abono mediante transferencia bancaria (ES65-2100-4375-8601-0054-1983) En la próxima semana se planifica un día para realizar visita y entrega de dicho terminal en Guadalupe, totalmente activado con número nuevo: 613112091 Ya sabía que hoy viernes 29, podía acudir a la entidad Liberbank para retirada de dinero extra." ················ Óscar, secc. ecca., se encargar del abono de la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-08-01','miguel, enviamos vía lexnet solicitud de revisión de sentencia del tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2022-08-01','TERESA LLAMO AL TS DEL HOSPITAL DE ZAFRA PARA PEDIR IFNORMACION 40335 Y ME COMENTA QUE NO ME PUEDE FACILITAR INFORMACION POR TELEFONO QUE TAN SOLO ME PUEDE INDICAR DE CUANDO SE VA A PRODUCIR EL ALTA Y SI LA EVOLUCION ES BUENA O MALA QUEDA EN INFORMARSE Y LLAMARME PARA DECIRME','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-01','Ana: Llamo a Mila, Revital (927 22 55 30 // Nº personal: 676 593 154): ······················································································································································· Envío correo a Toni-Futuex: "Hola, de nuevo, Toni, Con respecto al presupuesto de la farmacia, lleva varias semanas preguntando por él, estábamos a la espera. Lo paso a la sección ecca., por mi parte les daré el ok, pues entiendo que es necesario y dada la cuantía no creo que pongan problema. La idea es abonarlo mediante transferencia bancaria a la farmacia, ya se lo dije también a José Manuel, así no hay que modificar su asignación y nos aseguramos de que se abona y él tiene los productos que necesita periódicamente. Por cierto, en el presupuesto, se ve ven borrosos los datos, ¿podríais facilitarnos el nombre y teléfono de contacto de la farmacia para llegar a un acuerdo con ellos? En cuanto al aumento de asignación que solicita José Manuel, hablé con él la semana pasada al respecto, le dije que teniendo en cuenta los últimos presupuestos aprobados, Alberto no creo que ceda en eso, y que además, si realmente reduce el consumo de tabaco y bebidas energéticas, debe de disponer más dinero en efectivo para otras cuestiones. *Ojalá y que la asistencia a los ECA (antiguos CEDEX) dé sus frutos, sería todo un logro con José Manuel… En relación al cierre del Catering por vacaciones, en mi opinión, lo más fiable y más saludable para él, es contratar otro cáterin, pero entiendo también, que es complicado para tan pocos días. Así que hablándolo con Maite, se le ocurre, y si la compañera puede, a mí me parece bien, que podría acompañarle Virginia a retirar el extra y a realizar la compra de productos precocinados (lo más saludable posible) para esas dos semanas (Del 13 al 28). Confirmarnos, por favor, si esto es posible, pues no sé cuándo coge vacaciones Virginia. *Para el día 7, que es algo puntual, él me ha manifestado en varias ocasiones, que a veces le sobra comida de un día para otro, y de hecho ha anudado el pedido cuando tenía comida en casa, así que creo que podría apañarse. Por último, la asistencia a Revital, considero que puede ser interesante para él, al menos tendría otros apoyos, un tratamiento individualizado y una ocupación, aunque fueran días puntuales en semana. Como bien decís, el perfil de José Manuel es complicado y a todas nos surgen reticencias, pero tampoco se pierde nada por probar. Él dijo que no quería ir si tenía que pagar, por poco que fuera (copago), pero al parecer, tratándose de tratamientos, no tiene por qué haber copago y si lo hubiera es posible que sea una cuantía baja. He llamado a la Clínica y van a preparar el Contrato con Cláusula Suspensiva, ya le he facilitado los datos y vamos a tramitar la revisión PIA a tal fin."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-01','Ana: Llamo a Mila, Revital (927 22 55 30 // Nº personal: 676 593 154): ······················································································································································· Envío correo a Toni-Futuex: "Hola, de nuevo, Toni, Con respecto al presupuesto de la farmacia, lleva varias semanas preguntando por él, estábamos a la espera. Lo paso a la sección ecca., por mi parte les daré el ok, pues entiendo que es necesario y dada la cuantía no creo que pongan problema. La idea es abonarlo mediante transferencia bancaria a la farmacia, ya se lo dije también a José Manuel, así no hay que modificar su asignación y nos aseguramos de que se abona y él tiene los productos que necesita periódicamente. Por cierto, en el presupuesto, se ve ven borrosos los datos, ¿podríais facilitarnos el nombre y teléfono de contacto de la farmacia para llegar a un acuerdo con ellos? En cuanto al aumento de asignación que solicita José Manuel, hablé con él la semana pasada al respecto, le dije que teniendo en cuenta los últimos presupuestos aprobados, Alberto no creo que ceda en eso, y que además, si realmente reduce el consumo de tabaco y bebidas energéticas, debe de disponer más dinero en efectivo para otras cuestiones. *Ojalá y que la asistencia a los ECA (antiguos CEDEX) dé sus frutos, sería todo un logro con José Manuel… En relación al cierre del Catering por vacaciones, en mi opinión, lo más fiable y más saludable para él, es contratar otro cáterin, pero entiendo también, que es complicado para tan pocos días. Así que hablándolo con Maite, se le ocurre, y si la compañera puede, a mí me parece bien, que podría acompañarle Virginia a retirar el extra y a realizar la compra de productos precocinados (lo más saludable posible) para esas dos semanas (Del 13 al 28). Confirmarnos, por favor, si esto es posible, pues no sé cuándo coge vacaciones Virginia. *Para el día 7, que es algo puntual, él me ha manifestado en varias ocasiones, que a veces le sobra comida de un día para otro, y de hecho ha anudado el pedido cuando tenía comida en casa, así que creo que podría apañarse. Por último, la asistencia a Revital, considero que puede ser interesante para él, al menos tendría otros apoyos, un tratamiento individualizado y una ocupación, aunque fueran días puntuales en semana. Como bien decís, el perfil de José Manuel es complicado y a todas nos surgen reticencias, pero tampoco se pierde nada por probar. Él dijo que no quería ir si tenía que pagar, por poco que fuera (copago), pero al parecer, tratándose de tratamientos, no tiene por qué haber copago y si lo hubiera es posible que sea una cuantía baja. He llamado a la Clínica y van a preparar el Contrato con Cláusula Suspensiva, ya le he facilitado los datos y vamos a tramitar la revisión PIA a tal fin."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-07-12','Maite:he hablado con el centro. Solicitaban una salida de Juan de 2/3 días al pueblo. La familia no asegura poder hacerse cargo de él durante ese tiempo. Tras valorar la situación hemos decicido que vaya un sólo día acompañado por un cuidador y así ver cómo va la visita , para ver la posibilidad de autorizar salidas de varios días. Hemos recibido el presupuesto del coste del monitor y del taxi. Se fijará el dia de visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-08-02','-Email TS del SSASB y mi respuesta. Buenos días , sólo podría ingresar en pisos si ella voluntariamente quiere , si es así , sin problemas . Si no quiere , se podría solicitar internamiento involuntario que habría que justificar muy mucho , por ahora no creo que el juzgado lo admita. Aunque le dieran la autorización , si ella no quiere estar se iría igualmente a su casa. Un saludo . SSB Villanueva Del Fresno Buenos días de nuevo! Ha estado aquí Ángela, justo después de hablar contigo, para decirme que el otro día se equivocó, que no le debe 60 euros a Quini, que son 40 Quini y 20 euros a otra chica que tiene el sábado, y también me ha dicho que a los testigos de jehová no les dió 3000 euros pero que si le dió una buena aportación, cada vez me dice una cosa, hoy si venía sola, le he dicho de irse a una residencia y me dice que cuando se encuentre peor si, no se si se puede dar el caso de ingresar a Ángela en los pisos tutelados de aquí de Villanueva??, pienso que sería una buena opción, la alejaríamos de Quini y ella estaría en el pueblo, que es lo que ella quiere y tendría la posibilidad de ir a su casa cuando lo deseara. Te dejo el número de cuenta y los datos de la farmacia, la cantidad ahora mismo que tiene a deber son 10,30 Farmacia Mª Ángeles Carretero Conde c/ Los Árboles Nº1 ( vva del fresno ) Badajoz CP 06110 Tlfno: 679475061 nº cuenta 3009008404202273835625','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-08-02','-Email TS del SSASB y mi respuesta. Buenos días , sólo podría ingresar en pisos si ella voluntariamente quiere , si es así , sin problemas . Si no quiere , se podría solicitar internamiento involuntario que habría que justificar muy mucho , por ahora no creo que el juzgado lo admita. Aunque le dieran la autorización , si ella no quiere estar se iría igualmente a su casa. Un saludo . SSB Villanueva Del Fresno --------------------------------------------- Buenos días de nuevo! Ha estado aquí Ángela, justo después de hablar contigo, para decirme que el otro día se equivocó, que no le debe 60 euros a Quini, que son 40 Quini y 20 euros a otra chica que tiene el sábado, y también me ha dicho que a los testigos de jehová no les dió 3000 euros pero que si le dió una buena aportación, cada vez me dice una cosa, hoy si venía sola, le he dicho de irse a una residencia y me dice que cuando se encuentre peor si, no se si se puede dar el caso de ingresar a Ángela en los pisos tutelados de aquí de Villanueva??, pienso que sería una buena opción, la alejaríamos de Quini y ella estaría en el pueblo, que es lo que ella quiere y tendría la posibilidad de ir a su casa cuando lo deseara. Te dejo el número de cuenta y los datos de la farmacia, la cantidad ahora mismo que tiene a deber son 10,30 Farmacia Mª Ángeles Carretero Conde c/ Los Árboles Nº1 ( vva del fresno ) Badajoz CP 06110 Tlfno: 679475061 nº cuenta 3009008404202273835625','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-08-02','nos ha informado la tutelada Rosa Serrano de Valdelacalzada, su marido ha fallecido en el dia de ayer, estaba en UCI , afectado por Covid creemos, este hombre tenia una frágil salud .. no sabemos si ahora ella podrá optar a una pensión de viudedad, porque tampoco sabemos si el marido habia trabajado.. -------------------- No le corresponde pq percibia PNC .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-08-02','Con fecha lunes 18 de julio de 2022, se realiza acompañamiento al juzgado por la citación que Emilia Morales tenía, en calidad de testigo en el procedimiento abierto por quebrantamiento de medidas cautelaras/ orden de alejamiento de su ex pareja Miguel Ángel Mateos, que está cumpliendo cárcel preventiva, en centro penitenciario de Badajoz. En este procedimiento en concreto, hay otras dos causas abiertas, Emilia no tenía asignado abogado. Solo estaban dos abogados de oficio por la parte de Miguel Ángel. Ellos han sido los que nos ha informado que solicitaron, tanto a la jueza como al fiscal, unificar estos procedimientos en uno solo, puesto que todo surge de las distintas denuncias que Emilia ha presentado: la de hoy lunes 18, en relación a que Emilia se fue a Don Benito, voluntariamente el año pasado y fue vista con Miguel Ángel, de paseo, estando ya emitida la orden de alejamiento. La guardia civil se lo llevo y cumple ahora prisión preventiva. Las otras dos citaciones como testigo, jueves 21 y viernes 22 de julio de 2022, son otras denuncias por las llamadas que Miguel ángel ha realizado a Emilia. El fiscal ha rechazado la petición de poder realizar vista u juicio de las tres causas en conjunto, de ahí que debe acudir Emilia también el jueves 21 y viernes 22 de julio. Antes del inicio de la vista, los abogados y el fiscal, con el visto bueno de la jueza, se ponen en comunicación, vía telefónica con Miguel Ángel, al que le comunican que si acepta conformidad de este hecho probado (ya que le detuvo la guarida civil con Emilia en Don Benito) con una condena de seis meses de prisión, o si decide ir a juicio el fiscal le pide un año de prisión. Al final acepta su conformidad y el quebrantamiento de la medida en sí. Por tanto, no hay que celebrar juicio en el día de hoy, quedando pendiente, como exponemos, las otras dos denuncias en relación a llamadas de teléfono. Emilia, que se ha desplazado desde CRR Olivenza hasta Badajoz en un taxi facilitado por el instituto de la mujer e igual, se muestra muy inestable emocionalmente, con momentos de ansiedad e irritabilidad, pasando del llanto a la euforia con mucha facilidad, siendo muy vulnerable, desconfiando de cualquier cosa que le digamos, pensando que solo tratamos de engañarla. Encontrarse así, le impide exponer con claridad un discurso coherente en relación a los hechos acontecidos. Cierto es, que estuvieron juntos en Don Benito, pero fue Emilia quien se desplazó allí. Que Miguel Ángel le llama y le escribe, como esta semana pasada, que ha recibido de él una carta, pero Emilia también le ha escrito, y no deja de llamarle, bien a Miguel ángel o a su hermano no cortando, por tanto, el vínculo existente y dando pie a que él comente, que Ella desea continuar la relación. Se realiza acompañamiento a cita planificada hoy 21 de julio de 2022, por una cédula de citación en el juzgado de lo penal nº 1 de Badajoz, citada como testigo en el supuesto quebrantamiento de condena y media cautelar por parte de Miguel Ángel Mateos, (anterior pareja de Emilia). Procedimiento por otra denuncia presentada por Emilia, en este caso, por una llamada que recibe por parte de Miguel ángel estando ella de paseo, y con testigos de profesionales del CRR Olivenza, que han sido citados también hoy como testigos. Miguel Ángel estaba citado presencialmente, ha acudido sin encontrarse con Emilia y se ah reunido con el fiscal y los abogados de ambas partes, para llegar a una conformidad del caso. Acepta los hechos y una condena de 10 mese y 15 días de prisión, que se sumaran a los seis meses que le han fijado por la denuncia del lunes 18 julio. Por tanto, Emilia no ha necesitado entrar en sala y se da por cerrado este hecho. Mejor para Ella que ya estaba muy alterada y con gran ansiedad. Se realiza siguiente acompañamiento el viernes 22 de julio, nuevo procedimiento, dentro de la causa de quebrantamiento de medidas cautelares. En esta citación Miguel ángel no acude presencialmente, se realiza el contacto por videollamada, para exponer la aceptación de conformidad por los siguientes hechos acontecidos: con fecha 18 de febrero fue visto en la población de Olivenza y se acercó a Emilia, pidiendo dinero y que le retirara las denuncias. A pesar de su resistencia inicial, sabedor de que los hechos han sido probados, acepta de nuevo, como los dos días anteriores, conformidad y 10 meses de prisión que si irán sumando a las anteriores penas. Por este motivo Emilia no tiene necesidad de entrar en sala ya que no se celebra la vista oral y se da por cerrado el caso una vez se emita sentencia. Hecho que ella agradece pues muestra mucha ansiedad al no poder exponer los hechos acontecidos con gran dificultad para recordar fecha y horas. (En otras ocasiones ha sido un desproposito, con un lenguaje muy desorganizado, que hacia ininteligible el discurso) No ha tenido abogado de oficio, pero el de Miguel Ángel y un guardia civil del cuartel de Olivenza, citado como testigo en este caso, le aconsejan que, en la medida de lo posible, no acepte las llamadas ni de Miguel Ángel ni de su hermano. También esperan que con el tiempo que Miguel Ángel estará en centro penitencial, pueda darse cuenta de que no cumplir las medidas tiene graves consecuencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-02','De: Jesus Perez de Acevedo Pinna >jesus@abacolegal.es> Enviado el: lunes, 01 de agosto de 2022 12:00 Para: Comisión Tutelar de Adultos (ctutelar@salud-juntaex.es) >ctutelar@salud-juntaex.es>; Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: Limpieza piso Mercedes Buenos días, El piso de Mercedes ya esta limpio. Es impresionante como estaba, he visto como vomitaban las dos señoras de la limpieza de los olores, han tenido que trabajar con doble mascarilla impregnada en colonia. Lo han dejado perfecto, muy bien. Han tenido que tirar muucha basura, ropa que estaba impregnada con caca y orines del perro, toda la comida. Mucho trabajo la verdad. Yo he estado pasando mientras trabajaban por que estoy cuidando al perro y al gato con la ayuda de un vecino suyo con el que ella tiene muy buena relación. Es un veterinario encantador que la ayuda muchísimo habitualmente. La tortuga murió, no sabemos exactamente por qué, parece que se ahogó. No puedo enviar los videos por que ocupan demasiado pero envío algunas capturas de los mismos, si los queréis decirme un móvil y los envío por whats app. Hace falta que vaya un fontanero por que el fregadero tenia un atasco y no ha habido forma de desatascarlo con productos. Así que tuvieron que desmontarlo para vaciarlo con un cubo. Tiene una montaña de ropa de media habitación, además de la que se ha tirado. Jaqueline ira lavándola a lo largo de esta semana para dejarla preparada. Para este trabajo Jaqueline y la otra chica que la ha ayudado han necesitado 13 horas, dos días y cobraran 15€ la hora. Es razonable teniendo en cuenta lo que había allí dentro. 390€. En ese importe Jaqueline incluye el lavado de la ropa que hará a lo largo de esta semana. Además de 76,75€ de productos de limpieza que tuvo que comprar. Adjunto los tickets. Mercedes no tenía nada y yo le dije a Jacqueline que comprar lo que necesitara. La cuenta de Jaqueline es la siguiente- ES47 0049 4640 9022 9510 7975. Por favor, no tardéis en pagarle que ella, la pobre, atiene rápido cuando la necesitamos y es la única persona que se mete en estos problemas de Mercedes. Quedo a la espera de confirmación de que hacéis la transferencia- 466,75€. Al respecto del tema médico, sabéis algo de Mercedes?, esta vez nadie me ha llamado del hospital. ----------------------------------- Se procede al abono . Jesús Pérez de Acevedo Pinna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-02','De: Jesus Perez de Acevedo Pinna >jesus@abacolegal.es> Enviado el: lunes, 01 de agosto de 2022 12:00 Para: Comisión Tutelar de Adultos (ctutelar@salud-juntaex.es) >ctutelar@salud-juntaex.es>; Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: Limpieza piso Mercedes Buenos días, El piso de Mercedes ya esta limpio. Es impresionante como estaba, he visto como vomitaban las dos señoras de la limpieza de los olores, han tenido que trabajar con doble mascarilla impregnada en colonia. Lo han dejado perfecto, muy bien. Han tenido que tirar muucha basura, ropa que estaba impregnada con caca y orines del perro, toda la comida. Mucho trabajo la verdad. Yo he estado pasando mientras trabajaban por que estoy cuidando al perro y al gato con la ayuda de un vecino suyo con el que ella tiene muy buena relación. Es un veterinario encantador que la ayuda muchísimo habitualmente. La tortuga murió, no sabemos exactamente por qué, parece que se ahogó. No puedo enviar los videos por que ocupan demasiado pero envío algunas capturas de los mismos, si los queréis decirme un móvil y los envío por whats app. Hace falta que vaya un fontanero por que el fregadero tenia un atasco y no ha habido forma de desatascarlo con productos. Así que tuvieron que desmontarlo para vaciarlo con un cubo. Tiene una montaña de ropa de media habitación, además de la que se ha tirado. Jaqueline ira lavándola a lo largo de esta semana para dejarla preparada. Para este trabajo Jaqueline y la otra chica que la ha ayudado han necesitado 13 horas, dos días y cobraran 15€ la hora. Es razonable teniendo en cuenta lo que había allí dentro. 390€. En ese importe Jaqueline incluye el lavado de la ropa que 