insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2022-08-02','-Solicito a P. Inclusión contrato ultimo con fecha de finalizacion y todas las nominas para comunicar a PNC . Como le harán un nuevo contrato , dicen que ya lo han enviado para firma , no creo que le corresponda PNC:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2022-08-02','Vuelvo a pedir al centro que nos diga cuanto se le debe por la subida.','2');
