insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2022-08-02','Amalia: le hemos subido la asignación a 108 €/semana (468 €/mes), desde 01/05/2022...anteriormente tenía 75 € porque había cometido alguna de las suyas (contrató sin autorización Secruritas Direct y una tarjeta bancaria). En mi opinión los 108 son suficiente...además tenemos presupuesto en supermercado de 320 €/mes, que está utilizando. Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-02','Ana: Envío correo a Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "En cuanto a Doroteo, considero que tanto desde aquí, desde el Programa de Apoyo Comunitario que gestiona Futuex (Virginia) como desde vuestro equipo, tenemos que seguir insistiéndole en la necesidad de que acepte ir a cualquier CRR, recordándole que después podrá solicitar el traslado al de Cáceres. *Además hay que hacerle ver que su hermana ya no quiere que siga viviendo en su casa y no tiene dónde ir." ·································································································································································································· Envío correo a Toni - Futuex: "En relación a DOROTEO DÍAZ CERRO, varias cuestiones: - Está en lista de espera ordinaria para el CRR de Cáceres (si hay lista de espera por emergencia social, imagínate cuánto puede tardar por lista ordinaria y más aún habiendo solicitado únicamente el centro de Cáceres… - La vivienda en la que vive con su madre, como sabéis, es de la hermana, Carmen. Ayer hablé con ella, me comunicó que debido al empeoramiento del estado de salud de su madre, se la quiere llevar a vivir con ella y para entonces, no quiere que Doroteo siga en la casa. Quiere que salga de allí, no quiere que se quede allí viviendo solo. Dada la actual situación, entendemos necesaria vuestra intervención con Doroteo para: - Hacerle ver la necesidad de aceptar todos los CRR, para que Pilar Martín, ESM, pueda tramitarlo por emergencia social. **Explicándole que, a posteriori, podría solicitar el traslado o la permuta al centro de Cáceres. - En el peor de los casos, es decir, que no lo acepte, ayudarle a buscar alojamiento alternativo. Si finalmente esto fuera necesario, lo ideal sería un hostal/pensión, pero sus ingresos son: 721,70, por lo que habría que encontrar algo con un precio ajustado para que pueda costearlo y que además le siga quedando dinero para gastos de bolsillo y para seguir costeando el Seguro de Decesos. Si no encontraseis nada que se ajustara, habría que ayudarle a buscar un piso de alquiler."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-01','Ana: Conversación telefónica con Carmen, hermana de Doroteo (669 864 167): Su madre en la actualidad tiene un estado de salud delicado y se la quiere llevar a su casa para atenderla mejor. ··· *A Doroteo le ha consentido vivir en su otra casa con su madre, pues esta tenía la tutela anteriormente. En el momento que se lleve a su madre, quiere que Doroteo salga de la casa. Además su hermano no quiere salir de esa vivienda. Ante la propuesta de que le pague el alquiler responde "mi hermano no puede pagar lo que vale esa casa". *Dice que "la Junta tiene la tutela y por tanto debería de haberle buscado ya otro sitio para vivir. Es la responsable de mi hermano." ··· Le explico el funcionamiento de la CTAEX y le recuerdo que está en lista de espera ordinaria para el CRR de CC. Su hermano no acepta ir a ningún otro CRR. *Dado el perfil de su hermano no tiene cabida en otro recurso en la actualidad y no sabemos cuándo se le dará plaza. *A día de hoy no tenemos más alternativa. ····· Se trabajará con su hermano, a través del Programa de Apoyo Comunitario, para intentar hacerle entrar en razón de la necesidad de que acepte el ingreso en todos los CRR. *Si no se consigue, se le apoyará en la búsqueda de otro alojamiento (Pensión o vivienda de alquiler).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2022-08-02','TERESA RECIBO LLAMADA DE LA TS DEL HOSPITAL DE ZAFRA CAROLINA, ME COMENTA QUE EL ALTA ESTA PREVISTO PARA EL MARTES PERO TODO DEPENDE DE LA EVOLUCION QUE TENGA, ME DEJA ENTREVER QUE LA EVOLUCION NO ESTA SIENDO BUENA PERO NO ME FAICLITA MAS INFORACION PUES DICE QUE NO ME LA PUEDE FACILITAR POR TELEFNO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-08-02','RENDICIO ANUAL VIVE SOLO EN SU CASA, ES HUERFANO Y NO TIENE FAMILIARES, SU UNICO HERMANO FALLECIO HACE VARIS AÑOS NO LE GUSTA ACUDIR AL MEDICO, ACTUALMENTE SE ENCUENTA SANO NO TIENE RELACIONES SOCIALES, SALE DE CASA CUANDO YA NO HAY GENTE POR LA CALLE, SOLO SE RELACIONA CON SUS CUIDADORAS, CO LA DELEGADA TUTELAR Y CON EL TRABAJADOR SOCIAL DEL SASB. PRECIBO PF417,70 Y ORFADAD 853,33 SALDO 29250€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-02','Ana: Correo de Pilar Martín, TS ESM-CC: "...ya he recibido el PIA de Martín, por un lado se le va a solicitar mantenimiento de la plaza T3 por el tiempo que el este aquí todavía. Por otro lado se le va solicitar plaza en CRR, cuando se lo den, yo lo entregaré por registro el viernes, el ya lo ha firmado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-02','Ana: Envío correo a Marta, TS del SSASB de Cilleros (tsocial@ayuntamientodecilleros.es) informando de la fecha en que ingresó en el CRR y su buena adaptación al mismo. ········································································································································ Envío correo a Paula, TO, y Carolina, Psicóloga, CRR, solicitando el Certificado de Ingreso en el CRR de Julia, para poder comunicarlo al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-02','miguel, recibo email de la tía de los tutelados Amelia: Buenas tardes, Miguel, ésta mañana volví a hablar con la notaría de Brihuega para recordarles estamos pendientes de que confeccionen escritura de aceptación de herencia de mis familiares. Vuelve a decirme Mónica que tienen mucho trabajo atrasado y que ahora comienzan las vacaciones, con lo cual, hasta finales de septiembre, no comenzarán a revisar, por orden de antigüedad, las distintas peticiones. Respecto a la vivienda de mis primos, después de hablar con varias inmobiliarias y decirme que está muy lejos el pueblo para encargarse ellos de la venta, he decidido dar de alta la venta en el Idealista o paginas similares y encargarme yo de las llamadas de teléfono y de las visitas, como me parece importante que la vivienda esté habitada para que no se incremente su deterioro, prefiriendo la venta, la he ofertado también como alquiler de mínimo un año. Entiendo que son viables las dos opciones y caso que encuentre algún interesado, cómo habría que gestionar? Gracias *********************Pregunto a Oscar por el saldo que tienen cada uno a fecha actual para buscar abogado de pago en Guadalajara y Don Benito, y me contesta: Sergio tiene 13.233€ en Unicaja y en Caixabank, a 1 de julio de 2021, tenía 72.885 €. Raúl tiene 13.355€ en Unicaja. Tiene una cuenta en Caixabank de la que desconocemos el saldo. ******************** Contesto a Amelia:Buenos días Amelia, te comento varias cuestiones a tener en cuenta. Para que se firme la herencia, al ser tutelados, la ley exige que el juzgado autorice: 1.-La aceptación de la herencia: que será previo a la firma. El juzgado competente será el último domicilio del causante. Por tanto necesitaremos un abogado donde fallecieron sus padres, es decir en Huetos (Guadalajara) su padre Máximo y en Cifuentes (Guadalajara) su madre Teresa. Por tanto necesitamos que me indiques el nombre y teléfono de 2 o 3 abogados para que comparemos presupuestos para contratarlos para que soliciten dicha autorización judicial de aceptación de herencia. Tras eso se podrá firmar la herencia. 2.-Una vez firmada la herencia hay que pedir Autorización judicial de aprobación de herencia en el el juzgado del domicilio actual de los herederos, que es en Don Benito (Badajoz). Por tanto tendremos que contratar un abogado de la zona 3.-Una vez todo esto hay que solicitar Autorización judicial para poder vender en el juzgado del domicilio de los tutelados, por tanto en Don Benito (Badajoz). Si bien la ley permite solicitarlo sin intervención de abogado, es seguro que después nos lo pedirá el juzgado, con lo que hay que buscarle un abogado de Don Benito. Aquí entre otros documentos el juzgado nos pedirá una tasación de la vivienda, para que ellos puedan autorizar por un precio mínimo la venta. Por tanto el abogado que busquemos en Don Benito debería llevar tanto la Solicitud de Autorización judicial de aprobación de la herencia como la Solicitud de Autorización judicial de venta. Si tienes cualquier duda ves comentándomelo. Teniendo en cuenta que no cumplen los requisitos para abogado de Oficio. Si quieres ves localizando abogados 2 o 3 abogados de Huetos y/o Cifuentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-02','miguel, recibo email de la tía de los tutelados Amelia: Buenas tardes, Miguel, ésta mañana volví a hablar con la notaría de Brihuega para recordarles estamos pendientes de que confeccionen escritura de aceptación de herencia de mis familiares. Vuelve a decirme Mónica que tienen mucho trabajo atrasado y que ahora comienzan las vacaciones, con lo cual, hasta finales de septiembre, no comenzarán a revisar, por orden de antigüedad, las distintas peticiones. Respecto a la vivienda de mis primos, después de hablar con varias inmobiliarias y decirme que está muy lejos el pueblo para encargarse ellos de la venta, he decidido dar de alta la venta en el Idealista o paginas similares y encargarme yo de las llamadas de teléfono y de las visitas, como me parece importante que la vivienda esté habitada para que no se incremente su deterioro, prefiriendo la venta, la he ofertado también como alquiler de mínimo un año. Entiendo que son viables las dos opciones y caso que encuentre algún interesado, cómo habría que gestionar? Gracias *********************Pregunto a Oscar por el saldo que tienen cada uno a fecha actual para buscar abogado de pago en Guadalajara y Don Benito, y me contesta: Sergio tiene 13.233€ en Unicaja y en Caixabank, a 1 de julio de 2021, tenía 72.885 €. Raúl tiene 13.355€ en Unicaja. Tiene una cuenta en Caixabank de la que desconocemos el saldo. ******************** Contesto a Amelia:Buenos días Amelia, te comento varias cuestiones a tener en cuenta. Para que se firme la herencia, al ser tutelados, la ley exige que el juzgado autorice: 1.-La aceptación de la herencia: que será previo a la firma. El juzgado competente será el último domicilio del causante. Por tanto necesitaremos un abogado donde fallecieron sus padres, es decir en Huetos (Guadalajara) su padre Máximo y en Cifuentes (Guadalajara) su madre Teresa. Por tanto necesitamos que me indiques el nombre y teléfono de 2 o 3 abogados para que comparemos presupuestos para contratarlos para que soliciten dicha autorización judicial de aceptación de herencia. Tras eso se podrá firmar la herencia. 2.-Una vez firmada la herencia hay que pedir Autorización judicial de aprobación de herencia en el el juzgado del domicilio actual de los herederos, que es en Don Benito (Badajoz). Por tanto tendremos que contratar un abogado de la zona 3.-Una vez todo esto hay que solicitar Autorización judicial para poder vender en el juzgado del domicilio de los tutelados, por tanto en Don Benito (Badajoz). Si bien la ley permite solicitarlo sin intervención de abogado, es seguro que después nos lo pedirá el juzgado, con lo que hay que buscarle un abogado de Don Benito. Aquí entre otros documentos el juzgado nos pedirá una tasación de la vivienda, para que ellos puedan autorizar por un precio mínimo la venta. Por tanto el abogado que busquemos en Don Benito debería llevar tanto la Solicitud de Autorización judicial de aprobación de la herencia como la Solicitud de Autorización judicial de venta. Si tienes cualquier duda ves comentándomelo. Teniendo en cuenta que no cumplen los requisitos para abogado de Oficio. Si quieres ves localizando abogados 2 o 3 abogados de Huetos y/o Cifuentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-07-29','Ana: Correo de Modesto, Res. Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): "Adjunto enviamos los presupuestos de Juan Sanguino (Taxi y Acompañante), para aprobarlos y concretar el día de la salida que pueda disfrutar el también, jejeje... Esperamos la respuesta." ····················· *Envío correo a Óscar, Secc. Ecca. con el presupuesto: "...si es viable, se acepta la propuesta, pues se valora necearia la visita a su localidad de origen. Porfa, confirma a la residencia si es viable y ponnos en copia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-08-02','Ana: Correo de Óscar, secc. ecc., a la residencia con copia a Maite y a mí: "Se autorizan los gastos solicitados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-08-02','Ana: envío correo a Toni-Futuex, derivando a Mª Ángeles al Programa de Apoyo comunitario: solicito seguimiento temporal e informe al respecto "... Como te decía, sólo queremos corroborar que está bien atendida y que, efectivamente, su deseo es el de continuar residiendo en el centro en que está y vender la vivienda para poder afrontar el gasto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-02','Maite: hemos valorado la posibilidad de vender la casa de la que es propietario al 100%. Le he eenviado a Miguel y Angel para que pidan autorización para vender. Hola chicos, Debido a las deudas que tiene Martín Domínguez Palencia, sería conveniente vender la casa de la que es propietario al 100%. Lo vemos a la vuelta de vacaciones de Angel. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-08-02','Ana: Correo de Paula, TO CRR Plas. (tocupacional.crrplasencia@grupo5.net): "Hola Ana, te escribo para hablarte de una necesidad que expresa Javier Agudo Cumplido en referencia a su casa. Comenta que la cerradura de la puerta de su casa está en mal estado y no tiene llave actualmente, así como que necesitaría una limpieza profunda, puesto que recuerda que puede estar muy sucia. La dirección de la casa es C/Berrocalejo nº14 en Puerto de Santa Cruz, Cáceres. Nos gustaría que nos dijerais si esto es posible y en su caso apoyar la fórmula para llevarlo a cabo. Así mismo comentaros el deseo de Javier de continuar dando pasos en su proceso de recuperación planteándonos a corto plazo el posible paso a piso supervisado. Estamos evaluando y trabajando aspectos para poder abordar este objetivo importante para Javier." ··················· Mi respuesta: "Buenas tardes Paula, Ok, mañana pediré presupuesto a empresa de limpieza y cambio de cerradura. Tendrán que acudir a la vivienda para hacer valoración y poder facilitarnos un presupuesto. Quizá puedan acudir de futuex para acompañar a la empresa. En cuanto al deseo de pasar a Piso Supervisado, me sorprende que se plantee en tan poco tiempo, pero estamos abiertos a esta opción, por supuesto, siempre que haya informes técnico de vuestro equipo que avale esta decisión y este importante paso. Ya nos vais informando de su evolución y las valoraciones que hagáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-03','TERESA ARCHIVO COMUNICACION REDUCCION DEL IMPORTE DE LA PENSION DE POR PROCEDIMIENTO DE RECAUDACION EJECUTIVA DE LA TGSS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-07-14','miguel, llega a ctutelar email de Mely: Buenas tardes Miguel. Soy Mely Serrano,hermana de vuestro tutelado José Lara Serrano. He intentado ponerme en contacto contigo por teléfono pero no he podido para comentarte que ya hay una persona interesada en la compra del piso, la chica de la inmobiliaria me dice que hace falta que firmemos un contrato de arras para la reserva. Le he dado tu número y correo para que ella se ponga en contacto contigo y así entre vosotros os ponéis de acuerdo para la firma. Igualmente te mando el número de teléfono de la inmobiliaria por si tú la puedes llamar El número es 609155518,la chica se llama Angela. Me gustaría me confirmaras la llegada de este correo, gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-08-02','miguel, me llega email de la inmobiliaria Angela >angela@grupo2inmo.es>API 798 GRADUADO SOCIAL C/ Barranquet, 2 (03570) VILLAJOYOSA TELF. 966853066 / 609155518 Info@grupo2inmo.es : Buenos días! Somos de Grupo II inmobiliaria, nos han facilitado sus datos un familiar de un interno del centro (José Lara) que lo gestiona Miguel, es por una propiedad que tienen en Villajoyosa (Alicante), han reservado la vivienda y falta concretar cómo se puede formalizar la compraventa por parte de D. José Lara, le remitimos contrato para firma, la firma de la escritura está prevista para finales de agosto, en la notaría de Villajoyosa de D. Juan G. Giménez, ya nos comentan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-08-03','miguel, mi contestación a la inmobiliaria y Mely (670336090), ante la recepción de un contrato de venta con arras por importe de 69.000€: Buenos días, hemos recibido el contrato de compraventa. Únicamente deben incluir lo que les adjuntamos a efectos de que pueda ser firmado por el representante de la Comisión Tutelar de Adultos. Necesitaríamos también que nos remitan una nota simple lo más actualizada posible, ya que según vimos en la última nota simple a nombre de Doña Justa Serrano Palacios, existía una condición resolutoria, cuyo levantamiento registral por caducidad se solicitó en la escritura de adjudicación de herencia e ignoramos si ya se ha llevado a inscribir al registro de la propiedad dicha escritura de herencia con desaparición de dicha carga registral. Otra cuestión, no sé si importante, es que en la escritura de herencia se acreditó la viudedad en el momento de del fallecimiento de Doña Justa de Don José Lara González, pero tuvo otra relación con Don Juan Manuel Pérez Garcia, con el que tuvo 5 hijos, e ignoro cuál de los matrimonios fue posterior, a efectos de que comprueben con Mely si a Don Juan Manuel (o sus sucesores) pudieran haberle correspondido algún derecho sobre dicha vivienda. Imagino que se divorció de Don Juan Manuel y se casó de segundas nupcias con Don José Lara González. Recuerden también a efectos de los cálculos que correspondan a cada hermano que el reparto entre los 7 hermanos en vida. Una de ellas ostenta el legado del tercio de libre disposición (entiendo a parte de su tercio de legítima y mejora) y los otros 6 hermanos son herederos por partes iguales del restante de la masa hereditaria (entiendo que lo que les corresponda por el tercio legítima y tercio de mejora). Estos datos deben calcularlos con la notaria. Por último, han de avisarnos al menos una semana antes de la firma de la escritura ya que la notaria de allí habrá de ponerse en contacto con la notaria de Mérida, de Don Gonzalo Fdez Pugnaire, Borja Igartua Fesser y Francisco Javier Hernández Téllez, para que desde aquí podamos ratificar la misma mañana la venta vía telemática. Quedo a su disposición para cualquier aclaración o duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-03','miguel, Amelia (tía de los tutelados) plantea si en vez de venta pueda alquilarse. Tras consulta vía email con Alberto y Teresa decidimos venta. Por tanto Amelia comienza la búsqueda de abogados y tasadores para elegir uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-03','miguel, Amelia (tía de los tutelados) plantea si en vez de venta pueda alquilarse. Tras consulta vía email con Alberto y Teresa decidimos venta. Por tanto Amelia comienza la búsqueda de abogados y tasadores para elegir uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-08-02','miguel, tras el reenvío de email que me remite Teresa donde la guardia civil de Monesterio le solicita información acreditativa de la incapacidad y cargo de tutor de la comisión, llamo sin éxito a la guardia civil, llamaré mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-08-03','miguel, tras conversación con la guardia civil de Monesterio (Sargento 924-516013)me confirma que hay abiertas unas diligencias por un supuesto delito grave de lesiones, donde la tutelada es autora de los hechos producidos el 24-7-22, hay un video de momentos previos a la agresión, y que se producen en un grupo de personas que consumen estupefacientes de forma habitual. No sabe si en el momento de los hechos ella estaba o no drogada. Le informo no sólo de cómo funciona la Comisión Tutelar de Adultos, sino también de los problemas judiciales anteriores de la tutelada. Le remito vía email, las sentencias de incapacitación, recurso ante la audiencia y nombramiento de tutor a la Comisión Tutelar, para que los remita al juzgado de Zafra donde se está instruyendo el caso, ba-pto-monesterio@guardiacivil.org: Buenos días, conforme conversación telefónica adjunto sentencia de incapacitación que fue recurrida y estimada en Audiencia Provincial, nombrando como tutor a la Comisión Tutelar de Adultos. Adjunto también a los efectos oportunos certificado del Cadex de discapacidad de un 65% Quedo a su disposición para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2022-07-28','el pasado 28 de Julio se visitó a Concepción Delgado Motiño en su finca El Compresor en Azuaga. Se la encontró haciendo sus quehaceres cotidianos junto a su hija Inmaculada. Previamente se había llamado a un electricista de la localidad, Roberto Blázquez (687 22 52 77) para que se acercara esa mañana a la finca y comprobara el estado de la instalación eléctrica. Cuando se llegó a la finca se llamó a Roberto y él se personó al cabo de unos minutos, estuvo comprobando el estado de toda la instalación eléctrica, con un aparato especial estuvo revisando el cuadro que había dentro de la casa por si hubiera alguna fuga y fue a las afueras de la finca para mirar la caja. Se estuvo revisando también las últimas tres facturas de la luz y se comprobó que en la de Abril-Mayo de 273€, aparece que estuvo un técnico de Endesa verificando el equipo de medida porque Inma pidió que fuera alguien de la compañía de luz a echar un vistazo. Y llama la atención porque justo después de esa verificación y de que un técnico revisara la caja de luz, las facturas siguientes han llegado muy bajas. La de Mayo-Junio es de 32€ y la de Junio-Julio es de 43€. Roberto comenta que cree que debía haber un problema con el contador de luz y que cuando ha venido el técnico de Endesa lo ha cambiado sin comentar nada ni a Concepción ni a su hija Inma y de ahí que ahora las facturas sean tan bajas. Se habló por teléfono también con otro electricista de Azuaga, Fernando (615 33 56 53) que comentó que había estado en la finca hace unas cuantas semanas y había comprobado toda la instalación. Llegó a la conclusión de que no había fugas ni nada raro que produjera un gasto tan elevado de luz, por lo que creía que podría ser un fallo de la compañía. En la visita que se realizó, se estuvo revisando toda la vivienda y no se vio ningún aparato extraño que pudiera justificar ese gasto. Tienen los electrodomésticos normales de una casa: frigorífico, horno pequeño, lavadora, termo eléctrico, ventiladores, brasero eléctrico y poco más. Lo que no se comprende es cómo han podido tener unas facturas tan elevadas algunos meses de este año. Tanto Concepción como su hija Inma están muy preocupadas por los avisos de corte de luz ya que tienen fecha de Septiembre y no saben si se van a hacer efectivos o no. Este tema las tiene muy preocupadas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-08-03','TERESA Aitor volvió ayer de Badajoz y de momento no tiene pensado irse de nuevo. La semana que viene estaremos de vacaciones y hará la compra con él Virginia, la compañera de Futuex. Necesitaría cortarse el pelo, no sé si será posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-07-08','Ana: correo de Pilar Martín, TS ESM CC (pilar.martinp@salud-juntaex.es), en relación a la consulta de derivación de Martín, desde el ESM al CSS: "HOLA ANA, HE HABLADO CON ESTRELLA DEL SOCIOSANITARIO Y ME DICE QUE LA DERIVACIÓN TIENE QUE SER DESDE LA UHB. UN ABRAZO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2022-07-15','Correo en ctutelar@ del hotel Sinagoga Hervás (informacion@hotelsinagoga.com): "Buenos días, nos ponemos en contacto con ustedes en relación a una estancia que nos reservaron y pagaron a través de transferencia a nombre de Aida María Martín De Pinol entrada el 13/7 y salida el 15/7 ya que a su salida hemos verificado que la habitación ha quedado bloqueada debido al mal estado en la que la ha dejado. Por lo que les informamos que la próxima vez que quiera reservar una habitación para ésta persona, se les cobrará automáticamente un suplemento por la limpieza extra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-03','Ana: Tras conversación con Ana Porras, TS del SAD (927 21 23 35 / ana.porras@ayto-caceres.es) me envía un mail: "Buenos días, Ana. Según hemos comentado, te adjunto modelos solicitudes Teleasistencia y Catering. El servicio de ayuda a domicilio empezará el próximo lunes 8 de agosto a las 9 horas. La auxiliar que comenzará el servicio se llama Rosa (la titular de la ruta se llama Petri, actualmente de baja laboral). Acudirá la coordinadora de la empresa Eulen (Paqui) al domicilio junto con la auxiliar para la presentación. Cualquier incidencia estamos en contacto. Un saludo. ················ A José Manuel le han condido el SAD, serán 4 h/semana (L Y X de 9:00 a 11:00 h). Tanto el TAD como el catering son gratuitos. ··· Se solicitará el catering y valoraremos el TAD. ········································································································································································································ Envío mail a Óscar, secc. ecca.: "Te paso presupuesto de farmacia relativo a José Manuel Romero Mediavilla, son productos que necesita para poder usar la dentadura postiza (ha estado mucho tiempo sin usarla, por eso no se compraba), ahora está convencido y ha comenzado a usarlo. Al parecer tendrá que comprarlo 2 veces al mes, pues con un tubo no le llega. *Desde la sección social se acepta. La propuesta, es, que si se aprueba desde la sección económica, contactéis con la farmacia para abonarlo mediante transferencia. Se puede acordar juntar varios recibos, o algo así (por ejemplo pago bimestral, si estuvieran de acuerdo). Te copio aquí los datos de contacto que me han facilitado, pues en el presupuesto no se ven bien: Farmacia julia Campos Acedo Avenida cervantes 8, Cáceres. Tlf.: 927748458 // 660748458 - - Por otra parte, acaban de llamarme del IMAS de Cáceres, le han concedido el Servicio de Ayuda a Domicilio que le solicité. El copago oscilará entre los 26 – 28 €/mes apróx. (Son 4h/semana a 1,67€/h). *Me indican que el abono hay que domiciliarlo, lo gestiona el OAR. He buscado en la Web del OAR del Cáceres y he encontrado un impreso general de orden de domiciliación bancaria. Os lo adjunto, pero no sé con seguridad si es éste. En el Ayto. no lo tienen. *Por cierto, el primer pago no se lo pasarán hasta 5 meses después. Como el servicio comenzará a prestarse el lunes que viene, hasta enero no le cobrarán nada." ···································································································································· Envío también correo a Toni-Futuex: "...Quería pediros, que, si es posible, el primer día acuda Virginia al domicilio y esté allí, si no todo el tiempo, al menos las primera hora. *Ya se lo he dicho a José Manuel. **Por cierto, José Manuel dice que apenas tiene productos de limpieza en el domicilio, ¿sería posible que Virginia le acompañase a comprar esos productos básicos (guantes, estropajos, lejía, friegasuelos, producto para el polvo), mañana o pasado para que el lunes a las 9h los tenga ya la auxiliar? En tal caso habría que autorizarle a retirar otro extra. ..." ····················· *Pongo para la firma del Representante Legal el contrato con cláusula suspensiva de REVITAL ya firmado por el centro. ················· *Subo al portafirmas digital la solicitud de Catering Municipal del IMAS-CC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2022-08-03','miguel, email de Tere a Oscar, y a la parte Juridica: Tras conversación con una sobrina de Saturnino me envia estos recibos para que procedamos a su domiciliación pues dice que esta vivienda la ha heredado Saturnino y debe hacerse cargo de los suministros. Yo no tengo conocimiento de esta herencia a ver si los jurídicos saben algo o puedes ver si efectivamente esa vivienda sale a su nombre…. ************************************Contestación de Oscar: Si nos confirmáis que hay herencia o es propietario de la vivienda, se pagará.****************************** contestación mía: Hola os adjunto informe social de hace un año que está en la carpeta de inventario. En él veréis que es el 3º de 4 hermanos y que uno está fallecido y residen en el País Vasco. No veo nada en la intranet ni en las carpetas virtuales de estar tramitando ninguna herencia. Por tanto no pagaremos nada, salvo que algún conocido o familiar envíe a la parte social el testamento de la persona que aparece titular de los impuestos, o bien nos demuestren que nuestro tutelado es quién debe pagar estas cantidades. Tere, por favor, intenta localizar a alguien que nos facilite una nota simple de la vivienda y, o bien herencias firmadas o bien certificado de defunción, últimas voluntades, testamento de D. Isidro Cuevas Rubio, y de su madre (de la cual no se menciona nada en el email)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-03','miguel, nuevo email de Amelia: Buenas, te facilito el contacto de dos abogados que conozco de Guadalajara: M Teresa Muelas Mazario Tfno 616 292 983 M Soledad Clemente Lucía Tfno 671 083 075 y 949 250819. Ya les he comentado la gestión que tenían que hacer. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-03','miguel, nuevo email de Amelia: Buenas, te facilito el contacto de dos abogados que conozco de Guadalajara: M Teresa Muelas Mazario Tfno 616 292 983 M Soledad Clemente Lucía Tfno 671 083 075 y 949 250819. Ya les he comentado la gestión que tenían que hacer. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BARQUERO'and apellido2='MARTIN'),'2022-08-04','-Contesto email al CSS : Buenos días , la tutela de Antonio es del 2014 ,tras remoción del cargo de su madre. La pensión es de clases pasivas , se la tramitarían los familiares con esa gestoría . No sabemos en qué condiciones hicieron ese contrato por eso se mantiene. El seguro de decesos es alto porque depende de la edad con la que se les haga . Imagino que no lo tendría y se le habrá hecho cuando lo tutelamos nosotros. Un salud','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-08-04','-Amalia . Adjunto a Angel la documentación que ha solicitado para solicitar al juzgado el pago de la deuda con Ap3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-08-04','-Remito email a su hijo : Buenos días , cuando se cancelen las cuentas de Blas podremos tener más controlado sus compras por internet , ya no podrá utilizar ni la cuenta ni el móvil de Blas . La delegada tutelar que le tenemos asignada acude mensualmente a la casa . Si quieres , cuando tengáis todas las gestiones realizadas te aviso del día y puedes estar con ella para cuadrar presupuesto y hacer una lista de compras más ajustada. Tu madre nos ha escrito para que la orientemos con las gestiones pertinentes tras el fallecimiento de Blas , entiendo que serán sus familiares los que se encargarán de las mismas . Un saludo . ----------------------------------------------------------- Estimadas Amalia y Carmen, ya me imagino que cada vez que recibís un correo sobre mi madre os echéis a temblar, de todas formas creo que este correo es más positivo que negativo. Después de todo lo ocurrido con Blas mi madre se ha mostrado un poco más abierta y accesible y como he tenido que gestionar algunas cosas en su teléfono me he dado cuenta de cómo ha estado operando para comprar estos días. Os cuento un poco. 1. En primer lugar, ella ha reducido bastante el coste de las compras por Internet, compra todos los días o casi todos los días por Aliexpress cosas por valor de 2€ o menos. También es verdad que hay que tenerla controlada porque de vez en cuando cae en la tentación de comprar cosas a plazos (por ejemplo, un aparato híbrido de aire acondicionado / ventilador). En cualquier caso, sus compras mensuales bajo ese menudeo de pequeñas compras por Aliexpress pueden llegar a los 40-60€ mensuales, que no es moco de pavo. Hay que estar muy atentos porque así no ahorra y luego no tiene ni para cosas como, por ejemplo, temas veterinarios para los gatos. 2. ¿Cómo operaba? Como sabe que el control es sobre ella entonces usaba una cuenta de La Caixa a nombre de Blas. He encontrado ingresos de 10-20€ a esa cuenta y desde ahí ha estado pagando seguramente el teléfono que conecta a Internet y diversas compras, muy probable es que ese dinero proceda del que se le da en mano semanalmente y de alguna venta puntual en Internet. Sin embargo parece que también está operando con una tarjeta bancario VAMOS de Ibercaja (su cuenta personal), no sé si como tarjeta virtual creada a través de Internet. Ahora que comenzaremos el procedimiento de cerrar las cuentas de Blas, al menos por ahí, estará más controlada. Además, ahora que estará sola, supongo que contará con menos dinero semanal en mano. 3. Tiene un descontrol total con las compras. Su frigorífico y su cocina son un poema de artículos repetidos (cuatro paquetes de margarina, varias bolsas de patatas de distintas compras, varios packs de leche, paquetes del mismo tipo de pasta, vinagre, artículos de limpieza repetidos, etc.). Además en las compras predomina la comida precocinada, productos con azúcar y las bebidas de sabores, que para una persona que, además tiene deudas y obesidad, habría que limitar un poco, en ese sentido me gustaría estarle más encima ahora. También he de indicar que compra sin ton ni son medicamentos (en algunos casos tiene cajas enteras caducadas o casi caducadas sin abrir escondidos bajo otros objetos) y mucha de la comida fresca tipo verdura o fruta se pudre sin usar. Si compra semanalmente ahora que está sola habría que limitar y potenciar el consumo de lo que ya tiene en casa o revisar el frigo y la cocinas antes de hacer la lista. Mi sugerencia ahora es que como ya no tendrá las cuentas de Blas mi hermana Rosa (que sí tiene los apellidos de Blas), dará de baja los servicios que estén asociados a su nombre (entre otros el móvil de Lowi) y ahí ya sí tendrá sentido activarle el servicio de LlamaYa de llamadas ilimitadas sin internet. Cuando se cancelen las cuentas de Blas (eso lo hará mi hermana) intentaré quitarle el móvil con conexión a Internet con alguna excusa y demorar su devolución, por lo que deberíamos estar atentos a cargos por compra de teléfono móvil. Por otro lado estaré más atento al tipo de compras que hace e incluso algún día me gustaría acompañarles a hacer las compras del súper para limitar ese consumo irracional que tiene. Creo que también, ahora que está sola, se podría ahorrar un poco en el dinero que se le da semanalmente. Quedo a vuestra disposición para hablar por teléfono o mantener una reunión si lo veis necesario. Un saludo y muchas gracias por todo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-07-27','Amalia : tras la visita de Futuex sobre los temas que les había planteado me envían respuesta : Hola! espero que hayas pasado unas buenas vacaciones... y que te queden otras poquitas para que se haga mas llevadero el verano. Yo me iré unos diitas a primeros de agosto y otros a primero de septiembre. Te envie una nota con el primer seguimiento y un informe de psiquiatra de este caso, el 12 de Julio, si no la tienes en el email te la mandaría de nuevo. Va a ser complejo el tema de poder organizarle el gasto, pero este seria mas o menos el presupuesto que se consideraria: Presupuesto semanal general: Alimentación + productos higiene y limpieza: 60 euros A su vecina por cuatro horas a la semana: 40 euros Por cuatro horas a la semana de ayuda a domicilio (repartidas en lunes y jueves, dos por día: 10 euros /hora.) Se sospecha que todo este tiempo la vecina pueda haberse aprovechado un poquito de su descontrol, la llevaba en coche para allá y para acá y le cobraba por esto, y por la comida y etc, pero es dificil acceder a la información a través de Angela, y aunque haya sido a trves del dinero se ha apoyado mucho en el entorno. Farmacia: tiene copago (8 euros máximo) aunque según la información recogida, le gusta comprar otras medicinas que ya no tiene asignadas en receta. Se le podría considerar de retirada unos 140 euros semanales aprox. si fuera viable. Lo ideal podria ser acompañarle a la compra o tener en alguna tienda si fuera posible cuenta para que se pagará por transferencia, pero creo que esto no va a ser posible, porque ella no lo va a permitir seguramente. Tendríamos que añadir: Bombona 19,55 euros (dos al mes aprox.) Además de que cada salida que hace por el pueblo, no va a pie, pide a la vecina que le lleve, y eso le supone un coste, que no terminan de aclarar si entra en el tiempo que está trabajando en su casa, o bien, se lo cobra aparte. Según su información, no entrega dinero alguno a los testigos de jehová, aunque tampoco aclara si pasan a visitarla y en qué frecuencia. No existen deudas y adiciones que se puedan observar. No usa televisor y por su religión no gasta en loterías y otros juegos. Pero sí compra en comida y otros objetos para la vivienda, pues dice que le gusta vivir bien, además de que quiere ayudar a su vecina, porque su corazón y religión se lo pide. El viernes 22 de julio, la trabajadora social nos ha comunicado que se le había autorizado una retirada de asignación de 100 euros, pero que no se puedo realizar pues la entidad bancaria le decía que no estaba la autorización disponible. Suponemos tiene que ver con que el banco no lo ha permitido. Del tema dependencia, que sepamos no cobra nada... ni tiene contrato con ninguna empresa, ya qeu lo de la vecina, es privado. Lo que si nos dijo ella, es "la mujer que venia por esa empresa yo no quiero que venga y que solo quiero que este Quini (la vecina) " entonces, no sabemos si es que ese PIA sigue, y no va nadie de la emprea y por ahi viene todo el lio o exactamente que ha pasaado,. Lo que si nos confirmó es que ella no quiere que vaya nadie, y solo su vecina, y que en algun momento si fue alguien por dependencia. Al igual que lo relativo a la comida, solo cogio comida de los pisos unos dias, porque luego una de las veces, uno de los platos era morcilla y ella por su religión de la que es muy intransigente, dice que no lo puede comer (al parecer los testigos de Jehová no pueden comer sangres y esas cosas...) Es bastante complejilla la cosa, pero a ver si estas informaciones van ayudando en la gestión del caso, ya me dices!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-08-04','-Amalia : Se deniega el acceso a la UHDAC . te envío la denegación de plaza en la UHDAC de Alejandro, por la misma situación que la otra vez, esta vez, claro, no lo han podido rechazar por el CI. Esto es de "juzgado de guardia". Me ha comentado Teresa que habéis recurrido la sentencia, a ver si puede ser por esa vía. Un abrazo. -------------------------------------------- buenos días Carmen , esto es increible , no hay forma de ingresar a este tipo de usuarios en ningún recurso. Lo de la UHDAC parece de chiste , nos han hecho trabajar para cambiar el CI para nada , ahora se sacan otra excusa . Todas las sentencias se tienen que revisar ,pero van a ir a menos , ya no hay incapacitación si no medidas de apoyo , y prevalece la voluntad y deseos de la persona . Estamos atados jurídicamente para abordar este tipo de problemáticas . Sólo cabe que él voluntariamente quiera ingresar en alguna comunidad terapeútica . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-08-04','TERESA ENVIO POR REGISTRO SOLICITUD REVALORACION PENSIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-04','Ana: Envío correo a Ana Porras, TS SAD IMAS CC (ana.porras@ayto-caceres.es): "Buenos días Ana, Adjunto Solicitud de Cáterin relativa a José Manuel Romero Mediavilla, firmada digitalmente por su Representante Legal. Hoy tenía cita en el médico para que le cumplimentara el Informe de Salud y os lo llevaría vosotras. Así podréis unirlo a la solicitud y darle registro de entrada a los dos documentos juntos." ······························································································· **Tal y como había acordado con Pilar Martín, le envío la solicitud de dependencia para reactivación del PIA y solicitar Tratamientos por Promoción de la Autonomía. ··· **Ella lo registrará junto con el Informe Social que ha elaborado. ·································································································································································································· Tras hablar con Virgina - Ed. Futuex, envío correo a Toni: "Comunicarte que tras llamar a Teresa a la oficina, hemos acordado que llamaba a Virginia directamente, así que le he llamado para comunicarle un par de cosas: - Como el Servicio de Ayuda a Domicilio comienza el lunes, le he pedido: o Mañana le acompañe a comprar productos de limpieza, que apenas tiene José Manuel en casa (Se ha enviado al banco autorización de retirada de 20€) o Acuda el lunes al domicilio de Jose Manuel a las 9 h. Acudirán también la Aux. de SAD y su coordinadora para las presentaciones y la organización del servicio. - El día 12 podrán retirar del banco 75 € para comprar los alimentos para esas dos semanas (tal y como habíamos quedado)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-08-04','TERESA EMAIL DE JOSE TS maria murillo delgado tlf. 624273503 , me comenta que tiene varios problemas entre los que esta el no poder cerrar la puerta de su casa porque esta rota.... me comenta que si le podeis llamar para hablar con vosotros. LA LLAMO POR TELEFONO Me comenta que quiere que le autoricemos para pedir un anticipo en el banco, le he explicado que eso no es posible, no tiene nada de dinero ahorrado pues coge la pensión entera. Vamos a comunicar la situación al juzgado porque la intervención con ella es imposible además se niega a recibir ayuda por nuestra parte. Tiene pendiente el pago del cristal ya que según hacemos la transferencia para hacer el pago ella la anula, a esto se le va a sumar una denuncia que tiene por delito de agresión, tendrá próximamente una vista por este tema. Me comenta que ya no tiene relación alguna con su madre, que ella paga el alquiler de su pensión y que los suministros se los paga el ayuntamiento. Dice que necesita arreglar electrodomésticos y la puerta y que como no tiene dinero está muy angustiada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2022-08-04','-Amalia : escribo email a Maite y asesores jurídicos : Buenos días , adjunto comunicación de excarcelación en breve del Ctro. Penitenciario. Según leo en su sentencia se autorizaba al ingreso en CSS . Esa autorización seguiría en vigor ? lo podemos ingresar ? Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-04','Ana: Llamada de José Manuel (627 788 798): Dice que ha firmado un contrato de Orange de Fibra Óptica y un móvil a pagar en 24 meses. El precio es de 57 + 9 €/mes. ············ Le indico que vuelva a la tienda y anule el contrato, pero dice que no, que necesita un móvil con contrato... Cuando le digo que informaré a Alberto y se devolverán los recibos, dice que le da igual, que le meterán en la Lista de Morosos y ya está...','2');
