insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2022-08-05','Ana: Recibo llamada de Mabel, Directora del CAMF - Alcuéscar (927 384 533 // 629 23 23 40): Ayer a última hora, la persona que iba a realizar la semana que viene (8- 15) de agosto), el acompañamiento al viaje a Valencia del Programa de Termalismo y Turismo en la Naturaleza del IMSERSO, llamó para renunciar al mismo. Ya se le abonó la gratificación por el acompañamiento el pasado 27 de julio mediante trasferencia. ···· Intentarán encontrar hoy mismo a otra persona para que haga el acompañamiento. *Desde la secc. ecca. de la CTAEX se reclamará la gratificación ya abonada y se realizará otra transferencia a la nueva persona en cuanto Mabel nos facilite los datos de ambas. ································· Envía los datos de ambas personas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-08-04','Ana: Correo de Toni-Futuex: "Hola Ana, se había previsto visita de supervisión a Isabel Cano Blázquez en Trujillo me temo q no va a poder hacerse por horarios de bus, te cuento 02/08/2022 Se contacta con CRR Plasencia y se informa que se ha solicitado desde la CTAEX la visita al domicilio de la madre de Isabel en la localidad de Trujillo, se les pide información sobre los horarios de autobús, pero aún no se ha gestionado el viaje, por lo que se les transmite que en la medida d lo posible sea un autobús que llegue a Trujillo por la mañana para poder realizar el seguimiento. Se acuerda confirmar todo en visita a CRR del día 4 de agosto. 04/08/2022 Se realizar visita en CRR a tutelados que están en seguimiento desde hace bastante tiempo y se aprovecha para organizar con los profesionales del centro el seguimiento a Isabel en Trujillo. Carol la Psicóloga informa del caso a rasgos generales, tanto desde el equipo de apoyo como desde el equipo del centro se considera adecuado este seguimiento, informan que Isabel sale de Plasencia en el único autobús que hay el viernes 5 a las 13:30 y la hora prevista de llegada según informan en el centro es a las 15:30 de la tarde aprox. se plantea por tanto realizar el seguimiento en lunes en el caso de ser posible porque Isabel se plantea volver el martes 8 al centro. Pero se consultan los horarios de autobús y se comprueba que tan sólo hay servicio los lunes y los viernes, por lo que regresa finalmente el lunes en el autobús delas 8:45, según se confirma después por vía telefónica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-05','Ana: Correo de Pilar Martín, TS ESM - CC (pilar.martinp@salud-juntaex.es): "Ana, he visto ya a Doroteo, creo que puede estar descompensado, ahora le verá su psiquiatra, pero ha salido un rato con Virginia a la calle hasta la 1,15 que le pueda ver para evitar tensiones. Unas veces dice que acepta irse a una pensión, otras que se niega a irse de la casa de su hermana hasta que le pague unos 3000 euros que según él le adeuda, otras que se quiere ir a su cas del pueblo, ...ya te contaré." ································ Nuevo correo de Pilar Martín: ", LA PSIQUIATRA VALORA QUE SE ENCUENTRA DESCOMPENSADO Y LO DERIVA A LA UHB."','2');
