insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-08-08','Escribo a parte eco y juridica , con respecto a PEDRO SUDON , fallecido el mes pasado me informan desde la R.M. Los Olivos que se han ingresado los 168 € de gastos personales de dos meses. Hay que darlos de baja igual que se hizo con el pago de la plaza. Van a hablar con la sobrina sobre cómo reintegrarlos . Resulta que Cristina Sudón es la única heredera de Pedro. Me surge la duda de si Pedro, con su sentencia , podía hacer testamento y si este tedrá validez . Cristina debe a Los Olivos 500 € de otro tío que tuvo ingresado , Jose Mª le va a plantear quedarse con estos dos ingresos y aún así le sigue debiendo. No sé si lo puede hacer o tiene que reintegrarlo en su cuenta .Nosotros ya no operamos en las mismas . Un saludo . ////////////////////////////////// Para todas las dudas , la respuesta es que debe dirigirse a los juzgados , se lo notifico a Jose M. de Los Olivos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-08-08','Escribo a parte eco y juridica , con respecto a PEDRO SUDON , fallecido el mes pasado me informan desde la R.M. Los Olivos que se han ingresado los 168 € de gastos personales de dos meses. Hay que darlos de baja igual que se hizo con el pago de la plaza. Van a hablar con la sobrina sobre cómo reintegrarlos . Resulta que Cristina Sudón es la única heredera de Pedro. Me surge la duda de si Pedro, con su sentencia , podía hacer testamento y si este tedrá validez . Cristina debe a Los Olivos 500 € de otro tío que tuvo ingresado , Jose Mª le va a plantear quedarse con estos dos ingresos y aún así le sigue debiendo. No sé si lo puede hacer o tiene que reintegrarlo en su cuenta .Nosotros ya no operamos en las mismas . Un saludo . ////////////////////////////////// Para todas las dudas , la respuesta es que debe dirigirse a los juzgados , se lo notifico a Jose M. de Los Olivos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2022-08-08','Buenos días, debido al tiempo transcurrido desde la sentencia de incapacitación de más de año y medio no sería válido el internamiento involuntario y por tanto habría que iniciar desde el principio la solicitud de internamiento involuntario.Miguel Fdez de Llera Por lo tanto , al salir de la carcel ira a su casa en Badajoz. Haremos visitas domiciliarias y veremos si es oportuno ingreso involuntario o no .','2');
