insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-08-08','criterios para ingresar. Nos preocupa mucho su situación personal y cómo está afectando al funcionamiento del centro y al estado de sus compañeros. Un saludo Mª del Mar Barroso Gómez, coordinadora CRR Olivenza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2022-08-08','Ana: Envío a REGISTRO (cac.merida.san@juntaex.es) Comunicación de Variaciones de Datos Bancarios PNC junto con el Alta de Terceros, para dar REGISTRO DE ENTRADA y remitirlo a la D.G. SSSS, Infancia y Familia (Serv. de Prestaciones Soc.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-08-08','Ana: Correo de Maripaz Casado, Psicóloga-Coord. UHDAC (mariapaz.casado@salud-juntaex.es) a Soraya Masa con copia a mí: "Buenos días. En esta ocasión os escribo en relación a la paciente Remedios CH.M., ingresada en la UHDAC desde el 2 de abril de 2019, con otras dos estancias anteriores. Tutela por la CTA. Remedios ha convivido con sus abuelos, madre y su hermana gemela. Estas dos últimas presentan también discapacidad intelectual. Tras el fallecimiento de los abuelos, las hermanas accedieron a diferentes centros residenciales de la red de discapacidad de la comunidad, y la madre en un Centro de Día. Informaros que, en relación a esta resolución adoptada en ese momento de asignar plaza residencial en Centros diferentes, miembros la familia contactan con nosotros puntualmente para comunicar su propuesta de acercar a las hermanas. El viernes fue la última vez que su tía Bele lo hizo para reiterar la petición de compartir el mismo Centro que su hermana, expresando que "toda la vida estuvieron juntas con su madre". La evolución de la paciente en la Unidad es favorable, con actitud colaboradora en lo referente a cumplimiento de normas, tareas y realización de las actividades programadas en su plan terapéutico. Actualmente no presenta conductas de ingestas en entorno con alta capacidad de contención y supervisión. Expresa deseo de asistir a Centro que ofrezcan opciones ocupacionales de su interés. Anhela poder permanecer cerca de su madre y hermana y tener así el contacto con ellas de manera más frecuente. Desde hace meses ese contacto se limita a llamadas telefónicas semanales y visitas mensuales a la madre y hermana en Badajoz, que transcurren sin incidencias. Valoramos positivamente la propuesta de la familia de aproximar residencialmente a las dos hermanas, en entorno con supervisión cercana y mantenida en el tiempo. Actualmente la paciente no tiene asignada plaza residencial comunitaria. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-08-08','TERESA ARCHIVO RESOLUCION DE REVISION DE INCAPACIDAD PERMANENTE POR CONTINGENCIA DE ENFERMEDAD COMUN CONTINUA CON EL MISMO GRADO Y MISMA PRESTACION PUES NO SE HA PRODUCIDO VARIACION EN EL ESTADO DE SUS LESIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-08-08','Ana: Envío correo a Estrella, Secc. Ecca: "Cuando puedas, mira porfa, si JOSÉ ANTONIO BARROS CORDERO tiene o no seguro de decesos. En su expediente digital no hay carpeta de decesos, pero en la base de datos pone que tiene seguro en GENERALI ESPAÑA, según indican lo paga la familia y se pidió copia a fecha de 26/04/2019. Compruébalo por favor y si no tiene, habría que contratar uno. Tiene 59 años." ·································································································································································································· *Tras valorar la situación ecca. de José Antonio, decido solicitar la prestación de Orfandad. ····· *Cumplimento Solicitud de Orfandad, pero falta un dato: Nº Seg.Soc. del padre. *Llamo a Fini, hermana de José Aª (651655267), en cuanto puedan me lo enviarán al ctutelar@','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2022-08-08','miguel, contestamos al requerimiento del jzdo nº2 de Cáceres via lexnet sobre el lugar donde reside Doña Clementa..Centro el Cuartillo de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2022-08-08','miguel, Tere me reenvia email de la sobrina de Saturnino (yolanda guerra cuevas >yolandaguerra@hotmail.es> ) Buenas tardes, Os adjunto escritura de la casa de la calle Concepción de la que mi tío Saturnino es el usufructuario hasta que fallezca, también el contrato de compraventa de la calle Zalamea en la que consta mi abuelo Isidro Cuevas Rubio como propietario y que al fallecer pasa en herencia a los hijos en los que se encuentra mi tío Saturnino. Por otro lado, la consulta que hice para poder realizar la venta de la casa de la calle Zalamea, comunicaros que finalmente no se va a realizar, así que no necesitamos solicitar ningún permiso con respecto a la situación de mi tío Saturnino. Cualquier aclaración que necesitéis, no dudéis a contactar conmigo. *************************************************** Tras revisar el testamento de la madre y el contrato por el que adquirió el padre de Saturnino contesto a Tere: Tere, no queda acreditado que tenga que tenga que encargarse del pago de los suministros y otros Saturnino. Lo que te remiten es una compraventa por el que el padre de Saturnino compró la vivienda y un testamento (que no acredita que sea el único y último pues no se acompaña del certificado de últimas voluntades, como tampoco se acredita la aceptación y reparto de la herencia de la madre, ya que su padre premurió a la madre) Catastralmente tampoco aparece la titularidad del inmueble a nombre de Saturnino. Lo único que dice el testamento es …”ordena la testadora los siguiente legados: A su hijo Saturnino Cuevas Moyano le lega la cantidad de cien mil pesetas, y el derecho de habitar en la casa número diecisiete de la calle Concepción de Higuera de la Serena, mientras conserve su estado de soltero” “…E instituye herederos por partes iguales a sus cuatro hijos…” Por tanto todos los gastos deben asumirlo los 4 hermanos (y por fallecimiento a sus descendientes), y Saturnino en su parte proporcional, previo que te acrediten facturas, presupuestos, etc. Comunícaselo a la sobrina','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-08','Ana: Llamada de José Manuel (627 788 797): Esta mañana han ido a su casa la Auxiliar de SAD, Rosario (Sustituta. ····· La que le corresponde es Petri, que actualmente está de baja) con la Coordinadora y Virginia, Ed. Futuex. **Tal y como está la casa, han acordado que primero necesita una limpieza a fondo, para lo que acudirán 2 auxiliares esta semana en otro horario. ········ El viernes compró con Virginia los productos de limpieza. ············· Hoy dice que ha colaborado con Rosario y ha puesto una lavadora. ······················································································································································································· En cuanto al contrato de Orange, dice que volvió a la tienda y está anulado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-08-04','Ana: Correo de Ana, TS de la Mancomunidad de Hurdes (ssb@mancomunidadhurdes.org): "Buenos días, Ana¡ Te envío la documentación que en el día de hoy me pasan desde la Residencia Madre Francisca de Azabal , para el expediente de pensión de orfandad que desea solicitar JOSE ANTONIO BARROS CORDERO. La hermana de él ha enviado esta documentación a la Residencia. Fini 651655267."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2022-08-08','TERESA RECIBO EMIAL DE LA TRABAJADORA SOCIAL DE TRUJILLO Buenos días. Os escribo para informaros de que ha venido a verme Beatriz Muñoz Ruiz, planteando las siguientes demandas: - Desea retornar al domicilio paterno. - Desea reclamar la custodia de su hija. Entiendo que tiene un tutor asignado, por lo cual cualquier gestión tiene que ser a través de vosotros. Si pudierais contactar con ella, os lo agradecería, para que ella pueda explicaros su situación. Si pudierais poneros en contacto conmigo, también os lo agradecería, ya que me resulta muy complicado poder contactar telefónicamente con vosotros. Un saludo. Mercedes Prieto Sánchez Trabajadora Social del SSASB de Trujillo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-08','Ana: Correo de Toni con Informe de Ingreso en UHB. ········ - Contacto con psiquiatra de la planta horario de lunes a viernes de 10h a 14h 924256965. ······· Guardo en el expte. digital. ······ Guardo también la nota de seguimiento. ···· Hoy no disponible la Psiquiatra de planta, tampoco se prevé el alta a día de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-09','Ana: Envío correo a Mila, Revital (centrorevital@gmail.com): "Adjunto el contrato relativo a JOSÉ MANUEL ROMERO MEDIAVIllA, firmado digitalmente por el Presidente de la Comisión Tutelar de Adultos de Extremadura. La semana pasada remití a la compañera del Equipo de Salud Mental, Pilar Martín, la solicitud de Dependencia para la activación del expediente y nueva propuesta de PIA, ella se encargaría de registrarlo junto al informe social que ha elaborado. Supongo que ya lo habrá registrado." ································································································································································································· Recibimos RESOLUCIÓN del IMAS-CC, José Manuel ha obtenido en la valoración 60 puntos y se le concede el servicio. *Guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-08-09','Ana: Recibimos Informe Social del IMAS para la Rendición Anual al Jdo. Sólo dice que a lo largo del 2022 no ha tenido ningún contacto con Ventura. Que la última vez que tuvieron contacto con él y con la Educadora de Futuex fue en febrero de 2018. Que en abril de 2018 empezó a prestársele el SAD y que continúa prestándosele a día de hoy. Y que si queremos más información se la pidamos a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-08-09','miguel, me llama por teléfono raquel (sobrina de la tutelada que ya envió un email el 3-8-22) (raquelrodriba@email.com: Buenas tardes, me pongo en contacto con ustedes como legítima heredera de una persona que comparte una cuenta bancaria con una tutelada por la junta. Con el fin de realizar las gestiones pertinentes y a petición notarial, agradecería se pusieran en contacto conmigo para hacer los trámites pertinentes, gracias y un saludo (teléfono de contacto 650269691)********************************* Me comenta que su madre falleció y tenía un dinero a plazo fijo en unicaja. Están tramitando el impuesto de sucesiones y en cuanto tengan todo se acercarán a liberbank para entregar la documentación y allí pedirán un documento de reparto del dinero. Nos llama porque la cuenta que había a plazo fijo por lo que veo en la última rendición de cuentas anual, se canceló y se transfirió a la cuenta de la tutelada, por lo que cuando procedan desde el banco al reparto lo cogerán de dicha cuenta. Le he dado el email de ctutelar y le he pedido que nos envíe el banco un email cuando vayan a hacer dicho cargo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-08-09','Ana: Recibimos RESOLUCIÓN del INSS de REVISIÓN de la PFHC. Le conceden 626,60 € x 12. Fecha de efectos: 01/10/2022. ················· *Lo comunico a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2022-08-10','TERESA permiso para ir desde el 11 de agosto hasta el 14 con su familia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2022-08-10','TERESA EMIAL PROINES Desde que está en nuestro recurso tiene revisiones con el neumólogo, en todas las consultas le recomiendan que deje de fumar, pero él se niega a abandonar el hábito. Los últimos meses le vemos más adormilado y hemos ido a medico, neumólogo, especialistas del sueño, neurólogo privados........... Tras varios meses de prueba el pasado 15 de julio de 2022 nos llaman para darnos resultados y telefónicamente nos dicen que los niveles de oxígeno en sangre son muy bajos y están al límite. Dicen que debe cuidarse y cumplir las recomendaciones que llevan años dándole pero que no cumple. Incluso le avisan que si no cambia rutinas que le darán el alta definitivamente. Las recomendaciones son: 1. Ponerse la máquina para dormir 2. Seguir una dieta equilibrada y sin excesos de grasas, sales y azúcares 3. Dejar completamente el tabaco 4. Salir a hacer ejercicio moderado De todas ellas Feliciano solo cumple a raja tabla lo de salir a pasear. • La máquina es muy molesta para dormir y se la quita constantemente. • Come con gula (hasta 5 o 6 plátanos de un tirón) • Se niega a abandonar el hábito del tabaco, aceptó ir al cedex para que le ayuden, pero en piso no acepta que le recortemos el número de cigarros Cuando hablamos con él nos dice a todo que Sí y parece que lo entiende, pero luego no cumple ninguna recomendación. Parece que le de igual que su salud esté en juego y como le conocemos y sabemos su frialdad realmente es así. No le da importancia a nada, pero a nosotros nos preocupa su situación. Como tutelado creemos que es nuestra obligación informar de su situación para que sepáis lo que está sucediendo con este usuario y comentarle que si su conducta sigue en esa línea nuestro trabajo con él es prácticamente imposible e inviable en los pisos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-08-09','Amalia : Plan de intervención inicial finalizado . Envío a sección eco presupuesto fijado: Buenas , se realiza presupuesto de gastos e ingresos de esta señora. Ingresa 1200€ de P. Jubilación. Tiene de ingresos fijos domiciliados 117€ Se le autoriza a 1000€ máx al mes , divididos por semana , creo que quedaría en 220€ semanales. El banco en VVa. sólo abre dos días a la semana , martes y viernes, quedarlo abierto para que pueda ir cualquiera de esos días. Necesita el primer reintegro para este viernes , el dinero de 150€ que se autorizaron directamente en el supermercado se le ha agotado. Con respecto a la ayuda a domicilio , he tenido que hacer una anulación del PIA que tenía concedido pq no ha contratado a empresa. De momento , ella quiere que vaya a ayudarle en la casa la vecina , que la pagará del reintegro semanal. No se abonará nada en farmacia , si quiere algo fuera de lo pautado sanitariamente , lo abonará de su reintegro. Un saludo. No accede a ingreso en residencia de mayores ni pisos tutelados del pueblo . De momento se mantiene en el domicilio , con visitas de Futuex , la TS del SSASB , apoyo de Quini su vecina. Verbaliza que los 5000€ que sacó de la cuenta se los dió a los Testigos de Jehobá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-08-09','TERESA. Me acaba de llamar del Cuartel de la Guardia Civil de Zafra, de la comisión de violencia de género, Beatriz quiere poner una denuncia por violencia de Genero y necesitaban hablar con su representante legal. SE LE EXPLICA QUE ES UN CARGO POLITICO Y QUE ELLA PUEDE Y DEBE PONER LA DENUNCIA SIN MAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-08-09','Amalia : Plan de intervención inicial finalizado . Envío a sección eco presupuesto fijado: Buenas , se realiza presupuesto de gastos e ingresos de esta señora. Ingresa 1200€ de P. Jubilación. Tiene de ingresos fijos domiciliados 117€ Se le autoriza a 1000€ máx al mes , divididos por semana , creo que quedaría en 230€ semanales. El banco en VVa. sólo abre dos días a la semana , martes y viernes, quedarlo abierto para que pueda ir cualquiera de esos días. Necesita el primer reintegro para este viernes , el dinero de 150€ que se autorizaron directamente en el supermercado se le ha agotado. Con respecto a la ayuda a domicilio , he tenido que hacer una anulación del PIA que tenía concedido pq no ha contratado a empresa. De momento , ella quiere que vaya a ayudarle en la casa la vecina , que la pagará del reintegro semanal. No se abonará nada en farmacia , si quiere algo fuera de lo pautado sanitariamente , lo abonará de su reintegro. Un saludo. No accede a ingreso en residencia de mayores ni pisos tutelados del pueblo . De momento se mantiene en el domicilio , con visitas de Futuex , la TS del SSASB , apoyo de Quini su vecina. Verbaliza que los 5000€ que sacó de la cuenta se los dió a los Testigos de Jehobá.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-08-09','-Amalia : Derivo el caso a Teresa , es de su zona . Hecho Plan de intervención','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-08-09','Ana: Correo del CRR (crr@grupociudadjardin.com): "Desde el Equipo de Salud Mental de Cáceres nos han facilitado una solicitud de informes a nombre de la persona tutelada Juan Mario San Roman Blasco, en la que nos comentan que tiene que firmarlo sus tutores para solicitar el informe en relación al proceso abierto que se tiene con Juan Mario. Adjuntamos solicitud a la espera de la firma correspondiente." ····················· Subo la solicitud al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-09','Ana: Llamada de Julia (644 897 339): Comunica que ha dado positivo en COVID, por lo que le han aislado en su habitación. Su compañera de habitación, Isabel Cano, anoche al enterarse de que tenía que salir ella del cuarto, se alteró y se autolesionó el brazo. Estuvo dando puñetazos a la pared. **Ella dice que para estar así prefiere irse a otro centro. Argumento que son incidentes puntuales, que ella estaba bien, tranquila y contenta. *Lo admite y dice que además se lleva muy bien con Isabel. Ambas necesitan ahora el apoyo mutuo. ············ A parte narra que, tanto ella como Julia, está recibiendo amenazas de Yasmina, pareja de Ceferino y antigua residente del CRR, que fue expulsada hace días y trasladada al CRR-CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-09','Ana: Llamada de Pilar, TS ESM - CC (54612): me comunica que Doroteo sigue ingresado en la UHB. Ha hablado con Carmen, la TS del Hptal. *Intentarán hacerle entrar en razón de la necesidad de que acepte ingresar en cualquier CRR. **Pues no cree que le vayan a derivar a UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2022-08-09','Ana: Alberto, Jefe Secc. Ecca, me informa de la situación ecca. de Clementa: no tiene dinero. Abona el centro y de préstamo hipotecario más intereses 205€/mes. **Del préstamo son titulares su esposo fallecido, Enrique Moreno Niso y ella. **Como avalistas constan su hija, Mª Pilar Moreno Amado (638 530 172) y su yerno, Roberto Moretón González.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2022-08-10','TERESA Recibo llamada del ts del hospital de zafra, su estado es favorable pero no le darán el alta hoy tal y como tenían planificado, me seguirá informando Esta acompañada de sus familiares sobrina y hermana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-08-10','miguel, recibo email de Sonia de Asindi: Hola Miguel, te remito la citación al Médico Forense de Aaron Rosado Alarcón. Organizaremos para llevarle nosotros. Quería aprovechar para plantearte algunas cuestiones que me trasladan los familiares más directos de Aaron. Ya han limpiado la vivienda y le han traído ropa, televisión y otros enseres a Aarón. Ahora quieren saber si hay que dar de baja el tema de la luz, el agua,... En cuanto a otros temas de herencia me dicen que les indiquemos que documentación se necesita para que puedan ir preparándola. Me aluden a las gestiones en el banco, cuenta de Julio,...no saben cómo proceder. Ya me vas contando. Un saludo, ************************************** Reenvío el email a Alberto y Ana Matamoros: Buenos días, me pregunta el centro que la familia le pregunta si se puede dar de baja los suministros de la vivienda… Si quieres Ana pregunta a Sonia qué es exactamente lo que quieren dar de baja. Por mi parte la indicaré los documentos que necesita para poner en marcha la herencia del padre. **************************************************** Envío email a Sonia: Buenos días, gracias Sonia. Doy traslado a Ana Matamoros y la sección económica para que vean el dar de baja los suministros… En cuanto a la documentación que necesitan recabar los familiares para puesta en marcha de la herencia son la siguiente: 1.-testamentaria: formada por certificado de defunción, certificado de últimas voluntades (pueden pedirla online), testamento o declaración de herederos (que habría que hacer si no hubiera dejado hecho testamento) 2.-Certificados de saldos y de movimientos de cuentas bancarias del último año del fallecido (finado o causante) 3.-Notas simples actuales de los bienes inmuebles que haya podido dejar. En caso de no existir bienes inmuebles se pueden ahorrar los trámites de hacer una escritura ante la notaria, ya que únicamente habría que desbloquear y repartir el dinero de las cuentas bancarias que deje el fallecido. Una vez que tengan esa documentación, en 6 meses hay que liquidar el impuesto de sucesiones. En el caso de Aaron además hay que solicitar autorización judicial (mediante abogado y procurador) para aceptar y aprobar la herencia, y en caso de que haya un inmueble que se quiera vender, también habría que pedir la correspondiente autorización de venta. Por este motivo, una vez que recaben esa información la familia(necesitaremos alguna persona de contacto que nos facilite información y documentación) y sepamos los bienes que componen la masa hereditaria, procederemos a poner en marcha la liquidación del impuesto de sucesiones, escritura notarial de adjudicación de herencia y las correspondientes autorizaciones judiciales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-08-10','miguel, email de Amelia: Buenas tardes Miguel, me comentan que para solicitar la tasación hay que aceptarla a través de éste correo y pagar previamente la misma, se puede pagar de varias maneras, entre ellas tranf bancaria donde específican el num de cuenta. La factura sólo puede ir a nombre de un solicitante, he dado los datos de Raúl ya que es el mayor. Por favor, proceded al pago para que se pueda visitar el inmueble tan pronto como sea posible, esta semana estaré en el pueblo pero no puedo concretar los planes más adelante, mi domicilio está a 70 km de dónde está ubicada la vivienda. Si fueras tan amable de avisarme cuando el pago esté realizado para agilizar la visita. En el concepto del pago mejor especificar el num de presupuesto, gracias ________________________________________ mi contestación: Buenos días, habitualmente se debe abonar aposteriori, pero lo trasladaré a la sección económica quienes si no tienen ningún inconveniente procederán al pago. Por favor facilitale a la tasadora una nota simple. Necesito te indiquen número de cuenta, concepto, beneficiario. Una vez la tengan la remitan a ctutelar@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JESUS'and edp.apellido1='DE LA OSA'and apellido2='DE LA OSA'),'2022-08-10','Ana: Recibimos Informe del CRR para la Rendición Anual: Francisco cada vez mantiene menos contacto y relación con la familia, a pesar de los esfuerzos de ésta para ello. *También han disminuido las relaciones significativas con sus compañeros, pasando cada vez más tiempo con ellos. ·········· Sólo sale por lugares cercanos y conocidos (barrio) y en ocasiones puntuales a otros lugares más lejanos acompañado de compañeros y/o profesionales. Tampoco realiza salidas nocturnas por no sentirse seguro. ···· Aunque aumenta su interés en excursiones fuera de la localidad.*La única actividad de ocio en solitario que práctica es la pesca, el resto de actividades no parecen interesarle. ················ Han notado un retroceso en su autonomía, tanto en la administración del dinero como en lo relativo a su enfermedad y sintomatología, necesitando más apoyo que en épocas anteriores. Pero conserva autonomía moderada para acudir al médico a por recetas, retirar la medicación de la farmacia y rellenar el pastillero (ésto con supervisión) ··············· Participa en la realización de tareas domésticas generales y demuestra tener habilidades instrumentales suficientes. A día de hoy requiere motivación para mantenerse activo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-08-10','Ana: Envío al CRR la solicitud de informe médico para derivación al CSS firmada digitalmente por el Presidente de la Comisión Tutelar. ································································································································································································ Ana: Envío correo a Miguel, Asesor Jurídico, con copia a Maite, Jefa de Secc.: "En relación a JUAN MARIO SAN ROMÁN BLASCO, hay que solicitar internamiento involuntario en la UNIDAD DE ALCOHOLISMO del Centro Sociosanitario de Plasencia. Te adjunto todos los documentos facilitados por el centro en relación a su consumo, los incidentes acaecidos y el riesgo para su salud padeciendo la enfermedad de DIABETES MELITUS además de sus patología mentales y el riesgo para el resto de pacientes al introducir el alcohol en el CRR e incitar a otros pacientes al consumo. Si no se pone remedio van a expulsarlo del CRR quedándose en la calle. Además no dispone de capacidad para vivir de forma independiente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2022-08-10','Ana: Nos remiten desde el centro nuevo presupuesto para completar los cambios de la silla de rueda y Resolución Aprobatoria de la Ayuda del SES para Material Ortoprotésico: "...estima la solicitud de reintegro de gastos de ortoprótesis por importe de 2678,85€. ··········· Paso a Alberto, Jefe Secc. Ecca., ambos documentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-08-10','miguel, comunico a la parte social (Ana y Maite) el exhorto que ha llegado del procedimiento Ejecutoria 9/2022 del juzgado de 1º instancia e instrucción nº4 de Plasencia.: Ana, ha llegado físicamente la resolución del juzgado que condena al cumplimiento de la pena de tratamiento psiquiátrico en el centro Luis de Toro de Plasencia o el que corresponda. Una vez que la esté cumpliendo que te den un certificado del centro de especialidad de psiquiatría indicándolo para que podamos comunicárselo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2022-08-10','TERESA He mantenido conversación con Mercedes Prieto, trabajadora social de los servicios sociales de Trujillo.927659391 Me comenta que Beatriz ha acudido allí solicitando que quiere vivir con su padre que ella ya es mayor para estar en el colegio, y que quiere reclamar la custodia de su hija. El padre quiere pedir la remoción del cargo para ser tutor de Beatriz y también va a solicitar régimen de visitar para poder ver a su hija. Le he comentado la situación actual de Beatriz en el centro y como se realizan las visitas con la hija en función de su situación económica. Me pide que valoremos un traslado para que pueda estar mas cerca de su hija, este tema lo habláremos con ella cuando tengamos la llamada telefónica, y tras valoración habrá que comunicarlo al fiscal si es su deseo tal y como marca la nueva legislación. Hemos quedao que me informara de la entrevista que van a mantener hoy','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-10','Ana: Envío correo a Ana Benavente, TS del ESM-Plas (anamaria.benavente@salud-juntaex.es): "Buenas tardes Ana, Te remito resolución judicial que condena a Alfonso Marín de Cáceres al cumplimiento de la pena de tratamiento psiquiátrico en el centro Luis de Toro de Plasencia, para vuestro conocimiento y para que lo tengáis en cuenta a la hora de gestionar sus citas y seguimiento. Así mismo, solicitaros nos mantengáis informadas al respecto y que, por favor, nos hagáis llegar informes del servicio de Psiquiatría de las diferentes consultas, asista o no, para poder hacer las correspondientes comunicaciones al Juzgado sobre su cumplimiento de la medida. Ante cualquier cuestión, no dudes en contactar. Gracias y buena tarde."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-08-10','Ana: Envío correo a Ana Benavente, TS del ESM-Plas (anamaria.benavente@salud-juntaex.es): "Buenas tardes Ana, Te remito resolución judicial que condena a Alfonso Marín de Cáceres al cumplimiento de la pena de tratamiento psiquiátrico en el centro Luis de Toro de Plasencia, para vuestro conocimiento y para que lo tengáis en cuenta a la hora de gestionar sus citas y seguimiento. Así mismo, solicitaros nos mantengáis informadas al respecto y que, por favor, nos hagáis llegar informes del servicio de Psiquiatría de las diferentes consultas, asista o no, para poder hacer las correspondientes comunicaciones al Juzgado sobre su cumplimiento de la medida. Ante cualquier cuestión, no dudes en contactar. Gracias y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-10','Ana: REUNIÓN con Soraya Masa, acudimos Maite y yo. **Se acuerda que la semana que viene, el día 16, Soraya contactará con el Director en funciones del CSS, pues ahora está de vacaciones, y tratará con él la necesidad de internamiento en el CSS (UME, URA o la unidad que consideren).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-08-10','Ana: Mariluz, Jefa de Secc. de Acceso a Recursos de Salud Mental, me comunica que ha hablado con Ceferino. *Éste plantea el cambio al CRR de CC para poder vivir con Jasmina. Mariluz le ha dicho que de ninguna manera se va a aceptar dicho cambio, pues cuanto están juntos generan conflictos. ····························· Llamada de Ceferino (641 881 543): Dice que ha hablado con "el SEPAD y le han dicho que no se le acepta el cambio", ante eso le digo que no podemos hacer nada. Además le recuerdo que los cambios de recursos, como bien sabe, los debe solicitar en el propio CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-08-10','Ana: Envío correo a Toni-Futuex: "En relación a Ángel Félix Maillo, comunicarte que he recibido comunicación desde Cáritas de Plasencia, de que se ha quedado sin móvil y sin alojamiento, le han echado de la casa en la que estaba viviendo. Con respecto al móvil, les he pedido que envíen presupuesto con número de cuenta para abonarlo mediante transferencia bancaria. En cuanto al alojamiento, no sé cuándo tenéis programada la próxima visita, si se puede adelantar bien, sino, pues cuando la tengáis programada. Si cuando le visitéis no tiene aún alojamiento, y él acepta el apoyo, ayudarle por favor a buscar una habitación o un piso pequeño, plantea incluso en algún pueblo cerca de Plasencia. Ya nos vais informando al respecto." ··································································································································································································································································· Envío correo a Yessica, T.S. Cáritas(ydearriba@caritasplasencia.org): "No sé si Ángel Félix habrá vuelto a pasar por ahí, supongo que en tal caso le explicaste lo que estuvimos hablando, con respecto al presupuesto de teléfono (que necesitamos nº de cuenta para abonarlo mediante transferencia) y la búsqueda de alojamiento. Ante cualquier cuestión, no dudes en volver a contactar. Por cierto, he pedido a la Programa de Apoyo Comunitario gestionado por Futuex (Convenio firmado con la junta), que en cuanto sea posible vuelvan a visitarlo (no sé cuándo tienen programada la visita ni si la podrían adelantar) y, si él acepta el apoyo, le ayuden a buscar alojamiento (piso de alquiler/habitación) incluso fuera de Plasencia, como él mismo plantea en el escrito que nos enviaste." ·································································································································································································· Respuesta de Toni: "Hola Ana, no hay programada visita pq rexhazo de forma violenta los seguimientos hace unos meses y no hemos forzado la situación, creo q lo hablamos por email. Pero a mi vuelta y cuando estén las compis tb de regreso veremos si podemos abordarlo de algo la manera, sin q nadie corra riesgos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-08-10','Ana: Envío correo a Miguel, Asesor Jurídico, con copia a Maite, Jefa de Secc.: "En relación a JUAN MARIO SAN ROMÁN BLASCO, hay que solicitar internamiento involuntario en la UNIDAD DE ALCOHOLISMO del Centro Sociosanitario de Plasencia. Te adjunto todos los documentos facilitados por el centro en relación a su consumo, los incidentes acaecidos y el riesgo para su salud padeciendo la enfermedad de DIABETES MELITUS además de sus patología mentales y el riesgo para el resto de pacientes al introducir el alcohol en el CRR e incitar a otros pacientes al consumo. Si no se pone remedio van a expulsarlo del CRR quedándose en la calle. Además no dispone de capacidad para vivir de forma independiente."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-08-05','Ana: Tras leer correo de Yessica, TS Cáritas Plasencia: "Buenos días, mi nombre es Yessica de Arriba González, Trabajadora social del Comedor Social "Casa Betania", de Cáritas diocesana de Plasencia. Adjunto remito presupuesto de un nuevo teléfono para D. Ángel Félix, porque el que tenía se ha estropeado, y necesita el teléfono para comunicaciones y gestiones que estamos realizando. Asimismo enviamos una carta de su puño y letra en el que comenta la situación que sufre actualmente, ya que está viviendo en la calle, no tiene para pagar una habitación y solicita por favor que le busquen una habitación fuera de Plasencia. Observamos un deterioro físico grande, está más delgado y sin apenas fuerzas, acude diariamente al Comedor social pero no es suficiente para poder tener una recuperación plena, porque al vivir en la calle no puede descansar ni asearse correspondientemente. Por favor, rogamos le acepten el presupuesto del móvil y le busquen una habitación o un lugar donde poder descansar y recuperarse." ······················ Llamo a Yéssica, TS (927 422 406 - 645.887.203): Informo que se trata de una Curatela para la administración de sus bienes y sobre el modo de proceder de la CTAEX. La asignación que tiene aprobada, el seguimiento y apoyo que recibe del Programa de Apoyo comunitario gestionado por Futuex y la actitud de Félix ante el mismo, pues no acepta apoyo porque no quiere ningún tipo de control. ·············· Acordamos que tienen que facilitar el presupuesto pero con nº de teléfono y nº de cuenta para abonar el terminal mediante transferencia. Pediré a Futuex, que le visiten cuando puedan para apoyar en la búsqueda de habitación/piso de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2022-08-11','miguel, recibo email de la parte social (Tere y Maite): Buenas, Envián este correo desde Proines. Tere les ha dicho que lo comunicaremos al juzgado pq no podemos hacer nada al respecto. No sé la conveniencia de hacerlo. *************************************************** mi contestación:Buenos días, como sabéis no se puede obligar a nadie a dejar de consumir estupefacientes y sustancias tóxicas. Este es uno de esos casos. Está bien que intenten que adquiera unos hábitos como es dosificarle las cantidades que toma a lo largo del día, pero llegado al punto en que está seguramente sea irreversible que lo deje. Entiendo que todo lo que comentan debe ir unido al resto de situaciones sociales que recoja el informe social que se manda junto a las rendiciones anuales. No se trata por tanto de una incidencia puntual que haya que notificar al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-08-10','Ana: Correo de Modesto, Res. Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es): "Adjunto enviamos la factura del acompañamiento de Juan Sanguino el cual salió a pedir de boca. Juan contentísimo y todo fenomenal. Por favor pásasela a quien corresponda para su abono, el cual esperamos que sea pronto y dejemos el listón bien alto para futuros acompañamientos. En la factura aparece el número de cuenta." ·························· Paso factura para su abono a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-08-11','Ana: Conversación con María Álvarez, TS de Alcuéscar (Martes y Jueves en Aldea del Cano: 927 38 31 25): Ayer acudió Saturnino a su despacho, pedía dinero, se mostró exigente y un tanto agresivo verbalmente. Le enseñó su cartilla bancaria, donde pudo comprobar los ingresos y todas las retiradas de efectivo que ha efectuado. *Me pregunta a qué corresponden los ingresos que tiene. También informa que le ven mucho por los bares y parece algo más nervioso. ····· Explico la situación actual, las dificultades con el banco, las acciones emprendidas por cada una de las secciones de la CTAEX y del seguimiento y apoyo por parte del Programa de Apoyo Comunitario. ········· *Acordamos que ante cualquier incidencia nos hagan comunicación por escrito y ante cualquier signo de descompensación activen el 112. *Lo comunicará también a la Policía y a la Guardia Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-08-11','Ana: Conversación con Marisa, Directora de la Residencia Madre Francisca de Azabal (927 436 031 / 696 17 20 98): me explica que cuando José Aº ingresó, le hicieron como "favor" un precio especial. La cuantía que debería abonar a día de hoy son 1000 € y él abona 750 apróx. ············ Como se solicita la pensión de orfandad, si se la conceden habrá que abonar más. Si no llega a los 1000 €, no pasa nada, pero hay que abonar la cuantía más aproximada posible. ··········· Pido a Marisa que nos lo pongan por escrito en un correo para trasladar la situación a la sección económica. Me facilita el email de la resi para que se lo pida por escrito: residenciamadrefranciscazabal@hotmail.com ··· Les envío el mail. ······························································································································································································· Con el nº de seg. soc. del padre, que facilita Fini (fini_barros@hotmail.com), hermana de José Aº, finalizo la solicitud y la subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-08-11','Ana: Llamada de Isabel (649 642 635): dice que ayer se cayó, por la noche, se metió en una cueva que hay cerca del CRR y se tropezó con una viga. Tiene dolorida y amoratada la cadera. ······· Ahora está durmiendo sola en un habitación en la planta baja, dado que Julia, su compañera de habitación, está aislada por Covid. ···· No le gusta estar abajo sola y echa de menos a Julia. *Le digo que ahora tiene que apoyarse la una a la otra (han entablado amistad) ············· Me informa también que mañana finalmente irá su madre a visitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-08-11','Ana: Tras hablar con Sonia Bernabé (927 390 193), envío correo a Alberto y Miguel, en relación al que escribió Miguel ayer: "Buenas, a los dos, Simplemente comunicaros que ya he hablado con Sonia, TS de Asindi: la casa en que vivía el padre de Aarón, es una vivienda social en régimen de alquiles de la Junta de Extremadura. Los sobrinos (primos de Aarón) ya han ido a la Consejería de Vivienda a comunicar el fallecimiento del padre y ya han vaciado la casa para entregarla a la Junta. Sonia les va a comunicar que pueden proceder a dar de baja los suministros (esperemos que no haya problemas con esto) Por otra parte, cree que Aarón es el único heredero, pues tiene otros dos hermanos pero por parte de madre. De su padre, que se sepa, es el único hijo. Sonia preguntará también a la sobrina si nos puede facilitar sus datos de contacto (nº de teléfono e email) por si precisásemos hablar con ella. Hasta el momento están muy involucrados y colaborando bastante con respecto a Aarón (le han llevado sus pertenencias, visitado un par de veces y le llaman de vez en cuando)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-08-11','Amalia. -Hay que firmar la no aceptación PIA y registrarlo . -He enviado a CRR solicitud + I. medico para solicitar plaza residencial de mayores por decreto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-11','Ana: Llamo a Jesús, hermano de Martín (927 23 75 73 // 600 70 22 55): solicito que redacte un breve documento en que proponga la venta de la vivienda de la que es copropietario con Martín. ············ Le envío correo (gjdpalencia@gmail.com) con copia oculta a Maite y Miguel: "Tal y como hemos acordado mediante conversación telefónica, te anoto el contenido mínimo que debe tener el escrito de propuesta de venta de la vivienda de la que eres copropietario junto con tu hermano Martín. - Datos personales tuyos y de tu hermano (Nombre, Apellidos, DNI) y parentesco. - Datos de la vivienda: nº de referencia catastral, nº de finca/s registral, dirección física y titulares de la vivienda. - Si pudieras hacernos llegar también la NOTA SIMPLE, sería de gran ayuda. - Expresar, en el escrito, tu deseo/conformidad de vender la dicho inmueble. Por otra parte, si nos pudieras facilitar los datos de la otra vivienda de tu hermano, lo agradeceríamos, pues nos facilitaría bastante las gestiones."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-11','Ana: Llamo a Jesús, hermano de Martín (927 23 75 73 // 600 70 22 55): solicito que redacte un breve documento en que proponga la venta de la vivienda de la que es copropietario con Martín. ············ Le envío correo (gjdpalencia@gmail.com) con copia oculta a Maite y Miguel: "Tal y como hemos acordado mediante conversación telefónica, te anoto el contenido mínimo que debe tener el escrito de propuesta de venta de la vivienda de la que eres copropietario junto con tu hermano Martín. - Datos personales tuyos y de tu hermano (Nombre, Apellidos, DNI) y parentesco. - Datos de la vivienda: nº de referencia catastral, nº de finca/s registral, dirección física y titulares de la vivienda. - Si pudieras hacernos llegar también la NOTA SIMPLE, sería de gran ayuda. - Expresar, en el escrito, tu deseo/conformidad de vender la dicho inmueble. Por otra parte, si nos pudieras facilitar los datos de la otra vivienda de tu hermano, lo agradeceríamos, pues nos facilitaría bastante las gestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-08-12','Ana: correo de Yessica, TS del Comedor Social de Cáritas (ydearriba@caritasplasencia.org): "Buenos días Ana, sí, viene todos los días, le pedí el número de cuenta pero creo que se la olvidado dármelo. Con respecto a la habitación me ha dicho que está buscando ,y me preguntó cuánto tiempo tardarían en darle respuesta, le informé que es parte de un proceso que deben valorar y que por lo tanto se demoraría en unos días o semanas. En cuanto tenga el número de cuenta de la empresa, lo adjunto por esta vía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-12','Maite:he contactado con el centro Mentalia de Arévalo para que valoren la posibilidad de ingreso de Mercedes, de forma temporal. Hasta el dia 16 de agosto no está la persona que lleva las adminisiones. Modesta, trabajadora social de Mentalia, me dijo que Mercedes habia sido usuaria suya hace muchos años. Envié mail a Juanjo ( equipo de salud mental badajoz) informando del trámite realizado con el centro y haciéndole saber la necesidad de que Mercedes permanezca en la UHB hasta que pueda entrar en el centro. Buenas tardes Juanjo, Soy Maite Gómez, compañera de Amalia. Como te ha comentado élla, estamos viendo la posibilidad de que Mercedes Pérez Pinna ingrese en un centro de Avila. He hablado esta mañana con ellos y me dicen que hasta la semana que viene no pueden responder, ya que faltan profesionales del equipo. Es necesario que Mercedes pueda permanecer en la UHB hasta que nos respondan y saber si puede entrar en este centro. En cuanto sepamos algo os informamos. Gracias. La semana que viene hbalré con Mentalia de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-08-12','Maite: enviado al centro de Alcuéscar el informe social para que valoren la posibilidad de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2022-08-12','TERESA TRAS CONVERSAICON CON CAROLINA TS HOSPITAL DE ZAFRA ME ENVIA DOCUMENTACION PARA SOLICITAR PLAZA T3 TRAS EL ALTA EN EL HSOPITAL PUES LA FAMILIA PIDE QUE LA LLEVEMOS A OTRA RESIDENCIA LE ENVIO TODA LA DOCUMENTACIONA A LA ESPERA ME INFORME DONDE HAY PLAZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-08-12','Ana: Envío a registro del SES - Oficina de Atención al Ciudadano (oac.merida.san@juntaex.es) la solicitud de PRESTACIÓN DE SUPERVIVIENCIA: ORFANDAD, junto a toda la documentación pertinente para que le den registro de entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2022-08-12','TERESA Teresa, se va a realizar la derivación de Juan José Mesa Candil a UHDAC de Plasencia desde el equipo de Salud Mental de Don Benito y un requisito es una ORDEN DE INTERNAMIENTO INVOLUNTARIO DEL JUEZ, por lo que debéis solicitarla vosotros al encontrarse tutelado, actualmente Juan José se encuentra ingresado en UHB de MÉRIDA desde el pasado 2 de agosto. Cuando tengáis dicha orden de internamiento involuntario me la remites para que la envíe al equipo de salud mental de Don Benito. SE LO PASO A MIGUEL PARA QUE LA SOLICITE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2022-08-12','TERESA A PETIDCION DE MARGARITA ENVIO DESETIMIENTO PARA QUE ARCHIVEN LA PETICION DE TRASLADO DE RECURSO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2022-08-12','Ana: Correo del CRR-CC (crr@grupociudadjardin.com): "Buenos días, en relación a la persona tutelada del CRR de Cáceres, Félix Valle Simón, adjuntamos consentimiento informado para una pequeña intervención quirúrgica en una uña de la mano, para que sea firmado como nos solicitan desde el equipo médico." ············· Recabo la firma del D-Gerente y lo remito al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-12','Ana: envío correo a Toni-Futuex: "Nos han llamado hace unos minutos de la UHB de Cáceres. Quieren dar el alta a DOROTEO DÍAZ CERRO, además él lleva varios días pidiendo irse a su casa. **Su madre dice que con ella no vuelve y puesto que no tenemos otro sitio donde llevarle a día de hoy, hemos pedido que le tengan allí hasta el miércoles, para que el mismo martes se le pueda buscar hostal/pensión. **No obstante, el martes Soraya Masa hará algunas llamadas a ver qué otra opción tenemos. Él no acaba de aceptar el ingreso en otros CRR que no sean el de Cáceres. **Os pedimos, por favor, que, a ser posible, nos ayudéis a buscar un hostal/pensión aunque sea temporal para que pernocte a partir del miércoles, mientras se busca otra alternativa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-16','Ana: *Puesto que la semana pasada daba error en el envío, vuelvo a enviar a Jesús, hermano de Martín, el correo con los contenidos del escrito-propuesta de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-08-16','Ana: Subo al Portafirmas Digital, la Comunicación de Variaciones de Datos Bancarios al INSS. ························ Envío a REGISTRO (oac.merida.san@juntaex.es) la comunicación de variaciones junto a la documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-08-16','miguel, llama la sobrina de la tutelada, Rebeca Gallego con tlfno 606205733, quién a través del email de una hna o hno (Macarena...) remitirá la documentación de la masa hereditaria del fallecido hermano de la tutelada. Me informa que ellos han aceptado y que el hijo? del fallecido renunció. También remitirá a ctutelar el número de teléfono de la asesoría de Coria que ha tramitado toda la herencia del resto de los hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-08-16','Maite:ha venido Rubén para que firmásemos los documentos para formalizar la matrícula en un ciclo formativo de mecanica en el IES Emérita Augusta. He llamado a Raquel del CRR de Mérida para contrastar la información y me ha dicho que lo habia hablado con ellos y seria beneificoso para él hacer el ciclo formativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-08-16','Ana: Llamada de Julia Durán, TS del Centro de Mayores ("Hogar") Peña del Cura de CC (22032): Ventura acude casi a diario al Centro y participa en muchas actividades. En verano las dos que tienen son Musicoterapia y Ajedrez. *Puesto que es usuario del SAD le ha propuesto solicitar el proyecto piloto de Catering del IMAS. Cuando Ventura lleve el Informe de Salud me remitirá la solicitud para que la firme el Presidente de la CTAEX. *Parece muy solo y le preocupa. *Le informo de que está derivado al Programa de Apoyo Comunitario que gestiona FUTEX, pero que él rechaza el seguimiento y los apoyos. *La Educadora es Virginia. ············ *Ventura quiere solicitar también el programa de termalismo del IMSERSO. *Nos remitirán la solicitud y la información al respecto. ····················· Por otra parte, dice que tiene la boca fatal y que necesitaría acudir a alguna clínica dental. *Solicitarán presupuestos, intentarán remitirnos un par de ellos. ··································································································································································································· Envío correo a Toni-Futuex: "En relación a VENTURA GÓMEZ GARCÍA, comunicarte que se ha puesto en contacto conmigo Julia, Trabajadora Social del Hogar de Mayores Peña del Cura de Cáceres. Puesto que Ventura acude al dicho centro prácticamente todos los días y la T.S. se está implicando bastante con él, creo que sería positivo retomar el seguimiento y los apoyos de Ventura contando con el apoyo y colaboración de Julia. Puesto que también se le ha ampliado el Servicio de Ayuda a Domicilio municipal, podría ser un buen momento para retomar el contacto con él, quizá lo acepte más y quiera colaborar. Julia se plantea también hacerle una visita domiciliaria y le parecería estupendo poder acudir con la educadora de referencia, que si no recuerdo mal es Virginia. Si os parece, podría ponerse en contacto con ella a su vuelta de vacaciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2022-08-17','Ana: Envío a María Cárdenas, TS ASPROVID, C.I. para Estudio Electrofisiológico y Ablación de Arritmias, debidamente firmado y sellado. ········· *Guardado en expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-08-17','miguel, envío a petición de Soraya contestación al juzgado de instrucción nº1 contestación al requerimiento de información de cuándo se internará el tutelado en la UHDAC, el cuál está en lista de espera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='VIREL'and apellido2='GALEA'),'2022-07-30','EXITUS El ssasb de Alconchel nos informa de su fallecimiento. El óbito tuvo lugar el 30/07/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-08-17','Ana: recibimos CERTIFICADO ACTUALIZADO DE PENSIÓN DE INCAPACIDAD PERMANENTE TOTAL: 527,40 € x 14.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-08-17','Ana: Envío correo a Ángel y Miguel, Asesores Jurídicos, solicitando el escrito de la situación ecca. que nos piden para solicitar la plaza en Montánchez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-17','Ana: Soraya Masa nos confirma que finalmente aceptan el ingreso de Martín en la UME, CSS-Plas. ·········· Nos reenvía correo de José Antonio Mesa Garrido Director del CSS, en funciones (joseantonio.mesa@salud-juntaex.es // 927 42 88 09 // 24154): "Hola, Soraya: No hay ningún inconveniente para el ingreso de este paciente cuando queráis. Únicamente te ruego que nos aviséis el día antes. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-08-17','Ana: Llamo a Diego, Padre de Consuelo (645 363 630 / 927 582 223), en relación a su llamada de ayer y la conversación posterior con Cristina - Psicóloga CRR: la propuesta de que de forma temporal vaya a casa todos los fines de semana y permanezca en el CRR de L a J, le parece bien. *Me pasa a Consuelo. Ella dice que no el parece bien la propuesta. No quiere volver al CRR, dice que no está bien allí, que hay mucho barullo, no está tranquila y se altera. Que además las monitoras le "quitan dinero". *Además, expresa haber tenido una corazonada que le dice que se tiene que quedar en su casa porque allí va a estar bien, cuidando a su madre. Verbaliza también que el pueblo para ella ahora mismo "es como el Paraíso y "el CRR como el Infierno". Con su "amigo" (Juan Mario), tampoco está bien porque bebe mucha cerveza y consume porros, que le quiere mucho pero ya no confía en él. *Le explico que estamos buscando una alternativa para él para que traten sus problemas de consumo. ·········· En cuanto a AIDIN (Asociación de Personas de Discapacidad con Programa de Normalización), dice que iría durante el día y se iría a dormir a casa. Pero que también están haciendo habitaciones en la planta de arriba. ········· Conforme avanza la conversación va cambiando su discurso, comienza a decir que no sabe por qué hay papeles que ponen que tiene Retraso Mental, pero ella no tiene, que tiene Esquizofrenia. Le corroboro que no presenta Discapacidad Intelectual y por ese mismo motivo no da perfil para el centro que su padre y ella plantean, pues es para P. con D.I. *Añade que se está pensando en no ir allí... *Le digo que vaya pensando todo con calma, que como mañana le llamará Cristina, Psicóloga, lo puede hablar con ella. ······························ *Llamo a Cristina, pero no está. Le dejan nota para que me llame mañana a primera hora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-17','Ana: Sara, Psiquiatra de UHB, confirma a Maite que Doroteo no cumple criterio para UME, por lo que no se acepta el ingreso. ·············· Maite habla con Soraya, nos pide que esperemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-08-18','Ana: Llamada de Cristina, Psicóloga del CRR-CC (927 830 210): Le informo sobre la conversación mantenida con Consuelo ayer. La llamará ella hoy. *Nos irá informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-08-16','Ana: Llamada de Diego, padre de Consuelo: dice que su hija no está bien en el centro y propone el cambio de recurso a AIDIN (Organización de asistencia y servicios para personas con discapacidad), le indico que su hija no da perfil para este recurso. Además no tiene servicio de residencia. ································································································································································································· Llamada de Cristina, Psicóloga del CRR-CC (927 830 210): Consuelo está en casa de sus padres. El padre le ha llamado para decirle que Consuelo no va a regresar al CRR, y que ya lo ha hablado con la CTAEX (No es cierto, ni siquiera me ha dicho que su hija estaba allí ni nos lo habían comunicado previamente desde el CRR). *A Consuelo le influye mucho el estado de Juan Mario y por el miedo a perderlo acaba haciendo cosas que no quiere hacer como consumir cerveza y otras sustancia con él, pagarles las consumiciones... **Hoy ha acudido al centro de salud de su pueblo para ponerse el inyectable y mañana tiene cita para recoger las recetas del resto de su medicación. ·············· Cristina considera que le puede venir bien estar más días en casa, pero tampoco demasiado tiempo. ···· Acordamos hacerle la propuesta de que se quede hasta el próximo lunes en casa y a partir de ahí, pasar de L-J en el centro y los fines de semana (V-D) en su casa. Al menos durante un tiempo hasta que la situación con Juan Mario mejore. *Mañana le llamaré yo y Cristina al día siguiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-18','Ana: Llamamos, Maite y yo, a Julia García Félix, Coordinadora de la Casa de la Misericordia de Alcuéscar (927 12 00 24): No saben si podrían aceptar a más personas. Están pendiente de hace dos valoraciones de otras dos solicitudes de ingreso, pero hasta mediados de la semana que viene que está el director del centro no podrán valorar y comunicárnoslo. **No obstante, recalca la voluntariedad como requisito indispensable en el acceso. ············ Llamamos a Juani, TS HSPA (56341 / Busca: 616 941 742): acordamos que hablará con Doroteo para plantearle la posibilidad de acceso en la Casa de la Misericordia, puesto que a su casa no puede volver y no debería vivir sólo, que sería la única alternativa que le quedara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-08-18','miguel, llega email del ayto de malaga notificando que se ha de reintegrar la fianza de 450€ correspondiendo al contrato de arrendamiento. Se lo reenvío a Rocío (la abogada)y a Damian para que comprueben si es correcto. Hablo con Damian quién me indica que no ha recibido el último pago del ayto. Le digo que vamos a abonarlo. También le explico que seguimos pendientes de la resolución del jzdo decano de Mérida (al que solicitamos en junio autorización para entablar demanda por desahucio, tal como solicitó el jzdo de Málaga y al que habrá que volver a solicitarlo en septiembre ante la falta de contestación por este jzdo decano asignando procedimiento y juzgado). Remito a Oscar y Alberto tanto dicho requerimiento de pago de los 450€ y les indico que envíen el justificante de la transferencia cuando la hagan a Rocío (abogada), ayto de Malaga, Damian. Damian menciona que ya está en piso tutelado y que quiere recuperar su capacidad, le informo que todo lo que no tenga que ver con temas jurídicos lo trate con su trabajadora social, Amalia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-08-18','miguel, asiste la abogada de oficio que solicité y yo por videoconferencia a la vista en el jzdo nº1 de Zafra (nos citaron ayer) para declaración de la tutelada, en procedimiento DPA Diligencias previas 494/2022, el cual quedará archivado ya que pide que se olvide todo porque ella está muy bien actualmente con Antonio (su pareja)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-08-18','Ana: Remito a Paula, TO CRR (direccion.crrplasencia@grupo5.net): el contrato de Rehabilitación del CRR, debidamente firmado y sellado por el Presid. CTAEX. *Pido nos remitan copia una vez lo haya firmado también Javier.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-08-18','Ana: guardo en el expdte. Correo del CRR-CC del martes 16, al ctutelar@, con las incidencias de las últimas semanas. Juan Mario continúa bebiendo cerveza a diario, con signos de embriaguez, con reacciones agresivas, orinándose encima...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA REYES'and edp.apellido1='TARDIO'and apellido2='NUÑEZ'),'2022-08-18','Maite: he contactado con el hospital de LLerena. En Septiembre tienen que cambiarle el catéter y necesitan el consentimiento informado. No sabían cual era el procedemiento. He hablado con Rosa de diálisis: 47260','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-08-18','Maite: ha llamado la madre de Eduardo, María. No está en la tienda de campaña y está preocupada: Queria saber si sabiamos donde está. No sabemos nada. Estaremos pendientes por si comuncian algo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-08-18','miguel, me llama la sobrina Raquel Rodriguez Baños(tlfno 650-269691 e email raquelrodriba@email.com)para decirme que necesita una autorización de la comisión para que el banco les de un certificado del plazo fijo de Virgilia (sobrina de la tutelada y de la que ella es heredera). Le pido el tlfno del gestor que le está tramitando los papeles, Miguel 647246302, email miguelgarjim43@gmail.com Quedo con él que envío un email a la parte económica, Oscar, para que vaya solicitando un certificado de saldo a fecha de fallecimiento de la sobrina, Virgilia, y se lo remita al gestor Miguel. Y envío email con los datos de Oscar al gestor para que pregunte las dudas que tenga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-08-18','Ana: Tras atender llamada de Jairo, envío un correo a Toni-Futuex: "En relación a JAIRO PUERTAS MARTIN, creo que ya os lo comenté, pero por si acaso. He hablado con él y expresa el deseo de que acuda Gloria a visitarle y apoyarle con en el proceso de Búsqueda Activa de Empleo que quiere iniciar. No sé si a Gloria le queda vacaciones y cuándo las tiene, ni en su caso, cuándo tiene programada la visita al Centro Sociosanitario, ya me iréis diciendo. En cualquier caso, a Jairo le he pedido que tenga paciencia y le he dicho que si Gloria no pudiera ir en agosto, ya le visitará seguramente en septiembre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2022-08-18','Ana: Tras varias conversaciones y valorar la propuesta que envía por mail, envío coreo-e a Daniel, Seguros Santa Lucía (daniel.blancob@agencia.santalucia.es): "Tras haberlo valorado con las compañeras de la sección económica y la Jefa de Sección de la Comisión Tutelar, lamentamos comunicarte que a Teresa Nevado le trae más cuenta mantener el Seguro de Decesos que se contrató desde aquí hace algunos años. La póliza incluye las misma servicios y abona la mitad de lo que le constaría en Santa Lucía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-08-17','Ana: Correo de Mónica, Enfermera del ESM-PLAS (monica.hernandez@salud-juntaex.es): "Buenos días Ana, Soy Mónica, enfermera del ESM Plasencia y en este caso referente del usuario Alfonso Marín de Cáceres. Me ha informado la Dra. Gutiérrez de la medida de seguridad que ha de cumplir dicho usuario. Desde ESM se comprueba adherencia mensual al tto depot y seguimiento. Informo de la siguientes citas: • 18 de agosto 9.45h c. enfermería • 27 de septiembre 9.30h consulta psiquiatría. Un cordial saludo," ······································ *Se lo reenvío a Toni-Futuex, para que desde el Programa de Apoyo Comunitario puedan realizar el apoyo/acompañamiento a la cita de Psiquiatría de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-08-18','Ana: Escribo a Mónica Hdez., Enfermera de ESM-Plas (monica.hernandez@salud-juntaex.es): "Buenas tardes Mónica, Gracias por informar. He solicitado apoyo para acompañamiento al Programa de Apoyo Comunitario, gestionado por Futuex, desde el que hacen seguimiento a Alfonso Marín de Cáceres, a la cita de Psiquiatría de Septiembre. Quería preguntarte por la asistencia de hoy a tu consulta, a la cita programada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-08-18','Ana: Llamada de Julia Durán, TS del Centro de Mayores ("Hogar") Peña del Cura de CC (22032): puesto que Ventura está diagnosticado de Inteligencia Límite, reúne requisitos para el PADDI, intentará hacer las gestiones para incluirlo en el programa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-08-18','Ana: Envío correo a Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "En relación a CEFERINO MARISCAL CRESPO, y a su petición de un móvil nuevo, queríamos solicitaros que no remitáis un presupuesto a su nombre de la tienda en que los ha mirado y preguntado precio. *El presupuesto debe tener el nº de cuenta de la tienda, para que, en caso de que Alberto el lunes lo apruebe, que espero que así sea, se le abone directamente a la tienda mediante transferencia y a posteriori Ceferino podría ir a retirarlo cuando quisiera. Gracias y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-08-19','Ana: Tras hablar con Maribel, TS SSASB-Mérida (824 90 50 49), envío correo a Amalia: "...Me ha llamado Maribel Candelario, TS del SSASB de Mérida (824 90 50 49). Comunica que ha recibido llamada de Ana María Rosco (616 72 94 63), solicitando cita para la renovación de la Renta Básica. Ana María, como ya sabíamos, no quiere oír hablar de que está tutelada, ni de la CTAEX. Le han dado cita para el lunes 22 a las 13 h, pero van a intentar cambiársela al miércoles, para tener margen de hablar contigo la TS y organizarlo, así hacer los trámites bien y que no ocurra como el año pasado, que estuvo 2 meses sin cobrar. *Aún está en plazo, hasta final de septiembre podría solicitarlo, pero al parecer ella cree que el plazo finaliza el 31 de agosto y aunque se lo han explicado ella insiste en esa fecha. Le he facilitado a la Trabajadora Social tus datos de contacto. No obstante, ahí tienes también su teléfono para que puedas llamarla tú si lo consideras."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-08-17','Ana: Correo de Marisa, Residencia Madre Fca. de Azabal (residenciamadrefranciscazabal@hotmail.com): "La fecha desde la que reside en el centro: 28 Agosto 2014 Los motivos por lo que ingresó y las condiciones (acuerdo económico al que se llegó): - José Antonio ingreso en la residencia por la situación que estaba viviendo. Motivos: - Vivia solo en un piso de alquiler sin ningún cuidado asistencial. - Tenía problemas de salud: persona diabética decontrolada, problemas de psiquitaria si una estabilidad y regularidad en la toma de medicamentos, mala alimentación, no tenia habitos de sueño estable acorde a su estado de salud, etc. - Situación económica: subsistia como podía. El acuerdo económico para ingresar en el centro: abonar como cuota la paga que cobra mensualmente + parte de las pagas extras. - La cuantía que viene abonando José Aº en la actualidad y la cuota que le correspondería abonar. - Actualmente Jose Antonio esta abonando: 12 pagas de 750€ + 2 extras de 600€ (Cuando cobra la paga extraordinaria). - La cuota que le corresponde pagar: 1.075€ - Solicitud de abono de mayor cuantía, para intentar adecuarse lo más posible, al coste de la plaza. Solicitamos el abono de una cuota de 1.075€ / mensuales."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-08-19','Ana: Envío correo a Alberto: "En relación a JOSE ÁNTONIO BARROS CORDERO, te reenvío correo de la Residencia, en el que, como les solicité, nos explican las circunstancias por las que ingresó, su situación económica y el acuerdo en que se llegó en su día (subrayo en amarillo abajo). Solicitan, cuando sea posible, el aumento de su cuota para aproximarse al coste real de su plaza en la actualidad. **Yo ya le he solicitado la Pensión de Orfandad, cuando recibamos resolución te informo y vemos cuánto más se podría abonar al mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-08-18','Ana: Conversación con Inés, TS sustituta de Estrella, CSS-Plas. (24146): Pedirán los presupuestos a la ortopedia. *Cuando reúnan toda la documentación para solicitar la AYUDA DEL SES para MATERIAL ORTOPROTÉSICO (informe médico con prescripción, facturas y solicitud), nos lo enviarán para cumplimentar lo que quede de la solicitud, recabar la firma del Presid. CTAEX y dar registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-08-17','Ana: Correo de Inés, TS sustituta de Estrella, CSS-Plas. (inesm.romero@salud-juntaex.es / 24146): "Te escribo porque Yolanda Caldera ha ido hoy a consulta de Traumatología y le han recomendado dos órtesis para la pierna. Una de ellas cuesta alrededor de 250 euros y es una órtesis estabilizadora regulable con bloqueo y la otra que le han recomendado cuesta sobre 80 euros y es un inmovilizador de rodilla. La referencia del catálogo de material ortoprotésico del SES es OIR020A. Intentaré contactar contigo por teléfono mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-08-19','Ana: Atención presencial a Ramón Galindo, primo de Aarón. Nos entrega fotocopia del DNI y Certificado de defunción de Julio, padre de Aarón, por si en un futuro nos hace falta para solicitarle alguna prestación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-08-19','Ana: Tras hablar con Pilar, Res. Navezuelas (684 220 280), le remito correo (pilarcortcer@gmail.com): "Tal y como hemos acordado mediante conversación telefónica, te envío adjunta la Sentencia de Incapacitación relativa a JUAN JOSÉ HORNERO RODRÍGUEZ. El segundo documento que adjunto es una aclaración del juzgado en cuanto a terminología. Seguimos en contacto." ···················· El lunes me remitirá informes médicos actualizados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-19','Ana: correo de Juani, TS HSPA (juanamaria.jimenezf@salud-juntaex.es): "La psiquiatra me ha dicho que hoy sin falta da el alta a Dionisio. Él me ha dicho que prefería quedarse en Cáceres, en el albergue y comer en el comedor social. Le he explicado que con su pensión no puede afrontar todo el mes y que en Alcuescar se encontraría muy bien, porque no solo hay discapacitados y mayores, como pensaba, sino personas de su edad y podría acudir a consulta en Cáceres. Llámame cuando puedas al busca Un saludo" ············ Hablo con Juani (56341): parece que Doroteo entiende que no tiene mucho dinero para estar mucho tiempo en el Albergue y que sería algo temporal. ··············· Llamo al Albergue Turístico Las Veletas - CC (C/ Gral. Margallo, 36, 10003 Cáceres - Teléfono: 681 25 87 01): contratamos una semana de alojamiento (23€/noche) que se abonará mediante transferencia por adelantado. El "check-in" lo hará a partir de las 17:30, pues comerá en el hptal. y permanecerá allí hasta que le den el informe de alta. ······················ Envío correo a Juani, TS HSPA (juanamaria.jimenezf@salud-juntaex.es): "Por favor, necesitaríamos que me hicieseis llegar a mi correo o a las malas por fax (924 00 31 94) el INFORME MÉDICO DE ALTA DEL SERVICIO DE PSIQUIATRÍA, nos lo piden para la valoración del ingreso en la Casa de la Misericordia. Por cierto, ya está abonada una semana de estancia en el Albergue turístico Las Veletas y enviado el justificante al mismo. Hemos comunicado que el check-in será a partir de las 17:30 h. Gracias por todo." ································································································································································································· Comunico a Toni Futuex el alta hospitalaria de Doroteo y dónde se alojará. Pido que hagan seguimiento lo antes posible. ······························································································································································································ Llamada de Carmen, hermana de Doroteo (669 864 167): pregunta "¿qué vais a hacer con mi hermano?". "¿dónde le vais a llevar", "¿quién le va a controlar la medicación?", "¿dónde va a comer?". Se le vuelve a explicar todo el proceso, el funcionamiento de la CTAEX y se le indica el recurso que se está intentando tramitar y el Albergue al que irá, al menos de forma temporal. ······· Entendemos que pasará por el domicilio a recoger su ropa y otros enseres personales. ··································································································································································································· Envío correo a Alberto, Jefe secc. ecca.: "En relación a DOROTEO DÍAZ CERRO, comunicarte la variación en su situación: - Ha estado ingresado 10 días apróx. en la UHB – Hospital San Pedro de Cáceres. Pero hoy ya le han dado el alta. *A casa con su madre no puede volver, la madre se niega a que vuelva a vivir con ella y la hermana tampoco colabora. **A falta de otros recurso al que pueda ir, de forma temporal se alojará en el Albergue Turístico las Veletas – Cáceres. El precio son 23€/noche. A partir de los 10 días podrían rebajar el precio algún euro más, pero poco. *La primera transferencia la ha hecho hoy María, pues había que abonarlo por adelantado. - A comer, en principio, acudiera al comedor social. - Hemos hablado con la Casa de la Misericordia de Alcuéscar, pero no nos podrán dar respuesta hasta mediados finales de la semana que viene, además estoy pendiente de informes para poder remitirles para la valoración. - Hay que DAR DE BAJA, la TRANSFERENCIA PERIÓDICA MENSUAL que se le ha estado haciendo a la madre en concepto de manutención. - Si se alarga la estancia, habrá que reajustar asignación para gastos de bolsillo (En vuestro Excel pone 50€ mensuales (poco me parecía), pero María ha mirado los movimientos bancarios y son 50€/semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-19','Ana: comunico a Pilar Cerrillo la aceptación de Martín en el CSS-Plas. (UME), puesto que es curatela ecca. y el hermano es colaborador, le llamará para organizar el traslado. ········ *El lunes me llamará al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-19','Maite: aceptan a Mercedes en Mentalia Arévalo.He hablado con Juanjo (UHB) para que pidan la autorización de internamiento involuntario. La semana que viene hay que concretar la fecha de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-07-15','Ana: Recibimos la Resolución de PFHC = 417,70€. Fecha de efecto: 01/07/22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2022-07-14','Ana: Recibimos el Cdo. actualizado de Pensión INCAPACIDAD ABSOLUTA = 721.70 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-07-07','Ana: Recibimos RESOLUCIÓN DE DEPENDENCIA, le reconocen GRADO II. ···· Ha obtenido una puntuación de 67 puntos según el Dictamen Técnico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-08-22','miguel, contestacion de Rocio Gracian (abogada): Buenas tardes Miguel Esta semana y la próxima estoy de vacaciones. He visto tu correo y ,por lo que leo en los archivos adjuntos, hay que devolver la fianza que el Ayuntamiento abonó a Damián. Las fianzas hay que devolverlas siempre al finalizar el contrato salvo que la vivienda presente daños o desperfectos. En este caso, dada la situación particular de los inquilinos de Damián y el procedimiento de desahucio pendiente no vamos a saber si hay o no desperfectos hasta que abandonen la vivienda. En cualquier caso, según expone el requerimiento del Ayuntamiento, Damián no presentó la documentación que le solicitaron en su día. Yo desconozco todo ese proceso porque Damián solo me encargó la notificación a los arrendatarios de la finalización del contrato y posteriormente el procedimiento de desahucio. Nunca me tuvo al tanto del tema de la subvención del Ayuntamiento. De ese tema solo tú me informaste antes de interponer la demanda que no se habían hecho bien las cosas y que mejor no reclamar las rentas debidas . Así que creo que es mejor devolver la fianza sin más, vaya a ser que salgan más irregularidades y tenga que devolver aún más dinero. No te parece?. El 29 me incorporo. Por favor, a ver si podéis informaros cuando llegue septiembre del juzgado y número de procedimientos de la demanda de solicitud de autorización judicial para estar insistiendo que resuelvan pronto. Creo que te dije en algún correo anterior que mi minuta por la demanda era 300 euros, más IVA, para que lo pongas en conociendo también de la parte económica de la comisión. Hablamos en septiembre.','2');
