insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-08-22','Ana: Teresa, TS de Novaforma, me remite Informe del Psicólogo de la entidad: "...desde el Servicio de Residencia de Novaforma, que Felipe presenta una alteración significativa de su patrón habitual de sueño así como aumento del consumo de tóxicos (café y tabaco). Pasa más de dos noches sin dormir y saliendo a fumar en torno a siete veces, cuando lo normal es que lo haga una o dos veces cada noche. Según refiere, se ha llegado a tomar hasta cinco cafés en un día (dos por la mañana y tres por la tarde), además de otro tipo de bebidas (leche, refrescos, etc.).", está asistiendo a bares y se deja influir por terceros, gasta más dinero de lo habitual, generando deudas con otras personas. "...Se incrementan (puesto que ya estaban generalmente presente) en las últimas semanas los pensamientos recurrentes y obsesivos de carácter suspicaz y que verbaliza, sobre los intereses (especialmente económicos) de otras personas, de la Asociación Novaforma, sus profesionales y también su familia sobre sus pertenecencias, sobre su testamento, etc.", "...aumento de pensamientos obsesivos así como un aumento de la dificultad para controlar sus impulsos y para esperar (impaciencia)...", "...El día 3 de agosto, ante su estado de nerviosismo, se recurre al MAP que prescribió un ansiolítico y también derivó al ESM para valoración psiquiátrica y revisión del tratamiento. El día 10 de agosto acude a revisión con el Dr. Enrique Goenaga del Equipo de Salud Mental de Cáceres, realizando éste ajustes en el tratamiento de Felipe." ····································································· Al preguntar a Teresa, TS, como sigue, responde: "Hola pues esta regular , super obsesionado con el dinero, la herencia ,ahora dice que se quiere ir de la residencia..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-08-22','Ana: Correo de Mónica Hdez, Enfermera del ESM-Plas (monica.hernandez@salud-juntaex.es): "Buenos días Ana, Disculpa la demora en responder. No acudió a la cita. Posiblemente se deba a que habitualmente el tratamiento se lo administran en Equipo de Atención Primaria para facilitar adherencia por problemas a la hora de movilidad geográfica. Me he puesto en contacto con la madre, sin éxito la semana pasada. Hoy contacté finalmente con ella para recordar fecha de dicho tratamiento. Habitualmente es cumplidor del mismo. Seguimos en contacto, buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-09-14','Buenos días, > > Mi nombre es Raquel Rodriguez Barrios, y me pongo en contacto con vosotros porque esta mañana al ir a hacer unas gestiones bancarias con mi padre, nos ha sido imposible realziarlas porque aparece como titular Jose Vicente Granado Granado, sin embargo, mis padres no están tutelados por la Junta de Extremadura, es por ello, que solicitamos la anulación de dicha persona como titular de la cuenta bancaria a la mayor brevedad, máxime cuando no podemos hacer ninguna disposición ni utilización de la cuenta bancaria. Adjunto datos: > La cuenta bancaria de mis padres es de Liberbank, con número > ES52 2048 1040 3830 0000 2542, en la localidad de Guijo de Granadilla > (Cáceres) > > Los datos de identificación de mis padres: > > CIPRIANO RODRIGUEZ FERNANDEZ 07418667V VIRGILIA BARRIOS GARCIA > 02471886F > > Asimismo, dicha persona aparece también como titular de una prima de mi madre, pero en este caso si que es tutelada por la Junta, sin embargo, no es una tutela económica con lo cual también solicitamos que se elimine la titularidad de la cuenta por parte de Jose Vicente Granado Granado, en este caso los datos de mi tía son: > > NEMESIA GARCIA PANIAGUA 07331247C > > Os facilito mi número de teléfono por si queréis poneros en contacto > conmigo, > > 686265345 > > Gracias de antemano y un cordial saludo > > RAQUEL RODRIGUEZ BARRIOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2020-09-14','Buenos días, > > Mi nombre es Raquel Rodriguez Barrios (aquelrodriba@email.com), y me pongo en contacto con vosotros porque esta mañana al ir a hacer unas gestiones bancarias con mi padre, nos ha sido imposible realziarlas porque aparece como titular Jose Vicente Granado Granado, sin embargo, mis padres no están tutelados por la Junta de Extremadura, es por ello, que solicitamos la anulación de dicha persona como titular de la cuenta bancaria a la mayor brevedad, máxime cuando no podemos hacer ninguna disposición ni utilización de la cuenta bancaria. Adjunto datos: > La cuenta bancaria de mis padres es de Liberbank, con número > ES52 2048 1040 3830 0000 2542, en la localidad de Guijo de Granadilla > (Cáceres) > > Los datos de identificación de mis padres: > > CIPRIANO RODRIGUEZ FERNANDEZ 07418667V VIRGILIA BARRIOS GARCIA > 02471886F > > Asimismo, dicha persona aparece también como titular de una prima de mi madre, pero en este caso si que es tutelada por la Junta, sin embargo, no es una tutela económica con lo cual también solicitamos que se elimine la titularidad de la cuenta por parte de Jose Vicente Granado Granado, en este caso los datos de mi tía son: > > NEMESIA GARCIA PANIAGUA 07331247C > > Os facilito mi número de teléfono por si queréis poneros en contacto > conmigo, > > 686265345 > > Gracias de antemano y un cordial saludo > > RAQUEL RODRIGUEZ BARRIOS','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2022-08-22','Ana: Envío a Julio, Aux. Admvo., para REGISTRO, oficio-solicitud de Certificado Actualizado de Pensión de Viudedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2022-08-23','Ana: Envío a Julio, CTAEX, oficio-solicitud de CDO. actualizado de P. JUBILACIÓN, junto con los documentos pertinentes para su registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-08-23','-Amalia: solicitud a parte eco : Buenos días , está ingresado en centro Camino a la Vida y ya se hace la transferencia del pago directamente al centro. ( está pendiente de juicio que saldrá en septiembre. ) Se han anulado los reintegros que tenía concedido porque de allí no puede salir . La familia solicita 70€ para llevarle tabaco , se le puede hacer una transferencia mensual al padre por este concepto . Hay que hacerle también al padre , una transferencia puntual de 300€ en concepto del pago del mes de agosto del centro que lo abonó él . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-08-23','-Amalia: solicitud a parte eco : Buenos días , está ingresado en centro Camino a la Vida y ya se hace la transferencia del pago directamente al centro. ( está pendiente de juicio que saldrá en septiembre. ) Se han anulado los reintegros que tenía concedido porque de allí no puede salir . La familia solicita 70€ para llevarle tabaco , se le puede hacer una transferencia mensual al padre por este concepto . Hay que hacerle también al padre , una transferencia puntual de 300€ en concepto del pago del mes de agosto del centro que lo abonó él . Un saludo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-08-23','-Amalia : respuesta que doy al SSASB . Está en contacto con REG y si necesita algún documento más me lo indicará. Amalia, Tal y como hemos hablado, ella puede firmar la solicitud, conforme a la normativa actual. No obstante, si puedes hablar con renta, podemos acompañar a su solicitud un escrito nuestro ratificándonos en la misma, para que no ocurra como el año pasado. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-08-23','-Amalia : respuesta que doy al SSASB . Está en contacto con REG y si necesita algún documento más me lo indicará. Amalia, Tal y como hemos hablado, ella puede firmar la solicitud, conforme a la normativa actual. No obstante, si puedes hablar con renta, podemos acompañar a su solicitud un escrito nuestro ratificándonos en la misma, para que no ocurra como el año pasado. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-23','Mayte : Buenos días Juanjo, Nos han contestado desde el centro de Avila. Mercedes es aceptada. Nos piden la autorización de internamiento involuntario y el certificado de vacunación. Yo me voy hoy de vacaciones pero estará Amalia. Ella concretará con el centro el día de ingreso. Tendriais que pedir el internamiento involuntario. Seguimos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-08-23','-Amalia : envio email a Carmen , TS del ESM, Buenos días Carmen. He estado hablando con Soraya Maya de estos dos casos , me pide que te indique lo siguiente : con respecto a M. Ortiz , la UHDAC ha aceptado el ingreso . El asesor jurídico está con las gestiones judiciales pertinentes y en cuanto quede plaza libre en el centro ingresará. con respecto a A. Nuñez Bono , me dice que en la subcomisión estuvo la médico del CEDEX . Que por favor , haga un informe indicando que ya se expuesto en la misma que el problema de Alejandro no era por su consumo y que tú como TS del ESM lo reenvíes , ratificando esa misma idea y solicitando a la UHDAC una revisión . Es increíble , que se tenga que hacer una segunda revisión del caso . Sinceramente , no se´ si funcionará pero es lo me traslada . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-11-25','-Amalia : tras los recursos planteados desde el ESM se admite a UHDAC , está en lista de espera , es necesario que ingrese ya . La familia está desbordada por sus peticiones económicas , agresiones verbales y amenazas , comunica la abuela vía telefónica que está gastando mucho dinero en juego . El abuelo está pendiente de operación médica y no lo pueden atender .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-08-22','-Es aceptado para ingreso en UHDAC , en cuanto quede plaza libre ingresará en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-08-23','Ana: Remiten desde la Residencia de Mayores Sierra de San Pedro (administracion@centrodemayoressierradesanpedro.es) la ACEPTACIÓN PIA de PRESTACIÓN ECONÓMICA VINCULADA AL SAR (175 €). Recabo la firma del Presidente de la CTAEX. ······························ Envío correo a la residencia: "adjunto remito la aceptación PIA debidamente firmada y sellada por el Presidente de la CTAEX. *Pongo en copia a mis compañeros de la Sección económica para que puedan localizar los recibos bancarios que indicáis (subrayo abajo en amarillo), para que os los remitan a esta dirección en cuanto les sea posible. Por cierto, ¿no se le va a solicitar plaza pública de residencia (Servicio de Atención Residencial)? Me extraña que de Dependencia sólo hayan facilitado a la opción de Prestación Vinculada al Servicio. Ya me decís cuando podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-23','Ana: Envío correo a Julia, Coord. Casa de la Misericordia de Alcuéscar (casadelamisericordia.alcuescar@gmail.com): "En relación a la conversación telefónica mantenida la semana pasada, te envío adjuntos los siguientes documentos para la valoración del ingreso en vuestro centro de Alcuéscar, relativos a D. DOROTEO DÍAZ CERRO, de 53 años de edad: - Certificado de Discapacidad - Dictamen Técnico del CADEX - Informe de Alta de la UHB (Servicio de Psiquiatría del Hospital San Pedro de Alcántara Como se refleja en el informe de psiquiatría, las relaciones familiares son malas y como te comentamos, la madre no quiere que vuelva a convivir con ella, de hecho actualmente está alojado en un albergue turístico de Cáceres. En las últimas conversaciones, tanto con la Trabajadora Social del Hospital, como ayer conmigo vía teléfono, expresó que aceptaba ir a vuestro recurso. Percibe una Pensión de Incapacitad Permanente Absoluta de 721,20€, de la que se podría establecer un pago a vuestro centro y una asignación semanal de bolsillo (Actualmente tiene aprobado 50€/semana). No cuenta con propiedades ni con ningún otro sitio a donde ir. Tiene solicitado ingreso en CRR de Cáceres, pero está en lista de espera. Si necesitas alguna otra información, dímelo." ··································································································································································································· Correo de Toni-Futuex: "En relación a DOROTEO DÍAZ CERRO, te anoto fechas de las próximas citas programadas, para que se le pueda hacer acompañamiento desde vuestro programa: - Consulta Psiquiatría en ESM: Viernes 02/09/2022 a las 12:30 h con la Dra. Carreiras - Consulta en Enfermería de Salud Mental: Lunes 5/09/2022 a las 10:00 h Ambas, como siempre, en Ronda del Carmen, nº 6, de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2022-08-23','Ana: Tras hablar con María, TS El Encinar de las Cruces (924 812 599 / 618 95 70 59 / mrivero@encinardelascruces.com), nos remite correo al ctutelar@: "el usuario CARLOS MARIA GRANDE VICARIO se traslada al centro residencial Ciudad Jardín en la localidad de Casar de Cáceres el 01/09/2022. Debido a su estado actual de nerviosismo y agitación precisa acompañamiento, estamos viendo la posibilidad de que alguien del personal de nuestro centro se ofrezca para dicho acompañamiento, pero nos gustaría saber si la Comisión Tutelar da el visto bueno y autoriza el siguiente presupuesto: - 30 € Tarifa acompañamiento - 30 € cuantía para financiar el transporte de regreso a Don Benito (a la ida el acompañante va en ambulancia pero el regreso debe costearselo la propia persona, bien en taxi, autobús, tren...) A la espera de vuestra respuesta. Gracias" ················ Desde la secc. ecca. les comunican que se acepta el presupuesto de acompañamiento. ································································································································································································ A petición de Pilar Cerrillo, TS de Grupo Ciudad Jardín, Casar de CC (calidad@grupociudadjardin.com) le remito mail: "- En cuanto a CARLOS MARÍA GRANDE VICARIO, es un expediente relativamente nuevo, el inventario se presentó en el Jdo. en enero de este año. En la Intranet nuestra no hay casi nada anotado. Hubo que abrirle cuenta bancaria y se le gestionó PNC en cuanto se pudo (son sus únicos ingresos. Anteriormente no percibía nada) y le hicieron el DNI, que tampoco lo tenía. Se contrató también desde aquí Seguro de Decesos con Caser Seguros, pues tampoco disponía de ninguno. Tiene reconocido un grado de Discapacidad del 85% (Trastorno Neurológico por Traumatismo Craneoencefálico y Limitación Funcional por fractura de cadera) y un grado III de Dependencia Según su sentencia se declara su “incapacidad total y absoluta para el gobierno de su persona y la administración de sus bienes” Tiene 38 años, es soltero y carece de red de apoyo familiar. Según el Informe Social que obra en nuestro inventario, estuvo ingresado en el Centro de Rehabilitación Neurológica Casa Verde de Mérida casi dos años. Tiene 6 hermanos que no quieren saber nada de él. Encamado, precisa supervisión, sujeción y cuidados sanitarios continuados. Espero que con esta información te sea suficiente. No obstante, creo que la TS del Encinar de la Cruces enviará informes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-23','Ana: Tras hablar con José Manuel y mantener las mismas demandas de la semana pasada, envío correo a Alberto, Jefe secc. ecca.: "En relación a José Manuel Romero Mediavilla, comentarte que comenzó a asistir al ECA (Equipo de Conductas Adictivas) y por indicación del Médico compró los parches para dejar de fumar (invirtiendo parte de su asignación en ellos en lugar de tabaco). A día de hoy dice que los parches no le hacen el efecto deseado y no es capaz de dejar de fumar, por lo que está algo más nervioso y está pidiendo tabaco por la calle. Ante la posibilidad de que pueda liar alguna o endeudarse con algún estanco o peor, te planteo la posibilidad de concederle un extra de 30 € para comprar algo de tabaco y que se lo administre de aquí a principios de mes que retire su asignación periódica." ······························································································································································································ Envío correo a Toni-Futuex: "En relación a JOSÉ MANUEL ROMERO MEDIAVILLA, lleva semanas preguntando por el nuevo presupuesto de farmacia para comprar el pegamento para la dentadura que solicitó Virgina antes de sus vacaciones. Cuando te sea posible, por favor, remítelo al ctutelar@salud-juntaex.es a la atención de la sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2022-08-23','Ana: Correo de Mª José, TS SSASB - (mjacosta@mancomunidadsierrasanpedro.com /927 668 147) al ctutelar@: "Buenos días, no he podido contactar por telefóno para hacer esta consulta que me urge: don Arturo José Rocha Merchán está tutelado y ocupa plaza residencial en la R.M de Santiago de Alcántara. Sus familiares con el consentimiento de don Arturo solicitan un traslado de residencia para estar más cerca de la familia. Mi consulta es si al estar tutelado esta solicitud de traslado de Residencia, la realiza la Comisión Tutelar o puede hacerse desde este Servicio (Servicio social de Atención Socal Básica)" ·················· Mi respuesta: "Buenas tardes Mª José, Hoy me ha sido imposible llamarte, mañana espero poder hacerlo. No obstante, te explico, mientras no se haya revisado su sentencia debería de firmarla, tanto él, expresando así su conformidad/deseo de traslado y por el representante legal (Presidente de la CTAEX). A posteriori puedes gestionarla desde ahí. Ante cualquier otra cuestión, este correo, desde el que te contesto, es el mío directo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-23','Ana: Llamada de Pilar Cerrillo (927 29 05 50 / 618 90 85 06): plantea la posibilidad del traslado de Martín a UME-CSS para el viernes 26. ····· Consultaré a la compañera de UME. ······ Ayer acudió a su cita en ESM-CC, la Psiquiatra corrobora la necesidad de ingreso en UME. *Me enviará el informe de la consulta. ············· Se encargará de solicitar ambulancia para el traslado, para la consulta de ayer se la pusieron. ································································································································································································· Llamo a Inés, TS sustituta de Estrella Durán, CSS-Plas (24146): me dice que nadie le ha dicho nada al respecto y que la UME está llena y que el Director, cree, que está de vacaciones. Consultará y me llamará mañana. ····················· *Hablo con Soraya, enviará un correo al Director de CSS, en pprio no debe haber problema en que ingrese el viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2022-08-24','Ana: Envío a Julio, Aux. CTAEX, para que dé REGISTRO DE SALIDA, oficio-solicitud de CDO. ACTUALIZADO DE P. ORFANDAD, y anoten esta dirección a efectos de notificaciones. ············································································································································································································································ Ana: Conversación con Mª José, TS SSASB - (927 668 147 / 691596071 / 626134446 = Nº Personal): Arturo ingresó vía Decreto en la Res. de Mayores. Valorado con Grado I de dependencia. Tanto él como sus familiares (sobrinos implicados, con los que existe buena relación, que le visitan con relativa frecuencia y salen con él a pasear y a tomar algo) solicitan el traslado a otro Centro Res. por acercamiento familiar, pues residen a 2 horas de distancia, motivo por el que no pueden visitarle con mayor frecuencia. ············· Mª José nos remitirá la semana que viene el escrito de solicitud de traslado firmado ya por Arturo, para que recabemos la firma del D. Gerente. Ella se encargará a posteriori de registrar la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-08-24','Ana: Óscar, secc. ecca., remite a la residencia los recibos bancarios de que se puede disponer (sólo pueden descargarse de los últimos 15 meses).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-24','Ana: Soraya Masa me confirma que Martín puede ingresar el viernes 26 en el CSS sin problema, se lo ha confirmado el Director del Centro. ··············· Se lo comunico a Pilar Cerrillo, TS de la Res. Casar de CC., quién a su vez me informa de que no le ponen ambulancia para el traslado. ······ Finalmente será su hermano quién le lleve en su coche. ······························· Nueva comunicación de Soraya, le han llamado del CSS; el viernes no habrá ningún psiquiatra en el centro y plantean la posibilidad de que ingrese mejor el lunes. ················ *Finalmente Pilar Cerrillo acuerda con el hermano que le acompañará el lunes. ································································································································································································ Envío correo a Inés, TS del CSS-Plas (inesm.romero@salud-juntaex.es): "Buenas tardes Inés, En relación a la conversación mantenida ayer, decirte que Soraya Masa, Jefa de Unidad de Programas Asistenciales, se puso en contacto con José Antonio Mesa y éste le ha confirmado el ingreso de D. MARTÍN DOMÍNGUEZ PALENCIA en vuestro centro. Dado que el próximo viernes días 26, no es viable por la falta de Psiquiatra, el traslado tendrá lugar el lunes día 29/09. ¿Podríais indicarme cuál sería el mejor horario para su llegada? Se lo diremos al hermano que es quién realizará el acompañamiento a Martín. Te envío la siguiente documentación: - DNI - Informe Social - Informe Médico - Auto de Internamiento Involuntario - Testimonio de sentencia de incapacitación y nombramiento - Testimonio de Aceptación del cargo Ante cualquier cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-08-24','Ana: Correo del CRR-CC (crr@grupociudadjardin.com) al ctutelar@: "Les escribo con motivo de comunicarles que en la tarde de ayer se produjo el ingreso en la UHB de Cáceres de la persona usuaria Esteve Pascual Ramos por desestabilización de su patología de base."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2022-08-24','Ana: Remito a Lola, TS de Plana Inclusión Cabeza del Buey, Autorización para el viaje a Benalmádena del 6-10 septiembre, firmada digitalmente por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2022-08-24','Ana: Remito por mail a Yolanda, TS del Hptal. Don Benito-Vva. (yolanda.sanchezcabal@salud-juntaex.es): Consentimiento Informado para Procedimientos con Anestesia debidamente firmado y sellado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-25','Buenas tardes, Amalia. Te informo que he acordado con el centro de Ávila que Mercedes probablemente va a ingresar el próximo martes día 30. Enviaremos al centro la comunicación al juzgado que ratificó el ingreso involuntario en la UHB y la resolución de este ingreso, tal y como nos ha informado el juzgado que debemos proceder. Estos enviarán al decanato de Ávila el traslado de la paciente y será el juzgado que corresponda allí el que lo ratificará. Estos días no trabajo por un problema familiar, pero consultaré el correo si quieres decirme algo. El lunes vuelvo. Un saludo. Juan José Marín Píriz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-25','Buenas tardes, Amalia. Te informo que he acordado con el centro de Ávila que Mercedes probablemente va a ingresar el próximo martes día 30. Enviaremos al centro la comunicación al juzgado que ratificó el ingreso involuntario en la UHB y la resolución de este ingreso, tal y como nos ha informado el juzgado que debemos proceder. Estos enviarán al decanato de Ávila el traslado de la paciente y será el juzgado que corresponda allí el que lo ratificará. Estos días no trabajo por un problema familiar, pero consultaré el correo si quieres decirme algo. El lunes vuelvo. Un saludo. Juan José Marín Píriz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-08-25','Buenas tardes Amalia, sí, increíble, yo se lo dije a Obdulia cuando se incorporó de las vacaciones, he intentado, tb ,ponerme en contacto con Estrella y con María Paz,de la UHDAC pero no me han cogido el telf. y la verdad, que no he seguido intentandolo. Pero sí, mañana bajo y le digo a Obdulia que haga el informe y lo envío. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-08-25','Ana: Correo de Pilar Cortijo, Residencia Santiago Apóstol - Navezuelas (pilarcortcer@gmail.com): "Buenos días, te envío la documentación a firmar para la operación de Juan José Hornero, le han dado fecha para el 31 de agosto por lo que me urge que me lo reenvíes firmado para enviarlo al hospital cuanto antes. Un saludo." ········································· Mi respuesta: "...Adjunto los Consentimientos Informados para las Anestesias así como para la Resección Transuretral de Vejiga, relativos a JUAN JOSÉ HORNERO RODRÍGUEZ, debidamente firmado y sellado por el Presidente de la de CTAEX."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2022-08-25','-Amalia : Derivada desde menores , la tecnico es Inmaculada ( tf 64571) email: inmaculada.zambrano@salud-juntaex.es . Está en Centro , CEE Los Angeles .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-16','Ana: Blanca, Directora del CRR-Plas (direccion.crrplasencia@grupo5.net) nos remite Informe de Incidencias desde el jueves 11 de agosto. Ha presentado alteraciones de conducta y heteroagresividad de forma continuada. "Los episodios tienen que ver con dificultades de gestión emocional ante situaciones de diferente forma (relaciones personales, demandas médicas, demandas económicas…), agravándose por el gran consumo de bebidas energéticas que está realizando"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-25','Ana: Tras leer correo de Blanca, Directora del CRR-Plas (direccion.crrplasencia@grupo5.net): "Buenas Ana, necesito hablar contigo sobre Julia, esta noche ha vuelto a tener una situación complicado y estoy valorando una expulsión hasta el lunes, llámame cuando puedas.", la llamo: se determina la expulsión temporal de Julia como medida terapéutica desde hoy hasta el domingo (3 noches). Puesto que a su casa, la madre se niega a que vuelva, buscaremos alojamiento en Plasencia. ········································································································································································································ Llamo a la Despensa de Extremadura (Pilar: 927421719), reservo 3 noches en régimen de Pensión completa: 48€/noche. *Envían factura proforma. ··········· *Se lo comunico a Alberto, Jefe Secc. Ecca. *Se acepta, enviar luego la factura con número de cuenta bancaria. ··········································································································································································································· Envío correo a Toni-Futuex: "En relación a JULIA MORÓN HERNÁNDEZ, y las recientes y sucesivas alteraciones de conducta en el CRR, se ha tomado, como medida terapéutica, la decisión de expulsarla durante 3 días del centro, desde hoy, día 25, al domingo día 28. Hemos reservado alojamiento en régimen de pensión completa en La despensa de Extremadura. Puesto que durante la expulsión no puede tener contacto con el centro, os pedimos que estéis pendiente mañana, si no es posible visita, al menos mediante llamada de teléfono, para que sienta el apoyo que se le brinda desde los distintos recursos. Yo voy a llamarla ahora, pues considero, que desde todas las partes debemos transmitirle el mismo discurso: No puede seguir manteniendo este tipo de conductas que no le benefician en absoluto, ni a ella ni a nadie, no puede volver a su casa, su madre no quiere tenerla allí, y no tiene más opciones de centro ni ningún sitio donde ir. Si continúa así la expulsión será definitiva y no contamos con más opciones. De hecho entiendo que la única opción que le quedaría sería en el C. Sociosanitario, dónde ella no quiere ir. (*Para UHDAC, en principio, no da perfil…)" ··································································································································································································· Recibo, y guardo en el expdte. digital, informe del CRR con las últimas incidencias y la expulsión temporal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-25','Ana: Envío correo a Pilar Cerrillo (calidad@grupociudadjardin.com): "Buenos días Pilar, Me confirma Inés, compañera del C. Sociosanitario, que la mejor hora para el ingreso de Martín el próximo lunes es sobre las 11 - 11.30 de la mañana. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-08-25','Ana: Correo de Inés, TS CSS-Plas (inesm.romero@salud-juntaex.es): "Por otro lado, YOLANDA CALDERA ya tiene su ortoprótesis. Son 90 euros. El lunes recogeremos en la farmacia tanto el presupuesto como la factura y la pagaremos desde aquí. Luego, cuando ya esté pagado te lo mando todo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2022-08-24','Amalia : Buenas , está en CSS Mérida, el Plan de intervención inicial lo hace Tere . Me llamaron ayer del centro , es urgente cambiar cuando se pueda los titulares de la cuenta. Aparece con su padre y éste es consumidor de drogas . Contratada la información con TS del SSASB de Calzadilla. Un saludo. ------------------------------------------------------- Abierta cuenta , pendiente cambio pensión .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2022-08-24','Amalia : Buenas , está en CSS Mérida, el Plan de intervención inicial lo hace Tere . Me llamaron ayer del centro , es urgente cambiar cuando se pueda los titulares de la cuenta. Aparece con su padre y éste es consumidor de drogas . Contratada la información con TS del SSASB de Calzadilla. Un saludo. ------------------------------------------------------- Abierta cuenta , pendiente cambio pensión .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2022-08-25','-Amalia : datos básicos del caso : Regina y su hermano nacieron en Badajoz , ella hace 18 años . Padres con EMG y problemas de adicción, sin capacidad para atenderlos . Se encarga de cuidarlos una tía paterna y el marido de ésta con los que se van a vivir . Desde menores se procede a dar VºBº para acogimiento familiar permanente que cesa en 2020 por problemas en el ámbito familiar de acogida : fallecimiento de su tío , su primo entra en prisión por V.G. , los hijos de éste pasan a convivir en el mismo domicilio ... Regina estudia en el CEE Los Ángeles en Badajoz y se queda en la residencia del colegio de lunes a viernes . Los fines de semana tiene plaza de menores gestionada por HOFA en un piso sito en C/ Rota , 41 , de Badajoz ( zona Mª Auxiliadora ) .Coordinadora de HOFA , Manoli Gordillo ( 669504520- inmaculada.zambrano@salud-juntaex.es )quedo pendiente concertar entrevista con ella . Inma , TS del S.T. Menores de la D.G.SS.SS ,I y F , ya les ha notificado que Regina pasa a la CTAEX para que contacten con nosotros . Me pregunta si tiene que seguir en la plaza del piso , le indico que por el momento y hasta los 21 años que puede permaner en el CEE, es lo más conveniente para ella . Los informes del colegio son buenos y si pedimos una plaza de discapacidad supondría salir de ese colegio dado que no hay plazas en Badajoz. Tengo que preguntar si hay que abonar algo por esa plaza . En verano va a un campamento gestionado por menores . No tiene ninguna prestación , quedo pendiente que se abra cuenta y solicitaré PNC Invalidez. Diagnosticado 65% G.D. por retraso mental ligero con alteraciones de conducta. Se le hace seguimiento en ESM . No tiene seguro decesos, en cuanto tengamos el primer pago de la pensión se tiene que contratar uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2022-08-25','-Amalia ; datos básicos del caso : Regina y su hermano nacieron en Badajoz , ella hace 18 años . Padres con EMG y problemas de adicción, sin capacidad para atenderlos . Se encarga de cuidarlos una tía paterna y el marido de ésta con los que se van a vivir . Desde menores se procede a dar VºBº para acogimiento familiar permanente que cesa en 2020 por problemas en el ámbito familiar de acogida : fallecimiento de su tío , su primo entra en prisión por V.Género. , los hijos de éste pasan a convivir en el mismo domicilio ... Regina estudia en el CEE Los Ángeles en Badajoz y se queda en la residencia del colegio de lunes a viernes . Los fines de semana tiene plaza de menores gestionada por HOFA en un piso sito en C/ Rota , 41 , de Badajoz ( zona Mª Auxiliadora ) .Coordinadora de HOFA , Manoli Gordillo ( 669504520- inmaculada.zambrano@salud-juntaex.es )quedo pendiente concertar entrevista con ella . Inma , TS del S.T. Menores de la D.G.SS.SS ,I y F , ya les ha notificado que Regina pasa a la CTAEX para que contacten con nosotros . Me pregunta si tiene que seguir en la plaza del piso , le indico que por el momento y hasta los 21 años que puede permanecer en el CEE, es lo más conveniente para ella . Los informes del colegio son buenos y si pedimos una plaza de discapacidad supondría salir de ese colegio dado que no hay plazas en Badajoz. Tengo que preguntar si hay que abonar algo por esa plaza . En verano va a un campamento gestionado por menores . No tiene ninguna prestación , quedo pendiente que se abra cuenta y solicitaré PNC Invalidez. Diagnosticado 65% G.D. por retraso mental ligero con alteraciones de conducta. Se le hace seguimiento en ESM . No tiene seguro decesos, en cuanto tengamos el primer pago de la pensión se tiene que contratar uno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-08-25','Amalia : -le envío a la técnico PIA toda la documentación por email y se la entrego a Julio para que la registre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2022-08-25','Amalia ; entrego a Julio para que registre a PNC un cambio de variaciones , con el último contrato que me han enviado. Ese contrato ya firmado se le registra a P.I. Montijo para que lo tengan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='FERNANDEZ'and apellido2='RAMOS'),'2022-08-25','Amalia : Datos básicos del caso. Ingresada desde 1984 en CSS de Mérida . En la sentencia de tutela aparece como tutor el antiguo Dtor. del CSS , se ha solicitado desde el mismo la remoción para que pase a la CTAEX . Dignosticada con 57% G.D. sin revisión y Grado III.2 dependencia. Tiene póliza de seguro de decesos con Mapfre. Percibe P. Orf. Absoluta de 767€ mensual. Con más de 40000€ ahorrados. Comprobar titulares de la cuenta , se lo pido a la sección eco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='GATO'and apellido2='LOZANO'),'2022-08-25','Amalia : el CSS de Mérida informa : Os informo de que Rafael Gato Lozano ha sido ingresado en la planta de medicina interna. Se le va a contratar acompañamiento a través de una empresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-08-26','Ana: Reenvío a Alberto correo con Presupuesto para compra de móvil para Ceferino, con el OK de la secc. social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-26','Ana: Llamo a Julia, Casa Misericordia Alcuéscar (927 12 00 24): Programamos el ingreso de Doroteo el miércoles día 31, entre las 10:30 y las 11:00 h. ······· En cuanto a las citas programadas, el día 2 acudirá a la de Psiquiatría, ESM y si la del día 5, Enfermería, es sólo para el inyectable, se le administrará en Alcuéscar. ······························································································································································································· Solicito a Toni-Futuex, acompañamiento a Doroteo el día del ingreso y a la cita de ESM (V. 02/09), así como la gestión de los medios de transporte oportunos. ······································ Gestiono con el Albergue Las Veletas la ampliación de la estancia de Doroteo con salida el miércoles 31. ··············································· Comunico tanto a Doroteo como a su hermana Carmen, el ingreso en la Casa de la Misericordia el miércoles 31.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-25','Ana: Llamada de Doroteo (609 928 621), plantea quedarse los próximos días a dormir con su madre, me pasa con su madre, Carmen, que dice que si es temporal no le importa que se queda allí. Les recuerdo a los dos que el piso es su hermana y ésta no quiere que Doroteo vuelva. ··· Acordamos que hablaré con ella. ···················································································· Llamo a Carmen, hermana de Doroteo (669 864 167): ella se niega a que Doroteo vuelva a pernoctar en su piso con su madre. *Se lo comunico a Doroteo, que ha de volver al Albergue hasta que pueda ingresar en el Centro de Alcuéscar. *Aunque se muestra molesto con su hermana lo acepta. ································································································································································································· Soraya Masa, Jefa Ud. PP.AA., me comunica que le han confirmado que la semana que viene, Doroteo podrá ingresar en la Casa de la Misericordia de Alcuéscar. ······ Llamaré mañana para organizarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-26','Ana: Envío a Alberto, Jefe Secc. Ecca y los Asesores Jurídicos, con copia a Maite y Óscar, las notas simples de las viviendas propiedades de Martín, que nos remite su hermano Jesús (gjdpalencia@gmail.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2022-08-18','Ana: Correo de Toni-Futuex: Sandra ya ha formalizado la matrícula en la UEX. *Ha realizado también la orden de domiciliación bancaria. ··· Adjunta documentos que reenvío a la sección ecca. (Orden de domiciliación bancaria y matrícula, como justificantes).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-08-23','Ana: correo de Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net): "Buenas Ana, os comento sobre Isabel Cano, hemos mandado un informe a fiscalía informando del posible no cumplimiento de la orden de alejamiento que Jesús (pareja de la madre de Isabel) tiene respecto a Isabel. Una educadora les vio por la calle, contactamos con la policía los cuales nos recomendaron que si vuelve a pasar avisamos al 091 para en ese momento poder actuar ya que de otro modo es la palabra de una persona contra la otra. De todas formas y ante las posibles consecuencias que pudiera tener para Isabel, hemos decidido informar. Isabel no reconoce que él este presente en las visitas. Me comenta Isabel que quieres hablar con nosotras, cuando puedas hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-26','Ana: Blanca me comunica que cree que Julia se marchó por la noche del Hotel y se fue a casa de sus padres a Cilleros. ···························· *Llamada del Hotel la Despensa de Extremadura, comunica que Julia pasó la tarde bien en el hotel, ceno y se subió a la habitación, hasta que entre las 00:30 y la 01:00 h Julia salió con su maleta y sus cosas diciendo cosas raras y se marchó en taxi. ··················································································· Correo de Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "S, efectivamente Julia está en Cilleros. Acabada de llamarnos si madre. Anoche llego a su casa tranquila y su madre permitió que entrara. Hablo con su madre, hoy mucho más accesible y capaz de entender la situación. A la cita con psiquiatra no acudirá, ya que no ha podido montar en el autobús por no llevar mascarilla. Creo que tenemos que pensar entre todas las personas implicadas en el caso una alternativa a esta situación, ya que es complicado que Julia sea capaz de manejarse en un recurso como el nuestro. En principio por autobuses no sabemos si volverá el domingo o el lunes. Al final la consecuencia de expulsión no va a ser tal, al haberse ido a su casa y su madre haber aceptado. Por nuestra parte cuando llame la daremos el.mensaje que cuando vuelva la atenderemos. Viene Gloria, Futuex al centro, hacemos coordinación sobre Julia, evolución y posibilidades. Durante la reunión recibe varias llamadas de Julia con versiones no ajustadas." ····································································································································································································· Llamo a Julia, nada más saludarle y preguntarle cómo está, responde que está en Cilleros, que ella no quiere ir a ningún hotel, que su madre va a poner una queja y que no quiere hablar más que se va a poner nerviosa. Cuelga sin dejarme hablar nada más. ································································································································································································· *Desde Futuex confirman que Julia está en Cilleros, la MAP, no ha querido colaborar para activar el 112. En teoría luego cogerá el bus para acudir a la cita en el ESM-Plas. ··············· Nuevo correo de Toni - Futuex: "Según ella, ha ido a coger el bus y al no tener mascarilla no le han dejado subirse (supuestamente ha ido a coger el bus para ir a la cita a Plasencia) Según ella, que si que el lunes por la mañana, regresa, porque el domingo no hay bus.. se ha intenado reflexionar con ella sobre lo que ha pasado, aunque ahora mismo está un poco reticente a esa reflexión y vuelca toda la responsabilidad en el centro, la madre también le refuerza está conducta... pero bueno como ha pasado siempre se retroalimentan porque es un vinculo de convivencia algo tóxico." ·························','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-08-29','Ana: Llamada de Teresa, Novaforma (662 337 460): Felipe ha acudido al banco a retirar dinero sin autorización. Ha pedido 180€. En el banco le han dicho que no pueden dárselo sin dicho documento y se ha enfadado. *Volverá el lunes. *A petición de Teresa, Novaforma, Lourdes, secc. ecca, reenvía la autorización habitual al banco recordando que mientras no remitan otra autorización de extra no deben darle más dinero, por mucho que él acuda e insista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-08-23','Ana: Correo de Toni-Futuex: "Hola, para primeros de septiembre se va ir para allá, para acompañar a Desideria Barbero, a retirar el dinero y se pretenderá hacer está gestión. Nos prondemos lo primero a intentar localizar a la ts de refencia de Jairo, que aveces es muuuuy complicado, como hemos comentado en alguna ocasión, ya que si vamos sin previa cita, pues no nos dejan ni acceder a ver a los usuarios de alli. Y podriamos quedar con el, en el centro de empleo de plasencia, si lo ven bien y le autorizan la salida desde alli. Asique ya te iria comentado que tal la gestión con el, en cuanto se pueda hacer"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-29','Ana: Correo de Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net), del sábado: "Buenas, os envío informe sobre las incidencias de Julia Morón. Como directora del recurso decido la ampliación de la expulsión temporal del CRR hasta el lunes 29 de agosto con el fin de salvaguardar a las personas y profesionales del CRR, ante las múltiples incidencias protagonizadas por Julia durante su expulsión temporal." ··················· Guardo el informe en el expdte. digital. ······················ Llamo a Blanca, Directora CRR (673 22 55 27): Al parecer Julia ha estado pernoctando en el Hostal la Muralla, Plas. No saben si ha pagado. *Su madre le dio dinero para comer, pero los primeros días se lo ha gastado en invitar a cervezas a Ceferino y a Isabel. ········· Debe dinero a taxistas de Plasencia, pero no tenemos las facturas. *Si éstos se ponen en contacto con el centro les remitirán a la CTAEX. ············ Todo lo que haya que abonar, se le "retrotraerá" a Julia del as futuras asignaciones mensuales. ····································································································································································································· Nuevo correo de Blanca, con copia a Eva, Mariluz y Raquel, Secc. Acceso a RR. Salud Mental: "Julia, acude al recurso, se mantiene por los alrededores con comentarios sobre la expulsión, las supuestas amenazas que ha recibido, quejas sobre las profesionales y dirección...etc. Ahora creemos que ha bajado al hostal a por sus cosas ya que no se encuentra en el centro. Ante cualquier circunstancia activaremos 112 con presencia policial. Actualmente no tiene dinero ni tabaco (el sábado cuando vino lo solicitó todo) siendo esta circunstancia generadora de conflictos. Permanecer en el CRR en la actualidad es un riesgo para ella y para el recurso. La medida de expulsión temporal no ha sido efectiva y por nuestro recurso abierto no estamos en condiciones en fijar unos mínimos de cumplimiento de horarios y conductas de respeto ya que la persona tiene que querer. Necesitamos que entre los recursos implicados pongamos una solución, ya que la permanencia en el CRR es complicada." ······························································ *Se lo reenvío a Soraya Masa, Jefa UD., adjuntando los 3 informes de incidencias de este mes. ·············· Llamo a Eva, Psicóloga: hablará con Soraya Masa también. ······························ Acuerdo con Eva y Soraya: Eva llamará a Blanca para indicarle que si es necesario, esta tarde activen el protocolo y si la llevan al hospital que avise a Soraya al WhatsApp corporativo para tratar de mediar para un ingreso en UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-08-25','Ana: Soraya Masa, Jefa UD. PP.AA., me comunica que en la Casa de la Misericordia podrían aceptar el ingreso de Pablo, pero éste tiene que ser realmente voluntario, es importante que Pablo quiera ingresar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-08-26','Ana: Llamo a Julia, Casa de la Misericordia de Alcuéscar (927 12 00 24): Aunque creen que es un caso muy complicado aceptan intentar el ingreso de Pablo, pero sólo sí él está convencido y dispuesto a ingresar. Expresa que actualmente la casa está funcionando muy bien, hay muy buen ambiente, armonía, unión y concordancia y temen que el ingreso de Pablo altere a los demás residentes y la convivencia. ················· *Puesto que también se acepta el ingreso de otra persona a cargo de la CTAEX, se plantean que sean escalonados los mismos, y como hay que abordar bien con Pablo la aceptación, no se procederá al ingreso de éste hasta la semana siguiente, para que desde Futuex puedan trabajarlo bien con él y apoyar en el proceso cuando tenga lugar el ingreso, así como en la adaptación al recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-08-29','Ana: Envío correo a Toni-Futuex, con copia a Teresa y Maite, CTAEX: "En relación a Pablo Galán Gilgado, comunicaros que se ha aceptado el ingreso en la Casa de la Misericordia, pero sólo con la condición de que Pablo acepte este ingreso de manera convencida, entendiendo qué implica esta decisión y aceptando la normas de convivencia del recurso. El ingreso se plantea para la semana del 5 de septiembre, pero la fecha ya la cerrará Teresa con Julia, coordinadora del recurso, cuando esté de vuelta. *Os pedimos que en esta semana y pico que media hasta el ingreso, trabajéis en profundidad con él la idea del ingreso en dicho recurso para que pueda ingresar de forma voluntaria y lo más consciente posible y que hagáis el apoyo tanto para el traslado e ingreso, como en el proceso de adaptación, intensificando, a ser posible, las visitas durante las primeras semanas. Ya nos decís cómo va Pablo esta semana y qué dice al respecto de su traslado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-08-29','Ana: Tras hablar con José Manuel, con Rosa, Auxiliar de SAD, y después con Paqui, Coordinadora del SAD-Eulen (629 557 324), envío correo a Óscar, Secc. Ecca.: "Buenas Óscar, En relación a José Manuel Romero Mediavilla, he recibido llamada de su Auxiliar de Ayuda a Domicilio, dado el estado de suciedad de la vivienda, necesitan más productos de limpieza (lejía, quita grasa, estropajos, bayetas…) y calcula que será aproximadamente 20 €. He hablado con Paqui, coordinadora del SAD, y autoriza que la Auxiliar le acompañe el miércoles al banco a retirarlo y a comprar los productos. Así pues necesitaríamos la autorización para este miércoles día 31 en la oficina habitual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-08-29','Ana: Llamada de Modesto, Res. (673 315 439): en relación a la no propuesta de plaza pública para Juan, me explica que Juan ha expresado en varias ocasiones, que él no se quiere mover de la residencia en la que está. Así pues, como puede permitírselo, se cumple este deseo. ·················· *En cuanto a las visitas a su pueblo, se podría volver a organizar una para mediados-finales de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-08-29','Ana: Conversación mantenida con Blanca, Directora CRR (673 225 527): el sábado, Julia Morón invitó a Isabel y a Ceferino a tomar cervezas. Isabel llegó al centro ebria y tuvieron que llamar al 112, acudió la ambulancia y la asistieron allí, pero no hizo falta llevarla al hptal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-08-29','Ana: Llamo a Yéssica, TS Cáritas (927 422 406 - 645.887.203): Está de vacaciones, se incorpora el jueves día 1. ···························· Llamo a Ángel Félix (643 622 174): sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-29','Ana: Envío correo a Alberto: "En relación a DOROTEO DÍAS CERRO, si no surge nada raro, ingresará el próximo miércoles día 31 de agosto en el Centro de la Casa de la Misericordia de Alcuéscar. Ya le confirmé a Óscar que hay que dar de baja la transferencia periódica a la madre en concepto de manutención. *En cuanto al abono del centro, Julia, coordinadora, en base a la pensión que percibe Doroteo, solicita que sean unos 600€, a mí a priori no me parece mal, pero le dije que lo vería contigo Alberto, pues hay que tener en cuenta el resto de gastos, como por ejemplo seguro de decesos, ropa, gastos de bolsillo que habría que reajustar… Cuando quieras lo vemos. Ya le dije que ahorrado tienen muy poco y ahora había que abonar Albergue y los taxis que va a necesitar para un par de traslados. Cuando quieras lo vemos también. *Pongo en copia a Julio, para que a partir del miércoles haga el cambio de domicilio en la base de datos." ······································································································································································································· Respuesta de Alberto, Jefe secc. ecca: "ANA: TIENE INGRESOS DE 721,70 €/MES Y SI COSTE CENTRO 600 €/MES (ENTIENDO QUE 12 ÚNICAS MENSUALIDADES), EL MÁXIMO REINTEGRO PODRÍA SER DE 30 €/SEMANA (130 €/MES), LO CUAL SUPONE AHORRO DE 1.100 €/AÑO (ROPA, VACACIONES, IMPREVISTOS, AHORRO...). ANA: HABLA CON CENTRO Y QUE VEAN SI ES ACEPTABLE. X CIERTO...NO SE SI TENDRÁ OTROS GASTOS DE PODOLOGÍA, PELUQUERÍA, FARMACIA..., EN CUYO CASO HABRÍA QUE REVISAR A LA BAJA EL REINTEGRO." ················· El miércoles, día del ingreso, lo hablaré con Julia, Casa Misericordia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-29','Ana: Llamo a Inés, TS CSS-Plas.: El ingreso se ha producido bien, sin incidencias, a priori Martín parece motivado y quiere cuidarse y estar bien. Me irán informando acerca de su evolución. ········································· Envío correo a Alberto y Julio, con copia a Maite y Óscar: "Comunicaros que esta misma mañana se ha producido el ingreso de Martín Domínguez Palencia en el Centro Sociosanitario de Plasencia. Aquí, de momento no tiene que abonar plaza, lo cuál se vendrá muy bien para empezar a sanear sus cuentas. Julio, porfa, cuando puedas, ya sabes, otro cambio para la base."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-08-29','Ana: Llamada de Mirella y Aitor (696 132 077): Mirella es quien dirige la conversación, dice no han estado abriendo la puerta durante las últimas veces porque han estado muy liados yendo a Cáceres y Badajoz. Dice que Aitor está cansado de recibir sólo 50€/semana para comida y que a ella su padre sólo le da 90€/mes. *Aitor no se quiere ir al centro y piden el dinero para irse a vivir de alquiler, pues dice que esa casa es de Felisi, no de ellos, a esto último les doy la razón. Mirella sigue hablando: "Él sólo quiere disfrutar todo lo que no ha podido disfrutar de aquí para atrás por haber estado en centros, quiere libertad". También dice que ha dejado de consumir y está dispuesto a acudir al "CEDEX" a hacerse controles. "Sólo ha bebido y fumado porros en la fiestas" dice. ····· Añade que hoy han limpiado en casa y que van a dejar que les visiten la educadoras y que les acompañen a hacer la compra. ······ Piden que se deje de pagar la plaza del centro y les explico que hasta que no tengamos respuesta del Juzgado, eso no lo podemos hacer. ······· También que se les aumente la cuantía autorizada, a lo que respondo que mientras no haya informes positivos del CEDEX y de las educadoras, no se va a aumentar y en cualquier caso la última palabra la tiene Alberto. ··· Indico que informaré de todo a Teresa, que aún es la TS de referencia. ··································································································································································································· Llamo a Raquel - Programa de Familia Mancomunidad Tajo-Salor (659 926 956): ha estado esta mañana con la policía local en la vivienda, al parecer está aún peor, totalmente insalubre. Además tienen unas 8-10 bolsas de basura allí acumuladas sin tirar al contenedor. *Raquel le ha dicho que mientras que no limpien la casa no les van a acompañar a comprar comida, de hecho hoy no han ido. Mañana volverán a ver qué tal (Como realmente suelen acudir los miércoles a comprar pueden aguantar estos dos días). *La policía local va a elaborar un informe que nos remitirán mañana mismos para que podamos enviarlo también al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-08-29','Ana: Llamo a Raquel - Programa de Familia Mancomunidad Tajo-Salor (659 926 956): A día de hoy desconoce el paradero de Miguel Ángel. ······· Les han comentado que regresó a Aliseda, pero como tiene una orden de alejamiento de la Madre, la policía intervino y se marchó. Ahora no saben dónde está. Intentará averiguar algo y me informará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-08-30','Ana: Correo de ayer por la tarde de Blanca, Directora del CRR: "Buenas os mandamos el informe de Julia de ayer en UHB para que veáis cómo con los servicios sanitarios es capaz de tener control con la intención de evitar ingreso. Ella acude de manera voluntaria en ese momento se encontraba en expulsión temporal." ·············· Guardo informe de Alta en el expdte. digital. *Julia acude voluntariamente a urgencias, pero luego no quiere ingresar en UHB. ···································································································································································································· Nuevo correo de Blanca: "Buenos días, esta noche Julia la ha pasado tranquila. Ayer tuvimos atención con ella explicándole su situación actual y la responsabilidad de sus acciones. Seguiremos trabajando con Julia, pero creo que dabas sus necesidades el CRR no es un recurso ajustado para ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-08-29','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Aaron Rosado Alarcónbestá ingresado en Salud Mental en Cáceres desde el viernes por la noche. La última semana se notaba un cambio en su comportamiento y finalmente presentó conductas agresivas hacia profesionales y fue necesario llamar al Centro de Salud. Una de sus tías nos pidió que le informáramos cuando surgieran temas de salud porque ella trabaja en el Hospital y puede ir a visitarle. Hemos pensado en informarle y pedirle que cuando vaya no le lleve regalos como, por lo visto ha hecho en alguna ocasión, porque si relaciona comportamiento agresivo ingreso en Cáceres y recompensas o regalos, creemos que los ingresos pueden aumentar como nos ocurrió con otra persona. También quería comentarte que voy a mandar documentación relativa al programa de apoyo a personas con discapacidad en el contexto comunitario en el que participa Felisa Bruno. Se trata del contrato familiar que tiene que ser firmado tanto por los tutores"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-08-29','Ana: Correo de Toni-Futuex: "Desde el programa de apoyo social comunitario se realiza nota para informar que el 27 de agosto de 2022 (sábado), recibimos una llamada desde el Hospital Virgen del Puerto de Plasencia. En la misma nos indica el médico de urgencias que Desideria se encuentra en el hospital con un cuadro de disartria, no saben si provocado por la medicación o por un problema isquémico. Nos dicen que el motivo de la llamada es debido a que Desideria quiere el alta voluntaria, solicitando el médico que se autorice el ingreso involuntario para poder realzarle pruebas, al ser fin de semana lo solicitará al juez de guardia. A los minutos recibimos otra llamada, que Desideria se ha escapado del hospital, el médico nuevamente nos dice que el juez está informado de toda la situación. ..." Su pareja, Ángel, también parece descompensado. ···· Guardo nota en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-08-29','Ana: Toni-Futuex, confirma que visitarán a Jairo y le acompañarán al SEXPE el día 1/09. En el CSS ya están informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-30','Ana: Toni-Futuex, informa en mail con varios asuntos: "...A Doroteo, no le hemos visto todavia para poderle decir que el taxi, va ir a buscarlo el miercoles a las 9.30.. es que no damos con el, y el telefono no lo coge, mañana si no está en el hotel, iremos a la casaa de la madre...y a ver que pasa el mirercoles, ojala y todo bien!" ································ *Comunico a Toni que intentaré comunicar yo hoy a Doroteo a la hora que le recogerá el taxi. ·················· Ana: Llamo a Doroteo (609 928 621), me comunica que ya ha estado con Gloria, Futuex (porque Virginia está de vacaciones) y se lo ha comunicado. Dice que tienen su maleta y sus cosas preparadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-08-29','Ana: Recibimos documento del INSS (Dirección Provincial de CC), para la elección de la PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2022-08-08','TERESA RECIBO CORREO DE MARISA LA TS DE SAAB DE VILLAFRANCA INDICANDOME QUE LE HAN LLAMADO DESDE VIVIENDA QUE VAN A VACIAR LA CASA PORQUE TIENEN QUE HACER REFORMA MARISA MUESTRA INTERES POR SALVAR ALGUNOS ENSERES PARA EL MUSEO ETNOGRAFICO DE VILLAFRANCA SE ELABORA UN DOCUEMENTO EL CUAL FIRMA MARIA EN EL QUE DONA TODOS SUS ENSERES AL AYUNTAMIENTO DE VILLAFRANCA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2022-08-30','TERESA envío el número de cuenta bancaria de Guadalupe Blandón, la madre de Cristian Carrasco de Monesterio. Se le ha trasladado la información sobre la transferencia periódica que se le hará con 100€ para la manutención de su hijo y se ha alegrado mucho. Ha comentado que su hijo está pasando las vacaciones de verano con sus primos en Hinojal, en casa de su abuela paterna. Volverá en Septiembre y en esa fecha se podrían comenzar las retiradas quincenales de 75€. La retirada de 75€ a la quincena se considera apropiada para Cristian ya que no tiene gastos muy excesivos, además es bueno que se vaya acostumbrando a administrar su dinero y a ir generando ahorros, sobre todo por la deuda que tiene acumulada. Probablemente en las primeras retiradas del banco le acompañe su madre, ella se ha ofrecido voluntaria de muy buen grado, pero lo ideal es que cuando él lleve un tiempo yendo al banco, lo haga solo. Ya que se cree que es muy importante que empiece a adquirir ciertas responsabilidades sobre su vida y sus actividades cotidianas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-30','-Email del Dtror del CRR : Tras informarme Juanjo (TS) de la decisión de Mercedes de no acudir al CRR para la entrevista. Según me cuenta se muestra muy contraria a cualquier posibilidad que no sea residir en su domicilio, le propongo poder hablar yo directamente con ella, aunque valora que no es un momento adecuado. Por lo que a pesar de que le den el alta de la UHB entiendo que sería conveniente seguir manteniendo la opción de ingreso en el CRR, por lo que para cualquier cosa estamos en contacto. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-30','-Email del Dtror del CRR : Tras informarme Juanjo (TS) de la decisión de Mercedes de no acudir al CRR para la entrevista. Según me cuenta se muestra muy contraria a cualquier posibilidad que no sea residir en su domicilio, le propongo poder hablar yo directamente con ella, aunque valora que no es un momento adecuado. Por lo que a pesar de que le den el alta de la UHB entiendo que sería conveniente seguir manteniendo la opción de ingreso en el CRR, por lo que para cualquier cosa estamos en contacto. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-08-30','Buenos días, Amalia. Te informo que al final Mercedes se ha echado para atrás en lo que respecta al centro de Mérida. Rechaza ingresar en él, incluso a visitarlo. No ha habido manera. Reclama un centro "que se adecue a sus necesidades". Hemos descartado por tanto trasladarla al CRR de Mérida y hemos decidido hacerlo de forma involuntaria a Ávila, al centro que habíais propuesto, dado que la paciente no acepta irse de forma voluntaria, y la impresión es que da igual lo que le ofrezcamos, que lo va a rechazar. Sigue sin aceptar que no está bien. A finales de semana, el viernes como mucho, tenemos previsto darle el alta y trasladarla a Ávila. El jueves viene el Dr. Zamora, que está estos días de vacaciones y procederemos al traslado de forma involuntaria. Estaremos en contacto. Un saludo Juan José Marín Píriz Trabajador Social del Hospital Universitario de Badajoz juanjose.marin@salud-juntaex.es Ext.: 48330','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-30','Ana: Ante la consulta de Inés, TS del CSS-Plas (inesm.romero@salud-juntaex.es), respondo: "Según nuestra base de datos, fue valorado en 2013 y dio SIN GRADO. Pero este año ha solicitado REVISIÓN y aunque al menos a nosotros no nos han remitido la RESOLCIÓN, hemos podido comprobar en SIDEX que hay una nueva resolución de fecha 22/07/22 en la que se le ha valorado con GRADO II. Puesto que, todavía, es una Curatela económica, podríais hacer desde ahí la comunicación del cambio de domicilio para la negociación del PIA. El documento tendrá que firmarlo él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-30','Ana: Ante la consulta de Inés, TS del CSS-Plas (inesm.romero@salud-juntaex.es), respondo: "Según nuestra base de datos, fue valorado en 2013 y dio SIN GRADO. Pero este año ha solicitado REVISIÓN y aunque al menos a nosotros no nos han remitido la RESOLCIÓN, hemos podido comprobar en SIDEX que hay una nueva resolución de fecha 22/07/22 en la que se le ha valorado con GRADO II. Puesto que, todavía, es una Curatela económica, podríais hacer desde ahí la comunicación del cambio de domicilio para la negociación del PIA. El documento tendrá que firmarlo él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-08-30','Buenos días Rosa , te estoy llamando , no consigo contactar . Desgraciadamente la Comisión Tutelar de Adultos no tiene ningún recurso propio , y el acceso a los que existen es en igualdad de condiciones que el resto de usuarios , no tienen preferencia . Eduardo tiene establecida medidas de apoyo , de supervisión en la esfera económica y de salud , supeditadas a su voluntad , deseo y preferencias conforme a la nueva ley 8/ 2021 de 2 de junio , que reforma el procedimiento civil y procesal para el apoyo a personas con discapacidad . En momentos de descompensación las medidas de apoyo son de carácter representativas . Las alternativas residenciales que habéis propuesto son las más apropiadas , el Centro Padre Cristóbal podría acogerlo , o pagar una habitación en un hostal . Como recurso residencial adecuado a su patología mental podría solicitar plaza en Centro Residencial de Rehabilitación , derivado desde su Equipo de Salud Mental , pero se exige su voluntariedad en el acceso y actualmente no lo acepta. Se le están haciendo visitas , intentando ganar su confianza y que acepte la ayuda . Quería consultaros si alguna vez ha solicitado vivienda de promoción Pública . si es lo que demanda tiene que solicitarla en Vivienda . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-08-30','Buenos días Rosa , te estoy llamando , no consigo contactar . Desgraciadamente la Comisión Tutelar de Adultos no tiene ningún recurso propio , y el acceso a los que existen es en igualdad de condiciones que el resto de usuarios , no tienen preferencia . Eduardo tiene establecida medidas de apoyo , de supervisión en la esfera económica y de salud , supeditadas a su voluntad , deseo y preferencias conforme a la nueva ley 8/ 2021 de 2 de junio , que reforma el procedimiento civil y procesal para el apoyo a personas con discapacidad . En momentos de descompensación las medidas de apoyo son de carácter representativas . Las alternativas residenciales que habéis propuesto son las más apropiadas , el Centro Padre Cristóbal podría acogerlo , o pagar una habitación en un hostal . Como recurso residencial adecuado a su patología mental podría solicitar plaza en Centro Residencial de Rehabilitación , derivado desde su Equipo de Salud Mental , pero se exige su voluntariedad en el acceso y actualmente no lo acepta. Se le están haciendo visitas , intentando ganar su confianza y que acepte la ayuda . Quería consultaros si alguna vez ha solicitado vivienda de promoción Pública . si es lo que demanda tiene que solicitarla en Vivienda . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-08-30','De: Salud Extremadura >inf.saludextremadura@salud-juntaex.es> Enviado el: martes, 30 de agosto de 2022 11:45 Asunto: Contacto Comisión Tutelar de Adultos Nombre: rosa Apellidos: vigario trenado Asunto: Situación de Eduardo Caballero Páez Mensaje: Buenos días soy Rosa Vigario Trabajadora Social del Ayuntamiento de Mérida, quisiera comentar la grave situación que atraviesa Eduardo Caballero que está tutelado en la Comísión. LLeva dos años viviendo en una tienda de campaña en la calle, esta situación ha empeorado ya que le han destrozado la tienda y la han rociado con gasolina por lo que ahora duerme en las inmediaciones del teatro romano en un banco y se dedica a la mendicidad . Desde S. Sociales se le ha propuesto alternativas como ingreso en el Centro Padre Cristobal, alquilar una habitación en el hostal torero, comedor social.. pero rechaza estas alternativas y lo que demanda es una vivienda social, tampoco quiere solicitar el reconocimiento de discapacidad. Mi pregunta y ante la gravedad del caso es si existe algún recurso propio de la Comisión que pueda dar respuesta a la grave situación de vulnerabilidad que atraviesa Eduardo. Es beneficiario del IMV Correo Electrónico y/o Teléfono de Contacto: rosa.vigario@merida.es . Teléfono: 924387407','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-08-30','Ana: Acuerdo mediante mail con Araceli, TS Mentalia, Arévalo (tsocialpsicogeriatria.arevalo@mentaliasalud.es), que la llamada el día 1 a Juan Carlos la haré a las 9:15 h. ············ El resto de llamadas, los jueves, con carácter quincenal, a las 14 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-08-30','Email del CRR : Adjunto presupuesto del gasto de los 60€ para ropa. Comentarte que Emilia ha tenido un ingreso programado en UHB durante el fin de semana. Ha regresado esta tarde y se encuentra tranquila y abordable. Saludos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-08-30','Ana: Reenvío correo-e de Toni-Futuex al ctutelar@: "Hola Ana, buenas tardes, te envio para el area económica Área económica (reclamación factura Alameda agosto 2022): Contacta Verónica, gerente del hotel, para comunicar que no ha llegado el pago de la factura correspondiente al mes de agosto. Jose sigue muy agusto en el hotel, está totalmente hecho a la vida allí y lo tratan genial, como a uno más del personal del mismo. La cuantía de este mes es de 775€, se adjunta factura en documento a parte. "','1');
