insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-08-30','Ana: paso a Julio, Aux. Adtvo. CTAEX, para que registre en SIREX, oficio y documento de "Opción de PFHC" remitida por la Dirección Provincial de CC del INSS, debidamente sellado y firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-08-31','NOTA PARA HACER CONSTAR. Cambio de domicilio. Vivía en la C/ de las Margaritas, 59; 10004; Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-08-31','Ana: Correo de Soraya Masa (Destinatarios: Miguel-CTAEX, Carmen Franco y Pilar del Río - Directoras de los CSS y José Antonio Mesa-Psicólogo y Director en funciones CSS-Plas.): "Hola a tod@s, espero que estéis bien. El motivo de este mail es informaros que se puede llevar a cabo el traslado de Cipriano Bazaga Miguel el próximo lunes 5 de Septiembre a la UME del Centro Sociosanitario de Mérida. Para cualquier cuestión podéis contactar con Juan José Marín que es el psicólogo de dicha Unidad. Pongo en copia también a la Comisión Tutelar para que tenga esta información."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-08-31','Ana: Llamada de África, TS Comedor Social Mérida (609 50 35 34): está allí Francisco, quiere hablar conmigo, pone el manos libre: Comunica que está de nuevo en Mérida, pernocta en el Hostal El Torero, por el que abona 300€/mes. A comer acude al comedor social. Su autorización es de 340€/mes. Pide aumentarla a 400€. *Consultaré a la secc. ecca. ···· Expresa que continúa con sus seguimientos en el ESM de Cáceres y poniéndose su inyectable cada 21 días en el centro de salud (ahora en Mérida). Dice estar estable. Le hicieron analíticas y tenía un pelín bajo el sodio, pero algo sin importancia. Tiene solicitada plaza en Piso Supervisado (CC /Don Benito/ Zafra). *Quiere ayudar a su hija, quien sigue viviendo con su Prima Ana Garrido Chamorro, pagando los libros de texto. Acordamos que nos remitan presupuesto de la librería con nº de cuenta para que pueda abonarse mediante transferencia y ellas sólo tengan que pasar a recogerlos. ······························································································································································································· Correo de Alberto, Jefe secc. ecca: "SE ACEPTA SUBIR ASIGNACIÓN A 400 €/MES A PARTIR 01/09/2022....DE AQÚI PAGA SU ESTANCIA EN EL HOSTAL EL TORERO DE MÉRIDA Y SUS GASTOS." ··························································································································································································· Se lo comunico a África, TS, quien se lo comunicará a Francisco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2022-08-31','TERESA TERE/ALBERTO: CUALQUIER REQUERIMIENTO ECONÓMICO DE JOSÉ FLORENCIO SERÁ DENEGADO (INCLUIDO TAXI, ROPA, ETC...) MOTIVO: LOS CONTINUOS GASTOS QUE GENERA JOSE FLORENCIO: TAXIS, GAFAS, MOVIL, ROPA...ESTÁN GENERANDO EVOLUCIÓN NEGATIVA SALDO...INASUMIBLE. TERE: REVISAREMOS SITUACIÓN EN ENERO 2022 LOURDES: REQUERIMIENTO ECONÓMICO JOSÉ FLORENCIO: DENEGADO DE ANTEMANO Y SI EL MUESTRA DESACUERDO...QUE SE PONGA EN CONTACTO CON TERE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-08-25','Ana: Llamada de Cristina, Psicóloga CRR-CC (927 830 210): Consuelo apareció en el centro en la madrugada del sábado, debido a conflictos con su hermano decidió no quedarse más en casa y volver al centro. *En principio firmó la solicitud de traslado al CRR de Mérida, pero en el momento de enviarlo dijo que no. ····· Ya le han explicado en el centro que como ella no quiere, de momento no solicitan el traslado, pero eso no quiere decir que si llegado el caso lo consideran necesario procederán a solicitarlo de oficio como medida terapéutica/disciplinaria. ······················ Con Juan Mario la relación no es saludable y discute mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2022-08-31','Ana: Llamada de Cristina, Psicóloga CRR-CC (927 830 210): Félix anoche volvió a agredir a otro residente. L@s compañer@s le tiene miedo y nadie quiere denunciar. *En este caso, tampoco se le puede enviar a casa como medida terapéutica, por las circunstancias de la madre. **Ya han hablado con Sheila, Directora CRR, sobre la necesidad de denunciar desde el propio recurso por lo hecho y el riesgo y perjuicios para el resto de residentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-08-31','Ana: Llamo a Raquel - Programa de Familia Mancomunidad Tajo-Salor (659 926 956): ha hablado con Alejandro, hermano de Miguel Ángel. Dice que le vio un día con unos papeles por Cáceres y le dijo que debía ingresar de nuevo en prisión. ······································································································································································································ Bajo a hablar con Jorge Morán, Jefe de Ud. Prestaciones Eccas. Desentendencia, para preguntar por la Prestación ecca. para cuidados en el entorno familiar. *Ésta ya no la percibe, la dieron de baja hace un par de años por incumplimiento de los requisitos. El cuidador era el padre fallecido (Lucio Ramos Cortina). **Tiene una DEUDA por COBROS INDEBIDOS de 4.090,20€. *De momento eso no se podrá abonar, el procedimiento seguirá su curso. La deuda le ha sido notificada en dos ocasiones: 09/06/20 y 03/01/20. **SE lo paso a Icíar para el INVENTARIO. ················ Me facilita información sobre su cuenta bancaria (en la que percibía la prestación) y se la paso a Icíar, secc. ecca. ····························· *Según el expdte. de dependencia ha sido expulsado de 5 COMUNIDADES TERAPÉUTICAS. ······································ Según el Dictamen Técnico del CADEX, presenta Alteración de la Conducta, Trastorno del Dllo e Inteligencia Límite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-08-31','TERESA Como te comenté en el informa que te envié ayer, el lunes fueron a hacer compra ellos solos. Hemos hablado con los de la tienda y les hemos dicho que si no llevan dinero y no les acompañamos no les den nada porque no se le pagará. Hemos entrado al domicilio y han tirado todas las bolsas de basura, como te comenté ayer el Ayuntamiento les llevó 3 contenedores a casa y los llenaron. No han limpiado, por lo que el olor en el domicilio continúa siendo insoportable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-09-01','Ana: Llamada a Juan Carlos, a Mentalia (920 301 400): nada más comenzar la conversación comienza a llorar emocionado y diciendo que quiere irse de allí, no quiere estar en ese centro. Cuando consigue calmarse y hablar, dice que en el centro hay animales (cochinos, cabras, un burro, gatos y perros) y también un huerto, pero que él no participa en nada de eso. Le digo que tiene que decirles que él quiere, para que lo tengan en cuenta y que yo se lo diré también a Araceli. Le recuerdo que lo llamaré de nuevo en 2 semanas. ·················· Hablo con Araceli, le incluirán en "la granja". Confirmamos las llamadas quincenales a las 14 h los jueves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-09-01','Ana: Correo de Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com) a las 8:32 h: "Felipe Blanco se ha escapado, ya hemos dado parte a la policía a ver si lo encuentra pronto y en que estado lo encuentra." ··············································································· A las 9:30 h llamo a Teresa, TS, quien me confirma que Felipe ya ha aparecido. Llamaron al centro del Jdo. diciendo que estaba allí y la directora ha ido a buscarle. En este momento está tranquilo. ······ Creen que hay algo más detrás de las conductas y de su solicitud de más dinero, pero aún no han averiguado. ·············· Le recomiendo que vayan elaborando un registro diario de incidencias, tanto para comunicar a la UPA, como para si fuera necesario, comunicar al Jdo. ································································································································································································ Nuevo correo de Teresa Nogueira, Novaforma (trabajadorasocial.novaforma@gmail.com) a última hora: "al final Felipe ha hecho ingreso en psiquiatría, estaba tranquilo, es lo mejor, a ver i le ajustan la medicación y mejora."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-08-22','miguel, me contesta Oscar: Adjunto certificado de saldo de cuenta bancaria a 21-5-22. Aunque en la cuenta aparece como titular Virgilia, los ingresos de esta cuenta, desde que tenemos conocimiento de ella por lo visto en las rendiciones, han procedido únicamente de la pensión de Nemesia. Virgilia nunca ha aportado dinero a esta cuenta bancaria. El depósito con núm. 20481041872600027907 fue rescatado el 25 de septiembre de 2020, estando viva Virgilia, con lo que entiendo que no se puede llevar a la masa hereditaria. Anotaciones en ficha para que veas lo que se hizo en su momento. - “SEPTIEMBRE 2020: SE ABRE UNA NUEVA CUENTA EN LIBERBANK Y SE INGRESA EL PLAZO FIJO QUE TIENE CON OTRA TITULAR (SU SOBRINA). LLAMA LA HIJA DE LA TITULAR (RAQUEL) Y SE INFORMA QUE SE HAN HECHO LAS GESTIONES EN BENEFICIO DE LA TUTELADA. MANIFIESTAN PODER HACERSE ELLOS CARGO DE LA TUTELADA (CONVERSACIÓN EN BUEN SENTIDO CORRECTA) - OCTUBRE 2020: SE TRASPASAN 15.000 EUROS DESDE LA CUENTA ANTIGUA A LA CUENTA NUEVA. - DICIEMBRE 2020: SE HACE EL CAMBIO DE PENSION A LA CUENTA NUEVA - 2021/01/28: JUANA/ALBERTO: CANCELAR ESTA CCC, LLEVARNOS SALDO A CCC SOLO TUTELADA Y REDOMICILIAR TODOS LOS RECIBOS EN CCC NUEVA TUTELADA. JUANA HABLA CON HIJA DE LA OTRA TITULAR DE ESTA CCC Y ENTIENDE Y ACEPTA LAS ACTUACIONES QUE SE ESTÁN REALIZANDO.” Por lo que veo, a finales de 2020 se abrió una nueva cuenta a nombre de Nemesia y se traspasó el cobro de la pensión. Se solicitó el cambio de las domiciliaciones para cerrar la cuenta en la que estaba con Virgilia, para no tener los problemas que vamos a tener ahora, pero no se llevó a cabo. En teoría, el depósito se canceló por lo mismo, porque estaba a nombre de Virgilia, pero no era su dinero. Según la anotación, la hija de Virgilia era conocedora de esta cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-09-01','Ana: correo de Toni, TS C.R. Cervantes (antonia.dediego@salud-juntaex.es): "Eugenia Pacheco Vicente, viene hace varios meses solicitándonos una subida de la asignación semanal de 15€ a 20€. hablando con Gloria su Educadora de Futuex hemos visto que podía ser posible, porque con todos los gastos que ella origina a lo largo del mes, más la subida de 5€ de asignación, le quedarían de ahorro 93.53€. Por todo ello solicito que sea estudiado la subida de asignación." ························ Reenvío la solicitud a Óscar, secc. ecca., por mi parte, si es viable, ok.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-09-01','miguel, reenvío certificado de saldo de la cuenta a fecha de fallecimiento a la hija de Virgilia (Raquel) y su asesor fiscal para el impuesto de sucesiones Miguel(miguelgarjim43@gmail.com; raquelrodriba@email.com): Buenos días, el depósito con núm. 20481041872600027907 fue rescatado el 25 de septiembre de 2020, estando viva Doña Virgilia, con lo cual no se puede llevar a la masa hereditaria, no obstante les remitimos certificado de saldo que nos remite la entidad bancaria a la fecha de fallecimiento de Doña Virgilia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-09-01','TERESA En relación a Pablo Galán Gilgado, comunicaros que se ha aceptado el ingreso en la Casa de la Misericordia, pero sólo con la condición de que Pablo acepte este ingreso de manera convencida, entendiendo qué implica esta decisión y aceptando la normas de convivencia del recurso. El ingreso se plantea para la semana del 5 de septiembre, pero la fecha ya la cerrará Teresa con Julia, coordinadora del recurso, cuando esté de vuelta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-09-01','TERESA RECIBO NUEVOS INFORMES DE LA SITUAICON DE AITOR POR PARTE DEL PROGRAMA DE FAMILIA ASI COMO INFORME DE LA POLICIA LOCAL, LOS ADJUNTO POR EMAIL A MIGUEL PARA QUE LOS COMUNIQUE AL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-01','miguel, el día 23 Oscar remitió a la tasadora (particulares@st-tasacion.com) justificante de ingreso para la tasación de 435,60€. Reenvío dicho justificante a Amelia (tía de los hnos Gil Sanz): Buenos días, te adjunto el justificante de transferencia que mi compañero envió al email de la tasadora que nos indicastes. Por favor, a ver si logras averiguar cuándo nos remitirán dicha tasación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2022-09-01','TERESA comunicar a la Comisión Tutelar que el usuario CARLOS MARIA GRANDE VICARIO con DNI 76041928H deja de estar hoy 01/09/2022 en nuestro centro, se traslada con su plaza sociosanitaria T1 al centro residencial Ciudad Jardín en Casar de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='MORCILLO'and apellido2='PAJUELO'),'2022-09-01','miguel, contesto a Alberto y a Mª Luisa: Buenos días, para proceder a dicho desbloqueo imagino que habréis preguntado a la entidad si necesitan o no autorización judicial. Si es así tenemos que contratar un abogado para que lo solicite el juzgado por lo que necesito me remitáis un certificado de saldo del depósito para enviarlo al abogado. Voy a solicitar presupuestos de abogados…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='MORCILLO'and apellido2='PAJUELO'),'2022-08-24','miguel, recibo email de Alberto con copia a Mª Luisa: MIGUEL: SI, EL DEPÓSITO LO CANCELAMOS Y POSTERIORMENTE LA CCC (DE ESTO YA SE ENCARGARÁ MARÍA. MIGUEL: CUANDO TENGAMOS LA AUTORIZACIÓN NOS LO PASAS PARA QUE PROCEDAMOS. MARÍA: ESTAMOS PENDIENTES CADA X TIEMPO PARA PREGUNTARLE A MIGUEL SI LLEGA LA AUTORIZACIÓN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-09-01','Ana: Llamo a Ángel Félix (643 622 174): comunico que ya puede ir a recoger el móvil a la tienda y a retirar el extra al banco. ······························································································································································································ Envío correo a Toni-Futuex: "He vuelto a hablar con Ángel Félix Maíllo, dice que acepta el apoyo de las educadoras del Programa de Apoyo Comunitario para la búsqueda de vivienda de alquiler. Se muestra un tanto agobiado con este asunto y pregunta cuándo van a ir a visitarle y ayudarle a buscar piso. Si fuera posible, por favor, agilizar la visita. Ya me vais informando al respecto." ································································································································································································ Ana: Llamo a Yéssica, TS Cáritas (927 422 406 - 645.887.203): está ocupada, me devolverá la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='BUENO'and apellido2='SANTOS'),'2022-08-24','miguel, recibo email que Alberto nos envía a la parte social (Maite y Amalia), Oscar y a mi: PUES NOS ENCONTRAMOS EN UNA SITUACIÓN SIMILAR A PEREZ PINNA PERO MENOS SANGRANTE: • SIN TENER EN CUENTA NI UN SÓLO GASTO EXTRA: ROPA, TRANSPORTES, ACOMPAÑAMIENTOS, CUESTIONES SANITARIAS: PARTE CADA AÑO CON -120 € (AUNQUE EL ÚLTIMO AÑO YA FIGURA CON - 1.109,7 €) • PERDER 120 € EN UN AÑO CON EL SALDO QUE TIENE DE 10.000 € ES ASUMIBLE, PERO LA REALIDAD ES OTRA: o ESTE AÑO HA COMPROMETIDO UN GASTO DE 1.820,5 € DE DENTISTA, DEL QUE, A DÍA DE HOY, FALTAN X ABONAR 1.200 € o NOS INDICA CENTRO QUE VA A CONTINUAR CON GASTOS DE ROPA Y SIMILARES (LÓGICO X OTRA PARTE). o HE VISTO CONVERSACIONES CON CENTRO SOBRE PROBLEMAS X USO DE MÓVIL X TUTELADO...ESO, TARDE O TEMPRANO GENERARÁ GASTOS. o COMO PRETENDE EL CENTRO HACER FRENTE A NUEVOS GASTOS QUE PUDIERAN PRODUCIRSE RELACIONADOS CON: • DENTISTA. • GAFAS. • MÓVIL • ACOMPAÑAMIENTO. • OTROS. X TANTO, SI LA OPCIÓN PROPUESTA X EL CENTRO ES PAGAR HOY HASTA QUE SE AGOTE SALDO Y LUEGO "DIOS PROVEERÁ", LA CTAEX, EN MI OPINIÓN, NO DEBE ASUMIR LA RESPONSIBILIDAD DE ESA MALA GESTIÓN. HABRÁ QUE LLEGAR A UN ACUERDO RESTRICTIVO SOBRE EL GASTO O "COMO MÍNIMO", QUE HAYA UN "INFORME" QUE JUSTIFIQUE CON CRITERIOS CLAROS, EL ASUMIR ESTE FUNCIONAMIENTO. IMPORTANTE: CUANDO ESTEMOS TODOS INCORPORADOS TRATAMOS ESTE TEMA Y ESTABLECEMOS UN CRITERIO. AMALIA: SI TE PARECE LO VAS HABLANDO CON CENTRO...REITERO MI OPINIÓN: NO SE TRATA DE UN FUNCIONAMIENTO PUNTUAL...LO QUE PROPONE CENTRO ES FUNCIONAR ASÍ HASTA QUE DINERO SE AGOTE. ________________________________________','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='BUENO'and apellido2='SANTOS'),'2022-09-01','miguel, contesto a Alberto y Amalia: Buenos días, no entiendo bien qué vamos a hacer…Si os parece cuando vuelva Maite y previa reunión de la parte social para tratar el asunto, nos reunimos para nos indiquéis qué hacer desde la parte jurídica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2022-08-24','email de Alberto a la parte Jurídica: ACTUACIONES Y ACLARACIONES: ICIAR • ES62 2085 4600 0903 3051 4148 - CCC SOLO MADRE (MARIA LUISA): ICIAR SOLICITARÁ CANCELACIÓN DE ESTA CCC Y DOMICILIAR TODOS LOS GASTOS ASOCIADOS A LA CCC ES44 2085 4600 0003 3049 5804- CCC MANUEL • JUSTISFICACIÓN: MANUEL TIENE UNOS INGRESOS MUY SUPERIORES A LOS DE ANTONIO (ÚNICAMENTE PORQUE AMBOS CONFORMAN LA MISMA UNIDAD FAMILIAR: X ESTE MOTIVO SE CARGAN LOS GASTOS EN LA CCC DE MANUEL, CON INDEPENDENCIA DE QUE, PARA DETERMINADOS GASTOS COMUNES, ANTONIO PUEDA APORTAR UNA PARTE - LIMITACIÓN DE LOS GASTOS QUE AFRONTA MANUEL: EL IMPORTE DE SUS INGRESOS SUPERIORES A LOS DE ANTONIO. • BANCO INDICA QUE DE FORMA AUTOMÁTICA TRANSFERIRÁ CADA MES DESDE LA CCC ES44 2085 4600 0003 3049 5804- CCC MANUEL A LA CCC ES21 2085 4600 0503 3039 0922 - CCC DE LOS 3 HERMANOS Y MADRE FALLECIDA: EN ESTA CCC SE PAGA EL PRESTAMO X EL IMPORTE NECESARIO PARA PAGAR LA CUOTA DEL PRÉSTAMO. • HERENCIA (ÁREA JURÍDICA): URGENTE: HABRÍA QUE HACER LO ANTES POSIBLE LA HERENCIA DE LA MADRE DE TUTELADOS RODRIGUEZ RIVERO, LUISA (ANTIGUA TUTELADA FALLECIDA). • PRESTAMO: DECISIÓN PENDIENTE, EN FUNCIÓN DE REUNIÓN ÁREA JURÍDICA Y ECONÓMICA. o AREA ECONÓMICA PROPONE CANCELACIÓN PARCIAL/TOTAL PRÉSTAMO A TRAVÉS RECUPERACIÓN PLAN AHORRO MANUEL (4.000 €) + APORTACIONES DE AMBOS HERMANOS (MANUEL Y ANTONIO) X EL RESTO....HAY QUE TENER EN CUENTA QUE NO SE PUEDE CONTAR CON EL TERCER HERMANO , LUCIANO (NO TUTELADO), QUE TAMBIÉN DEBERÍA APORTAR PERO QUE DEBIDO A SU SITUACIÓN PERSONAL Y ECONÓMICA, ESTÁ IMPOSIBILITADO PARA ELLO. ICIAR (24/08/2022) INFORMACIÓN QUE APORTA DIRECTOR IBERCAJA: • SEGURO DE VIDA: TOMADORA MADRE FALLECIDA, ASEGURADO LUCIANO, BENEFICIARIO BANCO (RELACIONADO CON EL PRÉSTAMO): 250 €/AÑO (SIN DEUDAS). • PLAN AHORRO SEGUROS MANUEL: o VENCIMIENTO: 12/2029, ESTA ASOCIADO A PRESTAMO COMO MEDIO BANCO PARA ASEGURAR PAGO + SE PODRÍA RECUPERAR EL DINERO, PERO NO LO ACONSEJA EL BANCO PORQUE TIENE ALGO DE INTERÉS. o SALDO POSITIVO PLAN AHORRO A DÍA 24/08/2022: 4.000 € (QUE PODRÍAN SER RESCATADOS). • HIPOTECA: o VENCIMIENTO 02/2029 o PENDIENTE A 24/08/2022: 11.000 €. o LIMITACIÓN CANCELACIÓN: INDICA BANCO QUE NO ES POSIBLE PROCEDER A CANCELACIÓN PRÉSTAMO SIN HACER TODOS LOS TRÁMITES RELATIVOS A LA HERENCIA (CONSULTAR A ÁREA JURÍDICA) ________________________________________','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2022-08-25','contestación de Angel: Buenas, Ambos hermanos están curatelados, por lo tanto, no necesitamos solicitar autorización judicial para aceptar la herencia. ¿Qué documentos tenemos de la causante? Certificado de defunción, testamento, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-09-01','Ana: Llamo a Julia, Casa Misericordia Alcuéscar (927 12 00 24): el ingreso ayer fue muy bien, sin ningún tipo de incidencias. De momento parece aceptar las normas de funcionamiento y entregó el tabaco para la "dosificación" diaria, como hacen con el resto de residentes. ······················· *Solicito a Julia que me remita Cdo. de Ingreso en Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-29','email de Angel: Buenos días, No estuve en esta reunión, estaría Miguel. Si he entendido bien, ¿quieren vender la casa sita en Cáceres, en C/. Huaina Capac, nº 6 (en catastro), nº 1 (según Nota Simple)? Martín tiene el 75% y el hermano el 25%. Está embargada con 14.604,32 euros, por el Juzgado de 1ª. Instancia nº 1, de Cáceres (procedimiento 543/2008). Si es así, habría que hablar con el Juzgado y que nos digan como está ese embargo. En cuanto a autorización para vender no necesitamos, porque es una curatela. ¿Martín quiere vender su parte? El otro inmueble, C/. García Márquez, de Cáceres, es 100% de Martín. No tenemos Nota Simple.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-29','contestacion de Angel:Buenos días, ¿Tenemos comprador? El valor mínimo del bien, a efectos de impuestos son 169.321,15 euros. Hicimos una tasación, en el año 2013, que ascendió a 193.436,93, pero como hubo que reparar unos daños debido a un incendio en el garaje, que costaron 20.500 euros, quedó en 172.900 euros. No sé en qué estado se encuentra la vivienda actualmente. Habría que actualizar la tasación o quedarnos con el valor mínimo a efectos de impuestos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-08-29','nueva contestacion de Angel: Hola, Esa otra vivienda está embargada por el Juzgado. Hasta no saber en qué estado se encuentra ese embargo no podemos hacer nada. En septiembre intento hablar con el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-01','contestacion de Amelia: Buenos días, Miguel El tasador realizó la visita el pasado viernes, ayer estuve hablando con ellos y entre hoy y mañana me envían el informe. La finalidad de la tasación es Asesoramiento valor de mercado que permitirá gestionar la venta de la vivienda pero no la constitución de hipoteca en el inmueble porque no está registrado. Te mando documento del Registro de la propiedad con la dirección y la referencia catastral de la vivienda en el que se especifica que no está registrado. Me dijo el tasador que para la venta de la vivienda necesitaríamos certificado energético y dicho certificado no estaba incluido en el precio de la tasación, quedé con él en que a la vez que visitaba la vivienda obtuviera información para poder emitir el certificado sin tener que visitarla de nuevo. El presupuesto del certificado serían unos 90 euros sin iva, si es necesario para la venta habría que obtenerlo… En cuanto tenga la tasación te la hago llegar y habría que autorizar el precio mínimo de venta tan pronto como sea posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-08-30','miguel, recibo email de Sonia de Asindi: Hola Miguel, quería informarte que el día 22 Aaron Rosado Alarcón acudió a la cita del médico forense. El profesional que le acompañó me dice que el médico forense ha valorado que no tiene las capacidades para declarar por lo que emite informe y se lo remite al fiscal. Imagino que ya nos irán diciendo cómo proceder. Además tiene pendiente otras causas que, imagino, se resolverán más o menos con el mismo procedimiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2022-09-01','Ana: Llamada de Pilar Cerrillo, Res. Grupo Ciudad Jardín, Casar de Cáceres (927 29 05 50): Carlos María ha ingresado hoy a media mañana. Desde que ha llegado no ha parado de dar voces y soltar improperios. *Requiere sujeciones varias, ya en el centro del que procede se las tenían puestas. Se le ve bien cuidado y aseado. ············ Según informe médico presenta antecedentes psiquiátricos y neurológicos, así como hetero y auto-agresividad. *Tuvo intento autolítico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-08-30','Ana: Llamada de Isabel (649 642 635): Se propone ir a un hostal/pensión a Trujillo la semana del 26 de septiembre. *Ella plantea ir a comer a casa de su hermana durante su estancia en Trujillo, dice que ha hablado con ella y le parece bien. *Si su hermana nos lo corrobora (a nosotros o al CRR) se acepta. ············ Solicitaré al CRR que le apoyen en las gestiones de búsqueda de alojamiento y medios de transporte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-09-01','-Email TS de SSASB de Mérida ROSA VIGARIO >rosa.vigario@merida.es> Acabo de atender a Eduardo y le expuesto las diferentes alternativas: El recurso del Centro de Rehabilitación lo ha descartado ya que no asume que padece ninguna patología mental. El centro Padre Cristobal no tiene plaza en la actualidad ni tampoco el Centro Hermano en Badajoz, me dan la alternativa de ocupar una plaza en el Centro de Emergencia Bravo Murillo de Badajoz. Se lo comento a Eduardo y tampoco quiere este recurso. Ya por último se le propone como alternativa habitacional alquilar una habitación en el Hostal el Torero pero tampoco está de acuerdo argumentando que está muy lejos de Mérida. Para terminar se informa que existen ayudas de contingencias para pago de alquiler de una vivienda ( 3 mensualidades ) pero para poder tramitarlo necesitaría un contrato de alquiler., Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-09-01','-Email TS de SSASB de Mérida ROSA VIGARIO >rosa.vigario@merida.es> Acabo de atender a Eduardo y le expuesto las diferentes alternativas: El recurso del Centro de Rehabilitación lo ha descartado ya que no asume que padece ninguna patología mental. El centro Padre Cristobal no tiene plaza en la actualidad ni tampoco el Centro Hermano en Badajoz, me dan la alternativa de ocupar una plaza en el Centro de Emergencia Bravo Murillo de Badajoz. Se lo comento a Eduardo y tampoco quiere este recurso. Ya por último se le propone como alternativa habitacional alquilar una habitación en el Hostal el Torero pero tampoco está de acuerdo argumentando que está muy lejos de Mérida. Para terminar se informa que existen ayudas de contingencias para pago de alquiler de una vivienda ( 3 mensualidades ) pero para poder tramitarlo necesitaría un contrato de alquiler., Un saludo. ------------------------Buenos días te comento que Eduardo si ha solicitado vivienda de Promoción Pública. Hoy tiene cita en los Servicios Sociales y le comentaré de nuevo las posibles alternativas habitacionales y los posibles recursos. Un saludo.--------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-09-01','-Email TS de SSASB de Mérida ROSA VIGARIO >rosa.vigario@merida.es> Acabo de atender a Eduardo y le expuesto las diferentes alternativas: El recurso del Centro de Rehabilitación lo ha descartado ya que no asume que padece ninguna patología mental. El centro Padre Cristobal no tiene plaza en la actualidad ni tampoco el Centro Hermano en Badajoz, me dan la alternativa de ocupar una plaza en el Centro de Emergencia Bravo Murillo de Badajoz. Se lo comento a Eduardo y tampoco quiere este recurso. Ya por último se le propone como alternativa habitacional alquilar una habitación en el Hostal el Torero pero tampoco está de acuerdo argumentando que está muy lejos de Mérida. Para terminar se informa que existen ayudas de contingencias para pago de alquiler de una vivienda ( 3 mensualidades ) pero para poder tramitarlo necesitaría un contrato de alquiler., Un saludo. ------------------------Buenos días te comento que Eduardo si ha solicitado vivienda de Promoción Pública. Hoy tiene cita en los Servicios Sociales y le comentaré de nuevo las posibles alternativas habitacionales y los posibles recursos. Un saludo.--------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-09-01','Ana: Envío correo a Blanca, Directora del CRR con copia a Paula y Carolina: "Tal y como planteamos hace unos días mediante conversación telefónica, y tal y como hablé con ISABEL CANO BLÁZQUEZ antes de ayer, si continuáis de acuerdo en ello, porque lo creáis necesario/beneficioso a nivel emocional para ella, vamos a probar que vaya unos días (entre diario) a Trujillo pero alojándose en un hostal/pensión. La fecha que le he dicho, para que no coincida con las visitas de su madre y no fuera precipitado, es la de la semana del 26 de septiembre. Creo que sería bueno que desde el recurso le apoyéis en a búsqueda del alojamiento y así como en la búsqueda y gestión del billete de autobús o medio de transporte que mejor consideréis. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-09-02','Ana: Recibo llamada de Rocío Jociles, Dependencia, SSTT CC (64860). La han valorado en agosto por empeoramiento y ha dado GRADO III. *La residencia en la que está ya tiene plazas acreditadas. Se aceptará el PIA = Prestación Vinculada al SAR. *No planteamos el cambio a plaza pública dada su edad y los años que lleva ya en la residencia. Si llegado el momento hiciese falta, que no creemos, se podría solicitar revisión del PIA.············· Rocío me enviará la Aceptación del PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-09-01','Ana: correo de Teresa Nogueira, Novaforma (trabajadorasocial.novaforma@gmail.com): "al final Felipe ha hecho ingreso en psiquiatría, estaba tranquilo, es lo mejor, a ver i le ajustan la medicación y mejora."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-09-01','Ana: Correo de Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "Buenos días, os informamos de situación de Julia, desde que ha venido a la expulsión no hay alteraciones conductuales graves de amenazas, gritos y agresiones. Observamos sintomatología como labilidad emocional, alta demanda de atención ... que a nuestro juicio podría disminuir con un ingreso, pero Julia no lo ve necesario. Estamos en contacto con salud mental para poder ir orientando la intervención. Si vuelven a aparecer alteraciones conductuales os comentamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-09-02','Ana: Recibimos por correo postal ordinario, el "recibo" del alquiler de la habitación del mes de septiembre, escrito y firmado a mano por el dueño del piso, Pablo Pastor. ·························· Llamo a Toñi (677 806 445) varias veces sin éxito. ·· La idea es facilitarle el nº de móv de la secc. ecca. para que pueda enviar imágenes del documento por WhatsApp y así no gastar dinero en sobres y sellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-09-02','Ángel: Envío al Servicio de Renta Básica de Inserción, la ratificación de la CTAEX relacionada con la solicitud que ha presentado Ana María Rosco Ávalos, a la siguiente dirección de correo electrónica, inforentabasica@salud-juntaex.es, tras hablar con Jesús Vadillo del Equipo Psicosocial de Renta Garantizada, extensión 66087.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-09-02','Ana: Recibimos una factura (Nº 15) del 26 de agosto de la papelería de su pueblo con un importe de 200€. *Este gasto no estaba comunicado ni autorizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-09-02','Ana: Correo de Blanca, Directora del CRR: "Anoche llamamos al 112 para que valoración de Julia. Llegó al CRR sobre la 1.30 de la madrugada, con mareos y malestar. Activamos protocolo de 112 sin presencia policial ya que no había amenazas, ni insultos contra otras personas. El 112 acudió al recurso atendió a julia con medicación y nos orientó a hablar con salud mental, ya que es ese momento no había motivos para valoración psiquiátrica y ella se negaba. Según nos cuenta consumió bebidas energéticas hecho que hace que se disparen síntomas. Nos pondremos en contacto de nuevo con salud mental con la idea de continuar trabajando con Julia la necesidad de ingreso ya que no cumple con criterios de ingreso involuntario al ser capaz de controlar la situación. Continuamos con el mismo procedimiento en caso de alteraciones conductuales graves si aparecen. Actualmente la situación de Julia en el centro es muy inestable ya que requiere mucha atención para que sea capaz de contener conductas disruptivas, si bien es cierto que la atención de ayer fue diferente a la de estos días, siendo capaz de manejarse sin agredir verbalmente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-09-02','Ana: correo de Óscar, secc. ecca, a Toni, TS CR Cervantes: "Una vez analizada la situación económica de Eugenia, no es viable la subida de asignación, ya que su nivel de ahorro es menor al establecido por la sección económica de la Comisión Tutelar como idóneo. Además, en los últimos meses se ha elevado la media mensual de gastos por servicios que genera desde el propio centro. En unos meses volveremos a analizar la situación y os comunicaremos cualquier cambio al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-08-30','Ana: Envío correo a Pilar Cerrilo (calidad@grupociudadjardin.com): "Tal y como hemos acordado, mediante conversación telefónica, te adjunto los siguientes documentos relativos a Mateo Ruano Moreno, para la solicitud de los pisos de Montánchez: - Certificado Catastral Telemático - Declaración de la Renta – Ejercicio 2021 - Certificado actualizado de pensión"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2022-09-02','Ana: Respuesta al correo de Pilar Cerrillo (calidad@grupociudadjardin.com): "Buenas de nuevo Pilar, El seguro de decesos lo tiene en CASER SEGUROS. Adjunto la Póliza. El nº de cuenta es: ES68 2103 7114 0900 3009 6661 La entidad bañaría es Unicaja Banco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-09-02','Ana: Envío correo a Pilar Cerrillo (calidad@grupociudadjardin.com): "Te adjunto la solicitud de ingreso en la Residencia Balcón de Extremadura de Montánchez (Pisos Tutelados) relativa a Mateo Ruano Moreno. Los otros dos documentos los tienen ya en la sección económica, en cuanto los tengas listos te los harán llegar a ti directamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-09-05','miguel, tras consulta al servicio común general (el que hace de oficina de reparto de asuntos, en relación a la autorización para entablar el procedimiento de desahucio), remito email a Rocio Gracian (Abogada). Buenos días Rocio, según me confirma la oficina de reparto de los juzgados de Mérida, el procedimiento para la autorización del desahucio lo está tramitando el juzgado de primera instancia de Mérida con número de procedimiento X15 nº392/22. He intentado hablar con ellos pero comunica. En cuanto sepa algo más te lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-09-05','TERESA me pongo en contacto con la Comisión Tutelar para informar del caso de DAVID ESTEVEZ FELIPE. Este chico tiene 36 años, está tutelado e ingresa en nuestro centro en plaza T3 el 01/04/2022.Le he solicitado una revisión de grado por empeoramiento puesto que tenía reconocido solo grado I y sus limitaciones son importantes en la vida diaria. Tras ser valorado el 25/08/2022 ha obtenido grado II y estoy viendo con la técnico del SEPAD cual es el recurso más idóneo para él pero primero quería hablarlo con vosotros, como insitución que ha asumido su tutela y guarda. El deseo del usuario es volver a su localidad natal, Olivenza, o zona cercana. Tengo solicitado un traslado con su plaza T3 a algún centro en Badajoz, sin embargo, hay que ser conscientes que puede llegar a perder puntuación de este tipo de plaza. Por edad, no da el perfil para acceso a centros residenciales públicos por lo que desde el SEPAD me informan que sería conveniente pedir valoración y acceso a centro residencial para personas con discapacidad (perfil CADEX). ¿Podríais decirme que os parece esta opción, es cierto, que por perfil de discapacidad primero valorarán la necesidad de apoyo que precisa y en función a eso le asignarán centro pero no puede elegir...por lo que la opción de regresar a su localidad no es muy viable? Quedo a la espera de vuestra respuesta antes de entrevistarme con el usuario VAMOS A SOLICITAR PERFIL AL CADEX A TRAVES DE PIA POR CONSIDERAR QUE EL CENTRO RESIDENCIAL PARA DISCAPACIDAD ES MAS IDONEO PARA EL POR LA EDAD QUE TIENE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-09-05','TERESA Desde el programa de apoyo social comunitario, lo podemos gestionar, aunque va implicar, el que una compañera se vaya para Zalamea, y ayude en que se quede todo bien en la casa y cerrarlo todo y la otra que vienen haciendo el seguimiento conjunto, la ts y la terapeuta, se vaya para ayudarlo en la incoporación en Alcuescar. En primer lugar, existe voluntariedad de Pablo de irse a un centro, ya que lleva meses trasladando este deseo, aunque creemos que las expectativas en relación a las actividades que puede realizar allí son altas (cuidar animales, tener un huerto…) y pueden no ajustarse a la realidad, llevando como consecuencia el querer regresar a su domicilio en un corto periodo de tiempo. Actualmente Pablo se encuentra estable, desde que salio del socio ha estado bien, sin tener ningún incidente por alteraciones conductuales en su localidad. Desde farmacia diariamente le proporcionan el tratamiento farmacológico, tarea que deberá ejecutar el centro ya que él no muestra capacidad para la correcta administración de su tratamiento. Desde el programa de apoyo social comunitario nos encargamos mensualmente de la pauta correcta del xeplion (inyectable cada 30 días). Próxima dosis para el 5 de septiembre, e iremos en esos dias. Creemos que seria imprescindible que este apoyo en la medicación se haga desde el centro, ya que si no lo hacen el no tiene suficiente habilidades para mantener la adherencia y si está sin medicación. Uno de los gastos a contemplar para favorecer la estancia en el centro, es el dinero mensual pautado para tabaco. Actualmente corresponde a unos 80 euros mensuales aproximadamente. Para poder apoyar en el traslado sería adecuado planificarlo con tiempo y que la fecha del mismo fuera a partir del 12 de septiembre,para que diera tiempo a todo, ya que parte del equipo de Badajoz, ademas, la semana tiene solo tres dias, por festivos: • Traslado en taxi hasta el centro. • Recogida medicación en la farmacia. • Dejar al corriente de pago alimentación, tabaco…. • Poder ayudarle en la relación de su maleta. • Dejar recogido y cerrado el domicilio, para evitar dejar alimentos que puedan estropearse en el frigorífico, así como llaves de suministros abiertas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-09-05','TERESA EMAIL DE MARI CIELO DEL CRPS Efectivamente a su padre le dío un infarto y estuvo ingresado unos días, le dieron el alta y ella quería el dinero para irse y pasar unos días con ellos. Ya está de vuelta y la semana pasada tuvo un conflicto con ella por un mesa que se le ha roto, pero se ha comprado una por wallapop (aunque ya le he advertido de que no se la vais a pagar). Esta mañana me ha llamado varias veces, hablando del dinero y de que nadie le ayuda, quiere dejar el CRPS y se ha puesto a insultar a los compañeros; le he pedido respeto en varias ocasiones, pero he tenido que decirle que cuando esté más tranquila me llame y colgarle; está muy descontrolada. Mañana tiene cita con la psicologa, pero hace varias semanas que no viene. Ha llamado en varias ocasiones a la psiquiatra, pero están intentando evitar el ingreso. Voy a hablar con la psicologa para ver si puede hablar con ellas, si no voy a tener que ir a su casa. No está para estar sola y no tener ningun apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-09-05','miguel, Mª José (hna 675882305) me envía tres documentos resumen de gastos, que vienen recogidos en la escritura de herencia que en su día indicaba la deuda del tutelado con sus hnos que ascendía según esa escritura a 1.097,61€. ************************************************* Mi contestación: Buenas tardes Mª José, mañana te llamo porque he estado reunido. Comentarte que de la venta de la vivienda de Azkoitia hubo 7.000€ que no se repartieron. Tampoco se han repartido los 6.000€ que se retuvieron de la venta de la vivienda del Valle de la Serena. Por tanto tendrás que calcular todos los gastos y todos los ingresos que hay para la tramitación de toda la herencia ya que veo faltan gastos notariales, registrales (inscripción de la herencia en el registro de la propiedad), plusvalía, otros, etc. Recuerda que tienen que ir acompañados de las facturas. Lo que me remites ya está acreditado en la escritura de herencia no obstante tendrás que explicarme, pues no lo entiendo la hoja de liquidación de la cuenta de Bankinter. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2022-09-05','TERESA RECIBO LLAMADA DE ATI Y ME INDICA QUE TIENE INTENCION DE CASARSE, PARA ELLO SOLICITA 3000€. LE INDICO QUE TIENE QUE COMUNICAR AL JUZGADO SU INTENCION DE CASARSE Y QUE ME LO TIENEN QUE FACILITAR POR ESCRITO LA RESPUESTA DEL JUZGADO PARA YO PEDIR AUTORIZACION PARA EL DINERO QUE SOLICITA TAMBIEN ME COMENTA QUE QUIERE CAMBIAR DE VIVIENDA PUES CON LAS ESCALERAS SU PAREJA TIENE MUCHAS DIFICULTADES PARA SUBIR Y BAJAR LE INDICIO QUE PUEDE IR A MIRAR A TRAVES DE UNA INMOBILIARIA Y CUADO TENGA CLARO QUE CASA QUIERE ME PODNRE YO EN CONTACTO PARA FORMARLIZAR EL CONTRATO DE ALQUILER','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2022-09-06','TERESA ENVIO CAMBIO DE CUENTA PARA COBRO DE PRESTACIONE EN IBERCAJA ENVIO EMAIL A M DOLORES DIMIEL TS DEL SOCI Estamos en proceso de inventario con este expediente, lo voy a iniciar yo en vez de Amalia. Hemos solicitado la apertura de una nueva cuenta en Ibercaja para la gestión de la pensión, en cuanto este la pensión en la nueva cuenta haremos autorización para que podáis disponer del dinero para sus gastos personales, estimo que para para el mes de octubre a mas tardar noviembre. En principio creo que con eso es suficiente, si necesitas algo me lo comunicas y lo vemos, quedo pendiente avisarte cuando puedas retirar dinero','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-09-06','miguel, hablo por teléfono con Mª José móvil 675882305(hna del tutelado), quien me confirma que José Luis para ponerse en paz con sus hermanos tiene que ingresar en la cuenta de Bankinter nº 0128.0353.26.0100021932 el importe de 1.105,23€ ya que los hermanos es el dinero que durante algún tiempo adelantaron para el pago de los trámites. El dinero que queda en esa cuenta 4.023,92€ es de los otros 3 hermanos que se repartirán entre ellos. En cuanto al dinero de señal de la casa de Azkoitia de 7.000€ y 6.000€ del Valle de la Serena, ya se ha gastado. Me mandaran los movimientos de la cuenta para que les pregunte las dudas. Y seguidamente fijaremos fecha de firma de venta de la rústica, donde cada hermano cobrará unos 5.000€ El resto de rústicas (solares) ya me adelanta que tendrán dificil venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-06','miguel, me pongo en contacto con la abogada Mª Teresa Muelas Mazario (tlfno 616-292-983; mtmuelas@icaguadalajara) para pedirle presupuesto para la Solicitud de Aceptación, aprobación de herencia y Autorización de Venta: Buenos días conforme conversación telefónica, necesitaríamos nos hiciera un presupuesto aproximado para solicitar la aceptación y aprobación de herencia y autorización de venta de los padres de los sobrinos de Amelia Rodrigo Sanz (628-581-997; email melitonarodrigo@hotmail.es). Dichos sobrinos Raúl y Sergio Gil Sanz están tutelados por la Comisión Tutelar de Adultos, perteneciente al SEPAD de la Consejería de Sanidad y Servicios Sociales de la Junta de Extremadura. Las escrituras de adjudicación de herencia las está preparando Notaria de Guadalajara, Jimena del Castillo Rodriguez. Tfno 949 248079 y correo de Marian: mgperez@despacho.notariado.org de los padres de los tutelados Rául y Sergio Sanz, que fallecen en Huetos el padre, Máximo Gil Garcia y en Cifuentes la madre, Teresa Sanz Carrascosa. Adjunto las liquidaciones del impuesto de sucesiones que tramitó su tía Amelia, junto con los correspondientes certificados de defunción, certificados de últimas voluntades, testamentos, y los testimonios de incapacitación y remoción con nombramiento del cargo de tutor a la Comisión Tutelar de Adultos. Quedo a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-06','miguel, me pongo en contacto con la abogada Mª Teresa Muelas Mazario (tlfno 616-292-983; mtmuelas@icaguadalajara) para pedirle presupuesto para la Solicitud de Aceptación, aprobación de herencia y Autorización de Venta: Buenos días conforme conversación telefónica, necesitaríamos nos hiciera un presupuesto aproximado para solicitar la aceptación y aprobación de herencia y autorización de venta de los padres de los sobrinos de Amelia Rodrigo Sanz (628-581-997; email melitonarodrigo@hotmail.es). Dichos sobrinos Raúl y Sergio Gil Sanz están tutelados por la Comisión Tutelar de Adultos, perteneciente al SEPAD de la Consejería de Sanidad y Servicios Sociales de la Junta de Extremadura. Las escrituras de adjudicación de herencia las está preparando Notaria de Guadalajara, Jimena del Castillo Rodriguez. Tfno 949 248079 y correo de Marian: mgperez@despacho.notariado.org de los padres de los tutelados Rául y Sergio Sanz, que fallecen en Huetos el padre, Máximo Gil Garcia y en Cifuentes la madre, Teresa Sanz Carrascosa. Adjunto las liquidaciones del impuesto de sucesiones que tramitó su tía Amelia, junto con los correspondientes certificados de defunción, certificados de últimas voluntades, testamentos, y los testimonios de incapacitación y remoción con nombramiento del cargo de tutor a la Comisión Tutelar de Adultos. Quedo a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-09-06','Email de Juanjo , TS de la UHB . Sí, salió a las 8 de la mañana. Puso alguna dificultad, que quería hablar con su psiquiatra antes de irse... pero bueno, se fue en la ambulancia acompañada por personal de la UHB. El viernes contacté con el primo a pesar de que ella no hacía lista y quedó en traerle una maleta. Ayer habló además con el vecino para decirle lo que necesitaba y le dijo. Iba a venir el primo por la tarde. A ver si le va bien. -------------------------------------- Le pido a Miguel que comunique al Juzgado el ingreso y los gastos a abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-09-06','miguel, hablo con el abogado Pablo Garrote quien me confirma que ya tienen casi todos los documentos preparados en la notaria, que ahora va a pedir la autorización judicial para aceptar la herencia, y que me avisará cuando esté todo preparado para que me acerque en coche a su firma. Una vez firmada me dice que la liquidación del impuesto de sucesiones suele hacerla la propia notaria. (Una vez que tengamos la autorización judicial de aprobación de la herencia y la de la venta, podrá venderse al comprador interesado)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-01-17','Maite: José Maria ingreso en Hermanas Hospitalarias el 2 de diciembre, de Palencia. Durante su estancia allí ha estado tranquilo. Tb ha pasado el Covid. El 12 de enero de 2022 ha sido trasladado a un centro en Avila, Mentalia Arévalo. De momento la adaptación es buena. El contacto en el centro es la trabjadora social, Modesta ( 920 30 14 00).tsocialpsiquiatria.arevalo@mentaliasalud.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-09-05','TERESA RECIBO LLAMADA DE LA MADRE DE JOSE MARIA 644 87 68 93, ME INDICA QUE DESDE EL CENTRO LE HAN DICHO QUE PUEDE IR A VISITAR A SU HIJO ESTE JUEVES PROXIMO TRAS COMPROBAR CON MAITE NO TENEMOS NOTIFICACION ALGUNA DE ESTO SE LLAMA AL CENTRO Y LE INDICAMOS QUE ESTO HAY QUE VALORARLO PREVIAMENTE POR EL ELEVADO COSTE QUE SUPONE REALIZAR ESTA VISITA EL CENTRO NOS INDICA QUE HABLARA CON LA FAMILIA PARA POSPONER LA VISITA NOSOTROS VAMOS A BUSCAR OTRA FORMA DE VIAJAR PARA QUE SEA MAS ASEQUIBLE YA QUE EL GASTO DE TAXI QUE SUPONE ES INVIABLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-07','miguel, recibo email de la abogada Mª Teresa Muelas Mazario, mtmuelas@icaguadalajara.org; Tnos.- 949212660/616292983 : Buenas Tardes. A la vista de la documentación remitida procedo a remitir el presupuesto por mi intervención en proceso de aprobación judicial de herencia y posterior solicitud de autorización judicial para la venta de bienes: Entiendo que no va a ser necesaria la autorización previa al estar siendo preparada la herencia en la notaría y que bastaría la aprobación judicial de la herencia realizada, puesto que ambos son los únicos herederos de sus progenitores por iguales partes 1.- Proceso de aprobación judicial de la aceptación de herencia.- 392,00 Euros. 2.- Proceso autorización judicial venta de bienes de incapacitados.- 450,00 euros Dichas cantidades se incrementarán con el IVA correspondiente. ***************************************************** mi contestación a la abogada: Buenos días, conforme el actual artículo 287.5º CC es preciso la solicitud de aceptación de herencia y conforme el artículo 289 CC establece la obligación de la solicitud de aprobación judicial para la aprobación de herencia. Y conforme el artículo 287.2º CC se requiere dicha autorización para vender. Confirme si el presupuesto que me ha remitido recoge las 3 actuaciones, caso de que así sea por favor indíqueme número de cuenta, concepto a incluir y cómo hemos de proceder al pago, adelantamos alguna cantidad de dinero? Tendría que indicarme a nombre de quién hacemos el poder apud acta, para lo que necesitaré los datos del procurador (nombre, dni, nº de colegiado) y ante qué juzgados de primera instancia se va a interponer dichos procedimientos…para incluirlo todo en el poder apud acta que haremos desde los juzgados de Mérida','2');
