insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-09-07','TERESA gestiono todo con el usuario y lo envío firmado al SEPAD. Que tengáis ya constancia vosotros que tiene reconocido un grado II ya y se va a tramitar el mantenimiento de su plaza sociosanitaria T3 en nuestro centro y la valoración del perfil del CADEX (para ingreso en residencia para personas con discapacidad). Un saludo María Martín Rivero Trabajadora social. Encinar de las Cruces Nº COL. 07-1209 924 81 25 99/ 618 95 70 59','2');
