insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-09-12','TERESA RECIBO LLAMADA DE LA SUEGRA DE MARTA EN LA QUE ME COMUNICA QUE EL SABADO PASADO MARRA SE ENCONTRO CON SU MADRE Y LA PAREJA DE ESTA Y LA INSULTARON DICIENDOLE PUTA. ME LLAMA PARA QUE LO TENGAMO EN CONOCIMIENTO, LE COMENTO QUE POR UNA VEZ VAMOS A DEJAR PASAR LA HISTORIA PARA NO COMPLICAR MAS LA COSAS PERO QUE SI VUELVE A SUCEDER PONGAN UNA DENUNCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2022-09-12','TERESA RENDICION ANUAL MARIA DLE MAR RESIDE EN LOS PISOS SUPERVISADOS DE ZAFRA DESDE EL AÑO 2015. PADECE ESQUIZOFRENIA PARANOIDE, SE ECUENTRA ESTABLE PERO CON DELIRIOS DEBIDO A SITUACION RESIDUAL TIENE POCA RELACION CON LA FAMILIA TAN SOLO TIENE EL APOYO DE SU HERMANA BLANCA Y NO DE FORMA CONTINUADA PARTICIPA EN LAS ACTIVIDADES DEL CENTRO Y ESTA BIEN ADAPTADA PENSION 2000€ POR INCAPACIDAD LABORAL, DINERO EN CUENTA 94000','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2022-09-12','TERESA RENDION ANUAL MIGUEL RESIDE EN LA RESIDENCIA DE MAYORES LA SERENA DESDE EL 2019. PRESNTA BUENA ADAPTACION AL CENTRO ESTANDO TOTALMENTE INTEGRADO, PARTICIPA EN LAS ACTIVIDADES Y TALLERES DE MANERA ACTIVA. TAN SOLO TIENE RELACION CON UN SOBRINO EL CUAL LO LLAMA FRECUENTEMENTE PARA INTERESARSE POS SU ESTADO DE SALUD PERCIBE UNA PENSION DE JUBILACON DE 1252€ DINERO EN CUENTA 81000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-09-12','miguel, llega físicamente nuevo requerimiento de la oficina del defensor del pueblo requiriendo 3 cuestiones: 1.-se solicite perito psiquiatrico para el proceso penal 2.-se le remita escrito de defensa judicial 3.-se proceda a su solicitud en ingreso en centro adecuado. La 3º cuestión ya se está realizando en procedimiento ITR Internamiento involuntario 356/2022 del jzdo de 1º instancia e instrucción nº2 de Cáceres. De las dos primeras cuestiones se da traslado a la abogada Carmen Lucas para su cumplimiento Se contesta a la oficina del Defensor del Pueblo en dichos términos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2022-09-12','TERESA RENDICION ANUAL CORAL TIENE DISCAPACIDAD, PROVIENE DE UNA FAMILIA DESESTRUCUTRADA. INGRESA EN EL CENTRO RESIDENCIAL NTR SRA DE LAS CRUCES EN EL AÑO 2011 DERIVADA DEL SISTEMA DE MENORES ANTE LA MAYORIA DE DAD. OCUPA PLAZA RAE Y CONVIVE CON OTRO HERMANO EN EL MISMO CENTRO TIENE CONTACTO CON LA FAMILIA Y SE HACEN SALIDAS CORTAS EN EL TIEMPO CON EL OBJETIVO DE INTEGRAR EL NUCLEO FAMILIAR PERCIBE PF 626,60€ Y ORFANDAD 22,70€ SALDO EN CUENTA 18000','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-09-13','miguel, llega del jzdo de 1º instancia e instrucción nº3 sde Mérida del procedimiento ITR Internamiento 243/2021 autorización para el internamiento involuntario en centro residencial de mayores','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-09-13','miguel, enviamos (inés) a través de Sirex contestación al defensor del pueblo y remitimos dicho requerimiento para su cumplimiento a la abogada Carmen Lucas. Así mismo al tener cita con el forense para el procedimiento de internamiento involuntario que se está tramitando en el jzdo nº2 de Cáceres, reenvío email a Maite y Ana: Buenos días, adjunto comunicación del juzgado para que comparezca mañana día 14 Saturnino a visita del forense. Yo voy a reenviárselo a la abogada junto con la comunicación que le hacemos del requerimiento que nos ha llegado de la oficina del defensor del pueblo. Os adjunto: 1.-citación para que del internamiento involuntario del que está tramitándose en el jzdo nº2 de Cáceres comparezca para su revisión por el forense. 2.-Requerimiento que nos hace la oficina del defensor del pueblo 3.-Contestación que hacemos al defensor del pueblo. 4.-Remisión de dicho requerimiento a su abogada defensora Carmen Lucas para el cumplimiento de dos de los 3 puntos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-09-13','miguel, enviamos (inés) a través de Sirex contestación al defensor del pueblo y remitimos dicho requerimiento para su cumplimiento a la abogada Carmen Lucas. Así mismo al tener cita con el forense para el procedimiento de internamiento involuntario que se está tramitando en el jzdo nº2 de Cáceres, reenvío email a Maite y Ana: Buenos días, adjunto comunicación del juzgado para que comparezca mañana día 14 Saturnino a visita del forense. Yo voy a reenviárselo a la abogada junto con la comunicación que le hacemos del requerimiento que nos ha llegado de la oficina del defensor del pueblo. Os adjunto: 1.-citación para que del internamiento involuntario del que está tramitándose en el jzdo nº2 de Cáceres comparezca para su revisión por el forense. 2.-Requerimiento que nos hace la oficina del defensor del pueblo 3.-Contestación que hacemos al defensor del pueblo. 4.-Remisión de dicho requerimiento a su abogada defensora Carmen Lucas para el cumplimiento de dos de los 3 puntos. ********************************************** Y envío email a la abogada Carmen Lucas: Buenos días, adjunto escrito recibido ayer día 12/9/22 por el defensor del pueblo, para su cumplimiento, que te hemos remitido por carta ordinaria. Como verás de lo que nos requieren son 3 cuestiones: 1.-solicitemos para el procedimiento penal un perito psiquiatra (que tiene que ser de solicitado de oficio por el juzgado ya que no tiene capacidad económica) 2.-les remitamos tu escrito completo de defensa 3.-se proceda a su internamiento en centro adecuado. Como verás en la documentación adjunta el 3º punto ya se está tramitando en el juzgado de 1º instancia nº2 de Cáceres con el procedimiento ITR Internamiento 356/2022. En cuanto a los otros dos puntos debes de darles cumplimiento y comunicárselo a la oficina del defensor del pueblo. Nosotros ya hemos remitido contestación a dicha oficina del defensor del pueblo en ese sentido. Por otra parte y en relación al procedimiento de ITR Internamiento 356/2022, tiene citación para mañana 14-9-22 Saturnino para que le vea el forense, por si puedes comunicárselo, en cumplimiento de lo solicitado por la oficina del defensor judicial. Quedamos a tu disposición para cualquier aclaración.','2');
