insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-09-13','Buenos días Amalia, en el caso de Eduardo Caballero Páez, hablamos con la TS de SSASB y la del Centro de Salud. Al final se tomó la decisión de proponer desfavorable su solicitud al considerar que la adjudicación directa de una vpp no era el recurso adecuado para Eduardo. Ha vuelto a solicitar vivienda por segunda vez y tras ser entrevistado, y comprobar que su situación no ha cambiado, nos reiteramos en la propuesta desfavorable. Eduardo no acepta otra opción que no sea la adjudicación de una vivienda de promoción pública. Y desde esta Oficina seguimos considerando que no es el recurso adecuado para él. Un saludo Nuria Moreno Rebollo Trabajadora Social Teléfono 924 332459 Servicio de Adjudicación y Mantenimiento Dirección General de Vivienda Consejería de Movilidad, Transporte y Vivienda Avd. de las Comunidades S/n 06800 Mérida','2');
