insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-09-13','Ángel: Vuelvo a enviar correo electrónico al Ayuntamiento de Zafra, registroentrada@zafra.es, solicitando certificado de número de gobierno de la vivienda donde vive Beatriz en alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-09-14','Ángel: Llamo al Ayuntamiento de Zafra, 924554601, para preguntar por el certificado de número de gobierno de la vivienda donde vive en alquiler Beatriz. Me facilitan el teléfono de la persona que lo gestiona, José Pachón (extensión 2012). Quedan en llamarme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-09-14','TERESA Comunicarte que Aitor desde hoy se encuentra trabajando como monitor de una ruta escolar en el IESO de Alcántara, con un contrato de nueve meses y un salario de 466 euros, lo que no te puedo especificar es si son brutos o netos. Respecto a la vivienda la situación es cada vez más insalubre. ME PONGO EN CONTACTO CON LUIS MARTINEZ SUPERVISOR DE ACOMPAÑANTES EN EL TELFNO 671 09 97 63 PERO ME SALTA EL BUZON LE MANDO CORREO LUISMARTINEZ@EXTERNASERVICIOS.NET Mi nombre es Teresa, soy la trabajadora social de la comisión tutelar de adultos de la junta de Extremadura. Me dirijo a usted porque tenemos conocimiento que han formalizado un contrato como acompañante de transporte escolar para la ruta de Navas del Madroño a nombre de Aitor Moreno Felipe con DNI 76744854H Esta persona se encuentra a cargo de esta comisión tutelar por sentencia de incapacitación, dicha sentencia le incapacita para tomar cualquier decisión en cualquier ámbito de su vida por lo tanto no puede formalizar un contrato de trabajo ya que su firma no tiene validez y por lo tanto el contrato es nulo de pleno derecho. Esta persona se encuentra tutelada, además tiene discapacidad y se le prestan medidas de apoyo para todos los ámbitos de su vida (laboral, económico, sanitario, etc.) Ruego se ponga en contacto conmigo a la mayor brevedad posible ya que consideramos que el perfil que presenta Aitor no es idóneo para prestar este servicio, ya que no puede supervisar menores de edad cuando él mismo está bajo nuestra supervisión por las dificultades que tiene, además el contrato que le han hecho no tiene validez alguna legal por la situación jurídica en la que se encuentra Aitor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-09-14','TERESA ARCHIVO RESOLUCION GRADO DE DEPENDENCIA (GRADO I)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-09-14','miguel, enviamos por lexnet (ines) comunicacion al juzgado nº2 Caceres la imposibilidad de contactar con el tutelado, y se adjunta justificantes de que recibió la comunicación por sms de la citación, así como el informe de agosto e email de futuex indicando la imposibilidad de tratar con él y su hermano Tomas, por lo que solicitamos que de oficio el jzdo dicte las medidas de oficio que considere ante la imposibilidad de ejercer el cargo de tutor del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-09-14','Ana: Correo de Toni-Futuex, del día 8, al ctutelar@ y al mío: "Buenas noches, adjunto envío la nota de lo sucedido hoy respecto al fallecimiento de Ángel marido de Desideria. De forma inesperada, se desconocen las causas por el momento, le van a practicar autopsia, al parecer. Tanto mis compañeras de equipo q gestionan el caso, como yo misma, estamos de vacaciones, hasta la semana próxima no se podrá hacer, en el caso de verse necesario, un seguimiento en Plasencia para ver a Desideria. Estos días, parece que va a contar con el apoyo de la familia pero tendría q gestionarsele un apoyo más intenso a partir de ahora, porque aunque era habitual que tuvieran delirios compartidos, el al final era un apoyo funcional para la tutelada. Ha tenido plaza en el sociosanitario, no sabemos muy bien en qué sigue eso, porque llevaban sin ir desde la pandemia, pero tal vez sería una opción. Cualquier cosa, estamos a disposición y la semana que viene abórdamos seguimiento." ·············· *Guardo nota en el expte. digitial. ····················','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-14','miguel, recibo email de Amelia: Miguel, te mando el expediente de tasación, ahora hay que autorizar el precio mínimo de venta, como la tasación ha sido más de 50.000 euros, yo propondría la venta como máximo entre 25/30.000 euros para que sea más fácil venderla... Pienso que la venta es la mejor opción xq una vivienda cerrada se estropea más que utilizándola y sería necesario que alguien estuviera pendiente de reparaciones. En cuanto pueda, vuelvo a contactar con la notaría de Brihuega, cómo van los trámites con los abogados de Guadalajara? ***************************************************** Contesto a Amelia: Buenos días, no se puede vender en menos de la tasación. La autorización que el juzgado nos dé será mínimo la de la tasación. Se la reenvío a la abogada Mª Teresa Muelas Mazario que esperemos pueda llevar el caso. ***************************************************** Reenvío la tasación a la abogada Mª Teresa Muelas, mtmuelas@icaguadalajara.org: Buenos días Mª Teresa, adjunto la tasación para la solicitud de autorización judicial de venta que habrá que hacer. Buenos días Mª Teresa, adjunto la tasación para la solicitud de autorización judicial de venta que habrá que hacer. Quedo pendiente me indique los datos del procurador y en qué juzgado de primera instancia se presentará la solicitud de aprobación de herencia y la autorización de venta. Si necesita depósito conforme los honorarios que nos indicó en su email, dígamelo indicándome nº de cuenta y concepto. Quedo pendiente me indique los datos del procurador y en qué juzgado de primera instancia se presentará la solicitud de aprobación de herencia y la autorización de venta. Si necesita depósito conforme los honorarios que nos indicó en su email, dígamelo indicándome nº de cuenta y concepto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-09-14','Ana: Llamada de Rosa, Serv. Protección Menores de SS.TT.- CC (64851), habla con Teresa, TS CTAEX: le comunica que Juan José se queda ya a vivir en el domicilio familiar a la espera de recibir plaza en C. Discapacidad. *Han tomado la decisión unilateralmente en SSTT, pues ese no es el acuerdo al que se había llegado. Dicen que ya no puede regresar al CAM. ·································································································································································································· Óscar, secc. ecca., me confirma que a Juanjo le están ingresando la PNC solicitada desde el mes de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2022-09-14','Ana: Maite, Jefa Secc, envió la semana pasada el CI para Extracción Dentaria, remitida por Rosa Bravo, Admvo. del CSS-Plas. ·············· Hoy remito yo a Rosa el CI para la Cirugía Dermatológica con Anestesia Local firmada y sellada por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-09-14','miguel, recibo contestación de la abogada Carmen Lucas: Miguel, yo no he recibido ninguna carta del defensor del pueblo, de otro lado yo llevo la defensa, no tengo porqué seguir instrucciones del defensor del pueblo, el informe forense es muy claro no se hasta qué punto tengo que tener al cuello en un proceso al defensor del pueblo, que asuman ellos la defensa, una cosa es velar por la legalidad y otra convertirse en el Director de mi trabajo. Lo que quieran que me lo digan a mí, pero no estoy dispuesta a esto. En relación al tema civil, yo no sé nada. Te llamé y no estabas, estoy cansadísima de este control que tienen, los hermanos, la madre, el Defensor, creo se están pasando. Que nombren a quien quieran de Abogado, pero no se puede estar encima y pedir datos de continuo, de algunos trámites incluso que no se han realizado, y una y otra vez, no sé hasta qué punto tengo que ser la Procuradora del Defensor del Pueblo, es que es una extralimitación, a mi juicio. *************************************************** la contesto: Gracias Carmen, disculpa que estamos entrando y saliendo de la oficina. Te entiendo perfectamente. Simplemente la comisión al ser temas estrictamente procesales los que comunica el defensor del pueblo, nuestra obligación es comunicártelo. A ver si pronto se resuelve con éxito el procedimiento','2');
