insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-09-14','miguel, llega físicamente la documentación enviada por la hermana del tutelado, Mª Josefa (marijoazkoitia@gmail.com), consistente en facturas, impuestos de sucesiones, y movimientos de las 3 cuentas Banco Popular, Sch, y Bankinter. Tras revisarlo con Oscar, le envío un email para su que hagan una transferencia para compensar los gastos de herencia de los padres: Buenos días, desde la cuenta de José Luis Murillo Horrillo hay que hacer una transferencia a la siguiente cuenta de Bankinter nº 0128-0353-26-0100021932 cuyos titulares son Mª Josefa, Inés, Andrés Murillo Horrillo Importe: 1.105,23€ Concepto: Abono de deuda de herencia de padres de Jose Luis Murillo Horrillo Cuando tengas hecha la transferencia envíame el justificante para enviárselo a su hermana Mª José.','2');
