insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-09-14','Ana: Envío a Julio, Aux. Adtvo., oficio solicitud de Cdos. actualizados de las P. de Viudedad y Jubilación, para que le de registro en SIREX. ···························· Envío a la a registro (oac.merida.san@juntaex.es): COMUNICACIÓN DE MODIFICACIÓN DE DATOS BANCARIOS, para que le den REGISTRO DE ENTRADA a la Dirección Provincial del INSS-CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-09-15','miguel, recibo email de Angela (inmobiliaria)comunicando que venderán la vivienda el 26-9-22: Buenas tardes! Respecto a la propiedad de D. José Lara de Villajoyosa (Alicante) informarle que tenemos la cita para firmar la escritura de compraventa el veintiséis de septiembre a las 11:00 de la mañana en la notaría de Villajoyosa de D. Juan G. Giménez Giménez, ya nos comenta usted la notaría en la que estará para firmar por ratificación, el comprador hará cheques bancarios con la parte de cada uno, los honorarios de la inmobiliaria se descontarán del total, ya le aportaremos factura, cualquier duda comentamos. Saludos Ángela Domenech API 798 GRADUADO SOCIAL C/ Barranquet, 2 (03570) VILLAJOYOSA TELF. 966853066 / 609155518 Info@grupo2inmo.es ************************************************* Mi contestación: Buenos días, nadie de la notaria se ha puesto en contacto con nosotros. Es necesario que nos envíen el borrador de la escritura para comprobar previamente las condiciones de la venta, sin lo cual no podemos ratificar. Por otro lado es necesario que la forma de pago del tutelado se haga a través de transferencia a su cuenta personal, no podemos aceptar cheques. Una vez que tengamos dicha información la notaria de Villajoyosa tendrá que indicarnos a cuál de los correos corporativos de los 3 notarios que hay en la notaria de Mérida enviaran la escritura para poder ratificar en la misma mañana.','2');
