insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-09-14','Maite: he hablado con la trabajadora social de la casa de la misericordia de Alcuéscar para concretar el dia de ingreso de Pablo. Me ha dichoq que el director no está hasta la semana que viene y hasta que no vuelva no se puede hacer. Nos llamarán ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-09-15','-Amalia : información sobre renovación renta extremeña garantizada y trámites realizados. Informo a los compañeros. Buenas , fijaros el documento que ha presentado Ana Rosco Avalos para renovar la renta extremeña garantizada . Os comento , a petición del servicio de Renta , que ya habló también con Angel para ratificar la firma de esa solicitud , he realizado diversos trámites . A requerimiento de ese servicio le han pedido para poder tener derecho a renovar su prestación : -Solicitud CADEX , para valorar su discapacidad. -Solicitud PNC . -Solicitud Ingreso Mínimo Vital . Todo ello está ya tramitado y registrado , era condición obligatoria si no ,deniegan la solicitud. Pero como ella se niega a hacerlo , se ha pedido como representante legal , ella no sabe nada , porque no podemos contactar y no atiende a ningún requerimiento ( ni siquiera el judicial ) Podría ser que perdiera Renta Extremeña si le conceden algunas de las que le he pedido y que económicamente son algo inferior , aunque tienen otras ventajas. *************************************************** contestacion de Angel: He leído, o al menos, intentado leer, el documento de marras. No deja títere con cabeza. Según ella, la documentación que le piden ya la tiene la Administración. Reclama cantidades impagadas, desde que presentó sus solicitudes de Renta básica extremeña e Ingreso Mínimo Vital y que ambas son compatibles. Por mi parte, envié escrito de Ratificación de la solicitud de Renta Básica Extremeña que presentó, para que no nos pasara lo del año pasado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2022-09-15','miguel, ha llamado la madre del tutelado, Teresa Barco; teresa.barco@hotmail.com; 924-230543 y 659064628, para preguntar cómo va el tema de la renuncia de herencia del padre. La indico que diga a Ruth (la abogada que ha llevado el trámite de la herencia de los hermanos) que se ponga en contacto con Angel por si le hiciera falta algún documento','2');
