insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2022-09-16','Ana: correo del día 14 de Máximo Pereira Serrano, sobrino de Agustín (maxperser@hotmail.com) al ctuterar@: "Buenas tardes. Me llamo Máximo Pereira Serrano, sobrino del tutelado por ustedes Agustín Serrano Muñoz. En la casa de su propiedad en Aldeanueva de la Vera se han producido unas goteras que han causado daños a un negocio sito en ese mismo edificio. Consultado con un albañil haría falta contratar una grúa para tener acceso al tejado y desatascar el canalón causante ,en principio, de las goteras. Además necesitaríamos contratar a una persona para limpiar los desperfectos. Por favor ¿nospodrian decir que es lo necesario para contratar dichas reparaciones y abonarlos a cuenta de Agustín Serrano? ¿Si contratamos a una persona para la limpieza podría justificarse con un recibo o algo distinto d una factura.? Muchas gracias y un saludo Mi tlf 660946698". ·························· Mi respuesta: "Buenas tardes Máximo, Lo primero que necesitaríamos sería un informe del Albañil en que se indiquen las reparaciones necesarias así como un presupuesto para la valoración y aprobación por la sección económica. Para la limpieza también sería necesario un presupuesto. Lo ideal es que se encargara una empresa. Si finalmente no fuera posible y la llevara a cabo una persona física, tendríais que indicarnos el coste y necesitaríamos una declaración jurada de dicha persona indicando sus datos, el servicio realizado, el precio y la fecha, anotando también el nº de cuenta para abonarle mediante transferencia bancaria. Ante cualquier otra duda puede volver a contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-09-16','Ana: Correo de Icíar, desde el ctutelar@: "Me ha llamado la cuñada de Desideria Barbero, hermana del marido, (Maite 686 641 770- 943.11.61.93), necesita urgentemente hablar contigo. Desideria vivía en Plasencia con su marido, el marido ha fallecido el día 8 de septiembre, me dice que cree que ha estado con el cuerpo del marido muerto dos días. Ha intentado ponerse en contacto con nosotros pero no lo ha conseguido, ya le he dicho que las dos hemos estado de vacaciones. También me cuenta que ha hablado con Gloria de Futuex , no sé si te habrán pasado algún correo con la situación. Está muy preocupada porque Desideria debe estar sola y en malas condiciones en la casa." ············ Maite, Jefa Secc. CTAEX y yo llamamos a Maite, cuñada de Desideria. (Hermana de Ángel). Asegura que su cuñada está mal y no tiene capacidad para vivir sola, teme que le ocurra algo a ella misma o ponga en riesgo a los vecinos (se olvida las cazuelas en el fuego). También ha descuidado su aseo y no se viste acorde a la temperatura que hace. Al funeral acudió con un plumífero a pesar del calor que hacía y no consintió en quitárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-09-16','Ana: Desideria cumple 59 años en unos días. Tiene reconocido un grado del 50% Discapacidad. Según Dictamen Técnico presenta Esquizofrenia Catatónica y Pérdida total de audición en un oído. ············ Tiene reconocido Grado II de Dependencia, pero el expediente está inactivo. En su día no aceptó el PIA de SAD. ············ *Rechaza todo tipo de apoyo y recursos: SAD, TAD, SAR, CRR...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2022-09-16','Ana: Correo de María Gía, Directora de la Res. Francisco de Asís (centrofranciscodeasis@gmail.com): "Buenos días Ana, Te escribo en relación a la situación de Inés Muñoz. Como te comenté tuvo una fractura en la meseta tibial, el médico decidió no operar e inmovilizar con férula para ver si soldaba por sí sola. Ha estado hasta el 30 de agosto con dicha férula y ha soldado bastante bien pero al quitársela le había producido una escara en talón de grado 2 que con ayuda de la enfermera va mucho mejor, no ha cerrado aún del todo, pero va progresando. Ahora con lo que nos encontramos es que no quiere levantarse por miedo a caerse y debe ir andando un poquito. La pierna la mueve fenomenal y no se queja de dolor pero nos cuesta muchísimo que aguante 40 segundos de pie y nos da miedo que esa inseguridad le impida volver a su situación normal. Volvemos a revisión el 4 de octubre, donde le harán radiografía y le verá el traumatólogo. Mi pregunta es si existe la posibilidad de que un fisioterapeuta la viera ya que no le han mandado ningún tipo de rehabilitación pero creemos que la ayuda de este profesional sería muy conveniente para ella y para su recuperación ya que ayudaría en la movilización y, seguro, en caminar." ················ Solicito que nos remitan informe y presupuesto de Fisioterapia para su valoración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-09-16','Ana: Correo de Pilar Martin, TS ESM-CC (9/09/22): "se nos propone la derivación a la UDAC desde la Comisión de Valoración de Acceso a Recursos Residenciales. Ya hablamos. Un saludo." ······················ Respondo: "...como sabes, ya estuvo en la UHDAC, justo antes de ingresar en el CRR, si de nuevo se considera necesario (existe criterio clínico), su ingreso en dicha unidad, por nosotros no hay inconveniente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2022-09-15','Ana: Correo del 7/09/22 Cristina Castro, Ed. Vera (educadorasocial@asociacionvera.com): "Buenos días, El 19 de agosto Joaquín sufre una caída accidental asociada a embriaguez y rompe sus gafas de ver. Adjunto envío Incidencia de Joaquín Herrero Jiménez y factura de las gafas a abonar." ················· Guardo los documentos en su expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-08-04','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Buenas, me pongo en contacto en relación a Ceferino Mariscal. Como os habrá informado y comenté yo con Ana, tiene el teléfono con la pantalla agrietada. Aunque le funciona, resulta en ocasiones complejo de manejar. La fecha de la adquisición del último móvil es de Marzo de 2021. Aunque parezca próxima, creo que es la ocasión que más tiempo ha conservado un teléfono desde que está aquí. Por ello quería solicitaros un extra de 200 Euros para poder comprar un aparato nuevo (Readmi C254 o 10C). La verdad es que le da mucho uso al móvil y estos en concreto parece que tienen buenas prestaciones (según me comenta)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-09-19','Ana: Envío correo a Ceferino, desde el ctutelar@ (ceferinomariscalcrespo64@gmail.com): "Buenos días Ceferino, En vista de los numerosos correos de las últimas semanas, en los que expresas los continuos cambios de opinión (unos días pides la Play y otros la Pioneer), de momento no se va autorizar la compra de ninguna de las dos cosas. No obstante, cuando hablé con Paula hace unos meses, acordamos que abordarían esta cuestión contigo en el centro y se plantearía la posible compra asociada a los objetivos terapéuticos y a compromisos que establezcáis para este “nuevo curso” y nos informarían al respecto. Por tanto, primero, como te dijo Maite, deberías de aclarar tu preferencia, haciendo una lista de pros y contra de cada uno de los productos para definir bien cuál sería tu prioridad. Y segundo, cuando alguna de las profesionales del CRR nos comuniquen, por escrito, lo que habíamos hablado se procederá a valorar la autorización de la compra. Dicho todo esto, recordarte, que para la autorización final de la compra (visto bueno de Alberto, jefe de sección económica), nos tienes que enviar un presupuesto a tu nombre (si pudiera ser dos del mismo producto en distintas tiendas mejor). Pongo en copia a Maite, Carolina y Paula, para que están al corriente." ································································································································································································· Respuesta de Paula: "Hola Ana, buenos días. Hemos recibido tus correos en respuesta a demandas de Ceferino Mariscal. Si te parece mañana hablamos un ratito, te contamos un poco nuestra visión, pensamos conjuntamente y luego ponemos por escrito lo que hacer respecto a Ceferino: siguientes pasos, necesidades, proyectos, etc."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-09-19','miguel, llama la sobrina Raquel, y la informo que no se les puede dar ese dinero ya que dicho traspaso de dinero se hizo en vida de su madre Virgilia y por tanto sólo podrán reclamarlo vía judicial. Mientras ese dinero seguirá en la cuenta de nuestra tutelada Nemesia. ***************************************************** Envio email a Oscar y Alberto: Buenos días, me acaba de llamar la sobrina Raquel (hija de Virgilia y extitular de la cuenta con nuestra tutelada) Dice no saber nada del traspaso del dinero en vida de su madre(ya le he dicho que nuestra excompañera Juana anotó haber hablado con un familiar para comunicar dicho traspaso). La indico que tendrá que reclamar ese dinero vía judicial puesto que ese traspaso se hizo en vida de su madre y a fecha actual está a nombre únicamente de nuestra tutelada Nemesia. Os informo para que intentéis tener controlado la parte que pueda reclamar en el juzgado esta sobrina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-09-19','INTERNAMIENTO INVOLUNTARIO REPARTIDO AL JUZGADO DE 1ª INST. E INSTRUCC. Nº 7 EL 12/09/2022 Y CON Nº REGISTRO 4363/2022','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-09-02','Ana: Correo de Paula, TO CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Aprovecho para comentarte que la semana que viene apoyaremos a Isabel con la búsqueda de hotel y que estamos intentando trabajar que sostenga su autocuidado y protección, también en relación a mantener las distancias con la pareja de su madre. Nos dijo también que comería y cenaría con su hermana y que ésta contactaría contigo para que pudierais verificarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-09-02','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Conchi: pensamos que sería buen momento para iniciar los arreglos de su vivienda, puesto que vamos avanzando en el proceso en CRR y la idea es que pueda ir preparándose para el futuro. Así mismo no ha llegado al CRR la tarjeta de débito que se había tramitado por vuestra parte (sección económica). Lo comento por si os hubiera llegado a vosotras o bien verificar que no está en el buzón de su domicilio en Madroñera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2022-09-02','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "la próxima semana hace por fin el preoperatorio para realizar una prueba diagnóstica ginecológica (sospechas de posible patología tumoral). Iremos informando si nos dan mayor información."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-09-19','Ana: con respecto al último correo de Paula - CRR, anotado, solicito presupuestos para los distintos arreglos necesarios en la vivienda y paso a Óscar, secc. ecca., la consulta sobre la tarjeta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-09-02','Ana: Correo de Blanca, Directora CRR-Plas. (direccion.crrplasencia@grupo5.net) con copia a la secc. Salud Mental: "Os informo que Julia está verbalizando querer irse de alta, solicita su dinero y sus cosas. Estamos intentando contener la situación, pero es posible que en algún momento decida irse del centro. Si hay alteraciones graves y no hay ingreso procederemos como la semana pasada a una expulsión con apoyo para que se quede en hostal hasta que el lunes valoremos la situación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-09-15','Ana: Envío correo a Miguel, Asesor Jurídico: ", ¿es posible volver a comunicar todas las últimas incidencias a partir de esa fecha para unirlo al procedimiento que iniciaste? Pues son numerosas las que han acaecido este verano y no está de más que en el Juzgado sepan cómo está la situación y el riesgo al que se expone él mismo y al resto de residentes." ··································································································································································································· Respuesta de Miguel: "Hola, sí. Recapitula todas las incidencias pero no me las des hasta que en unos días nos digan qué juzgado y procedimiento le darán para el internamiento involuntario…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-09-19','miguel, envío email a Oscar para que proceda al abono de la 2º transferencia del dinero que debía el tutelado a los otros 3 hermanos por importe de 987,26€ (que unidos a los ya abonados de 1.105,23€ hacen un total de 2.092,49€)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-09-19','miguel, envío email a Oscar para que proceda al abono de la 2º transferencia del dinero que debía el tutelado a los otros 3 hermanos por importe de 987,26€ (que unidos a los ya abonados de 1.105,23€ hacen un total de 2.092,49€). Quedo con Mª Jose que hable con Nagore que me lo envíe Nagore. Me envía Nagore el borrador','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2022-09-19','Ana: Correo de Cristina, Asoc. Vera (educadorasocial@asociacionvera.com) en respuesta a mi consulta: "Joaquín acude al centro ebrio muy de vez en cuando, le retiramos la salidas autónomas durante un tiempo. El ya está bien y no le han quedado secuelas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-09-19','Ana: Renvío correo de Inés, TS CSS-Plas, a Óscar, secc. ecca.: "Me ha llamado la hija de María Jesús Martín, porque se casa su hermano y María Jesús es la madrina y hay que comprarle un vestido. Plantea Puerto que ella le puede adelantar el dinero y luego pasaros la factura para que sea la propia María Jesús la que se compre el vestido. Le he dicho que entendía que no tenía que haber ningún problema, en principio, pero que tenía que consultártelo." Pido que actualicen su ficha ecca. y den respuesta al CSS. ······························································································································································································ Correo de Óscar a Inés: "Buenas tardes Inés. Se autoriza el gasto para el vestido de madrina de María Jesús Martín. Por favor, enviadnos la factura para anotarla en el expediente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-09-19','Ana: Renvío correo de Inés, TS CSS-Plas, a Óscar, secc. ecca.: "Me ha llamado la hija de María Jesús Martín, porque se casa su hermano y María Jesús es la madrina y hay que comprarle un vestido. Plantea Puerto que ella le puede adelantar el dinero y luego pasaros la factura para que sea la propia María Jesús la que se compre el vestido. Le he dicho que entendía que no tenía que haber ningún problema, en principio, pero que tenía que consultártelo." ············ Pido que actualicen su ficha ecca. y den respuesta al CSS, indicando, en caso de ser viable, de qué cuantía puede disponer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-09-19','Ana: Llamada a Martín, al despacho de Inés, TS CSS-Plas (sustituta de Mariví): Martín expresa encontrarse bien, mucho mejor que la última vez que estuvo allí ingresado 3 años. Verbaliza "No puedo estar solo en casa". Se encuentra a gusto en URA. ········· En cuanto a la posibilidad de venta de alguna de sus dos viviendas, dice que no entraba en sus cálculos y no se lo esperaba. Creía que tenía más dinero en cuenta. Al explicarle la necesidad de venta debido a las numerosas deudas (algunas ya se han subsanado, otras aún no ha sido posible) dice que lo entiende pero no sabe cuál prefiere vender. Acordamos que lo va a pensar un par de día y hablará también con su hermano. Nos llamarán al respecto. ······· *Por otra parte, Inés nos recuerda la necesidad de comprarle ropa. ································································································································································································· A petición de Ángel, Asesor Jurídico, envío correo a Jesús, hermano de Martín (gjdpalencia@gmail.com): "Buenas tardes Jesús, ¿Qué tal estás? Te traslado consulta de mi compañero Ángel, Asesor Jurídico, en relación a la posibilidad de venta de la vivienda de la que tu hermano y tú sois copropietarios, copio textualmente: “¿Puede el hermano enviarnos la oferta formal que realice ese potencial comprador por escrito? Y al mismo tiempo, que nos informe del estado en el que se encuentre el embargo, amén de intentar nosotros investigar y preguntar por el en el Juzgado.” Ya nos dices cuando puedas. Gracias y buena tarde. PD: He hablado con tu hermano hoy y lo noto bastante bien. Le he preguntado su oposición acerca de la posibilidad de venta, pero no se lo esperaba. Hemos acordado que va a pensarlo un par de días y que también lo hablará contigo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-09-19','TERESA Genaro empieza hoy de nuevo con su trabajo de "espantapájaros", todo en las mismas condiciones que la otra vez Hacemos lo mismo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2022-09-19','Ana: correo de Óscar, secc. ecca. a Felisa Custodio, TS CAMF Alcuéscar, con copia a mí: "Desde la Comisión Tutelar de Adultos se ha solicitado el 31 de agosto a Dª. Fabiana García, por correo electrónico y por correo certificado, la devolución de la cuantía indebidamente cobrada por el acompañamiento de Rosario Solís Bermejo, que asciende a 480€. A día de hoy, aún no se ha regularizado la situación. Os lo comunicamos por si tenéis alguna otra forma de contactar con ella para darle una solución a esta situación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-09-19','Ana: Llamada de Elma, TS del Ayto. de Plas. (600 44 92 38): La semana pasada recibió llamada de Maite, cuñada de Desideria (hermana de Ángel Pérez Manzano) muy preocupada por Desi y por el hecho de que se quede sola. Le informo que Maite y yo hablamos con ella el viernes. *Expongo como está la situación y el rechazo por parte de Desi de cualquier Apoyo. *Hablará con María, TS del C. Salud e intentará acordar con ella una visita conjunta. ·········· *Intentaremos estar todas muy coordinadas en el seguimiento de Desi. ····································································································································································································· Envío correo a Toni-Futuex: "Buenos días, Muchas gracias por la info. Comunicado que el vienes hablamos con Maite, cuñada de Desi, expresa una gran preocupación por su cuñada y por el hecho que viva sola. Ya le expliqué la situación. En cuanto a esto, ¿con qué periodicidad tenéis pensado visitarla? Consideramos que ahora, si fuera posible, debería de visitársele al menos una vez a la semana, hasta que se vaya viendo su evolución. *Y se aborde con ella, que sabemos que no es fácil, la necesidad de aceptar algún tipo de apoyo como la Ayuda a Domicilio y Teleasistencia, sobre todo si sigue sin querer acceder a algún recurso residencial. Comentaros también que hoy he hablado con Elma, TS de Servicios Sociales Municipales y ésta intentará acordar y realizar una visita conjunta con la TS del Centro de Salud. Me mantendrá informada. Con respecto a vuestra propuesta: “Una cosa que creemos que podria valorarse... siempre y cuando fuera factible, y lo consideraran desde su ESM es que pudiera tener la medicación inyectada, y asi, hacerlo coincidir con el acompañamiento para retirada de dinero (que si lo aprueba la comsion, seria dos al mes) y daria margen de intentar este acompañamiento y garantizar que se toma la medicación. No sabemos si por el tipo de trastorno o por otras circunstancias seria una paciente para este tipo de medicación. Por esto os lo hacemos llegar, para que si se considera, se pueda dar traslado desde la comisión a su ESM”, tengo pendiente hablar aún con Ana Benavente, TS del ESM así como con la sección económica. *Por otra parte, vamos a solicitar el certificado de Defunción de Ángel para poder pedirle la P. de Viudedad. Seguimos en contacto. Buena semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-09-19','Ana: Se ha matriculada en la CEPA, comienza mañana, en horario de mañana, hoy ha acudido a la presentación, de momento le ha dado buena impresión, está contenta. ··········· Pregunta por la salida a su casa, le comunico que en el CRR ya tienen la respuesta, pero se ha aprobado y podrá retirar 150€ a tal fin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2022-09-19','Ana: Óscar, secc. ecca., me facilita información acerca de situación ecca, de Inés: "Tutelada tiene 4 cuentas y un depósito en UNICAJA: - ES4621037706400030004149: Titulares OK. Ingreso pensión orfandad 767,50 €*14. Cargos: decesos. SALDO: 32332,17€. - ES61 2103 7706 4000 3000 1357: Titulares OK + Manuel García Alías (primo). Se incluyó a Manuel en la cuenta para gestionar la venta de un ganado de hermano muerto. Sin ingresos. Cargos: agua de vivienda de hermano y gastos tutelada. SALDO: 2366,24€. - ES65 2103 7706 4100 3000 0072: Titulares OK + Miguel Muñoz Alias (hermano). Sin ingresos y sólo cargos hermano (seguro y OAR) SALDO: 12004,52€. - ES13 2103 7706 4300 3000 0134: Titulares OK + Miguel Muñoz Alias (hermano). Sin ingresos y sólo cargos tutelada (centro) SALDO: 19353,13€. - 21037706 49 0020014745: Depósito 60.101,21€. Titulares OK + Miguel Muñoz Alias (hermano) Situación eco estable. Parece ser la única heredera hermano fallecido (soltero). Los otros hermanos fallecieron antes de cumplir el año de vida. Hace años se interesaron por la compra de las viviendas, pero no tenemos nada en el expediente. Antes de ser tutelada se debió realizar la herencia de los padres, ya que se pagó sucesiones. De la herencia del hermano no hay nada hecho."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-09-19','miguel, enviamos por lexnet oficio comunicación incidencias de contrato laboral que ha sido anulado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-09-19','miguel, via lexnet desde abogacia comunicacion del juzgado indicando la incomparecencia del tutelado al forense. Contestamos mediante oficio por lexnet ratificando la comunicacion anterior e incorporando la documentación remitida en su día donde comunicabamos la imposibilidad de contactar con el tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-09-20','miguel, recibo email de Ainés comunicando a la abogada Ana de Pablo que prescinden de sus servicios e indicarme que cualquier tramitación ha de hacerse con la familia: Buenas tardes Miguel, por la presente te solicito que toda gestión en referencia a éste expediente se tramite sólo con la familia. He solicitado a Ana de Pablo prescindir de sus servicios, y así se lo he comunido a través del WhatsApp. Le hemos preguntado hoy, por última vez, y todavía seguía afirmando que estabaa la espera de contestación por vuestra parte para el abono, cuando no se había mandado ninguna liquidación, ni constatacion documental de éllo .... En fin, podríamos haber estado a si otro año... ! : Buenos días Ana, te comunico mi decisión de PRECINDIR DE TUS SERVICIOS PROFESIONALES, puesto que están siendo inexistentes. No es de rigor profesional no informar a una cliente de las gestiones que estás llevando a cabo en referencia al procedimiento hereditario para el que se es contratada, ni responder a ningún tipo de medio por el cuál nos estamos intentando poner en contacto contigo; teniendo en cuenta además, que no ésta no la primera vez que ocurre, sino que viene siendo la tónica de actuación en más de una ocasión por tu parte desde el inicio, hecho que ha dilatado y retrasado la finalización del procedimiento. Me ha sido constatado la falta de actuaciones, tanto en ésta ocasión como anteriormente por Miguel A. Fernández de Llera, Asesor jurídico del Área Jurídica de la Comisión Tutelar de Adultos de Extremadura, el cuál tramita todo lo referente al expediente tutelar de nuestro hermano José Luis. Ésta falta de rigor profesional ha derivado en el retraso en la finalización del procedimiento, con las consiguientes consecuencias negativas en muchos ámbitos a nivel familiar. Desde primeros de julio (y anteriormente en muchas ocasiones) te hemos llamado por teléfono, preguntado a través del whassap en varias ocasiones, haciendo caso omiso a nuestras consultas hasta día de hoy, alegando diferentes ocupaciones, enfermedades, situación COVID,..etc, etc.... Ante éllo me he puesto en contacto con Miguel A. Fernández, y nos ha constatado que NO se le ha envíado ningún tipo de liquidación ni documentación al respecto como para proceder a liquidar/abonar como nos indicaste en tu último whassap de fecha 19 de julio del presente. ¿Cómo van a proceder a abonar algo que no tienen conocimiento si no se les ha enviado? ¿Cómo nos indicas que se está esperando a una respuesta/abono de la Comisión Tutelar, luego comunicar los interesados en el procedimiento que se está a la espera de respuesta a algo que no se ha llevado a cabo? A parte de los perjuicios que ésto nos supone a nivel familiar, creo que es poner en evidencia el rigor profesional de otros profesionales que son parte del procedimiento. POR MI PARTE, procedo a seguir con el procedimiento por mi cuenta y riesgo, como he venido realizando en más de una ocasión al no sentirme representada a título particular, y esperando que no se me pasen los honorarios por unos servicios no acometidos que han redundado daños y perjuicios a título personal y familiar, un saludo. AINES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-09-19','miguel, recibo email de su tía Amelia: Buenas tardes, Miguel, lo podemos hablar pero imagino la conversación al respecto. Entiendo que se haya pedido una tasación y que ésta se pueda ajustar, probablemente si llamo al tasador la pueda retocar un poco al alza y a la baja pero eso serían unos pocos miles de euros, en el mejor de los casos. La cuestión es que se puso a la venta la vivienda hace varios años por el importe aproximado del valor catastral, 40.000 euros y no hubo interesados, dos personas fueron a verla y como se trataba de familiares, se les habló de negociar el precio, por 25.000 euros se la habíamos vendido pero no aceptaron porque implicaba, en su caso, derribarla y hacerla nueva, y eso incrementaba mucho el precio final. Creo que por cómo es la vivienda y dónde está situada, el precio de 25/30.000 euros es un buen reclamo para compradores porque es una oportunidad, pero veo difícil, muy difícil, venderla por el valor de tasación. Implica que alguien la derribe para construir de nuevo o la rehabilitación integral de la misma ya parte con un valor muy alto de adquisición. Entiendo que no queráis la opción de alquiler porque supone para vosotros muchas complicaciones y además yo tendría también que echaros una mano en esas gestiones. El resumen es que debido a toda ésta burocracia, me imagino presenciando en no demasiado tiempo, el deterioro grave de la vivienda de mis abuelos,(coincide además que es dónde yo nací), y que probablemente presencie hasta cómo se hunde… Porque si no se vende, alguien tiene que estar pendiente y visitarla regularmente para subsanar los desperfectos que se vayan produciendo y volvemos otra vez a pedir presupuesto y autorización para acometer esa reparación urgente y seguimiento en mi caso, de esa reparación porque no hay más familiares que muestren ningún interés por la vivienda y lo que es peor, por sus familiares incapacitados. Discúlpame pero tengo la sensación que todo el esfuerzo en gestionar la aceptación de herencia y todos los demás trámites no están sirviendo para nada ***************************************************** mi contestación: Buenos días, entiendo perfectamente lo que comentas pero no depende de la actuación de la Comisión. Como te comento se requiere por ley (artículo 287 CC) pedir autorización judicial para vender, y entre los requisitos que tendrá que aportar el abogado se requiere la tasación, que sirve de referencia para la decisión del juez. Al ser una prueba de parte, no tiene sentido que perjudique a quién la aporta por cuanto si se indica que vale 40.000€ y según indicas no se venderá por más de de 25 o 30.000€, una de dos o se cambia la tasación o habrá de justificarse al juez con otro informe de perito que no vale más de esa cifra. Si quieres lo comentamos como te dije, pero desde la Comisión no podemos hacer nada más que ponerlo en manos del abogado y la resolución judicial como es lógico será de obligado cumplimiento en caso de que coincida (como viene siendo siempre)con el valor que se indica en la tasación. Intenta si lo crees preciso hablar con el tasador para intentar modificarla a la baja, es todo lo que puedo decirte.','2');
