insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-09-28','miguel, envío email a Angel: Hola compi, ha llamado Coral 618817695 preguntando como va el trámite. Y según veo sigue igual, queda pendiente tras la presentación de la demanda de aprobación de herencia en el juzgado de 1º instancia de Villafranca de que le asignen procedimiento (sólo hay un juzgado allí). Por favor pregúntale a Angel Calle si sabe algo nuevo para estar encima de que resuelvan en el juzgado lo antes posible','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-09-27','Se llama al Servicio Común de Ordenación Civil para preguntar en que estado se encuentra el procedimiento ya que nos urge la venta, pues a M. Angeles ya no le queda dinero. Me contestan que el retraso que lleva el procedimiento es debido a que se ha acumulado al proc. 243/22, pero que ya tienen fecha de señalamiento que se ha fijado para el próximo día 16 de enero de 2023 a las 9:15 horas, y que recibiremos la diligencia. Por tanto el procedimiento es X15 AUTORIZ JU DISP BS/D 243/22, del Jzdo de 1º instancia e instrucción nº3 de Caceres','2');
