insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-09-28','Ana: Envío correo a Marcelino Sánchez Ruano, TS de Vivienda de CC (927 00 14 32 / marcelino.sanchez@juntaex.es): "Buenos días Marcelino, Tal y como acordamos ayer, mediante conversación telefónica, te adjunto Cdo. Literal De Defunción del padre de Aarón Rosado Alarcón, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura. Así mismo, adjunto documentos relativos al propio Aarón, para acreditar su situación: - Certificado de Ingreso en Centro Residencial para personas con Discapacidad Intelectual - Testimonio aceptación del cargo Hacer constar que ni Aarón, ni el Gabinete Técnico de la CTAEX en su representación, solicitan la subrogación del derecho a la vivienda en que residía el padre. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-09-28','Ana: Llamada de Isabel de Cáceres, madre de Alfonso (680 784 490): Ayer Alfonso acudió a su cita con la Psiquiatra en el ESM-Plas., todo bien hasta que salió de la consulta y comenzó a demandar a su madre una consola. *No le dieron informe médico a la salida de la consulta. ················ Dice que hacía mucho que no se ponía tan borde y no la amenazaba. Lleva un estilo de vida muy sedentario, está engordando mucho, pesa en torno a 150 Kg, no camina ni hace nada, no sale de la habitación, fuma mucho y come demasiado. Le dijo que le iba a dar un infarto y la culpa la iba a tener ella. Le demanda también ir a vivir a Madrid, ella le explica que no se lo pueden permitir. ··· La asignación (490 €/mes) se la da integra a primeros de mes y "se lo gasta todo en tabaco y porros". ··········· *Me pasa con él. Pide ir alquilar una habitación en Madrid para ir a pasar allí u mes, le pregunto para qué quiere ir a Madrid y responde "para divertirme". Le pregunto en qué invierte el dinero que se le da y no quiere decir en qué, expresando finalmente "con lo que me dais me limpio el culo". ······· Dice también que le robamos, que él tiene mucho dinero, que él trabajó mucho años en muchas empresas y qué si no he visto su CV. ·········· Dado que comienza a elevar demasiado la voz y el tono y que su actitud es exigente y desafiante, se decide dar por finalizada la conversación tras habérselo comunicado previamente y haberle pedido respeto al hablar, nadie se lo ha faltado aún a él. ····· A la madre la llama mentirosa y le grita también. ·································· *Nueva conversación con la madre: Confirma que no ha trabajado nunca. Que los problemas comenzaron cuanto Alfonso tenía 14 años. A los 15 le diagnosticaron. Cuando tenía 19 años falleció su marido de cáncer. ······ Con Gloria de Futuex, Alfonso apenas a tenido contacto, se niega, se queda encerrado en su habitación y en las pocas interacciones se cierra en banda y presenta una actitud inadecuada. *Se muestra muy preocupada por la salud de su hijo y no consigue ponerle límites ni que salga de casa para caminar ni relacionarse con nadie. *En su familia hay antecedentes de patología mental. ········ Tiene otros 4 hijos que no la presentan. ······························································································································································································ Envío correo-respuesta a la Dra. Mª Jesús Gutiérrez, Psiquiatra ESM - Plas. (mariajesus.gutierrez@salud-juntaex.es): "Buenas tardes Mª Jesús, Muchas gracias por mantenernos informados de la asistencia a las citas relativas a ALFONOS MARÍN DE CÁCERES. Agradecería que cuando pudiera, nos hiciera llegar Informe Clínico sobre su estado actual. Precisamente esta mañana he recibido llamada telefónica de Isabel de Cáceres, madre de Alfonso, manifestando que ayer, justo al salir de la consulta, Alfonso se puso “muy borde” con ella y exigiéndole que le “comprara una Consola para jugar en su cuarto”. Me ha pasado con él y durante la conversación ha mantenido una actitud exigente, desafiante, con muy malos modales y utilizando expresiones de mal gusto. Dice, así mismo, algunas cosas que, entiendo, obedecen a su patología, como que él tiene mucho dinero en la cuenta porque ha trabajado y cotizado muchos años y que si no he visto su Currículum. Su madre corrobora que él “no ha trabajado nunca”. Refiere también que toda la asignación que tiene aprobada mensualmente desde el Gabinete Técnico de la CTAEX, se lo queda él y se lo gasta todo en consumo de “tabaco y porros”. Por lo demás, no hace ningún tipo de vida social y tiene un estilo de vida nada saludable, apenas sale de la habitación, come demasiado y no precisamente de forma saludable, no hace ningún tipo de ejercicio físico y ya pesa en torno a los 150 kg. Isabel teme por su salud, también en este sentido, y que pueda darle algún día un ictus o infarto. Él, siendo conocedor de esta preocupación, le ha dicho hoy mismo que le va a dar algo y va ser por su culpa. La mayor parte de las veces que Gloria, Educadora del Programa de Apoyo Comunitario, asiste a su domicilio para hacerle seguimiento, él no quiere salir de dormitorio y no habla con ella y las pocas interacciones que ha tenido ha mantenido, según su propia madre, y las notas informativas de Gloria, la misma actitud que hoy conmigo y se cierra en banda ante cualquier posible intervención. Le informo de todo ello para que lo pueda tener en cuenta en sus próximas consultas. Un saludo, gracias y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-09-27','Ana: Envío correo-respuesta a la Dra. Mª Jesús Gutiérrez, Psiquiatra ESM - Plas. (mariajesus.gutierrez@salud-juntaex.es): "Estimada Ana, Le informo de que el paciente Alfonso Marin de Caceres, ha acudido a consulta en el dia de hoy, solo. Posteriormente he mediado conversación con la madre. En la conservación mantenida con la madre refiere que ella le da la medicacion oral. Se constata buena adherencia a la medicacion depot en su centro de salud. Se prescribe mantener tto. Se da cita en 3 meses para seguimiento. (coordino con Gloria, que acude presencialmente de Futuex) Esperando que esté bien, recibe un cordial saludo." ·················· Guardo el correo en PDF, en el expdte. digital. ························ *Próxima cita: 15/12/22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-09-28','Ana: Llamada de María, TS del CS San Miguel, de Plasencia (74638). Me comunica que Desideria ha acudido al CS para anular la cita que tiene el día 30 a las 8:15 h para hacerse una resonancia. Le pido por favor que no la anulen pediré intervención y si fuera posible acompañamiento a la misma al Programa de Apoyo Comunitario. ············· Me informa también que tiene cita telefónica con enfermería de Salud Mental programada para mañana. Le informo de que no será posible, pues desde el fallecimiento de su marido, no tiene ni quiere teléfono. Lo comunicaré tb para que le acompañen al ESM para comunicarlo y que a partir de ahora todas las citas sean presenciales. ······························································································································································································· Llamo a Toni-Futuex: No podrán acompañarla el viernes debido al horario. Pero irán mañana al domicilio a visitarla y abordarán esta cuestión. Intentarán acompañarla mañana al ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-06-30','Ana: Informe Social para la Rendición Anual: Alfonso mantiene el mismo estilo de vida sedentario y nada saludable que en el año anterior: come y fuma demasiado, no sale casi de casa, no se relaciona con otras personas, carece de amigos... Los seguimientos psiquiátricos no son regulares, se salta algunas consultas. Es reticente a acudir a las citas médicas, tanto especialistas como de Att. Primaria. *En general no habido variaciones en el último año, sus rutinas de vida son las mismas. *"Es muy difícil trabajar con esta familia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-09-28','Maite: He acordado con INCLUSIVES que el ingreso será el próximo 5 de octubre, miércoles. EL padre lo acompañárá. Irán en taxi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-09-28','miguel, se firma la venta de la vivienda de los padres en Villajoyosa, ante el notario Juan Guillermo Gimenez Gimenez Protocolo 1803 y ratifico la misma mañana ante D. Gonzalo Fdez Pugnaire Protocolo 1421','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-09-29','Ana: Remito a Julio, CTAEX, SOLICITUD DE REVISIÓN DEL GRADO DE DISCAPACIDAD DEL CADEX junto a toda la documentación pertinente para que le dé registro en SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-09-29','miguel, envio email a Amalia y Maite: Buenos días, me ha llamado Bego 924-846008 (Aseroría Jurídica de Banca Pueyo) para preguntar por cómo están los trámites para su ingreso. Me ha pedido que remitamos porque así lo ha pedido el juzgado un informe de cuándo, cómo y si es posible dónde se va a ingresar a la tutelada. Me consta que Amalia hablastes con SSB Montijo en Julio pero tenemos que saber qué avances hay porque quieren subastar la vivienda. Por la parte jurídica, hemos solicitado internamiento involuntario que está pendiente nos asignen el número de juzgado de Montijo y número de procedimiento. Quedo pendiente de vuestro informe para remitirlo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-09-29','Ana: Guardo en el expdte. digital el informe de seguimiento de junio, remitido por Gema, Ed. del CAM Fco. Pizarro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-09-28','Ana: Correo de Óscar, secc. ecca.: "Ya está hecho el reintegro permanente de 340€ a la oficina de Avda. de la Hispanidad de Cáceres (hablé con el centro y me dijeron que era la que estaba más cerca)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-09-27','Ana: correo de Teresa, TS CTAEX, a la Casa de la Misericordia: "Te comento la situación actual para que lo tengáis en cuenta en el proceso de adaptación. Pablo iba a la farmacia diariamente y allí le proporcionan el tratamiento farmacológico ya que él no posee habilidades para tomar adecuadamente el tratamiento. Desde el programa de apoyo social comunitario se encargaban también mensualmente de la pauta correcta del xeplion (inyectable cada 30 días). Última dosis fue el 5 de septiembre. Muy importante el seguimiento en la medicación, ya que si no la toma no tiene suficiente habilidades para mantener la adherencia y control de la abstinencia al alcohol. Con respecto al tema económico, se le ha dado dinero para que fuera con algo al centro. Uno de los gastos a contemplar para favorecer la estancia en el centro, es el dinero mensual pautado para tabaco. Actualmente corresponde a unos 80 euros mensuales aproximadamente Quedo pendiente que me indiquéis presupuesto de gastos personales para gestionar asignación así como necesidades a cubrir (ropa, calzado, peluquería, podología, etc.) Este expediente lo llevaba, una vez que tengamos todo cerrado ya el seguimiento lo hará mi compañera Ana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-09-28','Ana: Envío correo-e a Laura Salguero, TS ONCE CC (927 62 74 80 // LASS@once.es): "Te remito la solicitud para el viaje ya firmada digitalmente por el Presidente de la CTAEX. La sección económica, aunque con reticencias que ya te explicaré, ha aprobado el presupuesto para dicho viaje. Y al respecto de esto, quería preguntarte, ¿cuándo y de qué modo hay que proceder para abonar el viaje (transferencia, cargo en cuenta…) ya me dices cuando puedas. Agradecería por favor, eso sí, que le transmitas a Ventura, que los gastos de bolsillo para dicho viaje, sí que tendrá que asumirlos de su asignación mensual. Ante cualquier cuestión, no dudes en volver a contactar."','2');
