insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2022-09-29','llega informe social para cuando hagamos la revisión de sentencia. Envío email a la parte económica para que emitan un informe económico para poder solicitar la revisión de sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2022-09-29','Ana: Llamada de Isabel Pino, TS Ayto. de Miajadas (927 347 000 - Ext. 3216): Sabe que ha dejado de abonar el alquiler, y la Ayuda de la Junta que le concedieron como Víctima de Violencia de Género, debería haberlo justificado, pero no lo ha hecho. Se lo gasta todo. ················ **Me enviará Informe Social para la revisión de la Sentencia y solicitar nuevas Medidas Judiciales de Apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-09-29','Ana: Llamo de José Manuel (627 788 797): Le informo que puede ir a retirar de la farmacia el medicamento para ir al baño. ······· Informo también que el lunes podrá acudir con Virginia- Ed. Futuex, a retirar el extra de 200€ para comprar ropa. ··········· En cuanto al aumento de asignación que viene solicitando, le explico que si finalmente se le sube la asignación, no podrá podrá volver a solicitar ningún extra, tendrá que abonar todo lo que necesite de su asignación quincenal. *Así mismo, reitero que si en enero fuera necesario volver a contratar el catering privado porque no continúe el municipal, habría que volver a reducirle la asignación.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-09-29','Maite: Ana y yo hemos hablado con Juan Carlos.Las llamadas están fijadas cada quince dias los jueves a las 14:00h. Sigue manifestando no querer estar en ese centro. No le gusta pq no puede salir y no le dejan el móvil. Pregunta, como en llamadas anteriores, cuándo se va a ir a otro centro. También nos ha preguntado si vamos a ir a verlo a Mentalia. Nos dice que no está incluido en las actividades de la granja y el huerto. Hablaré con la trabajadora social para que me de información al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-09-28','Ana: Correo de Óscar, Secc. Ecca. a Toni-Futuex: "...Con respecto a la compra de ropa por parte de José Manuel, se va a autorizar un reintegro puntual de 200€. Necesitamos que nos digáis qué día y los datos de la persona que le va a acompañar a realizar el reintegro, para especificarlo en el escrito. ..." ··············· *Toni responde que le acompañará Virginia el próximo lunes día 3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-09-29','Ana: Correo de Cristina, Ed. Asoc. Vera, con nuevo informe, parte de incidencia, parte de lesiones y denuncia interpuesta ante la Guardia Civil. **Adrián ha agredido a otro usuario del centro. ············ *Lo remiten también a la secc. de discapacidad (UPA).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-09-29','Ana: Correo-respuesta de Toni de Diego, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "Hola Ana Pues la situación sigue casi igual. últimamente ha tenido dos altercados con dos residentes diferentes. Se le ha llamado varias veces la atención por pedir tanto tabaco como dinero, aunque ella no asume esta conducta, siempre la niega. Ella insiste en quererse ir a Castuera, y pregunta reiteradamente cuando se va a ir. Suele salir todos los viernes a comer, unas veces sola y otras veces con un compañero. Bueno su comportamiento mejora cuando tiene toques de atención por un tiempo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-09-30','miguel, contesto a Damian: Buenos días, adjunto justificante bancario del ingreso. Lo único que podemos comprobar es lo que aparece en el movimiento bancario. Dudo que el banco pueda decirle algo más, pero si quiere acérquese con el justificante que le adjunto de ingreso y a ver si al menos le saben decir qué juzgado de lo penal 2 es Mérida, Málaga, Plasencia? Es imposible localizar con las referencias que aparecen en el movimiento de cuenta el juzgado y el procedimiento al que pertenece este ingreso…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-09-30','Ana: Correo de Alberto, Jefe Secc. Ecca, tras nueva valoración y propuesta por mi parte: "ANA: OK A SUBIDA REINTEGRO QUE PASARÁ DE 132 €/QUINCENA A 165 €/QUINCENA ANA: ESTA SUBIDAD DEJARÁ DE TENER EFECTO INMEDIATO EN EL MOMENTO EN QUE VUELVA A ASUMIR EL PAGO DEL CÁTERING....VOLVERÁ A LOS 132 €/QUINCENA. ANA: LOS ESTRAS DEBEN ESTAR LO MÁS CONTROLADOS POSIBLES....SI SUPERA LO QUE HASTA AHORA SE LE ESTÁ DANDO DE EXTRAS (OTROS 100 €/MES APROX), TENDRÍAMOS QUE BAJARLE TAMBIÉN LA ASIGNACIÓN. OSCAR: MODIFICAR REINTEGRO PERMANENTE A PARTIR 01/10/2022----PASA A 165 €/QUINCENA OSCAR: YA HA HECHO ROPA: reintegro puntual de 100 € EL 01/10/2022, JUNTO CON EL PRIMER MES DE INCREMENTO DE REINTEGRO" ······························································································································································································· Ana: Llamo de José Manuel (627 788 797): Le informo que puede ir a retirar de la farmacia el medicamento para ir al baño. ······· Informo también que el lunes podrá acudir con Virginia- Ed. Futuex, a retirar el extra de 200€ para comprar ropa. ··········· Le comunico también que se le ha aprobado la subida de asignación quincenal, a partir del día 1. *Así mismo, le reitero, que si en enero fuera necesario volver a contratar el catering privado porque no continúe el municipal, habría que volver a reducirle la asignación. ············· Tuvo la cita el día 27, el Psiquiatra le cambió la pauta, pero dice que le ha sentado fatal, su hijo tuvo que ayudarle a subir a casa porque él sólo no podía. Ha dejado de tomarla. Ha llamado al Psiquiatra y le han dicho que luego le llamará. ··············· Pide un teléfono nuevo, se le ha estropeado el que tenía y está usando uno con el que sólo puede hablar. **Le explico que con la subida de asignación y el extra para ropa, tendrá que esperar. Se valorará para Navidades-Reyes. ················································· *Llamo a Paqui, Coordinadora del SAD-Eulen (629 557 324), le comunico que, dado que José Manuel tiene que ir a compra ropa el próximo lunes, pues la educadora no puede acompañarle otro día, no podrán prestar el servicio dicho día. *Avisará a la Aux.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-09-30','Envío correo a Toni-Futuex: "Buenos días Toni, En relación a MARÍA LUISA MONTAÑA ALISEDA, me informan desde la residencia, que a pesar de habérsele incrementado la asignación, de vez en cuando sigue pidiendo dinero y tabaco a otras personas residentes y generando algunas incidencias si se lo niegan. Queríamos pediros, que desde el programa de apoyo comunitario, sigáis abordando este asunto en la visitas, pues ahora debe tener dinero suficiente para sus gastos de bolsillo para sus gastos y, aunque sabemos que es difícil de modificar estas conductas aprendidas, no debe seguir molestando a otros residentes. Sabemos que demanda ir a la Residencia de Castuera, pero aunque hace meses que se solicitó este traslado, parece que van a tardar en materializarse, por lo que habrá que insistir también en que ha de tener paciencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-09-26','Ana: En relación a la propuesta-solicitud de autorización para el arreglo de la vivienda de Conchi (Sera en torno a 3.000 - 3.500 €, pendiente de actualizar el presupuesto que enviaron en febrero), Alberto Secc. Ecca. pregunta si es necesaria pedir autorización al Jdo. ········ Correo-respuesta de Ángel, Asesor Jurídico: "Dispone de una finca en Madroñera, al 100% de propiedad. Con respecto a la autorización del gasto, como siempre os digo, todo gasto que salga de lo ordinario, es extraordinario. Ahora, la práctica seguida en esta Comisión es que gastos menores de 3.000 euros, por economía y agilidad en la gestión y para evitar daños en los vecinos colindantes, en el caso que los haya, no pedimos autorización judicial. Una vez realizado el gasto, se justifica en la rendición correspondiete."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-09-30','Ana: Correo de Toni-Futuex: "De la resonancia que no y que no, q ella no tiene hacerse nada, muy muy reactiva. Pero del resto, pues medianamente bien, consiguieron que saliera de casa, se acercaron al centro de salud de su barrio, aunque a Salud mental no quiso ir . Ella dice que el día 10 de noviembre de la cita si va, pero antes no. Se acercó la compañera, hablo con la enfermera y con Ana B. le dijeron que quieren hacerle analítica para comprobar que se toma la medicación. El jueves va otra compañera para retirada de dinero, que intenten q vaya a analítica y sino atraves del centro de salud del barrio, san Miguel. Desde allí esperan que vaya a la cita programa del 10 de noviembre y esperan que sea Desideria la que acuda a salud mental, no plantean hacer mucho más por ahora. Que si desde la comisión se necesitan informes de seguridad psiquiatría que se soliciten por escrito, nos dijeron. Y que si se comprobará en analítica ;si se logra hacer, que no se toma la medicación.. q ya se valoraría otra cosa,,no nos dicen mas. Alomejor para este jueves , día 6, que Desi está avisada q va una compi para allá , se podría valorar pedir un extra e intentar comprar un móvil básico para uso de personas mayores, ya que el de ángel desi no lo usa, esta siempre apagado pero quizá comprando uno de nuevas sencillo y explicándolo lógrenos algo, para eso se tendría que liberar un extra de 150/180 eu o así." ······························································································································································································· Correo-respuesta: "En relación a la compra del móvil, estamos totalmente de acuerdo en la necesidad, pero puesto que ella no quería no se había contemplado comprarlo. pero si conseguís desde el programa convencerla para que lo tenga y lo utilice, nos parece perfecto. Pongo en copia a Maite, además de a Óscar, de la sección económica, para que, aprueben, que creo no habrá problema, la compra y realicen los trámites oportunos con el banco. Óscar, porfa, confírmale a Toni una vez lo hayáis valorado." ································································································································································································ Respuesta de Óscar, Secc. Ecca, a Toni: "Económicamente no hay objeción a la compra de un móvil para Desideria Barbero. Lo mejor sería que la tienda donde lo compre nos envíe la factura con los datos de Desideria y un número de cuenta para realizar la transferencia. Ya me decís"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-09-30','Ana: Correo de Sonia-Bernabé, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informaros que Felisa Bruno Saavedra ayer ingresó en la Unidad de Salud Mental de Cáceres. Llevaba varios días nerviosa, manifestando que quiere ir al médico a Cáceres por diferentes dolencias, que necesita la medicación de rescate porque quería pegar, escaparse,... Al estar así varios días y, a pesar de la intervención, no varia su estado anímico y la conducta se ha ido agravando por lo que la doctora la derivó a Cáceres para que la valoren en urgencias. Iremos preguntando estos días cómo se encuentra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-09-30','Ana: Correo de Ángel, Asesor Jurídico: "Acaba de enviarme el Juzgado la firmeza. Se lo acabo de reenviar a Inés, para que acepte el cargo de curador representativo." ································································································································································································· Se lo comunico a Verónica, TS SSASB Moraleja (927 90 11 14). ·········· Irán preparando la documentación para el inventario para enviárnoslo en cuanto reciban el oficio solicitándolo desde aquí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-09-30','Ana: Envío a Rosa Bravo, CSS, CI para administrar tratamiento de ACITRETINA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-10-03','Me informa una de las trabajadoras que ayer vio a M. Antonia en la feria y no se encontraba bien. …al parecer se había caído. He contactado con su prima y me lo confirma. La prima me comenta que no se pueden hacer cargo todo el día de M. Antonia. Esta mañana irá a curarse al centro de salud y después se irá de comida con los residentes de Plena Inclusión. Mañana tiene comida con los pensionista. El ritmo que lleva al final le pasará factura con la diabetes que padece. Por otro lado la hermana de M. Antonia muy preocupada por el estado de salud, no quiere que le autoricemos las salidas a Zafra. Te va a llamar por teléfono. También te informo que la prima de M. Antonia me dice que no le ha llegado el ingreso de los 150€. M. Antonia, según su prima no podrá irse de nuevo hasta el 1 de Noviembre. Sin embargo ella dice que vosotros le habéis dicho que cada 15 días se puede ir. Me imagino que serán cosas de ella. TERESA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-10-03','TERESA EMIAL MARISA TS VILLAFRANCA Se ha puesto en contacto con este servicio ADOLFO GARCIA CRUZ, con DNI 079260062S y que percibe PNC expte 0377/I/06 ya qu ha recibido carta en la que informan que se ha suspendido el pago de la PNC por no enviar en su día la declaración individual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-10-03','Ana: Correo de Rosa Bravo, CSS (rosamaria.bravop@salud-juntaex.es): "Buenos días Ana: Te adjunto la liquidación de la medida de seguridad de internamiento del paciente que fue trasladado al Centro Sociosanitario de Mérida, tutelado por esa Comisión. CIPRIANO M.B." ·············· "Medida de Seguridad de Internamiento en Régimen Cerrado en establecimiento adecuado a la patología que padece" Total de días = 731. Fecha de inicio: 01/06/2022 -- Fecha de cumplimiento: 31/05/2024. ·································································································································································································· Lo reenvío al CSS Mérida (csanitario.merida@salud-juntaex.es): "En relación al paciente, CIPRIANO MIGUEL BAZAGA, cuyo cargo ostenta la CTAEX, os reenvío correo con documentos sobre liquidación de la medida judicial que está cumpliendo en vuestro centro. Así mismo, por favor, cuando podáis remitid a mi compañero Miguel, Asesor Jurídico, y a quién pongo en copia, Certificado de Ingreso en Centro para que él pueda remitírselo al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-10-03','miguel, Ana nos remite email del CSS Rosa adjuntando la liquidación de condena de la ejecutoria 268-22 del jzdo de lo Penal 1 de Plasencia, hasta el 31-5-2024','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2022-10-03','Ana: Remito a la Res. Padre Damián de Plasenzuela (residenciaplasenzuela21@gmail.com) el Consentimiento Informado para la administración de las Vacunas de la Gripe y la 4ª dosis de Covid, firmadas digitalmente por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-03','Ana: tras varios correos de Isabel, envío uno a Paula, TO del CRR: "Te reenvío coreo de Isabel Cano, hoy ha enviado varios. Habíamos hablado de para Navidad, se mostró conforme, pero ya esta mañana “le urgía más”… en otro correo posterior a este, que ahora le responderé, dice que ya mejor 100 euros para ropa en lugar del reloj… o eso creo entender… Por favor, cuando podáis, si es posible, al igual que con Ceferino, abordar con ella esta cuestión, pues no puede comenzar a pedir cada día una cosa distinta. No obstante, visto lo visto, cuando lo tenga claro, y para más adelante, pues ya no parece ser urgente el reloj, nos decís cuál es la prioridad y si puede adjuntar presupuesto mejor, sabéis que en la secc. ecca. suelen pedirlo." ················· Contesto a Isabel poniendo en copia a Paula, TO: "Buenas tardes Isabel, Entendemos que lo primero que tienes que hacer es valorar cuál es la prioridad, si la ropa o el reloj, y en base a ello decidir. Con el apoyo de las profesionales del CRR, estamos seguras de que podrás tomar la mejor decisión al respecto. Si decides el reloj, lo mismo, tendrás que aclararte, pues ya has enviado imagenes de distintos relojes, habiendo cambiado de opinión en menos de una semana. Cuando ya lo tengas claro, por favor, enviar presupuesto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-10-03','Ana: Envío correo a Toni-Futuex: "En relación a JESÚS MANUEL RAMOS BARGÓN, necesitamos que, en cuanto os sea posible, nos remitáis INFORME firmado sobre los últimos seguimientos realizados y su situación actual, nos los solicita desde el Juzgado para la revisión de su sentencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2022-10-04','Ana: Remito a la Res. San Pedro de Valencia al Alcántara el C.I. para la administración de las vacunas de la gripe y la 4ª dosis de Covid, firmado digitalmente por el Presidente de de la CTAEX.','2');
