insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-10-04','Ana: Paso a Julio, CTAEX, para registre en SIREX el Oficio- SOLICITUD Certificado actualizado de P. Orfandad. ································································································································································································· Remito correo Miguel, Limpiezas Extremas (info@limpiezasextremas.com): "Me pongo en contacto de nuevo contigo para solicitar un presupuesto de limpieza en otro domicilio, propiedad de una persona cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura. Se trata de una vivienda ubicada en la C/ Berrocalejo, nº 14, de la localidad de Puerto de Santa Cruz (Cáceres). Con tu permiso, facilito tu contacto a la Coordinadora del Programa de Apoyo Comunitario, gestionado por Futuex, para que podáis poneros en contacto, al igual que la vez anterior en Alcuéscar, para visitar la vivienda y remitirnos presupuesto. En caso de que aceptéis el trabajo, la compañera de dicho programa, os facilitará los datos para que podáis remitirnos el presupuesto a la siguiente dirección: ctutelar@salud-juntaex.es, a la atención de la sección económica. ..." ································································································································································································· Envío correo a Toni-Futuex: "He llamado Miguel, de la empresa “Limpiezas Extrema”, pero el teléfono no está disponible. Tal y como me indicó en otra ocasión, le he enviado un correo electrónico, que te reenvío, para solicitarle presupuesto de limpieza de un domicilio. Como puedes ver, indico que te paso el contacto para que podáis concertar fecha de visita con él. El domicilio que hay que visitar y que, creemos que habría que limpiar, es el de JAVIER AGUDO CUMPLIDO. Él reside actualmente en el CRR de Plasencia, las compañera tendrán que recoger las llaves. Él mismo demanda la limpieza de la casa. El domicilio lo indico en el correo de más abajo (hilo), subrayo en amarillo. Y el presupuesto, para agilizar, pueden enviárnoslo directamente desde la empresa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-10-04','Ana: Paso a Julio, CTAEX, para registre en SIREX el Oficio- SOLICITUD al INSS Certificado actualizado de P. Jubilación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-10-04','Según los Pliegos, la ausencia del recurso durante 15 días continuados o 45 anuales, sin justificación, es motivo de pérdida de plaza. En el caso de Emilia, vamos a darle otra oportunidad, pero debéis hacerlo por escrito recabando su firma. Le daremos un plazo hasta el 21 de octubre para que cambie su proceder con respecto a la ocupación de la plaza. Se puede permitir salidas de fines de semana, y las horas diarias establecidas, pero debe permanecer en el Centro y participar en las actividades, talleres, citas ... programadas en su PIR, además de cumplir con el resto de normas de convivencia y horarios, incluida la pernoctación en el centro. Si para esa fecha continúa con la misma dinámica y sigue sin hacer uso normalizado de la plaza que ocupa, nos lo comunicáis por escrito junto con su compromiso firmado y procederemos a darle de baja definitiva de la plaza. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-10-04','Ana: Envío correo a Toni-Futuex: "En relación a A.F. MAILLO SANTIBAÑEZ, cuando podáis, remitirnos INFORME FIRMADO, sobre la visita e intervención, o intento de ello, que hayáis llevado a cabo con él desde el Programa de Apoyo Comunitario, pues si es preciso, se va a comunicar al Juzgado junto con el informe que enviéis. Puede que incluso se pida la revisión de las medidas de apoyo. *Especificar si finalmente se ha podido hacer algo con respecto al apoyo para la búsqueda de vivienda que solicitaba."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-10-04','Según los Pliegos, la ausencia del recurso durante 15 días continuados o 45 anuales, sin justificación, es motivo de pérdida de plaza. En el caso de Emilia, vamos a darle otra oportunidad, pero debéis hacerlo por escrito recabando su firma. Le daremos un plazo hasta el 21 de octubre para que cambie su proceder con respecto a la ocupación de la plaza. Se puede permitir salidas de fines de semana, y las horas diarias establecidas, pero debe permanecer en el Centro y participar en las actividades, talleres, citas ... programadas en su PIR, además de cumplir con el resto de normas de convivencia y horarios, incluida la pernoctación en el centro. Si para esa fecha continúa con la misma dinámica y sigue sin hacer uso normalizado de la plaza que ocupa, nos lo comunicáis por escrito junto con su compromiso firmado y procederemos a darle de baja definitiva de la plaza. Saludos,','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-10-04','escribo email a Rosa , del SSASB Buenas Rosa, hemos hablado con Vivienda para confirmar si tiene la vivienda de promoción pública solicitada . Nos informan que efectivamente la ha pedido por 2 veces , pero que en reunión mantenida con TS del SSASB y del CTro. de Salud no se ha determinado como el recurso más oportuno y se la han desestimado . Voy a solicitarle a Eduardo PFHC +P. orfandad , subiría en ingresos a los actuales de IMIVI . Con ello valoraremos la opción de piso de alquiler . La madre está informada de todo por mí , que por deferencia lo hemos considerado así. No obstante, su hijo no quiere contactos con ella , y desde la Comisión se le informará sólo de lo que sean datos no confidenciales , no del plan de intervención que se va a realizar . Se le ha pedido si puede apoyar economicamente para el alquiler y lo ha declinado . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-10-04','miguel, Rocio Gracian (abogada de Damian en juicio de desahucio) me pide la citación para que no archiven el procedimiento en Malaga. Hablamos con el Jzdo nº1 de Mérida, quienes nos remiten por fax la citación para el día 15-11-22 y se lo reenvío a Rocío Gracian (abogada de Damian en juicio de desahucio)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-10-04','miguel, hoy se firma la venta de la rustica paraje rustica de los carniceros del Valle de la Serena. Firmada ante la notaria de Azkoitia Doña Iciar Fernández Protocolo 978. Y firmo la ratificación de la venta hoy en notaria de Mérida, ante Don Gonzalo Igartua Fesser Protocolo 124','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-10-04','escribo email a Rosa , del SSASB Buenas Rosa, hemos hablado con Vivienda para confirmar si tiene la vivienda de promoción pública solicitada . Nos informan que efectivamente la ha pedido por 2 veces , pero que en reunión mantenida con TS del SSASB y del CTro. de Salud no se ha determinado como el recurso más oportuno y se la han desestimado . Voy a solicitarle a Eduardo PFHC +P. orfandad , subiría en ingresos a los actuales de IMIVI . Con ello valoraremos la opción de piso de alquiler . La madre está informada de todo por mí , que por deferencia lo hemos considerado así. No obstante, su hijo no quiere contactos con ella , y desde la Comisión se le informará sólo de lo que sean datos no confidenciales , no del plan de intervención que se va a realizar . Se le ha pedido si puede apoyar economicamente para el alquiler y lo ha declinado . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-04','Buenos días Araceli, Hable con mi compañera Amalia: amalia.diaz@salud-juntaex.es. 924 00 60 30. Mercedes es una curatela asistencial para el tema económico. Según su sentencia sólo podemos intervenir en el área económica. Tiene que saber que el ingreso en vuestro centro ha sido involuntario, determinado por el juez a propuesta de la Unidad de psiquiatría del hospital de Badajoz. Es cierto que desde esta Comisión hemos colaborado en todo lo relacionado con vosotros ( documentación…) pero no ha sido decisión nuestra, aún estando de acuerdo en que era necesario. Respecto a las medidas de apoyo, ella es perfectamente conocedora de su situación. Tiene la sentencia y sabe que implica. Nos gustaría saber cual es su demanda, antes de hablar con ella. A diferencia de Jose María Morón y Juan Carlos García, no le hacemos un seguimiento telefónico normalmente. A pesar de ser curatela económica, se intenta intervenir en otras áreas como en la de la salud, pero no suele aceptar la ayuda, no cogiendo nuestras llamadas ni abriendo la puerta a las educadoras que van a visitarla….. Tenemos pendiente su presupuesto para pasarle la asignación. Seguimos hablando Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-04','Buenos días Araceli, Hable con mi compañera Amalia: amalia.diaz@salud-juntaex.es. 924 00 60 30. Mercedes es una curatela asistencial para el tema económico. Según su sentencia sólo podemos intervenir en el área económica. Tiene que saber que el ingreso en vuestro centro ha sido involuntario, determinado por el juez a propuesta de la Unidad de psiquiatría del hospital de Badajoz. Es cierto que desde esta Comisión hemos colaborado en todo lo relacionado con vosotros ( documentación…) pero no ha sido decisión nuestra, aún estando de acuerdo en que era necesario. Respecto a las medidas de apoyo, ella es perfectamente conocedora de su situación. Tiene la sentencia y sabe que implica. Nos gustaría saber cual es su demanda, antes de hablar con ella. A diferencia de Jose María Morón y Juan Carlos García, no le hacemos un seguimiento telefónico normalmente. A pesar de ser curatela económica, se intenta intervenir en otras áreas como en la de la salud, pero no suele aceptar la ayuda, no cogiendo nuestras llamadas ni abriendo la puerta a las educadoras que van a visitarla….. Tenemos pendiente su presupuesto para pasarle la asignación. Seguimos hablando Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-04','Ana: Llamo a María, TS del CS San Miguel, de Plasencia (74638): Desideria no acudió a la cita programada para la RESONANCIA MAGNÉTICA del cerebro y anuló la cita con el MAP. *Me enviarán documento en que conste por escrito. ··································································································································································································· Envío correo a Ana Benavente (anamaria.benavente@salud-juntaex.es) preguntando si finalmente se atendió a Desideria en la cita programada de Enfermería que tenía la semana pasada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-04','Ana: Llamada a Mamen, TS de Caritas (927 235 082): le proponen ingreso en Comunidad Terapéutica, que a priori acepta. **Hoy han tenido la cita en el ECA ("CEDEX") para solicitar el ingreso. Por otra parte, ya habló en su día con Pilar Martín, TS ESM-CC, para que desde el equipo se proceda a la derivación a CRR para que pueda ingresar tras su paso por comunidad terapéutica. ················ El martes día 11 tiene cita en el Serv. de Psiquiatría, ESM, y ella le acompañará. ··········· Considera necesario solicitar la revisión del grado de dependencia. Tendrían que pedir los informes pertinentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-10-04','Ana: Envío correo a Julio, CTAEX: "Te adjunto documentos para registrar a la GERENCIA TERRITORIAL DE CÁCERES del SEPAD. AVDA. HERNÁN CORTÉS, 1. Código SIREX: A11030403 Es una Comunicación de Variación de Domicilio a Dependencia relativa a DOROTEO DÍAZ CERRO." ·············· Se adjunta cdo. de ingreso en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-10-05','Ana: Remito a Victoria Sánchez, Aux. Adtvo. ASINDI (victoria.adgestion.asindi@gmail.com) solicitud del certificado de empadronamiento individual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-10-05','Ana: Remito a Victoria Sánchez, Aux. Adtvo. ASINDI (victoria.adgestion.asindi@gmail.com) solicitud del certificado de empadronamiento individual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-10-03','Ana: Correo del Programa de Familia Tajo Salor (programafamilia@tajosalor.es >programafamilia@tajosalor.es): "Buenos días Ana, nos ha llamado Felisi y nos ha dicho que hace tiempo fue con su suegro y su cuñada a Cáceres a dar de baja la luz y el agua de la casa de Navas, pero no pudieron e hicieron otra cosa. No se explica muy bien, pero nos cuenta algo de que tiene que ir a pagar los recibos al banco, que tiene una deuda muy grande porque Aitor no le manda las cartas…creemos que puede ser que quitasen la domiciliación. Igual no es nada pero para que comprobéis, si os parece, si la tiene domiciliada aún y si realmente existen esas deudas de las que habla. Si no te importa luego nos decís algo, que ya sabes cómo es Felisi… Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-10-05','Ana: Tras consulta con las compañeras de la secc. ecca. escribo al Programa de Familia: "Buenos días, - En relación a los recibos del agua, me confirman las compañeras, que le pasan los cobros de AQUANEX de forma trimestral. El último fue en el mes de agosto. Estarán pendiente en noviembre para ver si se lo vuelven a pasar. - En cuanto a los recibos de la luz, le han pasado cargos de HC ENERGÍA en septiembre, por tanto, domiciliado sigue. Entiendo que ya se lo explicáis vosotras, ¿verdad? Ante cualquier otra cuestión, ya sabéis, no dudéis en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIO'and edp.apellido1='GALLEGO'and apellido2='MOLINA'),'2022-10-05','SALIDAS JULIO-SEPTIEMBRE "Algunas salidas programadas de ocio se han realizado por la localidad intentando adaptarnos a la nueva normalidad."*******Asisitió a la ortopedia de Plasencia y ha salido acompañado al pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2022-10-05','SALIDAS JULIO-SEPTIEMBRE "Algunas salidas programadas de ocio se han realizado por la localidad intentando adaptarnos a la nueva normalidad."*******Asistió a consultas de oftalmología********Actividad programada desde el Ayto. el día del Alzheimer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-10-05','miguel, recibo email de la TS dirigido al abogado de la otra parte que propuso la compra del usufructo: Estimado Letrado, a petición de Carmen, ruego me indique si la otra parte ha aceptado la cantidad por el usufructo que quería la residente, según correo que puede leer más abajo del 31 de marzo de 2022. Muchas gracias. Saludos. Felisa Custodio Hernández','2');
