insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-10-05','miguel, recibo email de la TS dirigido al abogado de la otra parte acondebarbero@condefuentetajaabogados.es que propuso la compra del usufructo: Estimado Letrado, a petición de Carmen, ruego me indique si la otra parte ha aceptado la cantidad por el usufructo que quería la residente, según correo que puede leer más abajo del 31 de marzo de 2022. Muchas gracias. Saludos. Felisa Custodio Hernández','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-03-31','miguel, recibo email de la TS Felisa Custodio Hernández trabajadora_social_alcuescar@imserso.es> que nos manda al otro abogado acondebarbero@condefuentetajaabogados.es y a mí: Estimado letrado, está conmigo la residente Carmen Gómez Muñoz, le he explicado tal y como hemos hablado por teléfono que sin liquidación de gananciales y según el Código Civil le puede corresponder entre un 10 y un 30% del usufructo. Según el cálculo sería la cantidad de 41.610 euros. La misma se muestra conforme con la cantidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-10-05','miguel, recibo email de Estefanía: Buenas tardes Miguel, ya me he informado del tema de la declaración de herederos. Se puede hacer en partidos notariales limítrofes al de la residencia del fallecido. Así que creo que lo mejor es encargarlo a otra Notaría diferente a la de Herrera del Duque. Por cierto me harté de llamar y efectivamente nadie me lo ha cogió. Son un desastre o tienen poco personal. Te paso el enlace de los partidos notariales de Badajoz, porque yo no sé muy bien cuales serían los que lindarían con ese distrito notarial. Notarios por poblaciones - extremadura (notariado.org) Me informas por favor cual nos podría corresponder entonces, y ya nos ponemos en contacto con la Notaría correspondiente. Sino también podemos llamar al colegio notarial de Extremadura y ellos nos lo indicarán Un cordial saludo, Estefanía Fernández ******************************************** Me llama Loli de la notaria de Herrera del Duque y se compromete a intentar firmar en una semana para lo cual me pide sentencia de incapacitación completa, acreditación de José Vicente y mi autorización (que queda pendiente) junto con los dos testigos que habremos de localizar para su firma. Envío email a Tere: Tere, necesito que localices dos testigos y te envíen dni para firmar en notaria de Herrera del Duque la declaración de herederos del hijo fallecido de Alfonsa, Agustin. En cuanto tengas las fotocopias de los dni que te lo envíen para que se los mande a la notaria. Vamos a agilizarlo lo más posible. Al final me han llamado de la notaria de Herrera del Duque y se comprometen para hacerlo. Los dos testigos tienen que saber que van a firmar en la notaria de Herrera del Duque. Te lo digo porque el fallecido era de Talarrubias (que falleció además en su vivienda)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-10-05','Ana: Envío correo a María Bueno, PNC (maria.buenomar@salud-juntaex.es): "Buenas tardes María, Te he llamado, pero ya es mala hora. En relación a D. FELIX MAILLO SANTIBAÑEZ, cuyo cargo de CURADOR ostenta la CTAEX, acabo de darme cuenta de que no hemos remitido la Declaración Anual de PNC, ¿podríais remitírnosla, porque no la recibimos con el resto. Por otra parte, necesitaríamos un Certificado Actualizado de la PNC. Dime si te vale con este correo o necesitas que registre un oficio al respecto. Adjunto Testimonio de Auto de nombramiento y aceptación del cargo. Ya me dices, gracias y buena tarde." ······························································································································································································ Respuesta de María Bueno: "De acuerdo, doy traslado a gestión de la nueva situación del pensionista. En relación al documento de revisión anual de este año nos consta registrado por lo que hasta el próximo año no os debéis de preocupar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-10-05','Ana: Recibimos informe de Psiquiatría de Juan Mario para remitir al Jdo junto con los informes de incidencias de los últimos meses y reiterar la solicitud de ingreso en CSS (Ud. de Alcoholismo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-05','Ana: Correo de María Timón, TS del C. Salud Plas. II ( mariapaula.timon@salud-juntaex.es // 927 42 31 00): "Buenos días. Te envío lo único que hemos podido sacar respecto a la prueba de RM a la que Desideria no se ha presentado. Es un pantallazo de su agenda. En el caso de que no te sirva tendríamos que hablar con Atención al Usuario. Ya me dices. También informarte que en principio la iban a derivar a una clínica privada para hacérsela allí (desconozco los motivos), pero desde la clínica estuvieron intentando localizarla telefónicamente y les fue imposible; es por lo que le dieron la cita por correo ordinario para el Hospital."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-10-06','Buenas Teresa, comunicarte que nos ha llamado Aitor Moreno y nos dice que se ha ido a Badajoz. Nos cuenta que se van a quedar allí definitivamente y que su dirección, de momento, es en C/ La Lamprea, 25, que es la casa de la abuela de su pareja. Nos pregunta si va a ir alguien allí con él a hacer la compra semanal como hacíamos en Navas. Además hay varias cosas que quedan pendientes aquí, como por ejemplo, una alarma que instalaron en la casa de su madre, deudas que nos dicen que tienen en tiendas de la localidad (no sabemos en cuales ni de cuánto…) y una posible deuda con Movistar ( han contratado fibra y tienen un televisor nuevo que imaginamos deben pagar a plazos pero no podemos asegurarlo). Cualquier cosilla no dudes en llamarnos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-10-06','Ana: Leyre Sanz, TS de la Res. Ciudad Jardín-Cánovas CC (t.socialcanovas@grupociudadjardin.com): me remite el Contrato de Admisión de la Residencia firmado ya también mediante huella diligenciada por la propia Josefa. ·········· Lo guardo en el expdte. ····························································································································································································· Envío correo a Julio, CTAEX la siguiente documentación para registrar en SIREX: - Oficio - Aceptación PIA - Contrato Admisión C. Residencial - Facturas - Recibos bancarios Para remitir a: Gerencia Territorial Cáceres Sur (SEPAD), Sección de Dependencia. Plaza Hernán Cortés Nº1, 10001 Cáceres. Código de registro: A11030403"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-10-06','Ana: Remito a Mª Victoria Sánchez, Aux. Adtvo. ASINDI (victoria.adgestion.asindi@gmail.com), la autorización para participar en las actividades programadas para los juegos JEDES','2');
