insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2022-10-06','Ana: Remito a Mª Victoria Sánchez, Aux. Adtvo. ASINDI (victoria.adgestion.asindi@gmail.com), la autorización para participar en las actividades programadas para los juegos JEDES firmada digitalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-10-06','Ana: Desde el CAM Fco. Pizarro, nos remiten el último informe evolutivo emitido en ASPACE-Trujillo, con fecha de 4/10/22. *Guardo en el expdte. digital. ··· Las conclusiones del mismo son: "Durante todos estos años, se ha podido ver un cambio muy positivo en Juanjo. Así, se han visto reducidas las conductas de reto y de negativa en gran medida. Con respecto a sus iguales, su forma de relacionarse está siendo muy positiva, incluso llega a utilizar diferentes estrategias de afrontamiento en situaciones que se escapan de su control. A nivel de autonomía, con los apoyos necesarios, es capaz de realizar las actividades de la vida diaria de forma satisfactoria. Para finalizar, atendiendo a su nivel cognitivo, también necesita apoyo para el aprendizaje de nuevos conceptos, pero con un lenguaje proactivo y adaptando diferentes aspectos ambientales, es capaz de responder a las demandas." ········ No obstante, a lo largo del informe detalla aquellos aspectos en los que aún necesita apoyo a nivel motor, de autocuidado y relacional. ·························· En nuevo correo remiten CERTIFICACIÓN ACADÉMICA, de la FP Básica. Guardo en el expdte. digital. ·································································································································································································· Mediante conversación telefónica, Marcos, Ed. del CAM Fco. Pizarro, enviarán por correo ordinario la documentación que obra en su expediente (formato papel).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-10-03','Ana: correo del CAM Fco. Pizarro (cam.franciscopizarro@salud-juntaex.es) con documentos: Resolución Tto. Psicológico de Habilitación Funcional, Informe ASPACE de 29/06/22, Informe Evolutivo ASPACE de 24/01/22, Nota de cita reprogramada de ESM Infanto-Juvenil, Resolución del Grado de Dependencia e Informe ESM Infanto-Juvenil de fecha 22/02/22. ············ Guardo todo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-10-06','miguel, envío a Ana la providencia de revisión de sentencia: Buenos días Ana, desde el juzgado están revisando la sentencia de Ramos Bargon. Nos piden un informe social en el que tendréis que incluir su situación actual en cuanto qué recursos pueden ponerse a su disposición como medidas de apoyo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-10-06','Ana: Correo de Paula, TO CRR-Plas.: "Buenas Ana, os escribimos para comentaros acerca de Conchi Fernández. Esta mañana ha tenido una sobre ingesta de medicación, según verbaliza sin intención autolítica y se ha quedado en el hospital con tratamiento de carbono (según nos han informado). La doctora no ha verbalizado que estuviera en una situación de riesgo para su vida en ese momento. Por contextualizar un poco, esto ocurre tras haber pasado el fin de semana en Trujillo (para trabajar autonomía y sostener la relación con su hija) y a su regreso verbaliza malestar porque dice haber discutido con hermanas y hermano, argumentando no percibir su apoyo, y posteriormente también incluye a profesionales del centro, comenzando a verbalizar su de nuevo querer irse de forma inmediata, estar cansada del centro, etc. En estos días ante el malestar sostenido decidimos aumentar la supervisión tanto en medicación (en proceso de mayor autonomía) como en atención presencial de profesionales. Así, en uno de estos momentos de atención, (estábamos tratando de adelantar cita con su psiquiatra) esta mañana ha reconocido haber tomado medicación (que ha sacado de la farmacia) por lo que inmediatamente hemos acudido a urgencias hospitalarias para que la atiendan. Os iremos informando si hay novedades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-10-06','Ana: María Bueno, TS Servicio de Prestaciones Sociales - Dirección Gral. (maria.buenomar@salud-juntaex.es), me remite Cdo. Actualizado de PNC: 632,10 € x 14. ········· Guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='CANCHALES'and apellido2='MALDONADO'),'2022-10-06','miguel, llega a ctutelar email de Tere: Informar que la madre de SOLEDAD CANCHALES MALDONADO falleció el pasado 29 de septiembre, se encontraba ingresada en la Felipe Trigo, hay que tramitar la herencia que le corresponde a Soledad. ************************************************ mi contestación: Tere, esta tutelada tiene dinero de sobra para contratar los servicios de herencia con cualquier abogado y/o gestoría. No veo en su expediente ningún informe social para saber si hay más herederos o no. No tenemos nada sobre la madre (certificado de defunción, últimas voluntades, testamento, notas simples de inmuebles, certificados de saldo bancarios…). Habla con el centro y que te digan qué persona de contacto (por ejemplo algún familiar) puede encargarse de facilitar toda la documentación que necesitaría el abogado y/o gestoría para dicha tramitación y si tienen preferencia porque lo tramite algún abogado y/o gestoría en concreto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-10-06','llega resolución no firme de internamiento involuntario den UHDAC, que remitimos a Amalia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-10-06','Email del CSS de Mérida , remito a seccion juridica posibilidad de pedir atorizacion para internamiento involuntario. ¡Hola, Amalia! Adjunto te remito informe social de Francisco Cuevas López. El día 30 de enero de 2023 cumple la condena. Se va a solicitar plaza pública en centro de atención residencial para personas mayores. El problema es que cuando le concedan la plaza solo tiene 15 días para ingresar en el centro. Si en el día en el que cumple condena aún no le han concedido plaza ¿adónde irá? Hasta mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-10-06','Email del CSS de Mérida , remito a seccion juridica posibilidad de pedir atorizacion para internamiento involuntario: Adjunto te remito informe social de Francisco Cuevas López. El día 30 de enero de 2023 cumple la condena. Se va a solicitar plaza pública en centro de atención residencial para personas mayores. El problema es que cuando le concedan la plaza solo tiene 15 días para ingresar en el centro. Si en el día en el que cumple condena aún no le han concedido plaza ¿adónde irá? Hasta mañana. ---------------------------------------------------------- Buenos días , entiendo que la plaza residencial se le va a pedir por PIA , al tener grado II. Una vez cumplimentado puedes renviármelo para que lo firme el gerente y lo registremos en la unidad de dependencia. No me fio , que llegado el día se niegue a ingresar , a pesar de que actualmente ha aceptado el ingreso y ha elegido sitios preferentes . Yo añadiría todas las zonas descartando la de Villanueva para tener más opciones. Se lo he pasado a los jurídicos para que valoren solicitar internamiento no voluntario . Te voy diciendo . Hay que ir moviéndolo ya , para que llegue a fecha. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2022-09-01','EXITUS A través de consultas en bases de datos de PNC y CIVITAS se confirma la defunción. Se baraja la fecha del 01/09/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-06','Ana: Correo de Ángel, Asesor Jurídico CTAEX: "Hemos enviado a la Audiencia Provincial escrito de averiguación patrimonial de los recursos del demandado." ············· En relación al delito cometido por el primo de Isabel hacia ésta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2022-10-06','Hola, tiene seguro con Mapfre. a ella le cargan trimestralmente el recibo, está al corriente en el pago. ya se lo he comunicado a su hermana, que le dará de baja. Me llama la atención que en su póliza, dentro de los servicios contratados está incluido la incineración y urna, por lo tanto no tiene contratado ni nicho ni lápida. Esto lo ha decido ella??.ya me decís.os adjunto una copia. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2022-10-06','Ana: Remito a Mª José Acosta, TS de la Mancomunidad Sierra de San Pedro (mjacosta@mancomunidadsierrasanpedro.com / 626134446 / 691596071): Escrito-solicitud de traslado a la Residencia de Mayores de Campillo de Llerena por acercamiento a familiares, firmado mediante huella diligenciada y firma digital del Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-06','Ana: Envío correo a Andrés, Seguros Atocha (andres@segurosatocha.com) "... La solicitud de la Pensión de Viudedad y el Auxilio por Defunción, finalmente la solicitaré yo desde aquí. Para el resto de gestiones; tramitación de bajas y certificados de últimas voluntades, adjunto la Autorización para el tratamiento de los datos y la cesión para la prestación de servicios profesionales, firmado digitalmente por el presiente te de la CTAEX. Ante cualquier cuestión no dudes en volver a contactar. Un saludo." ·································································································································································································· Remito correo a Toni- Futuex: "En relación a Desideria Barbero Bueno, estoy tramitando la Pensión de Orfandad, y solicitan el libro de familia o acta de matrimonio. No lo tenemos en el expediente, ¿sería posible que cuando vayan las compañeras a visitarla en los próximos días, le ayuden a localizar el documento y nos los remitáis escaneado?" ································································································································································································ Remito a REGISTRO (oac.merida.san@juntaex.es): "Adjunto remito la siguiente documentación relativa a Dª. Desideria Barbero Bueno, cuyo cargo ostenta la CTAEX: - Solicitud de Pensión de VIUDEDAD firmado digitalmente por el presidente de la CTAEX. - Certificado de Defunción del marido fallecido - DNI de la solicitante - DNI del Presidente de la CTAEX - Testimonio de aceptación del cargo - Nombramiento del D. Gerente del SEPAD - Resolución de Delegación de Competencias Habrá de registrarse de entrada en: Dirección Provincial de INSS en Cáceres Avda. de España, nº 14 CP: 10001 – Cáceres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-10-06','miguel, recibo por carta mucha documentación de reclamaciones que ha hecho la tutelada ante diversas instituciones con un discurso totalmente incoherente. Lo escaneo y remito a Ana y Maite: Buenas tardes, os adjunto escrito recibido esta mañana por correos de la tutelada. Leedlo con detenimiento. Desde hace tiempo llama preguntando por los trámites para recuperar su capacidad y ha intentado tal como le indiqué solicitar un abogado de oficio que la representara. La cuestión es que aunque tiene un discurso por teléfono coherente, tras leer por encima esta documentación y a donde se ha dirigido me da la impresión que necesita ayuda urgente, tal vez un internamiento…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-10-06','Ana: Envío a la Res. el Conquistador el CI para la administración de las vacunas de la Gripe y Covid (4ª Dosis) firmado digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-10-06','Ana: llamo a Margarita Montero, T.S. de Montánchez (637 099 759): plantea algunas dudas que tiene sobre la situación económica de Mateo (pensión de alimentos, salario, deudas..). Es muy reticente a concederle la plaza. *Tiene que hablarlo con la Directora y la Alcaldesa. *Quiere que nos comprometamos a empadronarlo en el municipio, solicitar la Revisión de Grado de Dependencia o solicitar plaza por DECRETO, en cuanto sea posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2022-10-06','EXITUS El centro informa de su fallecimiento. El óbito tuvo lugar en la tarde del 06/10/2022. En su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='FRAGUAS'and apellido2='CARPINTERO'),'2022-10-07','Ángel: He hablado con el nieto, José Luis Fraguas Vidal (660536372), para que consiga dos testigos y formalicemos la Declaración de Herederos del padre de María José. A su vez, están gestionando la herenci de los abuelos. Todos fallecieron en vigo. Nos va a facilitar contacto con la Notaría y alguna Gestoría/Despacho de Abogados que podamos contratar para solicitar autorización judicial de aceptación de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-10-07','Ana: Tras recibir llamada de Julia, madre de Julia, envío correo a Toni-Futuex: "Buenas, de nuevo, Toni, Me llama Julia, Madre de Julia Morón Hernández, pregunta si Gloria nos ha enviado 2 facturas de taxi, mis compañeros de sección económica no encuentran nada al respecto. Si Gloria las tiene, por favor, cuando podáis, remitirlas a la atención de la sección económica a la dirección ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-10-07','Ana: Reenvío a Toni-Correo de Ángel, Asesor Jurídico CTAEX, solicitando que visiten el adosado de la C/García Márquez para ver el estado de la vivienda y nos remitan fotos de la misma. *Facilito el contacto de Jesús, hermano de Martín. ································································································································································································ Llamo a Mariví Clemente, TS CSS-Plas (24142): Me comunica que Martín actualmente "no está nada bien, lleva unos días muy revueltos, con una actitud muy rara", "una psicopatología extraña". *No cree que esté en condiones de tomar una decisión relativa a la venta de una u otra vivienda. Lo conocen de cuanto estuvo ingresado con una orden judicial para cumplimento de condena, desde 2010 hasta agosto de 2013. ···················· Según nota de la Psiquiatra, Ana, presenta "conductas inusuales" (arroja objetos por la ventana, tira papeles y productos que no le gustan a la basura...), "soliloquios". Le ha modificado la medicación, esperan que evolucione bien con el tratamiento nuevo. ············ Si la semana que viene estuviera mejor, nos llamarían para que hablásemos con él. Pero cree, que así y todo, es mejor que le expliquemos que opción creemos que es mejor y se puede trabajar con él para que lo acepte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2022-10-07','TERESA ENVIO REVISION PIA POR EMAIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-10-07','TERESA SALDO 28/09/2022: 2.332,14 €....MUY POCO TERE: CONSUMOS: NOS TIENES QUE INFORMAR SOBRE LA BAJA DE LUZ Y AGUA. TERE/MAITE/ALBERTO (28/09/2022): SE ACUERDA: INGRESA EN CASA MISERICORDIA ALCUESCAR 26/09/2022 X 400 €/MES GASTOS: SE APRUEBAN 75 €/MES PARA TODOS LOS GASTOS QUE PUDIERA TENER EL TUTELADO. LO ADMINISTRA EL CENTRO. EXTRAS: NO SE PODRÁ AUTORIZAR NINGUNO PARA NINGÚN CONCEPTO...TERE: ESTO DEBES ACLARÁRSELO AL CENTRO PROBLEMAS: ESTE TUTELADO PUEDE TENER EMBARGOS IMPREVISTOS QUE DESCUADREN TODAS LAS CUENTAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2022-10-10','Ana: Envío a Belén Pavón, Res. Grupo Asoma, el CI para la administración de las vacunas de la gripe y Covid, firmado digitalmente por el D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-07','Ana: Respuesta de Toni-Futuex, ayer a última hora: "Lo intentaremos la siguiente vez, pero es super desconfiada con todo lo que tiene que ver con documentos, papeles o temas suyos.. sabemos que la familia es de Irún no? no se si a través de su hermano, del que tenemos el numero de contacto seria mas fácil, pero igualmente lo intentamos primero con ella si eso. Lo del movil, ha salido aparentemente bien... se ha comprado uno basico con tarjeta prepagado por 40 euros una ganga! jiji. No se el número ni mucho mas, porque me lo ha dicho la compi por whastapp, en cuanto tengamos el seguimiento te lo paso. Lo que si hemos hablado, es que el dinero sobrante, 140 euros, se los costodiaramos y se le pueden llevar para la proxima vez, o ver si va necesitando para algun extra.. Hoy de los 200 que saca habitualmente, ha gastado 90 eu en una buena compra, y se ha quedado con el resto para ir comprando mas cosillas de alimentos, y en ese sentido ella se administra muy bien, compra mas o menos de todo y se las organiza, tampoco puede estar logicamente sin dinero, asiuqe se ha quedado con el sobrante. Y aunque ha desconfiado muchisimo, hemos conseguido que nos entregara para custodiarle, lo sobrante del movil, nos ha pedido firmarle un papel, y se ha quedado conforme. Asique lo explitaremos bien en la nota de seguimiento, pero ahora mismo tenemos 140 eu suyos, para llevarselos en la proxima visita, y acompañarle a comprar algo que necesite para la casa o de ropa o lo que sea, que ella necesite. A ver si con el movil se maneja, que hemos probado y parece que si"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-09-15','Ana: Recibimos del INSS, resolución aprobatoria de PFHC = 417,70 € X 12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-10-10','Ana: Tras hablar con Mariluz Madrigal y Raquel Gómez, Secc. Salud Mental, y leer el correo de Sheila, Directora CRR-CC, envío correo a Miguel, Asesor Jurídico CTAEX: "Te reenvío correo con información e informes, relativos a la situación actual, cada vez más gravosa para su salud, de JUAN MARIO SAN ROMAN BLASCO. Le han ingresado en la UHB, tuvo un incidente en la sucursal bancaria, se desplomó en el suelo y tuvieron que llamar a la ambulancia. Gracias a que había una "médica en la sala". *Adjunto también informe de Psiquiatría relativo a la consulta en el Equipo de Salud Mental de fecha 12/08/22. Por favor, consideramos que hay que volver a comunicar al Juzgado la situación actual y expresarle la urgente necesidad de ingreso involuntario en la Unidad de Alcoholemia del Centro Sociosanitario de Plasencia, para su tratamiento y rehabilitación. La propuesta desde la Sección de Salud Mental, es, si ingresa próximamente, guardarle la plaza en el CRR, para cuando puedan volver a darle de alta en el C. Sociosanitario. *En cambio, si no ingresa en dicha unidad, terminarán expulsándolo del centro y sin el apoyo y control que ejerce éste en con respecto a su diabetes, administración de insulina y el resto de medicación, alimentación… las consecuencias para Juan Mario pueden ser fatales."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-10-11','Ana: Envío correo a Estrella Durán, TS del CSS-Plas (estrella.duranc@salud-juntaex.es): "en relación a ANDRÉS SILVA BONIFACIO, nos ha comunicado desde el centro de Plena Inclusión que hay previsto un pase de salida para ir al centro a finales de este mes. ¿Podrías confirmarme esta información? Aquí nos sabemos nada. Y por cierto, ¿cómo sigue? Entiendo que, si hay este planteamiento, es que va a mejor, pero agradeceríamos que nos informaras de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-10-11','Hola Amalia, de acuerdo, mañana hemos programado un seguimiento. Te cuento por aqui, lo último de cuando lo vimos este verano.. este hombre tio un lio con el dinero, que no sabemos si es real o ficción o que.Desde el programa de apoyo social comunitario, realizamos nota para indicar la información recogida en el último seguimiento y para adjuntar el Justificante de realización del Plan de empresa, que le gestionaron desde Cocemfe (Estela). Este plan le obliga estar dado de alta como autónomo (él no sabe el tiempo, creemos que dichas subvenciones exigen un mínimo de dos años de alta como autónomo), paga inicialmente este año una cuota mensual de 89,15 euros, pero subiendo la misma a partir de enero (no sabe concretamente ni cuanto le subirán las cuotas). Indica que con este plan de empresa recibirá una subvención de 7900 euros que quiere invertir en traerse a su novia de Colombia. A estos pagos se le añade la cuantía de 60 euros mensuales del gestor que le lleva la documentación como autónomo. Sus expectativas laborales son altas relacionadas con trabajos como comercial por eso refiere que es imprescindible ser autónomo, este trabajo ya lo ha realizado anteriormente vendiendo enciclopedias, realizando contratos con compañías eléctricas, etc.… Él espera encontrar trabajo en un corto periodo de tiempo ya que dice malvivir con la PNC. Solicita al programa que le ayudemos en la búsqueda de empleo. (Ya le indicamos algunos lugares, donde elaboran itinerarios de trabajo protegido, se ha inscrito en alguna bolsa en SIFU) pero el lo que quiere, es el autoempleo a traves del autonomo (creemos que es un poco complicado todo esto, no sabemos como desde Cocemfe se le ha dado alas la verdad). En relación al préstamo bancario nos sigue dando diferentes cifras de cobro, indica que se lo pasan a primeros de mes y que al no tener dinero en el banco los intereses son muy elevados llegando a pagar más de 200 euros el mes pasado, refiere que las próximas cuotas deben ser de 25 euros (Banco Santander). Según nos informa Antonio ha tenido una cita de psiquiatría el 28 de septiembre a las 10:30 horas, con el doctor Calderón (Equipo Salud Mental Valdepasillas). En el seguimiento le encontramos tranquilo ya que había podido retirar del banco el día anterior 284 euros, compró comida, echó gasolina al coche y realizó un giro de 50 euros a su novia de Colombia, la cual tiene 22 años y ha visto presencialmente 15 días. Pero no obstante veremos que sucede con está situacion que dicen desde el banco.. lo de que teman por su integridad fisica, pues a ver, suponemos que llegara pegando voces, porque es bastante brusco, pero no sabemos hasta que punto serán en el banco. Y tambien esta lo del consumo de alcohol que pueda hacer que llegue mas agitado al banco. Lo hemos visto pocas veces para saber exactametne sus reacciones. Rosario trabajadora social de la localidad, ese dia, indica que Antonio es un caso muy complicado y que cuando se queda sin medios económicos para comprar comida recurre a familiares de forma insistente (padres, tíos…) y a los servicios sociales, , que llegó a la oficina de la trabajadora social desaliñado y muy agitado porque no podía retirar dinero, un dia de este verano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-10-11','Hola Amalia, de acuerdo, mañana hemos programado un seguimiento. Te cuento por aqui, lo último de cuando lo vimos este verano.. este hombre tio un lio con el dinero, que no sabemos si es real o ficción o que.Desde el programa de apoyo social comunitario, realizamos nota para indicar la información recogida en el último seguimiento y para adjuntar el Justificante de realización del Plan de empresa, que le gestionaron desde Cocemfe (Estela). Este plan le obliga estar dado de alta como autónomo (él no sabe el tiempo, creemos que dichas subvenciones exigen un mínimo de dos años de alta como autónomo), paga inicialmente este año una cuota mensual de 89,15 euros, pero subiendo la misma a partir de enero (no sabe concretamente ni cuanto le subirán las cuotas). Indica que con este plan de empresa recibirá una subvención de 7900 euros que quiere invertir en traerse a su novia de Colombia. A estos pagos se le añade la cuantía de 60 euros mensuales del gestor que le lleva la documentación como autónomo. Sus expectativas laborales son altas relacionadas con trabajos como comercial por eso refiere que es imprescindible ser autónomo, este trabajo ya lo ha realizado anteriormente vendiendo enciclopedias, realizando contratos con compañías eléctricas, etc.… Él espera encontrar trabajo en un corto periodo de tiempo ya que dice malvivir con la PNC. Solicita al programa que le ayudemos en la búsqueda de empleo. (Ya le indicamos algunos lugares, donde elaboran itinerarios de trabajo protegido, se ha inscrito en alguna bolsa en SIFU) pero el lo que quiere, es el autoempleo a traves del autonomo (creemos que es un poco complicado todo esto, no sabemos como desde Cocemfe se le ha dado alas la verdad). En relación al préstamo bancario nos sigue dando diferentes cifras de cobro, indica que se lo pasan a primeros de mes y que al no tener dinero en el banco los intereses son muy elevados llegando a pagar más de 200 euros el mes pasado, refiere que las próximas cuotas deben ser de 25 euros (Banco Santander). Según nos informa Antonio ha tenido una cita de psiquiatría el 28 de septiembre a las 10:30 horas, con el doctor Calderón (Equipo Salud Mental Valdepasillas). En el seguimiento le encontramos tranquilo ya que había podido retirar del banco el día anterior 284 euros, compró comida, echó gasolina al coche y realizó un giro de 50 euros a su novia de Colombia, la cual tiene 22 años y ha visto presencialmente 15 días. Pero no obstante veremos que sucede con está situacion que dicen desde el banco.. lo de que teman por su integridad fisica, pues a ver, suponemos que llegara pegando voces, porque es bastante brusco, pero no sabemos hasta que punto serán en el banco. Y tambien esta lo del consumo de alcohol que pueda hacer que llegue mas agitado al banco. Lo hemos visto pocas veces para saber exactametne sus reacciones. Rosario trabajadora social de la localidad, ese dia, indica que Antonio es un caso muy complicado y que cuando se queda sin medios económicos para comprar comida recurre a familiares de forma insistente (padres, tíos…) y a los servicios sociales, , que llegó a la oficina de la trabajadora social desaliñado y muy agitado porque no podía retirar dinero, un dia de este verano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-10-11','TERESA Buenas tardes, soy Pili Arias, psicóloga de Plena inclusión Cabeza del Buey. En relación a la tutelada Marta Rivera Núñez, estamos valorando la posibilidad de poner una tarifa de internet en el domicilio junto con el teléfono móvil que saldría sobre unos 31€ mensuales, tendría internet en el domicilio más llamadas ilimitadas y 10gb en su teléfono móvil, ya que nos comenta que suele gasta unos 40-45 euros al mes realizando recargar para poder seguir teniendo megas. ¿Esto sería posible? A la misma vez y como ya se habló en su momento, Marta está valorando positivamente utilizar otros medios anticonceptivos como podría ser un implante o un diu, que son gratis y nos resulta más seguros, ya que no depende de si ella se quiere poner el parche o no. ¿Cómo veis vosotros este tema? Y por último, comentaros que han llamado a Marta para trabajar de limpiadora en una entidad bancaria dos horas a la semana en Peñalsordo, el jueves han quedado en llamarla para informar de todas las condiciones. Se trata de una baja médica por lo que no sabemos la duración del contrato. ¿Existe algún problema con que acepte la oferta de empleo? SE PROPONE QUE LE DEN DE ALTA A NOMBRE DE LA MADRE DEL NOVIO OK A CAMBIO DE METODO ANTICONCEPTIVO OK A TRABAJO ME QUEDO A LA ESPERA DE CONTRATO PARA SU FIRMA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2022-10-11','TERESA DERIVO A FUTUEX PARA PLAN DE INTERVENCION ME SOLICITAN LOS COMPAÑEROS JURIDICOS IFNORMACION SOBRE CARNE DE CONDUCIR Y COCHE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-10-11','miguel, Sonia Bernabé de Asindi me traslada la comunicación de la abogada del caso donde me indica que el Procedimiento Abreviado 230/2021-Juz nº 6 Cáceres ha quedado archivado (donde Yaiza denunció al tutelado)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-10-11','Ana: Correo de Ángel, A. Jurídico: "La situación económica de Martín es crítica actualmente, según me trasladó Alberto: • Dispone de un saldo en cuenta, a fecha de 6/10/22, de 834,43 euros. • Percibe una pensión de incapacidad permanente absoluta, por importe de 949,54 euros en 14 pagas. • Tiene unos gastos mensuales de 836,91 euros. • Tiene una deuda pendiente con el centro donde residió de 861,13 euros. • Tiene una deuda pendiente con el OAR de 610 euros, aproximadamente. • El Juzgado de lo Penal, 1, de Cáceres, le ha condenado al pago de 10.564,22 euros. • Esta situación ha sido enviada al Abogado, para que lo comunique al Juzgado y solicitar un aplazamiento/fraccionamiento. En cuanto a la venta se decidió el adosado, porque es 100% propiedad de Martín y no lo utiliza, porque cuando sale del centro, va al otro inmueble, que tiene en propiedad junto con su hermano. No necesitamos solicitar autorización judicial para vender, al ser una curatela, pero si se opone vamos a tener que comunicarlo al Juzgado y exponerle su situación, para que nos autorice. En cuanto a alternativas para conseguir liquidez, él habla de una moto, tv, etc. Habría que preguntarle para que nos de información. En cuanto al Informe no lo remite, incluso habla de mejora en los últimos días: “se muestra tranquilo, correcto, colaborador”. ································································································································································································· Envío correo a Mariví Clemente, TS del CSS (victoria.clemente@salud-juntaex.es), con los movimientos bancarios de Martín, para que se los puedan dar y abordar con él cuando lo estimen oportuno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-10-11','tf. arrendador : Francisco Trinidad Gil . 924365389/ 638598348 tf de su hijo Angel , Fco. ha fallecido hace un año','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='FAJARDO'and apellido2='ABRIL'),'2022-10-08','EXITUS Tras las averiguaciones de Amalia, se constata que el óbito tuvo lugar el 08/10/2022','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-10-10','Ana: Correo de Óscar, sección ecca, a Alberto y a mí: "Saturnino sigue haciendo y deshaciendo a su antojo, con la ayuda de su hermano. Ya tiene la cuenta en negativo. Además de los reintegros que quiere, os envío tres movimientos: - Transferencia de 100€ a Santiago Bote Gaspar por “Pago de deuda”. - Transferencia a su hermano Tomás por el enganche de la luz de 300€. - Seguro de auto con Allianz, recibo semestral de 294,12€. ¿Tiene coche y carné? ¿El seguro es suyo o se lo ha domiciliado el hermano en su cuenta? ¿Lo devuelvo? ······························································································································································································· Inés, CTAEX, remite a Toni de Futuex, la citación para el Examen Médico Forense: 28/10/22 a las 12:00h, para que se la hagan llegar en papel a Saturnino. ······························································································································································································· Puesto que desde el Jdo. no han llegado a contestar a la petición de la retirada del Permiso de Conducir (solicitado en marzo de 2021), pido a Miguel, Asesor Jurídico, que reitere dicha petición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-10-11','Ana: Mariví, TS del CSS, nos reenvíe correo de Rosa Mª Fdez. Barrera, Psiquiatra, con el resumen del "EVOLUTIVO" de Martín, según el cual presenta conductas inusuales y soliloquios posiblemente relacionadas con la descompensación psicopatológica recogidas en el informe de la UHB. *No se muestra de acuerdo en la venta de ninguna de las dos viviendas, ni reconoce a su hermano como copropietario de una de ellas. "Considera que puede solventar sus "pequeñas deudas" con el dinero ahorrado. ···· "En los últimos días ha intentado esconder alguna pastilla, por lo que se encuentra en observación sin salidas de la Unidad" ····················· Se lo reenvío a Ángel, Alberto y Maite, CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-10-11','Ana: Ana Benavente nos remite INFORME CLÍNICO de PSIQUIATRÍA. Guardado en expte.','2');
