insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-10-13','TERESA ENVIO POR REGISTRO DECLARACION INDIVIDUAL DE PENSION YA QUE NO SE HABIA ENVIADO Y LE HAN SUSPENDIDO LA PRESTACION TAMBIEN SE LA ENVIO POR EMAIL A MARIA BUENO PARA QUE SOLICITE LA RETROACTIVIDAD','2');
