insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-10-11','miguel, solicito al registro civil del juzgado de paz de Talarrubias certificado de nacimiento donde conste en nota marginal inscripción de incapacitacion y nombramiento a Ctaex. Me indican que me la remiten hoy para que el miercoles día 19-10-22 pueda ir a firmar la declaracion de herederos a Herrera del Duque.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-10-13','Ana: Paula comunica que Javier no tiene las llaves de su casa, si no encontramos a nadie que tenga copia, habría que cambiar la cerradura. *Lo comunico también a Toni-Futuex. Ya se lo habían comunicado en el CRR ··················· Llamo a Mª Jesús Gómez Lozano, TS SSASB Mancomunidad Comarca Trujillo (621 247 237): El miércoles próximo irá al pueblo y tratará de averiguar si alguien tiene llaves. *Me confirmará. ····························································································································································································· Como me comunican desde Futuex que tenían previsto y ir mañana mismo al domicilio, tras valorarlo y redactarlo con Miguel, Asesor Jurídico, *envío a Toni-Futuex, acuerdo de autorización de entrada para limpieza en domicilio y cambio de cerradura, por solicitud del propio tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-10-14','Ana: correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Se decidió que sí, irá de pase desde el lunes 24 al viernes 28 de este mes. A ver qué tal sigue...él está ambivalente por una parte quiere ir, pero por otra tiene temores, lo que sí ha cambiado es que expresa estos temores, no los actúa como hacía antes...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-10-14','Ana: Correo de ayer de Alberto, Jefe Secc. Ecca.: "OSCAR HA HABLADO CON EL DIRECTOR DEL BANDO DONDE OPERA/OPERAMOS CON EL TUTELADO: • DESDE HACE 1 MES LE ESTÁ DANDO AL TUTELADO 50€/SEMANA (217 €/MES) Y A PARTIR DE AHORA SEGUIRÁ NUESTRAS INSTRUCCIONES. • NOS INFORMA QUE EL TUTELADO HA COMPROMETIDO 50 €/MES PARA EL PAGO DE ELECTRODOMÉSTICOS PARA LA CASA (TENEMOS QUE AVERIGUAR FECHA FIN DEUDA PERO APROX. 1 AÑO). • CONSUMOS: IMPOSIBLE DE CUANTIFICAR TODAVÍA...SI ALGUIEN PUDIERA VISITARLE Y CONCIENCIARLE SERÍA PERFECTO. • TELEFONÍA: IMPOSIBLE DE CUANTIFICAR. IDEM QUE ANTERIOR. • CON INDEPENDENCIA DE LO ANTERIOR SERÍA POSITIVO QUE SE VISITASE AL TUTELADO PARA PACTAR UN PRESUPUESTO MÁS REAL (NOS DICEN QUE NO QUIERE SABER NADA DE LA CTAEX). INGRESOS: PN ORFAND 220,70 x 14 PR X HC 417,70 x 12 PROBLEMAS: • DEUDA PENDIENTE CON SEPAD DE 2.600 € QUE IREMOS ABONANDO BÁSICAMENTE CON LAS EXTRAS (OSCAR). • IMPREVISIBILIDAD EN CUANTO A LOS POSIBLES EMBARGOS Y QUE PODRÍAN TRASTOCAR CUALQUIER PLANIFICACIÓN." ················································································· *Traslado a Toni-Futuex, la petición de Alberto. ····························································································································································································· Correo de Toni-Futuex: "no se le puede ver hace tiempo, porque rechaza frontalmente las visitas... desde que se instaló en Alcúescar, permitió algo al principio pero muy poco. En cuanto precisamente no tuvo todo el dinero que deseada, empezo a bloquear el contacto con la compañera, no le cogía el telefono, y ya por último cuando se acercó a la localidad, le dejó muy claro que no queria verla y que no queria saber nada de la comisión ni relacionado, bueno ni de nadie que le diga como tiene gestinarse, incluyo fue bastante beligerante en el discurso "como sigas viniendo tu y yo vamos a tener problemas serios"... y cosas asi. Te acuerdas que nos solicitaste un informe para el juzgado ahi lo expresabamos todo. De hecho, por parte de Ines de la comisión, nos ha hecho llegar un par de veces o tres, una notficación para el forense para que se la hicieramos llegar y siempre ha sido a traves del hermano o el primo poq con el, es imposible, no nos coje el telefono ni permite visitas.Por cierto, que no se ha presentado o no se que ha pasado para que le hayan tenido que citar varias veces, ahora hay una pendiente para el 28 de este mes e intentaremos yendo a Alcuescar pero si no, pues a traves del hermano o si no su primo en del bar de alli. Al parecer el tiene que ir a firmar al juzgado de Paz no sabemos si todas las semanas, creemso que las notificaciones se le pueden hacer llegar ahi.. creo que ha podido influir tambien, en esta epoca? el hermano, que ha sido muy muy critico tambien con la comisión como bien sabes, porque te ha mandado emails, exigiendo que Nino cobrara toda su pensión y no razonando , ni entendiendo lo que signfica la administracion de bienes en una tutela, porque en epocas anteriores antes de entrar en prision, era complicado pero se le podia visitar y tenia buena adherencia en general con la compañera, todo se ha vuelto más dificil desde este ultimo periodo. No obstante se ira a Alcuescar y si conseguimos algo te lo comentare, y sino, pues tambien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-10-13','Ana: correos de Ceferino (ceferinomariscalcrespo64@gmail.com): "Buenos días. No quiero ir a italiano. Lleváis diciéndome todo el verano que para diciembre o enero me comprabais la DJ 800 con su respectivo maletín. Voy a dejar de ir a italiano. Lo digo para que no afecte a lo de la Pioneer dj800 qué tanto habíais prometido desde el verano o antes para diciembre o enero espero tenerla para esa fecha un saludo" ························ Lo que voy a hacer es implicarme más en el tema literario y en la música. Me pondré a escribir todos los días y a pasar la hechicera y el asesino que es la segunda y última parte de la biología de Big little aparte de dos relatos más que añada. ahora con el frío haré más streaming ya domino la dj400, quiero ver qué tal se me da la de j800 (yo creo que bien) voy a estar ligado a la música y a la literatura. La música le estoy dando bastante bien. Pero ahora me voy a poner más en serio con la escritura. Gracias espero que me comprendáis. ···································································································································································································· Mi respuesta, con copia a la TO-CRR: "Buenos días Ceferino, Nos parece bien que retomes aquellas cuestiones que más te han interesado siempre y te centres en ellas. Lo de dejar Italiano, al igual que matricularte en la Escuela de Idiomas para cursarlo, también son decisiones tuyas. Lo que nos inquieta son tus continuos cambios de opinión, pues da a entender que no estás muy centrado y no tienes las ideas muy claras. Sabemos que en el centro te ayudan a centrarte y te apoyan en el proceso de toma de decisiones, por lo que debes aprovechar las sesiones con las profesionales y dejar de tomar daciones a la ligera que no te favorecen. Es importante aprender a gestionar de forma adecuada los impulsos, y para eso cuentas con las Psicólogas y la Terapeuta Ocupacional del centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-10-13','-Pongo a firma PIA con los 4 centros residenciales elegidos por el usuario. ¡Buenos días, Amalia! Adjunto te remito la Aceptación PIA de solicitud de plaza pública en centro de atención residencial para personas mayores de Francisco Cuevas López. He anotado los cuatro centros residenciales por los que ha optado el paciente, ya que, hay uno de ellos que tiene bastantes plazas y tiene muchas posibilidades de que le concedan la plaza allí, como es el caso de la RRMM J.C. Rodríguez Ibarra. Si, aun así, tenéis intención de modificar la Aceptación PIA para solicitar todos los centros residenciales de Extremadura, excepto los que hay en Vva. de la Serena, entonces, tendréis que contactar con el paciente para renegociar el PIA. Por favor, cuando registréis la Aceptación PIA de Servicios, envíame una copia y así informo de la negociación del PIA en SIDEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-10-13','-Pongo a firma PIA con los 4 centros residenciales elegidos por el usuario. ¡Buenos días, Amalia! Adjunto te remito la Aceptación PIA de solicitud de plaza pública en centro de atención residencial para personas mayores de Francisco Cuevas López. He anotado los cuatro centros residenciales por los que ha optado el paciente, ya que, hay uno de ellos que tiene bastantes plazas y tiene muchas posibilidades de que le concedan la plaza allí, como es el caso de la RRMM J.C. Rodríguez Ibarra. Si, aun así, tenéis intención de modificar la Aceptación PIA para solicitar todos los centros residenciales de Extremadura, excepto los que hay en Vva. de la Serena, entonces, tendréis que contactar con el paciente para renegociar el PIA. Por favor, cuando registréis la Aceptación PIA de Servicios, envíame una copia y así informo de la negociación del PIA en SIDEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2022-10-13','-Amalia : pongo a firma PNC para luego registrar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-10-13','Ana: Envío a Pilar, Residencia, CI para Resección de transuretral de vejiga, firmado digitalmente por el presidente de la CTAEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-10-13','Ana: llamada de José Manuel, el día 26 le caduca el DNI y lo tiene que renovar. Ya ha pedido cita para ese mismo día. *Las tasas son 12 €. *Escribo a Toni-Futuex, para preguntar si le van poder acompañar desde el programa. Si es así pido que nos envíen copia escaneada (o al menos imagen) y que lo acompañen también al banco para que lo escaneen allí. ································ Por otra parte José Manuel dice que quiere cambiar su TV, que la que tiene es muy antigua y se ve muy mal. Dice que no quiere esperar a navidad como habíamos hablado, y como su cumpleaños es el día 18, que le gustaría comprarla ahora. **Sería para cumpleaños, navidad y reyes, si se aceptara no podría pedir nada más después. *Pedirá presupuestos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2022-10-13','Ana: Tras llamar a Isabel Pino, TS SSASB Miajadas, envío correo a Ángel, Asesor Jurídico CTAEX, respondiendo a sus consultas: "Tengo pedido un informe social a la Trabajadora Social de los Servicios Sociales de Atención Social Básica de Miajadas, por ser la TS de referencia y la que la ha atendido en los últimos meses y conoce su situación actual. La he vuelto a llamar y me ha dicho que está en ello, no cree que hoy le dé tiempo a enviárnoslo, pero sino dice que mañana. En cuanto a la PNC, el año anterior se la suspendieron por no haber presentado la declaración de la renta (había tenido varios contratos). Por indicación de la TS acudió a una gestoría, hizo la declaración, la presentó y se la reanudaron. *En esto ocasión se la ha suspendido por NO HABER PRESNTADO LA DECLARACIÓN ANUAL DE PNC, obligatoria. *También acudió a la TS al ver que no la cobraba, y en teoría ya lo ha subsanado, ha hecho la Declaración y la ha presentado por ventanilla única. Entendemos que se la reanudarán próximamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='HERNANDEZ'and apellido2='DIAZ'),'2022-10-13','ARCHIVO En virtud de Sentencia 972/21, de 14 de diciembre, Rollo de Apelación RPL 56/21 (nig: 06070 41 1 2019 0000073) dictada por la Audiencia Provincial de Badajoz, Sección 2, que revoca lo dispuesto en el fallo de la Sentencia 83/20, de 30 de septiembre, dictada por el Jzdo. de 1.ª Inst. e Inst. n.º 1 de Jerez de los Caballeros.*********************************La Audiencia Provincial nombra Curadora a su hija Dña. Ángela González Hernández.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-10-13','Ana: Correo del programa de familia Tajo-Salor (programafamilia@tajosalor.es): "Hoy le hemos acompañado a su casa de Navas a por ropa de invierno y como ya te dijimos aquello está en muy malas condiciones, hay comida putrefacta por toda la casa y están acudiendo bichos. Todo esto, como es lógico, ha afectado mucho a Felisi que nos ha dicho que quería poner una denuncia. Lo ponemos en tu conocimiento porque no sabemos cómo hay que actuar en estos casos. Cuando hemos llegado al domicilio ha saltado una alarma que tiene contratada su hijo y ha acudido una patrulla de la Guardia Civil que ha visto cómo estaba todo y ha hecho algunas fotos. La casa no la va a poder limpiar sola Felisi, no sé si podría pagar alguna empresa de limpieza o algo así, pero sería importante que además sea rápido porque ya te digo que hay bichos y puede que vaya a más." ···································································································································································································· Mi respuesta: "Precisamente hace unos minutos me ha llamado Mirella, la novia de Aitor, hablando muy rápido y nerviosa, me costaba entender lo que decía… que habían tenido que salir del domicilio con urgencia por estar enfermo su abuelo y que por eso había dejado la casa “un poco sucia”. Me decía algo de una alarma que yo no entendía, y me habéis aclarado ahora, jeje. No sabía que habían contratado una… Lo de la limpieza de la vivienda, ya habíamos acordado en el equipo que cuando por fin salieran de la casa (confiando en que llegara la autorización del juzgado y Aitor volviera al centro), se contrataría una empresa de limpieza, cuyo servicio costeará el propio Aitor. ¿Conocéis alguna empresa de limpieza de confianza en la zona que estuviera dispuesta a asumir el servicio? Si es así, por favor, decírnoslo y solicitarle presupuesto para que pueda valorarse en la sección económica. Sino buscaremos alguna otra empresa desde aquí. *En mi opinión también habría que cambiar la cerradura de la casa y arreglar el cristal roto. Lo que no sé es cómo podríamos hacer para que no volviesen a meterse ahí, que no pudieran volver a saltarse por el patio ni por ningún sitio… Y lo ideal sería también, que una vez adecentado todo, Felisi pudiera regresar a su casa. Y lo de dar de baja esa alarma, no sé cómo habría que hacerlo. ¿Sabéis qué empresa es? ¿El pago estará domiciliado?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-10-13','Ana: Envío correo a Blanca, Carolina y Paula CRR: "En relación a Julia Morón Hernández, dos cuestiones: - He hablado con Estrella, Trabajadora Social del C. Sociosanitario de Plasencia, me comunica que seguramente a Julia le darán el Alta en UME el próximo lunes, lo que no sé es si vosotras lo sabíais, supongo que sí, pero no he caído en preguntarle. - En cuanto a la situación económica de Julia, os reenvío correo de Alberto, Jefe de Sección Económica, pues del fin de semana de la expulsión anterior a su ingreso en UME, tomó 2 taxis que no se abonaron. Hace una propuesta, con la que la sección social estamos de acuerdo, para que Julia vea consecuencias a sus actos y tome conciencia al respecto. Podéis leerlo en el hilo del correo. Subrayo en amarillo. Así pues, su asignación se verá reducida en 50€ a partir del mes que viene y hasta el 1 de junio de 2023."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-10-13','Ana: correo de Estrella Durán, TS UHDAC: "Ha estado mejor unos días atrás y Maripaz se estaba planteando ese pase a su centro, pero el domingo pasado tuvo que ser contenido por una fuerte alteración con heteroagresividad. No te he dicho nada todavía, porque esta mañana tenemos reunión de unidad y según se decidiera te hubiera dicho...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-10-14','Ana: Envío correo a Ana Marta, TS CAMP Plasencia (anamarta.fernandez@salud-juntaex.es): "Te adjunto el Consentimiento Informado para las Medidas de Restricciones Físicas de Movimiento relativas a BRAHIM EL KINTY SNEIBA, firmadas digitalmente por el Presidente de la CTAEX, tras haber recibido el visto bueno del fiscal para su firma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-14','Ángel: En relación con la solicitud de averiguación patrimonial solicitada al Juzgado, con respecto a Daniel Granados García, para el pago de la responsabilidad civil de 20.000 euros, envío contestación a Ana. Sale de la cárcel en 2025. Hasta entonces nada. ····················· Ana: Comunicado al CRR el día 17.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2022-10-14','TERESA SITUACION ECONOMICA SE PROPONE X ÁREA SOCIAL DAR LA TOTALIDAD DE LOS INGRESOS (INCLUIDAS LAS PAGAS EXTRAS) AL TUTELADO. X EL ÁREA ECONÓMICA SE LIMITAN ESTOS GASTOS A QUE LA EVOLUCIÓN DEL SALDO NUNCA SEA NEGATIVA. • SE DECIDE MANTENER REINTEGRO 50 €/SEMANAL (217 €/MES). • TERE DISPONE DE 180 € PARA EXTRAS HASTA 31/12/2022, QUE DISTRIBUIRÁ A SU VOLUNTAD DE ACUERDO CON EL TUTELADO. • TERE DISPONE DE 745 € PARA EXTRAS DESDE 01/01/2023 HASTA 31/12/2023, QUE DISTRIBUIRÁ A SU VOLUNTAD DE ACUERDO CON TUTELADO.  DICHO IMPORTE DE 745 € SE VERÁ REDUCIDO EN CASO DE QUE LA MEDIA DE CONSUMOS SUPERE LOS 85 €/MES PRESUPUESTADOS.  DICHO IMPORTE DE 745 € SE VERÁ REDUCIDO EN CASO DE TENER QUE AFRONTAR CUESTIONES QUE AFECTEN "GRÁVEMENTE" AL PATRIMONIO DEL TUTELADO (GASTOS MÉDICOS ELEVADOS, EMBARGOS, ETC.). • TERE COMUNICARÁ LOS GASTOS EXTRAS, CON EL LÍMITE PACTADO A OSCAR QUE LLEVARÁ UN CONTROL DE LOS MISMOS EN LA FICHA DEL TUTELADO. • OSCAR COMUNICARÁ A TERES LA MINORACIÓN DEL SALDO DEL QUE DISPONE PARA EXTRAS (EN CASO DE INCREMENTO DE CONSUMOS O DE IMPREVISTOS DE ESPECIAL RELEVANCIA). • FINALIZADO EL AÑO Y TENIENDO EN CUENTA LOS POSIBLES IMPREVISTOS (AQUÍ SI SE TENDRÁN EN CUENTA LOS GASTOS MÉDICOS, EMBARGOS Y SIMILARES QUE SE HAYAN TENIDO QUE ABONAR), LA CANTIDAD DE LA QUE TERE DISPONDRÁ PARA 2024 SE RECALCULARÁ CONFORME A LOS DATOS DE 2023 Y CON EL MISMO CRITERIO DE EVOLUCIÓN NO NEGATIVA DEL SALDO.','2');
