insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-10-14','Ana: Remito a Mabel, Directora del CAMF (mariaisabeljimenez@imserso.es): CI para la Administración de las Vacunas de la Gripe Estacional y Covid (4ª dosis) firmado por el presidente CTAEX.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-10-14','miguel, solicitamos de nuevo internamiento involuntario al Juzgado Decano de Cáceres (por 2º vez) ya que desde junio no nos han asignado juzgado y procedimiento. Incorporamos los informes de incidencias y médicos desde junio hasta ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-07','miguel, la notaria me remite el borrador de la escritura de herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-10','miguel, remito a la notaria el testimonio que faltaba de aceptación del cargo de Raul: Buenos días, adjunto el testimonio que nos ha remitido el juzgado. Cuando puedan indicarnos si está todo correcto y cuándo se firmará para organizar la firma de la herencia con la notaria de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2022-10-14','- Oscar escribe : Esta señora entró a finales de 2019. Sólo podríamos haber hecho las declaraciones de IRPF de 2020 y 2021, de habernos informado la familia que hacía la declaración de la renta (el hermano fue quien propuso su incapacitación). Pongo en copia a Miguel, por si puede aclarar con Hacienda las declaraciones que faltan por pagar y que nos las envíen y la apunto en el Excell para hacerla el año que viene. En cualquier caso, los embargos han sido de 916,93€ y 377,82€. Teniendo más de 500.000 € y tres viviendas en la mejor zona de Badajoz, no deberían preocuparse tanto. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2022-10-14','- Oscar escribe : Esta señora entró a finales de 2019. Sólo podríamos haber hecho las declaraciones de IRPF de 2020 y 2021, de habernos informado la familia que hacía la declaración de la renta (el hermano fue quien propuso su incapacitación). Pongo en copia a Miguel, por si puede aclarar con Hacienda las declaraciones que faltan por pagar y que nos las envíen y la apunto en el Excell para hacerla el año que viene. En cualquier caso, los embargos han sido de 916,93€ y 377,82€. Teniendo más de 500.000 € y tres viviendas en la mejor zona de Badajoz, no deberían preocuparse tanto. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2022-10-14','Buenos días, en el banco Caja Rural de Extremadura, tiene autorizado un reintegro de 200€, al entrar a comprobar veo que el día 4 de octubre, le han dado 250€, que no entiendo el motivo. Arriba adjunto PDF, enviado al banco. Volveré a enviar de nuevo para que quede constancia que no tiene autorizado más dinero de los 200€ Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-10-14','Ana: Llamada de Juan José, dice que en la cita con el Cardiólogo le han dicho que no han encontrado ninguna anomalía, está todo bien. Cuando nota la opresión en el pecho es de los nervios. ············· Pregunta por el último presupuesto de barra y pesas que ha remitido, su cumpleaños es el día 18. *Le informo que está pendiente de la aprobación de la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-09-07','Ana: Estrella, secc. ecca, remite por mail a Pilar Cerrillo la Autorización Bancaria para, una vez ingrese, abonar el precio públ. estipulado para la plaza en la Res. Balcón de Extremadura de Montánchez además de la autorización para realizar las gestiones y abonar los gastos relativos al sepelio. ············· *Aún no le ha concedido la plaza en este recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-14','Buenos días, Amalia. Ayer me comentó el psicólogo de la UHB que le habían llamado de la UME porque Mercedes Perez Pinna era la siguiente para poder ingresar en la UME. Al parecer querían entrevistarse con ella, pero hemos quedado antes en preguntar si esa entrevista tenía que ser en persona e informarles de dónde se encuentra actualmente Mercedes. Supongo que tanto ella como vosotros aceptaríais la plaza en UME de Mérida, ¿no? Ya te iré informando Saludos Juan José Marín Píriz Trabajador Social del Hospital Universitario de Badajoz juanjose.marin@salud-juntaex.es Ext.: 48330','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-10-14','Ana: Recibimos Cdos. de Pensiones del INSS, Jubilación = 354,89 € y Viudedad = 977,68 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-10-14','Ana: correo del programa de familia: "Lo de la empresa de limpieza podemos preguntar y mirarlo. Te digo algo en breve, vale? Yo también creo que debería cambiar las cerraduras, si lo hacemos y Felisi no esconde ninguna llave en la cochera no podrán acceder a la vivienda a no ser que rompan ventanas y demás, que no creo que lo hagan. El cristal también habría que ponerlo porque además es de una ventana que da a la calle y es baja. Si queréis se lo proponemos a Felisi que no va a tener problema y puede hacerlo con la asignación semanal que tiene (al menos las cerraduras). Hoy precisamente iremos a acompañarle a sacar dinero, se lo comentamos. La alarma es de movistar, y puede que la tengan contratada junto a la fibra y una tele que deben tener financiada. Hace bastante nos hablaron de una cuanta que Aitor había abierto en una sucursal de La Caixa en Badajoz pero no te puedo decir más, no sabemos si lo tendrá domiciliado en esa cuenta ni siquiera de donde sacaron dinero para meter en esa cuenta. Lo ideal sería que Felisi, una vez solucionado la limpieza y demás del domicilio volviese a Navas, sí. Lo iremos trabajando si te parece, aunque creo que eso nos puede costar un poco pero bueno, poco a poco." ····························································································································································································· Mi respuesta: "Pues sí, dado que Felisi tienen dinero en la tarjeta monedero de una quincena que no ha sacado, podría asumir de ahí el gasto de cambio de cerradura y cambio de cristal de la ventana en cuestión. Pediré también al programa de apoyo comunitario, gestionado por Futuex, que apoyen también en la intervención para hacerle entender la conveniencia de que regrese a su casa y que no esconda llave alguna en la cochera ni similar. *No sé si habría posibilidad de que guardaseis una copia en las dependencias del programa de familias, en el ayuntamiento o similar, si ella así se quedara más tranquila. *Donde tampoco consideramos que debería dejar ninguna, es en la casa de los padres de Jesús. En cuanto a los contratos que hizo Aitor, si lo hubieran domiciliado en su cuenta bancaria, de la que aquí se tiene constancia y con la que se opera, se dará de baja. Si es con la nueva cuenta, no sabemos si será posible, pues desde la Sección Económica ya pidieron en su día información a La Caixa y no han dado respuesta. Pediremos que lo vuelvan a intentar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-10-14','miguel, hablo con el juzgado de Plasencia nº1 y le confirmo que asistiremos por videoconferencia. Inés llamará para pedir los códigos de conexión. Compruebo que ya comuniqué a Rosa del CSS y ésta me confirmó que le acompañarán el lunes a las 11h sala 1 del juzgado. ***************************************** Me llama la abogada Estrella Barbero 927-418014 que va a intentar llegar a una conformidad a lo que pide el Ministerio Fiscal. Aunque el lunes me confirmará, seguramente con rebaja de alguna de las siguientes sanciones, en principio quedará la pena de la siguiente forma: 3 años de prisión (sustituidos por 4 años de internamiento en régimen cerrado. No habría inconveniente para su cumplimiento en el propio CSS, siempre que haya sitio en el momento de ejecutar la sentencia) Multa de 11 meses a 5€ diarios Responsabilidad civil por daños 11.500€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-10-14','TERESA M. Antonia se fue esta mañana. Su prima me ha llamado muy disgustada porque no se le ha avisado con tiempo. Me dice tal cual que ella no se va hacer responsable de ella este fin de semana pues no le ha podido preparar comidas, compras… En cuanto a Claudia la iba avisar de que llegaba M. Antonia pero no sabía de cierto si está o no disponible este fin de semana. Ya le he dicho que la solución la tienen ellas (tan solo le tienen que decirle a M. Antonia que no se puede ir y nada más).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-10-14','Ana: Informe Social para Inventario: Residente en el CAMF de Alcuéscar desde diciembre de 2018. Soltera. Presenta tetraparesia secundaria a Ataxia de Friedrich y habla escandida. Grado de discapacidad reconocido: 96% y Grado II de Dependencia. ··· Precisa ayuda para todas las ABVD. ·· Deambula en silla de ruedas eléctricas. *Percibe una PNC con complemento ATP. ············································· *Remito correo a Alberto, Jefe Secc. Ecca., detallando todos los problemas económicos que presenta, elevados gastos, desproporcionados en relación a sus ingresos, numerosos créditos en distintas financieras y su propia entidad bancaria, tarjetas de crédito, múltiples compras online.... *No acepta apoyo ni supervisión al respecto que le ofrecen desde el centro. *Solicito baja de las tarjetas bancarias, recalcular asignación y extras. ······························································································································································································· Remito a Mabel, Directora del CAMF (mariaisabeljimenez@imserso.es): CI para la Administración de las Vacunas de la Gripe Estacional y Covid (4ª dosis) firmado por el presidente CTAEX.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-10-14','Ana: Informe Social para Inventario: Residente en el CAMF de Alcuéscar desde diciembre de 2018. Soltera. Presenta tetraparesia secundaria a Ataxia de Friedrich y habla escandida. Grado de discapacidad reconocido: 96% y Grado II de Dependencia. ··· Precisa ayuda para todas las ABVD. ·· Deambula en silla de ruedas eléctricas. *Percibe una PNC con complemento ATP. ············································· *Remito correo a Alberto, Jefe Secc. Ecca., detallando todos los problemas económicos que presenta, elevados gastos, desproporcionados en relación a sus ingresos, numerosos créditos en distintas financieras y su propia entidad bancaria, tarjetas de crédito, múltiples compras online.... *No acepta apoyo ni supervisión al respecto que le ofrecen desde el centro. *Solicito baja de las tarjetas bancarias, recalcular asignación y extras. ··········· Pediré a Felisa Custodio, TS CAMF, que solicite a la familia copia de la póliza del seguro de decesos. ······························································································································································································· Remito a Mabel, Directora del CAMF (mariaisabeljimenez@imserso.es): CI para la Administración de las Vacunas de la Gripe Estacional y Covid (4ª dosis) firmado por el presidente CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-10-06','TERESA EMAIL FUTUEX la información de Pedro Tomas para llevar a cabo el ingreso en la unidad de desintoxicación de Plasencia. Ha tenido algunos positivos, en cedex ultimamente y asi lo consideraron alli y el parece estar de acuerdo. Ademas ha tenido algun problema con su pareja actual, están regular,.. ella le acusa de robarle 400 eu y hace un par de noches tuvo otro episodio de consumo, Solicitan un informe con el motivo de la tutela y de su situación actual, para que desde la Comisión solo se tenga que adjuntar porque fue tutelado. le acompañamos al CEDEX ya que tenía consulta con la psicóloga y el médico. Días anteriores su pareja ya nos había comunicado que la situación entre ellos era mala, que Pedro estaba bebiendo y que ella tenía pensado dejar la relación. Informa que se irá del domicilio a casa de una amiga una vez que Pedro se vaya al centro. (A dia de hoy, 6 de Octubre la relación sigue siendo regular, pero continua en el domicilio): Cuando llegamos al centro la psicóloga pregunta si va hacerse voluntariamente control, a lo que Pedro indica que no porque dará positivo. Lleva sin realizarse los últimos controles, indicando Candi (pareja) que esa decisión la ha tomado ella porque sabía que estaba bebiendo y daría positivo. Desde el CEDEX le indican que ella no puede tomar esa decisión, que allí deben comprobar la sustancia que toma no solamente el beber alcohol es justificación para faltar a los controles. En la consulta de psicología, primero entra Pedro a la consulta y al poco tiempo solicitan entrar a la terapeuta ocupacional del programa y su pareja Candi. Nos informa que en el último control (31 agosto 2022) Pedro Tomás ha dado positivo en cocaína. Información que ha ocultado al programa, en los seguimientos realizados para sacar dinero en el mes de septiembre. Plantea que tras esta recaída se debe tomar una decisión ya que el tratamiento ambulatorio no está funcionando y ella propone una comunidad terapéutica opción que Pedro rechaza, aceptando irse a la unidad de desintoxicación de Plasencia, (sabe que esta opción es para un corto periodo de tiempo y creemos que por eso acepta). Tanto con el médico como con la psicóloga se valoran las causas que han llevado al consumo; En primer lugar, se determina que Pedro no tiene una actitud de rechazo al consumo que lo hace porque le viene impuesto por terceras personas (pareja, profesionales de apoyo…) Los trabajos de colaboración en la radio y en actividades culturales del ayuntamiento son la excusa que pone y el medio que utiliza para seguir consumiendo y teniendo una vida social donde se den las oportunidades para consumir. No lo ve como un peligro y no indica dejar esta actividad o realizarla solo ocasionalmente. Existen indicios que a través de estas colaboraciones recibe dinero en metálico. En relación a los consumos indica que el último de cocaína fue el pasado 28 de agosto y que se la ofrecieron, mintiendo en este aspecto ya que debe dinero por comprar estas sustancias y refieren que alguien del pueblo les amenaza por no pagarle. Ante esta circunstancia Candi ha pagado algunas de sus deudas por miedo. En el último mes ha seguido consumiendo alcohol de forma habitual, diciendo que el día anterior había bebido 6 latas de cerveza que es un total de 2 litros. En relación a su tratamiento para el trastorno bipolar, en la última revisión de psiquiatría el pasado 31 de agosto le reajustaron la medicación pautándole el Abilify maintena cada 20 días, pero nos indica que le tocaba hace unos días, pero no ha ido a ponérselo. Desde el CEDEX de Castuera van a tramitar toda la documentación para el ingreso a la unidad de desintoxicación de Plasencia. La trabajadora social es Sila. Correo electrónico: sila.sanchez@salud-juntaex.es. Nos solicita un informe social de la situación actual de Pedro y que se incluya la situación que le llevó a estar tutelado junto con el número de sentencia. Adjuntamos al correo un pdf con la información de la ropa y los enseres que precisa en su ingreso. Nos comunican también que necesitará un test de antígenos antes del ingreso y llevar otro consigo para hacérselo allí pasado unos días. El médico del centro le da la documentación para que en su centro de salud solicite una analítica y la prueba de Mantoux (para descartar tuberculosis). Como último la trabajadora social pide una persona de contacto y un teléfono de Comisión tutelar de adultos. ....ENVIO INFORME SOCIAL A SILA Y LE INDICO QUE YO SOY LA PERSONA DE REFERENCIA....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-10-17','Ana: Correo del sábado 15 de Ceferino: "Buenos días Ana te escribo este correo porque quisiera marcharme del CRR. Ya llevo más de cuatro años y quisiera emprender mi vida en un piso de alquiler en Plasencia. Si tengo que estar en el piso estaré pero no por mucho tiempo por favor quiero llevar una vida autónoma Javier el gerente ha dicho que se van a hacer más pisos y quisiera irme a uno de ellos o si no alquilarme el mío propio por favor Ana y comisión tutelar espero que me ayudéis en este proyecto de mi salida del CRR de Plasencia un saludo" ·················· Respondo con copia a Blanca y Paula, CRR: "Entiendo que tengas otros proyectos en mente y desde aquí se intenta apoyar aquellos que se consideran que son adecuados y beneficiosos para ti. Pero tú tienes que entender que la Comisión Tutelar de Adultos tiene una responsabilidad con respecto a ti por mandato judicial y todas las decisiones tienen que ser justificadas y coherentes con dicho mandato. Desde el Gabinete Técnico de la Comisión, trabajamos de forma coordinada con las técnicos del CRR y no vamos a tomar ninguna decisión sin tener en cuenta su criterio, e intentaremos, como siempre, hacerlo de forma consensuada con ellas, pues son quienes mejor conocen tu evolución y te apoyan y guían en tu proceso terapéutico. He de recordarte, además, que con frecuencia cambias de idea en muchas de tus decisiones y en los últimos años ha solicitado en numerosas ocasiones cambiar de recurso dando marchas atrás en tu decisión poco tiempo después. Pongo en copia a Blanca y Paula, intentaré hablar con ellas entre hoy y mañana, si a ellas también les viene bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-10-17','Ana: Llamo a José Manuel (627 788 797): transmito la decisión tomada desde la secc. ecca.: Él debe abonar las tasas del DNI con su asignación. ········ Dice que también tiene que pagar las fotos y que en total le suponen casi 17 €. ····· Pide también dinero para cortarse el pelo, 12 €. Dice que no tiene para todo, que tiene que comprar también productos de limpieza y leche. *Se lo plantearé a Alberto, Jefe Secc. Ecca. ································································································································ *Llamo a Paqui, Coordinadora del SAD-Eulen (629 557 324), comunico que el próximo miércoles 26, José Manuel tiene cita a las 10:37 h. para renovarse el DNI. Acordamos que la Aux. acudirá al domicilio en el horario habitual (9:00 h) y después le acompañará a la Comisaría. Si a las 11 h no han terminado ella se marchará. ··········· *Llamo de nuevo a José Manuel y se lo explico. ············· *Lo comunico también por mail a Toni-Futuex. Ya no hay necesidad de que le acompañe Virginia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-17','miguel, recibo email de Amelia: Buenos días, Miguel Me han llamado de la notaría de Brihuega para firmar la escritura de aceptación herencia, hemos quedado el miércoles 26 de octubre a las 11 mañana. Me comentan que vosotros tenéis que ratificar esa escritura o bien simultáneamente o que puedo recoger la escritura más tarde y enviaros la para su ratificación. Me vas diciendo si es correcto, gracias ________________________________________ envío email a la abogada con copia a Amelia: Buenos días Mª Teresa, tal como comentamos necesitamos vaya preparando solicitud para aceptación, aprobación de herencia. Recuerde que se querrá poner a la venta, cuyo importe entiendo que se basará en la tasación. Ruego conteste al email que le remití el 14-9-22 indicandome cuenta, concepto al que hacer ingreso de provisión, honorarios, y me indique los datos del procurador al nombre del que irá el poder apud acta para que vayamos haciendolo. La herencia se quiere firmar en la notaria de Brihuega el día 26-10-22 por lo que necesito nos indique si puedo ratificarla o tendré que esperar. *************************************** Envío email explicativo a Amelia (tía de los hnos Gil Sanz): Buenos días, según me indicó la abogada Mª Teresa Muelas Mazario, mtmuelas@icaguadalajara.org; Tnos.- 949212660/616292983, ella pedirá tras la firma de la herencia la solicitud de aprobación de la herencia. La idea que tengo es que solicite junto a esa aprobación, la autorización para vender, cuyo precio y documentación nos tendrá que ir solicitando y yo te iré pidiendo a través de ella o ella directamente. En cuanto a la firma de la ratificación quedo a la espera de lo que me diga la abogada de si puedo o no firmar inmediatamente la ratificación de esa herencia. ******************************************************* Hablo telefónicamente con la abogada Mª Teresa quién me indica que me mandará los datos del procurador, número de cuenta, que intentará pedir simultaneamente aprobación de herencia y autorización de venta y que hablará con Amelia para decirle que la resolución judicial se ajustará a la tasación (salvo prueba en contrario)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-17','miguel, recibo email de Amelia: Buenos días, Miguel Me han llamado de la notaría de Brihuega para firmar la escritura de aceptación herencia, hemos quedado el miércoles 26 de octubre a las 11 mañana. Me comentan que vosotros tenéis que ratificar esa escritura o bien simultáneamente o que puedo recoger la escritura más tarde y enviaros la para su ratificación. Me vas diciendo si es correcto, gracias ________________________________________ envío email a la abogada con copia a Amelia: Buenos días Mª Teresa, tal como comentamos necesitamos vaya preparando solicitud para aceptación, aprobación de herencia. Recuerde que se querrá poner a la venta, cuyo importe entiendo que se basará en la tasación. Ruego conteste al email que le remití el 14-9-22 indicandome cuenta, concepto al que hacer ingreso de provisión, honorarios, y me indique los datos del procurador al nombre del que irá el poder apud acta para que vayamos haciendolo. La herencia se quiere firmar en la notaria de Brihuega el día 26-10-22 por lo que necesito nos indique si puedo ratificarla o tendré que esperar. *************************************** Envío email explicativo a Amelia (tía de los hnos Gil Sanz): Buenos días, según me indicó la abogada Mª Teresa Muelas Mazario, mtmuelas@icaguadalajara.org; Tnos.- 949212660/616292983, ella pedirá tras la firma de la herencia la solicitud de aprobación de la herencia. La idea que tengo es que solicite junto a esa aprobación, la autorización para vender, cuyo precio y documentación nos tendrá que ir solicitando y yo te iré pidiendo a través de ella o ella directamente. En cuanto a la firma de la ratificación quedo a la espera de lo que me diga la abogada de si puedo o no firmar inmediatamente la ratificación de esa herencia. ********************************************************** Hablo telefónicamente con la abogada Mª Teresa quién me indica que me mandará los datos del procurador, número de cuenta, que intentará pedir simultaneamente aprobación de herencia y autorización de venta y que hablará con Amelia para decirle que la resolución judicial se ajustará a la tasación (salvo prueba en contrario)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-10-17','miguel, se llega a una conformidad de nuestra abogada (Estrella Barbero 927-418014 y 675758841 e email estelabarbero@icac.es) con el MF en el procedimiento abreviado 400/2021 del jzdo de lo penal 1 de Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='MULERO'and apellido2='SALGUERO'),'2022-10-17','TERESA ME PONO EN CONTACTO CON ELENA 924541106 DE LA RESIDENCIA NTRA SRA DEL AMPARA DE BURGUILLOS. EL TOTAL DE LA DEUDA POR LA PLAZA 6800€ YA QUE ESTABA COBRANDO LA AYUDA POR DEPENDENCIA DESDE NOVIEMBRE DE 2021 Y NO ESTABA PAGANDO EL IMPORTE TOTAL DE LA PLAZA. ACORDAMOS PAGO DE LA PLAZA 1000€ TRANSFERNCIA PERMANENTE TRANSFERENCIA PUNTUAL DE 50€ PARA GASTOS DE PODOLOGIA Y PELUQUERIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-10-17','miguel, envio email a Oscar: Oscar indicame el saldo que tiene actualmente en cuenta y cuánto cobra el tutelado mensualmente. Si tiene algún gasto importante dimelo también. Número de cuenta al que pueden cargar la multa e indemnización del procedimiento abreviado 400/2021 del jzdo de lo penal 1 de Plasencia. Se va a llegar a una conformidad de una multa de unos 1.200€ e indemnización de unos 11.500€ de cuando quemó el psiquiatrico de Plasencia… *********************************************** contestacion de Oscar: - Saldo: 51.525,53 €. - Cobra pensión de orfandad de 603,17€ * 14 pagas y pensión familiar por hijo a cargo de 417,70€ * 12 pagas. - Gastos mensuales centro 735€ mes aprox. - Gastos extras: 12.000 € de un embargo judicial de 9 de junio de 2021. - Cuenta de Unicaja: ES6621037114020010288670.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-17','miguel, recibo email de la abogada Teresa Muelas: Buenos días Perdone el error. Creí que les había enviado un email indicándoles que la notaría no va a necesitar que solicitemos primero autorización para la aceptación de herencia. Está tramitando la escritura para que procedamos a la aceptación. Posteriormente habrá que acudir al juzgado para la aprobación de la partición. Debió ocurrir algún problema porque es cierto que no lo encuentro en correos remitidos. Pues bien. Como les digo, la notaría está preparando la escritura, con lo que nos ahorramos un trámite. Sería bueno que la persona que hizo el encargo, insista a la oficial para que se de un poco de prisa. Yo insistiré también esta semana. En cuanto a provisión de fondos, y procurador, se los indico enseguida. ************************************************ mi contestación: Gracias, quedo a la espera de los datos del procurador/a y del número de cuenta, importe, concepto. Entiendo que podemos ratificar simultáneamente el día 26-10-22 es así?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-17','miguel, recibo email de la abogada Teresa Muelas: Buenos días Perdone el error. Creí que les había enviado un email indicándoles que la notaría no va a necesitar que solicitemos primero autorización para la aceptación de herencia. Está tramitando la escritura para que procedamos a la aceptación. Posteriormente habrá que acudir al juzgado para la aprobación de la partición. Debió ocurrir algún problema porque es cierto que no lo encuentro en correos remitidos. Pues bien. Como les digo, la notaría está preparando la escritura, con lo que nos ahorramos un trámite. Sería bueno que la persona que hizo el encargo, insista a la oficial para que se de un poco de prisa. Yo insistiré también esta semana. En cuanto a provisión de fondos, y procurador, se los indico enseguida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-17','Perdone el error. Creí que les había enviado un email indicándoles que la notaría no va a necesitar que solicitemos primero autorización para la aceptación de herencia. Está tramitando la escritura para que procedamos a la aceptación. Posteriormente habrá que acudir al juzgado para la aprobación de la partición. Debió ocurrir algún problema porque es cierto que no lo encuentro en correos remitidos. Pues bien. Como les digo, la notaría está preparando la escritura, con lo que nos ahorramos un trámite. Sería bueno que la persona que hizo el encargo, insista a la oficial para que se de un poco de prisa. Yo insistiré también esta semana. En cuanto a provisión de fondos, y procurador, se los indico enseguida. ************************************************** mi contestación: Gracias, quedo a la espera de los datos del procurador/a y del número de cuenta, importe, concepto. Entiendo que podemos ratificar simultáneamente el día 26-10-22 es así?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-10-17','miguel, me llama la tutelada 927-095795 y tras conversación con ella explicandole que el escrito es inviable juridicamente hablando (distintas pretensiones, falto de fundamento jurídico yde pruebas, dirigido a multiples organismos, mal dirigido, falta de tipicidad, falto de concruencia...) Envío email a la parte social: Buenos días, me acaba de llamar Mª Antonia preguntándome qué se puede hacer con la documentación que os escanee y os remití. Ya le he explicado que no somos abogados y que el escrito a mi entender es inviable, dirigido a multiples organismos, no se sabe qué solicita pues toda diversas materias (problemas con la Administración, vulneración de derechos humanos, temas penales)…A parte que muchos de estos escritos viene el sello de haberlo presentado en ante el Tribunal Supremo, otro dirigido al Consejo de Ministros…es incoherente en todos los sentidos y tal como le he explicado no puede acogerse a nuestro ordenamiento jurídico (falto de concreción de qué quiere, de pruebas, de fundamento jurídico de normativa, jurisprudencia…) Entiendo que la parte social debéis actuar en este expediente lo antes posible ya que en Colegio de Madrid no quieren atenderla, y ya le he explicado que al residir en Plasencia habrá de tener que dirigirse al Ilustre Colegio de Abogados de Cáceres, al menos para que la asesoren… Tampoco puedo contestarla por escrito porque envió esta documentación por sobre sin registro de entrada…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-17','miguel, email de Amelia: *********************************************************** mi contestación: Hola, quedamos pendiente de las indicaciones de Mª Teresa en cuanto a la fecha en la que podamos ratificar esa escritura de herencia y nos aclare el valor a partir del que finalmente se podrá vender…Por eso las cuestiones relacionadas con la venta tendrás que hablarla directamente con ella. Como te comenté todas las ventas realizadas con intervención de la Comisión Tutelar se han hecho por importe igual o superior al que figuraba en tasación, pero si la abogada logra que el juez resuelva por un importe inferior no nos vamos a oponer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-17','Ana: Tal y como acuerdo con Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es) remito correo: "Adjunto remito la SOLICITUD DEL REVISIÓN DEL GRADO DE DEPENDENCIA Y SOLICITUD DE RECURSO RESIDENCIAL, relativo a Miguel Ángel Ramos Andrés, firmado digitalmente por el Presidente de la CTAEX. Así mismo adjunto la siguiente documentación para aportar junto a la solicitud: - Testimonio de Sentencia Medida Judicial de Apoyo y Nombramiento - Testimonio de Aceptación del Cargo de Curatela Representativa - Copia del DNI del Presidente de la CTAEX - Decreto de Nombramiento de Director Gerente del SEPAD - Resolución de Delegación de Competencias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-10-17','Ana: Remito a Miguel, Asesor Jurídico CTAEX: "Buenas tardes Miguel, Tal y como hemos acordado, te remito los correos de enfermería y psiquiatría (en PDF) y el Informe de Psiquiatría del Equipo de Salud Mental de Plasencia, para comunicar al Juzgado el cumplimento de tratamiento ordenado como Medida de Seguridad por tres meses, para que lo comuniques al Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2022-10-17','Ana: Isabel Pino, TS SSASB Miajadas, me remite el Informe Social solicitado. ························ Lo guardo en el expdte. digital y se lo reenvío a Ángel, Asesor Jurídico: "Te envío el Informe Social para revisión de la sentencia de Curatela de VANESA FERNÁNDEZ GÓMEZ. El informe es breve pero conciso y creo que suficiente para que adopten nuevas medidas, más uniendo los informes de la sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-17','Ana: Conversación telefónica con Paula, TO CRR (682 70 44 01): le hago propuesta ecca. que plantea Alberto, Jefe Secc, de extra anual de 900€, a partir del 01/01/23 con todos los requisitos que plantea. *Lo valorarán en equipo y nos dirán algo al respecto. ·········· *Por otra parte, de aquí a final de año se autorizan, por parte de Alberto, los siguientes gastos: "• RELOJ: SI, MÁXIMO 50 €...SE ENCARGA OSCAR. • VIAJES A TRUJILLO: 170 € PARA VIAJE OCTUBRE Y 170 € PARA VIAJE DICIEMBRE...TODO IMPORTE QUE SOBRE PASE LO ANTERIOR DEBERÁ ABONARLO LA TUTELADA DE SU REINTEGRO." *Paula se lo comunicará a Isabel. ·················· Pregunto por el TRATAMIENTO PSICOLÓGICO que estaba estaba realizando en consulta privada y me informa que ya lo ha FINALIZADO y con éxito. ················································································································································································································· Envío a Julio, CTAEX: - Oficio-solicitud de certificado actualizado de pensión de orfandad - Testimonio de Sentencia de incapacitación, nombramiento y aceptación del cargo para que le dé registro en SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-10-18','TERESA ENVIO SOLICITUD CERTIFICADO DE PENSIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-18','Ana: Correo de ayer por la tarde de Isabel (imariacano.ic@gmail.com): "Buenas tardes Ana te quería contar una cosa mi madre se va a separar de su pareja y se quiere venir a vivir aquí a Plasencia y me ha dicho que si puedo yo vivir con ella para que ya no esté sola y yo esté aquí y esté mejor con mi madre en enero a un año desde que estoy aquí en el CRR y la verdad me gustaría irme con mi madre a vivir aquí a Plasencia si tengo que esperar más tiempo espero pero no mucho eh que ya estoy un poco harta del crr." ················································································································································································································ Mi respuesta: "Buenos días Isabel, Como sabes, la Comisión Tutelar de Adultos tiene una responsabilidad con respecto a ti por mandato de un juez, a quien tenemos que rendir cuentas de nuestra actuación. Así mismo, desde el Gabinete Técnico de la Comisión Tutelar de Adultos, al igual que en el CRR, tenemos que velar por tu bienestar e intentamos tomar decisiones beneficiosas para ti en todos las áreas de tu vida, teniendo siempre en cuenta el criterio técnico de las profesionales del CRR que son quienes mejor conocen tu evolución y te apoyan y guían en tu proceso terapéutico. Aunque entendemos que tu madre te eche de menos, ella tiene que entender que tú, a día de hoy, tienes una serie de necesidades que ella no puede atender, pues no cuenta con la formación y preparación necesaria. En cambio, en el centro de rehabilitación en que el vives ahora, cuentas con especialistas que te ayudan en tu día a día y con las que has evolucionado a mejor en estos últimos meses, tú sabes lo beneficioso que ha sido para ti residir este tiempo ahí. No obstante, es un proceso que requiere tiempo y haz de tener paciencia para culminarlo con éxito y no volver a recaer. Pongo en copia a Blanca, Carolina y Paula, para que estén informadas y puedan tratar también esta cuestión contigo. Si ellas lo consideran necesario, hablaremos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-10-18','miguel, llega email del abogado y la procuradora: Buenas tardes, Estimados Miguel y Jorge Acaba de enviarme el árbitro la notificación del laudo a la parte contraria en fecha 3 de octubre, El plazo que ponía en el laudo para cumplimiento era de 1 mes , por tanto plazo para cumplimiento 3 de noviembre Estoy a la espera de que me envíe la proforma con sus honorarios , en cuanto la tenga os la paso Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-18','Ana: Correo de Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net): "Os comento sobre M. Isabel Cano Blázquez. Ayer tras salida en horario tarde- noche, avisa que ha sufrido una agresión sexual, Se activó protocolo, se acudió al hospital para valoración donde la vieron forense y policía. Según informe no se encuentran signos. está incapacitada legalmente. Nos recomiendan poner denuncia. Hoy tras coordinación con UFAN la unidad que lleva los temas de agresiones subiremos a interponer la denuncia. Os vamos contando. Si desde la comisión como tutores legales consideraís otros tipo de actuaciones nos decís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-10-18','Ana: Remito correo a Toni-Futuex: "No sé si habéis llegado a intentar contactar de nuevo, y visitar, a Ventura Gómez Gía. La Trabajadora Social del Hogar Peña del Cura de Cáceres, que os comenté, sigue trabajando con él y está bastante implicada, como os comenté podéis intentar organizar una visita conjunta, si es que no lo habéis hecho ya, claro. Por otra parte, él está pendiente de poder recibir tratamiento bucodental, puede ser otro motivo para “enganchar” con él. Pues, dado que tienen reconocido, según el Dictamen Técnico del CADEX, “Inteligencia límite”, reúne los requisitos para ser usuario del programa PADDI. Por eso, os pedimos, que por favor, intentéis, solicitarle cita para dicho programa e incluso que le acompañéis el primer día, aportando el Certificado de Discapacidad y el Dictamen Técnico del CADEX." ········································· *Subo al portafirmas digital la solicitud del Catering Municipal. ·············· Consulto en el IMSERSO (91 266 77 13) por el plazo de solicitud de los Programas de Termalismo. Los del año que viene (Ventura quiere para Febrero y Marzo) no se abrirá hasta final de año. Indican que volvamos a consultarlo a primeros de diciembre. ··································································································································································································· Envío correo Registro del SES (oac.merida.san@juntaex.es): "Buenas tardes, En representación de D. Ventura Gómez García, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, os remito Oficio y Solicitud de Servicio de Comida a Domicilio Municipal, junto con toda la documentación relacionada a continuación e indicada tanto en la propia solicitud como en el oficio, para dar REGISTRO: - DNI de la persona interesada - DNI del Presidente de la Comisión Tutelar de Adultos - Testimonio de Aceptación del cargo - Decreto de Nombramiento del Director-Gerente del SEPAD - Resolución de delegación de competencias como Presidente de la CTAEX - Informe de Salud - Certificado de discapacidad del CADEX La solicitud va dirigida a: INSTITUTO MUNICIPAL DE ASUNTOS SOCIALES C/ Atahualpa, s/n 10005 – Cáceres CÁCERES"','2');
