insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-10-18','Ana: Comunico a Juan José (667 958 878) que se autoriza, por su cumpleaños, el presupuesto para material deportivo del Decathlon (barra de musculación y discos). Se abonará mediante transferencia bancaria. ······················ Aprovecha para contarme que hoy ha ido hacerse análisis de orina y que mañana a las 13h tiene cita con la TS del ESM (Pilar Martín), según él, Pedro, el TO, le ha recomendado que acuda en relación a la modificación de la legislación relativa a la capacidad jurídica. (Yo ya se lo expliqué y añadí que si su hermana, como dijo, iba a solicitar la asumir ella el cargo, no era necesario hacer nada más)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-10-18','Ana: Llamo a José Manuel (627 788 797): comunico que se aprueba el presupuesto más económico del TV. *Le recuerdo que es por su cumpleaños y Navidad/Reyes, **no podrá pedir nada más por estos motivos. ······· Dice que ya se ha cortado el pelo en una peluquería LOW COST, así pues no se le dará más dinero por este concepto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-18','miguel, envío a la notaria de Brihuega: Buenos días, adjunto los certificados de nacimiento así como la autorización para firmar la ratificación en la notaria de c/ Romero Leal 24 de Mérida (Badajoz), tlfno 924-317761 de los notarios D. Gonzalo Fernández Pugnaire, D. Borja Igartua Fesser, y D. Francisco Javier Hernández Téllez. Los datos de contacto del oficial que tramitará dicha ratificación será jose Luis (tlfno 924-317761 ext 013) email joseluis@notariaromeroleal24.com Cuando esté firmada la herencia habrán de enviarla telemáticamente a uno de los 3 notarios para lo cual deberán hablar con José Luis para poder localizarla para su ratificación por esta Comisión Tutelar de Adultos. Habrán de indicarnos a qué hora si firmará para intentar ratificarla en la misma mañana del día 26-10-2022. No obstante si se firma tarde tendríamos que ratificarla el día siguiente. En otro orden, en principio vemos bien el borrador de la escritura de adjudicación de herencia. ************************************************ Envío email a José Luis de Notaria de Romero Leal: Buenas tardes José Luis, el día 26-10-22 se quiere firmar una adjudicación de herencia en la notaria de Brihuega de los padres fallecidos de dos hermanos tutelados por la Comisión Tutelar de Adultos. Adjunto la autorización para la firma de dicha ratificación, así como sus certificados de nacimiento y el borrador de la escritura. Necesitamos ratificar la misma mañana del día 26-10-22 en la medida de lo posible, para lo cual como verás debajo he enviado un email explicativo a aquella notaria de Brihuega.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-10-18','-Refiere Miguel ( jurídico ) que no es necesario solicitar autorización judicial para centro residencial , puesto que él voluntariamente ha decidido ingresar y ha elegido los sitios.','2');
