insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-10-18','Ana: Llamo a María Bueno, PNC D.G. SS.SS. (PNC): me comunica que la Resolución de la PNC la mandaron desde SS.TT. en julio al CAM de Trujillo. ············ O bien, se la pedimos a dicho centro y bien les enviamos un escrito solicitando la copia de la Resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-10-19','miguel, enviamos vía lexnet los 3 informes justificantes del cumplimiento de la pena de la ejecutoria 9/2022 del jzdo nº4 Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-10-17','Ana: correo de Toni-Futuex, comunicando el estado de insalubridad en que ha dejado Aitor la vivienda de su madre, una vez que se ha marchado a vivir a Badajoz. *Adjunta también fotografías (guardadas en el expediente digital). Han dejado todo sucísimos, con restos de comida, ropa, basura y otros objetos desparramados por toda la casa, el colchón sucio y lleno de manchas, insectos merodeando por los restos de comida, todo el maneje de cocina con suciedad acumulada y pegada desde hace tiempo, las sartenes quemadas... *Además ha instalado una alarma de Movistar, contrató un paquete con fibra, TV y alarma. ·············· Ahora cada vez que Felisa intenta acceder a su domicilio salta la alarma. ·················· Felisa se dio un sofocón al ver el estado actual de su vivienda y se muestra dispuesta a denunciar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-19','Ana: Correo de Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net): "Os informamos que Isabel se encuentra tranquila. Desde la Policía nacional nos llaman para citar a Ceferino a declarar ya que fue a él la primera persona a la que Isabel llamó para contar lo sucedido. Irá acompañado por un profesional del recurso. Le avisaremos ahora de la citación." ············· En otro correo adjuntan la denuncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-10-19','Ana: Correo de Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net): "Os informamos que Isabel se encuentra tranquila. Desde la Policía nacional nos llaman para citar a Ceferino a declarar ya que fue a él la primera persona a la que Isabel llamó para contar lo sucedido. Irá acompañado por un profesional del recurso. Le avisaremos ahora de la citación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-10-19','Ana: Tras reunirnos Alberto, Maite, Teresa y yo, envío correo a Toni-Futuex y a Raquel y María, programa de familia: "Comunicaros que acabamos de mantener una reunión de equipo con respecto a la situación de Felisa Felipe Teomiro, su vivienda y su hijo Aitor Moreno Felipe. Tras valorar toda la información que nos habéis transmitido desde ambos programas, se toman las siguientes decisiones y os pedimos de nuevo colaboración para apoyar a Felisi en distintas gestiones, además del apoyo emocional y otra índole que nos consta le estáis dando. - Los gastos que conlleve volver a adecentar la casa correrán a cargo de Aitor. - La limpieza de la vivienda, si desde el Programa de Familia no habéis encontrado otra empresa de la zona que esté dispuesta y elabore presupuesto a nombre de Aitor, la solicitaremos a la empresa Limpieza Extrema, con la que ya hemos contratado otras con buenos resultados. - Para el cambio de la cerradura, el Jefe de la Sección Económica, dice, y con razón, que mejor nos envíen también un presupuesto del cerrajero a nombre de Aitor y se le abona mediante transferencia, para que no tenga que asumirlo Felisi (la idea era que después Aitor se lo devolviera, pero quedará todo así mejor justificado). - El cristal roto, de momento Alberto, plantea que no se arregle, hasta que no aseguremos de alguna manera que Aitor no pueden volver a romperlo y a colarse. *El resto de “arreglos” pertinentes se realizarán a posteriori. Lo iremos viendo. - En cuanto a la alarma que ha instalado Aitor, los compañeros de la sección económica ya han comenzado gestiones para intentar cancelar el contrato, que está a nombre de Aitor y anularlo. *No obstante, si no es posible bloquearlo antes de que asista el cerrajero y la empresa de limpieza, creemos que quizá, desenchufando el router a Aitor no le llegará notificación de que están entrando en la casa. Así mismo, creemos aconsejable que cortéis la luz (bajar los diferenciales). No estamos seguras de si surtirá efecto, pero por probar no se pierde nada y además, así se ahorra también en consumo. - Y en relación a la cuenta que abrió en Caixabank, desde la sección ecca., en cuanto supimos de ella, pidieron información al banco para poder actuar, pero no dieron respuesta… volverán a intentarlo. - Felisa, como bien proponíais, debería denunciar. Miguel, Asesor Jurídico, explica que puesto que el hecho de denunciar es un hecho personalísimo, es ella misma la que debe acudir a interponer la denuncia, y puede ir acompañada de alguna profesional de cualquiera de vuestros programas, agradeceríamos que, desde uno u otro tenéis disponibilidad, lo acordéis y la acompañéis. Ya nos confirmáis. - A Felisi la voy a llamar hoy mismo, sé que me ha llamado estos dos días pasados, he visto las llamadas perdidas, pero tampoco he querido devolverle las llamadas hasta que nos hubiéramos reunido. - A Felisi le vamos a plantear también, la posibilidad de poner rejas en las ventanas por las que su hijo, o cualquier persona, se pueda colar, pero tenemos que saber si ella estaría dispuesta, pues no a todo el mundo le gusta esta opción. - Por supuesto la situación se volverá a comunicar al Juzgado, del que aún no hemos obtenido respuesta y no sabemos por qué… Agradeceríamos que, una vez más, nos remitieseis informes actualizados y firmados, para poder adjuntarlos, junto con las fotografías de la vivienda y el escrito que se redacte desde aquí. Entiendo que también se podrá adjuntar la denuncia de Felisi." ··································································································································································································· Llamo a Felisi (624 856 746): el teléfono está apagado o fuera de cobertura. ············ Llamo al otro nº (722 494 033): Felisi, se muestra dispuesta a denunciar y a poner rejas en las ventanas susceptibles de que alguien se pueda colar y a puerta trasera que da al patio. *Le informo también del resto de las decisiones tomadas, se muestra de acuerdo en todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-10-19','miguel, firmo en notaria de Herrera del Duque Declaración de Heredero de Agustin, ante el notario D. Pablo Sanchez Martin con Protocolo 1236. Envío un email a Estefanía confirmandoselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-19','llega email de Blanca de CRR: Buenos días, Os informamos que Isabel se encuentra tranquila. Desde la Policía nacional nos llaman para citar a Ceferino a declarar ya que fue a él la primera persona a la que Isabel llamó para contar lo sucedido. Irá acompañado por un profesional del recurso. Le avisaremos ahora de la citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-10-19','Ana: correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Te comunico que el pase que estaba previsto para finales de este mes de Andrés Silva Bonifacio a su centro, se ha suspendido ya que está muy inestable...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-19','miguel, recibo email de Teresa Muelas (abogada): Acabo de hablar con Amelia y me ha dicho que ha cambiado de notaría. Que ahora se va a hacer con al notaría de Brihuega, porque la otra notaría tardaba mucho. Y la cita para la firma es con la nueva notaría. Según me indica habéis envido documentación a esta nueva notaría. Quería comprobarlo, pues en vuestros datos me remitísteis a la notaría de Jimena del CAstillo. Me pongo en contacto inmediatamente con Brihuega para organizar todo ********************************************************* Y remite nuevo email: Ya he hablado con la notaría de Brihuega. Efectivamente se firma el día 26 de octubre. Se haría la ratificación el mismo día. Tenéis que comunicar los datos de la notaría para ratificación y pedir cita para firmar la ratificación sobre las 13,00 horas. Si os viene mejor, darme a mí los datos y se los paso a la notaría de Brihuega. Como mejor sea. La procuradora que vamos a poner en el asunto judicial se llama MARIA TERESA HERNÁNDEZ ARROYO, es la colegiada 27 del Colegio de Procuradores de Guadalajara. ********************************************************* Envío email a la abogada Teresa donde adjunto certificado de nacimiento, autorización, testimonios de aceptación del cargo de la Ctaex de los hermano Gil Sanz: Hola Teresa, me apunto los datos del procurador, dime a qué juzgados de 1º instancia y procedimiento hemos de poner en el poder apud acta. Te adjunto también comunicación que he hecho a la notaria de Mérida para su ratificación. También envié ayer a la notaria de Brihuega comunicación de esta documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-10-20','Ana: Correo de Paula, TO, en relación a la propuesta que hacen desde la sec. ecca. y que le plantee el día 18: "Buenas, os escribo en relación a Isabel Cano, era para confirmar la autorización para sacar los 170 Euros de este mes para la salida a Trujillo para mañana o pasado, puesto que se va el lunes día 24 de Octubre. Tal y como hablamos en conversación telefónica transmitimos a Isabel la indicación de que en los próximos meses podría realizar esta salida de finales de octubre y otra durante el mes de diciembre, en la que también se autorizarían 170 Euros. Así mismo la posibilidad de contar para navidades con 50 Euros para comprarse un regalo (posible reloj). Así mismo hemos valorado la propuesta de contar con un extra anual el próximo año de 900 Euros para cubrir las necesidades de Isabel. Entendemos que a priori puede facilitar la planificación económica de demandas que ya conocemos con respecto a Isabel, por lo que nos parece bien intentarlo. Si bien somos conscientes de que es insuficiente para sostener salidas al hotel a Trujillo para visitar a su familia, incluso organizándolas cada dos meses, puesto que esto supondría no poder atender a ninguna otra necesidad. Muchas gracias por vuestra atención y esperamos vuestra confirmación de que puede sacar el dinero mañana o pasado para la salida del mes de octubre." ························································································································································································································ Correo-respuesta de Óscar, secc. ecca., a Paula y Carolina, CRR: "Ya se ha enviado a Unicaja la autorización para el reintegro de 170€ para retirar entre hoy y el lunes. Ya nos avisáis para hacer el de diciembre y para la cuestión del reloj. En cuanto al extra anual, una vez analizado de nuevo su situación y, entendiendo las limitaciones que supone, se ha decidido que la cuantía total para el año 2023 sea de 1.200€. Con este importe deberá asumir todos los extras que surjan durante el año y los viajes a Trujillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-10-20','miguel, me pregunta Oscar por los trámites para poder desbloquear la cuenta: Miguel, ¿cómo va este tema? Le mandaste lo que te pidió en este correo de 27 de mayo?? Es que aún no han hecho la transferencia ni han cerrado la cuenta. ********************************************************* Envío email al abogado Manuel Andrino Manuel Andrino >mandrino@andrinoabogados.com>, a la asesoría del Cid y Villafaina inmaculada@delcidyvillafaina.com: Buenos días Manuel, por favor dime cuando puedas cómo va este asunto, a ver si nos pueden agilizar en el juzgado la resolución de este expediente. Hace tiempo que mandaron de la entidad bancaria este email que adjunto debajo y estamos a la espera de la resolución judicial para poder disponer de la cuenta bancaria: De: FRANCISCO RODRIGUEZ TOLEDANO Asunto: RE: Cancelación cuenta José Antonio Delgado Rodríguez Buenas tardes, Aún no ha sido posible la cancelación de la cuenta de Doña JOSEFA RODRÍGUEZ RASERO, con adjudicación de su saldo y transferencia a la cuenta indicada del Sr. Delgado Rodríguez, por encontrarnos a la espera de documentación requerida al Asesor Jurídico de la Comisión Tutelar de Adultos de Extremadura, Sr. Miguel A. Fernández de Llera, concretamente autorización judicial para la aceptación de la herencia, imprescindible para la finalización del expediente de referencia, y de la que, según nos ha informado recientemente, se encuentra en trámite. En cuanto dispongamos de la documentación, atenderemos la solicitud de cancelación y transferencia que nos han hecho llegar, informándoles convenientemente, a fin de que puedan desarrollar de forma correcta la labor que les han encomendado. Quedamos a vuestra disposición para agilizar este asunto. *********************************************** Y envío a Oscar: Hola, te adjunto email que he mandado al abogado con copia a la asesoría. Desde mayo estamos pendientes de este asunto, y lo último que sabemos como verás es que tenían que ampliar la autorización judicial al padre (creo) del tutelado D. José Delgado Repilado. En cuanto me conteste te digo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-20','Ana: Cumplimento y subo al portafirmas la Solicitud de PNC. ······························· Llamo a Mamen, TS del Centro Vida - Cáritas: me enviará el DNI escaneado y un Certificado de Ingreso en Centro. ············· El Informe Social aún no ha podido hacerlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-10-20','miguel, contestación del abogado de Manuel Andrino, que reenvío a Oscar: El día 01/09/2022 se presentó escrito en el Juzgado aportando el certificado del Registro de Actos de Última Voluntad y copia del testamento de D. José Delgado Repilado, interesándose que la autorización para la aceptación de la herencia fuese también respecto de la herencia de éste último. En el escrito se pedía del Juzgado el señalamiento de nueva comparecencia, sometiéndose a consideración del LAJ que se pudiese resolver el procedimiento sin necesidad de celebración de comparecencia al poder resolverse con la documentación ya aportada en el Juzgado. Por el Juzgado no se ha resuelto aún nada. La Procuradora, mi hermana Rosa, ha llamado varias veces al Juzgado pero no le dicen nada. Le voy a decir que vuelva a llamar e intente hablar con el LAJ. De no ser posible presento escrito solicitando que se resuelva nuestra petición','2');
