insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-10-20','Amalia : Hablo con Mercedes , de Caritas , va a enviar nuevo pto. de ingresos y gastos para subir asignación. Desde agosto se ha ido a compartir piso con dos usuarios más , siguen haciendo seguimiento desde Caritas. Va a enviarme dirección se lo pasaré a FUTUEX para que hagan visita. Le solicité PF+ P. ORFANDAD , aprobadas. No dió grado dependencia , he solicitado plaza RAL por decreto y tiene 50 puntos en baremo, está en lista.','2');
