insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-10-20','miguel, nos comunican desde abogacía apertura de juicio oral pero tiene ya abogado (tiene Letrado de designación particular JUAN PABLO GARCIA DE CASTRO MARTINEZ DE ACUÑA) con lo que una vez finalice la vía penal, procedimiento DPA Diligencias previas, procedimiento abreviado 584/2022 (procedimiento abreviado 93/22), juzgado nº1 Badajoz y se retome la civil (para procedimiento de medidas de apoyo civil)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-10-20','-Amalia : Es una curatela provisional , estamos pendientes de firmeza y que se indiquen las esferas donde hay que intervenir.Vive solo y los únicos ingresos son de PNC. Acude al banco amenazando para que le den más dinero , pero se le da la pensión íntegra. No entiendo cómo han podido hacerle un plan de empresa similar , que no se ajusta en nada a su capacidad socio económica . He solicitado a la delegada tutelar que en la próxima visita al pueblo lo aclare con la técnico. Está pagando cuota de autónomo para hacer este plan de empresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2022-10-20','-Alberto : TODO ÁREA ECO: NO SE ABONARÁ NI UN SÓLO EXTRA X CONCEPTO ALGUNO AL TUTELADO ISMAEL LÓPEZ IGLESIAS. CUALQUIER SOLICITUD EN ESE SENTIDO DEBERÁ PASAR PREVIAMENTE X AMALIA. OSCAR: ÁREA SOCIAL, EN TANTO EN CUANTO DECIDE CUAL VA A SER EL PLAN DE INTERVENCIÓN CON EL TUTELADO, NOS INDICA QUE, DADAS LAS CIRCUNSTANCIAS QUE CONCURREN EN EL MISMO, DEBEMOS ACTUAR DE LA SIGUIENTE MANERA: REINTEGRO PERMANENTE DE 421 €/MES A PARTIR DE 01/11/2022. 2 REINTEGROS PUNTUALES DE 210 € A LO LARGO DEL AÑO, CON LA SIGUIENTE PERIODICIDAD: 1º REINTEGRO EN 01/07 DE CADA AÑO. 2º REINTEGRO EN 01/12 DE CADA AÑO. NO HABRÁ NI UN SÓLO EXTRA PARA ABSOLUTAMENTE NINGÚN CONCEPTO YA QUE SE LE ABONA LA TOTALIDAD DE SUS INGRESOS Y LO POCO QUE RESTA SE GASTARÁ EN SEGURO DECESO Y COMISIONES BANCARIAS. AMALIA: TIENE QUE QUEDAR CLARO QUE NO HAY PARA NINGÚN TIPO DE EXTRA (INCLUIDO SALUD) YA QUE AL ABONAR TODOS SUS INGRESOS, LO QUE RESTA SE GASTARÁ EN SEGURO DECESO Y COMISIONES BANCARIAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2022-10-20','-Amalia : Llamo a su hermano Jose Mª , no consigo contactar con Ismael. EL hermano vive el Alburquerque y no tiene relación con él . Me dice que Ismael vive con sus padres y otro hno. en la C/ Pimienta , 79 en Antonio Domínguez en Badajoz. TF de su hermano Maikel 622112168 , que vive con él .','2');
