insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-20','Ana: Llamada de Raquel , vecina del 4ºA de Desi (648 61 98 93). Anoche, entre las 23:30 y las 00:00 g hubo una incidencia grave. Acudieron 3 unidades de la policía local (6 agentes). Estuvo dando gritos, golpes y arrojando objetos y basura por la ventana. Subieron a hablar con ella, pero no consintió en abrir la puerta a la policía. *No es l primera vez que "le dan estas crisis", pero no se han atrevido a llamar a la policía por miedo a posibles represalias por parte de Desi. ···· *Raquel ha hablado también con Sonia, TS de Futuex. ·············· Indico que ante cualquier otra situación similar llamen directamente al 112. ········· Me llamarán si vuelve a surgir algo más. ······························································································································································································ Tras conversaciones telefónicas con Ana Benavente, TS del ESM y Elma, TS de SSASB, me remiten Parte de Actuación de la Policía Local (Guardado en expdte) y envío correo a Toni-Futuex: "He hablado con Raquel, vecina de DESIDERIA BARBERO BUENO, vive en la misma planta. Ya me ha dicho que ha hablado también al respecto con Sonia, TS del Programa de Apoyo Comunitario. Me ha narrado el incidente de anoche, dice que no es la primera vez que ocurre, pero que no han llamado antes a la policía por miedo a posibles represalias por parte de Desideria. Le he indicado que, ante nuevos signos de descompensación, llamen al 112. Ya tenemos el parte de la Policía Local de anoche. He hablado también, tanto con Ana Benavente, TS del Equipo de Salud Mental de Plasencia, como con Elma, TS de SSASB, de Plasencia. *La Médica de Atención Primaria iba a personarse en el domicilio para valorarla hoy. *No sabemos si finalmente la llevarán a Urgencias al Hospital. Iremos viendo. No obstante, en caso de que no ingrese, Elma intentaría organizar una visita conjunta con Ana Benavente y la Médica, para remitirnos informes y poder remitir al Juzgado. Cuando podáis, por favor, remitirnos informe firmado de los últimos seguimientos (visitas y teléfono)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-10-21','A fecha de 21/10/2022 se envía por correo certificado a Don Jose Moreno Moyano, la documentación solicitada por él mismo, referente a Embargo de Creditos, referencia R1078222000880, junto con el Justificante de registro de salida Sirex. Se remitió a la C/ Margallo, nº 45, Palacete la Alameda de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-10-21','Ana: Correo de Blanca, Directora del CRR-Plas.: "A su vuelta del ingreso el lunes, vamos observando ciertas dificultades de adaptación a la estructura del recurso, muchas demandas en vida cotidiana en gestión económica sobre todo, necesidad de contención ante verbalizaciones de no querer estar en el recurso y labilidad emocional que la interfiere en realizar actividades. Estamos intensificando las atenciones individuales para que la adaptación al recurso sea adecuada pero queríamos informaros de la situación actual." ····································································································································································································· Mi respuesta: "Gracias por informar, esperemos con la intensificación de vuestra intervención a nivel individual, evolucione positivamente y consiga adaptarse al recurso. Si os parece bien, voy a pedir que la compañera del Programa de Apoyo Comunitario gestionado por Futuex, que le visitaba cuando estaba en el domicilio, intente apoyar también en este proceso a través de visitas y llamadas, no sé exactamente con qué periodicidad podrá pasar por allí, pero podría coordinarse con vosotras para trabajar todas en la misma dirección. Podría ser otro apoyo para ella." ······················· *Envío correo a Toni-Futuex, con esta petición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-21','Ana: Remito a Julio, CTAEX, oficio y solicitud de PNC, para que le dé registro en SIREX, junto con toda la documentación indicada en el oficio. ·································································································································································································· Llamada de Pilar Martín, TS del ESM-CC (54612): aún no ha registrado la solicitud de revisión del grado de dependencia, como tiene que registrar también la solicitud de CRR, intentará registrar hoy las dos cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-10-21','miguel, enviamos al jzdo nº6 de Cáceres, Medidas Cautelares Previas 538/2022, todos los informes sociales de incidencia desde junio que se mandó al jzdo decano de Cáceres la solicitud de internamiento involuntario, para incorporarlos al procedimiento','2');
