insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-21','Ana: Correo de Ana Benavente (anamaria.benavente@salud-juntaex.es): "Ayer ingresó de forma involuntaria Desideria en la UHB del Hospital Virgen del Puerto." ······················ Lo comunico a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-10-21','Ana: Envío a Julio, Aux. Advo. CTAEX, para que dé REGISTRO en SIREX, documento de ELECCIÓN DE CENTROS DE DISCAPACIDAD (se quedan abiertas todas las zonas)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-09-29','Ana: Llamada de Manuel, padre de Manuel (623 247 979): dice que en casa no hay buen ambiente. Él sigue en la línea de siempre Además no ha vuelto a tener cita en el ESM. **Intentaremos gestionarle nueva cita en el servicio de Psiquiatría. Además, con los 200€/mes que se le da ("asingación-manutención"), no le llega. Veremos la posibilidad de incrementar esta cuantía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-10-21','Ana: Hablo con Manuel, padre (623 247 979): La situación sigue igual. En cuanto a la asignación que se le transfiere, dice que los 25€ que proponen desde la secc. ecca. no le van a sacar de nada, así que mejor que se lo dejen en su cuenta. ··· *Aprovecha para decirme que su nieta, según le ha dicho ésta, no está recibiendo la transferencia mensual de la manutención desde hace 2 meses. La percibe en la Caixa. ········· Lo transmito ambas cuestiones a la secc. ecca. ···························· *Hablo con el propio Manuel, dice que ha pedido la revisión de su sentencia, que no sabe el día exacto, pero que le han dicho que tendrá el juicio al mes que viene (noviembre). *Además le gustaría irse a vivir de alquiler de forma independiente. Le recuerdo su situación económica, pero él dice que e apañaría... *En cuanto a la propuesta de volver a Piso Supervisado, dice que no, que "las cosas luego no son como te las pintan". ········································································································································································································ Envío correo a Toni-Futuex: "En relación a MANUEL DOMÍNGUEZ MARTÍN, con quién en otras ocasiones habéis hecho gestiones puntuales, queríamos derivarle al programa de apoyo comunitario para seguimiento periódico en el domicilio familiar, donde reside actualmente: C/ Espartero, nº 65. Moraleja (Cáceres). La convivencia, según comenta el padre, no es muy buena, la madre está enferma. Viven los tres en la misma casa. Percibe una PNC, de la cuál le pasa 150 € de manutención a su hija. Y a su padre se le hace una transferencia mensual de 200€. No da para mucho más. Estuvo residiendo en los Pisos Supervisados de Don Benito, pero desde que ha regresado al pueblo no ha vuelto a tener seguimiento en Salud Mental, intentaré gestionarle cita para psiquiatría. Os iremos diciendo. Presenta Grado I de dependencia y 69% de discapacidad, con diagnóstico de Esquizofrenia Paranoide. *Lo ideal sería que volviese a ingresar en recursos residencial de salud mental, pero de entrada él no quiere. Quiere irse a vivir de forma independiente a un piso/casa de alquiler, pero económicamente esto, a día de hoy, no es factible. Habrá que ir trabajando con él sobre estas cuestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-10-21','Ana: Llamada de Pilar, sobrina: su tía está muy delicada, sigue ingresada en el Hospital San Pedro de Alcántara y tiene mal pronóstico. ······· Veremos la posibilidad de solicitar plaza pública en la Residencia El Cuartillo de CC, de cara al alta o si diera puntuación para plaza T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-24','Ana: Pilar Martín, nos remite la Derivación que han hecho para CRR a la UPA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2022-10-24','miguel, me llama Bartolomé 697-601881 para pedirme le diga como va el procedimiento X08 Tutela 359/2019 del jzdo nº1 Montijo. Llamo al juzgado y me confirman que se trata de la Rendición Anual de Cuentas, que está pendiente de resolverse, y que una vez se resuelva seguramente se inicie un procedimiento de revisión de sentencia. Llamo al tutelado para decirselo ******************************************************* Comenta el tutelado que a ver si podemos ayudarle porque tiene internet (móvil) intervenido y limitado, le comento que en eso no puedo ayudarle. Dice también que para la revisión de la sentencia ha intentado contratar los servicios de un abogado pero le dicen en el colegio que debido a que le tenemos limitada las cuentas no puede solicitarlo. Le digo que de eso tiene que hablar con la parte económica, ya que pide que se liberen sus cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2023-11-27','TERESA´ TELEFNO DE CONTACTO 644163927 CRISTIAN MADRE DE CRISTRIAN, GUADALUPE: 643095828','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-10-24','TERESA RECIBO LLAMADA DE LA TRABAJADORA SOCIAL DEL SASB DE BADAJOZ PARA INFORMARSE SOBREA AITOR YA QUE HAN ACUDIDO ALLI PARA PEDIR AYUDA ME INDICA QUE LO HA DERIVADO AL PROGRAMA DE FAMILIA ANTE LA SITUACION EN LA QUE SE ENCUENTRAN ESTAN VIVIENDO EN LA CALLE LAMPREA 23 EN CASA DE LOS ABUELOS DE MIRELLA SU PAREJA ACTUAL( MIRELLA SECO GARCIA) LA ABUELA TIENE UNA ENFERMEDAD NEURORAL DEGENERATIVA DE LAS LLAMADAS ENFERMEDADES RARAS LA CUAL HA REREDADO TAMBIEN LA MADRE DE MIRELLA Y PROBABLEMENTE MIRELLA TAMBIÉN LA TERMINE SUFRIENDO. MIRELA TIENE DISCAPACIDAD Y PROVIENE DE FAMILIA DESESTRUCUTIRA NUNCA LE HAN PUESTO LIMITES Y ESTA ACOSTUMBRADA A CONSEGUIR LAS COSAS A BASE DE MALOS MODALES Y POR LA FUERZA PRESENTANDO NULA TOLERANCION ANTE LA FRUSTRACION ACUNDEN A LOS SERVICIOS SOCIALES PARA SOLITAR la extinción de la tutela y gestionar su dinero HABLO CON CHON EDUCADORA DEL PROGRAMA DE FAMILIA: 924 47 89 13 HE ACORDADO CON ELLA LA GESTION DE HACER CONVENIO CON ALGUN SUPERMERCADO PARA PODER HACER LA COMPRA COM OHACI EN NAVAS Y PAGAR POR TRANSFERENCIA. LE ACOMPAÑARIA LA DELEGADA TUTELAR PARA SUPERVISAR LA COMPRA Y ASEGURAR ASI LA ALIMENTACION HASFA QUE EL JUZGADO NOS DE RESPUESTA ME QUEDO A LA ESPERA DE QUE NOS INDIQUEN SUPERMERCADO PARAHACER DERIVACION A FUTUEX Y COMERZAR A HACER LA COMPRA SEMANAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-24','miguel, envío email a la abogada Teresa Muelas, Amelia (tía) AMELIA RODRIGO SANZ >melitonarodrigo@hotmail.es>y notaria de Brihuega: Buenos días Teresa, según compruebo para la aprobación de la escritura notarial de herencia que se firmará el día 26-10-22 en Brihuega, sobre 12,30h a 13h estaré en la notaria y que nosotros intentaremos ratificar ese mismo día en Mérida, necesito me indiques lo siguiente en relación al paso posterior que sería la solicitud de autorización judicial para la aprobación de herencia y la autorización de venta: Para el apud acta de la procuradora cuál es el juzgado de primera instancia competente? Según veo el competente sería conforme el artículo 62 de la LJV (ley de jurisdicción voluntaria 15/15) el juzgado de primera instancia del domicilio del tutelado? En este caso sería Don Benito, ya que se encuentran residiendo en la CAMP Nuestra Señora de las Cruces… Si es así, entiendo que lo suyo es que busquemos un abogado y un procurador en Don Benito para lo cual necesitaría que Amelia tuvieras controlada (en tu poder) la escritura original de adjudicación de herencia y nos enviara copia simple a este email la notaria de Brihuega, una vez esté todo firmado, incluido la ratificación. Por supuesto la notaria de Brihuega debe enviarnos, si queréis a mi email y/o a ctutelar@salud-juntaex.es la factura que correspondan a Sergio y Raúl Gil Sanz a efectos de su abono. Amelia, recuerda que una vez firmada la escritura de herencia debes presentarla en el ayuntamiento a efectos del pago de Plusvalía, cuya liquidación también nos tendrás que enviar para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-24','miguel, envío email a la abogada Teresa Muelas, Amelia (tía) y notaria de Brihuega: Buenos días Teresa, según compruebo para la aprobación de la escritura notarial de herencia que se firmará el día 26-10-22 en Brihuega, sobre 12,30h a 13h estaré en la notaria y que nosotros intentaremos ratificar ese mismo día en Mérida, necesito me indiques lo siguiente en relación al paso posterior que sería la solicitud de autorización judicial para la aprobación de herencia y la autorización de venta: Para el apud acta de la procuradora cuál es el juzgado de primera instancia competente? Según veo el competente sería conforme el artículo 62 de la LJV (ley de jurisdicción voluntaria 15/15) el juzgado de primera instancia del domicilio del tutelado? En este caso sería Don Benito, ya que se encuentran residiendo en la CAMP Nuestra Señora de las Cruces… Si es así, entiendo que lo suyo es que busquemos un abogado y un procurador en Don Benito para lo cual necesitaría que Amelia tuvieras controlada (en tu poder) la escritura original de adjudicación de herencia y nos enviara copia simple a este email la notaria de Brihuega, una vez esté todo firmado, incluido la ratificación. Por supuesto la notaria de Brihuega debe enviarnos, si queréis a mi email y/o a ctutelar@salud-juntaex.es la factura que correspondan a Sergio y Raúl Gil Sanz a efectos de su abono. Amelia, recuerda que una vez firmada la escritura de herencia debes presentarla en el ayuntamiento a efectos del pago de Plusvalía, cuya liquidación también nos tendrás que enviar para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-10-24','Ana: Recibimos de la D.G. de SS.SS, Infancia y Familia, Notificación de la Resolución de Extinción del derecho a PNC (fecha de efectos: 1/julio/2022). **Reclaman la cantidad de 861,29 € en concepto de cobro indebido por periodo del 1/07/22 y 30/09/22. ······················ La remito a Alberto y Óscar, Secc. Ecca. ········ Guardada en Expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-10-24','Ana: Correo de Mª Jesús Gómez Lozano, TS del SSASB Mancomunidad Comarcar de Trujillo (ssb32mancomunidadcomarcatrujillo@hotmail.com / 621 247 237): " Me preguntabas si había algun vecino o familiar en la localidad de Puerto de Santa Cruz que tuviera llaves de la vivienda de Javier. Me he informado y preguntado y nadie tiene llaves"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-07-13','AMALIA: TENEMOS CDO. R. CIVIL DE YOLANDA SI POR AHÍ PUDIERAMOS OBTENER CDO. DEFUNCION DE LOS PADRES PARA PEDIR P.ORFANDAD ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-10-25','TERESA RECIBIOMOS EN EL BUZON DE LA COMISION PETICION DE INFORMACIOND DE DONDE SE ENCUENTRA YOLADA RESIDIENDO hablado con ellos, es un tío de Yolanda que quiere saber de su sobrina, el que ha escrito es primo de Yolanda Fco José Martin TElefn 610 87 72 35, quieren saber en que centro esta y hablar con ella, les he dicho que se lo vamos a comunicar y si ella desea tener ese contacto lo facilitaremos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-25','miguel, recibo email de Teresa Muela: Buenas tardes La competencia para la aprobación de la aceptación de la herencia sería el lugar de domicilio del causante, según los artículos 93 y 94 de la Ley de Jurisdicción Voluntaria. Según creo el domicilio del causante es Guadalajara y es por eso, por lo que estamos haciendo aquí la herencia. La competencia para la enajenación de los bienes sería el domicilio de la persona con discapacidad. Yo pensé hacerlo con una procuradora que actúa en toda España y llevar las dos cosas que son las que presupuesté. Decirme si al final sigo llevándolo yo o no. Por otra parte para el nombramiento de procurador mediante apud acta electrónica, hay dos sistemas 1.- Nombrar procurador para el expediente concreto, en cuyo caso hay que esperar a saber el numero de procedimiento. El Juzgado concede diez días de subsanación. 2.- Otorgar apud acta para todos los trámites, en cuyo caso se puede presentar con la demanda. Espero vuestras noticias *********************************************************** mi contestación: Buenos días, son conceptos distintos: 1)La aceptación de la herencia, viene regulado en el artículo 94 LJV (TÍTULO IV De los expedientes de jurisdicción voluntaria relativos al Derecho sucesorio/ CAPÍTULO III De la aceptación y repudiación de la herencia/ Artículo 94.1. Competencia, legitimación y postulación. “Será competente para conocer de estos expedientes, cuya tramitación se ajustará a las normas comunes de esta Ley, el Juzgado de Primera Instancia del último domicilio o, en su defecto, de la última residencia del causante y, si lo hubiere tenido en país extranjero, el del lugar de su último domicilio en España o donde estuviere la mayor parte de sus bienes, a elección del solicitante”. **Y una vez firmada la escritura notarial de aceptación de herencia sin beneficio de inventario se procede a la solicitud de aprobación de herencia y la solicitud de aprobación de venta (con enajenación directa sin pública subasta)***** Dicha aprobación judicial de herencia, viene regulada en el artículo 62 LJV (TÍTULO II. De los expedientes de jurisdicción voluntaria en materia de personas/ CAPÍTULO VIII. De la autorización o aprobación judicial para la realización de actos de disposición, gravamen u otros que se refieran a los bienes y derechos de menores y personas con discapacidad con medidas de apoyo para el ejercicio de su capacidad jurídica personas con discapacidad con medidas de apoyo para el ejercicio de su capacidad jurídica) “1. Será competente para el conocimiento de este expediente el Juzgado de Primera Instancia de la residencia del menor o persona con discapacidad. Si antes de la celebración de la comparecencia se produjera un cambio de la residencia habitual de la persona a que se refiera el expediente, se remitirán las actuaciones al Juzgado correspondiente en el estado en que se hallen. 2. Podrán promover este expediente quienes ostenten la representación legal del menor o ejerzan el apoyo a la persona con discapacidad a los fines de realizar el acto jurídico de que se trate, así como la propia persona con discapacidad de conformidad con las medidas de apoyo establecidas. Cuando se trate de la administración de bienes o derechos determinados, con facultades concretas sobre los mismos, conferida por su transmitente a título gratuito a favor de quien no ostente la representación legal, o cuando se ejerzan separadamente la tutela o curatela de la persona y la de los bienes deberá solicitar la autorización, si fuere precisa, el administrador designado por el transmitente o el tutor de los bienes. Si el acto fuera respecto a los bienes del patrimonio protegido, el legitimado será su administrador. 3. No será preceptiva la intervención de abogado ni procurador siempre que el valor del acto para el que se inste el expediente no supere los 6.000 euros. Cuando lo supere, la solicitud inicial podrá realizarse sin necesidad de ambos profesionales, sin perjuicio de que el Juez pueda ordenar la actuación de todos los interesados por medio de abogado cuando la complejidad de la operación así lo requiera o comparezcan sujetos con intereses enfrentados”. Y el artículo que habilita para pedir conjuntamente la solicitud de aprobación de herencia y la autorización de venta entiendo que es el artículo 63.3 LJV “Si la solicitud fuera para la realización de un acto de disposición podrá también incluirse en la solicitud la petición de que la autorización se extienda a la celebración de venta directa, sin necesidad de subasta ni intervención de persona o entidad especializada. En este caso, deberá acompañarse de dictamen pericial de valoración del precio de mercado del bien o derecho de que se trate y especificarse las demás condiciones del acto de disposición que se pretenda realizar”. ****En cualquier caso desde aquí venimos haciendo herencias constantemente y nos exigen desde los juzgados este modus operandi. Nosotros necesitamos hacer poder apud acta porque el representante de la Comisión Tutelar de Adultos es un político y no es posible asegurar la primera opción que indicas en tu email (1.- Nombrar procurador para el expediente concreto, en cuyo caso hay que esperar a saber el número de procedimiento. El Juzgado concede diez días de subsanación.). Es por ello por lo que te pedía me confirmaras que el juzgado Decano de los de primera instancia de Don Benito (por ser el domicilio de los tutelados-herederos). En otro orden necesito no localizo tu presupuesto (y la de la procuradora) para la tramitación de ambas cuestiones: aprobación de herencia y autorización de venta, porque dependiendo del coste tendríamos que contratar o no otro abogado y procurador. Por último indicarte que conforme el Código civil, sí es preceptivo la aprobación judicial de la herencia (una vez firmada la misma), pero no la aceptación de la misma (que habría que haberla solicitado judicialmente previamente a la firma de la escritura notarial) Artículo 289 No necesitarán autorización judicial la partición de herencia o la división de cosa común realizada por el curador representativo, pero una vez practicadas requerirán aprobación judicial. Si hubiese sido nombrado un defensor judicial para la partición deberá obtener también la aprobación judicial, salvo que se hubiera dispuesto otra cosa al hacer el nombramiento. En cualquier caso, quedo a tu disposición para cualquier aclaración. Es importante que quede claro porque mañana se quiere firmar la escritura notarial de aceptación de herencia en la notaria de Brihuega y posterior ratificación por esta Comisión Tutelar de Adultos en nombre de los tutelados Sergio y Raúl Gil Sanz. Quedando a tu disposición para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-10-25','miguel, recibo email de Teresa Muela: Buenas tardes La competencia para la aprobación de la aceptación de la herencia sería el lugar de domicilio del causante, según los artículos 93 y 94 de la Ley de Jurisdicción Voluntaria. Según creo el domicilio del causante es Guadalajara y es por eso, por lo que estamos haciendo aquí la herencia. La competencia para la enajenación de los bienes sería el domicilio de la persona con discapacidad. Yo pensé hacerlo con una procuradora que actúa en toda España y llevar las dos cosas que son las que presupuesté. Decirme si al final sigo llevándolo yo o no. Por otra parte para el nombramiento de procurador mediante apud acta electrónica, hay dos sistemas 1.- Nombrar procurador para el expediente concreto, en cuyo caso hay que esperar a saber el numero de procedimiento. El Juzgado concede diez días de subsanación. 2.- Otorgar apud acta para todos los trámites, en cuyo caso se puede presentar con la demanda. Espero vuestras noticias *********************************************************** mi contestación: Buenos días, son conceptos distintos: 1)La aceptación de la herencia, viene regulado en el artículo 94 LJV (TÍTULO IV De los expedientes de jurisdicción voluntaria relativos al Derecho sucesorio/ CAPÍTULO III De la aceptación y repudiación de la herencia/ Artículo 94.1. Competencia, legitimación y postulación. “Será competente para conocer de estos expedientes, cuya tramitación se ajustará a las normas comunes de esta Ley, el Juzgado de Primera Instancia del último domicilio o, en su defecto, de la última residencia del causante y, si lo hubiere tenido en país extranjero, el del lugar de su último domicilio en España o donde estuviere la mayor parte de sus bienes, a elección del solicitante”. **Y una vez firmada la escritura notarial de aceptación de herencia sin beneficio de inventario se procede a la solicitud de aprobación de herencia y la solicitud de aprobación de venta (con enajenación directa sin pública subasta)***** Dicha aprobación judicial de herencia, viene regulada en el artículo 62 LJV (TÍTULO II. De los expedientes de jurisdicción voluntaria en materia de personas/ CAPÍTULO VIII. De la autorización o aprobación judicial para la realización de actos de disposición, gravamen u otros que se refieran a los bienes y derechos de menores y personas con discapacidad con medidas de apoyo para el ejercicio de su capacidad jurídica personas con discapacidad con medidas de apoyo para el ejercicio de su capacidad jurídica) “1. Será competente para el conocimiento de este expediente el Juzgado de Primera Instancia de la residencia del menor o persona con discapacidad. Si antes de la celebración de la comparecencia se produjera un cambio de la residencia habitual de la persona a que se refiera el expediente, se remitirán las actuaciones al Juzgado correspondiente en el estado en que se hallen. 2. Podrán promover este expediente quienes ostenten la representación legal del menor o ejerzan el apoyo a la persona con discapacidad a los fines de realizar el acto jurídico de que se trate, así como la propia persona con discapacidad de conformidad con las medidas de apoyo establecidas. Cuando se trate de la administración de bienes o derechos determinados, con facultades concretas sobre los mismos, conferida por su transmitente a título gratuito a favor de quien no ostente la representación legal, o cuando se ejerzan separadamente la tutela o curatela de la persona y la de los bienes deberá solicitar la autorización, si fuere precisa, el administrador designado por el transmitente o el tutor de los bienes. Si el acto fuera respecto a los bienes del patrimonio protegido, el legitimado será su administrador. 3. No será preceptiva la intervención de abogado ni procurador siempre que el valor del acto para el que se inste el expediente no supere los 6.000 euros. Cuando lo supere, la solicitud inicial podrá realizarse sin necesidad de ambos profesionales, sin perjuicio de que el Juez pueda ordenar la actuación de todos los interesados por medio de abogado cuando la complejidad de la operación así lo requiera o comparezcan sujetos con intereses enfrentados”. Y el artículo que habilita para pedir conjuntamente la solicitud de aprobación de herencia y la autorización de venta entiendo que es el artículo 63.3 LJV “Si la solicitud fuera para la realización de un acto de disposición podrá también incluirse en la solicitud la petición de que la autorización se extienda a la celebración de venta directa, sin necesidad de subasta ni intervención de persona o entidad especializada. En este caso, deberá acompañarse de dictamen pericial de valoración del precio de mercado del bien o derecho de que se trate y especificarse las demás condiciones del acto de disposición que se pretenda realizar”. ****En cualquier caso desde aquí venimos haciendo herencias constantemente y nos exigen desde los juzgados este modus operandi. Nosotros necesitamos hacer poder apud acta porque el representante de la Comisión Tutelar de Adultos es un político y no es posible asegurar la primera opción que indicas en tu email (1.- Nombrar procurador para el expediente concreto, en cuyo caso hay que esperar a saber el número de procedimiento. El Juzgado concede diez días de subsanación.). Es por ello por lo que te pedía me confirmaras que el juzgado Decano de los de primera instancia de Don Benito (por ser el domicilio de los tutelados-herederos). En otro orden necesito no localizo tu presupuesto (y la de la procuradora) para la tramitación de ambas cuestiones: aprobación de herencia y autorización de venta, porque dependiendo del coste tendríamos que contratar o no otro abogado y procurador. Por último indicarte que conforme el Código civil, sí es preceptivo la aprobación judicial de la herencia (una vez firmada la misma), pero no la aceptación de la misma (que habría que haberla solicitado judicialmente previamente a la firma de la escritura notarial) Artículo 289 No necesitarán autorización judicial la partición de herencia o la división de cosa común realizada por el curador representativo, pero una vez practicadas requerirán aprobación judicial. Si hubiese sido nombrado un defensor judicial para la partición deberá obtener también la aprobación judicial, salvo que se hubiera dispuesto otra cosa al hacer el nombramiento. En cualquier caso, quedo a tu disposición para cualquier aclaración. Es importante que quede claro porque mañana se quiere firmar la escritura notarial de aceptación de herencia en la notaria de Brihuega y posterior ratificación por esta Comisión Tutelar de Adultos en nombre de los tutelados Sergio y Raúl Gil Sanz. Quedando a tu disposición para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-10-25','miguel, tras la llamada recibida por Pilar (sobrina) explicandome el estado grave de salud de su tía, el hecho de que quieren abrir una cuenta, de si pueden o no hacerlo...le explico que una vez hecha la rendición final de cuentas al juzgado pueden personarse allí como acreedores y/o herederos...Que el procedimiento de autorización para vender se archivaría en caso de que falleciese y podrían disponer del bien para venderlo o disponer de él. Envío email a Ana a petición de ella (Pilar sobrina): Buenos días, ha llamado Pilar la tía de Maria Ángeles, que es como sabéis una administrador de bienes. Me comenta que está muy grave, y llama para preguntar si pueden abrir una cuenta para afrontar los gastos que pueda necesitar caso de que necesite por ejemplo para sepelio. Le va a dar su teléfono a su hermano Fernando Rodriguez (abogado jubilado) para que le asesore de cuál es la situación actual (hay un procedimiento judicial abierto para vender la vivienda cuya vista la tenemos en el jzdo nº3 de Cáceres para el 16-1-2023. Me decía, que te de el recado que te llamará la trabajadora social para informarte de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2022-10-25','-Amalia : empieza taller de empleo el 1 de octubre , percibirá 800€. Estoy pendiente de respuesta del centro para dejar PNC por PFHC o mantenerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-10-25','TERESA VIVIENDA MARIA MURIILO DELGADO Recibo correo de inmocaixa solicitando contactar con la persona que lleva el expediente de María para tratar tema de vencimiento de contrato de alquiler. Me pongo en contacto con ellos a través del 900 100 686 y tras identificarme me pasa con un tal Eduardo el cual me explica la situación: El contrato de alquiler finalizo en febrero de 2021, se le notifico la no renovación del mismo por causas que no me explica tan solo me dice que tras un análisis de la situación deciden la no renovación del aquiler Desde esta fecha la Caixa deja de cargar los recibos en la cuenta por lo tanto no se esta pangando alquiler. Según María sí lo está pagando, ella misma saca el dinero y lo ingresa en otra cuenta para pagar el alquiler ya que su madre ya se ha desentendido de ella y no mantienen relación. Nos solicitan la entrega voluntaria de la vivienda en el plazo máximo de un mes, si cumplimos esto no iniciaran ningún proceso para reclamar los meses que ha estado viviendo María gratis. Si pasado este tiempo no se ha entregado la vivienda iniciaran un proceso judicial reclamando lo que estimen oportuno TENEMOS QUE BUSCAR UN ALOJAMIENTO ALTERNATIVO PARA MARIA PROBLEMAS 1. ELLA NO QUIERE IRSE DEL PISO NI INGRESAR EN NINGUN CENTRO 2. ES PACIENTE DE SALUD MENTAL CON LO CUAL LA DERIVACION A UN RECURSO DE LA RED DE SALUD MENTAL LA TIENE QUE HACER EL PSIQUIATRA Y CONTANTO CON LA VOLUNTARIEDAD DE LA PERSONA 3. NO DISPONE DE AHORROS Y PERCIBE UNA PNC CON LO CUAL NO PUEDE ASUMIR UN ALQUILER SOLUCIONES¿? JEJE SI OS PARECE BIEN NOS REUNIMOS MAÑANA Y LAS BUSCAMOS EQUIPO¡¡','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-10-25','miguel, me llega email del abogado Pablo Garrote Delgado para que haga poder apud acta ante el juzgado decano de Zafra a favor del procurador Javier Gutiérrez Reyes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2022-10-25','-Amalia : El Plan de intervención no ha llegado a finalizarlo Tere , me pasa el caso , desde el centro me están llamando a mí para la gestión. La pensión entra hoy en la nueva cuenta . Se le va a mandar la autorización a la DTRA. del CSS para que saque dinero . Está en Unidad de no copago , van a sacar sólo para tabaco.','2');
