insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-25','Ana: Sentencia del Jdo. de 1ª instancia e instrucción nº 4 de Cáceres, condena a Miguel Ángel, por "delito de QUEBRATAMIENTO DE CONDENA previsto y penado en el art 468.1 del CP, con la concurrencia de la circunstancia eximente incompleta de alteración o anomalía psíquica del art 21.1º en relación con el art 20.1º del Código Penal, a la pena de SEIS MESES DE MULTA con cuota diaria de 6 EUROS" y "medida de seguridad de LIBERTAD VIGILADA consistente en el obligación de seguir tratamiento médico externo adecuado a las patologías que padece durante CUATRO AÑOS Y SEIS MESES y al pago de las costas procesales."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-10-26','miguel, remitimos vía lexnet solicitud de revisión de sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-10-26','miguel, Tere me reenvía email de José del SSB de Montijo: buenos dias !!! gracias por la info te cuento yo lo que se para que tu tambien lo sepas, efectivamente , no se han renovado la mayoria de los contratos de esas casas, lo que me dijo el director de la caixa de aqui es que lo quieren vender con hipoteca... sin embargo conozco a dos personas que se les ha renovado 8 años mas, esos pisos estan en la zona que yo llevo y todos pasan por aqui tarde o temprano. la samana pasada hable con la madre de maria, me dijo que le pagaba ella el piso a Maria, eso de que saca el dinero y lo paga en otra entidad es un cuento chino, porque como los pisos son de la caixa la caixa les cobra a todos los recibos en su sucursal de monesterio, no tiene sentido que si tu eres un banco uses otro banco para cobrar. maria me llamo el otro día para " disculparse" por no haberse presentado el jueves a la delegada tutelar, me dijo que "esa mujer le habia avisado con poco tiempo" y también me dijo que, si no habia una solución aceptable e intentaban desauciarla se defenderia " a machetazos", tú sabes cómo es María y el genio que tiene....','2');
