insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2022-10-27','email enviado a Fco Sanchez Calzado (Curro) por la parte jurídica (Angel): Buenos días, En relación a este asunto, los correos electrónicos que comentas de los días, 20, 25 y 26 de octubre del 22, no llegaron porque la dirección de correo a la que fueron enviadas (ctutelar@salud.juntaex.es), no es la correcta, la dirección correcta es ctutelar@salud-juntaex.es. Una vez rastreado el correo electrónico, el del 24/3/2022 si llegó, pero en el Decreto remitido que adjuntamos, de fecha 21/3/22, dictado por el Juzgado de Primera Instancia e Instrucción, nº 1, de Villanueva de la Serena (Badajoz), procedimiento DT5 D.T. 5ª Ley 8/2021 0000120 /2022, se acordó en su Parte Dispositiva: “1.- Admitir la solicitud presentada por AURORA PAREJO MORENO, sobre OTRAS MATERIAS respecto de con domicilio en . 2.- Dar cuenta a S.Sª para acordar las actuaciones que considere necesarias conforme al artículo 42 bis c apartado 3 de la LJV.” En consecuencia, esta Comisión Tutelar de Adultos de Extremadura no elaboró Informe alguno porque no se lo solicitaron y, al no ser preceptivo, de conformidad con lo regulado en el artículo 42 bis c), apartado 3, de la Ley de Jurisdicción Voluntaria, estuvo a expensas del trámite que resolviera el Juzgado mencionado. En cuanto a la comparecencia fijada para el día 25/10/22, por favor, de haber asistido, solicitamos Informe a esta Comisión Tutelar de su contenido. **************************************** Los emails referidos por Curro son: Remito adjunto petición de revisión de la incapacidad y establecimiento de las medidas de apoyo que procedan. Como quiera que la CTAEX es quien ejerce las funciones tutelares ruego que se estudie la cuestión y se informe sobre su parecer, a la luz de la nueva normativa a la que nos debemo, para el momento procesal oportuno. Saludos. Buen día El pasado marzo remití documentación y pedí informe sobre esta tutelada. La comparecencia está señalada para el próximo martes día 25, , no se si se ha remitido informe o en su caso si se va a remitir para la comparecencia. Saludos Buenos días Dentro de un 45 minutos tengo la comparecencia en relación a éste asunto. Pedí en marzo pasado y reiteré el día 20 de octubre, informe de la CTAEX sobre la petición que formula la tutelada. Podríais darme información telefónica sobre esta cuestión, para la comaparecencia de ésta mañana?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-10-27','TERESA Buenos días Teresa, qué tal? Hoy, de nuevo, nos ha llamado Aitor para preguntar si vais a darle algo de dinero para comprar alimentos y demás. También nos cuenta que ha ido a la trabajadora social y van a solicitar una vivienda. Nos pide que te diga que por favor, os pongáis en contacto con él para contarle qué pasa con su dinero y algunas preguntas sobre el centro, su ropa… Os paso su teléfono y el de su pareja por si queréis poneos en contacto con ellos, el de Aitor es 604830453 (ha cambiado el número de nuevo, al parecer) y el de su pareja, que normalmente es la que lo coge es 653527921.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA REYES'and edp.apellido1='TARDIO'and apellido2='NUÑEZ'),'2022-10-27','TERESA RENDICION ANUAL REYES RESIDE EN LA RESIDENCIA HOGAR SAN JOSE DE AZUAGA DES EL AÑO 1988 ESTA PERFECTAMENTE ADAPTADA, NO TIEN APENAS CONTACTO CON LA FAMILIA, LOS HERMANO HAN DELEGADO TODOS LOS CUIDADOS EN LA RESIDENCIA PERCIBE PNC 421,40€ SALDO 2000€ PAGA PLAZA PUBLICA CON AYUDA DE VINCULADA DE RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-10-27','miguel, llega sentencia firme que no ejecutoria según me confirma el jzdo de lo penal nº1 Plasencia, envío email a la parte social, Ana y Maite y a la parte económica, Oscar: Buenos días, me confirma el jzdo nº1 de lo Penal de Plasencia que esta sentencia es firme por haber conformidad, pero que podemos esperar a que dicten la ejecutoria para el abono de la multa de 5€ por 25 meses, que a mi me sale 3.750€ y la indemnización de 11.586,91€, y los 25 meses de internamiento en régimen cerrado, que deberán indicarnos fecha de inicio y final de cumplimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-27','-Email de UHB : Buenos días, Amalia. De todas formas, para nuestra desgracia han vuelto a paralizar los ingresos por falta de psiquiatra. Es para llorar. No tenemos la autorización judicial para el ingreso en centro. Nos dijeron en el Juzgado que tenía que autorizarlo el juez que le correspondiera de Avila una vez estuviera allí. Te puedo mandar lo que les envié al centro de Ávila, la autorización para el ingreso involuntario en la UHB por parte del juez y la comunicación a dicho juzgado del traslado. Ahora en cuanto lo encuentre te lo reenvio, que tengo algo de lío. Juan José Marín Píriz Trabajador Social del Hospital Universitario de Badajoz juanjose.marin@salud-juntaex.es Ext.: 48330','2');
