insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEANDRO'and edp.apellido1='PEREZ'and apellido2='DIAZ'),'2022-10-27','TERESA TRAS GESTION CON LIMPIEZA EXTREMA Y APROBACION DE PRESUPUESTO HOY COMIENZA CON LA LIMIEZA DE LA VIVIENDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-27','-Email de UHB : Buenos días, Amalia. De todas formas, para nuestra desgracia han vuelto a paralizar los ingresos por falta de psiquiatra. Es para llorar. No tenemos la autorización judicial para el ingreso en centro. Nos dijeron en el Juzgado que tenía que autorizarlo el juez que le correspondiera de Avila una vez estuviera allí. Te puedo mandar lo que les envié al centro de Ávila, la autorización para el ingreso involuntario en la UHB por parte del juez y la comunicación a dicho juzgado del traslado. Ahora en cuanto lo encuentre te lo reenvio, que tengo algo de lío. Juan José Marín Píriz Trabajador Social del Hospital Universitario de Badajoz juanjose.marin@salud-juntaex.es Ext.: 48330','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-27','-email del centro Mentalia: Hola, muchas gracias por tu repuesta y por los documentos que remitiste. Revisé la sentencia y ella como bien dices es conocedora de la misma y de los ámbitos de protección que dicta la misma. En cuanto a la perrita y la vivienda, la he informado pero refiere que no es así que la única persona que se ocupa de su vivienda y la perrita es su vecino José Mª, a su primo Jesús lo rechaza y no quiere que entre en su inmueble. Saludos Araceli','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-10-04','-Amalia : escribo al centro Mentalia . Buenos días , queda perfectamente explicada la situación de Mercedes . Te adjunto la sentencia de incapacitación , que ella tiene en su poder pero supongo que la tendrá en su casa .Para que la tengáis vosotros también , y por si demanda verla; se la podéis mostrar. Como indica Maite , Mercedes es curatela exclusivamente económica y sólo supervisión de salud a través de contactos con su ESM . Es diferente su situación a la de los otros dos tutelados que tenemos en vuestro centro . Su ingreso como sabéis ha sido un internamiento involuntario vía judicial derivada desde la unidad de psiquiatría , supongo que tendréis esa autorización . La Comisión Tutelar no tiene nada que ver con este ingreso . Las demandas de Mercedes que podemos atender son respecto a su esfera económica , que tienen que ser avaladas por la sección económica de esta Comisión , por ello es mejor que vengan por escrito para poder compartirlas con los compañeros . Creo que pudiera estar preocupada por su perrita y su vivienda. Su primo Jesús es la persona de referencia que se está encargando de todo. La vivienda se ha limpiado y está todo ordenado. La perrita sigue en la casa , su primo se encarga de darle la comida y un vecino desinteresadamente la saca a diario. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2022-10-27','-Email de sección eco : AMALIA: COMO YA SABES HA SUBIDO EL ALQUILER DE 300 A 340 €/MES A PARTIR DE 11/2022. LA FAMILIA YA NO LE PASA LOS 100 €/MES...AL MENOS A SU CCC. SU SALDO BANCARIO, CONFORME A COMO GASTA EN SU VIDA ORDINARIA Y CON EL NUEVO IMPORTE DE RENTA ES DE - 575 €/AÑO (INVIABLE)...EL SALDO, SI NO HUBIESE IMPREVISTO SE ACABARÍA EN 6/7 AÑOS. LA ÚNICA SOLUCIÓN, Y SIN QUE SE LE PUEDA CONCEDER UN SÓLO EXTRA: NI ROPA, NI FARMACIA, NI TRATAMIENTOS, NI ELECTRODOMÉSTICOS... ES ADEMÁS BAJARLE EL REINTEGRO A 190 €/MES (43 €/SEMANA) DESDE YA. ACTUALMENTE, EL REINTEGRO (INCLUYENDO EXTRAS) ES DE 240 €/MES (55 €/SEMANA). BAJAMOS EL REINTEGRO??? - Mi respuesta : Buenas , en mi opinión dejaría el reintegro como está , tiene ahorros para pagar 80€ que supondría la subida de los dos meses que quedan de este año. No tendrá extras en Navidad. Para enero , todas las pensiones van a subir conforme a IPC y podría hacer frente a la subida del alquiler con esos ingresos . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-10-27','Maite: Se le ha adjudicado plaza en servicio de residencia de apoyo limitado de Fuente de Cantos Francisco ASuar TRAS NEGOCIACION DEL PRECIO DE LA PLAZA EN LA QUE ESTA ACTUALMENTE SE RENUNCIA A ESTA PLAZA Y CONTINUA EN CASA DE LA MISERCORIDA DE ALCUECAR PUES LA ADAPTACION ESTA SIENDO MUY BUENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-10-27','-Amalia : envio email a sección eco : Buenas , a partir del 1 de noviembre pueden ingresar la fianza , el contrato se extingue el día 31 de octubre. el agua y la luz , se abonarán solo hasta ese día . Creo que no hay que hacer cambio en contratos porque seguían a nombre del dueño del piso. estoy pendiente que la Dtra. de la RM me diga cómo quiere que abonemos , ingresó el 11 de Octubre. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-10-27','TF DE PACO , VIVE CON SU MADRE EN ALANGE : 609111882 Le voy a pasar el Nº de cuenta de Carmen donde tiene que abonar los 300€ de fianza. Le informo de la baja de alquiler y suministros. Pondrá el piso en alquiler con la inmobiliaria de Rafael 678855147 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTIBALIZ'and edp.apellido1='MENDEZ'and apellido2='CARRASCO'),'2022-10-27','-Amalia . TF de Estib. 643498687 Me llama porque dice que está conociendo a un compañero de trabajo pero que Segunda no quiere que lo vea y le impide quedar con él. Por el momento no quiere que hagamos nada por miedo a represalias en el centro.','2');
