insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2022-10-27','-Amalia . El informe médico pide valorar acompañamiento nocturno. He pedido pto. a la empresa que la acompaña por el día . Solicito valoración de ingreso en centro a Futuex . Tiene 89 años , informe medico guardado en su expediente. Con Deterioro Cognitivo pero no grave.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2022-10-27','Ángel: Envío al hijo del arrendador, Paco, elpacotri@gmail.com, porque el arrendador falleció hace un año, finalización de contrato de arrendamiento de vivienda y entrega de llaves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2022-10-27','-Amalia : Se ha solicitado desde el ESM Valdepasillas derivación a UHDAC. He pedido al centro La Luz información sobre el caso: Crístofer lleva una temporada en la que se encuentra muy inquieto y agresivo, tanto con compañeros de la vivienda tutelada donde reside, como con compañeros de Centro Ocupacional y con los profesionales del Centro. La mayoría de los usuarios cuando él les amenaza, se callan. Muestra baja resistencia a la frustración, dificultad en el control de sus impulsos e inestabilidad emocional. Todo esto conlleva que presente graves problemas en la convivencia con los demás. Este tipo de conductas la psicóloga del centro (Rebeca) las ha tratado con su psiquiatra (Dr. Samino). Se han hecho varios ajustes de medicación con idea de encontrar una mejora, pero no se han obtenido los resultados esperados. Además, el pasado día 12 de octubre agredió a uno de sus compañeros de vivienda tutelada donde reside. Comenzó provocándole verbalmente, después pasó a amenazarle con "agredirle con las botas de punta de acero" y después se produjo la pelea. Como consecuencia su compañero (Juan Sanjuan Guisado) sufrió una fractura desplazada de 5º metacarpiano de la mano derecha y abrasiones en la zona interfalángica de 1º, 2º y 3º dedo de la mano izquierda según está reflejado en el parte judicial de lesiones emitido por el médico que lo atendió en el servicio de urgencias del Hospital Universitario de Badajoz. La familia de Juan ha denunciado los hechos. Días antes, también agredió a uno de sus monitores de Centro Ocupacional. Como medida preventiva, desde que ocurrió el incidente con su compañero se encuentra en nuestro Centro en el servicio de Residencia, presentando los mismos problemas de convivencia que presentaba en el piso. El último incidente lo presentó ayer mismo, según me ha hecho saber el coordinador de dicho servicio (Felipe). Se mostró muy agresivo con una de las cuidadoras que lo atiende en Residencia y según me cuenta pudo producirse un nuevo incidente Debido a todo lo anterior, y ya que no se han obtenido mejoras con los cambios de medicación realizados, su psiquiatra ha considerado su derivación a la UHDAC. Por lo que tengo entendido, tanto Sole como Rebeca han emitido informes explicando la situación y se les ha adjuntado el parte judicial de lesiones de Juan. Dicha documentación ha sido entregada a la trabajadora social del Equipo de Salud Mental que lo atiende (Carmen Díaz).','2');
