insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-25','Ana: correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Buenos días, Ana Te informo que está ingresada en este centro a Desideria Barbero Bueno, pasó ayer desde la UHB del Hospital "Virgen del Puerto" Seguimos..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-27','Ana: correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Me he puesto en contacto con Antonia, Coordinadora de Futuex para que el día 3 vengan a acompañar a Desi al domicilio para que recoja ropa y vea si ha dejado algo que pueda resultar peligroso...(comida, llave gas etc..) y para que la acompañen al banco para sacar dinero para sus gastos de bolsillo. Hemos quedado que me llaman el día 2 para concretar dónde quedamos, ya que a Desi la trasladará el coche del centro acompañada de una Auxiliar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-10-28','-Amalia , anoto email de la tecnico de Caritas . Hoy he tenido entrevista con Tomás Pérez. Te paso la información de contacto y el presupuesto: Calle Fuerte Nº 13, 2ºB y nuevo móvil: 643627176 Presupuesto: Ingresos: 402€ Gastos: Alquiler 150€ Luz 27€ Gas 39,1€ Comida 25/30€ por semana Seguro decesos: No sabe cuánto es TOTAL: 366,1€ Diferencia: 35,9€ La idea que hemos hablado Tomás y yo era la de subir sus ingresos a 450€ y dejar el resto en la cuenta para gastos imprevistos y como ahorro. Hoy por la tarde se acercará a Aexpainba para preguntar por los talleres y que le entreguen el modelo de solicitud en el caso de que alguno le interese. La solicitud tendríais que firmársela vosotros. Ya he quedado con él para el próximo mes. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-10-28','-Amalia : ha pasado a pisos supervisados en Almendralejo . Contacto : Buenos días Soy Alicia, la psicóloga de los pisos supervisados de Almendralejo. Me ponía en contacto contigo para informarme de una usuaria que está tutelada por la comisión. También, para hablar de su situación actual. Si puedes llamarme sería estupendo. Número de teléfono: 674355164 -------------------------- Tras hablar con la psicologa me informa que la adaptación es buena , ya no quiere cambiar de localidad. No se habla con la familia materna pero ha retomado relaciones con el padre y familia paterna. Está contenta. La madre cuando ella era pequeña denunció al padre por algún tipo de maltrato o negligencia con la niña , no tenemos más información al respecto. De momento queda con sus primos y tias paternas. Una de ellas es soltera y quiere que se vaya a vivir con ella . Se va a facilitar salidas de fines de semana para ver cómo evoluciona esa relación. El tema del móvil que quiere , se va a a valorar la necesidad del mismo y se le pide pto. nuevo para abonar en su caso con la extra de diciembre.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-10-28','-Amalia , ingresos de Tomás : 400,42€, pone en concepto pensión no contributiva 220,70€ pone en concepto pensión seguridad social P.Orfand. A fecha de hoy tiene un saldo de 5.930,24','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-10-28','-Amalia , escribo email a la técnico de Cáritas .Ya he pasado nueva dirección a Futuex para que hagan visita. Buenas, Tomás tiene PFHC y P. Orfandad que le solicité yo. Sus ingresos son de 402 €más 270 €. En enero si finalmente se aprueban los Ptos . del Gobierno se van a subir bastante ambas pensiones. Esperamos a enero para con los nuevos ingresos establecer un presupuesto más holgado para él . Se le puede hacer autorización de un extra porque tiene ahorros suficientes . Indicadme cuanto necesitaría para cubrir los dos meses que le quedan , cuenta ya con la extra de la orfandad que necesite . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-10-28','-Amalia , escribo email a la técnico de Cáritas .Ya he pasado nueva dirección a Futuex para que hagan visita. Buenas, Tomás tiene PFHC y P. Orfandad que le solicité yo. Sus ingresos son de 402 €más 270 €. En enero si finalmente se aprueban los Ptos . del Gobierno se van a subir bastante ambas pensiones. Esperamos a enero para con los nuevos ingresos establecer un presupuesto más holgado para él . Se le puede hacer autorización de un extra porque tiene ahorros suficientes . Indicadme cuanto necesitaría para cubrir los dos meses que le quedan , cuenta ya con la extra de la orfandad que necesite . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2022-10-28','-Amalia : escribo a sección eco : Buenos días , Rosa Gomez Cedillo es una señora de 89 años con deterioro cognitivo que de momento , sigue en su domicilio como es su deseo ,con el servicio de una señora que la cuida a través de la empresa SADEX desde hace años. Tras la última visita al neurólogo este nos informa que su deterioro va en aumento y que valore la opción de acompañamiento nocturno. He pedido presupuesto que os remito (825€), tiene bastantes ahorros , sería posible aumentar estas horas ?? por cuánto tiempo ? Otra alternativa sería el ingreso en centro residencial plaza privada , rondan los 2100€. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-10-27','Ana: Envío correo a Paula, TO CRR: "Os reenvío correo de Ceferino, esta vez no le hemos contestado. Por supuesto, cuando no se le contesta insiste e insiste, aunque cuando se le contesta sigue insistiendo también... Yo ayer estuve de curso y me vuelvo a marchar dentro de unos minutos, pero llamó con insistencia a mi compañera María (sección económica), con el mismo discurso. Así y todo ayer por la tarde volvió a escribir, os lo reenvío ahora también. Alberto, Jefe de secc. económica, de momento, no quiere hablar de nuevos extras “innecesarios”. Como dijimos, lo que finalmente decida, con el trabajo que hagáis con él abordando sus verdaderos intereses, se hará propuesta de cara a diciembre-enero." ······················· Respuesta de Paula: "es incontrolable que siga enviando correos, aunque nuestra recomendación sigue siendo la de mantener el acuerdo que hicisteis e hicimos con él de una vez a la semana. Como sugerencia, salvo que sea para algo urgente, sería bueno que le recordarais el acuerdo de intercambio de una vez a la semana y que lo siguierais así, puesto que él no lo logra. En cuanto al tema económico, no ha acudido a las sesiones que hemos tenido para trabajar este aspecto (planificación, estrategias, etc.). Por otro lado es consciente de que, a pesar de haber tomado algunas decisiones, no las sostiene por lo que asocia consecuencias que él mismo elige y después se siente mal por ello. Respecto a lo que pide, si acude a las sesiones hablaremos de ello y podremos abordar distintas posibilidades y os voy diciendo cómo lo vamos a hacer."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2022-10-28','TERESA ENNVIO COTRATO FIRMADO DE SAD A GIAMEX Y ACEPTACION PIA A DEPENDENCIA ZAFRA PARA SU TRAMITACION, QUEDO A LA ESPERA COBRAR AYUDA DE DEPENDENCIA YA QUE YA SE HA INICIADO EL SERVICIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-10-28','Ana: Ante la propuesta de que Cristofer cambie de recurso al PROYECTO MI CASA, gestionado por Plena Inclusión Montijo, Maite, Jefa de Secc. y yo, llamamos a Ana Isabel Amor, Psicopedagoga: Christofer no tiene apego con Cristina, "su pareja", para él no es impedimento el cambio de RR y de localidad. Y sigue siendo un demanda en él el irse a vivir a Vivienda Tutelada. ················ Leemos y guardo en el expdte. digital el informe de seguimiento de Placeat.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-28','Ana: Ante las dudas planteadas por Toni-Futuex, mediante e-mail, respondo, con copia a Maite: "Estrella Durán, TS del Sociosanitario, también nos ha escrito al respecto. Puesto que Desi acudirá en vehículo del centro y acompañada también por una Auxiliar, entendemos que no hay problema en una salida que solicitan desde el centro y autorizan la Psiquiatra. Es una cuestión que están abordando con ella. *Por otra parte, en el caso de que se negara a regresar al centro, consideramos que la compañera tendría que llamar al Socio y comunicarlo a la TS y/o Psiquiatra y que desde el propio recurso activen el 112. Sería como cuando un interno se fuga del centro, pues está ingresada involuntariamente en la Unidad de Media Estancia. En cuanto al dinero, me parece bien que le facilitéis dinero para gasto de bolsillo, del que le sobró de la compra del teléfono móvil y le estáis custodiando desde el programa de apoyo. Y solicitaré a la sección económica que realicen la autorización de retirada el Centro para cuando sea necesario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-10-26','Ana: Se remiten al Centro los CI de Anestesia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2022-10-21','TERESA Se comunica que se marchará al domicilio familiar hoy sábado a las 11 hasta el martes 1 por la tarde. Ira en taxi y con acampañamiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2022-10-31','AMALIA: LO QUE SE INDICA SE PUEDE APLICAR TANTO A LA CONTRATACIÓN DEL SERVICIO DE NOCHE (HABRÍA QUE SUMAR A LOS 825 €/MES DEL SERVICIO DE NOCHE, LOS 1.108 €/MES DEL SERVICIO DE DÍA Y LA MANUTENCIÓN DE 200 €/MES) COMO A QUE INGRESE EN UN CENTRO PRIVADO (2.100 €/MES). DUDAS: ENTENDEMOS QUE EL COSTE DEL SERVICIO DE NOCHE O DEL CENTRO PRIVADO YA INCLUYE EL IVA, PK SI NO ES ASÍ ESTARIAMOS HABLANDO DE OTROS CÁLCULOS. SALDO A DÍA DE HOY: 119.708,80 € CON LOS DATOS ECO ACTUALES Y SI INCLUIMOS EL SERVICIO DE NOCHE (Y SUPONEMOS QUE EL IVA YA ESTÁ INCLUIDO) CADA AÑO PERDERÍA -20.000 €. X TANTO, Y SIEMPRE QUE NO HUBIESE GASTOS EXTRAORDINARIOS O SIMILARES EL SALDO SE AGOTARÍA EN MENOS DE 6 AÑOS: HABRÁ QUE TENER EN CUENTA LA POSIBILIDAD DE QUE ESTA PERSONA SIGA VIVA DESPUÉS DE HABER AGOTADO EL SALDO. CUALQUIER INCIDENCIA ECONÓMICA RELEVANTE DEJARÍA SIN EFECTO ESTOS CÁLCULOS. SEGURO DECESO: ESTA PERSONA LLEGO A CTAEX SIN SEGURO DECESO Y X SU EDAD NO SE FORMALIZÓ: X TANTO HABRÁ QUE DEJAR AL MENOS 3.000 € PARA SU FALLECIMIENTO. EN ESTE CASO LO QUE DECIDA EL ÁREA SOCIAL ESTARÁ BIEN, PERO ENTIENDO QUE ESTA CUESTIÓN ES TAN RELEVANTE A NIVEL PATRIMONIAL QUE ANTES DE HACER NADA DEBEMOS COMUNICARLO AL JUZGADO: ESTAMOS HABLANDO DE HACER DESAPARECER 120.000 € EN 5-6 AÑOS (Y ESTO SI TODO VA BIEN).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-10-31','TERESA TELEFNO MADRE 644876893','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-31','Ángel: Envíamos por lexnet al Juzgado de lo Penal 1, de Cáceres, en el procedimiento Ejecutorias 235/2022, centro adecuado para cumplir medida de libertad vigilada, que es el sito en Avda. Ronda del Carmen, 6, de Cáceres, donde se encuentra el Equipo de Salud Mental y el Equipo de Conductas Adictivas, a los que deberá acudir para recibir el tratamiento prescrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2022-10-31','-Amalia , escribo a Laura de Aexpainba : Te comento por aquí un par de cosas : Tengo que aclarar cuales son sus ingresos por PNC actualmente . Los tiene suspendidos por completo por el contrato laboral que tenía anteriormente ? en su extracto bancario aparece el cargo de TGSS de 721,70€ , a qué corresponden estos ingresos ? a rendimiento laboral ? cuales van a ser los ingresos con el nuevo contrato laboral ? para poder calcular otro presupuesto . Hablamos también sobre ésto , no puedo contactar con vosotros , igual has cogido puente . El nuevo contrato laboral tiene que reenviarlo Juan José a PNC , no está curatelado en esa esfera. Si no lo veis posible lo hacemos desde la CTAEX , pero no es lo correcto y nos pueden poner pegas . un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-10-31','-Amalia , se recibe email del Ctro. penitenciario de Extremera para hacer cambio PIA en Extremadura . Desconozco empadronamiento , se lo pido a Julio. Su sentencia es sólo para altas y ttos. médicos y patrimonial para todo lo que exceda de una cuantía ordinaria. No creo que podamos hacer esta gestión , dado que no está curatelado en esa esfera . No deberíamos controlar cuantía económica de escasa cuantía y percibe PNC .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-10-31','-Amalia , se recibe email del Ctro. penitenciario de Extremera para hacer cambio PIA en Extremadura . Desconozco empadronamiento , se lo pido a Julio. Su sentencia es sólo para altas y ttos. médicos y patrimonial para todo lo que exceda de una cuantía ordinaria. No creo que podamos hacer esta gestión , dado que no está curatelado en esa esfera . No deberíamos controlar cuantía económica de escasa cuantía y percibe PNC .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-10-31','-Amalia : recibo email de Miguel , desde el SSASB no nos han enviado la solicitud de centro pedida en verano y en varias ocasiones más . Según delegada tutelar Justa amenaza con intento autolitico si sale de su casa , creo que es por esta razón por lo que la compañera no me envia el informe social que necesitamos. Buenos días, me ha llamado Bego 924-846008 (Aseroría Jurídica de Banca Pueyo) para preguntar por cómo están los trámites para su ingreso. Me ha pedido que remitamos porque así lo ha pedido el juzgado un informe de cuándo, cómo y si es posible dónde se va a ingresar a la tutelada. Me consta que Amalia hablastes con SSB Montijo en Julio pero tenemos que saber qué avances hay porque quieren subastar la vivienda. Por la parte jurídica, hemos solicitado internamiento involuntario que está pendiente nos asignen el número de juzgado de Montijo y número de procedimiento. Quedo pendiente de vuestro informe para remitirlo al juzgado. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-10-31','-Amalia : recibo email de Miguel , desde el SSASB no nos han enviado la solicitud de centro pedida en verano y en varias ocasiones más . Según delegada tutelar Justa amenaza con intento autolitico si sale de su casa , creo que es por esta razón por lo que la compañera no me envia el informe social que necesitamos. Buenos días, me ha llamado Bego 924-846008 (Aseroría Jurídica de Banca Pueyo) para preguntar por cómo están los trámites para su ingreso. Me ha pedido que remitamos porque así lo ha pedido el juzgado un informe de cuándo, cómo y si es posible dónde se va a ingresar a la tutelada. -------------------------------------- Me consta que Amalia hablastes con SSB Montijo en Julio pero tenemos que saber qué avances hay porque quieren subastar la vivienda. Por la parte jurídica, hemos solicitado internamiento involuntario que está pendiente nos asignen el número de juzgado de Montijo y número de procedimiento. Quedo pendiente de vuestro informe para remitirlo al juzgado. ------------------------------- Mi respuesta : Buenas , os comento porque este caso también va a traer cola .. La solicitud de informe social obligatorio que pedí al SSASB en verano y dos veces después no llega . Según averiguaciones con la delegada tutelar , Justa amenaza con suicidarse si la sacamos de su casa y que no va a ingresar en residencia de mayores nunca . Creo que puede ser esta la razón por la que la compañera no se atreve a enviarme el informe social para el ingreso. ¿ qué podemos hacer ante ésto ? lo comunicamos al juzgado ?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-10-31','-Amalia : recibo email de Miguel , desde el SSASB no nos han enviado la solicitud de centro pedida en verano y en varias ocasiones más . Según delegada tutelar Justa amenaza con intento autolitico si sale de su casa , creo que es por esta razón por lo que la compañera no me envia el informe social que necesitamos. Buenos días, me ha llamado Bego 924-846008 (Aseroría Jurídica de Banca Pueyo) para preguntar por cómo están los trámites para su ingreso. Me ha pedido que remitamos porque así lo ha pedido el juzgado un informe de cuándo, cómo y si es posible dónde se va a ingresar a la tutelada. -------------------------------------- Me consta que Amalia hablastes con SSB Montijo en Julio pero tenemos que saber qué avances hay porque quieren subastar la vivienda. Por la parte jurídica, hemos solicitado internamiento involuntario que está pendiente nos asignen el número de juzgado de Montijo y número de procedimiento. Quedo pendiente de vuestro informe para remitirlo al juzgado. ------------------------------- Mi respuesta : Buenas , os comento porque este caso . La solicitud de informe social obligatorio que pedí al SSASB en verano y dos veces después no llega . Según averiguaciones con la delegada tutelar , Justa amenaza con suicidarse si la sacamos de su casa y que no va a ingresar en residencia de mayores nunca . Creo que puede ser esta la razón por la que la compañera no se atreve a enviarme el informe social para el ingreso. ¿ qué podemos hacer ante ésto ? lo comunicamos al juzgado ?','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TELESFORA'and edp.apellido1='MORALES'and apellido2='CHACON'),'2021-10-31','EXITUS Por sospechas del compañero Óscar, se investiga su posible fallecimiento. Tras consultar la base de datos de PNC y de CIVITAS, se comprueba su posible fallecimiento como cierto. Para su confirmación se lleva a cabo llamada al CSS de Mérida, quien en su día debió haber advertido del caso y no lo hizo. Se confirma que el óbito tuvo lugar el 28/08/2021 en el propio CSS dónde residía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='BARRIGA'and apellido2='CARNERERO'),'2022-10-31','.Amalia : hablo con Julia , TS de Rosalva , último informe de salud: Buenas tardes Amalia, He hablado con el Dr. Lopez , Cirujano Digestivo del Hospital de Mérida, Manuel está ingresado por pancreatitis aguda, me informa que su estado es comprometido, incluso que corre peligro su vida. Están valorando trasladarlo a UCI, si lo trasladan me informarán por teléfono, si finalmente no lo trasladan a UCI, le buscaremos acompañamiento. Informo al médico que está Tutelado por la Junta de Extremadura. Informo a residencia de Segura de León de su estado por si quieren informar a su hermana Soledad. Saludos. -- Julia Moreno González Nº Col. 07-492 Trabajadora Social Rosalba Mérida Telf. 924388673 juliamoreno@gruporosalba.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-10-31','TERESA RECIBO LLAMADA DE LA TRABAJADORA SOCIAL INFOMANDOME QUE ANGELA QUIER INGRESAR EN PISO SUPERVIDADO LE INDICO QUE ES UNA BUENA OPCION Y QUE SE PONGAN EN CONTACTO CONMIGO DESDE EL PISO PARA GESTIONAR EL INGRESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-10-31','TERESA JOSE TIENE UN COBRO INDEVIDO POR LA VINCULADA DE AYUDA A DOMICILIO YA QUE NO SE ESTA REALIZANDO EL SERVICIO LLAMO A LA EMPRESA CON LA QUE SE HABIA CONTRATADO EL SAD CENTRO FUNICIONAL AZUL (HABLO CON MARIAN 634785050) Y ME COMENTA QUE ELLOS LE NOTIFICARON AL SEPAD EL FIN DEL SERVICIO HABLO CON LALI DES GESTION ECONOMICA DE DEPENDENNCIA 924003188) Y ME COMENTA QUE NO TIENEN CONOCIMIENTO DEL CESE DE LA ACTIVIDAD LE SOLICITO A LA EMPRESA ME FACILITEN LA INFOMRACION DE CUANDO HAN COMUNICADO EL CESE Y PORDER PONER AL DIA LOS PAGOS. ME LLAMA JOSE TRABAJADOR SOCIAL DE MONESTERIO Y ME COMUNICA QEU JOSE HA DECIDIDO INGRESAAR EN LA RESIDENCIA DE MEDINA EN PLAZA CONVENIDA Y PAGARA EL 75% DE LA PENSION LE FACILITO EL CONTRATO FIRMADO POR EL REPRESENTANTE LEGAL SOLICITO REVISION DE GRADO YA QUE ACTUALMENTE TIENE UN GRADO UNO Y SU ESTADO A EMPEORADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-11-02','Ana: Correo del lunes 31 de Toni-Futuex: "Hemos confirmado con el socio, para el jueves 3, le entregaremos 35 eu, para gastos de bolsillo (sigue quedandole remanente) pensando en que pudiera seguir ingresada o necesitara algo, le custodiamos el resto. El único, tema un poquitin, discrepante por decirlo de alguna manera, es que desde el socio nos trasladan la responsabilidad de avisar al 112 si no quiere regresar al domicilio, nos indica Estrella que como cualquier otro ciudadano podriamos hacerlo.. le hemos explicado que esto no va ya asi, y que al estar ingresada involuntariamente en el centro, deberia ser el centro quien comunicase la posible falta, como bien indicadas tu, como si se tratará de una fuga.. (estamos de acuerdo contigo). De hecho, cuando no ha estado institucionalizada, nos ha liado varias veces en su domicilio, y poquito se ha podido hacer.. comunicarlo a su equipo de salud mental y como bien sabes, de poco a ido sirviendo, hasta que no se ha valorado precisamente desde alli por los conflictos vecinales, al intervencion del 112. También nos ha indicado la ts del socio, que la auxiliar que va acompañando no va a subir a la casa de Desi.. no pasa absolutamente nada, porque nosotras subimos con ella. No obstante, vamos a confiar, que va ir a su domicilio y a regresar y que todo va a fluir perfectamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-10-31','EXITUS El centro comunica su fallecimiento. Tuvo lugar el óbito el 31/10/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-10-18','TERESA ENVIO SOLICITUD DE AYUDAS EXTRAORDINARIAS DE APOYO SOCIAL PARA CONTINGENCIAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='CANCHALES'and apellido2='MALDONADO'),'2022-11-14','TERESA RECIBO DOCUMENTACION PAR GESTIONAR LA HERENCIA DE LA MADRE DE SOLEDAD RECIENTEMENTE FALLECIDA EN LA RESIDENCIA FELIPE TRIGO A TRAVES DE NIEVES LA TRABAJADORA SOCIAL ENTRE LA DOCUMENTACION SE ENCUENTRAN DOS CARTILLAS UNA A NOMBRE DE LA MADRE Y OTRA EN LA QUE ESTAN MADRE E HIJA TAMBIEN HAY LAS LLAVES DE UN PISO QUE TIENE EN BADAJOZ LE ENTREGO LA DOCUMENTACION A MIGUEL PARA QUE CONTACTE CON AL GESTORIA QUE COMENZO EL TRAMITE DE HERENCIA DE UNA TIA DE SOLEDAD LA DOCUMENTACION SE GUARDA EN EL EXPEDIENTE DE SOLEDAD Y LA LLAS LLAVES EN LA CAJA FUERTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='CANCHALES'and apellido2='MALDONADO'),'2022-11-02','miguel, Tere me entrega documentación de testamentaria (certificados de defunción de las dos hermanas original, y de la madre fotocopia, un certificado de últimas voluntades, algunas facturas...escaneo las dos cartillas del santander de la madre, los originales los deja Tere en el expte fisico y las llaves de pisos las guarda en su caja fuerte Tere) **************************************** Tras hablar con un familiar y con la Asesoria Marquez Asesores sl (Cecilio) les remito documentación y pido presupuesto para tramitar la herencia y venta *************************************************** Hablo con el primo de la madre fallecida Juana, Fernando Canchales, quien me confirma que la familia era de Badajoz y de madre soltera. Me dice que desconoce el motivo por el que el vecino Juan Carlos Vidarte (vecino) suspendió los trámites que se estaban realizando. *************************************************Envio email a Asesoría Marquez Asesores (despacho@marquezasesores.es):','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='CANCHALES'and apellido2='MALDONADO'),'2022-11-02','miguel, Tere me entrega documentación de testamentaria (certificados de defunción de las dos hermanas original, y de la madre fotocopia, un certificado de últimas voluntades, algunas facturas...escaneo las dos cartillas del santander de la madre, los originales los deja Tere en el expte fisico y las llaves de pisos las guarda en su caja fuerte Tere) **************************************** Tras hablar con un familiar y con la Asesoria Marquez Asesores sl (Cecilio) les remito documentación y pido presupuesto para tramitar la herencia y venta *************************************************** Hablo con el primo de la madre fallecida Juana, Fernando Canchales, quien me confirma que la familia era de Badajoz y de madre soltera. Me dice que desconoce el motivo por el que el vecino Juan Carlos Vidarte (vecino) suspendió los trámites que se estaban realizando. *************************************************Envio email a Asesoría Marquez Asesores (despacho@marquezasesores.es): Buenos días Cecilio, conforme conversación mantenida le adjunto la documentación que nos han hecho llegar desde el centro CAMP Las Cruces de Don Benito donde reside Soledad Canchales Maldonado tutelada (actual curatela representativa conforme ley 8/21) por la Comisión Tutelar de Adultos del Sepad. Como le comentaba por teléfono necesitamos que continúen los trámites de herencia en notaria y en juzgado (aceptación, aprobación de herencia), ya les informaremos si también autorización para vender judicial. Les adjunto la documentación que nos ha llegado físicamente y que debe estar en su expediente ya que en su Asesoría se estuvo tramitando como podrá comprobar. Necesitamos presupuesto lo más ajustado posible para realizar todos los trámites. Por otro lado, hemos localizado un primo (Fernando Canchales 605982215) de la fallecida madre Juana (soltera) y madre de las tres hijas Angela, Enriqueta, ya fallecidas las tres, y nuestra tutelada, Soledad, a la que creemos es la única heredera. Entiendo que necesitarán de la colaboración de este primo para hacer las correspondientes declaraciones de herederos de las fallecidas hijas, hermanas de nuestra tutelada. Quedo a su disposición para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-10-28','Ana: Correo de Blanca Conejero, Directora CRR-Plas. (direccion.crrplasencia@grupo5.net): "Buenas Ana, este fin de semana Concepción Fernández Muñoz, realiza la salida habitual del mes al hostal. Se ha va de hoy al domingo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-10-27','Ana: Llamo a Alberto Bueso, TO-EVD (21841): para solicitar la ampliación de centros habría que volver a presentar nueva solicitud de revisión de PIA (modelo de solicitud de dependencia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-10-28','Ana: Llamada de Pilar, sobrina de Mª Ángeles (645 90 95 26): dice que la situación es ya muy grave, "mi tía va a morir". No le funciona el riñón. Ahora mismo está aislada. No responde a tratamientos y si continúa así procederán a sedarla de forma paulatina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2022-11-02','Ana: Recibimos el Certificado Actualizado de Pensión de Orfandad Absoluta solicitado al INSS: 767,50 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-11-02','Ana: solicito por mail al CAM de Trujillo (cam.franciscopizarro@salud-juntaex.es / educadores.cam.franciscopizarro@salud-juntaex.es): resolución de PNC que les remitieron al centro por error.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-02','TERESA Buenas tardes Teresa, soy Anto Morán del SSASB de Almendralejo,solo queria comentarte la siguiente incidencia respecto a Bartolomé Colchón Carmona, me ha exrañado mucho su comportamiento. Ha llegado sin cita y ha entrado al despacho sin esperar turno alguno, esta circunstancia me extraña dado que él siempre se muestra educado y respetuoso con los demás. Lo he visto muy acelerado y excesivamente eufórico, con un discurso muy alejado de la realidad al manifestar que "trabaja para un magnate americano y que él va a dar mucho trabajo a la gente de este pueblo,construyendo casas y hoteles..." .Venia a Servicios sociales para que sus pensiones se le ingresaran en otro banco por " indicaciones del magnate". Se ha ido rápido sin dejarme racionar. Desconozco su estado psiquico actual pero su comportamiento y pensamientos no son los propios por lo que os informo al estar tutelado por la Comisión y saber que Susana quien le hacia el seguimiento desde Futuex ya no trabaja en este ámbito. DERIVO A FUTUEX PARA VISITA URGENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-11-02','Ana: Llamada de Diana - TS, Secc. Dependencia 5-Plasencia (24124 / diana.gonzalezj@salud-juntaex.es): me piden que registremos a la Ud. de Prestaciones Eccas de Dependencia, SEPAD, el ALTA DE TERCEROS. ···················· Paso a las sección ecca. CTAEX el Alta de Terceros cumplimentado y firmando por el D.Gerente. para que lo lleven al banco. ············ *confirmar a Diana cuando se haya registrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-11-03','-Amalia : Intento averiguar cual es su domicilio en Extremadura , hago consulta a Julio . "Hasta que nos den acceso a Cliente Ligero no hay posibilidad de comprobarlo por nosotros mismos. Aunque en su expte. digital hay grabado un certificado expedido por el Ayto. de Helechosa de los Montes, de 3 de octubre de 2019. De cuando entró. En el indica que su domicilio es Lugar Zona Extramuros, Letra S, 1º A.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-11-03','Ana: Nos remiten desde el CAM Fco. Pizarro de Trujillo, la Resolución de la PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-11-03','-Amalia : Intento averiguar cual es su domicilio en Extremadura , hago consulta a Julio . "Hasta que nos den acceso a Cliente Ligero no hay posibilidad de comprobarlo por nosotros mismos. Aunque en su expte. digital hay grabado un certificado expedido por el Ayto. de Helechosa de los Montes, de 3 de octubre de 2019. De cuando entró. En el indica que su domicilio es Lugar Zona Extramuros, Letra S, 1º A.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-11-03','-Amalia , escribo a sala Lendinez del Ctro. Penitencirio de Estremera en Madrid : Buenos días , me he reunido con la sección de dependencia para aclarar este trámite de traslado . En primer lugar , desde la Comisión Tutelar no podemos hacer esa gestión porque no está incapacitado en esa esfera, tiene que realizarlo y firmar ese documento él mismo . Os facilito el modelo necesario si es su deseo solicitarlo . Os adjunto también sentencia de incapacitación , es curatela específica para esfera sanitaria y actos económicos que excedan de cuantía ordinaria. Me indican desde dependencia , que para poder solicitar un traslado de expediente , es necesario indicar domicilio en esa Comunidad Autónoma y Cdo. de empadronamiento. Este requisito no lo cumple José , puesto que ni reside ,ni tiene domicilio en Extremadura. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='MORCILLO'and apellido2='PAJUELO'),'2022-11-03','Ángel: En relación a la solicitud de autorización para liquidar el plazo fijo de 3.000 euros en unicaja, asistimos hoy a la vista en el Juzgado de Primera Instancia e Instrucción, nº 1, de Don Benito. Acceden a nuestra petición y no se oponen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='BARRIGA'and apellido2='CARNERERO'),'2022-11-03','-Amalia , recibo email de Rosalba : Buenas tardes Amalia, Tal como acordamos, te informo sobre el estado de salud de Manuel Barriga, finalmente lo trasladaron a UCI, el pronóstico es delicado, de momento no van a intervenir quirúrgicamente. Cuando tengamos noticias te informo.','2');
