insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2022-11-03','-Amalia : dan el alta de Joaquina Salguero Capote. Es la señora que reside en La Granadilla , empiezo plan de intervencion por emergencia Hemos aceptado el cargo con fecha de hoy. Somos sus curadores representativos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-11-03','TERESA Aitor Moreno Felipe ya no está en el centro ADISER de Castuera. La renuncia se firmó el 19 de octubre. El centro ha cobrado todo el mes. Devolverán la cantidad proporcional. Ya no habrá que hacer pago mensual de la plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-03','Ana: llamada de José Manuel (627 788 797): dice que Pilar Martín, TS del ESM, le ha recomendado que vaya al Centro de Día Francisco Chanclón. La Directora se llama Carmen Cisnero (927 00 67 22). Ha ido a verlo y le ha gustado. Le han dicho que hay lista de espera, pero que cuentan con servicio de comida, Ayuda a Domicilio, T.O. y Psicología. Le costaría 201 €/mes. ······· Pide ir. También dice que no le gusta la comida del nuevo catering (que el que da el servicio municipal el el Cáterin Sol), que la comida está muy sosa. Le recuerdo que él no debe tomar sal. *Pide volver a cambiar al catering anterior aunque tenga que pagarlo. ············ En cuanto a Revital, le explico que aún no han enviado la propuesta PIA. Hay que tener paciencia y esperar. ···· Pilar Martín también le ha dicho que se le pondrá TAD. ············· *Le explico que hablaré con Pilar Martín y se estudiarán todas las propuestas que hace, pero que no puede solicitar cosa nuevas y/o cambios casa 2 meses. *De momento tiene que seguir como está, con el catering y el SAD municipales. ·········· *Durante la llamada están en casa de la hermana, con quien dice tener contacto de vez en cuanto con ella y visitarla de vez en cuando. Se le escucha de fondo con aparente buena actitud hacia él y "participando" en la conversación que mantenemos. ···························· *Conversación con Pilar Martín, TS ESM-CC (54612): Cuando vayan a revisarle para el PIA, se solicitarán tanto el Tratamiento en Centro Revital como el Centro de Día Fco. Chanclón. ············· En cuanto al TAD, que propone de nuevo Pilar, insisto en que no haría buen uso del mismo, esto ya estaba acordado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-11-03','Ana: A petición de Pilar Martín, TS ESM-CC, envío correo-e a Ángel y Miguel, Asesores Jurídicos CTAEX: "En relación a MIGUEL ÁNGEL RAMOS ANDRÉS, porfi, ¿podríais confirmar en el Juzgado si tiene alguna otra causa abierta? Es que me dicen que puede ser un impedimento para el acceso al recurso solicitado (CRR), decirme en cuanto podáis, pues habrá una comisión para valorar su acceso en pocos días." ······························ *Hablar, cuando lo sepamos con Mariluz, Jefa Secc. de Salud Mental. ··· Fecha probable de comisión: 08/11/22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-11-03','Ana: Llamada de Cristofer (630 616 022), dice que hoy está "tristón", no va a ir al C.O. y añade "No me gusta este centro, me quiero ir a otro", "¿Yo me puedo ir al que estaba antes en Montijo?" ··········· Intento animarle, le explico que tiene que tener paciencia y que los trámites están hechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-11-02','Ana: correo de Toni-Futuex con nota de los últimos apoyos prestados a Felisi. Acudieron con ella a la Guardia Civil, pero finalmente *NO se atrevió a poner la denuncia, principalmente por miedo a las represalias de su hijo y Mireia. ········· La alarma de Movistar no fueron capaces de desconectarla (ni desconectando la electricidad ni desconectando otros cables). Aitor y Mireia se pusieron en contacto con el Equipo de Familia porque les estaban viendo con las cámaras. ·········· *Adjunta presupuesto de limpieza (988,42€ + IVA). ···· *La paso a Alberto. ·········· *Felisis también solicita otras acciones para reacondicionar su vivienda: pintar la casa, reponer menaje que han estropeado, cambiar colchones...)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-11-03','Ana: Llamo a Marisa, TS del ESM Coria (70841), varias veces, sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-03','miguel, contesto a la abogada Teresa que me pregunta si ya hemos firmado la ratificación de herencia. Mi contestación: Buenos días Teresa, el registro civil de don benito se supone que este lunes han enviado los certificados por correo. Espero que lleguen el lunes o martes próximo. En cuanto lleguen te aviso porque iré a ratificar la herencia inmediatamente. Hoy ha firmado el representante de la Comisión los poderes apud acta para la solicitud de aprobación de herencia y autorización de venta. En cuanto firme la ratificación de la herencia la semana próxima te remitiré los poderes por esta vía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-03','miguel, contesto a la abogada Teresa que me pregunta si ya hemos firmado la ratificación de herencia. Mi contestación: Buenos días Teresa, el registro civil de don benito se supone que este lunes han enviado los certificados por correo. Espero que lleguen el lunes o martes próximo. En cuanto lleguen te aviso porque iré a ratificar la herencia inmediatamente. Hoy ha firmado el representante de la Comisión los poderes apud acta para la solicitud de aprobación de herencia y autorización de venta. En cuanto firme la ratificación de la herencia la semana próxima te remitiré los poderes por esta vía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-11-03','TOD@S: SE VA A PROCEDER A MINORAR EL REINTEGRO DE LA TUTELADA....SI ÁREA SOCIAL TIENE ALGÚN INCONVENIENTE CON ESTO, LO HABLAMOS. A PARTIR DE 01/12/2022 Y HASTA NUEVO AVISO, EL MISMO PASARÁ A SER DE 200 €/MES. OSCAR: ABRIMOS UNA NUEVA CCC EN UNICAJA/IBERCAJA Y CUANDO TENGAS CCC SE LO PASAS A AMALIA PARA QUE CAMBIE PENSIÓN. OSCAR: NUEVO REINTEGRO PERMANENTE X 200 €/MES A PARTIR 01/12/2022...AVISAS A TODAS LAS OFICINAS BBVA DE BADAJOZ. CUANDO SE ABRA CCC UNICAJA/IBERCAJA, PASAS EL REINTEGRO A NUEVA ENTIDAD OJO: HAY QUE PASAR TAMBIÉN DOMICILIACIÓN SEGURO DECESO...PÁSASELO A ESTRELLA. AMALIA: XFA, PASA LA PENSIÓN A LA CCC QUE TE FACILITE OSCAR. AMALIA: HACE MUCHO TIEMPO QUE NO HAY TRANSFERENCIA A MADRE DE TUTELADA...SÓLO HAY REINTEGROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-11-03','TOD@S: SE VA A PROCEDER A MINORAR EL REINTEGRO DE LA TUTELADA....SI ÁREA SOCIAL TIENE ALGÚN INCONVENIENTE CON ESTO, LO HABLAMOS. A PARTIR DE 01/12/2022 Y HASTA NUEVO AVISO, EL MISMO PASARÁ A SER DE 200 €/MES. OSCAR: ABRIMOS UNA NUEVA CCC EN UNICAJA/IBERCAJA Y CUANDO TENGAS CCC SE LO PASAS A AMALIA PARA QUE CAMBIE PENSIÓN. OSCAR: NUEVO REINTEGRO PERMANENTE X 200 €/MES A PARTIR 01/12/2022...AVISAS A TODAS LAS OFICINAS BBVA DE BADAJOZ. CUANDO SE ABRA CCC UNICAJA/IBERCAJA, PASAS EL REINTEGRO A NUEVA ENTIDAD OJO: HAY QUE PASAR TAMBIÉN DOMICILIACIÓN SEGURO DECESO...PÁSASELO A ESTRELLA. AMALIA: XFA, PASA LA PENSIÓN A LA CCC QUE TE FACILITE OSCAR. AMALIA: HACE MUCHO TIEMPO QUE NO HAY TRANSFERENCIA A MADRE DE TUTELADA...SÓLO HAY REINTEGROS.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-10-31','miguel, contestación de Mª José Murillo a la abogada Ana de Pablo: Buenas tardes Ana, Tras recibir la minuta por tus honorarios en el tramitación de la Herencia de D.Luis Murillo Ocampos y Dña. Inés Horrillo Carmona, y como interesadas en el procedimiento, por el presente le comunicamos nuestro desacuerdo en varios puntos de los honorarios: 1. PUNTO PRIMERO de los honorarios. Respecto a éste punto hay dos cuestiones importantes a tener en cuenta: - En primer lugar, la contratación de sus servicios para éste punto, como inicio del procedimiento hereditario, se realizó para asesorar y representar a D. Andrés Murillo a título individual como interesado y parte del procedimiento, contando tanto Dña. Marijose Murillo, Dña. Inés Murillo en éstos inicios con su propio servicio de asesoramiento jurídico a título individual , así como D. José Luis Murillo, asesorado y representado por el abogado de la Comisión tutelar de la Junta de Extremadura, Miguel Férnandez de LLera. - En segundo lugar, el estudio previo y preparación de las escrituras de Herencia de D. Luis Murillo Ocampos y Dña. Inés Horrillo Carmona fue realizado por la notaría Iciar Fernández Zornoza, hecho que se constata en las facturas que adjuntamos de la minuta por dichos servicios, giradas y abonadas por partes iguales por los cuatro hermanos y , por un importe de 478,04 €, haciendo un total de 1.912,12 €. A su vez, éste hecho es totalmente constatable al no acudir a la firma de éstas escrituras y toda la parte inicial como representante jurídica familiar, sino como representante de Dn. Andrés Murillo Horrillo. Una vez finalizada ésta fase, tras la firma de las escrituras de herencia el 1/03/ 2019, se mantuvo una reunión familiar por parte de Dña. Marijose e Inés Murillo con el hermano de ambas, Dn. Ander Murillo Horrillo, y llegaron al acuerdo que para la gestión de todo lo referente al procedimiento A PARTIR DE ÉSE MOMENTO, TRAS LA FIRMA DE ESCRITURAS, contratar tus servicios para representar a toda la familia, y prescindir de otros servicios jurídicos que el resto de interesados tenían también a título individual hasta ése momento; hecho que se te comunicó y aceptaste como abogada particular de Dn. Ander Murillo pasar a ser la representante del resto de los tres hermanos en el procedimiento familiar. Hecho que se corrobora, a su vez, con la provisión de fondos familiar de 100 € realizada el 1/06/2019. Anteriormente a ésta última fecha, no hubo ninguna provisión familiar puesto que la familia no tenía contratados tus servicios, ni te conocíamos, te conocimos personándote en la firma como abogada de Dn. Ander Murillo. (art. 1259 Y siguiente del CC) Con lo que los servicios y honorarios indicados en éste punto no proceden girarse bajo ningún concepto a Dña. Marijose Murillo, Dn. José Luis Murillo y Dña. Inés Murillo, puesto que en ese momento quién había contratado sus servicios y al que estabas representando a título individual fue Dn. Ander Murillo Horrillo. Independientemente de ésto, además se mencionan servicios que han sido realizados por tu parte., sino por la Notaría Iciar Fernánez Zornoza. ¿Qué tipo de profesionalidad es girar honorarios de servicios realizados por otra profesional y que los 4 hermanos ya han abonado ? (justificantes adjuntos a éste correo) 2. A partir del punto 2º de los honorarios, se tienen que girar no sólo a tres Hermanos Murillo Horrillo, es decir, Dña. María José, Dn. Ander y Dña. Inés Murillo Horrillo, sino a cuatro hermanos herederos, faltando el cuarto, Dn. José Luis Murillo Horrillo, interesado en el procedimiento para el cual también has realizado todas las gestiones mencionadas en tus honorarios profesionales. Con todo lo cual, SOLICITAMOS se realicen las correcciones solicitadas anteriormente, se modifique y se gire conforme a derecho correctamente la factura a nombre de los CUATRO HERMANOS, Murillo Horrillo, desde el 2º punto, dado que el primer punto no corresponde bajo ningún concepto a María José, Inés y José Luis, hecho que se puede corroborar a todos los efectos y ante cualquier instancia correspondiente (hay constancia testifical, documental y correos electrónicos tanto de otros profesionales jurídicos como de de la notaría Iciar Fdez. Zornoza). Confiando en una respuesta de acuerdo al respeto y rigor profesional que todo profesional jurídico debe al resto de profesionales de su ámbito, y no intentar cobrar por servicios no realizados y abonados por el mismo concepto a otros profesionales, además sin tener en cuenta y sin entrar a cuestionar el deber de diligencia profesional que en todo momento hubiera de haber regido el procedimiento hereditario a partir de su representación al conjunto familiar (hecho constatable, a su vez), quedamos a la espera de la factura corregida acorde a los servicios efectivamente realizados a las cuatro partes representadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-11-03','Ana: Llamo a Juan Carlos, a Mentalia (920 30 14 00): Mantiene el discurso de que no le gusta el centro y se quiere ir al que estaba antes. Expresa también que no le dejan tener el móvil y a él gusta escuchar la música en el móvil. ·········· "El tabaco me lo dan contado", y no se lo dan hasta que no coma, pide que le mandemos tabaco desde aquí "en un sobre", le explico que eso no puede ser. ···· "Trabajo más que los otros, limpiando animales y dándoles de comer y todo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-11-03','miguel, contestación de la abogada Ana de Pablo a Mª José: Estimada Marijose, paso a contestar a tu mensaje de correo electrónico de 31 de octubre y os envío a cada uno la minuta de honorarios rectificada: 1.-Constatado que el encargo profesional de los tres hermanos Murillo se hizo con posterioridad a la firma de la escritura de Herencia. He suprimido de la minuta de honorarios lo correspondiente al apartado: 1ª:"Asesoría jurídica, estudio y preparación de Herencia..." de la minuta correspondiente a tí y a Inés, porque efectivamente, en un principio fui contratada por Ander y , en consecuencia, elaboré un borrador de escritura con el inventario de fincas y demás bienes del caudal hereditario, adjudicándoles los valores que estimé (por encima del valor de mercado para que no hubiera ganancia patrimonial que declarar a Hacienda cuando se produjeran las ventas). Esta gestión corresponde minutar exclusivamente a Ander. 2.- El resto de puntos (de 2º a 6ª, que pasan a ser de 1º a 5ºen la minuta rectificada) corresponden a la minuta correspondiente al encargo profesional recibido por los tres hermanos Marijose, Ines y Ander Murillo, girando a cada uno de los tres en proporción a lo que del trabajo realizado considero que corresponde a cada uno de los tres. Las gestiones realizadas en beneficio del cuarto hermano, se las minutaré aparte y en su proporción. La minuta que os envío a cada uno responde a la hoja de encargo de servicios recibida por los tres hermanos y dividida en tres partes iguales, rectificando el apartado relativo a las gestiones sobre la Escritura de Herencia, que corresponden sólo a Ander. Quedando a tu disposición para cualquier aclaración, recibe un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-11-02','miguel, escribo a la abogada Carmen Lucas: Buenos días, adjunto escrito recibido este lunes del defensor del pueblo donde piden los escritos intercambiados por el tutelado contigo para tu conocimiento. Entiendo que no estas obligada por el principio de confidencialidad. Quedo a la espera de tu contestación para responder a la oficina del defensor del pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-11-03','miguel, contestación de Carmen Lucas (abogadas): Te mando la calificación del Fical, tengo que defender una eximente completa par declararle inimputable, me vendría muy bien algún informe de Psicologo que le trata, indicando que, cuando está desequilibrado (en este caso parece que, sin medicacion y con bebida ¿No?) no controla sus actos ¿Podríais conseguirlo? ¿Teneis el informe del Fornese verdad? Creo que nos marca la pauta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-11-03','miguel, Ana me envía el último informe de psiquiatría, y queda pendiente si le envían algún otro informe más reciente. En cuanto a correos con Saturnino a la abogada que pide la oficina del Defensor del Pueblo, ni Ana ni yo tenemos nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-10-20','Ana: Llamada de Rosa, TS del C. Salud de centro-CC (54328): Ventura acudió a su despacho después de mucho tiempo sin acudir por allí. ········· Rosa me pregunta si vemos oportuno solicitarle el catering del IMAS. Le indico que ya se lo hemos solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-10-18','Ana: correo de Toni-Futuex con información de los últimos seguimientos (06/10 - 7/10 - 10/10 - 11/10 - 13/10): En la primera de estas visitas, presentaba notable deterioro físico y un brazo escayolado. Estaba viviendo en la calle y reconoció el consumo de tóxicos. ··· Acordaron con la directora del Centro de Acogida de Cáritas cita para el día siguiente, día 7. A la cuál acudió. ······ El día 11 ingresó en dicho centro. ····· Se comprometió a acudir al ECA y hacerse los correspondientes controles de orina. Para poder mantenerse en el centro no puede consumir. ············ El día 13 "informan desde el centro el comportamiento es adecuado, pero ha estado algo nervioso porque ha estado dos días sin tomar su dosis de metadona, informan que ya se ha gestionado con CEDEX la recogida de la misma para que pueda tomarla en el centro. Comunican también que ha dado negativo en el control de orina para el consumo de sustancias." ··········· Se niega a la posibilidad de ingreso en comunidad terapéutica, su único objetivo cuando se recuperes es vivir de forma independiente en una vivienda de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-11-03','Ana: Correo Residencia Balcón de Extremadura - Montánchez: "comunicaros que desde ayer Dº Mateo Ruano Moreno esta en nuestro Centro de Montánchez."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-10-25','Ana: correo de Mamen, TS del Centro Vida, Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te adjunto el informe social con la información de Miguel Ángel, la verdad que de momento esta respondiendo bastante bien en el proceso. Cualquier cosa me dices, seguimos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-11-04','Ana: Reenvío correo remitido por Ángel, A. Jurídico CTAEX, a Mamen, TS Centro Vida-Caritas, y a Pilar Martin, TS ESM-CC: "En relación a la solicitud que nos hace al Juzgado (subrayo en el hilo en amarillo), ¿podríais enviarle, alguna de la dos, las próximas citas que tenga tanto en el ECA como en el ESM? No sé si las tendrá en papel o si tú, Pilar, podría solicitarlas ahí en vuestro centro. Para poder remitírselo al Juzgado y que vean que ya ha iniciado el tratamiento. No sé si piensan que a estos centros puede acudir diariamente o qué es lo que esperan, son tratamiento ambulatorios, y entiendo que habrá que comunicárselo y explicárselo al Juzgado." ··········· "En relación al cumplimiento de la medida de libertad vigilada impuesta a Miguel Ángel Ramos Andrés, te envío el requerimiento que nos hace el Juzgado (archivo Dior), para que cuidemos que en el plazo máximo de 5 días, el tutelado inicie dicho tratamiento en el centro indicado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-11-04','TERESA Comunicar que Marta se ha escapado del centro y no tenemos noticias suyas desde las 12.00h de esta mañana, estamos intentando localizarla y cuelga el teléfono. A María Luisa Calvo trabajadora social, sustituta de Alexandra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-07','TERESA El pasado día 27 de octubre se recibió un mensaje de Laura de Feafes Almendralejo comentando que algunos compañeros de Barto le habían enseñado ciertos mensajes de whatsapp que hacían referencia a ideas delirantes y extrañas, se charla con ella y se le comenta que el próximo día 3 de noviembre Bartolomé tiene cita en el centro de salud para el inyectable y que se le acompañará para ver qué tal se encuentra. El lunes 31 de octubre se llama a Barto para quedar con él el jueves 3 , comenta que no piensa ponerse el inyectable de forma muy nerviosa, se le explica que de cualquier manera sería bueno vernos y tomar un café tranquilamente para charlar, nos dice que de acuerdo, y quedamos en vernos a las diez el día 3 en su domicilio. Se recibe una llamada de Barto el día 2 de noviembre para confirmar la visita y sin decirle nada vuelve a insistir en que no piensa ir a ponerse el inyectable. Se llama a María (la enfermera de salud mental para comentárselo), se pone en contacto con él y Barto le da la misma respuesta negativa al hecho de ponerse el inyectable, María le pide que se acerque simplemente a ver cómo está y él acepta. Incidencias: Ese mismo día se recibe información de la Trabajadora Social del Ayto explicando que Barto ha acudido contando ciertas ideas delirantes. El día 3 se acude al domicilio de Bartolomé y se encuentra la casa abierta y su aux de ayuda a domicilio y una pareja de la policía local dentro, la vecina de abajo ha avisado a la policía porque le entraba agua por el techo. Parece ser que Barto ha tenido algún problema con el calentador o incluso es posible que, debido a la inestabilidad que presentaba en estos últimos días haya sufrido un brote, y lo haya arrancado provocando pérdida de agua, su piso se ha llenado de agua y se ha filtrado a casa de su vecina de abajo. Se adjuntan fotos. La policía comenta que sus compañeros de la policía nacional le han dicho que Barto ha ido a la comisaría a denunciar unos hechos completamedelirantes y sin sentido. Se llama a Barto para saber dónde está y cómo se encuentra pero no contesta. Se vuelve a llamar a los pocos minutos y nos comenta, con un estado tranquilo, que ha salido a hacer unas gestiones porque ha tenido problemas con el calentador, le preguntamos dónde está y no quiere decirlo , insiste en que nos vayamos y que lo llamemos en un rato por si nos podemos ver. Se recibe una llamada de su aux de ayuda a domicilio a quien hemos conocido antes (estaba en casa de Barto recogiendo todo el agua) y nos dice que el policía local que ha estado en casa de Barto ha cortado la llave del agua pero que sigue goteando y que probablemente se le vuelva a colar agua a la vecina de abajo. Se le da las gracias por la información. Se acude al centro de salud (area de salud mental) y nos reunimos con la administrativa de salud mental, la enfermera (María) y el psiquiatra de Barto, comentan que no pueden hacer nada a no ser que les llegue un aviso desde la policía y entonces lo manden por urgencias. Se vuelve a llamar a Barto y no contesta. Unas horas después María nos llama y comenta que ha intentado contactar con él pero que no ha sido posible. Se llama a la policía nacional y se habla con el policía que ha atendido a Barto, explica que ha estado allí y que, obviamente, no se ha llevado a cabo ninguna denuncia de acuerdo a los hechos que comentaba Barto porque era ideas muy extrañas y se le notaba muy alterado. Han intentado tranquilizarlo y un rato después se ha ido ya más tranquilo. Se le comunica que Barto es una persona que sufre un trastorno mental grave y que está desestabilizado porque no se ha puesto el inyectable, que si lo ven por la calle en estado nervioso o si reciben algún aviso de un vecino porque esté montando jaleo en casa que sepan por qué es y que, de acuerdo al protocolo que ellos suelen llevar a cabo, lo lleven al centro de salud u hospital para que reciba la atención necesaria. Se le deja el teléfono que aparece en la web de la Comisión Tutelar por si necesitaran ponerse en contacto con la misma. Se recibe una llamada de la vecina de abajo (la que ha sufrido el accidente con el agua) y comenta que Barto está en casa y que, desde su ventana, lo ha visto salir a tirar el calentador en un estado de nerviosismo y agitación dando portazos. Que están preocupados porque son personas mayores que no están tranquilas debido al estado de Barto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-11-04','Ana: Correo de Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "Buenos días, os informamos que ayer Isabel realizó una sobreingesta de medicación. Ha pasado la noche en el Hospital Virgen del Puerto en observación con previsible alta hoy." ··················· Nuevo correo de Blanca, al final de la mañana: "Buenas, os comento que Isabel ya está en el centro. La sobreingesta forma parte de su problemática para afrontar el malestar y las dificultades de gestión. Hace crítica de ello,no se valora como gesto autolítico. Continuamos con intervención."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-07','TERESA CORREO DE ANTO LA TS DEL SASB DE ALMENDRALEJO Buenas tardes Teresa ,me urge hablar contigo , llevo intentándolo toda la mañana y no ha sido posible ni a través de tu teléfono ni a través del de la Comisión. Desconozco si la compañera de Futuex ha visitado hoy a Bartolomé y ha realizado alguna intervención . Por otra parte , os informo que he contactado con la empresa que le presta el servicio de ayuda a domicilio y me comentan que no ven bien a Bartolomé a nivel psiquico y que este ha dejado de tomarse la medicacion . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-11-07','miguel, preguntan a Tere y ella a mi desde el centro María Cadenas Casco T.Social I.S.Hogar Nazaret “La Providencia”trabajadorasocial@providencia.es: Hola Teresa, Te mando el recibo con movimientos de cuenta de la madre de Juani y Maite. Nos lo envía la residencia donde vivía. ¿Cómo sigue ese procedimiento de declaración de herederos?¿finalizó? ************************************* Llamo a la notaria de Azuaga (924890159) para que nos manden la factura, la abonemos y seguidamente nos envíen la declaración de herederos. Una vez que llegue hablar con el centro para liquidar impuesto de sucesiones y desbloqueo y reparto de la cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-11-07','Email de la TS del centro de Arevalo. Buenos días, la verdad es que no está nada bien, en las intervenciones que realizo con ella objetivo un discurso desorganizado de tinte delirante donde incluye a Amalia y es bastante complicado que comprenda algunas de las explicaciones que aporto porque no me escucha, esperemos que mejore. El pasado lunes, hablé con ella sobre el tema de las llamadas con vosotras, la informé que sois curadores económicos, que las demandas que tuviera me las debía realizar a mí para la coordinación y que cuando quisiera hablar con vosotras me informara y fijábamos días y hora para realizarla conjunta, avisé a la unidad para que no la pasen llamada. En cuanto al dinero, tengo pendiente registras las transferencias de esta semana pero hasta el momento no lo había recibido. Saludos Araceli','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-11-07','Email de la TS del centro de Arevalo. Buenos días, la verdad es que no está nada bien, en las intervenciones que realizo con ella objetivo un discurso desorganizado de tinte delirante donde incluye a Amalia y es bastante complicado que comprenda algunas de las explicaciones que aporto porque no me escucha, esperemos que mejore. El pasado lunes, hablé con ella sobre el tema de las llamadas con vosotras, la informé que sois curadores económicos, que las demandas que tuviera me las debía realizar a mí para la coordinación y que cuando quisiera hablar con vosotras me informara y fijábamos días y hora para realizarla conjunta, avisé a la unidad para que no la pasen llamada. En cuanto al dinero, tengo pendiente registras las transferencias de esta semana pero hasta el momento no lo había recibido. Saludos Araceli','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-11-07','Email de Areceli> Buenos días, por el momento no hemos recibido auto del Juzgado de Arévalo sobre el procedimiento de internamiento, se informó al ingreso al Juzgado de Badajoz y se seguirá realizando semestralmente hasta que nos comunique Arévalo que ha recibido el expte y acepta la inhibición. En cuanto a su estado como os dije en el email de ayer, no se encuentra bien, verborreica y discurso delirante en el que te incluye a tí. Anoto el email para remitir las necesidades económicas de Mercedes te pondré en copia a tí. Saludos Araceli','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-11-07','Ana: Llamo a Marisa, TS del ESM y ECA de Coria (70841): Me informa de que ha comenzado a asistir al ECA, y el médico de éste, Jose, ha decidido derivarle directamente al ESM. ············ Llamo a Juana Mª, Aux. Admvo. (70838): acordamos que cuando vayan a enviarle la hoja de citación me la enviarán también a mí por email. ····················· Se lo comunico a Toni de Futuex, para que lo tengan en cuenta para la intervención. Les avisaré para el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2022-11-07','-Amalia , envío email a los compañeros. Buenas , he llamado a su madre varias ocasiones desde que supimos todo esto, , le he dejado mensajes pero no hay forma de hablar con ellos . Creo que es su hermano el mayor, el que ha sacado el dinero , no sé si su madre sabrá algo de ésto. Pero en el banco tendrán que informar a quien le han dado ese dinero y cómo ha podido retirarlo si no tiene autorización. Este hermano es el que no tiene discapacidad " reconocida " pero presenta adicción al juego , locales de alternes.. No creo que la madre que no puede ni andar ,ni el resto de los hermanos que presentan discapacidad de mayor nivel tengan capacidad para sacar el dinero . El tema de denunciarlo , tendrá que valorarlo Miguel , pero antes tendremos que tener la información exacta del banco. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-11-07','Ana: Llamada de Ángel Félix (643 622 174): está mejor, más recuperado desde que está en el Centro para personas sin hogar. Ya le han quitado la escayola también. ···· Solicita la compra de un atril de dibujo. Pero dice que en la tienda le han dicho que no le pueden traer el que quiere y que le han propuesto, desde el centro, pedírselo por Amazon. *Le indico que me llame mañana la monitora en cuestión (Mabel). Se le podría abonar mediante transferencia bancaria, si Alberto lo aceptara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-11-07','Ana: Envío correo a Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "En relación a Yolanda Caldera, se ha puesto en contacto con la Comisión Tutelar un tío suyo, dice quiere saber de su sobrina, se llama Fco José Martin, quieren saber en qué centro está y hablar con ella, se le ha dicho que se lo vamos a comunicar y si ella desea tener ese contacto lo facilitaremos. ¿Te importaría consultarle? ¿Y en caso de tener conocimiento de si existió relación previa (si puede ser beneficioso para ella o todo contrario) informarnos también al respecto?" ·········································· Respuesta: "Mañana regresa Maripaz de vacaciones, lo tratamos en la reunión de la unidad y ya te digo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-11-07','Ana: Correo de Mamen, TS Centro Vida- Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Ana informarte que desde el Centro de Acogida Temporal "Centro Vida", Programas Personas sin Hogar se ha enviado al juzgado las fechas de las citas que tiene Miguel Angel en Cedex, informando también que se ha iniciado protocolo para derivación a comunidad terapéutica por sus problemas de adicciones. Referente a la parte del Equipo de Salud Mental, yo ya en su momento envié informe del psiquiatra a este mismo juzgado, pero creo que si hay que volver a enviar informes y citas lo tiene que realizar Pilar Martin"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-11-03','Ana: Envío correo a Alberto, Jefe Secc. Ecca: "Adjunto presupuesto de limpieza en la vivienda de Javier Agudo Cumplido. Si no recuerdo mal, no tiene problemas económicos y supongo que es asumible. Hay que dar respuesta a Futuex para que acuerden con ellos fecha de realización del servicio. Confirmarle por favor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-11-07','Ana: Correo de Julia Durán, TS (julia.duranm@salud-juntaex.es): "Tras realizar Visita Domiciliaria junto a la compañera responsable del Servicio de Ayuda a Domicilio del IMAS, creo conveniente comentarte varias cosas que observamos y que desconozco si tenéis conocimiento de ello. Ha contratado un sistema de alarma en el domicilio. Nos comento que ha cambiado de entidad bancaria. Dispone de un ordenador portatil, que asegura le ha regalado la empresa de telefonía móvil. Asi mismo se observaron varias deficiencias en la vivienda como humedades de fachada y la baranda de la terraza esta floja, con el consiguiente peligro que eso conlleva. En este punto dime si quieres que hable con el Administrador de la comunidad para intentar subsanar ambos problemas." ·············· En conversación telefónica, Julia me comenta que Ventura no acepta el apoyo de Virginia-Futuex y propone un cambio de educadora. ············ Respondo al correo: "Intentaré que desde el programa de Apoyo Comunitario le cambien la educadora de seguimiento, a ver si es posible, y en tal caso, a ver si con la otra educadora conecta mejor y acepta su seguimiento. Con respecto al cambio de cuenta que te ha comentado, no habrá dicho qué entidad, no? Si pudieras averiguarlo sería estupendo para que los compañeros de la sección económica pueda hacer algo al respecto. Sin saberlo es difícil. En relación a la sistema de alarma, ¿sabes con qué empresa ha hecho el contrato? Y en cuanto a los arreglos de la comunidad, si hablas con la el Administrador, te lo agradecemos también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-11-08','TERESA RECIBO LLAMADA DE SU HERMANA ROSA INFORMANDO QEU BEATRIZ ESTA INGRESADA DESDE EL JUEVES EN LA UHB DE LLERENA, SE LA LLEVO UNA AMBULANCIA ACOMPAÑADA DE LA GUARDIA CIVIL ROSA – 696 33 77 32 SE LE HACE TRANSFERENCIA DE 100€ PARA GASTOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-11-07','Ana: Correo de Isabel (imariacano.ic@gmail.com): cuando me vais a dar los 50 euros que me dijisteis que me ibais a dar en navidad ? Ah ya tengo reservado el hostal en Trujillo para diciembre del 12 al 16 cuesta 120 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-10-27','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te informo que acaba de ser derivado Aaron Rosado Alarcón a Salud Mental. Ha bajado muy nervioso y queriendo pegar a todas las personas que se encontraban con él. Se ha activado el 112 y el médico ha valorado derivarle. Cuando sepamos si queda ingresado te informamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-10-10','Ana: Correo de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te informo que Felisa continua ingresada en Salud Mental en Cáceres. Hoy me ha llamado la Trabajadora Social del hospital y me dice que no para de trasladarles que quiere cambiar de centro, estar con su familia, ...les ha informado que tuvo un juicio que tenía que estar un año en ASINDI pero ya ha pasado entonces quiere estar con su familia. La compañera me comenta que está muy demandante con temas de salud y que cree que le darán el alta pronto. Por lo visto, quería que le visitáramos allí pero no lo consideramos conveniente porque sabiendo que está físicamente bien y atendida en otros aspectos, puede buscar en otro momento querer que se le ingrese y que tenga las visitas y llamadas que aquí no tiene. La necesidad de tener contactos con otras personas que conoce como familia o amigos no sé cómo la vamos a cubrir y, tal vez, es lo que más necesita por lo que nos dice."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-10-25','Ana: Correo de Sonia-Bernabé, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comunicarte que ya han dado el alta a Felisa Bruno. Como te comentaba en un correo anterior, ha manifestado repetidamente durante su ingreso que quiere el traslado al centro de Badajoz para estar con su familia. Desde que ha llegado nos alude a querer ir a Badajoz y demanda mucha atención, pero está yendo a su taller de Centro Ocupacional y, quiere participar en zumba. Va a probar hoy martes y el jueves para ver si le gusta la actividad de zumba por 5 € las dos sesiones. Si le gusta la apuntamos por 20 € todo el mes, lo necesita para quemar calorías y es una manera de salir de las instalaciones, conocer gente nueva"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-11-07','email a Tere de Adiser de la Ts Antonia Soriano Martin: Buenos días Teresa, en archivo adjunto te remito la copia de la denuncia que puso la monitora del taller a Natalia para que la tengáis vosotros también. Y también te adjunto la cita a psiquiatría del día 31 de octubre, no es necesario que abonéis nada en concepto de transporte y acompañamiento porque tiene de su dinero mensual que le ingresáis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-11-08','Mayte: me comenta Toni que le indiquemos en cuanto lo sepamos el día del traslado, que les urge sacarla de alli… me comenta que ellos pueden hacerlo con su propia furgoneta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-11-08','miguel, me llega de Tere los emails (el que le envió ayer el centro Adiser y el que remite a Maite) Adjunta la última denuncia por amenazas y agresión a las cuidadoras del centro. Me confirma Maite que están a la espera este mes del traslado de la tutelada a otro centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-11-07','Ana: Correo de Sonia-Bernabé, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que esta mañana ha sido derivada a Salud Mental de Cáceres Felisa Bruno Saavedra. Lleva varios días nerviosa y muy demandante de atención. Hoy ha llegado a agredir a una profesional que ha precisado atención médica por contractura y el médico ha presentado parte de lesiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-11-08','Ana: Envío correo a Sonia Bernabé, en relación a sus últimos correos: "...Iba a decirte que qué buena idea la participación de Felisa en la actividad de zumba. No sé si ha llegado a empezar y qué tal ha ido. Pero ya he visto y leído tu correo de ayer y que de nuevo se ha “desestabilizado”… Espero que no sea demasiado grave el daño a la compañera del recurso… Y que ella evolucione bien… estas conductas son muy difíciles de modificar… Por cierto, si no habéis comunicado estas agresiones a la sección de Discapacidad (Unidad de Programas Asistenciales) por favor, hacerlo cuando podáis. En cuanto al contacto que demanda con los familiares, lo valoraremos en equipo, pero lo veo complicado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-11-08','Ana: Envío correo a Julio-CTAEX, Aux. Adtvo. CTAEX: "adjuntar otro documento para registro: COMUNICACIÓN DE CAMBIO DE DATOS DEL EXPEDIENTE DE DEPENDENCIA, relativo a Mª de los Ángeles Rosado Albarrán, para que lo remitas a: S.E.P.A.D. Sección de Dependencia I Pza. Hernán Cortés, 1 C.P. 10001 CÁCERES BUZÓN de Registro Electrónico A11030403", para comunicar el fallecimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-11-08','Ana: conversación con Consuelo, Psicóloga y Responsable del Centro de Acogida Temporal de Cáritas- Plasencia (927 42 04 48): sin respuesta. ··············· Más tarde hablo con Isabel, TO de mismo centro. Plantean que no les importa hacer ellas el pedido del caballete de pintura para Ángel Félix a través de Amazon. ········· Pido que envíen presupuesto (captura de pantalla) al ctutelar@ para que valoren y, en su caso, lo aprueben.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-11-08','Ana: Llamada de Mª Carmen, TS del HSPA (56283), consulta algunos datos, pues están elaborando el informe para la derivación a UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2022-11-03','Ana: Correo de Ángel, A. Jurídico CTAEX: "En relación con la revisión de la sentencia de Vanesa Fernández Gómez, se ha fijado comparecencia para el día 29/11/22, a las 11:30. Nosotros asistiremos a través de videoconferencia. Vanesa está citada también, por lo que ese día tiene que acudir al Juzgado." ······················ Lo reenvío a Isabel Pino, TS del Ayto. de Miajadas (ipino@miajadas.org) para su conocimiento y por si puede asegurarse de que Vanesa lo sabe o en su defecto se lo comunique.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-11-08','miguel, tras hablar con la TS del plena inclusión de Ribera del Fresno, me confirma que desconoce gestoría para tramitar la liquidación de impuesto y desbloqueo de la cuenta bancaria por lo que llamo a gestoría de Azuaga Ramirez Duran CB 924-892736, email: asesoriaduranramirez@hotmail.es ********************************************************* presupuesto de la notaria: Ok recibido, hable con Notaria y efectivamente hay que liquidar en Oficina liquidadora de Llerena por lo que hay que desplazarse una vez para la liquidación y supongo que otra para retirar documentos que posteriormente tengo que presentar en Banco Santander, para que desbloquen la cuenta. Estos trabajos se los puedo realizar por 250 euros mas IVA . Si solamente tengo que desplazarme una vez y soy capaz de traerme la documentación en el día que me resulta difícil los honorarios serían de 125 euros mas iva. A la espera de su respuesta, para proceder a realizar las gestiones reciba un cordial saludo. Asesoría Durán Ramirez C.B. OFICINA AZUAGA Avda. de la Estación Nº 44 06920 Azuaga (Badajoz) Tfno. 924 89 27 36 Móvil 625 57 68 37 Email: ASESORIADURANRAMIREZ@HOTMAIL.ES OFICINA ALANIS Plaza de la Salud Nº 4 - Bajo 41380 Alanis (Sevilla) Tfno. 954 88 53 75 Móvil 639 88 57 88 Email: asesoriaduran@ncs.es *************************************************** envío email para me confirme la parte económica que puedo contratar estos servicios: Parte económica confirmarme si podemos contratar los servicios de esta gestoría para los trámites de impuesto de sucesiones y desbloqueo y reparto de la cuenta bancaria de la madre de las hermanas Juana y Mª Teresa Gonzalez Naranjo por 250 euros mas IVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-11-08','Ana: Envío mail a Toni-Futuex: "Buenas tardes Toni, En relación a VENTURA GOMEZ GARCÍA, teniendo en cuanta la poca/nula adherencia de Ventura con Virginia, Educadora del Programa de Apoyo Comunitario, y habiendo conocido por Julia Durán, la TS, del Hogar Peña del Cura, su intención manifiesta de incluso denunciarla, queríamos solicitaros el cambio de educadora, con la doble intención de: - Evitar a Virginia, cualquiere otro mal “trago” a consecuencia de las actuaciones de este hombre - Promover la adherencia al programa, ya que al parecer, recuerda con agrado, los contactos que ha tenido con Gloria, con quien es posible que pudiera funcionar. Ya nos dices qué os parece y si es posible nuestra propuesta. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-08','TERESA RECIBO CORREO DE ANTO TS SASB Teresa buenas tardes. Hoy me han llamado de la empresa de ayuda a domicilio que presta el servicio en casa de Bartolomé, me comentan que está sin agua desde el viernes, por lo que no puede asearse y el auxiliar se ve obligado a limpiar la vivienda con botellas de agua mineral . Destacan que es necesario reparar la tuberia del calentador para que deje de tener fuga. Os lo comento por si decidís enviar a un fontanero para su reparación y solventar esta circunstancia. DERIVO A FUTUEX PARA BUSQUE FONTANERO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2022-11-08','TERESA Buenas tardes Teresa, nada finalmente no quiere irse, cada día cambia de opinión, y le he dicho que para ingresar tiene que estar segura. Sería conveniente hacer las gestiones para que Ángela ingresara en un Centro residencial obligatoriamente, esta señora no está en condiciones de vivir sola, necesita ayuda 24 horas del día. Saludos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-11-09','miguel, recibimos email, CARMEN GONZALEZ >cgn@cecimag.onmicrosoft.com>:Nos ponemos en contacto con vosotros como representante legal de Raquel Rodriguez Barrios, quien en varias ocasiones ha contactado con ustedes en un asunto relacionado con la solicitud como parte interesada de una copia de la sentencia a nombre de Nemesia Garcia Paniagua, quien a dia de hoy figura como titulada por parte de la Junta de Extremadura. Sin embargo, dicha solicitud no se ha atendido por parte de la asesoría jurídica de la Comisión Tutelar de la Junta ni a través de correo electrónico ni a través de las distintas llamadas que a realizado a vuestros servicios. Siguiendo indicaciones del Juzgado de Plasencia, solicitamos una copia de la sentencia dirigida a nuestra interesada para evitar una moratoria en todos los procedimientos en los que se pudiera encontrar inmersa. Poniéndonos a su disposición y agradeciendo su total colaboración, les mandamos un saludo, ******************************************************** mi contestación: Buenos días, la sentencia de incapacitación no puede se les puede remitir por la ley de protección de datos. En cuanto a la reclamación que realizó en su día Raquel sobre una cuenta bancaria repartida en vida de su madre Virgilia, desde la Comisión Tutelar de Adultos entendemos que no puede llevarse a la masa hereditaria de su madre. ********************************************************* mi contestación: Buenos días, para iniciar el procedimiento judicial relativo al control que se ha realizado sobre una cuenta bancaria con dos titulares independientes es necesario la consulta de dicha sentencia para saber la disposición que se acordó en su momento, le agradecería me indicara cómo podríamos tener acceso a ella o como podríamos solicitar una copia puesto que mi representada es parte interesada. *******************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-11-09','Ana: En relación al correo de Ceferino preguntando por la compra de la Controladora Pioneer DJ800, y mi respuesta con copia a Paula y Carolina, profesionales CRR, recibo correo de Paula: "Hola, gracias por la coordinación a través de los correos. El martes mismo un rato antes de que comunicara con vosotros, hablamos Ceferino y yo del tema de la controladora. Como señalaba en otro correo estamos trabajando la toma de decisiones desde hace un tiempo en relación a sus intereses y su la participación en distintos roles en su vida. Fue Ceferino quién insistió en su decisión de vincular la controladora a la asistencia al curso de italiano, únicamente a la asistencia, no a resultados. Insistí en que valorara esta decisión y sólo accedió a limitar esta condición a participar hasta diciembre de este año. La realidad es que ha acudido a dos sesiones de todo el curso y no ha cumplido con el requisito que él mismo se había impuesto. Por ello, y de acuerdo a su proceso de adquirir mayor autonomía en el proceso de toma de decisiones y como medio de aprendizaje (ver sus limitaciones y necesidades, así como sus habilidades para poder ir aprendiendo nuevas estrategias) hablábamos el martes de que no tendría para navidades la controladora, puesto que él había decidido y tenía que ser consecuente con la decisión. Ayer no había traído el trabajo propuesto sobre qué acciones le acercan al cumplimiento de sus objetivos y cuales le alejan (tarea que iba a trabajar la posibilidad de ir a la discoteca de Madrid o no en relación a preparación, presupuestos y vuestra aceptación), por lo que ha limitado sus oportunidades para participar. A pesar de todo el mensaje es seguir apoyando que pueda hacer y proyectar, tomar decisiones y ayudarle a llevar a cabo sus proyectos y conseguir sus objetivos. Por este motivo, la controladora dejaría de ser su regalo de navidades y tendría que planificarlo de nuevo para otro momento y tomando decisiones (aunque sea para febrero, el objetivo es que lo logre). Si necesitáis más información o alguna cuestión podemos hacer una llamada incluyendo a Cefe si lo consideráis oportuno."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2022-11-08','Ana: Envío correo a María, Res. Ntra. Sra. de la Luz de Malpartida Plas (direccion@residencialaluz.com): "Adjunto remito el Consentimiento Informado para el sistema personalizado de dosificación de medicación relativo a Antonia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2022-11-08','Ana: Envío correo a María, Res. Ntra. Sra. de la Luz de Malpartida Plas (direccion@residencialaluz.com): "Adjunto remito el Consentimiento Informado para el sistema personalizado de dosificación de medicación relativo a GUADALUPE BARRAGÁN GARCÍA firmado por el presidente de la CTAEX."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-11-09','TF. ANTONIO FRAIRE : 657714690 , afraireroman@gmail.com Amalia : lo llamo para indicarle que no se le autoriza el adelanto de pension.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2022-11-09','Amalia : escribo a sección eco . Buenos días , comunico a Antonio que no se autoriza el adelanto de pensión solicitado . Desde la parte social ya se está trabajando con Antonio , pero no he establecido pto. económico hasta ver cómo queda finalmente su sentencia. En la primera de las sentencias , tenía tutela total y su padre era el tutor. En la revisión de la misma , se remueve del cargo al padre , a favor de la CTAEX . Y se establece curatela , pero no se especifica qué esferas abarca . Si os parece podemos ir solicitando movimientos actuales de cuentas , no sé si podréis tener acceso ya a ellas . Ya os adelanto , que percibe PNC , que de los 420€ paga autonomo ( 89€) y un gestor de autónomo ( 60€ mes ) .Me dice que paga un crédito de 35 € al mes , me suena raro . Vamos imposible que le llegue para pagar comida y suministros . Y gasolina , tiene un coche con el se desplaza hasta Badajoz . Resulta que solicitó una subvención de 7.900€ y es requisito mantenerse de autónomo . Estoy haciendo averiguaciones al respecto . Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-11-09','Tf de Julian , Dtor . del centro Camino a la vida. 657813847 Allí no tienen tf personal , hay que llamar al tf de Julian .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-09','miguel, llega sin inscribir nuestro cargo en el certificado de nacimiento del registro civil de don benito. les envio email: Buenos días, nos han remitido el certificado de nacimiento que adjunto del tutelado Sergio Gil Sanz pero sigue sin aparecer anotación al margen del nombramiento a la Comisión Tutelar de Adultos del cargo. Ruego que lo revisen, inscriban la aceptación del cargo de tutor de la Comisión Tutelar de Adultos de la Junta de Extremadura y nos remitan certificado literal de nacimiento con dicha inscripción, en el plazo más breve posible pues estamos a la espera de poder ratificar una herencia en la notaria. Les indico de nuevo la dirección al que enviárnoslo: Servicio Extremeño de Promoción de la Autonomía Personal y Atención a la Dependencia (SEPAD) Comisión Tutelar de Adultos Avda de las Américas nº4, 06800, Mérida (Badajoz)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-09','miguel, llega correcto inscripción de registro civil de don benito con nuestro cargo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2022-11-09','Ana: Llamada de Juan Aº, Res. Torre de Don Miguel (646 928 820) han conseguido cita en un pueblo cercano para acudir a renovar el DNI de José: 17/11/22. En cuanto lo tengan nos lo remitirán escaneado a color.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-11-09','miguel, recibo email de Rocio Gracian: Buenos días Miguel, El próximo día 15 de noviembre es la comparecencia en el Juzgado de Mérida en el procedimiento de solicitud de la autorización judicial. Tienen que acudir el solicitante que haya encabezado la demanda que te envié y también Damián. Como el objeto de la solicitud es simplemente pedir autorización judicial para continuar con el procedimiento de desahucio, y con la demanda ya aportasteis todos los documentos que demuestran lo que estamos pidiendo, ahora se trata simplemente de volver a reiterar en la comparecencia que dicten la autorización en base a todo lo alegado en la demanda. Te envío en archivos adjuntos las dos providencias que he recibido del juzgado, una primera en la que nos dicen que habida cuenta del tiempo transcurrido desde la vista sin que aportemos la autorización, iban a archivar el procedimiento. A ello contesté con un escrito aportando la citación del Juzgado de Mérida para el día 15, y me respondieron con la segunda providencia que te envío en la que suspenden el procedimiento hasta aportar la autorización judicial. Con ello podéis en la comparecencia pedir que se resuelvan la autorización lo más urgente posible, pues los inquilinos llevan más de un año dentro de la vivienda sin pagar nada. Ya me informas de como vaya todo, y muy importante que Damián vaya a la vista, es obligatorio que asista. ******************************************** Mi contestación: Buenos días Rocío, comentarte que conforme el email que te remito debajo quedamos en hacer un poder apud acta que al final entiendo que no hemos necesitado y que te adjunto con las procuradoras que nos indicasteis. Como veras el escrito lo hicimos nosotros y tal y como nos indicastes en el email no era necesario abogado y procurador por ser el importe inferior a 6.000€ Por tanto entiendo que debemos asistir la Comisión Tutelar de Adultos y Damian. Me llevaré tu número de teléfono ante cualquier duda que tengamos. Adjunto escrito de solicitud que enviamos en su día al juzgado y su justificante Lexnet, citación y el poder apud acta (que se hizo en su día para los juzgados de Plasencia porque allí residía Damian en aquella fecha) ****************************************************** Escribo a Damian: Buenos días el martes 15-11-22 a las 12:45h te espero en el juzgado de 1º instancia e instrucción nº1 de Mérida para el procedimiento X15 autorización disposición bienes medio de apoyo 392/22. Llevaré el número de móvil 616552977','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-11-09','Buenos días A pesar de que llevábamos muy bien camino con MJC, desde ayer solicitó el alta voluntaria. Ya van varias veces que he conseguido que reflexione al respecto, y ahora parece que tenía asimilado quedarse, pero debido a problemas de convivencia, ha decidido solicitarla de forma definitiva. Le he comentado que aguante un par de días, que se los tome para reflexionar, le he hablado de las consecuencias a largo y corto plazo, he hecho todo lo posible. Ahora mismo se encuentra muy motivada a formarse, se siente muy acompañada y acogida por su familia paterna (su tía y prima) y le han abierto las puertas de su casa, entonces comprendo que se encuentre muy cansada de los recursos y de la convivencia. Dentro de que haya pedido el alta, se encuentra coherente y es consciente de las consecuencias, distingue lo que le hace bien de lo que no (consumo de sustancias). Te lo comento en caso de que efectivamente decida firmarlo, en cuyo caso le adjuntaré el documento. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-11-09','-Amalia : escribo a Mayte y Eva de sección salud mental .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2022-11-09','Ana: Llamada de Paz Boticario, TS Cruz Blanca (927 24 68 52): la vivienda familiar de los padres de Alberto se incendió este verano (C/ Gía Plata - CC), saben que a los padres los ingresaron en un centro por emergencia social, pero no saben en cuál. Con el padre apenas tiene relación, pero con la madre tenía un contacto periódico, "es un amor" y a Alberto le viene muy bien estas llamadas. De hecho ahora está preocupado por su madre y no sabe dónde está. ··································································································································································································· Hablo con Noelia, Aux. Secc. Mayores D-Gerencia (924 00 84 90), me informa que sus padres (Orenza Iglesias Glez. y Máximo Molano Campos) ingresaron en julio por emergencia social en la Res. de Valdemorales. La directora se llama Fátima. ·········· Se lo comunico a Paz. ············· Quien establece contacto con la residencia, mañana mismo podrán hablar Alberto y su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CASADO'and apellido2='CARRION'),'2022-11-08','Ana: Llamada de Mariví Clemente, TS CCS-Plas (24142): el familiar que tenía asumido el cargo de Antonia ha fallecido. Han nombrado a la CTAEX como Curatela Representativa "para todas las esferas". Aquí aún no hemos recibido dicha sentencia. Una vez recibida hay 20 días para que adquiera firmeza y después habrán de enviarnos esa firmeza para poder aceptar el cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='MERA'and apellido2='CRESPO'),'2022-11-09','Ana: Llamada de Mariví Clemente, TS CCS-Plas (24142): me comunica que ha fallecido su madre. *No tiene derecho a P. Orfandad, pues su madre percibía una PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-11-09','Ana: Llamada de Minerva, TS del CR Cervantes (22237): Le ha llamado Charo, TS del C. Penitenciario de CC (927 18 14 07), comunicando que Carolina, hija de Mª Luisa, está allí ingresada. Quiere establecer contactos telefónicos con su madre y próximamente tiene un permiso de salida, le gustaría pasar a verla. ······················ Lo hablo con Maite, Jefa de Secc., tanto ella como Minerva como yo, consideramos que este contacto no es bueno para Mª Luisa, no le beneficia y suele desestabilizarse cada que contactan. ··································································································································································································· Llamo a Charo, TS del C. Penitenciario de CC (927 18 14 07): Carolina está más estable, presenta buena conducta y actualmente no consume, cuando salga de permiso pernoctará en el Centro de Acogida Temporal de Cáritas, donde residía de forma previa a su ingreso. No tienen otro sitio donde ir ni más apoyos. Su pareja también está ahora en prisión. ······· La fecha de excarcelación es enero de 2023 (sólo han sido 6 meses de condena). ·········· Le comunico la decisión tomada, pero no nos cerramos a que cuando vuelta a estar en libertad, si hay informes favorables del recurso en el que esté, se pueda probar el contacto y si fuera bien mantenerlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2022-11-09','Ana: Remito, a Cristina, Ed. Asoc. Vera, Autorización para la participación en la Charla formativa sobre Ed. Sexual firmada digitalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2022-11-09','Ana: Remito, a Cristina, Ed. Asoc. Vera, Autorización para la participación en la Charla formativa sobre Ed. Sexual firmada digitalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-11-09','Ana: Remito Autorización para la participación en la Charla formativa sobre Ed. Sexual firmada digitalmente.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-11-09','Ana: Remito, a Cristina, Ed. Asoc. Vera, Autorización para la participación en la Charla formativa sobre Ed. Sexual firmada digitalmente. ································································································································································································· Conversación con Cristina, Ed. Vera (681 14 39 11): comunica nueva incidencia de Adrián. Junto con otro compañero, ha insultado, agredido (collejas continuadas) y propinado trato vejatorio a otro residente, Domingo, de 85 años. Aprovecharon cuando no había monitores presentes por estar atendiendo otras cuestiones. *Han cursado denuncia. *A pesar de estar gravado en las cámaras, él lo niega todo.·········· Tiene a tod@s l@s residentes amenazados y amedrentados. ················· *A parte de esto tienen sospechas de que está robando (pequeños hurtos) en el supermercado Día, pero no lo pueden demostrar. *Hablarán con los trabajadores del mismo para pedir que estén pendiente y si los pillas que avisen directamente a la policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-08','Ana: Llamada de José Manuel, dice que quiere cambiar de Cáterin, pues el de ahora no le gusta. *Le recuerdo que fue él el que quería cambiarlo, pues además era gratuito. *Le digo que tiene el servicio hasta 31 de diciembre, se valorará el cambio para enero. ············ En cuanto a los centros, reitera que prefiere el Centro de Día a Revital. Le digo que esto ya está hablado, cuando le valoren de Dependencia se solicitarán ambas cosas, pues para el centro de día hay lista de espera. ····································································································································································································· Llamada de Pilar Martín (54612): dice que le ha llamado José Manuel diciendo que quieren que le lleven al CSS de Plasencia y que si no se va a cortar el cuello. *Cuando le dice que va a comunicarlo a la Enfermera, dice que no, que le llevarían al Hptal de CC y él quiere ir a Plasencia. ·················· Igualmente lo ha comunicado. La Enfermera, Cristina, ha dicho que le iba a llamar. ········ Pilar me informa que le han cambiado el tto. farmacológico el día 24/10, a petición de él mismo, por "mala tolerancia". ············· El Psiquiatra es Enrique Goenaga. ············ Las próximas citas programadas que le constan son : Enfermería de ESM el día 22/11 a las 9:00 h. ·· Enfermería C. Salud A. Primaria el día 16/12 a las 8:30 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-09','Ana: Llamada de Lourdes, TS del IMAS (927 21 23 35): Les ha llamado la Aux. de SAD comunicando que de Jose Manuel decía que se quería tirar por la ventana. *No ha acudido a la cita que tenía hoy programada. *Le habían avisado de que podía ir a las 9 h con el Psiquiatra. ······ Finalmente la Aux. ha conseguido que se calmara y le va a acompañar al ESM. ······················ Llamo al ESM, Pilar Martín no está en este momento, pero volverá más tarde. En centralita me comunican que el Dr. Goenaga está atendiendo, no obstante se lo comunicarán para que le atienda. ················· Hablo con José Manuel cuando iba de camino para el ESM, dice que no acudió a la cita porque tenía que ir la Aux. de SAD. Le digo que al igual que ahora podría habérselo dicho nada más llegar para que le acompañara. ········ Pide que de nuevo se le cambie la Educadora de Futuex (lo cuál no viene al caso con su supuesta ideación autolítica). Le digo que ya hablaremos de eso en otro momento. ·············· Intento contactar con Pilar Martín a final de la mañana (54612) sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-11-10','Ana: Respuesta a Paula, TO, al correo de ayer: "Muchas gracias a vosotras, por la pronta respuesta y sobre todo por vuestra intervención e implicación. Sabiendo que ya habéis hablado con él al respecto de todos estos asuntos, de momento no vamos a decirle mucho más, simplemente reiterarnos en lo que estáis trabajando con él y ante la duda le remitimos a vosotras. No obstante, si en algún momento lo consideráis necesario, podemos fijar un día y hora que os venga bien y tener una llamada conjunta." ··································································································································································································· Nuevo correo de Ceferino pidiendo en esta ocasión una X-Box, pantalla de ordenador y el juego Fifa. ·········· No le contestamos y lo reenvío al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-11-10','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Adjunto envío Informe de la última incidencia de D. Adrián Ortigosa Fuentes junto con la denuncia, parte de lesiones e incidencia." La persona agredida presenta contusiones en codo y pelvis. Guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='FERNANDEZ'),'2022-11-10','TERESA ARCHIVO RESOLUCION INCLUSION EN EL PROGRAMA PARA PACIENTES CON NECESIDADES ASISTENCIALES ESPECIALES EN EL AMBITO DEL SISTEMA SANITARIO PUBLICO DE EXTREMADURA','2');
