insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-11-10','Ana: Aurora Balaguer, Aux. Admvo. del ESM-CC (aurora.balaguer@salud-juntaex.es) me remite por mail el Informe de Psiquiatría solicitado: Saturnino no ha asistido ni a la cita programada de agosto ni a la de septiembre. ············ Se lo reenvío a Miguel, A. Jurídico CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-11-10','Ángel: En relacion con el procedimiento de revisión de medidas judiciales acordadas, enviamos al Juzgado de Primera Instancia e Instrucción, nº 2, de Montijo (Badajoz), Informe de parientes y prueba a practicar. Lo lleva Curro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2022-11-10','Ángel: En relacion con el procedimiento de revisión de medidas judiciales acordadas, enviamos alegaciones al Juzgado de Primera Instancia e Instrucción, nº 1, de Villanueva de la Serena (Badajoz). Lo lleva Curro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-11-10','miguel, Ana la Ts me remite informe médico que acredita que no asiste a las revisiones y citas médicas desde hace meses. Hablo con la abogada Carmen Lucas y me comenta que necesita un informe en que basar la petición de inimputación (tal como le ha pedido la oficina del Defensor del Pueblo) Envío email a la parte social Ana y Maite: Buenos dias, me comenta la abogada que independientemente de que no haya ido a las revisiones que intentéis conseguir un informe de algún médico que le haya tratado que acredite que tiene las capacidades muy mermadas para intentar basar la inimputabilidad que está intentando, en el informe de calificación de la defensa que tiene que emitir. Dependiendo de vuestra respuesta comunicaré todo al Defensor del Pueblo, al nº2 CC (que conoce de nuestra solicitud de internamiento involuntario) y nº6 CC que esta conociendo de la causa penal por delito de violación. ******************************************************* Contestación de la parte social Ana y Maite: Hola, de nuevo, Miguel, Ya hice la solicitud de informe al Equipo de Salud Mental que lo atiende y lo que nos envían es esto. No le atienden más profesionales de salud mental y el diagnóstico y su trayectoria /evolución como paciente viene reflejados en dicho informe. Si ella quiere otro documento que lo solicite como abogada directamente. ********************************************************* Reenvío email de la parte social a la abogada Carmen Lucas: Buenas tardes, esta es la contestación que me ha remitido la Trabajadora Social. Me comentan que no pueden conseguir nada más. Entiendo que la patología queda acreditada en su certificado de discapacidad en el historial de problemas sociales que quedan acreditados en el intento de internamiento involuntario que se hizo en 2017. En cualquier caso desde la Comisión no podemos aportar nada más en este asunto. Adjunto por si pudiera servir certificado de discapacidad del cades y auto de internamiento involuntario del 2017. Entiendo que quien debe dictar la inimputabilidad llegados a este punto es el forense. Procedo como hemos hablado a enviar escrito a Defensor del pueblo al nº2 de Cáceres y el nº6 de Cáceres. ****************************************************** Contesto a la parte social: Ana, adjunto contestación que he hecho a la abogada…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-10','miguel, recibo email de registro civil de Don Benito: Buenos días. Le mandamos el certificado de esta persona por deferencia, porque ni siquiera está inscrito aquí, está en el Registro Civil de Guadalajara, si falta la inscripción deberían ponerse en contacto con dicho registro civil. ****************************************************** contesto: Buenos días, dicho registro de Guadalajara nos remitió al registro civil de Don Benito porque entiende que son incompetentes por ser el nombramiento de cargo de tutores en Don Benito, que además coincide con la residencia habitual de los tutelados. Por favor, indiquenos cómo proceder, no sé si sería posible que hablaran entre ambos registros o con el juzgado. **************************************************** envio email al rgtro civil de Guadalajara: Buenas tardes, siguiendo indicaciones del registro civil de Don Benito y teniendo en cuenta que por ley las tutelas deben estar inscritas en el certificado de nacimiento, entendemos que es este registro quién debe inscribir y remitirnos el certificado de nacimiento de Sergio Gil Sanz donde conste el cargo de tutor que ejerce la Comisión Tutelar de Adultos. Adjunto debajo contestación del registro civil de Don Benito Ruego nos lo remitan lo antes posible para poder firmar una ratificación de herencia en la notaria. Pueden remitírmelo a este email con firma electrónica o físicamente a la dirección: Servicio Extremeño de Promoción de la Autonomía Personal y Atención a la Dependencia (SEPAD) Comisión Tutelar de Adultos Avda de las Américas nº4, 06800, Mérida (Badajoz) ***************************************************** envío email a Teresa Muelas y Amelia: Buenos días, ayer me llegó físicamente los certificados de nacimiento de Raúl y Sergio. El de Raúl está correcto pero no viene inscrito el cargo de tutor de la Comisión Tutelar de Adultos de Sergio por lo que no he podido firmar todavía la ratificación. Tras hablar con el registro civil de Don Benito me insisten que tenía que ser el de Guadalajara (lugar de nacimiento de ambos) el que tenía que haberlo inscrito. Como veréis en los emails de debajo recibidos por el Registro civil de Don Benito, estos no lo van a inscribir, por lo que he vuelto a insistir al registro civil de Guadalajara, por si tuvieseis oportunidad de hablar alguna de vosotras en persona, a ser posible, con el registro civil de Guadalajara. Quedo a la espera de qué me contesta este registro civil de Guadalajara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-10','miguel, recibo email de registro civil de Don Benito: Buenos días. Le mandamos el certificado de esta persona por deferencia, porque ni siquiera está inscrito aquí, está en el Registro Civil de Guadalajara, si falta la inscripción deberían ponerse en contacto con dicho registro civil. ****************************************************** contesto: Buenos días, dicho registro de Guadalajara nos remitió al registro civil de Don Benito porque entiende que son incompetentes por ser el nombramiento de cargo de tutores en Don Benito, que además coincide con la residencia habitual de los tutelados. Por favor, indiquenos cómo proceder, no sé si sería posible que hablaran entre ambos registros o con el juzgado. **************************************************** envio email al rgtro civil de Guadalajara: Buenas tardes, siguiendo indicaciones del registro civil de Don Benito y teniendo en cuenta que por ley las tutelas deben estar inscritas en el certificado de nacimiento, entendemos que es este registro quién debe inscribir y remitirnos el certificado de nacimiento de Sergio Gil Sanz donde conste el cargo de tutor que ejerce la Comisión Tutelar de Adultos. Adjunto debajo contestación del registro civil de Don Benito Ruego nos lo remitan lo antes posible para poder firmar una ratificación de herencia en la notaria. Pueden remitírmelo a este email con firma electrónica o físicamente a la dirección: Servicio Extremeño de Promoción de la Autonomía Personal y Atención a la Dependencia (SEPAD) Comisión Tutelar de Adultos Avda de las Américas nº4, 06800, Mérida (Badajoz) ***************************************************** envío email a Teresa Muelas y Amelia: Buenos días, ayer me llegó físicamente los certificados de nacimiento de Raúl y Sergio. El de Raúl está correcto pero no viene inscrito el cargo de tutor de la Comisión Tutelar de Adultos de Sergio por lo que no he podido firmar todavía la ratificación. Tras hablar con el registro civil de Don Benito me insisten que tenía que ser el de Guadalajara (lugar de nacimiento de ambos) el que tenía que haberlo inscrito. Como veréis en los emails de debajo recibidos por el Registro civil de Don Benito, estos no lo van a inscribir, por lo que he vuelto a insistir al registro civil de Guadalajara, por si tuvieseis oportunidad de hablar alguna de vosotras en persona, a ser posible, con el registro civil de Guadalajara. Quedo a la espera de qué me contesta este registro civil de Guadalajara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='CARVAJAL'and apellido2='MORENO'),'2022-11-10','miguel, recibí ayer email de Jose luis de la notaria de Merida: Buenos días Miguel: Te va a llamar una paisana mía, que se llama Gori López Barrena, para tratar de tramitar una aceptación de herencia del marido fallecido en Mérida, y posterior venta de una casa en Calamonte propiedad de don Felipe Galán Custodio (fallecido) y su esposa doña Catalina Carvajal Moreno (curatelada por la Comisión Tutelar de Adultos). La historia es ir moviendo documentación en el Juzgado a los efectos de la aceptación de la herencia y la posterior venta del único inmueble que integra la herencia del fallecido. Muchas gracias. **************************************************** Recibo la llamada de Gregoria Lopez 607375727 cuyo hijo está interesado en la compra de la vivienda. Parece ser que han adelantado mucho dinero a la hija, y piensa que lo recuperaran con la venta de la vivienda. Tras comentarle los trámites que conlleva la operación (liquidación IS, aceptación, aprobación de herencia y autorización de venta), y ver el precio de valor fiscal de la vivienda 61.893,70€ (inscrita en catastro, dice que no en rgtro de la propiedad) y comentarle que hable con jose luis de la notaria para ver soluciones a recuperar el dinero dejado a la hija, ya que acaba de darse cuenta que la venta no cubre la deuda que tiene con ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-11-10','miguel, me escribe la TS Felisa Custodio Hernández: Buenos días, me pide la residente que le pregunte si se pueden iniciar acciones legales ante la ausencia de respuesta a la propuesta que se hizo el pasado 31 de marzo y que pueden leer más abajo. Muchas gracias. Saludos. ****************************************** mi contestación: Buenos días, el abogado AQUILINO CONDE BARBERO no se ha puesto en contacto con nosotros en ningún momento. No tengo teléfono de este abogado. Si es posible que Felisa hable con él y que nos conteste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-10','miguel, contestación del registro de guadalajara: Buenos días, la inscripción de una Tutela no se practica hasta que no se recibe un exhorto de un órgano judicial, tras la tramitación del procedimiento de jurisdicción voluntaria correspondiente. Si no aparece el nombramiento del cargo tutelar, deberán ponerse en contacto con el órgano judicial que hubiera tramitado el procedimiento. **************************************** envío email a Inés: Hola Inés, pon un oficio al juzgado de Don Benito de 1º instancia e instrucción nº1 del procedimiento finalizado Remoción del cargo de tutor nº 208/2020 con el siguiente contenido: “Adjunto remito solicitud para remitan con carácter urgente al registro civil de Guadalajara testimonio de firmeza, nombramiento y aceptación de cargo de tutor de la Comisión Tutelar de Adultos del tutelado Sergio Gil Sanz. Para lo cual adjunto dichos testimonios, y el certificado del registro civil de Don Benito, el cual se declara incompetente para dicha inscripción debido a que el competente es el del lugar de nacimiento del tutelado cuyo dni adjunto Haciéndoles constar la contestación del registro de Don Benito y de Guadalajara que adjuntamos. Reciban un cordial saludo.” En el siguiente email te adjunto los documentos a anexar en el envío vía Lexnet e imprime también ese segundo email que te envío para adjuntarlo también. ******************************** Envío email a Teresa Muelas y Amelia: Buenas tardes, procedemos a reenviar al juzgado de Don Benito para que les remita exhorto judicial requiriendo al registro de Guadalajara que proceda a la inscripción. Cuando esté inscrito y me envíen certificado de nacimiento procedere a firmar la ratificación de herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-11-10','Ana: correo de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "NOS DICE LA COMISIÓN DE VALORACIÓN QUE PREVIAMENTE A SU SOLICITUD DE CRR VAYA A COMUNIDAD TERAPÉUTICA. YA HE HABLADO CON LOS COMPAÑEROS DEL ECA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2022-11-10','Buenas , he hablado con el centro y efectivamente me dicen que el alta terapeútica fue el viernes día 4 y que ha vuelto a su domicilio en Miajadas . Esta señora sólo tiene curatela económica , no necesita más medidas de apoyo . Se le ha solicitado ayuda a domicilio y voy a solicitar a FUTUEX que la incluyan en el programa . Ana , cuando pase el proceso de adaptación , te lo paso . He pedido informe de alta , por si te viene bien Angel , te lo paso . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-11-10','miguel, contestación del abogado AQUILINO CONDE BARBERO >acondebarbero@condefuentetajaabogados.es> Buenos días, reviso nuevamente el expediente, pues lo último que recuerdo es que mandaron un informe pericial sobre el valor de la vivienda, que comunique al Abogado, pero no tengo respuesta. Reinició la comunicación con el Abogado de las hijas. Un saludo. AQUILINO CONDE BARBERO BUFETE DE ABOGADOS - CONDE&FUENTETAJA C/ LOS COCHES, 7 – 4ºB – 40002 SEGOVIA Tlfno. 921 44 10 91 - Fax 921 44 11 85','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-11-10','miguel, contestación del abogado AQUILINO CONDE BARBERO >acondebarbero@condefuentetajaabogados.es> Buenos días, reviso nuevamente el expediente, pues lo último que recuerdo es que mandaron un informe pericial sobre el valor de la vivienda, que comunique al Abogado, pero no tengo respuesta. Reinició la comunicación con el Abogado de las hijas. Un saludo. AQUILINO CONDE BARBERO BUFETE DE ABOGADOS - CONDE&FUENTETAJA C/ LOS COCHES, 7 – 4ºB – 40002 SEGOVIA Tlfno. 921 44 10 91 - Fax 921 44 11 85 ******************************************** reenvio email a la trabajadora social de alcuescar trabajadora_social_alcuescar@imserso.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='CARNERERO'and apellido2='CARRILLO'),'2022-11-10','Ana: Remito a Rosa Bravo, CSS (): Consentimiento Informado para Colonoscopia-Ileoscopia, firmado y sellado por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-10','Ana: Tras valorarlo con Maite, Jefa de secc., envío correo-respuesta al CRR: "Para la asistencia de Julia a la visita de su hermano, que entendemos valorías como positiva para ella, tendría que aportar la parte proporcional de sus gastos (tanto de transporte como de alojamiento) lo cual ascendería a 200€ apróx. Puesto que en su cuenta tiene poco saldo y al hermano también le viene bien su visita, nuestra idea es proponer a la sección económica que ella aporte 150€ a los fines especificados y que su hermano le ponga el resto. En cuanto a sus gastos personales, debería asumirlo con su asignación mensual (no sé cuánto le queda para este mes). Decirnos como lo veis y si os parece bien lo planteamos a la sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-08','ana: Correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "Buenos días, os escribimos en relación a Julia Morón. Hemos hablado tanto con ella como con su familia porque van a realizar una visita a su hermano que permanece en un centro en Arévalo. Creo que, al menos antes, también era tutelado vuestro. El caso es que nos dicen que él pagaría todos los gastos de la visita (tanto el viaje como hotel y comida) y que serían tres noches. Si por vuestra parte no hay problema Julia realizaría esta salida. Necesitamos que nos confirméis vuestro consentimiento para la salida así como si ella tiene que pagar o no alguna cantidad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-11','miguel, recibo email de Amelia: De acuerdo, entiendo que ya no hace falta que me ponga en contacto con el registro Civil de Guadalajara ya que el juzgado de Don Benito les mandará exhorto judicial para que lo inscriba... Estamos en contacto ********************************************* contesto: Buenos días, correcto, esperemos que sean ágiles y rápidos. La pena es el tiempo perdido en pasarse la pelota de un registro al otro. En cuanto tenga el certificado de nacimiento con la inscripción firmaré la ratificación y os avisaré. Ya tengo los poderes de procuradores para continuar con el trámite con Teresa Muelas ante el juzgado de Don Benito para la aprobación de herencia y autorización de venta. Esto deberá esperar hasta ratificar la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-11','miguel, recibo email de Amelia: De acuerdo, entiendo que ya no hace falta que me ponga en contacto con el registro Civil de Guadalajara ya que el juzgado de Don Benito les mandará exhorto judicial para que lo inscriba... Estamos en contacto ********************************************* contesto: Buenos días, correcto, esperemos que sean ágiles y rápidos. La pena es el tiempo perdido en pasarse la pelota de un registro al otro. En cuanto tenga el certificado de nacimiento con la inscripción firmaré la ratificación y os avisaré. Ya tengo los poderes de procuradores para continuar con el trámite con Teresa Muelas ante el juzgado de Don Benito para la aprobación de herencia y autorización de venta. Esto deberá esperar hasta ratificar la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-11-11','miguel, envío email al notario de Coria andresdiego@notariado.org Buenos días conforme conversación telefónica de esta semana adjunto las resoluciones judiciales de nombramiento y aceptación de cargo de tutor a esta Ctaex de los hermanos Esteban Iglesias, junto con los datos de representación del representante de la Ctaex, el actual Gerente del SEPAD, D. José Vicente Granado Granado, y la correspondientes autorizaciones de este en mi persona para poder firmar la ratificación de la Escritura Pública de aceptación y adjudicación de Herencia Testada firmada en Coria (Cáceres) ante el notario de Coria, Don Andrés Diego Pacheco el 24-1-2019, con número de protocolo 98. Necesito me confirme que todo está correcto para pedir cita allí (1 semana después de dicha confirmación) y acercarme a firmarla.','2');
