insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-11-11','miguel, envío email al notario de Coria andresdiego@notariado.org Buenos días conforme conversación telefónica de esta semana adjunto las resoluciones judiciales de nombramiento y aceptación de cargo de tutor a esta Ctaex de los hermanos Esteban Iglesias, junto con los datos de representación del representante de la Ctaex, el actual Gerente del SEPAD, D. José Vicente Granado Granado, y la correspondientes autorizaciones de este en mi persona para poder firmar la ratificación de la Escritura Pública de aceptación y adjudicación de Herencia Testada firmada en Coria (Cáceres) ante el notario de Coria, Don Andrés Diego Pacheco el 24-1-2019, con número de protocolo 98. Necesito me confirme que todo está correcto para pedir cita allí (1 semana después de dicha confirmación) y acercarme a firmarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-11','TERESA Hoy se recibe una llamada de Barto, comenta que este es su nuevo número(673 48 60 21) , que se ha cambiado de compañía. Se le escucha tranquilo y se expresa correctamente. Comenta que el día 15 de este mes tiene cita en salud mental (con el doctor Eduardo) y que hay que acompañarlo, se queda con él a las nueve y media en su casa el martes para ir andando al centro de salud. Se le comenta que el lunes le llamamos para confirmar pero insiste en que no le llamemos, que nos veamos el martes a esa hora cómo nos ha dicho e insiste en que le acompañemos. (aprovechamos para ir con el claro) Según lo que se tiene apuntado y ya se habló con Barto en anteriores visitas, la cita de salud mental es para el día 15 de diciembre, se le ha dicho pero insiste en que es en noviembre. No se le insiste más ya que puede ser una muy buena oportunidad para que lo vean en salud mental aunque no le corresponda la cita para ese día. Se ha estado llamando a salud mental para comunicarlo pero no han cogido el teléfono, se seguirá intentando. Le preguntamos cómo está y afirma que se encuentra bien, que por la noche duerme bien, que se está alimentando bien y que tiene de todo en casa para comer. Se le pregunta por la medicación y asegura que se la está tomando (solo transilium). Le comentamos que si ha ido a ver a María (enfermera de salud mental) para hacer una visita, comenta que no, que hablo con ella por teléfono, nos lo dice de buenas maneras pero un poco irritado, no se le insiste más. Le preguntamos que qué tal con el tema del calentador y asegura que lo quitó porque no funcionaba bien y perdía mucha agua, que un amigo suyo va a ir a arreglarle este tema, que no quiere que la Junta le arregle nada. Se le pregunta por Elkin y comenta que con él muy bien. Se ha llamado a Antonia Morán (TS de SSB) para comentarle la información y trabajar en la misma dirección. Unas horas después se recibe una llamada de María (de la empresa Servicios Sociosanitarios San Judas) comenta que ha ido con el fontanero a casa de Barto y que lo ha notado calmado, bien es cierto que sigue con las ideas delirantes pero por lo que cuenta María parece estar tranquilo y expresarme más coherentemente. Explica que no han podido hacer nada en casa de Barto porque él no quiere, les ha contado que va a comprar un calentador pequeño de 30l y un amigo suyo se lo va a instalar. María no ha insistido más y le ha preguntado cómo se encontraba y si tomaba la medicación, Barto le ha dicho lo mismo que a nosotros, que está bien y que se está tomando transilium. María comenta que no emite ninguna factura porque no han hecho nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-11-11','Buenos días, Agradecería se nos informara del procedimiento que contempla la Comision tutelar como tutelar de Nemesia García Paniagua para la remisión de la sentencia a Raquel Rodriguez Barrios, como parte interesada, Gracias y reciba un cordial saludo, CARMEN GONZÁLEZ NEVADO CIMAG','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2022-11-11','Email de CARMEN GONZALEZ >cgn@cecimag.onmicrosoft.com> Buenos días, Agradecería se nos informara del procedimiento que contempla la Comision tutelar como tutelar de Nemesia García Paniagua para la remisión de la sentencia a Raquel Rodriguez Barrios, como parte interesada Gracias y reciba un cordial saludo, CARMEN GONZÁLEZ NEVADO CIMAG **************************************************** mi contestación Buenos días, el procedimiento por el que se nombró a la Comisión Tutelar de Adultos fue el procedimiento de incapacitación 426/2009 del juzgado de 1º instancia e instrucción nº2 de Plasencia. ***************************************************** nuevo email de CARMEN GONZALEZ >cgn@cecimag.onmicrosoft.com> Buenos días de nuevo, La sentencia a la que me haces referencia es en la que Virgilia Barrios renuncia a la tutela y se nombra a la junta como tutela de Nemesia García, sin embargo en esa sentencia se hace referencia a otro procedimiento por el que se dictó sentencia de incapacidad parcial a nombre de Nemesia el día 11 de marzo de 2010 (como imagino que vosotros tenéis copia de la sentencia con número de procedimiento 426/2009, lo podéis comprobar en los antecedentes de hecho), de esta última sentencia es de la que no disponemos de número de procedimiento ni juzgado ni nada y es en esa donde debe especificarse el control que se hace respecto a las cuentas bancarias. Gracias por toda la colaboración, CARMEN GONZÁLEZ NEVADO CIMAG ********************************************************** mi contestación: Buenas tardes, no disponemos de más información que podamos facilitarles. Pueden solicitar un certificado de nacimiento al registro civil o directamente al juzgado de 1º instancia e instrucción nº2 del juzgado de Plasencia donde al margen del mismo les indicarán los datos que solicitan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-11-11','TERESA Buenos días, ya hemos tenido el juicio. Van a solicitar una evaluación del forense y recopilar los datos de la incapacitación. Estamos a la espera de la nueva citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='VARGAS'and apellido2='SUAREZ'),'2022-11-11','TERESA ARCHIVO RESOLUCION SOLICITUD DE INCLUSION EN EL PROGRAMA PARA PACIENTES CON NECESITAS ASISTENCIALES ESPECIALES EN EL AMBITO DEL SISTEMA SANTARIO PUBLICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='FERNANDEZ'and apellido2='CALDERON'),'2022-11-11','TERESA TERESA ARCHIVO RESOLUCION SOLICITUD DE INCLUSION EN EL PROGRAMA PARA PACIENTES CON NECESITAS ASISTENCIALES ESPECIALES EN EL AMBITO DEL SISTEMA SANTARIO PUBLICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-11-11','TERESA TERESA ARCHIVO RESOLUCION SOLICITUD DE INCLUSION EN EL PROGRAMA PARA PACIENTES CON NECESITAS ASISTENCIALES ESPECIALES EN EL AMBITO DEL SISTEMA SANTARIO PUBLICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-11-11','Ana: Correo de Felisa Custodio, TS del CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): "Buenos días, la residente y tutelada Esther García Martín tiene consulta en maxi facial en Badajoz, hemos visto la sentencia y necesita consentimiento de tratamiento médico y/o intervención jurídica. Tienen la mala costumbre de facilitar este documento en el momento, he buscado pero yo no tengo modelos, a ver si me lo podéis mandar, si tienes, ya firmado para que no vaya a la consulta en valde, ya que me dice que posiblemente le tengan que extraer piezas dentales." ······················ Mi respuesta: "Pues me temo que no tenemos modelos. Nos suelen enviar el específico del servicio y hospital en cuestión con los datos de la persona concreta. Si tuvieseis el teléfono del servicio, podríais llamarle para que nos lo envíen directamente desde el hospital. Podéis facilitarle mi dirección de email sin problemas. Es la opción que se me ocurre más factible y rápida."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-14','Ana: Remito a registro, Oficina de Atención al Ciudadano (oac.merida.san@juntaex.es) solicitud de PNC, junto a la documentación pertinente. ·················· Entrego a los compañeros de secc. ecca., Modelo de Alta de Terceros para que los lleven al banco cuando vayan y así tenerlo cuando nos lo soliciten de PNC. ····················· Guardo el Justificante del Registro SIREX en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-14','Ana: Llamada de José Manuel (627 788 797): dice "el viernes me dio un impulso y saqué 400€ del banco", fue a otra oficina de Unicaja, no a la habitual. Se ha gastado todo el dinero en un móvil Siaomi 11 Note, un cristal templado, tarjeta de memoria de 128 GB, una funda y un altavoz. ················ Le digo que de entrada ya no puede pedir nada más para Navidad ni Reyes. Y que se lo comunicaré a Alberto, Jefe de Secc. Ecca. por si él estima algo más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-14','TERESA EMAIL TRABAJADO SOCIAL JOSE JULIAN Buenos días !!! He vuelto , hoy voy a ver a José , ya me han dicho que puede entrar en la residencia , vamos a preparar las ropa y oras cosillas , te voy contando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='LOPEZ'and apellido2='PILARES'),'2022-11-14','TERESA ENVIO SOLICITUD DE DEPENDENCIA PARA REVISION POR EMPEORAMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-11-14','TERESA ARCHIVO RESOLUCION DENEGATORIA DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-11-14','Ana: Remito a registro, Oficina de Atención al Ciudadano (oac.merida.san@juntaex.es) solicitud de Modificación de Datos Bancarios de la pensión de jubilación, para remitir a la Dirección Provincial del INSS-CC. ············· Guardo Justificante de entrada del Registro SIR. ·································································································································································································· Según Informe Social de Cruz Carmen Merino Vila, TS de la Mancomunidad Tajo-Salor: la situación que motivó su intervención y la puesta en conocimiento de Fiscalía, continúa igual. En la última visita realizada, Juan Gregorio estaba solo y presentaba aspecto sucio, desaliñado y desorientado. ············ Tiene permiso de conducir, pues en su vida laboral se dedicaba a la conducción de camiones, pero ahora mismo no tiene coche y tampoco sabe dónde está su carné. ············· Tenía Seguro de Decesos en Santa Lucía, pero aunque tenía domiciliado el pago, el hijo devolvía los recibos cuando se los pasaban.·········· La propuesta de la TS es la del Ingreso en la Residencia de Mayores de Alcántara, para que pueda tener cubiertas de forma adecuada todas sus necesidades y no se produzca un desarraigo de su localidad. ····························································Consulta SIDEX: Grado I de Dependencia. Expediente inactivo. Nunca ha recibido ninguna prestación ni de servicio ni ecca. Se negoció SAD, pero no aceptó el PIA. ········ Al parecer no quería cambiar a la Aux. que tenía con el SAD Municipal. ···································································································································································································· Llamo a Cruz Carmen Merino, TS Mancomunidad Tajo Salor (927 271 890): Considera necesario su ingreso, pero por Emergencia Social, vía Decreto, no se podría elegir centro y cree que sería contraproducente llevarle a otro centro fuera del pueblo. ······· Hace año y medio que falleció María, su mujer, y todavía de vez en cuanto acude a la residencia del pueblo, donde residía, a preguntar por ella y verla. Tiene momentos de más lucidez. En principio no se opone al ingreso. *Hay una vecina que de vez en cuanto le lava la ropa y está pendiente de él, quizá se podría contar con su apoyo de cara al ingreso. ················· Tuvo SAD municipal, pero llegó un momento en que NO dejaba entrar a la Aux. y tuvieron que dar de baja el servicio. ·············· El hijo no se ha presentado a las citaciones del Juzgado. Ha estado retirando el dinero de la cuenta Juan G. para fines distintos al de la atención a su padre. En numerosas ocasiones ha dejado la cuenta sin dinero. ····························· *Cruz acudirá a visitarlo de nuevo y me enviará la solicitud de centro para la firma y el Informe Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2022-11-14','Ana: correo de Ivonne, Directora Res. (direccionspa@valenciadealcantara.es): "Buenos días Lamento comunicar el fallecimiento con fecha 12 de noviembre 2022 de ROSA GOMEZ NEVADO" ····························································································································································································· Correo de Toni-Futuex: "El sábado 12, contacta la directora de la residencia donde se encontraba Rosa Gómez para comunicar que la tutelada había fallecido. Parece ser que fue todo bastante rápido, comenzó como con una infección de orina, se fue quedando como apagadita hasta que se quedó del todo. Yvonne comenta que en el informe de fallecimiento, el médico, indicó muerte natural. Suponemos os lo hará llegar. El funeral se llevó a cabo el domingo por la mañana, gestionaron tras averiguar el tema de la póliza de decesos que tenía Rosa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-14','TERESA ENVIO EMAIL A GESTION ECONONOMICA DE DEPENDENCIA CON LA DOCUMENTACION QUE ME HA PROPORICIONADO LA EMPRESA EN LA QUE COMUNICA LA BAJA DEL SERVICO CON FECHA 28 DE ABRIL PARA GESIONAR COBRO INDEBIDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-11-11','Ana: Nuevo expediente. Según sentencia: "JUAN GREGORIO tiene afectadas sus funciones cognitivas y volitivas en tal grado que le imposibilita para el gobierno de su persona y bienes.". "Nombro a la COMISIÓN TUTELAR DE ADULTOS, CURADOR CON CAPACIDADES ASISTENCIALES Y REPRESENTATIVAS de D. JUAN GREGORIO LOZANO VALLE, debiendo prestarle asistencia para para poder atender y proveer sus propias necesidades básicas diarias, como alimentación, aseo y vestido, y representarle para la toma de decisiones personales de la vida independiente, y todo lo contenido en el ámbito de la administración y disposición de bienes, en los actos que impliquen habilidades económicas, jurídicas o administrativas, para tomar decisiones de contenido económico, para realizar disposiciones testamentarias, donaciones o contratos, otorgar poderes, contraer obligaciones, para la realización de cualquier gestión ordinaria de su patrimonio, realizar pagos, efectuar disposiciones de dinero en efectivo o de otra forma, o para manejar cantidades de dinero de cualquier cuantía... y asimismo habrá de representarle para la toma de decisiones en lo relativo al ámbito de la salud... manejo y toma de medicamentos, seguimiento de tratamientos médicos o farmacológicos, decisión respecto de los tratamientos médicos necesarios, intervenciones quirúrgicas, pruebas diagnósticas, pautas alimenticias y en todo lo relacionado con la información sanitaria y prestación del consentimiento informado en materia de salud." ················· La Sentencia también AUTORIZA EL INTERNAMIENTO EN CENTRO ADECUADO en el Razonamiento Jurídico SEGUNDO, página 5: "...del informe forense antes aludido, se infiere que necesita vivir en un ambiente protegido, por lo que se estima procedente autorizar, por si fuera necesario, su internamiento en centro adecuado para el tratamiento de su patología."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-03-22','miguel, recibo email de la empresa que presta servicio a domicilio(Carmen Tello):Buenos días Miguel, adjunto te envio documento emitido por la Agencia Tributaria en el que figura que la deuda que te están reclamando está pagada, de todas formas, como ya te comenté, desde diciembre Felipe no tiene relación con Fernando Bravo ya que es la empresa la que factura, dime cómo realizaríais el pago de la factura de Febrero En espera de tu respuesta ************************************************** Remito email a Alberto y Oscar: En relación al tutelado Felipe Rodriguez Solis hay que reactivar el pago permanente de ayuda a domicilio. Paso a comunicar a AEAT la reactivación del pago debido a que justifica le empresa que ya está al día de la deuda, además de que no deberíamos haberlo interrumpido porque la deuda es con otra sociedad perteneciente a la misma empresa (nuestras facturas no son a nombre de Fernando Bravo, quitando las facturas de octubre y noviembre, que se adjuntaron a la contestación a AEAT. Por tanto el deudor de AEAT no tiene relación con la empresa a la que nosotros pagamos, es decir a la beneficiaria de nuestros pagos, que es Servicios Asistenciales FBC SLU, y a la que hay que hacer los abonos que se venían haciendo con carácter permanente, y cuya reactivación deberá incluir este mes de marzo (puesto que AEAT no nos llegó a contestar y por tanto a AEAT no llegamos a abonarles nada…) Cualquier duda me decis. Procedo a comunicarlo a AEAT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-14','Ana: Conversación con Verónica, TS de Moraleja (927 51 50 75): Pilar nunca ha querido ingresar en residencia, pero ahora sí quiere. Las compañeras del Programa de Familias le han acompañado a visitar la Res. El Encinar de Vegaviana (municipio de la comarca de Sierra de Gata) que es en la que ella muestra más interés. Esta semana la acompañarán a la de Moraleja (Res. San Blas), confían en que ésta le guste más pues tiene más actividades y hay residentes más jóvenes. Ella tiene 56 años. La idea, es que por agilizar, ingrese en plaza privada, pues se lo puede permitir. Percibe una pensión de Incapacidad Permanente de 1.684,16 €. Los precios de las plazas son: 1.194,42€/mes en la de Moraleja y 1.034,74 en la de Vegaviana. ················ Está valorada con Grado II de Dependencia pero no tiene activo el expdte. *Le ofrecieron SAD en su día, pero no quería cambiar a la Aux. del SAD Municipal que percibía y que mantiene a día de hoy. ········ También tiene contratado un Serv. de Catering privado a la Res. de Moraleja, pero no le gusta la comida (puede que esto influya en la elección de centro). ·························· *En cuanto a su hijo, Jorge Santiago, está en Prisión. ············ *Pilar tiene miedo de que si ingresa en residencia, su hijo, que actualmente está empadronado en su domicilio, pudiera intentar vender la vivienda cuando ella no esté allí viviendo. Aunque le han explicado que él no puede hacer eso pues ella es propietaria al 100% de la misma, no se queda tranquila. *Verónica propone intentar dar de baja al hijo en el Padrón, hecho que tranquilizaría bastante a Pilar. ···························· Pilar NO tiene permiso de conducir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2022-11-15','TERESA En relación a la ayuda a domicilio municipal para Tomas informarte que la tuvo puesto hasta la sentencia de incapacitación dos horas a la semana pero estas resultaron insuficientes. Este servicio está montado del tal forma que no puedo ofertarle más horas. Como vecino de Zafra tiene la posibilidad de acceder a este servicio pero debe ir a lista de espera. Con respecto al grado de dependencia y su visita al médico para el informe de salud creo que es cuestión de persuasión e insistencia. Es tan vital como acudir a su psiquiatra para el control del tratamiento de la esquizofrenia que tiene abandonado. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-11-14','Ana: Correo de Ángela Bueno, Directora PLACEAT (directora@placeat.org): "Buenos dias, comentarte que el traslado de Cristofer a Montijo está previsto realizar el viernes 18, sería posible gestionarlo con un taxi , acompañado de personal de aquí, y pasaros la factura del mismo?" ··············· Pido a Ángela un presupuesto de taxi para que puedan valorarlo en la sección ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-11-15','TERESA Acabo de hablar con Aitor, lo he despertado jeje. Le he propuesto el tema de anular la alarma para poder entrar a por sus cosas y me asegura que ya ha dado de baja la alarma…. Habrá que ir a comprobarlo y si es así empaquetar y enviarle sus cosas, entre ellas dice que le mandemos la tele….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2022-11-15','TERESA ENVIO CORREO A FUTUEX PARA INICAR PLAN DE INTERVENCION Tras conversación con el trabajador social que lleva este usuario me comenta la necesidad de ayuda a domcilio ya que la casa esta en malas condiciones de higiene. Voy a solicitar revisión e grado por empeoramiento pues en su día fue valorado y no dio grado, para ello necesito el informe de salud de su medico de cabecera, necesito que la delegada pase por el centro de salud y lo solicite a la trabajadora social. Vamos a valorar contratar SAD de formar privada, para ello necesito que hagáis valoración económica para ver los gastos que tiene y asignarle dinero de bolsillo y ver así cuánto dinero nos queda para poder contratar el servicio. Me comenta también el trabajador social que no acude salud mental, es necesario retomar las consultas y tratamiento, por lo tanto también es necesario contactar con salud mental para retomar el seguimiento. Yo mientras tanto voy valorando con Alberto en función de lo movimientos que vemos en la cuenta. Me quedo a al espera de la información y del informe de salud para ir gestionando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2022-11-12','EXITUS El centro comunica su fallecimiento, acaecido el 12/11/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2022-11-14','Ana: Correo de Isabel Pino, TS Ayto. de Miajadas (ipino@miajadas.org): "HE HABLADO CON VANESSA Y ME DICE QUE SI HA RECIBIDO LA CITACIÓN."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INOCENCIO'and edp.apellido1='MARTINEZ'and apellido2='NOVAS'),'2022-11-15','TERESA RENDICION ANUAÑ INOCENCIO RESIDE EN EL CAMP DE PLASENCIA DESDE 1989, LA ADAPTACION AL CENTRO FUE COMPLICADA PERO A DIA DE HOY ESTA TOTALMENTE INTEGRADO PARTICIPANDO DE LA VIDA DEL CENTRO ACTIVAMENTE SOLO NECESITA SUPERVISION PARA EL ASEO SIENDO AUTONOMO PARA LAS ABVD SE DESCONOCE RELACION CON FAMILIARES PRECIBE UNA PNC 421,40€ AHORRO 13500€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2022-11-15','Ana: Llamada de Ivonne, Directora Res. (690 962 955): explica que fue una muerte natural no esperada. No ha sufrido. Se produjo en la misma residencia. ············ Se lo comunico a María, Secc. Ecca, de cara a la rendición final de cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-10','Ana: Según informe Social de Verónica, TS SSASB de Moraleja: "Pilar vive sola en su domicilio, según la documentación que obra en su expediente social tiene reconocido un grado del 66% de discapacidad con carácter definitivo desde el 26/02/2008; y un Grado II Nivel 2 de Dependencia desde el 31/01/2011.", "Tiene diagnosticado un trastorno bipolar Tipo II. Episodio de hipomanía. Desconocemos si este es el diagnóstico actual de la interesada, pero sí podemos informar que acude regularmente a consulta en la Unidad de Salud Mental de Coria, acompañada de la auxiliar del Servicio de Ayuda a Domicilio (en adelante SAD) de titularidad municipal", "No es capaz de organizar un menú que se adecue a sus necesidades nutricionales, y generalmente se sobrealimenta.", "sus limitaciones psíquicas y su sobrepeso la hacen totalmente dependiente para la realización autónoma de su aseo personal. Es también dependiente para cualquier actividad relacionada con la higiene doméstica", así como para el tratamiento médico y pauta de medicación. ········ Tiene dos hijos, Jorge, quien ha tenido varias órdenes de alejamiento de su madre por agresión y Beatriz, que reside en Londres.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-10','Ana: Según informe Social de Verónica, TS SSASB de Moraleja: "Pilar vive sola en su domicilio, según la documentación que obra en su expediente social tiene reconocido un grado del 66% de discapacidad con carácter definitivo desde el 26/02/2008; y un Grado II Nivel 2 de Dependencia desde el 31/01/2011.", "Tiene diagnosticado un trastorno bipolar Tipo II. Episodio de hipomanía. Desconocemos si este es el diagnóstico actual de la interesada, pero sí podemos informar que acude regularmente a consulta en la Unidad de Salud Mental de Coria, acompañada de la auxiliar del Servicio de Ayuda a Domicilio (en adelante SAD) de titularidad municipal", "No es capaz de organizar un menú que se adecue a sus necesidades nutricionales, y generalmente se sobrealimenta.", "sus limitaciones psíquicas y su sobrepeso la hacen totalmente dependiente para la realización autónoma de su aseo personal. Es también dependiente para cualquier actividad relacionada con la higiene doméstica", así como para el tratamiento médico y pauta de medicación. ········ Tiene dos hijos, Jorge, quien ha tenido varias órdenes de alejamiento de su madre por agresión y Beatriz, que reside en Londres. ·············· Recibe el SAD y atención por el PAF, desde el que se coordinan periódicamente con el ESM de Coria. También tiene Serv. de Catering privado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-15','Ana: Envío correo a Alberto, Jefe secc. ecca, con copia a Maite y Óscar: "Tras haber leído el inventario e informe, haber hablado con la TS de referencia y valorado la situación, nos planteamos el ingreso de PILAR DIEZ SANTIAGO en centro residencial, a lo que Pilar se muestra dispuesta. *Puesto que sólo tiene reconocido Grado II de Dependencia y sus ingresos son elevados, por la vía de Dependencia tardarían bastante en darle plaza. Por tanto, planteamos su ingreso en plaza privada solicitando a posteriori la Prestación Económica Vinculada al Servicio (le corresponderá el mínimo, supongo, pero es una ayuda). La cuestión que queremos plantearte es la económica, como puedes ver en el inventario tiene: - Pensión de Incapacidad Permanente Absoluta: 1.684,16 € x 14 - Dos préstamos bancarios (preconcebido = 1.634,04 € y al consumo = 3.428,10 € ) - A fecha de inventario 212,74 € en su cuenta de ahorro - Plan de Pensiones: 8.034,94 €, que según el informe social se podría rescatar en cualquier momento si fuera necesario *El coste de las residencias que contempla son: - 1.194,42 € la de su pueblo - 1.034, 74 € la de otra localidad cercana Cuando podáis, valorar la posibilidad porfa, pues, cuando se decida, la idea es formalizar la solicitud, pero quiero que me confirméis antes que no hay problema en ello."','2');
