insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-11-15','Ángel: Se celebra hoy la vista en el Juzgado de Primera Instancia, nº 4, de Badajoz, procedimiento X15 AUTORIZ JUD DISP BS/D MEN/P DISCAP MED APOYO 0000570 /2022, en el que la hija pedía que Agustín le diera 10.000 euros. La Fiscal no se opone a lo solicitado por la hija, al disponer Agustín con dinero suficiente en cuenta (27.588,60 euros) con el límite máximo de 10.000 euros, para el caso que le supusiera abonar algún impuesto, como el de sucesiones/donaciones o irpf, que no es el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-11-15','Ana: Correo de Ángela Bueno, Directora PLACEAT, al ctutelar@: "A/A de la Sección económica Buenos dias El día 18 de Noviembre se realizará el traslado de CRISTOFER MONTERO MORENO desde la Residencia de Placeat en San Gil a Montijo, por cambio de servicio al Proyecto Piloto "MI Casa". Pedido presupuesto a un Taxista para realizar el mismo, irá acompañado de personal de Placeat, el coste asciende a 195€, cuando nos lo aceptéis y se haga efectivo el viaje enviaremos la factura del mismo para que se proceda a su pago." ················ Se autoriza el gasto por parte de la secc. ecca. y se lo confirman a Ángela.','2');
