insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-10-10','Ana: Correo de Ana Benavente, TS ESM-Plas. (anamaria.benavente@salud-juntaex.es): "Buenos días Ana: Respecto a Desideria Barbero Bueno la última vez que ha tenido cita presencial en el ESM ha sido el 1 de agosto con psiquiatría y enfermería. El 5 de septiembre la enfermera tiene una consulta telefónica. El 6 de septiembre acude acompañando a Ángel que era el que tenía la cita presencial a la consulta de enfermería. La próxima cita presencial con psiquiatría y enfermería es el 10 de noviembre. En la visita a domicilio ella misma pidió que no se adelantara. Nuestra enfermera está coordinándose con el enfermero del Centro de Salud de San Miguel para el control analítico. La psiquiatra es la Dra. María Jesús Gutiérrez y la enfermera Lourdes Berrocoso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-11-16','Ana: Puesto que desde el INSS, nos piden el Cdo. de Matrimonio para poder resolver sobre la solicitud de P. de Orfandad, pregunto a Toni-Futuex, si la TO o la TS del programa de apoyo comunitario han podido encontrarlo en las últimas visitas realizadas. ··············· No ha sido posible. ······· Intentarán contactar con el hermano de de Desi o la cuñada para preguntar dónde se casaron y poder solicitar el Cdo. al Registro Civil correspondiente. ·············································· *Toni-Futuex confirma que se casaron en Irún. ················ Solicito a Julio, Aux. Administrativo que solicite al Registro Civil de Irún el Cdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2022-11-16','TERESA ENVIO AUTORIZACION IMAGEN A PETICION DEL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-11-15','Ana: Correo del Programa de Familia (programafamilia@tajosalor.es): "Nos ha llamado la compañera de Fututex porque está de baja y había quedado con la empresa de limpieza para ir a la casa de Felisi el lunes y martes de la próxima semana. Nosotras no podremos acompañar a Felisi como pensaba hacer ella porque ya tenemos visitas y demás cerradas para esos días. Además pensamos que Felisi allí mientras le limpian la casa más que ayudar puede ponerse nerviosa y entorpecer pero claro, por otra parte, es su casa. No sé cómo podríamos hacerlo, a nosotras se nos ocurre, si te parece bien, que nos de Felisi la llave, se la llevamos a la empresa de limpieza y una vez terminen pasamos a recogerlas. Pero lo mismo creéis que Felisi debe estar en Navas mientras limpian…pero eso sí que no vamos a poder hacerlo, lo sentimos. Piénsalo y nos cuentas, vale?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-11-16','Ana: Envío correo-respuesta al Programa de Familia (programafamilia@tajosalor.es): "Yo creo que la mejor opción es la que planteáis, tanto para la propia Felisi como para los profesionales que se van a encargar de la limpieza. El “problema” vendría si ella se empeñara en estar presente, pues, entiendo, estaría en su derecho. En ese caso veríamos opciones, pero espero que no lo demande. Yo creo que si se le explica que es mejor para ella y sobre todo, que para que la empresa de limpieza pueda hacer bien su trabajo es mejor que no haya nadie por allí, lo aceptará. Por otra parte, quería pediros, que cuando le entreguéis la llave a los profesionales de la limpieza, le pidáis que la ropa de Aitor y Mirella, la metan en una caja o bolsas (lo que tengan) y lo dejen en el garaje, pues seguramente habrá que acabar enviándoselo todo. Y en relación a las cámaras, no sabemos si siguen funcionando. Sabemos que ya deben alguna mensualidad, pero no sabemos cuándo cortarán el servicio. Como sabéis, lo dieron de alta con una cuenta que abrió Aitor en otra entidad bancaria, a la cuál se han enviado escritos sin éxito… y en Movistar tampoco hemos conseguido que den de baja el servicio. *A una malas, creemos que se pueden tapar las cámaras para que puedan trabajar con intimidad. Lo que tememos es que vuelva a presentarse la Guardia Civil cuando acudan de la empresa de limpieza. Pero si se lo explicáis vosotras no creo que haya problema, no?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-11-16','Ángel: Se celebra hoy la comparecencia en el Juzgado de Montijo, relacionado con la revisión de la sentencia. Queda pendiente de resolución, en el sentido de quedar en una curatela representativa en el aspecto económico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-11-16','miguel, recibo email de Ana reenviando email de Toni de Futuex (Antonia Mª Rodriguez): Buenos dias Ana, que tal? Te hago llegar una cédula de requerimiento de pago de sanción del tutelado Juan Jose Gonzalez, creemos importante para las areas eco y jurídica, ha recibido ya varios requerimientos de pago por sanción. En el acompañamiento a la retirada de asignación, de hace unos dias, se revisan los movimientos para ver si se ha hecho la transferencia que se solicitaba desde el juzgado, por la sanción que se le impuso al tutelado, además, está algo intranquilo con ello por si no se paga en plazo; al hacerlo se comprueba que no se ha hecho dicha transferencia. La semana anterior Juan José facilita una notificación que ha recogido en el juzgado el viernes anterior, al ver la fecha, se le dice que le tiene que haber llegado antes pues es del día 10, se le hace hincapié en la importancia de pagar en tiempo y forma las sanciones que se le impusieron pues sino no puede dividir el pago. En esta ocasión se le requieren dos pagos de 180€ cada uno, el primero se tenía que hacer en 10 días desde la notificación, cumpliendo el día 25 si es en días hábiles (según creemos). Se adjunta escaneda, la cédula a este email. ************************************************* Contesto con copia a la parte social, Ana y parte económica Oscar y Alberto: Buenos días Oscar, necesito que la parte económica nos indiquéis cual es el saldo actual de la cuenta del tutelado Juan José González Carrero ya que hay que tramitar la herencia y la venta del inmueble. Por otro lado hay que abonar la dos multas del documento adjuntado por Ana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-11-15','Ana: Correo de Felisa Custodio, TS del CAMF (trabajadora_social_alcuescar@imserso.es): "os adjunto datos de interés que me traslada la residente Esther... "Ya tengo tarjeta de prepago es de Yoigo con 20 gigas y llamadas ilimitadas por 15 euros. Mi número es 633 92 26 06" ··············· Lo paso Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-17','TERESA José gonzalez Fernández ingresa hoy en la residencia de Medina de las torres , va en taxi , y le acompaña su hermano mayor Daniel. 682 83 72 36 Vanesa que es la gobernanta, la médico que se llama Estefanía','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-11-17','Ana: Correo de Sheila, Directora Técnica CRR-CC (crr@grupociudadjardin.com): "informarte de que Juan Mario San Román Blasco fue trasladado al sociosanitario de Plasencia en el día del lunes." ··················· Se lo comunico a Miguel, A. Jurídico - CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-11-17','Ana: Envío correo a Reyes, Seg. Social CC (reyes.picapiedra@seg-social.es): "Buenos días Reyes, En relación a la solicitud de P. de Viudedad, relativa a Dª. Desideria Barbero Bueno, cuyo cargo de Tutela ostenta la Comisión Tutelar de Adultos, hemos intentado conseguir el Certificado de Matrimonio a través de la propia Desideria sin éxito. Por ello, tras averiguar dónde se casaron, procedemos a solicitar al Registro Civil dicho certificado. En cuanto lo tengamos te lo hacemos llegar. Ante cualquier otra cuestión, no dudes en volver a contactar. Un saludo y buena mañana." ···························· Llamada de Reyes, Seg. Soc. (927 530 311): explica que justo hace 2 días revisó el expediente de incapacidad de Ángel, marido de Desi, y encontró copia del Libro de Familia. Lo ha remitido y han debido aceptarlo, pues le han reconocido la Pensión. ··································································································································································································· Llamada de Maite, cuñada de Desideria (943 11 61 93): Al parecer tiene pagos pendientes de una DERRAMA de la Comunidad. La reunión sobre ello tuvo lugar precisamente la semana anterior al fallecimiento de Ángel (marido de Desi). Habría que hablar con Raquel, vecina (648 61 98 93). ················· Lo comunico a las secc. jurídica y ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2022-09-22','Ana: llamada de Laura, TS del IMAS (927 21 23 35). Ayer tuvo una entrevista con Montaña. Dice que "está fatal". Intentó explicarle que está "incapacitada". No quiere facilitarle información sobre sus cuentas. ··········· Percibe una PNC de Invalidez. ······· Tiene reconocido un 65% de discapacidad por el CADEX. ············· Es usuaria del IMAS, pero es muy difícil de atender. ·········· Tiene una multa del Juzgado de 1.900 €, por la que tiene un embargo de 100€/mes. (*En principio la PNC es inembargable). Ella narra que la "violaron" y que tiene 2 hijos que dio en adopción. Según ella NO los tiene reconocidos. Tiene otro hijo mayor de unos 20 años apróx. *La familia nunca ha querido colaborar. ·············· Vive sola. ·· Padece un trastorno Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-17','TERESA VIAJE FAMILIAR VISITA • TAXI: 200 € QUE ABONA JOSÉ MARIA MORON (CONCEPTO: VISITA FAMILIAR) ------TERE: LE PASAS LA FACTURA A MARÍA PARA QUE LA ABONE • ALOJAMIENTO: 348 € QUE ABONA JOSÉ MARÍA MORÓN (CONCEPTO VISITA FAMILIAR) -------TERE: LE PASAS LA FACTURA A MARÍA PARA QUE LA ABONE • • GASTOS DE VIAJE: 150 € QUE ABONARÍA JULIA MORÓN  HACER TRANSFERENCIA DE 90 € A CCC DE JOSÉ MARÍA MORÓN (CONCEPTO: VISITA FAMILIAR A JOSE MARIA)  HACER REINTEGRO DE 60 € A JULIA MORÓN (EN SU CCC) (CONCEPTO: VISITA FAMILIAR A JOSE MARIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-09-29','Ana: Llamada de Pilar, sobrina de Mª Ángeles. El acompañamiento al M. Forense fue bien. Según Pilar, su tía iba contenta por el camino. Ignacio, el Forense, le hizo una serie de preguntas, entre otras si quería trasladarse a una residencia a CC más cerca de su sobrina y ella dijo que sí. *Pilar informó al Forense de las escaras que tenía su tía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-09-29','Ana: Llamada de Verónica, TS del Ayto. de Moraleja (927 90 11 14); me informa que esta semana ha llamado un Sr. Supuestamente Abogado del hijo, Jorge. *Su hijo quiere que le envíe dinero. ···· Su hijo es una personas muy violenta. Tiene una orden de alejamiento de su pareja también. ········ *Pilar NO quiere tener contacto con su hijo porque está aterrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-11-17','Ángel: En relación con el Internamiento Involuntario solicitado, el procedimiento (538/22) se está llevando en el Juzgado nº 6 de Cáceres. Han proveído el 2/11/22 dar traslado al Forense para que citen a Aitor y lo reconozcan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-11-17','miguel, hablo con Lorenzo hermano del tutelado (lorenzogarcia1950@hotmail.com/678731543)quien me confirma que ya firmaron la herencia y que necesitan la ratifiquemos y más adelante se venderá... Buenos días Lorenzo, para la ratificación de la herencia y posterior solicitud judicial (mediante abogado) para la aprobación judicial de la herencia y solicitud de autorización de venta si así lo quieren necesitaré: 1.-Escritura completa de la aceptación y adjudicación de herencia que hicieron Por ahora no hace falta me entregue los originales. En el momento en que puedan hacerme falta se lo solicitaría. Por favor envíeme los datos de contacto del abogado Francisco Vela (tlfno/email)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-11-17','Ana: Llamada de Maite, cuñada de Desideria (943 11 61 93): Al parecer tiene pagos pendientes de una DERRAMA de la Comunidad. La reunión sobre ello tuvo lugar precisamente la semana anterior al fallecimiento de Ángel (marido de Desi). Habría que hablar con Raquel, vecina (648 61 98 93). ················· Lo comunico a las secc. jurídica y ecca.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-17','TERESA RECIBO CORREO DE ANTO TS DEL SASB COMUNICANDO QEU HACE DOS DIAS QUE NO PUEDE ENTRAR LA AUXILIAR EN EL DOMICLIO, HA ENTRADO CON LA POLICA Y BARTOLOME NO SE ENCUENTRA EN CASA, NADIE SABE DONDE ESTA. CONTINUA SIN TRATAMIENTO PSIQUIATRICO ANTE SU NEGATIVA A PONERSE EL INYECTABLE ARCHIVO COMUNICADO EN SU EXPEDIENTE Y LO DERIVO A LOS ASESORES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-11-17','TERESA Hola Teresa, ok, he visto lo que me has enviado referente a Aitor. La limpieza estaba programada para la proxima semana, lunes y martes, asique hablaremos con Fissa, para explicar lo sucedido y que tiene que suspenderse por el momento,. Te aenvío adjunto informe de la visita realizada a los servicios sociales de la margen derecha y al tutelado Aitor Moreno. Y las informaciones que hemos recibido hasta el momento de este casao, nos avisaron de SSB que la abuela lo queria echar pero suponiamos que finalmente no habia sucedido. Valoración de la situación: Destacamos la situación difícil en la que Aitor vive en la actualidad, por su pareja, la convivencia familiar y el entorno que le rodea. Que rechaza cualquier ayuda de vivir en algún piso supervisado, como transición a la vida adulta, ya que no desea volver a Castuera. Que rechaza solicitar plaza en cualquier centro de formación y aprendizaje, incluso tipo inserción laboral, dice que sus amigos trabajan en la construcción y él puede hacer lo mismo. Que rechaza retomar su pauta de tratamiento psiquiátrico tan necesario para su estabilidad mental y emocional. Demanda disponer de su pensión completa para vivir en una vivienda alquilada, y tan fija es la idea, que su pareja le fuerza a buscar ya diferentes ofertas. Que rechaza cualquier trato con su madre, dice varias veces que no tiene familia. Desea acudir al centro de Castuera para recoger su ropa y pertenencias y alguna cantidad de dinero que dejó allí, que para ello se desplazará en tren, pero antes llamaría a la directora. Consideramos que, mientras que se resuelva su situación de ir a un centro o no, de manera quizás involuntaria, hay que buscar un recurso de alimentación y cubrir otras necesidades, dentro de las posibilidades económicas. Bueno, esto cuando residia en la casa de la abuela de Mireia, ahora no sabemos si es viable con su pensión, pensar en pagar un alquiler. Los servicios sociales han trabajado en otras ocasiones con el supermercado Al Lado, cercano a la sede, en parque de San Fernando, donde se podría establecer una compra semanal o quincenal. También cubrir gasto de carga teléfono, tabaco y algún gasto bolsillo. La ropa si la ha dejado en Castuera, se podría recuperar, para evitar compras innecesarias. Aitor demanda 65 euros semanales solo para comprar, además de los otros gastos expuestos. 08-11-2022 contacto telefónico: En el día de hoy, se recibe llamada telefónica de los SSB de margen derecha de Badajoz (José Antonio Casquero) psicólogo, para comunicar que tiene en ese momento en su despacho a Aitor y Mireya, exponiendo la situación en la que se encuentran: No pueden estar en la vivienda de la abuela materna, hecho que ya hemos reflejado en el informe de la visita realizada el jueves 3 de noviembre, siendo la situación insostenible. En la vivienda de la abuela paterna, que como dijimos reside cerca, solo puede residir Mireya, pero Aitor no sitio para quedarse allí. Demandan por tanto un recurso habitacional urgente. Dice que han pasado por centro hermano, algo que no les convence, o poder compartir un piso, para lo cual necesita disponer de su dinero. (Parece ser que al final, centro hermano si le ha convencido) Toda solución pasa por estar con Mireya, Aitor no se plantea que s ele pueda dar una solución a él como tutelado, sin ella dice que No, pues quieren vivir juntos. Sabemos que en parte, sus problemas se han agravado por esta relacion, pero ahora mismo ese vinculo, vemos complicado que se rompa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2022-11-17','TERESA Me comenta la enfermera que el día que van a poner el DIU a Carmen será el lunes próximo. Por favor cuando puedas nos envías el documento firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-17','Ana: Correo de Verónica, TS del Ayto. de Moraleja (s.sociales2@moraleja.es) al ctutelar@ y a mi dirección: "Tal y como le comenté a Ana Matamoros la semana pasada, Doña Pilar Díez Santiago, persona con medidas de apoyo a quien representa la Comisión Tutelar de Adultos de Extremadura, ha decidido ingresar en la Residencia de Mayores “San Blas” residencia de titularidad municipal del Excmo. Ayuntamiento de Moraleja. Está además preocupada porque cuando solicitó la documentación que les remitimos para completar su expediente en la Comisión Tutelar de Adultos, detectó que su hijo Jorge Barroso Díez está empadronado con ella, ha solicitado la baja de oficio en el padrón municipal, y es por ello, que les remito tanto el modelo de solicitud como la declaración de ingresos necesarios para formalizar su solicitud de plaza residencial, y la solicitud para comenzar con los trámites necesarios para formalizar la baja de oficio en el padrón (del domicilio de Pilar), de su hijo. Los ha firmado ella, y los remitimos para que nos sean devueltos con la firma del Presidente de la Comisión Tutelar de Adultos, entidad que representa a la solicitante en ambos trámites." ······················ Subo al portafirmas digital la solicitud de ingreso en Res. Mayores. ········· Envío correo a la sección económica y la jurídica en relación a la baja de padrón y a la Declaración de ingresos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-11-17','¡Buenas Amalia! Te escribía para informarte sobre la situación de MJC después de la semana pasada. Su tía le comentó que todavía no se daba una situación correcta para que se fuera a vivir al piso, por lo tanto, hemos mejorado su situación a nivel de convivencia y se encuentra más cómoda. Sigue yendo los fines de semana. Quedo pendiente de entregarte el presupuesto dental. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-11-17','-Amalia: Sólo comentarte que las pensiones están tramitadas y registradas , a esperar respuesta del INSS . Me ha llamado él y se lo he comentado igual . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-17','TERESA Hoy, 17 de noviembre, se recibe una llamada de María (servicios sanitarios San Judas,, que son quienes le hacen la ayuda a domicilio) para comentar que Barto sigue sin abrir la puerta y con el teléfono apagado, ya ayer, no abria la puerta, asique hoy le hemos indicado a María que llamara a la policía para entrar en casa de Barto, ya que una vecina tenia una llaves pero alli no hay nadie. Se llama a salud mental de Almendralejo para preguntar si Barto ha estado o está ingresado y comentan que no. (Se le deberia haber puesto inyectable en lugar de darle la medicacion oral, el dia que fue, pero bueno ante eso ya no se puede hacer nada) Se recibe otra llamada de María y comenta que , después de haber preguntado en diferentes bares y a personas que ella sabe que son amigos suyos, le han dicho que Barto ha ido a hacer el camino de Santiago, que ayer lo vieron en el parque con una capa negra y una mochila grande y le dijo a un amigo que "había cometido un pecado muy grande, que iba a hablar con el cura y después a hacer el camino". Se le llama por teléfono y sale el buzón, el otro día (que se le acompañó a salud mental) dijo que no quería que nadie lo molestará y que tenía el móvil apagado, se le insistió en que lo encendiera por si surgía alguna cosa o teníamos que ponernos en contacto, pero sigue apagado. No sabemos por lo tanto, donde esta o si esta bien, porque que sepamos no ha retirado dinero ni nada, para hacer tal camino y obviamente no está en su momento más estable, como para tal cosa. No se si, debeis comunicar al juzgado la situacion.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2022-11-17','-Email del centro con respecto a visitas de la pareja de su madre ,por el momento no se harán . Buenos días Amalia, desde el Centro seguimos considerando que no es conveniente que se produzcan las visitas. Zoraida carece de recursos personales para gestionar emocionalmente estas visitas. Creemos que sigue siendo especialmente vulnerable debido a las necesidades de afecto que presenta, ya que puede acceder a hacer cualquier cosa por recibir un halago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-11-17','-Amalia : nos contacta ha contactado por teléfono Jorge hijo de Justa Diaz Borreguero. A Justa le ha llegado citación del juzgado para valoración del medico forense por el internamiento, mañana dia 15 a las 12.30h. (Iremos con ella) Ella se lo ha comentado a su hijo con el que ha retomado la relación y él quiere contrastar información sobre la situación de su madre. Comenta que si es un tema económico podría hablar con sus hermanos y ver la posibilidad de poder ayudar económicamente a su madre para que se mantenga en su domicilio. Le hemos trasladado que debe ponerse en contacto con la comisión pues no estamos autorizados para dar información. El teléfono de Jorge es: 679 689 322','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-11-17','-Amalia : nos contacta ha contactado por teléfono Jorge hijo de Justa Diaz Borreguero. A Justa le ha llegado citación del juzgado para valoración del medico forense por el internamiento, mañana dia 15 a las 12.30h. (Iremos con ella) Ella se lo ha comentado a su hijo con el que ha retomado la relación y él quiere contrastar información sobre la situación de su madre. Comenta que si es un tema económico podría hablar con sus hermanos y ver la posibilidad de poder ayudar económicamente a su madre para que se mantenga en su domicilio. Le hemos trasladado que debe ponerse en contacto con la comisión pues no estamos autorizados para dar información. El teléfono de Jorge es: 679 689 322','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-11-17','En archivo adjunto se envía la inscripción de Macarena Otaño al Programa de Normalización, Orientación e Inserción Laboral de Down. Es un programa que llevan de inserción laboral desde la Asociación Síndrome de Down de Badajoz, en el que voluntariamente Macarena quiere participar para incorporarse a su bolsa de empleo. La persona responsable es Víctor Romero. A través de correo electrónico nos ha mandado la inscripción ya que no sabe si deben firmar sus tutores este tipo de solicitudes, entendemos que esto lo puede firmar ella sola, pero por si acaso, te hago llegar la inscripcion y datos de contacto Teléfono de contacto; 924 25 91 35 - 665 67 99 47 E-mail: insertdownbadajoz@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-17','Ana: Envío correo a Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "En relación al extra que se ha autorizado para que Julia pueda ir de viaje con sus padres a visitar a su hermano José María, se ha determinado que, entre otras cosas, con su aportación se abonarán los billetes de autobús. Por lo tanto, el lunes o el martes podrá retirar 60€, acompañada con Félix, como siempre (los compañeros enviarán hoy la autorización al banco) para que puedan comprar los 3 billetes en la estación (cuestan justo 20€ cada uno). El resto del dinero (hasta los 150€) los aportará mediante transferencia bancaria. El viaje tendrá lugar del próximo martes 22 al viernes 25, pasando en Ávila las noches del 22, 23 y 24."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-18','TERESA Ayer, Barto llamó a la compañera, te comento la informacion de la tarde de ayer, con respecto a Barto: Ayer, 17 de noviembre, sobre las cuatro de la tarde, se recibe una llamada de Barto, comenta que está en Ponferrada, en un albergue, se le pregunta por el nombre del mismo pero no nos lo dice. Se le pregunta cómo está y afirma que bien, que se ha ido por un tiempo porque necesita unas vacaciones y porque estaba muy agobiado de estar siempre en Almendralejo. Se le nota tranquilo, comenta que tiene dinero y que lleva las medicinas las cuales se está tomando, que , además, lleva consigo su tarjeta sanitaria por si necesitara sacar alguna mediccina más de la farmacia. Se le pide que no apague el teléfono y que, si lo hace, al menos nos llame a menudo para saber de él, afirma que nos llamará para contarnos su viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-11-17','Ana: Correo de Sonia Bernabé - Asindi: "Hola Ana, quería comunicarte una situación que afecta a Roberto y Justo Hernández Castaño. Este fin de semana está programado que vayan a casa. Su madre nos mandó la solicitud de salida, pero a los pocos minutos me manda unos audios en los que me dice que económicamente está mal y que no tendrían para darle de comer a los chicos. La he llamado para ver la situación y me dice que quiere que vayan pero también se quiere asegurar que les puede dar de comer, y por lo visto, su marido se gasta dinero en jugar a las máquinas, y van muy justos para los gastos de casa. Justo lleva varios días preguntándome cuándo se va a casa por lo que tiene ganas de ver a su padres, ha pasado un mes desde la última visita. Para que puedan ir, habíamos pensado que, de manera excepcional, y si lo autorizáis, puedieran comprar los chicos un mínimo de alimentos para las comidas de ellos dos durante el fin de semana (ejemplo macarrones, atún, tomate, algo de fruta,...) Yo creo que poniendo unos 10 € cada uno sería suficiente. Según me dice la madre no hay en el pueblo ninguna entidad como centro de mayores,,..que hagan comidas para las personas mayores y que se puedan encargar2 menús por un módico precio." ·············· Se autorizan los 10€ a cada uno. Y plantea la posibilidad de que se encargue menú en algún bar del pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-11-17','Ana: Correo de Sonia Bernabé - Asindi: "Hola Ana, quería comunicarte una situación que afecta a Roberto y Justo Hernández Castaño. Este fin de semana está programado que vayan a casa. Su madre nos mandó la solicitud de salida, pero a los pocos minutos me manda unos audios en los que me dice que económicamente está mal y que no tendrían para darle de comer a los chicos. La he llamado para ver la situación y me dice que quiere que vayan pero también se quiere asegurar que les puede dar de comer, y por lo visto, su marido se gasta dinero en jugar a las máquinas, y van muy justos para los gastos de casa. Justo lleva varios días preguntándome cuándo se va a casa por lo que tiene ganas de ver a su padres, ha pasado un mes desde la última visita. Para que puedan ir, habíamos pensado que, de manera excepcional, y si lo autorizáis, puedieran comprar los chicos un mínimo de alimentos para las comidas de ellos dos durante el fin de semana (ejemplo macarrones, atún, tomate, algo de fruta,...) Yo creo que poniendo unos 10 € cada uno sería suficiente. Según me dice la madre no hay en el pueblo ninguna entidad como centro de mayores,,..que hagan comidas para las personas mayores y que se puedan encargar2 menús por un módico precio." ·············· Se autorizan los 10€ a cada uno. Y plantea la posibilidad de que se encargue menú en algún bar del pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-11-18','Ana: Conversación con Sonia Bernabé (927 39 01 93): Felisa continúa ingresada en el hospital. Está muy demandante con cuestiones médicas (supuesto dolores y demás, para que le hagan radiografías, el test del Covid, etc.). Le están ajustando la medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-11-18','TERESA Me llama la TS de Peñalsordo que tiene allí a Felisa, madre de la pareja de Marta. Le está diciendo que últimamente Marta sale por la noche a las 11 o las 12 de la noche con excusas como que va a comprar un bocadillo o que va a ir a casa de un chico del pueblo que dice le esta ayudando con las tareas domésticas…. Felisa le dice que le acompañe el novio pero ella quiere ir sola. Felisa comenta que ella no quiere tener la responsabilidad de que le suceda algo a esas horas de la noche y se está planteando decirle que se vaya de su casa. Nos pide que hablemos con ella para que deje de salir de noche. Le he preguntado si está acudiendo al centro y comenta que el otro día no acudió y le dijo que le hiciera un justificante de que no ha podido ir porque tenía que ir con el novio a hacerse una foto. La trabajadora social le dijo que eso no era una causa justificada y no accedió a hacérselo. Le he dicho que nosotros no podemos impedir que ella salga y entre, que si Felisa decide que deje de vivir en su casa tendrá que irse a un recurso residencial. Habrá que hablar con ella para explicarle la situación y que sea consecuente con lo que hace.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2022-11-17','Ana: Laura, TS del IMAS - CC (laura.dominguez@ayto-caceres.es): envía mail al ctutelar@ con documentos relativos al embargo de Montaña por la pensión de alimentos a sus hijos, envía también DILIGENCIAS DE ORDENACIÓN requiriendo a Mª Montaña su ingreso en el plazo de 10 días en el CSS-Plas. para cumplir MEDIDA DE SEGURIDAD DE INTERNAMIENTO. ····················· Miguel, A. Jurídico, solicitará información al respecto al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2022-11-18','Ana: Conversación con Laura, TS IMAS-CC (927 21 23 35 - Ext. 4417): Montaña va de vez en cuando por allí. Actualmente se le nota que no está bien, le cuesta mucho entender lo que le quiere explicar. Ella consigue calmarla, no así otros compañeros del IMAS con los que se altera más. *El problema principal es que no está tomando la medicación, ella misma se lo ha dicho. ·············· No tiene SAD ni ningún otro recurso de apoyo pues ella no lo acepta y así y todo es una usuaria muy complicada. *Es bastante autónoma. ······················ Le explico que en relación al embargo no hay nada que podamos hacer. Y con respecto al ingreso, cuando sepamos algo más le decimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-11-18','Ana: Correo de Eva Álvarez, TS - Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org): "Me pongo en contacto contigo en relación a la derivación a Plena Inclusión Montijo, de Cristofer Montero Vázquez. Me comenta Amalia que eres tu quién puede decirme como se encuentra su expediente. Nosotras le acompañaremos el lunes para hacer el cambio de médico. También queremos saber si la asignación económica mensual seguirá siendo de 90€ al mes como cuando estuvo aquí. Si puedes me dices cuál es el importe de las pensiones para gestionar el 75% de la cuota de vivienda." ····························· Mi respuesta: "¿qué tal ha ido la llegada e ingreso de Cristofer? He tenido la mañana liada. El lunes intento llamarte y hablamos con calma. En San Gil, Plasencia, no contaba con una asignación económica mensual específica. En el centro tenían autorización general para los gastos precisara y en este sentido tenía una gasto mensual medio de 65€/mes. Entiendo que esta cuantía se mantendrá en vuestro centro. No obstante, si estimáis gestionarlo de otra manera o queréis renegociar la cuantía mensual, podéis poneros en contacto con la sección económica en el ctutelar@salud-juntaex.es. Podéis ponerme en copia sin problema. En cuanto a sus ingresos, percibe: - Prestación Familiar por Hijo a Cargo: 417,70 € - P. Orfandad Absoluta: 494,10 € La dirección desde la que te escribo es la mía directa, para todo lo que no sea específicamente jurídico o económico no dudes en escribirme o llamarme al número de la firma, que es el mío directo. Una vez haya pasado el periodo de adaptación a vuestro recurso, como sabes, el seguimiento pasará a Amalia, pero durante las próximas semanas estaremos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2022-11-14','Ana: Según Informe social de Inventario Montaña, de 48 años, está separada. Tiene un hijo de 22 años, Jose Ángel. Según manifiesta sus padres son los que la cuidan cuando se encuentra peor. En cambio, desde SS.SS. se han puesto en contacto con ellos y éstos no quieren colaborar. ········ Tiene otros 2 hijos cuya custodia ejerce el progenitor. ·················· Vive sola en una vivienda de alquiler social de la Junta de Extremadura. ············· Ha solicitado Ayuda para Suministros Mínimos Vitales en 2022, la cuál tiene concedida y presenta periódicamente las facturas. ·········· También le han concedido la Ayuda de Emergencia Social para ropa y calzado. ······ Se niega a aportar información sobre cuentas bancarias. ··········· *No tiene seguro de decesos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2022-11-11','Ana: Según sentencia, se trata de una CURATELA REPRESENTATIVA, "requiere de representación para tomar decisiones de contenido económico, para realizar disposiciones testamentarias, donaciones o contratos, otorgar poderes, contraer obligaciones, para la realización de cualquier gestión ordinaria de su patrimonio, realizar pagos, efectuar disposiciones de dinero en efectivo o de otra forma, o para manejar importantes cantidades de dinero de cualquier cuantía, salvo el dinero de bolsillo, para actuar ante entidades bancarias, contratar y gestionar servicios y productos financieros o bancarios y actuar ante los servicios administrativos de cualquier índole. También precisa de representación para la toma de decisiones en lo relativo al ámbito de la salud, entendiendo a título de ejemplo como elementos a integrar en el ámbito de la salud: manejo y toma de medicamentos, seguimiento de tratamientos médicos o farmacológicos, decisión respecto de los tratamientos médicos necesarios, intervenciones quirúrgicas, pruebas diagnósticas, pautas alimenticias y en todo lo relacionado con la información sanitaria y prestación del consentimiento informado en materia de salud."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-21','Ana: Correo de Lucía Ávila, Res. El Conquistador, de Trujillo (luciaavilasanchez67@gmail.com), al ctutelar: "Buenas tardes, quería informar que ésta mañana dimos un aviso al médico de A .P. para el Sr. Felix Amado Narciso, acabamos de hablar con la médico de urgencias y nos comunica que el estado es grave, iremos informando según tengamos noticias del hospital, un salud"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-18','Ana: Correo del viernes de Pilar Martín, TS del ESM - CC (pilar.martinp@salud-juntaex.es): "Buenas Ana, de nuevo tengo a José Manuel diciendo que se va a tirar del balcón, se lo he dicho a su enfermera para que le llame, yo también he hablado luego y me dice que se encuentra muy solo. Me encarga que le llames. Luego me dices, yo no desecho la posibilidad de recurso residencial de mayores, parece ser que no le parece mal el ingreso en la residencia Cervantes. Hasta ahora."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-18','Ana: Respuesta de Miguel, A. Jurídico CTAEX, en relación a la TS, en relación a la solicitud de baja del padron: "Buenos días Verónica, ese documento puede presentarlo directamente ella en el ayuntamiento." ····· Desde la CTAEX no se puede firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2022-11-21','Ana: Envío a Toni-Futuex, correo de Ángel, A. Jurídico CTAEX: "El 23/11/22, a las 13:00, está citada Catalina en el Juzgado. Hay que comunicárselo para que esté allí ese día. Si puede ser un poquito antes de la hora, para que pueda hablar con la Abogada, María Floriano. Nosotros estaremos a través de videoconferencia.", pido a Toni que se lo comuniquen y la acompañen si es posible. ································· Respuesta de Toni: "vamos a intentar también estar, se han mirado los horarios de buses y no hay para el regreso, asique gestionaremos un taxi Valencia de Alcantara-Cáceres, y pasamos la factura para abono al área eco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-21','Ana: Recibimos resolución del CATERING MUNICIPAL de José Manuel. Fecha de finalización del servicio: 31/12/22. ··································································································································································································· Llamo a José Manuel, no dice absolutamente nada de ideas autolíticas ni de ingreso en recurso residencial. Sólo se vuelve a quejar del cáterin y pregunta cuándo podrá comprar los sillones. A mi pregunta de hasta cuándo le dije que no podía enviar presupuestos, responde que hasta marzo. ················································································ Llamada de Anabel Teomiro, Técnica PIA (927 006 788 // 22050): Aunque para las revisiones PIA no se realizan visitas, dada las peculiaridades del caso ha propuesto a su jefa hacerle vista. ·········· El ingreso en Plaza Pública Centro de Día, dado su perfil no lo ve factible. ··· Podría optar a plaza privada en C. Día, pero le correspondería una P. Vinculada de 143€ y el coste de la plaza es más de 700€. *Esto no se lo puede permitir. ··············· Si le concedieran Tto. en Revital, le correspondería una prestación vinculada de 143€, pero tendría que pagar en torno a 330€ por el servicio. ·············· Le corresponden esas vinculada porque en el cálculo de descuentan los complementos de la pensión... ···························· *Ella entiende, que dado el perfil de José Manuel lo más adecuado sería un CRPS. ······················ Llamo varias veces a lo largo de la mañana a Pilar Martín, TS ESM, sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2022-11-21','Ana: Envío correo a Rosa Bravo, CSS Plas (rosamaria.bravop@salud-juntaex.es): "En relación a Mª MONTAÑA GONZÁLEZ ROLO, cuyo cargo de CURALETA REPRESENTATIVA ha sido aceptada recientemente por la CTAEX, os remito adjunta la EJECUTORIA INGRESO en vuestro centro del Juzgado de lo Penal nº 1 de Cáceres que nos han hecho llegar la compañera de los Servicios Sociales de Cáceres (IMAS). No sé si teníais conocimiento sobre ello. Nosotros hemos enviado el inventario hace poco al Juzgado y estamos iniciando el Plan de Intervención, no nos ha dado tiempo a casi nada más. Vamos a intentar que ingrese por su propio pie, sino nos planteamos activar el 112. Si queréis decirnos cuál sería el mejor día para el ingreso, intentaremos ajustarnos a esa fecha." ·················· Respuesta de Rosa: "Desconocíamos la Causa. He hablado con el Servicio Común de Ejecución, que nos mandará la Sentencia." ······························································································································································································· Envío correo a Toni-Futuex: "Necesitamos que visitéis lo antes posible a esta señora cuyo cargo se ha aceptado hace poco por la CTAEX y cuyo inventario se ha enviado recientemente. Apenas hemos podido hacer nada, excepto leer el informe y hablar en un par de ocasiones con la TS de referencia del IMAS. Laura, TS IMAS-CC (927 21 23 35 - Ext. 4417), la señora vive en domicilio y ha recibido esta ejecutoria que os adjunto y que nos ha remitido la TS. Ella en principio no quiere ingresar, pero si no va por su propio pie, tendremos que activar el 112 o procederán a tu detención. Si pudiéramos evitar estas dos últimas opciones mejor, así que os pedimos que la visitéis y, aún siendo precipitado, pues nos os habéis podido ganar su confianza de forma previa, intentéis convencerla de que será mejor ingresar así y con vuestro apoyo que teniendo que intervenir los cuerpos y fuerzas de seguridad del estado. Podéis coordinaros con la TS que la conoce. Es maja y parece implicada. Los datos son: MARÍA MONTAÑA GONZALEZ ROLO C/ Évora, nº 4, 3º C - Cáceres. Tlef.: 692 891 219 Adjunto la ejecutoria." ························· Respuesta de Toni: "ok. Esta semana intentamos ir a conocer a esta señora y a ver si con suerte se consigue algo, antes de la alternativa involuntaria." ································································································································································································ *Aunque en el Informe Social dice que la vivienda en que reside (C/Évora) es de alquiler social de la Junta, según Cdo. Catastral Telemático es de su propiedad: titularidad al 100%.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-11-21','miguel, me escribe y me llama damian para varias cuestiones, cuya conversación telefónica reenvío a Amalia: Buenos días, me ha llamado Damian preocupado por la resolución del desahucio del piso de Málaga. Ya le he explicado que el otro día fue el juicio para que nos den la autorización que necesita la abogada de Málaga para interponer la demanda de desahucio(los juzgados de Mérida se han retrasado meses para esto) Por otro lado dice que se encuentra mal (palpitaciones, estreñido,etc) desde que el director del Centro Javier le ha dicho la semana pasada que si no ve mejoría en el piso en que está lo mandará de vuelta al centro. Ya le he dicho que estas cuestiones tiene que hablarlo tanto Javier como él contigo. También le he dicho que le diga a Javier que se dirija a la Comisión a través de su trabajadora social para cualquier incidencia que tenga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-11-21','Ana: Recibimos EJECUTORIA del Jdo. de lo Penal nº1 de CC: se autoriza el TRASLADO de José Mª al CENTRO PSIQUIÁTRICO PENINTENCIARIO de Sevilla. ····· *El traslado se efectuará el día 23/11/22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-21','TERESA Perdona la demora, estoy en un curso esta semana y no me da tiempo a nada. Te concreto todo: • Serán 3 noches. Hemos pensado que vayan el martes de la semana que viene, hasta el viernes. ( si hay algún problema nos lo cominicais) • Su hermana Julia también irá. Serán tres personas. • La llegada a Salamanca es a las 15:30. • La vuelta desde Salamanca puede ser a las 10:00 14:30,15:00 • Cuando este todo nos pasais la factura del alojamiento y del taxista o que ellos directamante nos lo envíen. Te dejo el teléfono de mi compañera Teresa por si necesitais aclarar algo, 924 00 38 04, yo no estaré durante la mañana ( le pongo copia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-21','TERESA Buenos días, soy Estefanía Cuenda, directora de la Residencia de Medina de las Torres, donde ingresó José González Fernández el pasado día 17 de noviembre. Según me han informado, se encuentra bajo su tutela, por ello, he estado intentando contactar con usted a través del teléfono 924003804, pero no ha sido posible, me gustaría comentarle algunos aspectos acerca de este residente. Así mismo, le envío el contrato para que nos lo devuelva firmado. Muchas gracias Un saludo Estefanía Cuenda Charneco Directora Residencia Medina de las Torres Tfno: 675516505','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-11-21','Ana: Conversación con Estrella, TS CSS-Plas. (24146): me comunica que está muy mal, le han dicho que mejor no acuda aún a hablar con él. ·········· Le facilito información sobre su grado de discapacidad y pensión. ····· Pregunta también por la familia de éste, su madre falleció y con su padre no tiene relación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-21','Ana: correo de Lucía, Directora Res. El Conquistador - Trujillo (luciaavilasanchez67@gmail.com): "la única información que tenemos nos la ha dado la vecina que le cuidaba algunas veces ( el hospital no nos da información ) su estado en general es grave, sufre de cardiopatía grave y problemas respiratorios, no come y está con tranquilizantes. Si nos enteramos de algún cambio lo comunicaremos de inmediato."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-11-21','Ana: Correo de Eva Álvarez, TS - Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org): "Pues te cometo que, los chicos tutelados que están en nuestras viviendas disponen de una asignación mensual de 90€ que se gestiona desde el piso. Así era antes también cuando Crístofer estuvo con nosotras, le mandaré correo a la sección económica para comentarle. Me han comentado que le han comprado un edredón, a su gusto, para su cama, por lo que este mes tiene un gasto extra. Ya se le ha cambiado el médico aquí en Montijo. La llegada ha sido muy buena, sus compañeros además le hicieron una "fiesta" de bienvenida, así que él muy contento." ································································································································································································ Mi respuesta: "Gracias por informar. Me alegro que haya tenido tan buena acogida. Espero que se adapte bien al recurso. Pongo en copia a los compañeros de la sección económica para que puedan valorar lo del extra que planteas y darte respuesta. En cuanto al edredón que comentas, ¿se abonará de esos 90€ mensuales o hay que abonarlo a parte? En este último caso tendrías que enviar la factura al ctutelar@salud-juntaex.es y, para futuros gastos extra, tendríais que enviar presupuesto previo para su aprobación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-21','TERESA ENVIO CONTRATO DE RESINENCIA MEDINA DE LAS TORRES POR EMAIL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-11-22','Ana: Llamada de Sonia Bernabé (927 390 193): Felisa sigue ingresada. Ayer les pidieron ropa limpia y se la han llevado. ···· El viernes volvió a alterarse. ···· Van a ajustarle de nuevo la medicación. ············· Tiene concedido el Programa de Apoyo en el Entorno de Plena Inclusión (Federación), pero dura hasta final de año y no lo está pudiendo aprovechar. Le han pedido a la monitora a ver si puede recuperar algunas de las horas "perdidas" cuando le den el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-11-22','Como sabrás, Alberto se encuentra ingresado en un centro de rehabilitacion en Montijo donde se encuentra relativamente bien. Me comenta que tiene necesidad de hablar contigo para aclarar el asunto del dinero que, semanalmente, les ingresais en su cuenta y que no puede retirar porque las salidas las tiene restringidas. Para solventar esta situación le traspaso todas las semanas 50 euros para sus gastos en tabaco, articulos de aseo, y alguna otra cosilla que necesite. Quisieramos poder tener un contacto contigo cualquier dia que vinieras a Badajoz,ya que no nos hemos visto una o dos veces desde hace años, caso de poder vernos, me tendrias que avisar unos dias antes para poder solicitar el permiso para salir. de no poder tener esa cita, al menos, llamarlo para que el te exponga el tema de sus transferencias. Quiere que se le siga ingresando la cantidad que se le transferia antes de su ingreso en el centro, porque ahorraria en este periodo para poder sacarse el carnet de conducir, comprarse un patinete para poder desplazarse. En fin, el te lo explicaria mejor que yó. Otro asunto relacionado conmigo, es la deuda generada por esta circunstancia, que consiste en 1.623,60euros, consistente en 600 de los meses agosto y septiembre del centro, 600 de todas las semanas que le ingreso 50 euros, gastos cerraduras en su puerta 150, compra de varios articulos que necesitaba al ingreso, 140 que tuvo que prestarle su tio en el ingreso y, varias compras de menor cuantia. lo que no sea justificable por diversos motivos, seria firmar tanto Alberto como yó un documento de aceptación de dichos cargos. Desearia que, lo antes posible, pudieran regularizarme esta situación que me está afectando a mi economia. Caso de considerarlo oportuno, me podrian transferir a mi cuenta dicha cantidad. cc juan Ramos Nuñez.......0182 0376 84 0019600000 telf. mio 619782212 telf del centro 699184701 telf. direccion del centro 657813847 ( Julian )','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-11-22',
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-11-22','Ana: Sonia Bernabé, TS ASINDI, me remite documentos (Autorización Dcho. Imagen y Protección de Datos) para que Justo pueda participar en una actividad de la Red de Accesibilidad Cognitiva con Plena Inclusión: "Prueba de percepción visual. Pictogramas de Señalización para ayuntamientos". ···················· Se los paso a los A. Jurídicos CTAEX, para que confirmen que se pueden firmar. ··············· Una vez confirmado, cumplimento y subo los documentos al Portafirmas Digital. ···················· *Remito a Sonia Bernabé los documentos firmados digitalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-22','Ana: Se autoriza la compra de un pastillero semanal más grande. En el que tiene no le entra toda la medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-22','Ana: Envío correo a Verónica, TS del Ayto. de Moraleja (s.sociales2@moraleja.es): "Adjunto los siguientes documentos relativos a PILAR DÍEZ SANTIAGO, firmados digitalmente por el Presidente de la CTAEX: - Solicitud de Ingreso en Centro Residencial de Mayores Moraleja - Declaración de Ingresos Desde la sección económica, me comunican, y te lo transmito para que lo tengáis en cuenta a la hora de intervenir con ella, que se va a cancelar la tarjeta bancaria. Así mismo, seguramente le bloquee la cuenta, por lo que en principio no podrá sacar dinero. ¿Sabéis qué día, aproximadamente, podrá ingresar en la residencia? Pues en base a eso, podríais calcular un “presupuesto” aproximado para gastos de bolsillo, para enviar al banco una autorización de retirada del importe que nos digáis y, en función de la cuantía y de si consideráis de si la administrará bien o no, si se le hace la autorización para retirar de forma semanal, quincenal o mensual. Por cierto, también están haciendo averiguaciones en relación a los dos préstamos que tiene, los cuáles, en principio, también hay que seguir abonando, por lo que la asignación no deberá ser muy elevada." ································································································································································································· Llamada de Verónica, TS SSASB (927 51 50 75): Mañana registrará de entrada la solicitud de ingreso en centro. *Hay lista de espera, la residencia es de titularidad municipal, teniendo prioridad las personas residentes en el pueblo (empadronadas). Tiene a 2 personas por delante, por lo que no saben exactamente cuándo podrá ingresar. ········ Pilar tiene un gasto fijo para abonar el catering de la Res. San Blas. *No está domiciliado el pago. Me facilita el contacto del Director: Tino - 699 46 72 25. *Se lo pasaré a la secc. ecca. para que domicilien el pago. ·············· Por otra parte, tiene como gasto fijo los suministros y cuestiones varias relacionadas con la vivienda (esto sí está domiciliado). *En cuanto al gasto de bolsillo, no sabe decirme exactamente, son las compañeras del Programa de Familia quienes intervienen con ella al respecto. *A Pilar le encanta ir a hacer la comprar al Carrefour. ········· En cuanto a las citas en ESM, le suele acompañar la Aux. de SAD, pero esto cada vez es más complicado y no siempre podrá hacerlo. *Podríamos derivar al Programa de Apoyo Comunitario gestionado por Futuex. *Lo trataré con el Programa de Familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2022-11-21','Ana: Correo de Ángela Bueno, Directora PLACEAT (directora@placeat.org): "Buenos dias Ana, informarte que el pasado 14 de noviembre falleció Benedicta Simón, la que Maria considera su madre y que estaba en la Residencia de Mayores de Aldeanueva del Camino. Haremos un viaje a la Residencia porque Maria quiere recoger los enseres personales de ella. Solo es para tu conocimiento, cuando tenga fecha ya mandare a la seccion economica el coste del taxi para su aprobación, siempre que no tenga ella de su dinero de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-11-22','Ana: Llamo a Pilar, Directora de la residencia de Logrosán (639 58 54 89): "Valentina está pachuchina", "ha dado un bajón importante las últimas semanas". ······· Sigue caminando con el andador, pero aún no camina muy bien. El fisio le atiende 3 días/semana. Mañana hablará con el Fisio para preguntar estimación de tiempo que necesita el servicio y me llamará al respecto. ·············· Cree que tiene algunas otras propiedades (una "cerca" y una cuadra). Intentará averiguar algo. ····························································································································································································· Envío correo a los A. Jurídicos: "En relación a VALENTINA FERNÁNDEZ TREJO, 2 cuestiones: 1. ¿Podríais solicitar certificado catastral telemático? Me dice la Directora de la Residencia en la que vive, que cree que tiene alguna cuadra y “cerca” (pequeño terreno), que llegado el momento se podría vender. 2. ¿Habéis hecho alguna de los dos algo relativo a la herencia de sus padres? Según ha visto Óscar en alguna anotación de la sección económica esta gestión está pendiente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2022-11-22','TERESA Antonio Jesús participará en esta actividad el próximo jueves. Irán en vehículo de la entidad y, como siempre, acompañados Habilidades Fútbol Sala (Programa JEDES 2022) Miércoles 23 de Noviembre Salida a las 9.00 desde Plena Inclusión  Cáceres  Apoyo: Juan','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-22','TERESA Buenos días !!! El sábado fui a ver a José a las residencia , me dijo que comía mejor , y para el la preocupación de tomarse la medicación había desaparecido porque allí le ayudan a tomársela ... me comentó el tema de sacar dinero ... el es de caja Badajoz , y en Medina no hay caja Badajoz, como podemos hacerlo ? Le hacemos una tarjeta de cerdito? O me mandáis una autorización y le dejo el dinero ? Yo voy todos los sábados a zafra a hacer la compara semanal y desde mi pueblo ( Calzadilla de los barros) se va igual por la nacional que por Medina ...','2');
