insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-23','Ana: conversación con Pilar Martín, TS ESM-CC (54612): Informo sobre la información facilitada por Anabel Teomiro, Técnica PIA. ················ Va a pedirle cita en CRPS, se intentará su derivación. *Lo ideal sería también que lo aceptaran en Piso de Apoyo, funciona de L-V, aunque fuera varios días sólo en semana. ····················· Le propongo también el Programa de Integración Social de Feafex Extremadura. Iremos viendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-21','Ana: Conversación con Mariluz Madrigal, Jefa de Secc. de Acceso a Recursos de Salud Mental: Entiende que los recursos más adecuados para José Manuel en la actualidad son PROGRAMA DE INTEGRACIÓN SOCIAL de FEAFES Extremadura y el CRPS + Piso Apoyo Asociado (L-V). Ambos recursos Terapéuticos del SES. *La solicitud la tendría que hacer Pilar Martín-TS ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-11-22','Ana: correo de Maribel Ramos, TS UPA (mariaisabel.ramosa@salud-juntaex.es): "Remito la comunicación de ingreso de Remedios Chaves Masero en RAE "FCO: ASUAR" (Ayto. Fte. de Cantos). El Centro contactará con vosotras."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-11-22','Ana: correo de Óscar, Secc. Ecca: "- La cuenta de Unicaja ya está controlada y tiene anulada la tarjeta de crédito. - Han contestado de Banca Pueyo. Efectivamente tiene una cuenta que abrió en junio de este año con Andrés Valiente Valiente (su pareja??). Tiene asociada una tarjeta de crédito a nombre de él. Los movimientos que tiene son ingresos esporádicos que hacen ambos y algunos gastos de supermercado y estanco. Hay una compra de Amazon de la semana pasada, una vez cancelada la tarjeta de Unicaja. El saldo actual es de 89,84 €."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-11-21','TERESA EMAIL DEL PROGRAMA DE FAMILIA TAJO SALOR Aitor y su pareja se han venido a vivir a Garrovillas de Alconétar. Al parecer un familiar de Aitor les mandó dinero, pasaron la noche del jueves en la hospedería de Garrovillas y el viernes alquilaron una casa en la misma localidad. Según nos cuentan, un amigo de Aitor le dijo que le tenía un trabajo y evidentemente, no hay trabajo, se han gastado el dinero que le mandó su familia y ahora nos llaman porque no tienen para comer. Sé que no podemos hacer mucho pero te contamos para que al menos sepas la situación en la que se encuentra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-11-23','Ana: en relación a la cita de mañana con el Medico-Forense, Toni-Futuex, nos comunica que Virginia, Ed., está de baja, pero: "Hemos hablado con el centro y nos han dicho que ellos se ocupan que lo traen y le acompañan, les hemos pedido disculpas por las cirunstancias y por la precipitación.- Pero nos han dicho que se organizan en el centro para venir con el"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-11-23','Maite: desde Plena Inclusión Cabeza del Buey nos han comunicado faltas de asistencia de Marta justificadas con documentos no fiables, en el último mes está teniendo un comportamiento regular mintiendo en numerosas ocasiones.... Desde TUTUEX nos han informado que a diario llega tarde a casa por la noche ( 23.00/24:00 h) alegando que va a ver a un compañero que está enfermo para llevarle un bocadillo.... Felisa, suegra de Marta, no está de acuerdo con este comportamiento y así lo ha manifgestado a Teresa, educadora de Futuex. Hoy he hablado con Pilar y Mª Luisa, psicóloga y trabajadora social del Centro Ocupacional, sobre el comportamiento de MArta. Posteriormenete he mantenido una conversación con élla. Me ha estado contando cómo está y qué hace. Respecto a sus horarios nocturnos me ha trasladado la información que ya teníamos ( que lleva un bocadillo a un amigo...). Hemos hablado de la probabilidad que hay de que tenga que ingresar en un centro si no cumple las normas y/o no tuviese un domicilio en el que quedarse, y parece que es consciente. Seguiremos viendo su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-11-23','Ana: Llamada de Pilar Pacheco, TS del ECA - CC (54621 / pilar.pacheco@salud-juntaex.es): van a tramitar la solicitud de ingreso en COMUNIDAD TERAPÉUTICA para Miguel Ángel. ·········· Envío correo a Pilar: "Tal y como hemos hablado esta mañana, te adjunto: - Testimonio de Sentencia de Provisión de Medidas Judiciales de Apoyo - Testimonio de Aceptación del Cargo Solicitaros, por favor, que nos mantengáis informados sobre la solicitud de ingreso en Comunidad Terapéutica y nos comuniquéis, llegado el momento, el centro en que ingresará y la fecha de ingreso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-11-23','Ana: correo de Ángel, A. Jurídico: "He consultado en catastro y no tiene nada, la certificación negativa la he guardado en su carpeta de inventario. Con respecto a la herencia de sus padres, yo no he iniciado gestiones. No veo nada tampoco en su expediente ¿Disponemos de documentación?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-11','TERESA ENVIO POR REGISTRO SOLICITUD DE REVIION DE GRADO POR EMPEORAMIENTO, ACTUALMENTE TIENE UN GRADO UNO LA IDEA ES QUE SUBA DE GRADO Y PEDIR RESIDENCIA POR DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RUIZ'and apellido2='PACHECO'),'2022-11-23','Ana: Tras conversación con Mariví Clemente, TS del CSS-Plas (24142) remito email a Alberto y Óscar, Secc. Ecca.: "Me comunican desde el C. Sociosanitario, que DIEGO RUIZ PACHECO, ha ingresado en el hospital, le han detectado cáncer de pulmón y tienen que confirmar, pero creen que ha metástasis. Tienen mal pronóstico. En el hospital piden acompañamiento hospitalario sí o sí. Según: - Base de datos tiene SEGURO DE DECESOS - Rendición de este año, en junio contaba con 22.139€ en su cuenta bancaria Aún no tengo presupuesto de acompañamiento, pero no creen que sea muchos días, pues seguramente tras las pruebas oportuna le envíen con los paliativos de vuelta a centro. *Confirmarme que puedo autorizar dicho acompañamiento, pues por mi parte los días y horas que necesite."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RUIZ'and apellido2='PACHECO'),'2022-02-07','Ana: Según Informe Social para la rendición de 2022: Ingresa por primera vez en el CSS, desde 1981. ··· Tras el fallecimiento de su padre nadie se ha interesado por el paciente. ···· Su estancia es permanente desde el mismo fallecimiento por no contar con nadie que pudiera supervisar su tratamiento ni poder desenvolverse por sí mismo. Necesita apoyo para las actividades básicas de la vida diaria. ········ Presenta esquizofrenia paranoide.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-23','Ana: Correo de Lucía Ávila, Res. El Conquistador (luciaavilasanchez67@gmail.com) al ctutelar@: "hace un momento contactó conmigo el médico geriatra ( ENRIQUE JARAMILLO ) me comenta que aunque el Sr. Felix asimila bien el Tto. su estado es delicado y al estar tutelado es mejor que os pongais en contacto vosotros con él, preguntad por éste médico de la unidad de geriatria ( Hosp. San Pedro de Alcántara de Cáceres ) y por favor también nos gustaría que nos informaséis a nosotros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-24','Ana: Llamo al Dr. Enrique Jaramillo, Ud. de Geriatría del HSPA (927 25 15 74): indica que la mejor hora para llamar y que nos informen es a partir de las 13:30 h. *Ingresó con una Sepsis respiratoria, con origen en una pulmonía. Ha estado muy grave, pero parece que va respondiendo al tratamiento con antibióticos. No obstante, aún presenta insuficiencia respiratoria. ·· Todavía no le pueden dar de comer. ········· Me indica que la mejor hora para llamar es a partir de las 13:30 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2022-11-24','Buenos días Amalia En el día de ayer, fue derivado e ingresado Antonio Vega Fuentes, como la Comisión tiene la Curatela he informado al Hospital. Te lo comunico para que vosotros estéis informado también por si os piden alguna autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-11-24','Ana: Llamada de Juanjo, tiene mucho dolor en la pierna, está pendiente de operación de la rodilla, tiene fracturado el menisco. Le dijeron que en 3-4 meses le operarán. ·············· Va a acudir a Asociación Sorapán de Riero, en Aldea Moret, con una orientadora laboral, tiene el 12 de enero a las 12 h. Quiere participar en actividades y talleres de la entidad. ········· En el banco no quieren facilitarle los movimientos bancarios, se lo comunicaré a la secc. ecca.','2');
