insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-11-24','Ana: Llamada de Jairo, empieza a divagar sobre su estancia en el CSS, sus "motivaciones" y "objetivos" de vida (el discurso está vacío), verbaliza que se encuentra tranquilo y estable. ········ En la última visita de Gloria, Ed. Futuex, acudió al SEXPE, pero se olvidó el DNI y no pudo darse de alta como demandante de empleo. ·············· *Dice que tiene el "alta hospitalario" desde hace un año...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-11-24','Ana: Correo de Rosa Mª de Tena Medina, Directora del Centro Francisco Asuar de Fuente de Cantos (cofa@fuentedecantos.es), al ctutelar@, así como a Soraya Masa y Manuela: "adjunto remito un informe sobre la solicitud de nuevo ingreso de Dª REMEDIO CHAVES MASERO. ( Informe realizado después de haber recibido el Informe Clínico de la UHDAC)." ··········· En dicho informe expresan su disconformidad con el ingreso de Remedios en sus recursos argumentando la imposibilidad del centro para llevar a cabo algunas de las pautas y recomendaciones, por no disponer de personal suficiente ni medios para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-11-24','Ana: Envío correo a Paula, TO CRR: "En relación a ISABEL CANO BLÁZQUEZ, comunicarte que nuevo está preguntando, vía mail y teléfono, con su habitual insistencia, por los 50 € que se le iban a dar como extra de navidad. Ya le dije que sería para diciembre. En cuanto al destino del dinero, en un principio era para comprar el reloj, después dijo que lo había pensado mejor y lo quería para ropa porque le hacía falta y ya tenía visto lo que se iba a comprar y hoy dice que lo quiere para cuando vaya a su pueblo en diciembre. A nosotros nos da igual en qué lo invierta, pero sí nos gustaría que hiciera un buen uso de ello. Además, ha de quedarle claro que si lo gasta en otra cosa, no puede pedir luego, a los pocos días/semanas, de nuevo para ropa o el reloj. Ya me decís si lo habéis hablado con ella, para cuándo creéis que es mejor y en qué lo invertirá finalmente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-23','Ana: Llamo al Programa de Familia (927 14 71 14 / 648 69 15 67): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-24','Ana: Llamo varias veces al Programa de Familia (927 14 71 14 / 648 69 15 67) sin éxito, por lo que dejo un mensaje en el buzón de voz pidiendo que se pongan en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-11-24','Ana: Correo de Isabel Molero Vidal, TO - (imolero@caritasplasencia.org // 927 420 448 / 692 528 858): "Buenos días, mi nombre es Isabel Molero, terapeuta ocupacional del CAT (Centro de Acogida) de Cáritas Diocesana de Plasencia. Hace unos días tuve la ocasión de hablar con ustedes para que autorizasen un ingreso de 50 euros para una compra por parte de Ángel Félix Maillo Santibáñez a través de Amazon, me comentaron que este tipo de compras no se pueden hacer a través de su cuenta bancaria por lo que alguien tendría que hacerle el favor de hacerle dicha compra a través de otra distinta a la suya. Le he dicho que lo hago a través de mi cuenta sin compromiso por lo que solicito si es posible dicho ingreso a mi n.º de cuenta para realizarle la compra yo misma y le envíen el producto a la dirección de nuestro centro. Adjunto captura de pantalla del producto con el precio N.º de cuenta" ··············· Desde la Secc. Ecca. le confirman que se autoriza la compra y que le hará transferencia a Isabel, TO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-11-21','Ana: Llamada de Anabel Teomiro, Técnica PIA (22050): ha hablado con Mamen, TS de Centro Vida, le ha informado que primero ingresará en Comunidad Terapéutica. **Me enviarán la ACEPTACION PIA para ingreso en CRR, abierto a todos los centros. *El nº de buzón para el registro: A11030403','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2022-11-24','TERESA Mañana, 25 de noviembre, en Mérida, se va a realizar el "5º Encuentro de Mujeres de Plena Inclusión Extremadura", en el cual, participará Sara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2022-11-25','-Amalia , tras el alta del CRR de Mérida se vuelve a su casa de Miajadas . Autorizo para que pueda sacar su pensión . Le pasaré el caso a Ana cuando esté adaptada a la vivienda . He puesto acompañamiento de Futuex , aunque es solo curatela economica.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-11-25','TERESA Se autoriza 100€ semanales para la compra de alimentación en el supermercado coviran, seguimos el mismo método que cuando estaban en Navas, facilitáis por email la factura y hacemos transferencia. Importa no sobrepasar este limite de 100€. ¿Le vais a poder acompañar vosotros a la compra o preferís que lo haga la compañera de Futuex? ¿Habláis vosotras con el supermercado o es necesario que contacte yo con ellos? Necesitamos el numero de cuenta del supermercado para abonar las facturas. Gracias por vuestra colaboración Buen finde¡','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-25','TERESA SE AUTORIZA REINTEGRO EN SUCURSAL DE LEON POR IMPORTE DE 150€ SE CONSIDERA COMO ADELANTO DE ASIGNANCION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RUIZ'and apellido2='PACHECO'),'2022-11-25','EXITUS Fallecido el 25/11/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-11-28','Ana: Corre de Toni-Futuex: "limpieza efectuada en 18/11/2022 Limpieza vivienda Puerto de la Cruz, : Se acude, con la empresa de Limpiezas Extremas, a la realización de la limpieza de la casa de Javier Agudo. Lleva a 6 trabajadores para proceder con la misma, comenta que para acabarla en la misma mañana. Se repasa aquello a hacer, se le dice que toda aquella ropa y enseres que esté en los embalajes originales lo dejen, al igual que los dispositivos y aparatos electrónicos que encuentren. Cuando estaban finalizando la limpieza, acude la Guardia Civil, una patrulla de Ibahernando, al parecer los llamó el alcalde la localidad, según comentaban, los llamó el alcalde de la localidad al haberle ido, vecinos del pueblo, a comunicar que estaban entrando en la vivienda de Javier y quitando cosas… (las cosas de los pueblos, a veces..) En lugar de acercarse a preguntar y averiguar, directamente llamó a la Guardia Civil. Se les muestra la justificación que se tiene para la entrada en la vivienda, se le envía a su correo electrónico, que por suerte teniamos... si no igual hubiera sido mas lioso todo. Estuvieron pidiendo datos e identificaicon a los trabajadores de la empresa.. en fin. En documento a parte se adjuntan las fotos después de la limpieza. Tambien se adjunta, factura, y se recuerda que está abonado el 50 % que solo resta, el otro 50%. Hay pendiente una factura del apaño que hicieron desde la empresa para poder entrar, en la cerradura, que en cuanto nos la pasen, la enviamos." ················· *Lo que envía es presupuesto, no factura. Se lo digo a Toni. ············ Envío a Paula, CRR, las fotos de la vivienda tras la limpieza para que puedan enseñárselas a Javier, si lo consideran oportuno. ································································································································································································ Correo de Paula, TO - CRR: "Hola Ana, mil gracias por enviarnos las fotos, estoy con Javi y se encuentra muy bien, le ha gustado ver la casa. Me pregunta acerca de dos cosas: • Una cuánto ha costado la limpieza y que empresa la ha realizado. • Otra si se ha podido arreglar la cerradura también. Por su parte, sigue en el proceso para poder irse a piso próximamente (puede ser que en enero)." ········ Informo acerca de la empresa y coste de la limpieza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-11-24','Ana: Correo de Leyre, TS de C. Mayores Ciudad Jardín de Cánovas (t.socialcanovas@grupociudadjardin.com): ", me pongo contacto con ustedes para informarles que el próximo día 28 de Noviembre tiene cita en psiquiatría la tutelada por la Comisión Josefa Sánchez Díaz para informarles que cogeremos a la empresa de Asistencia familiar para el acompañamiento" ·················· Desde la Secc. Ecca. dan el ok.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-11-24','TERESA nos atiende amablemente y tranquilo, comenta que está en León, que ha llamado a Unicaja (no se sabe a qué oficina) para solicitar retirar algo de dinero y que se lo han denegado. Se le ha explicado que el banco no puede decidir sobre eso, que es la Comisión quién debe dar la orden para la retirada de efectivo y que no sabemos si, al no estar en Almendralejo, podrá retirar el dinero que solicita. Pide que le echemos una mano con este tema del dinero poniéndolo en conocimiento de la Comisión. Se le pregunta cómo está y contesta que bien aunque un poco nervioso. Explica que necesitaba salir de Almendralejo porque se sentía muy agobiado y que llevaba siete años sin salir del pueblo. Seguimos preguntándole para recabar algo de información y, aunque se muestra afable, está bastante hermético. Afirma que el camino de Santiago es muy duro y que se ha caído, que no se ha hecho nada pero que ha perdido la medicación (a pesar de que antes nos ha dicho que esperaba comer algo y tomársela), y que va de camino al centro de salud (a veces dice hospital) porque no se encuentra bien psicológicamente (dice estar nervioso) y, según nos cuenta, espera que lo ingresen y cuando se recupere, dentro de unos días, volverá a Almendralejo. Se le pregunta a qué centro de salud/hospital está yendo y solo responde que no sabe, que es en León. Intentamos seguir hablando con él pero comenta que tiene que dejarnos ya y que nos llamará mañana, se le pide que deje el teléfono encendido. Se despide muy amablemente de nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-11-28','Ana: Recibimos del Servicio de Prestaciones Sociales, de la Dirección General de SS.SS., nos solicitan MODELO DE ALTA DE TERCEROS, como consecuencia de la absorción de Liberbank por Unicaja. ·········· Cumplimento, recabo firma y lo paso a la secc. ecca. para cuando vayan al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANO'and apellido2='ARROYO'),'2022-11-28','TERESA RECIBO LLAMADA TECNICO PIA JAVIER PAR NEGOCIAR ME COMENTA QUE ANTONIA ESTA INGRESADA EN JESUS NAZARENO DE CABEZA DEL BUEY (924699946 MAMEN TS) HEMOS ACEPTADO EL CARGO ESTE MES, LE INDICO QUE ME ENVIE EL PIA PARA LA FIRMA DE JOSE VICENTE VALORAMOS ATENCION RESIDENCIAL PUBLICA PERO AUN NO TENEMOS DATOS ECONOMICOS, TIENE UNA HIJA CON PROBLEMAS DE CONSUMO QUE VIVE EN CASAS DE DON PEDRO, POR ARRAIGO VAMOSA SOLICITAR LA FELIPE TRIGO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-11-28','Ana: Llamo a Leire Sanz Gay, TS - Centro de Mayores Ciudad Jardín Cánovas (927 223 221 / 927 214 696): Josefa está al día de pagos con el centro. *Para abonar la plaza aporta el 85% de su pensión y una vez aprobada la Prestación Vinculada al Servicio de la Ley de Dependencia, ésta también se destinará al abono del centro. ················· En cuanto a la cita de hoy en Psiquiatría, finalmente no tiene que desplazarse, pues la van a realizar de telefónicamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-11-28','Ana: Respuesta a Mª Victoria, Aux. Admvo. ASINDI (victoria.adgestion.asindi@gmail.com), en relación al correo con motivo del regalo de Reyes: "Buenos días Mª Victoria, Como en años anteriores, nos parece perfecto y agradecemos que así lo hagáis, contáis con la aprobación del Gabinete Técnico de la CTAEX para destinar 15 € del fondo de cada persona a cargo de la CTAEX, para la adquisición de un regalo acorde a sus preferencias personales. Un saludo y buena mañana."','2');
