insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-11-28','Ana: llamada de sonia Bernabé, ASINDI (927 39 01 93): El viernes a medio día dieron el alta en la UHB a Felisi, llegó "muy muy demandante". El domingo AGREDIÓN a una monitora nueva que está haciendo una sustitución. *Hay parte de lesiones. ··· Activaron el 112, cuando llegaron los profesionales de la ambulancia los saludó muy contenta. La llevaron a urgencias pero de madrugada le dieron el alta y regresó al centro. ········· Me envía Informes de alta de la UHB el V.25 y de Urgencias de ayer 27.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-11-24','Ana: Llamada de Ceferino (641 881 543): dice que tiene "un problemilla", quiere ir el 4 de febrero a la Discoteca Fabric de Madrid a un festival de música. Pero que tiene que abonarlo con tarjeta sí o sí a través de "Travenplan" y como no dispone de una no podrá ir. El precio de la fiesta son 22€ si la compra ahora. ··· *Le explico que ese viaje y la asistencia a dicha fiesta no está autorizado desde aquí, ni siquiera se ha valorado con el equipo técnico del CRR. *Mientras no se autorice no asistirá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2022-11-23','Ana: Envío correo a Toni-Futuex: "En relación a AIDA MARTÍN DE PIÑOL, necesitaríamos INFORME ACTUALIZADO y firmado para remitir al Juzgado, en que detalléis las intervenciones que habéis llevado a cabo desde el programa de apoyo comunitario, los impedimentos que os ha puesto para la realización de visitas o gestiones varias, así como la situación actual en que se encuentra. El Juzgado nos lo ha solicitado porque ella misma ha solicitado la remoción del cargo y, entre otras cuestiones, argumenta que no recibe la atención que precisa y solicita por parte de la CTAEX. Os podéis imaginar las cuestiones que relata: no se le compran gafas, no se le arreglan los desperfectos de la vivienda, ni se le compran los electrodomésticos que necesita… entre otras cuestiones. Me comunican que se precisa con urgencia. Gracias de antemano."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-28','TERESA Buenos días compi !!! El sábado estuve con José , me ha dicho que la directora le ha puesto a firmar dos papeles pero no sabe para que son , esta igual que siempre , con su complejo de que está muy delgado, dice que está muy aburrido , le he propuesto llevarle unos libros pero no quiere ... por lo demás a mi no me dice que se quiera venir ..creo que empieza a adaptarse ... cruza los dedos Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='CANCHALES'and apellido2='MALDONADO'),'2022-11-28','miguel, hablo con Julia Marquez 683685875 de la asesoria, Luis Marquez, quien me confirma que no tienen información y no se hizo nada en su día. Quedo en darle su teléfono al primo de la madre fallecida de la tutelada (fallecieron también sus dos hermanas, es decir las tías de la tutelada). Según me dice Fernando Canchales (605982215) primo de la madre, vivieron las 4 juntas. Quedamos en que Fernando llamará a Julia Marquez para intentar aclararle lo que pueda de esta herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-11-25','Mira este documento. Eso es lo que debes pedir de tu taller de empleo, lo que viene en el reverso. Si no te lo facilita el SEXPE (o el ayuntamiento, si tuvieran algo: solicitud de homologación y resolución de la consejería autorizando el desarrollo del taller con x condiciones), a ver si lo puedes localizar de alguna alumna','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2022-11-28','Ana: Recibimos resolución aprobatoria de la P. Viudedad: 1.051,91 €/mes x 14. ····················· Acompaña otra resolución en la que indican que se suspende la PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2022-11-07','Ana: Paso a Julio para REGISTRO y envío oficio dirigido a PABLO GUILLEN CARO, habilitado, adjuntando la DECLARACIÓN JURADA de pensionista de clases pasivas, debidamente firmada, y solicitando el Certificado Actualizado de las Pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2022-11-28','Ana: Recibimos certificados actualizados de las Pensiones de PFHC - ISFAS (417,70 €) y Orfandad - Clases Pasivas - Familiar de Militares (703,50 €). ···················· Se los remito a Longina, TS de Madrigalejo (ssbmadrigalejo@hotmail.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2022-11-28','TERESA RENDICION ANUAL JOSEFA RESIDE EN LA RESIDENCIA DE MAYORES DE CASTUERA DESDE EL 2020 ES ENCUENTRA BIEN ADAPTADA E INTEGRADA Y PARTICIPA DE LA VIDA DE LA RESIDENCIA EN LA MEDIDA DE SUS POSIBILIDADES TIENE RELACION CON UNA AMIGA LA CUAL LA VISITA EN OCASIONES Y LA LLAMA POR TELEFONO PARA INTERSARSE POR SU ESTADO DE SALUD PERCIBE PENION ORFANDAD ABSOUTA 720€ SALDO 9.700€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-11-28','Ana: Reenvío a Paula, TO CRR-Plas, correo de Ceferino: "Buenos días. Necesito la Pioneer DJ 800 para trabajar. Lo digo porque ahora más que nunca me solicitan pinchar por streaming y quieren que pinche. Por Facebook, TIk TOk, Instagram. Soy un dj muy solicitado en streaming. Quiero trabajar" y le pregunto por los nuevos objetivos y compromisos acordados con él en el CRR. ····································································································································································································· Nuevo correo de Ceferino solicitando dinero para ropa. ······· Respondo que haga la solicitud a través del centro y recuerdo que tiene un extra anual que se gestiona en el centro que también podría invertirlo en ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-11-28','Ana: Remito correo a Julio, Aux. Admvo. CTAEX: "Te envío adjunta la solicitud de ingreso en centro, vía decreto, relativa a D. JUAN GREGORIO LOZANO VALLE, junto a la siguiente documentación - Declaración Jurada de Bienes del Solicitante - Informe Médico - Informe Social - DNI solicitante - Certificado de Empadronamiento - Certificado de Pensión - DNI Presidente CTAEX - Decreto de Nombramiento de José Vicente - Resolución de Delegación de Competencias Parar registrar y remitir, cuando puedas, a: SECCIÓN DE CENTROS II"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-11-28','Ana: Llamada de Doroteo (609 928 621): Dice que se debe a El Corte Inglés 17,40€, de una tarjeta que tenía. Es una deuda de 2011. Le llaman de vez en cuando para reclamar este importe. Le gustaría pagarlo. ····· Lo comunicaré a la secc. ecca. ··········· Por otra parte dice que se encuentra bien e informa de que está haciendo 3 "cursillos": Informática, Inglés y otro para mejorar la memoria. Los termina en febrero-marzo. ···· Para esta fecha le gustaría irse del centro. *Le gustaría vivir solo. Ya estuvo viviendo sólo durante un año antes de que le incapacitasen. Asistía a Feafes. ········ El viernes tuvo cita en el ESM, con la TS, Pilar Martín, y con la Psiquiatra. *Pilar volvió a plantearle el ingreso en CRR. Pero dice que quiere vivir solo. ················ Volverá a llamarme para hablar del asunto pasadas la fiestas de navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='VARGAS'and apellido2='SUAREZ'),'2022-11-28','TERESA RENDICION ANUAL DIEGO RESIDE EN EL CAM DE DON BENITO TIENE SOLO CON UNA DE SUS HERMANAS QUE FUE SU TUTORA, YA FAFLLECIDA CON EL RESTO DE HERMANOS NO TIENE RELACION SON TRES EN TOTAL TIENE UN 78% DE DISCAPACIDAD ESTA BIEN ADAPTADO AL CENTRO PERCIBE PENSION 726,92€ SALDO 3300€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-28','Ana: Llamo al Dr. Enrique Jaramillo, Ud. de Geriatría del HSPA (927 25 15 74): el numero no está disponible. ··········· Desde centralita del Hptal. me pasan con el control de Geriatría (56899) me pasan con el despacho médico, pero tampoco obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-25','Ana: En mi ausencia Tere intenta llamar al Dr. Enrique Jaramillo, Ud. de Geriatría del HSPA (927 25 15 74): el número no está disponible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-11-28','Ana: Conversación con Felisa Custodio, TS del CAMF-Alcuéscar (927 38 41 25 -- Ext. 46138): En relación a la asignación mensual de Esther, enviará un correo al ctutelar@ a la att. de la secc. ecca., detallando una propuesta para los siguientes conceptos: tarjeta prepago de teléfono y tabaco principalmente. En el centro cuenta con los productos de higiene necesarios. ·················· Al preguntarle por ella, dice que en su día la derivaron al Psicólogo, pues solía utilizar el chantaje emocional del tipo "Me voy a quitar la vida", cuando no conseguía lo que quería, pero luego estaba bien, es una conducta aprendida. ········ Desde que se la han anulado las tarjetas bancarias y bloqueado las cuentas, le pregunta con frecuencia y envía correos-e diarios para quejarse y pedir dinero. ······· *Ella le ha explicado que se trata de una MEDIDA DE PROTECCIÓN y los puntos positivos + ventajas que tiene para ella y parece entenderlo. ················· *Ha hablado con Miguel, su pareja, en relación al dinero que éste le da, pues fomenta las conductas consumistas. Miguel parece razonable, pero debe seguir dándole dinero, pues a diario acude a la cafetería a consumir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-11-16','Ana: Correo de Toni-Futuex con información acerca de la primera visita tras la derivación: "En un principio, se mantiene reunión con Manuel y su padre, más tarde, se une también la madre. Durante toda la visita se aprecia gran tensión entre los padres y Manuel, de forma constante le están juzgando, le transmiten total desconfianza, echando situaciones en cara, bien que hayan sucedido hace poco tiempo o desde hace años… Se intenta mediar y explicar que tampoco es aconsejable esa actitud, pues transmitirle confianza va a favorecer su accesibilidad. Manuel vive centrado, exclusivamente, en conseguir la remoción de la tutela, ir a vivir de forma independiente y no tener que rendir cuentas a nadie… Según comenta, ya ha buscado un abogado y está pendiente de que le llegue la citación judicial, según indica será en noviembre, para solicitar dicha revisión. Este hecho tiene a los padres bastante nerviosos, se les explica que Manuel está en su derecho de solicitar dicha revisión, pero tiene que ser consciente de sus limitaciones y de sus necesidades; se le explica la tutelado que como cualquier persona, pero debe ser consciente de que necesita una supervisión y unos apoyos, que no debe traducirlos en control, sino en apoyos para aquellas actividades más complejas o para las que tenga mayores dificultades. Sin embargo parace que su mayor interes es disponer de su dinero y hacer vida independiente, cuando sabe que no se gestiona de forma adecuada. Manuel señala que irá "aprendiendo a base de golpes, si este mes se gasta todo, para el siguiente ya se organizará diferente" (sabemos que esto no funciona así, pero este es su argumento).", pretende vivir de ayudas y prestaciones sociales. No muestra interés en ninguna ocupación. ········ "Su día a día ahora es completamente sedentario, no hace actividad alguna, salvo ir al bar. Su padre le administra el dinero mensual, al día, ahora, le está dando 5€ y le compra un paquete de tabaco; le daba 10€, pero se lo bajó porque el mes pasado estuvo consumiendo, fumó porros y no fue a los controles del CEDEX, a los que acude todos los martes." ········ él dice que sólo faltó el mes pasado, no volvió a hacerlo y le sigue control Marisa, TS. ······· "en salud mental sigue sin haber psiquiatra y es por ello que no se le ha revisado; el inyectable acude cada 28 días" ········ "En principio acepta los seguimientos, pero siempre haciendo alusión a que primero quiere pasar la vista judicial y luego ya va viendo" ······· Le plantean la búsqueda de alguna ocupación o actividad de ocio saludable y no lo descarta, pero tampoco parece realmente interesado. ··········· La posibilidad de irse a RR residencial la descarta por completo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-11-10','Ana: correo de Toni-Futuex: "Buenas dias Ana, es algo que habia valorado y estaba esperando a hablarlo con ellas en persona, que me reuno mañana. Ya que no queria que en ningún caso, se generará ningun tipo de mal entendido. Estoy muy satisfecha de la intervencion que ha intentado con tesón la compañaera, solo que aveces.. se produce este bloqueo por parte de los tutelados, como bien saben, rechazan frontalmente cualquier apoyo que se le quiera proporcionar. Fijate como son las cosas, que empezo a ver una educadora porque rechazó a la otra... osea que lo que esta pasando ahora, ya ha pasado, y de hecho me llama la atención que ahora hable bien de Gloria, porque precisamente, lo llevaba ella y decidimos cambio, porque no la podia ver.. pero bueno probaremos a ver que tal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2022-11-29','-Amalia : pongo a firma modelo alta a 3º para enviar a PNC .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-28','Ana: Correo de Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "te comentamos que Julia hoy tras " visita" de su padre y tras discusión con él se ha ido al pueblo. No hemos tenido conocimiento hasta que estaba en el autobús, se acuerda el regreso mañana en autobús, lo que cual en principio acepta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-11-29','PERCIBE P. ORFANDAD CLASES PASIVAS. DESCONOZCO SI ALGUNA DE LAS 2 MUJERES CON LAS QUE ESTUVO CASADO PERCIBEN P. VIUDEDAD ( SE LE DIÓ PRIMERO POR DESAPARECIDO Y LUEGO FALLECIDO ) . NO SE LE PIDE P.F.H.C DE CLASES PASIVAS PQ SON INCOMPATIBLES MAS DE 2 PENSIONES AUNQUE SEAN A DISTINTOS FAMILIARES POR EL MISMO CAUSANTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-11-29','Ana: reenvío a Óscar, Secc. Ecca, los datos que me facilita Laura Salguero, TS ONCE-CC, para el abono de las vacaciones de navidad de Ventura ya aprobadas previamente. ·················· Llamo a Laura (927 627 480): Ventura las últimas veces que ha hablado con él le ha dicho que quiere "su curatela". *Sólo cuenta lo que le interesa y a quién le interesa. La intervención con él le está resultando complicada. ··································································································································································································· Correo de Toni-Futuex: "...si que intentamos lo de Ventura.. y bueno... a ver si da algun tipo de resultado distinto, de momento, se coordinó la compañera con la ts de la peña del cura, con la intención de hacer una visita conjunta." ··································································································································································································· En cuanto a la información que me facilitó Julia Durán, TS del Hogar Peña del Cura: "-La cuenta bancaria la ha traslado a Unicaja desde la Caixa. -La alarma ha sido instalada por Moviestar, se desconoce el coste y como abona la cuota mensual. Al instalar la alarma le han "regalado" un ordenador portátil. Así mismo he dado traslado de las deficiencias en la vivienda al Administrador de la comunidad. Me insiste en ser el propietario de la vivienda, pese a no constar en la comunidad como tal.", reenvío correo a Alberto, Secc.Ecca, y a los A. Jurídicos CTAEX. ········ Respuesta de Ángel: "Puedo responder lo relacionado con la propiedad del inmueble, que efectivamente le corresponde a Ventura. La vivienda en cuestión, la compró su difunta esposa y la incorporó a la sociedad de gananciales. Al fallecer, Ventura dejó de pagar la hipoteca y el Santander inició un procedimiento de Ejecución Hipotecaria que se ha declarado nulo, porque no reclamaron a los herederos de la mujer, que eran sus padres. A pesar de esta circunstancia, el banco vendió la vivienda a un tercero, con al que seguimos pleiteando, con lo que Ventura continua en la vivienda, a título de propietario." ·············· Miguel pide: "si es posible te remita justificante de cualquier servicio contratado…movistar, nueva cuenta…Vamos a requerirles a anularlos por ser nulos dichos contratos" ········ Traslado ambas peticiones a Julia, TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-11-23','Ángel. Se dicta Auto autrorizando a que Agustín le de 10.000 euros a su hija. No es firme. Se dictó el 15/11/22, con lo que será firme a partir del 15/12/22. A partir de entonces, solicitaremos testimonio de la firmeza del Auto y un número de cuenta donde realizar la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-11-29','Ana: correo de Sheila, Directora del CRR-CC (crr@grupociudadjardin.com): "Informaros de que la persona usuaria Consuelo Nevado Pacheco se encuentra ingresada en la UHB por desestabilización de su patología de base. Os iremos informando de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-11-29','Ana: Llamada de Juana Mari, Aux. Advo. ESM Coria (70838). Le dan cita en Psiquiatría el próximo 13 de diciembre a las 16:00 h. en el Hospital San Pedro de Alcántara - CC. Le atenderá la Dra. Donoso Jiménez. ··································································································································································································· Envío correo a Toni-Futuex: "En relación a MANUEL DOMÍNGUEZ MARTÍN, me ha llamado Juana Mari, Aux. Advo. Equipo de Salud Mental de Coria. Le dan cita en Psiquiatría el próximo 13 de diciembre a las 16:00 h. en el Hospital San Pedro de Alcántara - CC. Le atenderá la Dra. Donoso Jiménez. Le enviarán a citación. No creo que a esa hora podáis acompañarle, quesería lo ideal, pero al menos, por favor, informarle de la cita y ayudarle a organizar el desplazamiento, que es importante que acuda." ································ Respuesta de Toni: "ajustando el horario de la mañana para salir antes o algo asi.. se lo planteare a las compis, y confio en que no habra inconveniente, seria bueno acompañarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2022-11-28','TERESA Acordamos autorizarte para la retirada de reintegro mensual del dinero de bolsillo de Jose Gonzalez Fernández ante la imposibilidad de retirarlo él mismo en la localidad de Medina de las Torres donde se encuentra residiendo actualmente por no haber sucursal de Ibercaja. Para que puedas retirar el dinero necesito me facilites Nombre Apellidos y DNI para enviar la autorización a Ibercaja de Monesterio. Puedes pasar a retirar la asignación la primera semana de cada mes, empezamos ya en diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-11-29','Ana: Icíar, Secc. Ecca, me comunica que el V. 25 ingresaron la pensión con la extra a Juan Gregorio en su antigua cuenta, aún no se ha procedido al cambio. Y el hijo ya ha retirado prácticamente todo entre el vienes y el domingo, desde el cajero con la cartilla bancaria. Le ha dejado sólo 318 € en la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-11-09','Ana: Correo de Julia Durán, TS del Hogar de Mayores Peña del Cura(julia.duranm@salud-juntaex.es): "tras entrevista realizada con D. VENTURA GOMEZ GARCIA, te envío la información que me habías solicitado: -La cuenta bancaria la ha traslado a Unicaja desde la Caixa. -La alarma ha sido instalada por Moviestar, se desconoce el coste y como abona la cuota mensual. Al instalar la alarma le han "regalado" un ordenador portátil. Así mismo he dado traslado de las deficiencias en la vivienda al Administrador de la comunidad. Me insiste en ser el propietario de la vivienda, pese a no constar en la comunidad como tal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-29','Ana: Llamo al Dr. Enrique Jaramillo, Ud. de Geriatría del HSPA (927 25 15 74): el numero no está disponible. ···········Llamo a control de Geriatría (56899) El Dr. Jaramillo no está, pero me pasan con otra Dra. Julia Molano, está más o menos estable, presenta demencia severa, GDS 7, no está indicado sonda nasogástrica. Va tolerando pequeñas cantidades de alimento. *Si la radiografía que le hacen hoy está bien, esta misma tarde le darán el alta. Llegó con deshidratación, pero ya está mejor también en ese aspecto. ·························· *Lo comunico a Lucía Ávila, Directora de la Res.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2022-11-29','Ana: Correo de Felisa Custodio, TS del CAMF (trabajadora_social_alcuescar@imserso.es): "Estimados compañeros, estoy con Esther viendo sus gastos fijos mensuales tal y como hablamos por teléfono, me dice que son: 15 euros tarjeta prepago. 45 euros cartón de tabaco. Productos de aseo:10 euros, hemos quitado el gel porque se lo da el centro. Total para su libre disposición: 70 euros." ··············· *Se autoriza por la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SALGUERO'and apellido2='CAPOTE'),'2022-11-29','ALBERTO MARTIN ROSETE ICIAR ROSA REYES;Amalia Diaz Gonzalez;ESTRELLA MARIANA GUERRERO PEREZ ICIAR: TELEFONO IBERCAJA SANTA MARINA 924252350 PAOLA DURÁN REINTEGRO PERMANENTE X 100 €/MES A PARTIR 01/12/2022. REINTEGRO PUNTUAL "EXTRA NAVIDAD" X 100 €, ENTRE LOS DÍAAS 14/12/2022 Y 21/12/2022. ICIAR: URGENTE: ABRIMOS OTRA CCC EN LA QUE ESTÉ ELLA SÓLA----JULIO (DIRECTOR CR LA GRANADILLA) PIDE QUE SEA EN UNICAJA. UTILIZAR LAS 2 CCC UNICAJA EN LAS QUE ESTÁ DE TITULAR ELLA SOLA ESTARÍA BIEN PERO PUEDE QUE TENGA DEUDAS ANTERIORES QUE CONSUMAN LO QUE INGRESEMOS: HÁBLALO CON JUANA ANTES DE HACER EL CAMBIO DE NÓMINA. SI NO ES EN UNICAJA, LO HACEMOS EN IBERCAJA. IMPORTANTE: PÁSALE EL Nº CCC NUEVO A AMALIA PARA EL CAMBIO DE PENSIÓN IMPORTANTE: CUANDO TENGAMOS NUEVA CCC TIENES QUE CAMBIAR EL REINTEGRO PERMANENTE!!! + LA ÚNICA DOMICILIACIÓN DE TELEFONÍA Y DE CENTRO. IMPORTANTE: CUANDO TENGAMOS NUEVA CCC PASAMOS LA TOTALIDAD DEL SALDO DE IBERCAJA ANTIGUO. AMALIA: TENEMOS HOY DE SALDO 3.000 €/APROX....HABLAR CON JULIO PARA ABONAR PARTE DE LA DEUDA QUE MANTIENE CON EL CENTRO....LÍMITE ENTRE 1.500 € Y 2.000 €. ESTRELLA: PENDIENTE SEGURO DECESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-11-29','Ana: Llamada de José Manuel, esta tarde a las 16.30 acudirá a Feafes Extremadura a un taller. Le ha derivado Pilar Martín. ··············· Mañana a las 10:30 van a valorarle el Equipo de Valoración de Dependencia. ······················ El día 5 tiene cita con Pilar Martín, TS ESM ·········· El 9 cita para radiografía del brazo en el HUC, no recuerda el horario, lo tiene anotado. ···· En mayo le toca el inyectable. ········ **Este viernes día 2 a las 11 h cita en el CRPS para la entrevista, para valorar su acceso al RR. ································································································································································································ A parte de todo esto, me cuenta que ha vendido el último móvil que compró por 80 € y se ha comprado "un zarrio" por 75 €. Pregunta cuándo podrá enviar nuevo presupuesto para teléfono... ·································································································································································································· Correo de Anabel Teomiro (ana.teomiro@salud-juntaex.es): "BUENAS TARDES ANA, ACABO DE HABLAR CON JOSE MANUEL ROMERO MEDIAVILLA, VOY A IR EL LUNES 5 AL DOMICILIO, LE HABIA DICHO MAÑANA PERO ME VIENE MEJOR EN LA RUTA DEL LUNES. SALUDOS" ··········································································································································· Correo de Toni-Futuex: "...he hablado antes con Pilar Perz de CIS de Cáceres, (Programa de Integracion social para personas con TMG de Cáceres Area) es un recurso que están iniciando, que lo gestiona ahora Feafes salud mental Extremadura, ya que anteriormente está gestionada por Feafes Cáceres y bueno ya sabes que terminaron mal con los recursos que llevaban. Yo he estado hablando estos dias con esta persona, que parece que está muy implicada con los usuarios, por otra tutelada, y hoy me ha llamado para indicar que está alli Mediavilla... A ver, que ojala enganche porque le puede venir muy bien el recurso, hacen sobre todo actividades de ocio está gente.. pero claro ya ha les ha contado y les ha demando lo de siempre, que si no tiene dinero para nada.. que si ha sentido el impulso de volver a ir al banco con la cartilla para que le den dinero, porque quiere un movil.. y etc. Me ha dicho que el, les habia facilitado tu número y que te iban a llamar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-11-29','Ana: Correo de Leire Sanz Gay, TS - Centro de Mayores Ciudad Jardín Cánovas (927 223 221 / 927 214 696), envía un escrito que, según dice, en su día envío a Amalia, en que expone: "Que el Precio de la Plaza en habitación compartida es de 1750 € /IVA, que se comprometió Gerencia en mantener el 85% de la pensión y el 50% de las pagas extraordinarias y que la subvención obtenida de la Ley de la Dependencia con G.II (397/426) fuese integra para la Residencia Ciudad Jardín Cánovas" ············· *Se reenvío a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-29','Ana: Correo de Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "Buenas Ana, Julia no ha regresado hoy, nos comenta que la persona del autobús no la ha dado permiso para montar en él por experiencias previas con ella. Vuelve mañana. Os comento. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2022-11-23','Antonia Casquero Jaén ha ingresado en hospital , he autorizado a un par de horas de acompañamiento hospitalario con una empresa , enviarán facturas semanales y las abonaremos directamente por transferencia . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-11-30','Ana: Llamo a Control de Pensiones del INSS (927 62 00 62): Me confirman que la nómina de diciembre ya se la ingresarán en la nueva cuenta de Unicaja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2022-11-30','TERESA De nuevo a domiciliado el teléfono en la cuenta, anteriormente lo pagaba la madre desde su cuenta. Los importes de las factura son muy elevados llegando a los 200€ por lo tanto hemos procedido a devolver los recibos. Rosario no para de llamar para que no le demos de baja a la línea de teléfono, yo le he explicado la situación y dice que ya ha dado de baja a lo que había contratado. Se ha presentado en el banco con el juez de paz para que no devolviéramos los recibos. Yo le he dicho a la madre que domicilie el teléfono en su cuenta y que nosotros le haremos transferencia permanente de 70€ para que pague las facturas de teléfono, así todo lo que supere ese importe lo tendrá que asumir la madre y no tendremos que estar devolviendo recibos. Es difícil comunicarse con ella por ello que la delegada le explique todo y nos facilite el numero de cuenta de la madre para hacer esta operación si ella está de acuerdo. En el caso que no acepte desde la comisión se van a seguir devolviendo todos los recibos que vengan de telefonía pues nos ha demostrado que no nos podemos fiar de ella pues al cabo de un tiempo vuelve a contratar paquetes que disparan las facturas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-11-30','Ana: Correo de Blanca, Directora CRR (direccion.crrplasencia@grupo5.net): "Buenas Ana, Julia ha vuelto está mañana. Os vamos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-11-30','Ana: correo de Lucía Ávila, Directora de la Res. (luciaavilasanchez67@gmail.com): "Buenos días, anoche sobre las 21h. aprx. regresó a nuestro centro el Sr. Felix Amado Narciso ( en un estado lamentable y no me refiero a la situación basal que ya sabíamos que no era buena ) cuando regresan del hospital tenemos por protocolo. ducharlos y revisarlos. A éste Sr no se le ha afeitado en 10 dias, tampoco se le han realizado cambios posturales ( solo quiero dejar constancia de como ha regresado, igual que un indigente....por lo que hacemos fotos para su expediente)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-11-30','Ana: Llamo al Programa de Familia (927 14 71 14 / 648 69 15 67) hablo con Patricia, Psicóloga. Pilar tiene el SAD todos los días. *NO tiene móvil, y según el criterio técnico del equipo, es mejor que no lo tenga, pues cuando lo tenía no hacía un uso adecuado del mismo. ··· Le parece bien la derivación al Programa de Apoyo Comunitario de forma complementaria a la intervención que hacen ellas. Pilar es sociable y abierta y cree que podrá aceptar bien a la compañera. ········ Con la hija, que vive en Inglaterra, actualmente no tiene contacto. ·········· *Acordamos que nos remitirán presupuesto aproximado de gastos de bolsillo y le preguntarán a Pilar por el Seguro de Decesos, cree que están pagando uno en el que están incluidos los dos hijos. En tal caso intentará hacernos llegar la póliza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-12-01','Ana: Envío a Toni-Futuex, correo para derivación de Pilar al Programa de Apoyo Comunitario. ········· Respuesta de Toni: "Nos ponemos a ello para poder hacer un seguimiento en breve."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-12-01','miguel, contestación a la abogada: Estimado Miguel, el encargo profesional fue de los tres hermanos, por lo que le he enviado a cada uno la minuta de honorarios correspondiente al trabajo como abogada realizado conforme a ese encargo y dividido en tres partes. Las hermanas Ines y Marijose no están de acuerdo con este planteamiento diciendo que como son cuatro herederos, se divida en cuatro partes el importe cobrado a los tres hermanos, lo cual no puede ser porque el encargo lo recibí de los tres y así les he minutado, a cada uno su tercera parte. Por otra parte, como he realizado labor profesional y gestiones correspondientes también al heredero José Luis (aunque no es mi cliente) le he enviado una minuta por esas tareas realizadas a su favor, que son: - Realizar el borrador de la Escritura de Herencia enviado a la Notaría de Azkoitia asignando los valores a todas las fincas heredadas. - Un vez firmada la escritura de herencia la presenté presencialmente a la Hacienda de Tolosa, con escrito de solicitud y dos impresos correspondientes al heredero José Luis, uno por parte de su padre y otro de su madre. Presenté también por correo certificado y acuse de recibo al OAR de Badajoz en relación a las fincas sitas en dicha provincia. También me encargué de presentar para la inscripción de las fincas a nombre de los cuatro herederos en el Registro de Azpeitia (piso de Azkoitia) presencialmente y en el Registro de Castuera (Fincas de Badajoz) enviando la documentación por correo certificado y con acuse de recibo. - Respecto a las ventas de las fincas, me encargué de la gestión para las valoraciones de las fincas sitas en Badajoz, encargando dicha tarea al arquitecto Javier Machío; si bien de la venta de la finca de Azkoitia se encargó la inmobiliaria Alberdi de Azkoitia, en cambio, yo me encargué de la venta de la finca sita en calle Malavé nº 47 de Valle de la Serena (Badajoz) contactando con los compradores, elaborando el contrato de Arras, enviándolo para su firma y explicándolo a los compradores sobre las cláusulas de dicho contrato antes de la firma, además de las gestiones con la representante del Banco Santander en Valle de la Serena a causa del préstamo hipotecario solicitado por los compradores y que el banco tardó muchísimo en concedérselo, a causa de sus dudas sobre la solvencia económica de los compradores. Numerosas reclamaciones a los compradores y a la gestora por dicha demora e incumplimiento del contrato de arras. Coordinar la venta entre la Notaría de Don Benito (contactos telefónicos y por mail con Rafael, encargado de la Notaría) y la notaría de Azkoitia, y envío de la documentación necesaria para la venta. Para la venta de la "finca de la Viña" sita en valle de la Serena realicé el borrador de la compraventa enviándolo a la Notaría de Azkoitia con los datos y envío de documentación. La labor arriba detallada es la que se minuta en la factura número 1020 al heredero José Luis Murillo Horrillo, por importe de 1.216€ más IVA, que en la Comunidad Autónoma del País Vasco no es nada "desorbitada" como usted afirma. Le envío nuevamente la factura detallada y rebajada, porque puedo entender que en Badajoz no se minute como aquí y en función de ello la rebajo. Quedando a la espera de sus noticias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-12-01','TERESA Buenas, ya hemos hablado con Toni, y con el taxi, se la recoge a las 11.00h Nos falta hablar con el camp que hoy no estaba la ts, mañana llamamos para avisar de la hora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-11-30','Ana: correo de Toni-Futuex, al ctutelar@: "Buenas tardes, tal y como hemos acordado en conversación telefonica, se hace llegar factura pendiente de abono, de reparación de cerradura de la casa de Javier Agudo, por la empresa de limpiezas. Contacta Miguel para hacer llegar la factura de los gastos derivados de la apertura de la puerta, la puesta de la cadena y el candado. Parece un coste algo elevado, pues la puerta era sencillo abrirla, aunque es cierto que se tomó la molestia de desplazarse a Trujillo y mirar en otras localidades si había posibilidad de encontrar una cerradura para sustituir, siendo imposible porque ya no se fabrica. Fue una situación de urgencia, dadas las caracteristicas de la cerradura, la lejania del pueblo y demás factores, la unica opcion existente fue esta, el que se hiciera este arreglo para poder acceder a la vivienda" ··············· Informo a Paula, TO del CRR para que le comunique el tipo de arreglo de cerradura a Javier.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2022-11-30','Ana: Correo de Toni-Futuex, adjunta el informe solicitado para remitir al juzgado: "Hemos intentado reflejar los seguimientos que se han realizado en este año, resaltando lo mas siginificativo, sobretodo en lo relativo a sus mentiras y su incapacidad en general para autogestionar su dinero y la forma de vincularese con los demas, especialemnte con Leandro, objetivandose una relacion de dependencia. Nos ha sido, como sabes, muy complicado acceder a ella, porque rechaza los seguimientos, planteando excusas inverosimiles o simplemente no atendiendo al telefono.. resultado sorprendente para nosotros por ejemplo lo ultimo acontecido de su supuesto viaje a EEUU este verano, del que desconocemos si ralmente se ha hecho y con que prevision y dinero.. pero lo que si es cierto que estuvo desaparecida, durante varias semanas.. (no se si alli, sabiais el tema este de ese supuesto viaje, que no hemos tenido tiempo ni de comentar , entre unas cosas y otras)" ··········· Reenvío el informe a los A. Jurídicos. ······ Lo guardo tb en el expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-11-30','miguel, recibo email de Ana de Pablo: Estimado Miguel Angel, adjunto le envío minuta de honorarios correspondiente a José Luis Murillo Horrillo por mi intervención profesional en relación a la herencia de D. Luis Murillo Ocampos y Dña. Ines Horrillo Carmona y posterior venta de alguna de las fincas heredadas. Quedando a su disposición para cualquier aclaración, reciba un cordial saludo **************************************************** email de Ana de Pablo a los hnos del tutelado con copia a nosotros: Estimados Ines, Marijose y Ander después de recibido el mensaje de correo electrónico de Mª José suprimí el primer concepto de la minuta consistente en "Asesoría jurídica, estudio y preparación de Herencia de D. José Luis Murillo Ocampos y Dña. Ines Horrillo Carmona", por los motivos que expuse en mi correo de 3 de noviembre, a pesar que en el borrador de la escritura enviado a Notaría establecí los valores a otorgar a todas las fincas, por encima del valor de mercado para que fiscalmente no tuvierais que declarar ganancia patrimonial como consecuencia de la venta posterior de las fincas, y en esto os asesoré a los tres. En consecuencia, los honorarios de las tres facturas modificadas, una a nombre de Inés (nº 985) otra a nombre de Mª José (nº 984) y otra a nombre de Ander(nº 986) responden al encargo profesional recibido por los tres hermanos a partir de la firma de dicha escritura, minutando a cada uno en proporción al trabajo realizado como abogada dividido en tres partes y añadiendo a la factura de Ander lo correspondiente al primer concepto suprimido a las hermanas Mª José e Ines. Los conceptos por los que se minuta son los siguientes: "1ª.-Gestiones sobre la Escritura de Herencia ante Hacienda de Gipuzkoa, Ayuntamiento de Azkoitia, OAR y Registros de la Propiedad de Azpeitia y de Castuera (Badajoz)". Después de firmada la Escritura de herencia hay que llevarla a Hacienda (Tolosa es la delegación de Hacienda más próxima a mi despacho) donde se presentan cumplimentados los impresos 670, dos por cada hermano en relación al padre y en relación a la madre fallecidos. También hay que presentar la escritura ante el Ayuntamiento de Azkoitia (donde radica la vivienda de kale Nagusia 30 y se hizo personalmente la gestión) y ante el OAR (en relación a las fincas sitas en Badajoz, en este caso se envió por correo certificado y acuse de recibo la documentación). También, para la inscripción registral de las fincas a nombre de los herederos se llevó la documentación y se hizo la solicitud de inscripción al Registro de la Propiedad de Azpeitia (gestión presencial) y se envió por correo certificado y acuse de recibo al Registro de la Propiedad de Castuera toda la documentación necesaria y escrito de solicitud de inscripción, con abono del envío y retorno de la documentación. Todo ese trabajo, incluidos desplazamientos y envíos de documentación, contactos telefónico y por correo electrónico, redacción de escritos e impresos se minuta en 1.180€ sin IVA. "2ª.-Intervención profesional para tasaciones de fincas de la herencia sitas en Valle de la Serena (Badajoz) y para venta de la finca sita en calle Malavé nº 47 de Valle de la Serena (Badajoz). Contrato de Arras y gestiones con la gestora del Banco Santander y el comprador de la finca, así como con la Notaría de Azkoitia y de Don Benito (Badajoz). Trabajo consistente en contactar con el tasador de las seis fincas sitas en Badajoz y explicarle la situación jurídica de las mismas (respecto del valor dado en escritura de herencia para evitar que exista ganancia patrimonial en caso de venta) y contactos para que acuda a realizar las tasaciones. Gestiones para la venta de la casa sita en Malavé 47 de Valle de la Serena: con los compradores, redacción del contrato de Arras, envío para su firma, aclaración a los compradores de las cláusulas del contrato y gestiones con la representante del Banco Santander en Valle de la Serena a causa del préstamo hipotecario solicitado por los compradores (que recordemos tardaron una eternidad en concedérselo a causa de las dudas sobre la solvencia económica de los compradores). Numerosas reclamaciones tanto a los compradores como a la gestora por dicha demora. Trabajo consistente también en coordinar la venta desde la Notaría de Don Benito (contactos telefónicos y por correo electrónico con Rafael, el encargado del asunto) con la Notaría de Azkoitia, y envío de la documentación necesaria para la venta. Esta intervención profesional se minuta en 1.216€ sin IVA sin la intervención para la venta de ninguna agencia inmobiliaria, cuando para la venta del Piso de Azkoitia la inmobiliaria Alberdi facturó 2.370€ sin IVA por su "intermediación inmobiliaria realizada en la compraventa de la vivienda sita en Azkoitia". "3ª.- Gestiones con la Comisión Tutelar de Adultos de la Junta de Extremadura para solicitar la Aprobación Judicial de la Herencia y para la Autorización Judicial de venta de las fincas y gestiones en relación con las intervenciones 1ª.-, 2ª.-, 3ª.- y para la venta de la finca sita en calle Nagusia nº 30 de Azkoitia". Por los contactos y comunicaciones necesarios a la Comisión Tutelar de Adultos de la Junta de Extremadura en relación a la Herencia de D. Luis Murillo Ocampos y Dña. Ines Horrillo Carmona y a la posterior venta de algunas de las fincas heredadas. Se minuta esta intervención en 993€ sin IVA. No se ha incluido en la minuta las gestiones con inmobiliaria Alberdi en la venta del piso de Azkoitia en representación de la parte vendedora, ni la asistencia a la firma de dicha venta en la Notaría de Azkoitia. Tampoco se ha incluido el encargo a la Notaría de Azkoitia para la venta de la "finca de la Viña" sita en Valle de la Serena, ni la redacción y envío del borrador de dicha venta a la Notaría y documentación necesaria para la venta (y de otro borrador, propuesta de extinción de condominio que no se llevó a cabo porque la Junta no está interesada en la adquisición de los terrenos) ni, por supuesto, está incluido el examen y liquidación de las cuentas realizadas porque Ines y Marijose las acordaron con Migue A. Fernández de LLera. No voy a entrar a responder a las descalificaciones y ofensas recibidas en los mails de Ines, que por supuesto no comparto porque no son ciertas. En toda mi trayectoria profesional no he recibido jamás una sola descalificación por el trabajo realizado y reitero que la minuta se corresponde con mi labor profesional realizada como abogada, detallando los conceptos en los que se divide el trabajo realizado. Confiando en que las dos minutas de honorarios pendientes de abono por Marijose e Ines hayan sido clarificadas y sean próximamente abonadas, ****************************************************** contestación de Aines: Estimada Ana, No voy a entrar tampoco a una puntualizacion hacia mi persona porque hemos expuesto una realidad del conjunto familiar, exponiendo datos objetivos, y de los cuales tenemos constancia a diferentes niveles. La Comisión Tutelar de Junta de Extremadura, representada por el asesor legal Miguel, corrobora los hechos también. Y los honorarios por gestiones administrativas se giran a 4 herederos, no a tres herederos, puesto que el 4 heredero se ha beneficiado de los trámites realizados, al igual que el resto. Y por éllo ha podido recibir todo el haber hereditario. Un saludo, esperando que se gire conforme a derecho, transparentemente proporcional a las cuatro partes. Si la cuarta parte, ha recibido todo solucionado también es un trabajo realizado para ésta. No sólo derechos también la obligación es proporcional en una 1/4 parte. Y, no pretender, además, girar más a la cuarta parte, representada por la Comisión Tutelar. Y estamos tratando un tema hereditario familiar, y si tienes alguna puntualizacion lo expones a nivel familiar profesionalmente y no focalizando en mi persona a título particular porque se envíe desde mi correo. ******************************************************** contestación de Mª José: Estimada Ana: De acuerdo a la minuta de los honorarios, de fecha 2 de noviembre, por tu intervención profesional ( Factura 984) en relación con la herencia de Don Luis Murillo Ocampos e Inés Horrillo Carmona y dado que somos cuatro herederos (Mari Jose, Andrés, Jose Luiis,e Inés Murillo Horrillo , tal como consta en las escrituras de herencia) y para los cuales se ha realizado todas las gestiones por tu parte. En esta minuta el total de tus gestiones asciende a 3.132,79 €, descontado la provisión de fondos por importe de 800€ abonados por los cuatro hermanos, que dividido entre cuatro herederos supone 783,17€. Cada hermano (cuatro) procederemos a abonar la parte proporcional de la factura 984 en la cuenta de Kutxabank que nos has facilitado en tu correo. FAMILIA MURILLO HORRILLO ********************************************************** contestación de Ana de Pablo: Estimados Marijose, Ines y Ander, Reitero que las tres facturas números 984,985 y 986 dirigidas respectivamente a Marijose, Ines y Ander, responden al encargo profesional como abogada recibido por los tres citados hermanos a partir de la firma de la escritura de herencia, y se ha minutado a cada uno en proporción al trabajo realizado como abogada desde el año 2019 a 2022, dividido en tres partes según encargo, añadiendo a la factura de Ander lo correspondiente al primer concepto suprimido a las hermanas Marijose e Ines. La parte del trabajo que haya resultado a favor de vuestro hermano José Luis se minuta aparte. Por tanto, la minuta total de honorarios por el encargo recibido de los tres hermanos es lo que asciende a 3.389 euros (3.132,79€ descontada la provisión de fondos de 800€ que lógicamente también fue abonada por los tres). El importe correspondiente a Inés y a Marijose, descontada la provisión de fondos, es 1.044,23€, por lo que si el abono realizado a día de la fecha es de 783,17€, queda pendiente el abono de 260,83€ por parte de Ines y 260,83€ por parte de Marijose. En la confianza de que se abonarán íntegramente las minutas enviadas, recibid un cordial saludo ****************************************************** contestación de Ana de Pablo: Una corrección: si los abonos de Marijose y de Ines han sido, descontada la provisión de fondos, de 783,17€ cada una, queda pendiente el abono de 261,06€ por parte de cada una. ********************************************************','2');
