insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-12-07','Amalia : Con respecto a pensiones , le han concedido PNC y sigue percibiendo REG en una parte . Si se consiguieran documentos de defunción del padre , se le podría pedir PFHC + p. Orfandad pero desconocemos la cotización del padre y en cuanto le quedaría . Podría ser inferior a lo que percibe con PNC + REG. Voy a intentar que los familiares nos faciliten datos por si se puede averiguar la cuantía que le quedaría . Oscar nos hace aclaración de gastos e ingresos y está en negativo . Habría que bajar su asignación mensual. Hola a los dos. Al hacer la rendición de Ana María, saco las siguientes conclusiones a nivel eco. A nivel de ingresos, ahora tiene una PNC de 236,60 y una Renta Básica de Inserción de 282,16 € (media 558,19 €/mes). En cuanto a los gastos: Sigue sacando una media de 532 €/mes (se le autorizó 537,84 €/mes que es lo que cobraba antes). Ha contratado una línea de teléfono de 18,90€/mes con Xenet. Le cobran casi 140€/año en comisiones (mantenimiento y descubiertos). Desde septiembre hace compras esporádicas en Amazon (hasta ahora 149,99 €, media de 50€/mes). A esto hay que añadir que su saldo actual es de 567,82 € y su diferencial anual con estas circunstancias está en -801,10€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-12-07','Amalia : Con respecto a pensiones , le han concedido PNC y sigue percibiendo REG en una parte . Si se consiguieran documentos de defunción del padre , se le podría pedir PFHC + p. Orfandad pero desconocemos la cotización del padre y en cuanto le quedaría . Podría ser inferior a lo que percibe con PNC + REG. Voy a intentar que los familiares nos faciliten datos por si se puede averiguar la cuantía que le quedaría . Oscar nos hace aclaración de gastos e ingresos y está en negativo . Habría que bajar su asignación mensual. Hola a los dos. Al hacer la rendición de Ana María, saco las siguientes conclusiones a nivel eco. A nivel de ingresos, ahora tiene una PNC de 236,60 y una Renta Básica de Inserción de 282,16 € (media 558,19 €/mes). En cuanto a los gastos: Sigue sacando una media de 532 €/mes (se le autorizó 537,84 €/mes que es lo que cobraba antes). Ha contratado una línea de teléfono de 18,90€/mes con Xenet. Le cobran casi 140€/año en comisiones (mantenimiento y descubiertos). Desde septiembre hace compras esporádicas en Amazon (hasta ahora 149,99 €, media de 50€/mes). A esto hay que añadir que su saldo actual es de 567,82 € y su diferencial anual con estas circunstancias está en -801,10€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-12-07','Amalia : Con respecto a pensiones , le han concedido PNC y sigue percibiendo REG en una parte . Si se consiguieran documentos de defunción del padre , se le podría pedir PFHC + p. Orfandad pero desconocemos la cotización del padre y en cuanto le quedaría . Podría ser inferior a lo que percibe con PNC + REG. Voy a intentar que los familiares nos faciliten datos por si se puede averiguar la cuantía que le quedaría . Oscar nos hace aclaración de gastos e ingresos y está en negativo . Habría que bajar su asignación mensual. Hola a los dos. Al hacer la rendición de Ana María, saco las siguientes conclusiones a nivel eco. A nivel de ingresos, ahora tiene una PNC de 236,60 y una Renta Básica de Inserción de 282,16 € (media 558,19 €/mes). En cuanto a los gastos: Sigue sacando una media de 532 €/mes (se le autorizó 537,84 €/mes que es lo que cobraba antes). Ha contratado una línea de teléfono de 18,90€/mes con Xenet. Le cobran casi 140€/año en comisiones (mantenimiento y descubiertos). Desde septiembre hace compras esporádicas en Amazon (hasta ahora 149,99 €, media de 50€/mes). A esto hay que añadir que su saldo actual es de 567,82 € y su diferencial anual con estas circunstancias está en -801,10€. ---------------------------------------- Mi respuesta : Buenos días , los ingresos son correctos , iban a quitarle la renta extremeña porque ella no cumple con el proyecto de compromiso que se exige para esa pensión, entre otras cuestiones . También se les exige que soliciten otras pensiones a las que pudieran tener derecho , y por eso se le solicitó PNC . Iban a quitarle la Renta Extremeña en su totalidad. Nos ha costado muchos trámites , que le concedan la PNC. Podría tener acceso a otras pensiones que quizás en cuantía le sean más beneficiosas pero sin si colaboración es imposible. Fue empleada pública , se le puede pedir Incapacidad Permanente , ella ya lo solicitó por su cuenta , pero se niega a pasar por el tribunal médico . Así que por el momento , es lo que se ha podido conseguir , PNC y Renta Extremeña Garantizada . He pedido a la familia otra documentación por si puedo pedirle otra pensión, hay que valorarlo. En mi opinión habría que limitar la asignación porque es inviable económicamente . Eso en la teoría , en la práctica , ya la tiene limitada pero amenaza a las empleadas del banco y éstas por miedo se lo dan ... Creo que poco se puede hacer , cuando le carguen y la cuenta esté a descubierto no podrá comprar..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-12-09','TERESA El viernes se firmó el contrato con la persona que se va a ocupar de la ayuda a domicilio de Adolfo García Cruz y hoy comienza a prestar el servicio. Por favor, facilítame los datos bancarios para generar el recibo Sepa. Serán 300€ al mes. Avísanos cuando se reactive la solicitud y enviaremos el contrato firmado para tramitarla.','2');
