insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-12-12','Ana: Envío a Beatriz, Directora de la Res. de Garrovillas de Alconétar (beapavonguerra@hotmail.com): el CONTRATO - CONVENIO DE ADMISIÓN RESIDENCIAL firmado digitalmente por el Presidente de la CTAEX. ··································································································································································································· Tras hablar con Cruz Merino, llamo a Beatriz Pavón - Directora Res. May. Garrovillas de Alconétar (619 55 31 89): *Mañana ingresará Juan Gregorio, le acompañará Cruz, TS. Acudirán a partir de las 11 h. ······························································································································································································· Comunico a Alberto, Jefe de sección ecca., el ingreso de mañana, el coste de la plaza y el coste de otros servicios de acompañamiento, para cuando sean necesarios. ····· Comunico también a Julio, Aux. Adtvo., para el cambio de domicilio en la Base de Datos.','2');
