insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-12-07','Ana: Correo de Anabel Teomiro, TO - Técnica PIA (ana.teomiro@salud-juntaex.es): "BUENAS TARDES ANA, EL LUNES ESTUVE EN CASA DE JOSE MANUEL ROMERO MEDIAVILLA. INFORMARTE QUE LA VIVIENDA VA ALCANZANDO NIVELES ACEPTABLES DE HIGIENE, EL BAÑO, DORMITORIO Y COMEDOR ESTAN BIEN, DONDE MAS SE NECESITA ES EN LA COCINA (LO EXPLICO EN EL INFORME PIA). DESCARTA IR A CENTRO DE DIA PORQUE NO LO PUEDE PAGAR, PERO REVITAL LE PARECE BUENA OPCION, YA LE DIJE QUE TENDRIA QUE APORTAR UNOS 180 EUROS Y ME DIJO QUE LO HABLARIA CON SU HERMANO Y CONTIGO, QUE LE PARECE ASUMIBLE. EN UNOS DIAS TE MANDARAN LA DOCUMENTACION PARA TRAMITAR LA PRESTACION VINCULADA AL SERVICIO DE PROMOCION DE LA AUTONOMIA, CUALQUIER DUDA, PONTE EN CONTACTO CONMIGO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-12-07','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que el lunes Felisa Bruno ingresó en Salud Mental. El sábado tuvo que regresar al centro a mediodía porque estaba muy demandante y no quería estar en la actividad en Brozas que organizó Mancomunidad. Hacía desde el inicio comentarios como "la voy a liar". El lunes desde primera hora bajó nerviosa y muy demandante, comentaba que la habían agredido el domingo y que quería denunciar y poner parte de lesiones. He preguntado sobre este último tema a los compañeros y me dicen que es al contrario, que ella es la que intentó agredir a un compañero. Se avisó al Centro de Salud para que valoran y cuando la enfermera iba a ponerle un calmante la empujó. No está tranquila desde la última vez que vino de Salud Mental, no para de decir que quiere cambiar de centro, ir a Badajoz,.... Según vayamos teniendo información sobre cómo se encuentra te voy informando"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-12-07','Ana: Correo de Mamen Sánchez, TS de C. Personas sin hogar de Cáritas - CC (mcsanchez.cdcoriacaceres@caritas.es): "...decirte que Francisco Cacho Garrido que desde el día 1 de diciembre esta en el piso supervisado de salud mental en Almendralejo." ··································································································································································································· Correo de Alicia, Psicóloga de los PPSS de Almendralejo (psicologia.pisosalmendralejo@grupo5.net // 674 35 51 64) al ctutelar@: "Os escribo desde los Pisos Supervisados Almendralejo para tratar los aspectos económicos relacionados con un tutelado vuestro: Francisco Cacho Garrido. Se encuentra en estos pisos desde el 1 de diciembre. Según nos informa, saca del banco 340, de los cuales 160 deben ir a la asignación mensual de la comida del piso. El restante nos comenta que él es autónomo y por lo tanto lo gestiona él. Nos gustaría una confirmación de dicha gestión." ·············· Óscar, secc. ecca., confirma la información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-12-07','Ana: Correo de Mamen Sánchez, TS de C. Personas sin hogar de Cáritas - CC (mcsanchez.cdcoriacaceres@caritas.es): "el juicio del día 12 de enero a las 10.15 es del juzgado de lo penal N.º 1, (Quebrantamiento de condena o medida cautelar). Este procedimiento tenia el juicio el día 24 de noviembre a las 10.45 horas, y se aplazo porque no se presento su abogado, y se ha vuelto fechar para el 12 de enero." ········· Se lo comunico a los A. Jurídicos CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2022-12-12','Ana: llamada de Cruz Merino (927 39 02 52): el viernes 16 acudirá la Policía Nacional al Ayto. para las renovaciones de DNI. *Hablará con la Res. para preguntar si alguien de confianza de la Res. podría hacer el acompañamiento y qué coste tendría, pues con el personal del centro en sí, no se puede contar para estas gestiones. *Tendrán que acompañarle 2 días, uno para hacerlo y otro para recogerlo ··························· Comunico a Alberto, Jefe Secc. Ecca., mediante mail, la necesidad de estos acompañamientos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-12-12','Ana: Reenvío a Alberto, jefe de secc. ecca., el presupuesto de gastos mensuales desglosado relativo a Pilar, que me remiten desde el Programa de Familias. ··· Por mi parte ok.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-12-12','Ana: Llamada de José Manuel: Dice que como tiene que volver a pagar el catering a partir de enero, cree que es mejor rechazar las prestación para el serv. tratamientos de Revital. ···· Por otra parte, pide un EXTRA para la cena de NOCHEBUENA y para comprar productos de limpieza, le recuerdo que estos últimos los puede comprar con la subida de asignación. ·· Y se queja porque con el móvil que tiene no puede enviar ni WhatsApp. ··· Le recuerdo que sacó dinero sin permiso y se compró uno que luego vendió...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-12-12','Ana: Envío correo a Alberto y Óscar, Secc. Ecca.: "He recibido llamada de DOROTEO DÍAZ CERRO, pide un extra de al menos 30 € para las fiestas. La verdad es que no pide muchos, así que por mi parte, si es viable, ok. *Habría que llamarle para confirmárselo y decirle qué día podría ir a retirarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2022-12-12','Ana: Correo de Pilar, Hogar San Vicente de Paúl, el viernes 9: "Buenos días, les comunicamos que, debido al galardón que les ha concedido el Exmo. Ayto. de Plasencia a las Hijas de la Caridad, mañana sábado van a realizar un pequeño reportaje en nuestro centro y Maria del Carmen quiere participar." ····················· Mi respuesta: "Buenas tardes Pilar, Disculpa, que el viernes no trabajé y hoy no he llegado a todo… supongo que Mª del Carmen participó igualmente, o espero que así haya sido. De acuerdo a la nueva ley 8/21, si ella entiende el alcance de su participación, puede firmar ella misma la autorización y participar en este tipo de cuestiones, siempre y cuando no haya perjuicios manifiestos para su persona. No obstante pondo en copia a los compañeros Asesores Jurídicos, por si tuvieran algo que añadir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2022-12-13','Ana: Según el informe social del CSS, para la rendición anual, Manuel se encuentra e la Unidad de Larga Estancia, lleva residiendo en el CSS, desde que ingresó en 1994. Carece de red social/familiar de apoyo. Tiene un hermano, también a cargo de la CTAEX, que reside en Badajoz (Hermanas Hospitalarias) con el que no existe relación. ······· La situación no ha variado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-12-13','Ana: Correo de ayer por la tarde de Sonia Bernabé, TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "me ha llamado la familia de los hermanos Hernández Castaño para decirme que si podíamos modificar la fecha en la que se van los hermanos a casa. Estaba previsto que se fueran para Navidad, pero dice que sus otros hijos van en Nochevieja y les gustaría que estuvieran todos juntos. Por nuestra parte no hay problema, así es que si autorizáis hablamos con Justo y Roberto y si están conforme comunico el cambio a Cruz Roja a través de Merche, la persona que les lleva habitualmente." ················· Mi respuesta: "Por mi parte no hay ningún problema, entiendo que quiera estar toda la familia junta. Pongo en copia a Belén, para que estén al corriente en la sección de acceso a recursos de discapacidad (por el transporte de Cruz Roja)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-12-13','Ana: Correo de ayer por la tarde de Sonia Bernabé, TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "me ha llamado la familia de los hermanos Hernández Castaño para decirme que si podíamos modificar la fecha en la que se van los hermanos a casa. Estaba previsto que se fueran para Navidad, pero dice que sus otros hijos van en Nochevieja y les gustaría que estuvieran todos juntos. Por nuestra parte no hay problema, así es que si autorizáis hablamos con Justo y Roberto y si están conforme comunico el cambio a Cruz Roja a través de Merche, la persona que les lleva habitualmente. Otro tema, Justo está yendo a zumba dos días a la semana con otras dos compañeras de ASINDI, y el grupo de zumba quiere organizar una cena de navidad el próximo viernes. Son 35 €. Estoy con el control de noviembre y termina con 19 €. Voy a ver los ingresos de Diciembre y se lo planteo a la sección económica." ················· Mi respuesta: "Por mi parte no hay ningún problema, entiendo que quiera estar toda la familia junta. Pongo en copia a Belén, para que estén al corriente en la sección de acceso a recursos de discapacidad (por el transporte de Cruz Roja). En cuanto a la cena de la Actividad de Zumba, estoy de acuerdo en la conveniencia de su asistencia a la misma, por todo lo positivo que le puede aportar. Cuando tengas claro qué cuantía extra necesitará, como dices, se lo comunicas a la sección económica, indicando que lo has hablado conmigo, por mi parte, si es viable, ok."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2022-12-13','Ana: Según Informe Social para la rendición anual, Tomás reside en la Unidad de Larga Estancia desde que ingresara en 2016. Está adaptado a dicha unidad, respeta las normas, es parcialmente autónomo para las ABVD, aunque presenta problemas de movilidad por dificultades en sus miembros inferiores. Interacciona bien con los demás. ········· Mantiene, ocasionalmente, contacto telefónico con su hermana Isabel, que llama para interesarse por su estado de salud y hablar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='TESORO'and apellido2='GARCIA'),'2022-12-13','Ana: Según Informe Social para la Rendición Anual, Andrés está ingresado en la Unidad de Larga Estancia. Reside en el CSS de forma ininterrumpida desde 1961. No ha recibido llamadas de ni vistas desde 2017. ··· Se encuentra en situación basal: transferencia cama - silla de ruedas. Presenta UPP a nivel sacro. Tiene establecido un plan de cuidados auxiliares. ··· Poca respuesta a estímulos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-12-09','Ana: Respuesta de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net) a mi correo del día 24 de noviembre: "Hola Ana, por nuestra parte puede cobrar a partir de la semana del 19 de diciembre esos 50 euros que pedía y comprarse lo que ella quiere (ahora una cazadora porque su madre le regaló el reloj)." ·············· Se le confirma que podrá retirarlo cualquier día de esa semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2022-12-13','Ana: Correo de Ángela, Directora Placeat (directora@placeat.org): "Comentarte que del 23 de diciembre al 2 de enero María pasará la Navidad en la residencia de Placeat en San Gil. El día 24 ha sido invitada a cenar por la familia de su pareja, para lo que solicito autorización, la recogerán esa tarde y regresará a dormir a la residencia." ·········· Mi respuesta: "Por parte del Gabinete Técnico de la CTAEX, y atendiendo a los deseos y preferencias de María, no hay inconveniente en que acuda a cenar el día 24 con su pareja y la familia de ésta. Tomo nota de todo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2022-12-13','TERESA conduce una furgoneta sin carné con la cual va a su campo en el que pasa la mayor parte del tiempo. Tiene diferentes y numerosos animales pero no se conoce bien en qué estado están. El trabajador social nos asegura que se ha puesto en contacto con una protectora de animales para que se acerquen a recogerlos y le confirmaron que irían, pero hasta el momento no ha aparecido nadie. Jesús comenta que lo más adecuado sería un piso tutelado pero que va a resultar complicado ganarse la confianza de Tomás, el cual no acude a citas médicas de ningún tipo y ni siquiera esta vacunado del covid19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-12-13','miguel, el abogado Manuel Andrino me remite Auto no firme de autorización de aceptación de herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-12-13','Ana: Llamo a Lourdes, TS SAD y Catering ( Ext. 4425): Cofirma que el serv. de cátering finaliza el día 31 de diciembre, pues no cuentan con financiación para más tiempo. ············· Llamo al Catering Mesa y Mantel (927 62 95 31): pido presupuesto para volver a contratar el servicio a partir de enero. En cuanto nos lo envíen por mail confirmaremos el inicio del servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2022-12-13','Ana: Envío correo a Eva Álvarez, TS - Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org): "¿Qué tal sigue Christofer Montero? Espero que su adaptación esté siendo positiva. Ya me dices cuando puedas. Queríamos solicitaros que nos enviéis, cuando podáis, un CERTIFICADO DE INGRESO EN CENTRO en que conste la fecha en que ingresó."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2022-12-13','TERESA Ildefonso, en su sentencia nada dice si puede conducir o no vehículos a motor. Si dice que padece una esquizofrenia paranoide de curso crónico con periódicas exacerbaciones agudas con síntomas residuales interepisódicos muy larvados y atenuados, que afecta de forma progresiva las capacidades personales, familiares, sociales y laborales del enfermo. Por tanto, si su tratamiento médico lo cumple de manera continuada y vigilada puede desenvolverse en un estado casi normal. Pero si los brotes de la enfermedad son frecuentes, prolongados e intensos, durante los mismos es recomendable la incapacidad absoluta. Por este motivo y ante el riesgo de no saber en qué estado se encuentra, podíamos negarnos a permitirle que conduzca. En otros casos (José Florencio González Mangas) hemos leído los prospectos de los medicamentes que se les administraba, donde se indicaba que no podía conducir vehículos a motor mientras estuviera recibiendo el tratamiento médico mediante la utilización de los psicofármacos prescritos. Por nuestra parte ok a que no se le facilite dinero para esta cuestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2022-12-13','TERESA Buenos días compañera, hemos programado salida para Nochebuena de los hermanos Coral y José Antonio, los días 24,25 y 26 de diciembre en taxi a Badajoz para que pasen esos dias con su familia. Contratamos un taxi, ya está reservado para el día 24 a las 10:00 horas y el día 26, a las 18:00 horas de vuelta; el coste es de 90 € cada viaje, que se abonarian en dos facturas, una a nombre de Coral y la otra , a la de José Antonio. Ademas, cada uno se llevaría 50€ de dinero de bolsillo. Si estáis conforme con ello, espero tu respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2022-12-13','TERESA Buenos días compañera, hemos programado salida para Nochebuena de los hermanos Coral y José Antonio, los días 24,25 y 26 de diciembre en taxi a Badajoz para que pasen esos dias con su familia. Contratamos un taxi, ya está reservado para el día 24 a las 10:00 horas y el día 26, a las 18:00 horas de vuelta; el coste es de 90 € cada viaje, que se abonarian en dos facturas, una a nombre de Coral y la otra , a la de José Antonio. Ademas, cada uno se llevaría 50€ de dinero de bolsillo. Si estáis conforme con ello, espero tu respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-12-13','Ana: Correo-respuesta de Cristina a mi consulta: "Buenas tardes Ana, Adrián en su línea, no se levanta a los talleres, amenaza a sus compañeros para que le den cigarros o le dejen sus aparatos electrónicos (adueñándose de ellos), etc. El pasado viernes 9 de diciembre tenía cita con el Equipo de Salud Mental, se negó a ir. No quería levantarse de la cama, haciendo caso omiso a las indicaciones del personal. Hemos recibido atención telefónica por parte de éste equipo y han decidido pautarle medicación oral: ABILIFILY 10 MG 0-0-1. En cuanto al tratamiento hormonal de Adrián, no tenemos ningún informe al respecto (simplemente hojas de tratamiento), es un tratamiento que ya tenía pautado cuando ingresó en nuestro centro. Si es necesario podemos pedir el informe que necesitéis a su Psiquiatra. Las últimas fechas del inyectable son: FECHA INYECTABLE DECAPEPTYL TRIMESTRAL : 17/06/2022 / 17/09/2022 / 17/12/2022" ····························································································································································································· Reenvío la información a Maribel Ramos, TS Secc. Acceso Discapacidad (mariaisabel.ramosa@salud-juntaex.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-12-14','-TF de su hermana PIlar 639151829 Ha llamado solicitando que desde la CTAEX se le impida a su hermano que pueda salir de la residencia de mayores que tiene solicitada. Envío email a sección jurídica : Buenos días , Paco Cuevas está ingresado en CSS de Mérida por cumplimiento de condena via judicial . Sale el 30 de enero y se le ha solicitado plaza residencial de mayores por emergencia social , todavía no la tenemos asignada pero no creo que haya problemas . Me temo que él ha aceptado esta opción para asegurarse salir del CSS . Su hermana me comenta hoy por tf que su intención es irse a un piso a vivir solo . Ante los antecedentes delictivos de este usuario ( violaciones ) hay alguna opción de solicitar internamiento involuntario en residencia para que no pueda salir o en CSS ?? Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2022-12-14','Ya he tramitado la baja de la luz. Agua no paga porque debe estar incluida en la cuota de la comunidad de vecinos, que sigue pagando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2022-12-14','Ya he tramitado la baja de la luz. Agua no paga porque debe estar incluida en la cuota de la comunidad de vecinos, que sigue pagando.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-12-14','REspuesta de Miguel : Buenos días, no podemos proceder a solicitar un internamiento involuntario si no hay informes médicos, sociales, y/o denuncias que lo recomienden. Indica Miguel : Claro, pero debería de saber su hermana que las limitaciones a los derechos de las personas tienen que ser dictadas en resolución judicial, para lo cual tendría que tener pruebas en ese sentido. La Comisión no puede obligar a nadie a entrar en un centro, ni limitar sus derechos Una vez pagada su condena es un ciudadano libre con los mismos derechos constitucionales de residencia, y circulación que cualquier otro. Le contesto que actualmente no existen esos informes , desde psiquiatria está compensado y no hay denuncias desde el CSS. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-12-13','Ana: correo de Cruz Merino, TS SSASB (cruzmerino@tajosalor.es): "Ya hemos llevado a Juan a Garrovillas. No quería irse de su casa, le hemos "engañado" diciendo que estaba su mujer (que ya falleció haces más de año y medio) y así ha entrado en la residencia. Esperemos que se adapte bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-12-14','- Gestion eco : REINTEGRO: SERÍA REDUCIRLO A 500 €/MES (ACTUALMENTE SACA 532 €/MES)Y NO GENERARÍAMOS NINGÚN AHORRO...LA CCC QUEDARÍA A 0 CADA MES SI QUISIERAMOS AHORRAR ALGO EL REINTEGRO SERÍA MENOR CONFORME A LO QUE ME DIGAS ESTABLECEMOS ESTE REINTEGRO O MENOR. OSCAR: ASEGURARNOS CON BANCO DE QUE TUTELADA NO PODRÁ ORDENAR NINGUNA TRANSFERENCIA....VER SI ES POSIBLE RECHAZAR/DEVOLVER/OTROS LAS TRANSFERENCIAS A AMAZON. ASEGURARNOS CON BANCO DE QUE TUTELADA NO TIENE NINGUNA FORMA DE PAGO (LIBRETA, ONLINE...). REVISAR CADA 2 MESES LOS GASTOS DE TELEFONIA...DE FORMA QUE SI LOS MISMOS SE DISPARAN SE REDUCIRÁ EL REINTEGRO QUE PACTEMOS. ESTRELLA: NO CONSTA LA FORMALIZACIÓN DE SEGURO DE DECESO...XFA, COMPRUEBALO Y SI NO COSTA PIDE PRESUPUESTO...LO HABLAMOS LUEGO...AMALIA: TU PUEDES INFORMARTE SI TIENE ALGO CON LA FAMILIA??? Me indican que no saben si la madre la tiene en Ocaso con ella , la madre ha sufrido un ictus y no puede hablar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-12-14','- Gestion eco : REINTEGRO: SERÍA REDUCIRLO A 500 €/MES (ACTUALMENTE SACA 532 €/MES)Y NO GENERARÍAMOS NINGÚN AHORRO...LA CCC QUEDARÍA A 0 CADA MES SI QUISIERAMOS AHORRAR ALGO EL REINTEGRO SERÍA MENOR CONFORME A LO QUE ME DIGAS ESTABLECEMOS ESTE REINTEGRO O MENOR. OSCAR: ASEGURARNOS CON BANCO DE QUE TUTELADA NO PODRÁ ORDENAR NINGUNA TRANSFERENCIA....VER SI ES POSIBLE RECHAZAR/DEVOLVER/OTROS LAS TRANSFERENCIAS A AMAZON. ASEGURARNOS CON BANCO DE QUE TUTELADA NO TIENE NINGUNA FORMA DE PAGO (LIBRETA, ONLINE...). REVISAR CADA 2 MESES LOS GASTOS DE TELEFONIA...DE FORMA QUE SI LOS MISMOS SE DISPARAN SE REDUCIRÁ EL REINTEGRO QUE PACTEMOS. ESTRELLA: NO CONSTA LA FORMALIZACIÓN DE SEGURO DE DECESO...XFA, COMPRUEBALO Y SI NO COSTA PIDE PRESUPUESTO...LO HABLAMOS LUEGO...AMALIA: TU PUEDES INFORMARTE SI TIENE ALGO CON LA FAMILIA??? Me indican que no saben si la madre la tiene en Ocaso con ella , la madre ha sufrido un ictus y no puede hablar.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-12-14','Ana: Envío correo a los A. Jurídicos CTAEX: "He recibido llamada de JESÚS MANUEL RAMOS BARGÓN, ya sé que desde las sección económica os han pasado consulta. Me dije hoy que se le acaba el plazo para presentar el recurso en el Juzgado y quiere poder pagar la factura de un abogado, ha solicitado la revisión de su sentencia.". ·················· Correo de Ángel, A. Jurídico CTAEX: "En relación con Ramos Bargón, os comento que el procedimiento de revisión de su sentencia ya está en marcha. Hay señalada una comparecencia el día 2/2/23. Asistirá Abogacía General y nosotros a través de videoconferencia ese día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2022-12-14','-Amalia . Este usuario entró por primera vez derivado de la UHB en el CSS . Salió de alta y volvió a entrar para cumplir medida judicial . Me informan hoy desde el CSS que liquida la misma el día 26 diciembre. Tiene solicitado CRR , G.II dependencia y 65% G.D. No puede volver a su casa con el padre porque es consumidor de drogas . Cogía la pensión del hijo y se la gastaba en drogas que consumían los 2. El hijo sufre alucinaciones . Escribo a Sección de Salud mental para solicitar plaza en CRR por emergencia Social . No hay psiquiatras para hacer informes de nada .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-10-27','Ana: Correo de Toni-Futuex: "Adjunto se envía informe sobre el tutelado jesús Manuel Ramo, relativo a su desempeño en las diferentes áreas, conforme lo entendemos desde el programa en virtud de los seguimientos y el conocimiento del caso, está firmado como me indicaste. Te envio también una extracto de las gestiones realizadas, un diario de los seguimientos a lo largo de este año, desde mi punto de vista menos relevante en cuanto a la información técnica que aporta, pero te lo envio también por si lo necesitas." ········ Se lo reenvío a Miguel, A. Jurídicos CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-12-14','Ana: llamo a Beatriz Pavón - Directora Res. May. Garrovillas de Alconétar (619 55 31 89): al preguntarle por Juan, dice "FENOMENAL", ayer la supervisora se lo llevó a la ducha y lo afeitó. Lo ha visto esta mañana y está tranquilo y contento. Cuando le ha preguntado ha contestado: "Muy bien, muy bien, no he pasado frío.", también ha dicho que la habitación le ha gustado mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2022-12-14','Ana: Envío correo a Alberto, Jefe Secc. Ecca.: "Sólo para que lo tengas en cuenta, a JULIÁN RAMÓN CIVANTOS FERNÁNDEZ tuvieron que sacarlo ayer de casa por riesgo de derrumbe del techo (otra vez…), lo han llevado a una pensión, como puedes leer más abajo. NO sabemos aún cuánto costará ni si se podrá abonar mediante transferencia, pero si no me equivoco, se lo puede permitir sin problema. Voy a ver si contacto con el albañil que hizo la obra la otra vez. *El problema aquí, si no recuerdo mal, es de la estructura del edificio y correspondía el arreglo a la comunidad de vecinos… tengo que revisar cómo quedó aquello, porque sinceramente, ya ni me acordaba, y eso que estuve mucho tiempo detrás de esta historia…. Cuando nos pasen factura del hostal hay que abonar." ······························································································································································································· Llamo varias veces a lo largo de la mañana a Paco Ortés, Albañil (638 712 004) pero siempre salta el buzón de voz. *La última vez dejo un mensaje pidiendo que se ponga en contacto conmigo. ·································································································································································································· Nuevo correo de Toni-Futuex: "Hubo bastantes problemas para encontrar algo, porque, cuando se comentaba que el alojamiento es para Ramón, existia cierto rechazo pero con la ayuda de la farmacéutica (que hay debajo de su casa y con la tiene gran trato) , se consigue que lo acepten en el Hotel Ibérica (664373247), se les dice que, en principio para una semana y con pensión completa. ..." ··· Al principio estaba muy nervioso, pero ya está más tranquilo. Cenó en la residencia y todo. *Le han dado una habitación de matrimonio un poco apartada para que tenga menos ruido y no se ponga más nervioso"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2022-12-13','Ana: Correo de Toni-Futuex, a última hora: "13/12/2022 MUY MUY URGENTE goteras en la vivienda: Se contacta con la auxiliar de S.A.D. por otras cuestiones y aprovecha para comunicar que la vivienda de Ramón está en muy malas condiciones, señala que tiene goteras en casi todas las dependencias, debido a las fuertes lluvias de hoy, de hecho, incluso cuando está acostado le está cayendo agua encima, estuvo moviendo la cama… Comenta que la exmujer de Ramón está intentando contactar para llevarlo a otro lugar, se le dice que si no quiere va a ser complicado… Se contacta con Ramón, como se esperaba, quita importancia, pero sí reconoce que le está volviendo a entrar agua y en todas las dependencias, no sólo en la habitación que está en peor estado; también en el salón, su habitación… Se le dice que no puede estar viviendo así, no es saludable y lo más adecuado sería que saliese de ahí, pero se niega… Se le insiste en que hay que tomar alguna medida pues va a enfermar y entonces tendrá que ir al hospital, cosa que no quiere. Se considera bastante peligroso que se mantenga en la vivienda, pues además de estar mojandose, tiene muchisima humedad que puede ocasionarle enfermedades respiratorias, y está el riesgo de la escayola que pudiera desprendersele o incluso parte del techo, porque está en muy mal estado. Debido a la situacion, le hemos asesorado y convencido, para que puediera pasar almenos un par de dias, en un hostal de la localidad, que parece que tiene disponiblidad. Iria con la auxiliar, esta tarde para alla. No sabemos si puede pagarse por transferencia, pero si no, Ramon podria irlo pagando de lo que retira del banco, en cuanto tengamos mas datos te comento,. Adjuntamos fotos del estado actual de la vivienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2022-12-14','Ana: Reenvío a la sección económica el presupuesto con máquinas de afeitar que me remiten desde la residencia (residencia@santiagodealcantara.com). Pido que le den respuesta directamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-12-14','Ana: Llamo a José Luis, hermano de José Manuel (687 581 061): acepta la propuesta de que le hagamos la transferencia ecca. a él y se encarga de acompañar a su hermano a comprar la comida para la cena de Nochebuena. ················· Llamo a José Manuel (627 788 797) y se lo comunico. ················ Me cuenta que ayer tuvo cita con el MAP, le ha derivado al Neumólogo, pues dice que se asfixia. Y le ha cambiado a preferente la derivación a Fisioterapia, pues tiene un dolor muy fuerte en la rodilla. ······ También le han llamado de la farmacia, para que vaya a recoger la crema que le ha prescrito el médico. ········· Escribieron de la farmacia al ctutelar@ consultándolo. *Óscar le recordó que todo lo que sea con prescripción médica se lo pueden dar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-12-13','Ana: Tras hablar con Alberto, jefe secc. ecca., me remite correo: "ANA: SE AUTORIZA REINTEGRO EXTRA "NAVIDAD" X 30 € AL TUTELADO....HABLAS CON HERMANO Y LE HACEMOS TRANSFERENCIA SI LO VES OPORTUNO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2022-12-13','Ana: correo de Felisa Custodio, TS CAMF Alcuéscar (trabajadora_social_alcuescar@imserso.es): "Estimada Ana, para tu conocimiento te doy traslado del correo que he remitido a mi Directora. Saludos." ····· "Buenos días, está conmigo Maribel Debón. Le he comentado que días atrás ha llamado el Señor Sebastián Alzas para decir que quería llevarse a la residente en su permiso de dos horas diarias. Refiere Maribel que no quiere saber más de este Señor, lo califica como "machista". Le hemos llamado y en su nombre le he trasladado que la residente no quiere saber nada de él ni tener ningún tipo de relación. Se muestra conforme. Ruego por favor, se de traslado a los departamentos afectados por si vuelve a llamar o incluso por si intenta venir al Centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-12-14','Ana: Llamo al Programa de Familia (927 14 71 14 / 648 69 15 67): Dejo mensaje en el buzón de voz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-12-13','Ana: correo de CRR-CC (crr@grupociudadjardin.com): "Comunicar el positivo en COVID 19 de la persona usuaria Juan José Bergantiño. Se encuentra con sintomatología leve en estos momentos. Procedemos a comunicar a su MAP, así como a estrechar vigilancia en sintomatología de personas usuarias y trabajadoras."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-12-14','Ana: Correo de Mamen Sánchez, TS de C. Personas sin hogar de Cáritas - CC (mcsanchez.cdcoriacaceres@caritas.es): "La citación del juicio del día 12 de enero de 2023 no la tenemos, como fue un aplazamiento la jueza informo al propio Miguel Ángel de la fecha nueva. El abogado es ANGE SANCHEZ-CIRUJANO SANCHEZ. TLF: 927 24 33 07" ········· Respondo y pongo en copia a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-12-14','TERESA Esta mañana se ha tenido una conversación vía whatsapp con María Murillo en la que comentaba que no piensa venir a la citación judicial que tiene en Zafra el día 15 de diciembre si no es en taxi pagado por la Comisión. Se le ha insistido en la posibilidad de venir con un amigo o de venir en bus (que es muy barato) y después, en lugar de estar esperando a que salga el bus de vuelta, aprovechar para quedar con algún amigo, que según ella tiene en Zafra, pero se niega. Asegura que no le importa faltar a la citación y que ya le llamarán para poder venir en otra ocasión. Se le ha comentado la posibilidad de pagar ella el taxi teniendo en cuenta que ha recibido la PNC + la paga extra (para también ver si, de alguna manera, nos comentaba algo sobre el asunto de la PNC, por si lo hubiera cobrado ella o cualquier cosa... ) y no ha hecho ningún comentario al respecto, simplemente se niega a venir pagando de su bolsillo el servicio que sea, pero si parece ser que dinero tiene, asique esto un poco raro. El ts de la localidad si confirmaba (que creo que habia hablado contigo) que Maria iba a cambiar de banco o habia cambio, pero la pnc tambien habria que cambiarla, como no sea que esto lo haya hecho ella por su cuenta y este recibiendo la pension en otro banco sin decir ni mú.. ni idea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-12-14','TERESA Bartolmé Colchón, movil apagado y no está en casa. Lo ultimo que supimos es que estaba en atocha.. pero haber si conseguimos recopilar la información y te la paso, por que, hasta ahora en su "viaje" hemos podido ir hablando con el, pero ya hace dias, que el móvil esta apagado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-14','Ana: Envío correo a Julia, Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com): "Buenas tardes Julia, He intentado llamar al centro, sin éxito. Quería preguntarte si tenéis alguna plaza libre. Imagino que no, pero por si acaso. Pues tenemos a un chico, cuyo cargo se aceptó hace unos meses, que actualmente está cumpliendo condena en el C. Penitenciario. Pero nos avisan, que a no ser que haya más causas pendientes, que no nos han confirmado aún, saldrá en libertad el día 6 de enero y no tiene dónde ir. Ahora está tranquilo y estable. Pero aún no ha tenido seguimiento en Salud Mental desde que está en Prisión. Tiene cita los próximos días. Quedo a la espera de tu respuesta. Gracias y un saludo." ································································································································································································ Envío correo a Mamen, Sánchez, TS de C. Personas sin hogar de Cáritas - CC (mcsanchez.cdcoriacaceres@caritas.es): "Quería preguntarte si tenéis alguna plaza libre. Imagino que no, pero por si acaso. Pues tenemos a un chico, cuyo cargo se aceptó por la CTAEX hace unos meses (de hecho el inventario no se ha enviado al Jdo. hasta octubre), que actualmente está cumpliendo condena en el C. Penitenciario de Cáceres. Pero nos avisan, que a no ser que haya más causas pendientes, que no nos han confirmado aún, saldrá en libertad el día 6 de enero y no tiene dónde ir. Ahora está tranquilo y estable. Pero aún no ha tenido seguimiento en Salud Mental desde que está en Prisión. Tiene cita los próximos días. Quedo a la espera de tu respuesta." ················· *Enví la misma consulta a Fernando Pecero, Casa de la Misericordia de Alcuéscar (aromasdecaridad@hotmail.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2022-12-14','Ana: Envío correo a Amalia, Alberto, Maite y Ángel: "En relación a este expediente, deciros que no se trata de una curatela económica, sin una CURATELA PARA LA SALUD. En el expediente no hay prácticamente nada. Lleva un mes en su casa y actualmente, por lo visto, está descompensada, pero nadie se ha atrevido a activar el 112. *En la Guardia Civil ya tienen varias incidencias, de las cuales tampoco tenemos informe/parte… la hija, que vive en Ibiza, iba a intentar conseguirlos. Amalia, finalmente la derivaste al Programa de Apoyo Comunitario? Necesito saber si han ido a visitarla ya. Por otra parte, ¿sabes si se le cambió el expediente al Equipo de Salud Mental de Cáceres? No he podido hablar con Pilar Martín, pues está de baja… Tengo que averiguar también si la están atendiendo desde aquí. Para rematar la Aux. de Ayuda a Domicilio está de baja. *Puesto que ya tiene cumplidos 60 años, no puede volver a acceder a CRR. Intentaré que ingrese en UHB, para valoración, diagnóstico y estabilización. Y después, a las malas, si se constatara que no puede vivir sola, intentaré recabar informes para internamiento involuntario…. Aunque lo ideal es que con apoyos, pudiera permanecer en el domicilio. Alberto: el expediente es de 2017, pero tampoco hay ninguna rendición hecha (al menos no escaneada)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-10-10','Ana: Correo de Ángel, Asesor Jurídico: "En relación con la venta de propiedades de Martín Domínguez Palencia, según hablamos vamos a poner en marcha la venta del adosado (C/. García Márquez, 10, de Cáceres), que es propiedad al 100% de Martín. La otra vivienda que tiene en propiedad, junto con el hermano, no vamos a venderla, salvo que me digáis otra cosa, porque es una vivienda a la que va cuando sale del centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-12-15','Ana: Envío correo a Toni-Futuex: "En relación a ANTONIA BERNARDO PIRIS, quería preguntaros qué tal están yendo los seguimientos, si los acepta y cómo la habéis visto a ella. Por favor, cuando podáis, enviarnos informe, y a ser posible firmado, pues según sea la situación, se remitirá al Juzgado o no."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-12-15','Ana: Envío correo-consulta a Toni-Futuex: "En relación a la vivienda de Felisi, se acordó que se cambiara la cerradura de la vivienda, pero si no recuerdo mal, nos tenían que facilitar un presupuesto. El cerrajero dijo que no se haría ningún otro trabajo, hasta que se hubiera abonado una factura pendiente de otro trabajo que le encargó Aitor sin autorización. Los compañeros de la sección social ya abonaron, mediante transferencia, dicha factura en el mes de octubre. Pero todavía no hemos recibido el nuevo presupuesto. ¿Podríais enviárnoslo, en caso de tenerlo, o pedírselo de nuevo a dicho cerrajero?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-12-15','ESTRELLA: FORMALIZAMOS SEGURO DECESO PARA ESTA TUTELADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-12-15','Ana: Llamo varias veces a Juan María Lozano, único hijo de Juan Gregorio (688 710 226): sin respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2022-12-15','Buenas , Ya he hablado con la TS de la R. M . de Villafranca , hasta el día 30 de enero tiene que cumplir la medida judicial en el centro socio sanitario . El día 31 tendría que hacerse el traslado a la residencia si desde mayores no tienen inconveniente . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMBROSIO'and edp.apellido1='MORENO'and apellido2='GARCIA'),'2022-12-15','La hermana del paciente se llama Dolores y los tlfs que aparecen en SIDEX son 924570088//618649310.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-09-05','Ana: Correo de Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net): "Buenas días, el viernes por la noche sobre las 12 , Julia os pidió todo su dinero de forma insistente para irse del recurso. Ante su insistencia y para evitar posibles alteraciones conductuales graves se lo dimos. Se fue a Cilleros, donde según nos cuenta su madre, llegó a casa alterada y se fue a dar vueltas por el pueblo. Sobre las 3 de la mañana, la convencieron que volviera al CRR, en ese momento exigimos que para entrar al recurso pasase por una valoración psiquiatrica. Desde el CRR hablamos con el psiquiatra contándole la situación, no estaba muy convencido pero al final accedió a poder valorarla y proponer un ingreso. Julia y sus padres estando en el hospital decidieron irse para el CRR porque el psiquiatra tardaba mucho. Tras hablar desde la dirección con ellos accedieron a volver para la valoración. Al final la información que nos da su madre es que se hace un ingreso voluntario. Intentaremos coordinarnos con la UHB del hospital pero normalmente hasta la 1 no nos dan paso con psiquiatra, si es que antes no la han dado el alta. Creo que es insostenible que Julia siga viviendo en el CRR, por sus necesidades un recurso abierto no se adecua a lo que necesita en este momento,poniendo en riesgo a las personas que viven en el CRR, al equipo y a la familia de Julia ya que son constantes las llamandas, salidas, demandas, exigencias y alteraciones conductuales de voces y amenazas con irse, con peticiones de dinero etc. No sé, la posibilidad de que desde SEPAD se pueda hablar con la UHB para que no sea un alta inmediata y se pueda valorar su situación. ( No tengo datos objetivos de que se la vayan a dar pero basándonos e lo que ha costado que ingresé me imagino que en cuando Julia exprese querer el alta se la darán)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BARQUERO'and apellido2='MARTIN'),'2022-12-15','- Amalia , me indican que ha fallecido hace un mes en el CSS , se les ha pasado comunicarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-16','Ana: Correo de ayer noche de Javier Navareño, actual director de la Casa de la Misericordia de Pinofranqueado (aromasdecaridad@hotmail.com): "...Con respecto al caso que nos presenta de momento no podemos atender a su petición. Aunque, si es posible, sí que nos gustaría conocer algunos datos básicos del solicitante (por si acaso tuviéramos alguna baja en los próximos días)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-15','Ana: Reenvío a Soraya Masa y Maite, el correo ya enviado el día 5/12 y añado: "Con respecto a esta cuestión, pendiente de tratar, deciros que me han confirmado, tanto de la Casa de la Misericordia como de Cáritas, que no tienen plazas libres… En Cáritas me avisarán si llegado el momento no hay otra cosa, pero de entrada me ha dicho que es difícil. NO TENEMOS ALTERNATIVA. Ya me decís cuándo podemos verlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2022-12-16','Ana: Reenvío a A. Jurídicos-CTAEX, el Certificado de Ingreso en Centro que solicité para comunicar al Juzgado y que me remite Beatriz, Directora del C. Mayores de Garrovillas de Alconétar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-12-16','Ángel: Asisto por videoconferencia a dos juicios en el Juzgado de Primera Instancia e Instrucción, nº 4 de Plasencia: El primero es el número 61/22, el denunciante es el centro y José Ángel Silva Jiménez, al que Adrián le quitó los pantalones y se mofó de él. Estas actuaciones son contitutivas de un delito de maltrato de obra, pero se le aplica la exención por su incapacidad, absolviéndole, debiendo cumplir la pena de medida de seguridad de libertad vigilada en el que deberá someterse a tratamiento médico adecuado durante 2 meses. El segundo es el número 95/22, el denunciante es Alexader Pajares Talavera, por agresiones. Estas actuaciones son contitutivas de un delito de lesiones, pero se le aplica la exención por su incapacidad. Deberá cumplir una medida de seguridad de libertad vigilada debiendo someterse a tratamiento médico adecuado durante 3 meses y al pago de una indemnización de 114 euros en concepto de responsabilidad civil, al ser solicitada por la madre de Alexander, que es su tutora legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-12-16','miguel, tras recibir en días anteriores escritura de declaración de herederos e impuesto de sucesiones originales de la asesoría de Azuaga, Durán Ramirez (Raúl), envío email al Sch, Pedro Jorge Cabezas Labrador (tlfno 924137805, 618996058, fax 924-137806, email: pcabezal@gruposantander.es Buenos días, conforme los datos facilitados por la asesoría Duran Ramirez adjunto los números de cuenta de las hermanas Gonzalez Naranjo, Mª Teresa y Juana en relación al reparto de la herencia de su madre fallecida Doña Juana Naranjo León cuyos números de cuenta a los que hay que realizar el ingreso de la cuenta de la fallecida es: - GONZALEZ NARANJO, JUANA - DNI 08833882L - CCC IBERCAJA ES04 2085 4566 8803 3057 8981 - GONZALEZ NARANJO, MARIA TERESA – DNI 08799349D – CCC IBERCAJA ES50 2085 4566 8303 3057 8883 Aunque me confirma Raúl de la asesoría Duran Ramirez, que ya les ha entregado la documentación necesaria para acreditar que son herederas y se proceda al desbloqueo y reparto de ese dinero, le adjunto Declaración de herederos y la liquidación del impuesto de sucesiones. Quedo a la espera de me confirmen cuándo y cómo (en qué cuantías) se produce dicho ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2022-12-16','TERESA • EL DÍA 12/12/2022 HAN CARGADO NUEVO RECIBO X 29 € APROX.: LO DEVOLVEMOS. • A PARTIR DE HOY TRANSFERIMOS "PUNTUALMENTE" CADA MES 70 € A LA CCC DE LA MADRE DE TUTELADA (Dª LUISA).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-12-16','Ana: Recibo correo de Toni-Futuex, con factura, los presupuesto pendientes para pintura y rejas, y con anotaciones de los últimos seguimientos del mes de octubre. *Guardo en el expdte. digital. ································································································································································································· Envío correo al ctutelar@: "Os reenvío factura de la cerradura de la vivienda de Felisa Felipe Teomiro. Finalmente lo abonó ella en metálico, pero tal y como habíamos acorado tendría que pagarlo Aitor. Así que entiendo que habrá que hacerle una transferencia desde la cuenta de Aitor Moreno Felipe a su madre Felisa. *Os paso también los presupuestos para los arreglos pendientes (limpieza y rejas), creo que ya los tenéis, pero por si acaso. *Esto, hasta que no demos orden desde aquí, no lo harán"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-12-16','Ana: correo-respuesta de Toni, con información de la visita realizada el día 06/10/22, en la que Antonia "Explica que ha dejado de asistir al psiquiatra y que lo ha denunciado en los juzgados porque no está de acuerdo con el diagnóstico, explica que ella ni tiene ni ha tenido nunca esquizofrenia y por este motivo a denunciado a su psiquiatra el DR. Juan José Mora, según palabras de la propia tutelada sufre acodo por parte de este profesional. Se le transmite la posibilidad de solicitar un cambio de facultativo en esta y cualquier especialidad médica sin entrar a valorar la veracidad de los datos que aporta porque no corresponde a la educadora y porque es muy probable que todo esto forme parte de su enfermedad puesto que en la consulta de psiquiatría a que se la acompaño el verano ya comentó el Dr. Juan José Mora la escasa conciencia de enfermad de Mª Antonia y el rechazo hacia el diagnostico. A través del dialogo se intenta que la tutelada retome la asistencia a estas consultas, pero ante el bloqueo de la tutelada en este asunto se le recomienda que si se encuentra más agitada, deprimida o con síntomas emocionales acuda a urgencias o solicite cita con otro profesional aunque se su MAP." ···················· *Volverán a visitarla y nos informarán al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-12-16','Ana: tras recibir correo-respuesta de Toni-Futuex, envío correo a Alberto y Miguel, con copia a Maite y Óscar, CTAEX: "Alberto: - reenvío nuevo presupuesto para aumento de asignación de SATURNINO MIGUEL SALGADO. No sé si es viable, pues como ya sabíamos, tiene domiciliados los suministros y no sé si le llega para todo. - Por otra parte informar de que pronto enviarán una factura en concepto de comidas en el mesón de su primo, donde sabemos que ha estado acudiendo a comer porque la casa no estaba acondicionada para ello. (Subrayo ambas cosas en amarillo) Por último, Miguel: subrayo en verde información relativa a la cita en el Instituto de Medicina Legal, a la que Saturnino no muestra interés en acudir y la “colaboración” (o todo lo contrario) de su hermano Tomás. Hay también captura de pantalla de WhatsApp de éste último." ·································································································································································································· Respuesta de Alberto, Jefe de Secc. Ecca: "ANA: en este momento no podemos plantearnos nada con esta persona...el saldo, hoy, es de 437 €...parece que está sacando lo que le parece desde junio de 2022, fecha en la que se estableció la asignación permanente (puedes verlo en la información que le envío a Oscar. X supuesto, con todo el reintegro extraído, no se ha podido abonar la factura de su primo el cocinero... ANA/OSCAR: tampoco sabemos quien ha dado orden para cargar los enganches de luz y agua...y aún no se pueden hacer las medias de consumos. OSCAR (URGENTE): este tutelado tiene autorizados 50 €/semana desde 28/06/2022...sin embargo puedes ver los REINTEGROS realmente realizados...todos ellos, excepto el relativo a las obras, SIN AUTORIZACIÓN....tampoco le han pedido a nadie autorización para altas de luz y agua. Hay que hablar con el banco URGENTEMENTE y ver porque ocurre esto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-12-16','miguel, recibo varios emails, parte económica, social, y de futuex: Buenos días, a tod@s, Alberto: - reenvío nuevo presupuesto para aumento de asignación de SATURNINO MIGUEL SALGADO. No sé si es viable, pues como ya sabíamos, tiene domiciliados los suministros y no sé si le llega para todo. - Por otra parte informar de que pronto enviarán una factura en concepto de comidas en el mesón de su primo, donde sabemos que ha estado acudiendo a comer porque la casa no estaba acondicionada para ello. (Subrayo ambas cosas en amarillo) Por último, Miguel: subrayo en verde información relativa a la cita en el Instituto de Medicina Legal, a la que Saturnino no muestra interés en acudir y la “colaboración” (o todo lo contrario) de su hermano Tomás. Hay también captura de pantalla de WhatsApp de éste último. Seguimos. De: Antonia María Ramirez >areasocial3@futuex.es> Enviado el: jueves, 15 de diciembre de 2022 15:12 Para: ANA MATAMOROS GOMEZ >ana.matamorosg@salud-juntaex.es> Asunto: Re: Saturnino Miguel Salgado Buenas Ana, otra vez.. jajja No recuerdo yo tampoco si te he enviado lo ultimo que supimos de el, en una seguimiento a finales de Octubre. Te lo pongo por aqui: Saturnino Salgado Jiménez 20/10/2022 Se realiza visita de seguimiento en Alcuéscar, el encuentro con el tutelado se produce gracias a la intermediación de su primo que lo persuada para que acuda a su bar y se reúna con la educadora de apoyo, puesto que el rechaza el seguimiento, no obstante, acude, pero le cuesta mantener conversación, tan solo aclara algunos conceptos económicos. Explica también que tiene adquirida una deuda con su primo por el tiempo que ha esta sin poder cocinar en casa y comiendo en su bar, en total la deuda asciende a 348€ tras preguntar a Miguel, primo del tutelado, dicha deuda asciende a 348€ correspondiente a gasto de alimentación en el bar por el periodo de tres meses y según las explicaciones de Nino y el dinero que está gastando y retirando en la actualidad se estima complicado que pueda hacerle frente, por lo que se acuerda que Miguel realizara una factura para que se valore autorizar o no el abono de eta deuda mediante transferencia. La conversación el tutelado se inicia a través de una propuesta para realizar un presupuesto estimado de gastos que permitan cubrir sus necesidades, se acuerda con el solicitar una subida de asignación de 50 a 75 euros que desglosa de la siguiente manera: - Alimentación---------------------------35€ semanales - Tabaco-----------------------------------15€ semanales - Productos de limpieza-----------------5€ semanales - Gas Butano-----------------------------20€ semanales Total-----------75€ semanales Saturnino realiza una solicitud ajustada valorando que hay productos que duran más de una semana por eso calcula por ejemplo 5 euros en productos de limpieza de forma semanal, debido a que una semana le faltarán unos productos y otras serán otros por lo se puede equilibrar el gasto. Con respecto a la conexión de electricidad para el suministro de la vivienda explica que le han dado el enganche ese mismo día y la compañía eléctrica CHC ya dispone de sus datos bancarios para la domiciliación del pago. También explica que ha realizado la domiciliación con el suministro de agua. Comunica también que ha comprado una lavadora que está pagando a plazos, según explica a través de domiciliación bancaria, calcula que terminara de pagarla en unos 5 ó 6 meses. De la misma forma comunica que necesita comprar ropa y también quiere comprarse un ordenador y un altavoz subwoofer. Al recordarle la citación para el instituto de medicina legal el tutelado manifiesta que ya le han comunicado la citación pero que no va a acudir porque no tiene medios para viajar a Cáceres, al intentar motivarle para la asistencia y buscar opciones de transporte, cambia radicalmente su tono en la conversación y se levanta marchándose sin dar opción a replica. Esa misma mañana a las 10:30 y tras haber intentado contactar con el hermano del tutelado para que le comunicara la citación judicial del próximo día 28 de octubre se recibe vía WhatsApp un mensaje de Tomás donde pide que no contacte más con él, se aporta continuación captura de pantalla. El hermano de Saturnino desde luego, no es una referncia en estos momentos, digamos muy lúcida. El 15/12/2022 a las 10:47, ANA MATAMOROS GOMEZ escribió: Buenos días Toni, Creo que no llegué a contestarte a este correo, sólo preguntarte si desde el mismo ha habido alguna novedad. Seguimos. De: Antonia María Ramirez >areasocial3@futuex.es> Enviado el: viernes, 14 de octubre de 2022 9:21 Para: ANA MATAMOROS GOMEZ >ana.matamorosg@salud-juntaex.es> Asunto: Re: Saturnino Miguel Salgado Hola Ana, que tal? Te resituo con el tema de Saturnino, no se le puede ver hace tiempo, porque rechaza frontalmente las visitas... desde que se instaló en Alcúescar, permitió algo al principio pero muy poco. En cuanto precisamente no tuvo todo el dinero que deseada, empezo a bloquear el contacto con la compañera, no le cogía el telefono, y ya por último cuando se acercó a la localidad, le dejó muy claro que no queria verla y que no queria saber nada de la comisión ni relacionado, bueno ni de nadie que le diga como tiene gestinarse, incluyo fue bastante beligerante en el discurso "como sigas viniendo tu y yo vamos a tener problemas serios"... y cosas asi. Te acuerdas que nos solicitaste un informe para el juzgado ahi lo expresabamos todo. De hecho, por parte de Ines de la comisión, nos ha hecho llegar un par de veces o tres, una notficación para el forense para que se la hicieramos llegar y siempre ha sido a traves del hermano o el primo poq con el, es imposible, no nos coje el telefono ni permite visitas.Por cierto, que no se ha presentado o no se que ha pasado para que le hayan tenido que citar varias veces, ahora hay una pendiente para el 28 de este mes e intentaremos yendo a Alcuescar pero si no, pues a traves del hermano o si no su primo en del bar de alli. Al parecer el tiene que ir a firmar al juzgado de Paz no sabemos si todas las semanas, creemso que las notificaciones se le pueden hacer llegar ahi.. (sino esta sucediendo ya) pero creemos que no ha ido a Cáceres a las citaciones anteriores, poruqe no le ha dado la gana. Es decir, prodemos indagar si vemos que nos permite algo, esta situacion, pero visto las ultimas veces, no albergo muchas expectativas de exito, y dado el perfil violento y con antecendentes no vamos a forzar una situación complicada. Sabes que creo que ha podido influir tambien, en esta epoca? el hermano, que ha sido muy muy critico tambien con la comisión como bien sabes, porque te ha mandado emails, exigiendo que Nino cobrara toda su pensión y no razonando , ni entendiendo lo que signfica la administracion de bienes en una tutela, porque en epocas anteriores antes de entrar en prision, era complicado pero se le podia visitar y tenia buena adherencia en general con la compañera, todo se ha vuelto más dificil desde este ultimo periodo. No obstante se ira a Alcuescar y si conseguimos algo te lo comentare, y sino, pues tambien. Buen dia! El 14/10/2022 a las 8:38, ANA MATAMOROS GOMEZ escribió: Buenos días Toni, En relación a SATURNINO MIGUEL SALGADO, desde la sección económica nos solicitan que en la próxima visita abordéis con él la cuestión de los consumos de suministros del hogar. Me pasan esta información que te facilito para que la tenga en cuenta en la intervención con él: 1. DESDE HACE 1 MES LE ESTÁ DANDO AL TUTELADO 50€/SEMANA (217 €/MES) Y A PARTIR DE AHORA SEGUIRÁ NUESTRAS INSTRUCCIONES. 2. NOS INFORMA QUE EL TUTELADO HA COMPROMETIDO 50 €/MES PARA EL PAGO DE ELECTRODOMÉSTICOS PARA LA CASA (TENEMOS QUE AVERIGUAR FECHA FIN DEUDA PERO APROX. 1 AÑO). 3. CONSUMOS: IMPOSIBLE DE CUANTIFICAR TODAVÍA...SI ALGUIEN PUDIERA VISITARLE Y CONCIENCIARLE SERÍA PERFECTO. 4. TELEFONÍA: IMPOSIBLE DE CUANTIFICAR. IDEM QUE ANTERIOR. CON INDEPENDENCIA DE LO ANTERIOR SERÍA POSITIVO QUE SE VISITASE AL TUTELADO PARA PACTAR UN PRESUPUESTO MÁS REAL” Por otra parte, parece que continúa sin beber alcohol y no tenemos constancia de que haya provocado ningún incidente en el pueblo, ya nos vais diciendo. Un saludo y buena mañana. -- ________________________________________ Antonia María Ramírez Cruceras. Psicóloga. Coordinadora Área Psicosocial email: areasocial3@futuex.es FUTUEX: Fundación para la Promoción y Apoyo a las Personas con Discapacidad Tel.: 924491914 - Fax: 924492051 Plaza Santa María 5 - Apartado 84. 06100 Olivenza (Badajoz) www.futuex.es ________________________________________','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-16','Buenos días Confirmo que este domingo será la mudanza de María Jesús Cruz al piso de su tía materna. La plaza queda guardada hasta el 8 de enero y la seguiremos supervisando y trabajando hasta dicha fecha. Un saludo. Alicia Psicologa Pisos supervisados de Almendralejo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-12-16','Ana: llamada de Macarena, Coordinadora del SAD Municipal de CC (gestión privada EULEN / 699 440 535). Me comunica que esta mañana cuando Ana, Aux. SAD, ha acudido al domicilio, Ventura no le abría, la puerta, resulta que se había caído y no podía levantarse. Han tenido que llamar al 112, han acudido los bomberos y ambulancia con médico. *Han roto una de las cerraduras. Habrá que arreglarlo. *Me pondré en contacto con el seguro pues tiene seguro de hogar. ······· En principio no ha sido nada grave pues el médico ha decidido dejarlo en casa. ············ La Aux. se ha quedado con él hasta que lo ha visto mejor. ············· Tras irse el médico, mientras la Aux. hacía otras tareas, tras ponerle el desayuno, ha vuelto y estaba sentado pero medio caído hacia un lado y se había orinado. ···· Creen que ha ocurrido como consecuencia de los nervios, pues tras asearle y demás, se encontraba mejor, ha conseguido que se pusiera de pie y caminar. ··· Los niveles de azúcar y tensión estaban bien. ················· Me enviará el Informe de Asistencia Sanitaria. ························································································································································································································ Más tarde llamo a Ventura numerosas veces, pero salta continuamente el buzón de voz. No consigo hablar con él. ············ La coordinadora de SAD (Eulen) intentará estar pendiente el fin de semana por si hubiera que llamar al 112. ·································································································································································································· Llamo a MAPFRE (918 365 365): Comunico la incidencia. Nº de expediente: L74208321. ··········· Intentará que acudan a arreglar la cerradura esta misma parte. Lo han tramitado como urgente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-16','Ana: Llamo al ESM-CC, hablo con Mabel, Psiquiatra (54604): corrobora que no se le ha visto desde el equipo desde que ingresó en Prisión y que tiene la cita programada mediante Telemedicina el día 22/12. Me enviará al email nota informativa de la consulta. *Valorará la posibilidad de derivación a CRR. ······· *Tendrá en cuenta la fecha de excarcelación para dejar solicitada cita programada de seguimiento. ·································································································································································································· Llamada de Julia Luján, madre de Sergio (924 626 557): pregunta por las opciones de su hijo a la salida de prisión. Le da miedo que vuelva a las andadas. Dice literalmente que "es un psicópata", "un peligro para la sociedad". ····················· Recuerda que su hijo tiene un plan de ahorros en el banco Santander. ········· Comunico esto último a la sdecc. ecca. pues en el Inventario no consta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2022-12-16','-Comunicación de plaza en CRR : Buenas tardes compañeras: Os informamos que acabamos de enviar el expediente de Francisco Giraldo al Director del CRR de Mérida, Javier Pecero. Ayer hubo una Renuncia y le toca a él por lista de espera de emergencia social. Lo citarán para la entrevista previa al ingreso. Nos comunicó Manoli, la Trabajadora Social del Sociosanitario, que el día 26/12/2022 finaliza la medida de internamiento involuntario de este paciente. Esperamos que vaya todo bien y se adapte bien al recurso. Saludos y buen finde!!Eva Eva Paredes Santiago 924 93 03 52 - 68420 Sección Salud Mental Unidad de Programas Asistenciales','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-19','Ana: Contesto al correo a Javier Navareño, director de la Casa de la Misericordia de Pinofranqueado (aromasdecaridad@hotmail.com): "Pues tiene 45 años. No está valorado por dependencia, de hecho hemos solicitado recientemente su valoración. Tiene reconocido por el CADEX un grado de discapacidad del 51% con Diagnóstico de Trastorno Mental por Trastorno de Personalidad." ················· Respuesta de Javier: "Teniendo en cuenta la edad del solicitante lamento tener que responderle que, aun teniendo plazas libres, no podríamos acogerlo como residente. En el mes de noviembre, como respuesta a una consulta enviada desde la dirección de este Centro, el SEPAD nos recordaban que, a tenor de lo establecido en el Decreto 88/1996, de 4 de julio, en el artículo 2.1 (donde se establece los requisitos de “edad mínima de admisión”) la edad mínima es de 65 años. En el caso de pensionistas se puede rebajar a 60 años. Y de manera excepcional incluso a 50 años. El caso que nos presenta no lleva ni siquiera a esa edad “excepcional” que marca el Decreto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-12-19','Ana: Reenvío a Secc. Ecca., presupuesto para ropa que me remite Minerva, TS del CR Cervantes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2022-12-19','Ana: Subo al portafirmas digital la autorización para la participación en los JEDES. *Los 10€ de inscripción los cogerán del fondo que tienen en la entidad para gastos de bolsillo de Joaquín. ··············· Una vez firmada por el presidente de la CTAEX la envío a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-12-19','Ana: Subo al portafirmas digital la autorización para la participación en los JEDES. *Los 10€ de inscripción los cogerán del fondo que tienen en la entidad para gastos de bolsillo de Adrián. ··················· Una vez firmada por el Presidente de la CTAEX se la envío a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-12-16','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "solicito la AUTORIZACIÓN para que Mª Antonia Bravo Patillas pueda acudir a su pueblo con su hermano en las Navidades, desde el 25 de diciembre al 1 de enero, así mismo solicitar los 100 € de gastos como habitualmente. (Adjunto autorización)".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-12-19','Ana: Se autoriza el extra de 100€ para el viaje de navidad a casa de su hermano y envío la autorización, ya firmada por el Presidente de la CTAEX a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-12-19','Ana: Llamada de Julia Durán, TS Hogar de Mayores Peña del Cura (22032) al parecer Ventura está enfadado con la CTAEX porque dice que no se le permite ser socio de la Asolación del Cáncer, cree que si se le dejara asociarse a cambio se mostraría más dispuesto a colaborar con todo y aceptaría el seguimiento de Futuex. ········· Se informará de la cuota y nos dirá. ············ Dice que el viernes faltó a una actividad de ajedrez, él avisó de que estaba malo y por eso no iba. ·············· Informo acerca de la incidencia acaecida. ·································································································································································································· Llamo a Macarena, Coordinadora EULEN del SAD Municipal de CC (699 440 535 / mcabanillas@eulen.com): *Ventura *Hoy mismo han arreglado la barandilla de la terraza a través del seguro de la comunidad de vecinos. ········ *Ventura ha pasado bien el fin de semana. Se encuentra mucho mejor. ··· *Ya han preparado la ropa para el viaje a Sevilla con la ONCE. ································································································································································································ Óscar, secc. ecca. me reenvía información del viaje de la ONCE facilitado por Cristian Díaz (CRDR@once.es): "...actividad ‘Navidad en Familia’ para que el afiliado Ventura Gómez pueda acudir con normalidad. Día de salida: 22/12/2022 Hora de salida: 9.00 Lugar de salida: Estación de autobuses de Cáceres Destino: Hotel ILUNION Alcora (Sevilla) Hora de llegada a destino: 14.00 Excursión: Córdoba (sin fecha). Día de regreso: 02/01/2023 Hora de inicio de regreso: 08.00 Hora de llegada a Cáceres: 13.00 Lugar de regreso: Estación de autobuses de Cáceres. Espero que la información sea de utilidad y, si tiene alguna duda, llámeme al 600 53 66 97." ····································································································································································································· Llamo a MAPFRE (918 365 365): Me informan que el viernes acudió el cerrajero pero Ventura no abrió la puerta. *No obstante, me informa que este servicio habría que abonarlo a parte, pues no le entra con su seguro... ················ Comunico el nuevo número que me ha facilitado Macarena de Ventura (682 48 31 26) y pido que vuelvan a enviar al cerrajero. ·········································· Lo comunico a Macarena, EULEN y a Julia Durán, TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-12-19','Ana: Envío a Rosa Bravo, Adtvo. CSS-Plas. (rosamaria.bravop@salud-juntaex.es) CI para Cirugía de Cataratas O.D. y la solicitud de inclusión en lista de espera, debidamente firmados y sellados por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-12-19','Ana: Correo de Blanca, Directora del CRR-Plas. (direccion.crrplasencia@grupo5.net): "Te comentamos de Isa, ayer tras caerse en la ducha e ir a urgencias para consulta, ingiere objetos refiriendo malestar por juicio de esta semana el día 23. En el hospital tras el traslado de urgencias, se va y nos llama que no la atienden verbalizando ideas autolíticas. Se consigue dar con ella y vuelve al hospital. La trasladan a Cáceres donde la hacen endoscopia pero no consiguen extraer todos los objetos, ahora está en Plasencia a la espera de otra endoscopia." ······················ Nuevo correo de Blanca: "Isabel ya está de vuelta en el CRR. El objeto que le queda (llaves) las deberá expulsar de manera natural, y tras valoración psiquiátrica no se considera que haya presencia de ideas autolíticas. Os mantenmos informadas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-12-19','Ana: Correo de Alicia Cordón, Psicóloga PP.SS. Almendralejo (psicologia.pisosalmendralejo@grupo5.net / 674 35 51 64): "Te escribía para comentarte un poco la situación de Francisco Cacho Garrido. Me comenta que él cobra 480 euros y solo tiene permitido sacar 340. Le gustaría que pudiera sacar todo el dinero, en su completo. Él ahora tiene que pagar 160 euros al mes para la comida y comenta que el resto no es suficiente para todo lo que tiene que pagar, que es su madre quién le pagaba la ropa y que ya no puede. En mi opinión, aunque se le aumente algo, no se le debería entregar el dinero por completo. Ahora mismo está muy desorganizado, quejándose de todo y sin ser capaz de dormir, lo cual comprendo que es un factor de riesgo para volver a consumir." ···················· Mi respuesta: "Siendo así, estoy totalmente de acuerdo contigo. No creo que sea adecuado aumentarle la asignación y mucho menos darle todo… de todas formas, creo que, como argumenta lo de la ropa, si consideráis que realmente presenta esta necesidad, podéis decirle que nos podéis enviar presupuesto de ropa a su nombre, y que se valorará y, en su caso, aceptará por la sección económica y podrá comprar la ropa. Se abonaría desde aquí a mediante transferencia bancaria. Si consideráis aumentarle la asignación, un poco, dime cuantía aproximada y se valora con el jefe de sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-12-19','Ana: Envío a Soraya Masa, Jefa Ud. PPAA con copia a Maite, Jefa Secc, informes relativos a Aarón, para valoración de derivación a Piso Proyecto Mi Casa - Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-19','-Email de la psicologa del Piso de Almendralejo: Confirmo que la fecha de alta de María Jesús será el 8 de enero. Ahora está en proceso de mudanza, disminuyendo progresivamente la supervisión por nuestra parte y observando qué tal va la convivencia con su tía. La firma del alta voluntaria la completáis vosotros o lo puede realizar ella? Por otro lado, María Jesús impuso una denuncia el día 1 de octubre de 2021 a la que refirió era su pareja. La única documentación que tenemos judicial es esa, aunque ella nos comentó que presenta una orden de alejamiento con dicha persona. Estas últimas semanas estuvo en contacto con un recurso de Mérida de violencia de género que le realizaba seguimiento sobre dicha situación. Si precisas de mayor información, hablo con ella. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-19','-Amalia : me llama M.Jesús ,desde el fin de semana ya está viviendo con su tía Manola Tf . 648573426 en C/ Costa Rica , 9 2ºb de Almendralejo . Solicita que se le suba los 380€ que percibe pq en la casa va a entregar 300€ . Solicita la mitad de la extra y que el tema dental lo va a quedar parado . La subida creo que es mejor esperar a enero y ver revalorización de las pensiones . Preguntar a sección eco si le damos algun extra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-12-19','miguel, envío email a notaria de Herrera del Duque: Buenos días Loli, estamos intentando hablar con vosotros urgentemente. Nos ha llegado contrarrembolso las escrituras de declaración de herederos que estábamos pendientes de recibir del hijo de la tutelada Alfonsa Montalban Serrano. Desde la Comisión no disponemos de pagos en efectivo (sólo podemos hacer transferencias desde la cuenta de los tutelados) por lo que las escrituras os la devolverán desde Correos y tendréis que pasarnos nueva factura por el importe de correos para que os podamos hacer la transferencia. Por favor intentad agilizar el envío de dichas escrituras una vez que os la abonemos. ***************************************************** recibo email de Loli: Buenos días, Miguel Alberto Ya hemos remitido las escrituras de los protocolos indicados y modificado la factura errónea. le adjunto nuevamente las dos facturas con la que estaba errónea rectificada. ************************************************** miguel, envío email a Oscar: Buenos días Oscar, la notaria de Herrera del Duque nos ha remitido por correo certificado las escrituras de declaración de herederos a portes debido, por lo que le van a ser devueltas desde correos. Les he pedido que modifiquen las facturas e incluyan el importe del envío de dichas escrituras. Comprueba si habéis pagado ya algo o no, y si estuviera todo correcto por favor abonad el importe y cuando le envíes justificante de transferencia indicadle que lo envíen a portes pagados a nuestra dirección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-19','-Amalia , escribo a jurídicos y Mayte para informarles : Buenos días , la semana pasada me llamaron de este recurso de Violencia de Genero para comentar que M. Jesús Cruz había ido a visitarlos . Desconocíamos estos hechos que ocurrieron poco antes de asumir la tutela . Os paso las medidas judiciales que se plantearon en su día . Saludos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-12-19','miguel, email de Rocio Gracian: Buenos días Miguel, He llamado al teléfono que me diste pero está apagado Te adjunto la Dligencia del Juzgado que responde a la solictud de la otra parte de comparecencia de Damián. La abogada contraria pidió erroneamente la comparecencia de Damián como TESTIFICAL, y eso no es posible porque la parte no puede comparecer como testigo. Como ves, la Diligencia del Juzgado le dice eso pero no deja claro si realmente tiene que comparecer o no, pues no sé si está diciendo que no puede comparecer porque no es testigo o que comperece pero para interrogatorio de parte. Tampoco sé si cuando dice que se tiene por anunciado el interrogatorio de parte se está refieriendo a que es la Comisión la que tiene que comparecer y no Damián. En vista de este lio, me he personado esta mañana en el Juzgado pero la funcionaria que lo lleva está hoy de teletrabajo, así que me han dicho que llame mañana. Espero que mañana me lo aclaren. Lo que si me han adelantado es que no suelen admitir videoconferencias, así que vamos a tener un problema. De todas formas mañana te confirmo todo. Estoy también en conversación con Javier Pecera y me dijo el viernes que me hará un informe de la necesidad de que se realice la videoconferencia y que Damián debe estar acompañado por ellos en la declaración. Como puedes ver en la Diligencia, el Juzgado va a librar exhorto al de Mérdia para que informen sobre si habéis solicitado o no la revisión de las medidas. He estado mirando la ley detenidamente y entiendo que en nada afecta que no se hayan revisado aún para que continúe el procedimiento. Entiendo que en virtud de la disposición transitoria se puede considerar que hay una continuidad en el cargo de la Comisión Tutelar en la representación de Damián para este asunto concreto de carácter patrimonial hasta la revisión de las medidas. ¿No lo crees así?, ¿Conoces casos en los que por no haber iniciado la revisión de las medidas se han paralizado los procedimientos?. Me quedé preocupada el viernes cuando hablamos. ******************************************************** mi contestación: Buenos días, perfecto, quedo a la espera de lo que puedas averiguar con la persona del juzgado que está teletrabajando. Comentarte de nuevo que conforme la disposición transitoria 5ª la antigua curatela de Damian hasta su revisión es actual curatela asistencial, siendo los límites de la misma los que aparecían en la antigua sentencia de incapacitación, hasta que conforme la nueva ley 8/21 proceda de OFICIO (por Juzgado y/o Ministerio Fiscal) a revisar en plazo de 3 años dicha sentencia. En cuanto a la videoconferencia si no puede darse, como mínimo tendrán que hacer un exhorto a los juzgados de Mérida porque a Málaga no vamos a ir ni Damián ni nosotros… Si el juzgado le quedan dudas de la capacidad (la legitimidad de Damian y la Comisión que actúan conjuntamente no creo dé lugar a dudas), deberían pedir informe pericial del forense mediante exhorto a los juzgados de Mérida. Mañana si te parece lo comentamos todo.','2');
