insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-19','miguel, contesto a Maite, Amalia y copia a Angel: Buenos días, acabo de llamar al juzgado (nº4 Mérida DPA 255/21)para interesarme por el procedimiento y me confirman que todavía está en instrucción el procedimiento y que está pendiente de resolución por parte del Ministerio Fiscal a un recurso que se interpuso, con lo que la medida de alejamiento a 300 metros y prohibición de comunicarse siguen vigentes. Me dicen desde el Juzgado que no les consta el incumplimiento de las mismas y por tanto creen que se estarán cumpliendo. Seguiremos pendientes de este procedimiento.','2');
