insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BARQUERO'and apellido2='MARTIN'),'2022-12-19','EXITUS Tras el descubrimiento hecho por la compañera Estrella, al hablar con la compañía de seguros Ocaso, se recaba, por parte de la compañera María, el hecho de la defunción de D. Antonio. Finalmente, tras esperar unos días, el centro informa de su óbito, acaecido el 19/11/2022. Fecha que ya adelantó la compañía de seguros.','2');
