insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2022-11-25','miguel, solicitado por lexnet al juzgado decano de Badajoz, el internamiento involuntario del tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-12-20','miguel, enviamos por lexnet informe social del CRR de Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2022-12-20','miguel, recibo email de Amalia: Este email me acaba de llegar del centro , yo no tenía conocimiento de esta revisión. Le pido al centro informe ??? aunque como veis estos van por libre. Saludos. ****************************************************** email de la educadora social Sandra Sanchez de OCEDIS Sandra Sánchez >ssanchez@inteligencialimite.org> Buenas. Informaros que el día 13 de diciembre Juan José Murillo Romano fue citado en el Instituto de medicina legal para revisión de sus medidas de apoyo. Durante la citación con la médico forense, ésta evaluó que en principio Juan José necesita apoyo en más ámbitos que el patrimonial. Estamos a la espera de la citación judicial. Saludos. *************************************************** email de Angel: Buenas, No estoy tramitando la revisión de la sentencia de Juan José Murillo Romano. Creo que en su día Miguel te envió algún correo solicitando informe social, porque desde los Juzgados nos instaban a solicitar la revisión, entre la que se encuentra esta de Juan José Murillo Romano. Un saldo. *************************** mi email: Hola no tengo constancia de esta revisión de sentencia, que imagino la habrá instado el Ministerio Fiscal. No tenemos referencia ni de juzgado ni de número de procedimiento. Entiendo que el centro debería remitir cualquier información que le llegue de los juzgados inmediatamente a recibirla. Os adjunto los emails de lo único que conozco…de septiembre donde quedó claro que sólo teníamos competencia en la esfera patrimonial de esta curatela. En dicha fecha se le acusaba de cómplice en un supuesto delito de robo y del cual si veis la intranet Angel solicitó información al juzgado, que creo no ha llegado nada. En definitiva que ni desde el juzgado ni desde el centro se ha facilitado que yo sepa información de este curatelado *******************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2022-12-20','Amalia : pido a s. eco información de sus ingresos: EN SU CUENTA APARECEN LAS SIGUENTES PENSIONES 671,48€ 767,50€ Y una prestación por desempleo que ha empezado a cobrar el 10 de noviembre por importe 250,25e','2');
