insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2022-12-20','-Amalia : escribo a Sandra de Aexpainba con respecto a la revisión de las medidas : Buenas , he preguntado al asesor jurídico si tenía conocimiento de esta revisión y me indica que no . "Hola no tengo constancia de esta revisión de sentencia, que imagino la habrá instado el Ministerio Fiscal. No tenemos referencia ni de juzgado ni de número de procedimiento. Entiendo que el centro debería remitir cualquier información que le llegue de los juzgados inmediatamente a recibirla." Desde el juzgado os van a solicitar informe del equipo en el que indiquéis cuáles son las medidas de apoyo que como guardadores creéis que puede necesitar . Cuando lo tengáis podéis reenviármelo y se lo derivo al asesor jurídico para que esté al tanto . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-20','Miguel : Buenos días, acabo de llamar al juzgado para interesarme por el procedimiento y me confirman que todavía está en instrucción el procedimiento y que está pendiente de resolución por parte del Ministerio Fiscal a un recurso que se interpuso, con lo que la medida de alejamiento a 300 metros y prohibición de comunicarse siguen vigentes. Me dicen desde el Juzgado que no les consta el incumplimiento de las mismas y por tanto creen que se estarán cumpliendo. Seguiremos pendientes de este procedimiento. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-12-15','miguel, envío email previa llamada a Paco Vela 1804@icaba.com (abogado recomendado por Lorenzo) cuyos datos son tlf movil:619549406; Fijo:924523507, email: 1804@icaba.com Buenos días, conforme conversación telefónica de esta mañana le remito mi email, donde necesitaremos tanto la autorización judicial de aprobación de la herencia firmada y posteriormente la autorización judicial para poder vender los inmuebles que la forman. He comentado a Lorenzo Garcia Cruz que se acerque a dejarle los originales. Una vez lo estudie necesitamos nos de un presupuesto y trámites a realizar lo más ajustado posible para comenzar cuanto antes con dichos trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-20','Miguel : Buenos días, acabo de llamar al juzgado para interesarme por el procedimiento y me confirman que todavía está en instrucción el procedimiento y que está pendiente de resolución por parte del Ministerio Fiscal a un recurso que se interpuso, con lo que la medida de alejamiento a 300 metros y prohibición de comunicarse siguen vigentes. Me dicen desde el Juzgado que no les consta el incumplimiento de las mismas y por tanto creen que se estarán cumpliendo. Seguiremos pendientes de este procedimiento. Saludos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2022-12-20','-Amalia . le reconocen cpto. de pnc por 3ª persona , pasa a cobrar 726,92€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-12-19','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comunicarte que hoy dan el alta a Felisa y regresará esta tarde. Mañana te informo con más detalle de cómo es su estado actualmente. Tengo que contactar con los compañeros de economía para ver posibilidades de que reciba regalo en su cumpleaños el día 28 de diciembre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-12-20','Ana: Correo del CRR-CC (crr@grupociudadjardin.com): "Adjunto enviamos consentimiento informado para la inserción de implante subcutáneo contraceptivo para la persona usuaria Consuelo Nevado Pacheco. Debemos presentarlos firmados antes del día 4 de Enero." ················ Les remito el CI firmado digitalmente por el Presidente de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-12-21','Ana: envío correo a Paula, en respuesta al que envió al ctutelar@: "Nos parece perfecto que trabajéis con Ceferino el aumento y desarrollo de sus habilidades para la toma decisiones de forma más autónoma y consciente, así como la anticipación y asunción de las consecuencia de las mismas. En cuanto a la controladora de sonido/mesa de mezcla Pioner 800 €, estamos totalmente de acuerdo con vosotras. Estaba asociada a unos compromisos y a los objetivos terapéuticos que establecéis con él en el centro. No cumplió su compromiso y no lo puede solicitar hasta febrero. Pero, ¿podríais aclararnos a qué compromiso está asociada ahora dicha compra, qué debe de cumplir para su compra? En lo referente al extra anual, según indica Alberto, Jefe de Sección Económica, el acuerdo al que llegasteis en su día, era que con dicha cuantía se cubrirían gastos, entre otras cuestiones que puedan necesitar, los relativos a ropa, calzado, cumpleaños, navidad, otras festividades… No obstante, este año, además de las asignaciones periódicas mensuales y la extraordinaria anual, se le han concedido extras para: zapatillas, cumpleaños, un móvil y la edición de su libro. Entendemos que este último corresponde a sus intereses y una actividad ocupacional, pero el resto de cuestiones debería haberse asumido con su extra anual, el cuál no sabemos en qué se ha invertido. *De todos modos, Alberto nos plantea que, de cara al próximo año, podéis plantear a la sección económica un aumento de dicho extra anual, si consideráis que él así lo requiere y teniendo en cuenta que, en este caso, podría permitírselo. Y si este año, no le queda presupuesto para el regalo de navidad, excepcionalmente se aceptaría la solicitud de la Nintendo switch Little, siempre y cuando el presupuesto no sea desmedido. Podéis remitir presupuesto de la tienda a nombre de Ceferino a la atención de la sección económica a ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-12-20','-email FUTUEX: Con fecha de , lunes 05 de diciembre de 2022, acudimos a la vivienda de Carmen Leal Benito para recoger EXTRACTO MOVIMIENTOS DE SU CUENTA EN CAIXABANK CON FECHA: 01-01-2021 AL 02-12-2022. Carmen acudió a su entidad bancaria el viernes 02 de diciembre a realizar su retirada de asignación y solicitó dicho extracto. Hemos tenido seguimiento con ella también el miercoles 7, por tener consulta presencial programada,en médico de atención primaria para revisión de su infección de piel, por el cual está en tratamiento de antibióticos. Está mejor de dicha afección cutanea. Saludos! --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-12-20','-email FUTUEX: Con fecha de , lunes 05 de diciembre de 2022, acudimos a la vivienda de Carmen Leal Benito para recoger EXTRACTO MOVIMIENTOS DE SU CUENTA EN CAIXABANK CON FECHA: 01-01-2021 AL 02-12-2022. Carmen acudió a su entidad bancaria el viernes 02 de diciembre a realizar su retirada de asignación y solicitó dicho extracto. Hemos tenido seguimiento con ella también el miercoles 7, por tener consulta presencial programada,en médico de atención primaria para revisión de su infección de piel, por el cual está en tratamiento de antibióticos. Está mejor de dicha afección cutanea. Saludos! --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-12-21','-Email de CRR , finalmente regresa al centro a pesar de haber solicitado el alta. Buenas tardes Os adjunto un nuevo alta voluntaria de Emilia. El martes agredió a un profesional y el resto de la semana ha presentado conductas desajustadas con compañeros. L e cuesta aceptar la gravedad de sus conductas y cuando se le marca y pone límites se marcha del centro . Hoy, ante los límites que se le han planteado como consecuencia de su conducta( no compartir los turnos de comedor con compañeros y pasar más tiempo en su habitación durante el fin de semana ) ha decidido solicitar el alta voluntaria e irse a casa de su amigo Antonio. Hemos acordado que regresara el lunes a las 16:30 a cita conmigo para valorar si mantiene su decisión de alta. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-12-21','Ana: Tras llamada de Estrella, TS del CSS (24146), envío correo a Alberto, Jefe Secc. Ecca.: "Me comunican desde el C. Sociosanitario de Plasencia que Remedios Chaves Masero ha ingresado en el hospital de Plasencia con una neumonía. Dadas las características requeriría acompañamiento hospitalario el mayor tiempo posible, pero no sé si puede permitírselo…. En la empresa EDADES informan al Socio de los costes: - Día completo (24 h): 155 € apróx. con IVA - Precio hora durante el día: 14,3 €/ hora (IVA incluido) - Precio hora durante la noche: 15, 4 €/ hora (IVA incluido) Dime si es viable, hay que contestar lo antes posible" ··································································································································································································· Estrella también me comunica que el teléfono de la empresa EDADES (646 71 54 76) y que le han dicho que no pueden garantizar el servicio en Nochebuena. ························· *Por otra parte, informa de que hay una voluntaria de Aprosuba 3 que ha ido a visitarla y que volverá a verla el día 28. Nos parece estupendo, siempre que no sea contraproducente para las personas, nos parecen bien este tipo de contactos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-21','Ana: Envío correo a Yessica, TS de Cáritas Plasencia (ydearriba@caritasplasencia.org): "Quería consultaros si en el Centro para Personas Sin Hogar de ahí de Plasencia tenéis plazas disponibles. No sé si tú me puedes responderme a esto y sino, dime exactamente a quién tendría que hacer la consulta. Se trata de un chico de 45 años, del que la Comisión Tutela ha aceptado recientemente el Cargo de Curatela Representativa. Sale el mismo día 6 de enero del Centro Penitenciario de Cáceres y no tiene adónde ir. Agradecería que nos indicaseis si es posible si hay posibilidad de que accediera a vuestro recurso el día 6." ······························································································································································································ Envío nuevo correo a Javier Navareño, Director de la Casa de la Misericordia de Pinofranqueado (aromasdecaridad@hotmail.com): "Buenas tardes Javier, Me plantean desde la Unidad de Programas Asistenciales del SEPAD, si esta persona no tendría cabida a través del Programa Residencial para Trastorno Mental Grave que se subvenciona desde el SEPAD." ····························································· *Respuesta de Javier: "Ciertamente no había tenido en cuenta la posibilidad de que el solicitante de la plaza pudiera participar del Programa de Apoyo Residencial para Trastorno Mental Grave. Tras valorarlo sí que la considero una opción viable. Ya le he abierto una ficha como solicitante de plaza. Si le parece oportuno puede remitirnos un informe más completo, para que pueda ser valorado por el equipo interdisciplinar de la Casa. De esta forma, cuando llegue el momento de que tengamos una plaza, podamos agilizar los trámites." ····································································································································································································· Llamada de Lola Bernal, TS de SSASB de la Mancomunidad de la Siberia (924 626 001), llevaba el expediente cuando Sergio residía en su pueblo. Ha hablado con la madre de Sergio. Le explico como está situación y la dificultad para encontrar recurso para él. ··· *Le recuerdo que en la sentencia no pone nada de ingreso en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-12-21','Ana: Reenvío a Secc. Ecca., presupuesto para abrigo que me remite Minerva, TS del CR Cervantes (minerva.salvador@salud-juntaex.es). Doy mi ok, en caso de ser viable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2022-12-21','Ana: Envío correo a Toni-Futuex: "¿podríais confirmarme si ya habéis hecho visitas a JOAQUINA MAYORAL PIZARRO y en tal caso, informarme al respecto. Nos llega por la hija que hay indicios de que se ha descompensado y necesitamos verificar esta información. Ya me dices cuando puedas." ··································································································································································································· Respuesta de Toni: "...llamada, como primera toma de contacto: Aprovechando la estancia en la localidad de Miajadas de hace algunas semanas, se intenta organizar una primera visita a Joaquina. En un primer momento, se contacta vía telefónica, la educadora se presenta, Joaquina comenta que no sabe por qué se le está llamando, pues no tiene nada que ver con la Comisión ni con la Junta, ella no tiene ninguna tutela ni nada, señala que lo único que tiene es problemas con la gente de la calle, quienes le dicen que no puede estar en su domicilio, que debe estar en un centro. Se intenta empatizar, se le dice que la gente de la calle no es quién para opinar sobre su vida, se le pone de antecedente su estancia en CRR, su salida y quién gestionaba parte de su situación, se le dice que puede tener una curatela, en este momento ya lo admite y establece que tiene revisión el día 15 de diciembre en Trujillo, se le dice que es para todos, es por el cambio de Ley. En general rechazo frontal a cualquier intervención. Se le intenta explicar qué gestiones haría la educadora y hacerle ver que todo es apoyo para ver cómo se encuentra en el domicilio, señala que bien, además, el ayuntamiento le ha puesto S.A.D. y le ayuda. Se aborda el asunto de la visita, en esta primera llamada indica que lo tiene que pensar, que no sabe para qué. Se le vuelve a llamar más tarde, en última ocasión, acaba accediendo a tener contacto con la educadora, pero dice que en el día de hoy la visita no, pues no tiene la casa arreglada y demás…, resulta excusa, pero aceptando acercamiento para otro día, se considera que se ha conseguido bastante. El objetivo es planificar otro seguimiento lo antes posible, para ver cómo se encuentra realmente, si es cierto que le señalan en el pueblo, si sigue el tratamiento y revisión en salud mental, pero es posible que nos deje entrar, ya que como te describo su actitud es esquiva y rechaza el apoyo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2022-12-21','Ana: Correo de Toni-Futuex, para ctutelar@ y para mí: "Juan, en sus varias e insistentes llamadas, solicita y demanda un extra de navidad de #150# euros, aunque según su deseo, sería todos los meses. Expone que con los 70 euros semanales no le llega, que tiene que pedir a los amigos, además del bono de comida que le entregan de Cáritas parroquial. En la visita presencial realizada el 19 de octubre de 2022, comprobamos que, de los 70 euros, entre tabaco y café, poco le queda para alimentación u otras necesidades. Le recordamos que su pensión es pequeña y a esa cantidad debe adaptarse, pero él insiste en recibir mayor cantidad, para no caer en la "mendicidad" (según sus propias palabras) Confirmamos que el 14 de diciembre se ha administrado su inyectable mensual de Abilify, pero sigue negándose a acudir presencialmente a consulta de psiquiatría en Cáceres. Aunque, según la información recogida por los diferentes profesionales en Guadalupe, no se registran incidencias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2022-12-16','Ana: Correo de Óscar, Secc. Ecca. al Programa de Familias (pafmoraleja@mensajerospazex.es): "La sección económica da el visto bueno al presupuesto enviado, por lo que se enviará escrito a Caja Rural de Extremadura para autorizar el reintegro de 200€ quincenales, con el acompañamiento de la auxiliar de ayuda a domicilio. Igualmente, estamos a la espera de que el Caterin San Blas nos envíe el documento de domiciliación del suministro prestado. No sabemos si lo están cargando ya en la cuenta bancaria, ya que aún no tenemos acceso a dicha cuenta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2022-12-21','-Amalia : nos comunican desde el centro que esta ´trabajando por su cuenta a través de la F. Sorapán pero no saben cuales son los ingresos. Lo estará cobrando en la cuenta de Caixabank, a la cual no tenemos acceso. Se ha solicitado varias veces la cancelación, con traspaso de saldo a su cuenta de Ibercaja, sin resultado alguno. Hace unos meses solicité movimientos bancarios para la rendición, pero no recibí respuesta.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2022-12-21','Ana: Llamada de Rosana, R.M. Balcón de Extremadura - Montánchez (699 198 186): Van a llevar a Isabel al hospital, está muy delicada. Va a requerir acompañamiento. ··········· Si encuentra alguien de confianza nos lo comunicará y enviará presupuesto del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2022-12-22','-Amalia , vamos a informar al juzgado de la situación de Fco. He pedido a Futuex información de las ultimas visitas . Cuando llegue hago una breve comunicación de la situación actual ( ver email de Alberto ) y se lo envío a Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-12-22','Ana: Correo de Alberto, Jefe Secc. Ecca.: "ANA: DISPONE DE DINERO PARA ASUMIR UN ACOMPAÑAMIENTO DE CIERTA ENTIDAD....SALDO HOY: 7.500 APROX. ANA: LO VAMOS VIGILANDO...HAZTE A LA IDEA DE QUE X CADA 10 DÍAS DE 24 HORAS: SON 1.550 €...ACTUAS COMO VEAS DURANTE LOS 10 PRIMEROS DÍAS Y LUEGO LO VEMOS. ESTRELLA: VAMOS ABONANDO CONFORME NOS INDIQUE ANA...A LOS 10 DÍAS OBSERVAMOS CCC Y VEMOS LO QUE PUEDE SEGUIR ASUMIENDO." ·································································································································································································· Llamo a la empresa EDADES (646 71 54 76), hablo con Didi. Acuerdo acompañamiento 24 horas, al menos durante los primeros días. Comunico nº habitación: 521 - 1. ························ Envío correo a Alberto y Estrella, Secc. Ecca.: "ya he hablado con la empresa EDADES: Didi - 646 71 54 76 (os lo pongo por si en algún momento tenéis que hablar con él). Intentarán comenzar hoy mismo con el acompañamiento en el hospital de REMEDIOS CHAVES MASERO. En la Sección Social hemos decidido comenzar con 24 horas de acompañamiento y según evolución vamos viendo, si es necesario, reducir horas (en este caso comenzaríamos quitando las noches). Enviarán factura al ctutelar@ con los datos de Remedios, que ya le he facilitado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-12-22','Ana: Tras leer correos de Isabel y hablar con ella por teléfono, envío correo a Paula, TO, y Carolina, Psicóloga, del CRR: "Os reenvío email de Isabel Cano Blázquez, en el que solicita de nuevo dinero. El extra que se le dio por Navidad, era para “todas las navidades”, ahora pide dinero de Reyes. Yo ha he hablado por teléfono y se lo he explicado, pero igualmente, ¿podríais, por favor, explicarle de nuevo que ya se ha gastado el dinero que se le dio por las fiestas y de momento no se le puede dar más? Alberto, Jefe de Sección Ecca., dada su situación y teniendo en cuenta el dinero que se le da a la madre para que pueda visitarla y los viajes periódicos que realiza a su pueblo, no contempla autorizarle más dinero en el concepto que demanda. Pues también es importante tenerle algo ahorrado para cuando surjan otras necesidades, como cuando necesitó acudir a un servicio privado de Atención Psicológica Especializada. Así mismo, no sé si Óscar, compañero de Sección Económica, os lo habrá comentado, pero de cara al nuevo año, también se le podrá autorizar un extra anual, como se viene haciendo con el resto de residentes cuyo cargo ostenta la CTAEX."','2');
