insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-12-22','Ana: Envío a Mª Victoria, Aux. Admvo. ASINDI (victoria.adgestion.asindi@gmail.com) la Autorización para los JEDES debidamente firmada y sellada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2022-12-22','Ana: Finalmente, recibo correo de Rosana - Res. de Balcón de Extremadura (balconextremadura@grupociudadjardin.com) con información de una empresa de servicios de acampamientos de Cáceres. ······················· Llamo a la Empresa ASISTENCIA FAMILIAR DE EXTREMADURA, hablo con Benancio (665 687 948 /gerencia@asistenciafamiliarextremadura.com): El precio por horas los días laborables asciende a 12,50 € + IVA y los días festivos: 17,50 € + IVA. Igual cualquier hora del día y noche. *Los días especiales (Nochebuena/Navidad/Nochevieja/Año nuevo): 20 € + IVA. ··················· Envío correo con esta información a Alberto, Jefe de Secc. Ecca. con copia a Maite, jefa CTAEX. ···································································································································································································· Envío mail a Benancio, Empresa: "Tal y como hemos acordado mediante conversación telefónica, solicitamos acompañamiento hospitalario de Dª ISABEL PULIDO CARAVACA, con DNI: 75973517D y cuyo cargo de Tutor ostenta la Comisión Tutelar de Adultos de Extremadura. Se encuentra ingresada en el Hospital San Pedro de Alcántara de Cáceres, pero aún no le han asignado ninguna habitación. De momento la mantienen en observación en URGENCIAS. La directora de la Residencia, Rosana, se pondrá en contacto contigo, bien por mail, bien por teléfono, para indicar el número de habitación cuando la pasen a planta. En principio, y mientras no se le diga lo contrario, se solicita el servicio durante las 24 horas del día. Adjunto Resolución del Grado de Dependencia. Pongo en copia Maite, Jefa de Sección, ante cualquier duda puede ponerse en contacto con ella (924 00 60 57) o en el correo: ctutelar@salud-juntaex.es *A esta dirección es a la que deberá enviar la factura a nombre de Isabel."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-12-22','-Información desde CRR Mérida : te confirmo que Ruben Montero ha solicitado de manera autonoma la pensión de orfandad y le ha llegado la carta de aprobación, por lo que le ingresan atrasos y a partir de enero la pensión. Les he pedido toda la información al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2022-12-22','Ana: Correo de Cruz Merino, TS: "Ya se renovó Martín Quirós Berrocal el DNI, mañana he quedado con la persona que realizó el acompañamiento para que me de sus datos y os lo haga llegar para que le podáis pagar. Me ha dicho que como ha estado varias horas, dos días diferentes le va a cobrar 50€ Yo le he pedido que me lleve fotocopia del DNI y su número de cuenta para que le podáis hacer la transferencia. Dime si la declaración que firme necesita algún dato en concreto que tenga que aparecer para tratar de ser lo más ágiles posible." ·································································································································································································· De acuerdo, muchas gracias. Los datos que deben aparecer son los personales (nombre, apellidos y DNI) así como los datos de la persona a quien hace el acompañamiento, los días y el motivo. Incluyendo el número de cuenta. Recuerda que debéis enviarlo al: ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2022-12-22','Ana: Envío Informe Social a Javier Navareño, Dir ······· Correo-respuesta de Javier, Director Casa Misericordia Padre Leocadio: "Gracias por remitir el informe. Nos hacemos cargo de la necesidad y del estado de desamparo al que Sergio se expone a partir del día 6. Nosotros también deseamos que los reyes magos se porten bien le concedan a Sergio una plaza. Seguimos en contacto. Ante cualquier novedad le informaremos de inmediato." ······································ *Pido a Maite, Jefa de Secc., que consulte si hay plazas a los Centros de Cáritas de los que me han facilitado el contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-22','TF.Mª Jesus : 613918280 email : mariajesusmile@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-12-22','-Amalia : queda pendiente respuesta sobre el extra de Navidad desde la sección eco. Indico contactos de la chica para que puedan notificarselo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-12-27','Maite: Ha llegado a ctutelar correo del CRR de Plasencia comunicando ingreso de Isabel en UHB: ``Buenos días, ¡Felices fiestas! Os comento sobre Isabel Cano, se encuentra ingresada en la UHB del Hospital Virgen del Puerto. El 24 de diciembre, en la cena ante un situación habitual para ella, adaptación del menú ante alergia al marisco, ingirió objetos como horquillas, parte de unas tijeras... Se activa protocolo y traslada el 112 al hospital, hacen endoscopia en Cáceres y queda ingresada en la unidad de salud mental. Os vamos informando. Un saludo. ··············································· Nuevo correo de Blanca, Directora del CRR: "Buenas, Isabel Cano ha sido dada de alta y se encuentra en el CRR, tras hablar con psiquiatra se considera que los ingresos no tienen un impacto para el cambio. Isabel hace referencia a mayor malestar por Navidades, y juicios que tiene pendientes, os vamos informando de la evolución." ······································· Respuesta de Raquel Gómez, Enfermera Secc. Salud Mental (raquel.gomeza@salud-juntaex.es): "Me parece increíble que esa sea la valoración de psiquiatría en una paciente con intentos autolíticos frecuentes y con la cantidad de ingresos que tuvo por este motivo en la UHB. En primer lugar, nos plantemos que si según psiquiatría no precisa ingreso hospitalario por no conducir a cambios en su comportamiento y teniendo en cuenta que una paciente con intentos autolíticos repetitivos y frecuentes no es perfil para estar en el CRR nos tendremos que volver a plantear su permanencia en el mismo. Por otro lado, en la última subcomisión los profesionales del Centro Sociosanitario se comprometieron a trabajar con ella el control de estos comportamientos, nos gustaría saber si se está realizando estas valoraciones por parte del CSS y si tienen conocimiento de todos los intentos e ingresos que ha tenido desde entonces. De igual modo, seguimos considerando importante que por cada intento autolítico que presente por muy leve que pueda parecer se derive a la UHB para su valoración por psiquiatría. Me consta que desde el CRR se están llevando cabo todas las intervenciones necesarias para ayudar a controlar sus frustraciones, esperamos que se encuentre mejor y evolucione bien a lo largo de estos días. Cualquier incidencia nos vais contando y de continuar con los intentos aconsejamos sea derivada a psiquiatría las veces que sea necesario. De continuar igual, si no mejora y los intentos van a más habrá que plantear una nueva subcomisión de valoración." ······················ Respuesta de Blanca: "La situación de Isabel es compleja, las dificultades graves de afrontamiento y gestión emocional la llevan a la ingesta de objetos normalmente sin ideación autolítica pero con un gran riesgo para su integridad. En este último ingreso ha necesitado contención por ello ha estado unos días en UHB, si no ante otras ingestas se atiende la salud física y tras valoración psiquiátrica se procede al alta, ya que se consideran conductas impulsivas sin ideación autolítica. Isabel llevaba unos meses mejor y sin ingestas, algo que ahora nos preocupa la intensificación y frecuencia en tan poco tiempo. Estamos en contacto con equipo de salud mental y en los ingresos con la UHB. Hoy al hablar con psiquitra nos comentaba que se encontraba tranquila, y que Isabel explicaba la ingesta debido a un aumento de estrés por las Navidades y el juicio. Con el CRPS, aún no ha establecido vinculo, ha acudido a alguna sesión, pero de manera muy puntual. Con el CSS, no ha vuelto a tener contacto. Estaremos atentas ya que la semana que viene tiene una citación en juzgado con médica forense. Ella refiere hoy, crítica por lo sucedido ya que no soluciona sus problemas. Es consciente tras el hecho de la posible pérdida de plaza. Estoy de acuerdo contigo, en que, de empeorar la situación, debemos plantearnos una intervención alternativa que refuerce la que está recibiendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-12-28','miguel, llega por abogacía (Escalona) el certificado de nacimiento con la inscripción del registro civil de Guadalajara de Sergio con el nombramiento del cargo de tutor a la Ctaex.***************************************** Remito email a José Luis de la Notaria: Buenos días José Luis, retomamos la ratificación que teníamos pendiente porque no estaba inscrito en el registro civil de uno de los hermanos tutelados Gil Sanz la tutela cuyo cargo ejerce la Comisión Tutelar de Adultos. Te adjunto de nuevo los dos certificados de nacimiento, el de Raúl creo que estaba correcto, y el de Sergio tiene la cv en la primera página. Por favor confírmame si están correcto y si puedo ir a ratificarlo o bien esta semana o bien el día 9-1-23 ******************************************************* Remito email a Teresa Muelas (abogada que tramitará las autorizaciones judiciales): Buenos días, te voy enviando los poderes apud acta de los hermanos Gil Sanz que hicimos hace tiempo, aunque esperemos que no tardemos en firmar la ratificación, ya que esta mañana nos han enviado electrónicamente el certificado de nacimiento con la inscripción del cargo de tutor a favor de la Comisión Tutelar de Adultos el juzgado de Don Benito. He vuelto a remitir a la notaria ambos certificados de nacimiento y teniendo en cuenta las vacaciones y suponiendo que el notario no ponga problemas me gustaría poderla firmar el 9-1-2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-12-28','miguel, llega por abogacía (Escalona) el certificado de nacimiento con la inscripción del registro civil de Guadalajara de Sergio con el nombramiento del cargo de tutor a la Ctaex.***************************************** Remito email a José Luis de la Notaria: Buenos días José Luis, retomamos la ratificación que teníamos pendiente porque no estaba inscrito en el registro civil de uno de los hermanos tutelados Gil Sanz la tutela cuyo cargo ejerce la Comisión Tutelar de Adultos. Te adjunto de nuevo los dos certificados de nacimiento, el de Raúl creo que estaba correcto, y el de Sergio tiene la cv en la primera página. Por favor confírmame si están correcto y si puedo ir a ratificarlo o bien esta semana o bien el día 9-1-23 ******************************************************* Remito email a Teresa Muelas (abogada que tramitará las autorizaciones judiciales): Buenos días, te voy enviando los poderes apud acta de los hermanos Gil Sanz que hicimos hace tiempo, aunque esperemos que no tardemos en firmar la ratificación, ya que esta mañana nos han enviado electrónicamente el certificado de nacimiento con la inscripción del cargo de tutor a favor de la Comisión Tutelar de Adultos el juzgado de Don Benito. He vuelto a remitir a la notaria ambos certificados de nacimiento y teniendo en cuenta las vacaciones y suponiendo que el notario no ponga problemas me gustaría poderla firmar el 9-1-2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-12-29','miguel, remito email al abogado de la tutelada Angel Garcia Calle, con copia a Angel: Buenos días, han sido firmadas las ventas de 3 inmuebles de los que componen la partición de herencia firmada ante el notario de los Santos de Maimona, Don Carlos Duro Fernández el 31-3-2022 con número de protocolo 301, en concreto se han vendido las fincas registrales número 7.619, 7617 y 11.550 ante el mismo notario con protocolos 1058 y 1059 ante el mismo notario con fecha 15-12-2022. Por este motivo necesitamos que nos remita: La firmeza del auto de autorización de ventas arriba indicado, previa subsanación del mismo conforme los emails debajo indicado por el notario de los Santos de Maimona, Don Carlos Duro Fernández. Le solicitamos agilice el trámites pues dependemos de esa subsanación y firmeza para poder ratificar las dos compraventas firmadas y las que se quieren firmar a corto plazo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-12-29','miguel, envío por lexnet comunicación, al jzdo de 1º instancia y al de instrucción nº5 de Cáceres, sobre las incidencias en el piso tutelado de la junta a los efectos oportunos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2022-12-30','Maite: Envié mail a TOni FUTUEX para ver cómo habia ido la presentación a Diego de la nueva auxiliar de domicilio. Todo bien, a Diego le ha gustado y se ha mostrado cercano y colaborador. Subo la nota de FUTUEX al expediente. La empresa enviará correo para formalizar contrato.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-12-29','Maite: Ha llamado el padre de Alberto. Ayer dia 28 dejó el centro. Oscar ha comunciado al banco para que no se haga la transferencia al centro del pago de la plaza. HOy he hablado con Chari, personal administrativo de este centro ( 924 45 50 58). Me ha confirmado que se fue de forma voluntaria ayer. Enviará un mail comunicándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='NUÑEZ'and apellido2='NAJARRO'),'2023-01-02','TERESA: CITACION CADEX Adjunto cita que nos ha llegado para Antonio Núñez Najarro, pongo en copia a Pilar para que lo tenga en su expediente. Aprovecho para comunicaros que el menor saldrá con la familia los días comprendidos entre el 29 de diciembre y el 2 de enero de 2023. Un saludo, Guadalupe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-02','TERESA Te escribo, por ponerte en antecedentes de la situación de Tomás Carvajal es un tutelado, bastante complejo de Zafra, con el que se están intentando llevar a cabo algunos seguimientos, por el momento, bastante infructuosos. Tiene algo de cercanía, con el ts Jesus Carramiñana y aunque en esta nota especificamos un poco las ultimas gestiones que se han pretendido con el, (tiene un vehiculo que utiliza indiscriminadamente y etc) lo mas importante, que ha sucedido ahora mismo, es que desde servicios sociales se comunica a la educadora lo siguiente vía whatsapp por parte de Jesús Carramiñana (trabajador social del Ayto de Zafra, teléfono: 665 98 33 86): "Me acaba de llamar Tomas. Que quiere todo como antes o se suicida. Creo que debeis gestionar retirada de vehículo" Tomás lleva unos días muy alterado ante la imposibilidad de retirar dinero del banco. Ha visitado en varias ocasiones a Jesús comentándole la problemática. Jesús comentó ayer que había mandado un email a la Comisión explicando este tema. Se considera importante dar algún tipo de solución a la problemática dadas las circunstancias . Ya que entendemos que tendrá las cuentas bloqueadas, como sucede algunas veces, mientras se tutela la cuenta. Es cierto, que dificilmente va a permitir poder hacer un presupuesto de gastos, pero si no puede retirar nada de nada, las consecuencias para si mismo o para los demás pueden ser impredecibles. Ya que no conciencia de enfermedad ni tratamiento, ni derivación a salud mental ni nada. Hace algunos diass se acudió al centro de salud a ver a Maria Zapata (TS) para pedir cita con el médico de familia de Tomás, la idea es acompañarlo, Jesús (TS de los SSB) le repitió a Tomás que tenía que ir con nosotros el día que se concretará al médico. La idea es que su médico lo vea, lo derive a salud mental y se pueda tramitar la dependencia. Se ha pedido cita por si fuera factible este acompañamiento. Es el día 21 a las 9:00 (quizás se modifique debido a la probable imposibilidad del acompañamiento). De todos modos, se ha charlado con Jesús en el ayto. y comenta que el día después de la última visita a Tomás, éste acudió a verlo diciendo que no quiere ayuda de nadie y que no piensa ir al médico. Jesús asegura que va a ser imposible un acompañamiento (mucho menos al médico) y que lo mejor es que la Comisión tome otro tipo de medidas dadas las circunstancias (no sabemos muy bien a que medidas se puede referir el trabajodor social, si se refiere a un involuntario ..) Conato de visita a Tomás Carvajal. Se ha acudido con Jesús Carramiñana (TS) al domicilio de Tomás. Jesús explica que Tomás recibe una pensión por orfandad y por hijo cargo, casi 1000 euros al mes. Tiene una tarjeta de crédito, si necesitara dinero estaría todos los días en el ayuntamiento en SSB. El último informe médico es de 2016 lo pidió Jesús a la TS del centro de salud (María Zapata) y le dijo que lo haría de acuerdo con la información que tenían pero que él tiene que personarse allí, para que medico pueda valorarle aunque Tomás no parece estar por la labor. Tomás tarda en abrirnos la puerta y cuando lo hace no nos deja entrar en su casa, se ve que en el salón tiene una mesa rodeada de peluches sentados alrededor y comenta que no nos deja pasar porque tiene que colocar unos ladrillos. Ya teniamos constancia de otras circusntancias, bastante llamativas, como que siempre lleve un peluche en una silla de paseo en el coche o quejas de los vecinos (se pone caretas y asusta a los niños): Se charla con él y apenas nos deja hablar, asegura que no quiere saber nada de nadie, que no se fía de nadie. Afirma que todo el mundo lo trata como a un criminal, se la ha insistido en que hemos ido justo para ayudarle en lo que necesite, pero se niega a ello. Se le pregunta si come bien, asegura que come caliente casi a diario, y que no toma medicación porque no quiere ir al médico pero que tiene mal los dientes y le gustaría poder arreglárselo. Se le comenta que podría ir al médico acompañado por nosotros para ver si le pueden ayudar en el centro de salud con ese tema pero se niega. Jesús le ha insistido en que debe colaborar con nosotros. Se pedirá cita en el centro de salud a la TS para su médico de cabecera, ya que ni siquiera sabemos si Tomás tiene tarjeta sanitaria, aunque no parece que vaya a acompañarnos al médico, Jesús le ha insistido en que debe hacerlo, pero Tomás apenas lo ha dejado hablar. Los vecinos comentan que están hartos de esta situación y que tienen miedo de que Tomás tenga un descuido un día (o incluso a propósito, algo que ya ha manifestado verbalmente) y se deje el gas abierto o prenda fuego a algo en su casa. Tomás nos enseña su furgoneta, lleva de copiloto a un peluche enorme que dice que compró hace tiempo y que le hace compañía en sus viajes, hace poco ha ido a Mérida, Los Santos y Villafranca, va con la furgoneta y sin creemos que sin carné o con el carné caducado. Enseña una mochila que dice que cogió de la basura y afirma que los vaqueros que lleva puestos también recogió de un contenedor. Por lo que cuenta y por lo que sabemos por Jesús, Tomás administra de muy malas maneras el dinero. Nos despedimos de él hasta la próxima. Tomás es un perfil muy complejo, no sabe comunicarse, solamente da voces y no sabe escuchar, lo cual hace aún más difícil el poder trabajar con él. No tiene conciencia de enfermedad ni tratamiento ajustado, por lo que, esto mediatizada todo muchisimo más. Además continuamente afirma que no quiere saber nada de nadie y que no quiere ayuda y que no se fía de nadie.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-01-02','Ana: Correo de Sheila, Directora CRR-CC, el día 30: "Adjuntamos presupuesto que Juan José Bergantiño nos presenta de cara al día de Reyes. Por otro lado, informar de que ha pedido realizar una salida los días 3 y 4 de enero, a una pensión en Badajoz. A nivel técnico, le hemos ofrecido la posibilidad de realizar una salida a Badajoz, ida y vuelta, uno de los días, puesto que ha sido una salida no organizada ni planificada con el centro. Nos comentáis cómo lo veis." ··························· Mi respuesta: "En relación a la salida que Juan José solicita, estamos de acuerdo con vosotras en que sea una salida de ida y vuelta en el día, dado que no ha sido organizada ni planificada con el equipo del CRR. Por otra parte, quería conocer vuestro criterio técnico, en relación a la compra de las mancuernas. Creo recordar que en su día lo hablé con Pedro, porque en el anterior CRR en el que estuvo (Badajoz) se obsesionó mucho con estos artículos, comenzó a comprar y a acumularlos, teniendo que llegar a venderlos después porque no tenía dónde guardarlos. No sé a día de hoy cuántas mancuernas tiene, si las necesita realmente ni el uso que les da. Si es algo comedido y creéis que le beneficia, no hay problema, se autorizará como su regalo de reyes, pero nos gustaría que nos confirmaseis que es así." ································································································································································································ Respuesta de Sheila: "Tras hablarlo con Pedro, me informa de que efectivamente, tiene muchas mancuernas y por tanto, no necesita nuevas. En cuanto a la salida, le informaremos a lo largo de la mañana de que solo podrá ser ida y vuelta por la falta de planificación"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-02','Ana: Correo-respuesta de Beatriz, Directora Res. Garrovillas de Alconétar: "Juan Gregorio está fenomenal, la semana pasada le visitó su hijo, todo tranquilo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-02','Ana: correo de Maite del día 30: "Hablé con los centros de Cáritas de Badajoz y Mérida, no hay plazas. Me facilitaron el teléfono de los centros de emergencia : Mérida ( Víctor 672159498) Badajoz ( 607519128)." ··································································································································································································· Correo de Sonia, TS C.Penitenciario-CC (trabajosocialcpcaceres@dgip.mir.es): Buenos días Ana soy Sonia, te envió el último informe de seguimiento de Psiquiatría de fecha 22/12/22 del interno D. Sergio Solanilla Lujan para completar expediente de cara a su próxima libertad prevista para el 06/01/23. Atentamente" ····· Guardo Informe en el Expdte. Digital. Según el mismo se encuentra estable a nivel psicopatológico, con conciencia de enfermedad. "Verbaliza necesidad de contención para control de su psicopatología". *Solicita informe para Ingreso en Comunidad Terapéutica. ······························································································································································································· Tras hablar con Julia, Casa de la Misericordia de Alcuéscar (615 628 680), llamo a las TS del C. Penitenciario (927 181 407) sin éxito. ········ Les envío un mail: "Os estoy llamando, pero imagino que estáis ocupadas. Resulta que me han contactado de la Casa de la Misericordia de Alcuéscar, justo se les ha quedado una plaza libre (debe ser un “milagro navideño” para Sergio, jeje). No obstante, me informan que él ya estuvo allí en su día, conoce perfectamente el funcionamiento y las normas del recurso. *Necesitan qué el confirme que está dispuesto a volver a dicho recurso. *Como os dije antes, no tenemos, a día de hoy, más alternativas para él y sus ingresos no darían para abonar durante muchos días una pensión/hostal. Sí él acepta ir y se compromete a aceptar las normas de convivencia del recurso, están dispuestos a que ingrese de nuevo. Quedo a la espera de vuestra respuesta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2023-01-02','Ana: El día 28/12 se recibe Informe de NACE. *Óscar, sección económica, lo utiliza para la rendición anual. ··········· Según el informe: "Soledad muestra mucho interés social por las personas y le gusta establecer vínculos, haciendo amistades con facilidad por lo que tiene buen desarrollo social. Es muy conversadora y sabe expresar perfectamente sus sentimientos, preferencias, gustos e intereses.", "Buena salud en general", "Relaciones familiares: Nulas, inexistentes excepto el contacto con un hermano... No hay contacto con los demás familiares, ni recibe llamadas telefónicas ni visitas de nadie que demuestre interés hacia su persona", "-Conducta negativa, poco interés si la actividad no le agrada por lo que necesita actividades estimulantes, motivadoras, que partan de sus intereses para estructurar su aprendizaje -Comportamientos inadecuados, manifestando enfados cuando se la contradice en algo que quiere hacer en el momento reflejando un comportamiento inmaduro de su edad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-12-27','Ana: correo de Blanca, Directora del CRR: "Buenas, Isabel Cano ha sido dada de alta y se encuentra en el CRR, tras hablar con psiquiatra se considera que los ingresos no tienen un impacto para el cambio. Isabel hace referencia a mayor malestar por Navidades, y juicios que tiene pendientes, os vamos informando de la evolución."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-02','Ana: correo del día 27/12 de Laura, Directora de asociación Vera (asociacionvera@msn.com): "Adjunto citación de Adrián Ortigosa Fuentes en calidad de denunciado para celebración de juicio el próximo 24/01/2023 a las 13:00 horas en el JDO.1A. INST.E INSTRUCCIÓN N.5 PLASENCIA.". Lo paso a los Jurídicos CTAEX. ································································································································································································ Correo de Ángel, A. Jurídico: "Ana, Adrián reside en Asociación Vera, de Jaraíz de la Vera, verdad? En ese caso, no tiene obligación de acudir a la citación, al residir fuera de Plasencia. Por favor, ponte en contacto con el centro para indicárselo. Envío escrito al Juzgado comunicando esta circunstancia y que le designen Abogado de oficio para que le represente en el juicio." ······························· Lo reenvío a Cristina, Ed., y Laura, Directora, A. Vera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-02','TERESA Estamos a la espera de que cobre sus pensiones de este mes y autorizarle, para el próximo martes, un reintegro de 600€, en tanto en cuanto consienta que, desde la sección social de esta Comisión, se realice un plan de intervención inicial con un presupuesto de gastos ajustado a sus necesidades y a sus ingresos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='CORDERO'and apellido2='PARRA'),'2023-01-02','TERESA En su carpeta de Inventario está toda la información de Ismael. Se ha solicitado apertura de nueva cuenta bancaria en Unicaja, para cambio de pensión, ya que la del Banco Santander está controlada por el hermano y no nos dan acceso. Ya ha generado deuda en el centro, a pesar de las buenas pensiones que tiene, porque el hermano ha dejado de pagar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-19','TERESA Buenos dias Teresa. Para informarte que habeis ordenado el bloqueo de la cuenta de Tomas Carvajal de tal manera que el no puede sacar dinero sin vuestra autorización. Es urgente el que habilitéis algún sistema para que Tomas pueda tener los recuso adecuados para obtener productos de primera necesidad. Un saludo (mi telefono 665983386)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2020-05-21','Teresa REcibo llamda de salund mental para anular la cita que tiene el 26 de mayo.Le llamo para comunicarselo y preguntar como se encuentra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2018-08-22','-AMALIA : TERESA FUTUEX YA ESTÁ CON LAS GESTIONES DEL PTO. FINAL DE LA OBRA Y LO QUE SE DEBE . QUEDO PTE. DEL PTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2023-01-02','Ana: Tras hablar con Jesús, hijo de Emilia, envío correo a Miguel, Asesor Jurídico y Maite, Jefa Secc.: "Informaros que unos de los dos hijos de Emilia, falleció al poco de ingresar ella en la residencia. Con el otro hijo, Jesús (643 063 690), acabo de hablar, como suponía su situación económica no es nada buena, de hecho se fue a vivir a casa de su madre con consentimiento desde aquí, una vez se quedó la vivienda desocupada. Actualmente dice que está cobrando el “ingreso mínimo vital”, con lo cual no puede hacer frente a esos gastos. No obstante, dice que hablará con sus tías y te llamará la semana que viene Miguel."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-12-27','Correo de Miguel, A. Jurídico: "Buenos días, para vuestro conocimiento, aunque lo hayamos hablado. Emilia está tutelada y tiene muchos bienes. No dispone de capacidad económica, y tiene creo por lo que hablamos unos 2.000€ ahorrados. Creo recordar que le sobran menos de 50€ al mes… Tenemos un problema para aceptar la herencia de su hermano ya que no disponemos de efectivo y como podéis ver debajo la asesoría habla del pago de unos 28.000€ en impuestos…. Aunque como podéis ver debajo le pregunto a la asesoría que otras opciones hay, y creo que ninguna, se me ocurre que la parte social habléis con sus hijos (Nacho no porque creo que anda en problemas legales, pero sí José Maria que puede que pueda ayudar a su madre económicamente…) No se me ocurren más opciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-01-02','Ana: Correo de Paula, TO CRR-Plas, del día 23: "Primeramente, nos gustaría recordar que el extra anual de este año se gastó casi de forma íntegra en los primeros meses del año debido a un manejo inadecuado que hizo con una compañera, por lo que tuvo que asumir gastos por la práctica totalidad de ese extra anual. A lo largo de los meses siguientes se valoró un cambio de estrategia general, en cuanto a las cantidades económicas que recibía (aumentar las mismas), para intentar disminuir las deudas que contraía con otras personas y poner el foco de su recuperación en la realización de acciones valiosas y no en el manejo del dinero, que claramente es un aspecto en el que necesita apoyo y en el que se está interviniendo actualmente de forma intensa y que tiene relación con aspectos complejos (identidad, manejo de emociones, proceso de toma de decisiones...). ...Estos cambios están sirviendo para motivar el trabajo que os mencionaba anteriormente respecto a la toma de decisiones: estamos intentando trabajar con él la importancia de los objetivos más que los objetos, y cómo éstos son el medio para llegar a aquellos. ...Así a primeros de año nos reuniremos para realizar una planificación de posibles gastos y proponer una cantidad de extras anuales ajustada a sus necesidades y a sus posibilidades económicas. En cuanto tengamos una propuesta os la lanzamos y nos coordinamos." ······ Guardo correo completo en el expdte. digital. ···································································································································································································· Mi respuesta: "Tomo nota de todo y hago partícipe de la información que facilitas, a Maite y Alberto, respectivos Jefes. Con respecto a la edición del nuevo libro, decirte que nuestro compañero Ángel, ya ha remitido hoy el contrato firmado por el Representante Legal a la editorial. Y entiendo, por lo que dice en el correo, que consideráis oportuno que se le compre como regalo de Navidad y Reyes la Nintendo que pide. Para ello, como te indiqué en mi correo, podéis remitir presupuesto de la tienda a nombre de Ceferino a la atención de la sección económica a ctutelar@salud-juntaex.es, para que den el visto bueno definitivo y pueda adquirir la consola. Quedamos a la espera del extra anual, llegado el momento, remitirlo también, por favor, al ctutelar@salud-juntaex.es" Vuelvo a escribirle: "...En cuanto a la inversión del extra anual, si hizo mal uso del dinero, entendemos que eso es algo de lo que tiene que responsabilizarse y asumir las consecuencias. No entendemos como terapéutico, que si hace mal uso de dinero, igualmente haya que autorizarle después más dinero para el resto de cosas que quiere o pueden ser de su interés. Pues nos parece que así no hay mucho aprendizaje al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-01-02','TERESA RECIBO LLAMADA DE JOSE TRABAJADOR SOCIAL ME COMENTA QUE JOSE SIGUE QUEJANDOSE DE QUE ESTA MUY DELGADO Y QUE SE QUIERE A SU CASA NO ES CONSCINTE DE QUE NO PUEDE VIVIR SOLO PUES NECESITA APOYO PARA LAS ACTIVIDADES DE LA VIDA DIARIA, HASTA PARA PONERSE LAS ZAPATILLAS NECESITA AYUDA MANIFIESTA QUERER IRSE A CASA PERO SU ESTADO DE SALUD LE IMPIDE IRSE AUNQUE QUISIERA CON LO CUAL NO HAY RIESGO DE QUE SE MARCHE Y ALLI SE ENCUENTRA TRAQUILO NO DA PROBLEMAS CON LO CUAL SUPONEMOS QUE CONTINUARA EN LA RESIDENCIA SIN DAR MAYOR PROBLEMA EN LA CASA AHORA SE HA MENTIDO UN HERMANO, VA A VER JOSE COMO ESTA LA SITUACION POR SI TENEMOS QUE TOMAR ALGUNA MEDIDA YA QUE LOS SUMINISTROS CONTINUAN DADOS DE ALTA Y NOMBRE DE JOSE PARECE SER QUE EL HERAMNO TIENE LLAVE Y POR ESO HA PODIDO ENTRAR HABRA QUE PLANTEAR UN CAMBIO DE CERRADURA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-02','Ana: Correo de Toni-Futuex, del día 23/12: "Ramón Civantos, aceptación traslado a residencia: Después de llevar unos días viendo que Ramón se encuentra cada vez más flojo, tanto físicamente por el tema de la infección, como anímicamente después de que sus hijos le rechazaron cenar o comer con él en Navidad, pues Ramón les propuso comprar un menú y pasar uno de los días juntos, pero se lo negaron; se le propone ingresar en una residencia de la zona para estos días. Ramón, en principio, señalaba que en el hotel estaba bien, que la habitación está genial, come bien y están pendiente, se le dice que estos días de Navidad será diferente, pues tienen otras cosas que atender, además, le vendrá bien el calor y cariño de personas que estén más pendientes, a parte, en una residencia tiene atención de enfermería, cosa que necesita y es conveniente. El día 21 no estaba muy convencido, el día 22, se vuelve a hablar con el tutelado, se le dice que, en principio para los días de Navidad, estas dos semanas, después, si quiere, se vuelve a la localidad, aunque lo ideal sería que se quedase, mínimo, hasta que se arreglase la cubierta de la vivienda. Se le dice que se van a ver las opciones de residencias que hay por la zona, pues no se quiere ir lejos y se le comunicará para que elija; así se hace, a través de la trabajadora social de la localidad, se buscan las posibilidades que hay para ingreso el día de mañana, se encuentran en la localidad de Carbajo y Cedillo, se le comunica a Ramón, comenta que prefiere Cedillo. Una vez confirmado se da paso a toda la tramitación, se habla con la directora de la residencia, Gema grupo Asoma (639694905) para cerrar y concretar todo lo del traslado, se hará mañana para estar en la residencia a las 12 de la mañana. Se contacta con un taxi para realizar dicho traslado, Inma (696712820). Igualmente se le dice a la auxiliar que le ayude a preparar el equipaje y se habla con la de la farmacia para que le deje la medicación preparada para estos 15 días. El precio mensual serian 1200 eu,pero iban a reestructuralo para hacerlo acorde al tiempo queel va a estar. Como la situación era un poco urgente, y tieneopciones económicas, se ha valorado, iniciar la tramitaiciónpara que ingresará hoy mismo, 23 de Diciebre. Por el momento, el se puede costear laplaza privada, pues que le saldria mas rentable que el hotel ysin duda es un recurso mas adecuado. Si realmente engancha,que seria perfecto, pues se prodia tramitar dependencia paraplaza pública" ·························· *Subo al portafirmas digital el contrato de la Residencia de Cedillo que me remite la Gema, Directora de la Residencia Municipal de Cedillo (gemamg.asoma@gmail.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2023-01-02','TERESA SE AUTORIZA SALIDA DEL 23 AL 28 DE DICIEMBRE CON SU FAMILIA DE ACOGIDA EN MALPARTIDA DE PLASENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2023-01-02','TERESA SALIDA DEL 22 DE DICIEMBRE AL 2 DE ENERO CON SU FAMILIA EN FUENTE DE CANTOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2023-01-02','TERESA SALIDA AL DOMICILIO FAMILIAR DEL 19 AL 21 DE DICIEMBRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2023-01-02','Ángel. Llama Juan Castillo (655936860), interesándose por una finca rústica contigua a la suya, que pertenece según él a Mariano Mora Cano, padre de Juan Mora Rodríguez. Se trata de una finca rústica, sita en Talarrubias, La Solana, Polígono 12, Parcela 78, de 1.000 metros cuadrados, que no tiene explotaciónn agrícola, sin uso, no hay escrituras, ni está inscrita en catastro, ni registro de la propiedad. Le propongo un arrendamiento rústico, debido a que la opción de iniciar los trámites de la herencia supondría tiempo y coste a nuestro tutelado, que cuenta con 78 años, que además contaba con otro hermano, Manuel, fallecido, que tuvo un hijo, su sobrino. Desestima la opción del arrendamiento y agradece el trato recibido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2023-01-03','TERESA Ya hemos solucionado el problema de los Ocupas de José , el sobrino se ha ido con su madre a jerez , su hermano Antonio ha cambiado el bombín por otro que tenía en casa para que no vuelve a suceder . Mañana me darán el móvil nuevo de José y te mando la factura con el número de cuenta para el abono Buen día José','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2023-01-03','TERESA solo se de él a través de la trabajadora social del Hospital Tierra de Barros, Ana. Ya el Hospital también ha conseguido hablar con los familiares (con sus sobrinos que residen en Plasencia). Se le derivó el día 21/12/2022 y aún permanece ingresado. Está en tratamiento y evoluciona favorablemente al tratamiento para septicemia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-03','Ana: Correo de Maite, TS C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es): "He hablado con el interno y está de acuerdo en ingresar en la Casa de la Misericordia. La libertad la tiene el día 6 de enero y de aquí salen después del desayuno sobre las 9 – 9:30 h de la mañana. Va a informar a su madre y no sabe si vendrá ella a buscarle para llevarle a Alcuéscar." ··························· Respondo: "...Pues confirmo con el centro su ingreso el mismo día 6. En cuanto a la Cuenta Pecunio, ya han anulado la transferencia periódica para que no entre en febrero. ¿Podríais poner un documento por escrito del dinero que lleva en efectivo a su salida (todo lo que le quede en la cuenta) para que lo firme y para que llegue con dinero al centro? Si me lo envías escaneado yo se lo reenvío a la Coordinadora de la Casa de la Misericordia." ······························································································································································································· Envío correo a Julia, Casa de la Misericordia (trabajosocialcpcaceres@dgip.mir.es): "Me confirma Maite, Trabajadora Social del Centro Penitenciario, que Sergio Solanilla Luján acepta ir a vuestro centro y se compromete a cumplir la normas de convivencia de la Casa. Te adjunto los siguientes documentos: - Informe Social del C. Penitenciario - Informe del Servicio de Psiquiatría (Consulta día 22/12/22) - Certificado Discapacidad - Dictamen Técnico del CADEX - Tarjeta Sanitaria - DNI Espero que sean documentos suficientes para el expediente, pues es todo cuanto tenemos. También hemos solicitado la valoración de dependencia, pero supongo que tardarán en ir a valorarle. Comunicaré el cambio de domicilio una vez haya ingresado en vuestro recurso. Recordarte que la salida es el día 6 de enero y ese mismo día se trasladará a Alcuéscar. Ante cualquier cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2022-12-23','TERESAA Comunicaros que D. JOSÉ LÓPEZ RUÍZ, tutelado por vosotros y que está ocupando plaza T1 en residencia de Mayores COMSER de Almendralejo, está ingresado en el Hospital de Tierra de Barros en estado grave desde el día 21.12.2022. Hemos tratado de llamar en varias ocasiones a su sobrino Antonio al 639 358 430, pero no logramos hablar con él y el Hospital tampoco consigue hablar con nadie de la familia para ponerle al día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-12-22','TERESA Hola Teresa te he llamado ahora, te informo de que la auxiliar de la empresa ayuda a domicilio de miguel fisio ha cesado su contrato ayer sin avisar , ayer limpio unas estanterías grande que tenía cosas personales de mi casa y las a tirado todas ha dejado unos libros, y me falta un reloj de valor que le compro mi madre . Voy a interponer denuncia a la Guardia Civil por hurto supongo que la empresa facilitará más información en este caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CAMPOS'and apellido2='MARTINEZ'),'2023-01-03','TERESA ARCHIVO RESOLUCION FAVORABLE INCLUSION EN PROGRAMA PARA PACIENTEES CON NECESIDADES ASISTENCIALES ESPECIALES','2');
