insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-03','Ana: correo de Gema, Directora de la Residencia Municipal de Cedillo (gemamg.asoma@gmail.com): "Julian está bien,adaptándose,pero tranquilo" ···························· Le envío a Gema el contrato de residencia y el documento de protección de datos de carácter personal firmado digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2023-01-03','COMUNICO FALLECIMIENTO DON PABLO GOMEZ GALLARDO RESIDENTE EN CENTRO FAMILIAR Y RESIDENCIAL NUÑOMORAL COMUNICA LA DIRECTORA DEL CENTRO: LETICIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-01-03','Ana: Subo al portafirmas digital la solicitud de termalismo del Programa del IMSERSO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-01-03','Ana: Tras hablar con José Manuel, envío correo a Alberto: "Te informo de la última de José Manuel Romero Mediavilla: Dice que el día 29/12 hizo un contrato con la compañía de teléfono FINET WORK con una permanencia de 12 meses. Contrató fibra óptica. *Dice que ya ha llamado para darlo de baja, pero le van a penalizar con 96 €. No sé si podrá devolver el recibo." ·································································································································································································· En cuanto a REVITAL, ahora dice que sí quiere ir... como aún no he enviado el documento de renuncia, le digo que volveremos a hablar mañana, para ver si continúa interesado, pues cambia constantemente de opinión. *Eso sí, dice que para ir, habrá que autorizarle otro extra para pagar la tarjeta de transporte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-01-03','Ana: Envío correo a Paula y Carolina - CRR Plas.: "Quería preguntaros por el empadronamiento de Julia Morón Hernández, como os comenté nos lo piden del Servicio de Prestaciones Sociales, para completar el expediente de solicitud de la Pensión No Contributiva. Nos dieron 10 días para presentarlo y se nos va a pasar el plazo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-01-03','Ana: Envío correo a Alberto comunicando que Ángel Félix solicita un extra por Navidad de 100€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-03','Ana: Icíar comprueba que no le han ingresado la pensión en el nueva cuenta, a pesar de lo que me dijeron el 30 de noviembre... El hijo ha vuelto a sacar casi todo el dinero. ··························· Además el recibo de la residencia lo han devuelto, no han podido cargarle el coste de la plaza. ············ Trato el asunto con la sección económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-04','Ana: Icíar llama al hijo de Juan Gregorio, pero este corta la llamada al poco de comenzar a hablar. ······································································································································································································ Envío correo-respuesta a Beatriz Pavón, Directora de la Residencia de Garrovillas de Alconétar (beapavonguerra@hotmail.com): "Pues por desgracia, a pesar de que cuando llamé a Control de Pensiones del INSS, a final de noviembre, me dijeron que la Pensión de diciembre ya se la ingresarían en la nueva cuenta que se le abrió, no ha sido así… y el hijo ha vuelto a hacer de las suyas y sacar casi todo el dinero de la otra cuenta. Voy a llamar de nuevo al INSS, aunque ya para el mes pasado no hay solución… No obstante, no es la primera vez que ocurren cuestiones similares desde que trabajo aquí, y me dice desde la sección económica, que se abonará a posteriori en cuanto se pueda, aunque sea de a poco cada mes. Hemos llamado al hijo, para pedirle que devuelva al menos parte del dinero de estos 2 últimos meses, pero ha colgado el teléfono a principios de la conversación. Lo siento por la parte que os toca, pero no podemos hacer nada más… Ante cualquier otra cuestión no dudes en volver a contactar." ······························································································································································································· Nuevo correo de Beatriz, Directora: "ayer llamó el hijo de Juan Gregorio para preguntarnos si cuando venga a visitar a su padre, puede sacarlo de paseo fuera del centro. A mí no me parece correcto, pero dime tú que hacemos." ································· *Mi respuesta: "Pues viendo los antecedentes, estoy de acuerdo contigo en que no es lo más beneficioso para Juan Gregorio. De momentos las visitas serán en el centro, “semi-supervisadas” al menos y mientras no perjudiquen en modo alguno a Juan Gregorio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2023-01-04','Ana: Envío a la registro (oac.merida.san@juntaex.es): "Adjunto SOLICITUD de PROGRAMA DE TERMALIMO DEL IMSERSO, a nombre de D. VENTURA GÓMEZ GARCÍA, cuyo cargo ostenta la Comisión Tutelar de Adultos, para que le deis REGISTRO DE ENTRADA. Adjunto así mismo: - Documento Solicitud2 – Datos Representante Legal - DNI del solicitante - DNI del Representante Legal - Testimonio de Aceptación del Cargo de Tutor - Decreto de nombramiento del Director Gerente del SEPAD - Resolución de Delegación de Competencias Hay que remitirlo a: IMSERSO Área de Termalismo Subdirección General de Gestión Avda. de la Ilustración, s/n, con vuelta a la C/Ginzo de Limia, 58 28029 Madrid" ····················· Envían registro del SIREX. Guardado en el expdte. digital. ············ Lo enviaré a Julia Durán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-01-04','Ana: Se autoriza extra de 100 €. *Llamo a Ángel Félix y confirmo que lo podrá retirar mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2023-01-05','Ana: Guardo en el expdte. digital el Contrato de la Residencia firmado por ambas partes (Representante Legal y Alcalde de Cedillo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2023-01-05','TERESA ayer, 3 enero: Se escribe a María por whatsapp, ya que no suele atender las llamadas telefónicas y se queda con ella en que mañana se le va a recoger en su casa para llevarla y acompañarla a la cita de salud mental en llerena a las 9:20horas. De forma hiperexcepcional, se iba a asumir el trasporte, ya que sino, sabiamos que no iba a acudir al psiquiatra.. y se consideraba muy pertiente,. Hoy, 4 enero: Esta noche se ha recibido un mensaje de whatsapp de María diciendo que se encuentra mal y está en la cama con fiebre.(suena a excusa la verdad, porque ayer estaba dispuesta y tan normal) Se le llama por la mañana y no contesta. Se llama a salud mental para comentar que no se va a acudir a la cita y aseguran que mandaran una carta a María con la nueva cita. A ultima hora de la mañana se acude a casa de María y se llama a la puerta, se escucha a Nerón pero parece no haber nadie. Se sospecha que María está en casa pero que no nos quiere abrir la puerta. Se le vuelve a llamar pero sigue sin atender al teléfono. Se habla con Jose (ts) que comenta que sospecha lo mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2023-01-05','TERESA 3 enero 2023: visita a Barto. Se recibe una llamada de Cati (vecina de Barto) diciendo que llegó anoche a casa. Se acude al domicilio y Barto nos abre la puerta de casa. Salimos a tomar un café. Se le nota tranquilo pero muy desmejorado. Asegura sentirse bien aunque vemos que tiene la mano izquierda muy hinchada y apenas mueve el brazo , se le pregunta qué le pasa y cambia continuamente de tema, no contesta a la pregunta. Una de las veces comenta que simplemente se la ha hinchado y está tomando antinflamatorios que le ayudan a reducir la hinchazón, cuando se intenta recabar más info se muestra un poco irritado y no se insiste más. Se le dice en más de una ocasión de acercarnos con él al centro de salud para que lo vean, pero se niega. Asegura que ha estado más de una vez en el hospital desde que se fue de Almendralejo. Barto habla de muchas cosas diferentes pero con hechos que no están conectados entre sí y de forma extraña aunque se le note tranquilo. Asegura que está tomando la medicación ,incluido el zipexa por la noche aunque se sospecha que solo está tomando el tranxilium. Cuenta que lo ha pasado muy bien. Él mismo explica que ha estado durmiendo en albergues y pidiendo dinero en la calle y con lo que ha sacado se ha comprado ropa. Habla acerca de una empresa que tiene con la que va a hacerse millonario. Tiene ciertas ideas delirantes, cuando se le insiste en algunas de ellas para saber más, simplemente no contesta y cambia de tema. Son ideas relacionadas principalmente con dinero y con espías. Se le acompaña al centro del pueblo y nos despedimos hasta la próxima Se acude al centro de salud para dejar esta información en conocimiento del área de salud mental. Nos atiende el doctor Eduardo (psiquiatra de Barto) que, después de explicarle la situación, comenta que, aunque Barto tiene ideas maníacas no pueden hacer nada mientras no esté muy alterado o reciban alguna notificación por parte de la policía porque se haya metido en algún problema. (resulta increible esto) La única solución que nos da es que se aumente la dosis de ziprexa a dos comprimidos en lugar de uno.Nos dice que en cuanto podamos llevemos a Barto al centro de salud aunque sea sin cita, se le ha explicado que se ha intentado pero que Barto se ha negado en rotundo, e incluso una de las veces ha contestado un poco irritado. Y que se tienen muchas dudas de que se este tomando la medicación correctamente. La administrativa de salud mental ha dado cita para el 7 de febrero a las 10:40, asegura no poder darnos cita antes pero que si podemos acudamos antes sin problema. Se acude a casa de Barto pero no está, se le llama y se le comenta que el próximo día que le visitemos iremos a una cita de salud mental y le comentamos lo que nos ha dicho Eduardo con respecto a ziprexa, se muestra reticente y enseguida se despide de nosotros. Se ha llamado a salud mental para dejarlo en su conocimiento. Aseguran que no pueden emitir ningún informe a no ser que Barto se persone allí. Se ha pedido cita para su médico de cabecera para ver si Barto se muestra más colaborador aprovechando que se queja desde un tiempo de dolor en uno de los brazos y que, su médico, pueda emitir el informe correspondiente una vez lo vea. Se intentará, ese mismo día, visitar a su psiquiatra. La cita para el médico de cabecera es para el miércoles 11 a las 10:30h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='NUÑEZ'and apellido2='NAJARRO'),'2023-01-05','TERESA: saldrá al domicilio familiar desde el día 5 hasta el día 8 de este mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2023-01-05','Ana: Envío a Toni-Futuex el correo de Administraciones Parra: "En relación a MARÍA JESÚS CRIADO RODRÍGUEZ, y tras comprobar que no tiene Seguro de Hogar, te reenvío correo de Administraciones Parra. Os solicitamos, que al igual que ya fue la compañera en otra ocasión cuando hicieron obras en el edificio, acuda de nuevo a su vivienda acompañada de un profesional para valorar las humedades que en teoría se producen en una vivienda vecina desde la suya y nos enviéis breve informe y presupuesto de la empresa/profesional en cuestión para su reparación, si fuera necesario." ········ "Contactamos con ustedes, como representantes de la propietaria de la vivienda 4D de la Av. de la Hispanidad 10 de Cáceres, para informarles que la vivienda 3D del mismo edificio, nos ha comunicado un problema de humedades cuyo origen se encuentra en la terraza de su vivienda. Les agradeceríamos que pasen por el edificio y den parte al seguro de su vivienda lo antes posible, para evitar que se agraven los daños de la vivienda inferior a la suya. Igualmente, les agradeceríamos que contacten con esta administración para que podamos mediar y coordinar los trabajos de reparación y la atención de daños de la vivienda afectada. Pueden contactar con nosotros a través de esta dirección de correo electrónico o de los teléfonos 927 233 112 y 658 205 216 (este último con Whatsapp, por si les resulta más cómodo, y emergencias 24 horas)" *Guardo éste correo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='NUÑEZ'and apellido2='NAJARRO'),'2023-01-05','TERESA: autorización de permanencia en el CAM "Pedro de Valdivia" de Villanueva de la Serena, para ANTONIO NÚÑEZ NAJARRO. Autorización que entrará en vigor, a partir del cumplimiento de su mayoría de edad (21 de diciembre de 2022), con una vigencia de tres meses; es decir, hasta el 21 de marzo de 2023. Esta autorización, será informada a Fiscalía de Menores y a la familia del joven.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-01-05','Ana: Llamada de Felisi (722 494 033): Está muy disgustada y preocupada, pues su hijo le ha enviado un sms diciendo que se ha metido en la droga y en el alcohol. Pide que le ayudemos. ··········· Por otra parte, dice que no pudo sacar dinero la última semana del año. *Lo comunicaré a Óscar, Secc. Ecca. ······ Y que se encuentra más a gusto viviendo en El Casar de Cáceres que en la Nava, ha vuelto a las clases para aprender a leer y a escribir, tiene amigas y sale mucho a pasear con su perrito. Le gustaría irse a vivir allí definitivamente y cambiar su casa por otra vivienda social del Casar. *Hablará al respecto con la TS, pues según dice, el Alcalde le dijo que sí podría...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-05','Ana: Hablo con Julia, madre de Sergio (924 626 557): Le confirmo el ingreso de su hijo mañana en la Casa de la Misericordia de Alcuéscar y la salida de mañana del C.P. entre 9:30 - 10:00. Confirma que acudirá ella a recogerlo y llevarlo a Alcuéscar. ·················································· Llamo a Victoria, Casa de la Misericordia (nº personal: 607 499 931): Confirma que ya tienen todo preparado para el ingreso mañana de Sergio. *Como mañana es festivo y estos días no está Julia, el lunes que viene ya se reunirán con él. *Y nos enviarán una propuesta de aportación para la plaza de asignación para gasto de bolsillo. ·········· Me informa también que, al menos durante los primeros días, saldrá siempre acompañado. ················· Confirmo todo a Maite, TS C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2023-01-05','Ana: Correo de Sheila, Directora CRR-CC (crr@grupociudadjardin.com): "Buenos días, la persona tutelada Juan José Bergantiño nos ha facilitado un presupuesto para ser valorado para la compra de un reloj. A nosotros nos parece excesivo el gasto que le supondría dicho reloj habiendo posibilidades más baratas para ese artículo, pero insiste en que os lo enviemos para valoración por vuestra parte." ···················· Respondo, con copia al ctutelar@ que a mí también me parece excesivo y que se inviten a escoger otro similar de menor coste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-01-04','Ana: Paula, TO CRR-Plas, me remite por mail el VOLANTE DE EMPADRONAMIENTO EN PLASENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2023-01-05','Ana: Envío a la oficina de atención al ciudadano - Registro SES (oac.merida.san@juntaex.es): "os remito para dar registro de SALIDA, la siguiente documentación relativa a D. JULIA MORÓN HERNÁNDEZ, cuyo cargo ostenta la CTAEX: - Oficio – remitiendo documentación - Documento Elección de PNC - Alta de terceros - Volante de Empadronamiento - Contrato del Centro de Residencial de Rehabilitación Debe remitirse a la dirección indicada en el oficio"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-01-05','Ana: Correo de Felisa Custodia, TS CAMF (trabajadora_social_alcuescar@imserso.es): "el pasado 15/03/2022 nos enviasteis correo con indicaciones de la tutelada Isabel Debón, limitando las salidas a dos horas diarias (puedes verlo más abajo). Actualmente la residente ya no mantiene ningún tipo de relación con este señor del pueblo, como ella misma me ha dicho. Por otro lado, ha iniciado una relación con un residente del CAMF de Leganés. De hecho, este residente está en nuestro centro pasando las navidades con Maribel. Por lo que ruego valoréis quitar la limitación de dos horas diarias." ······················· Mi respuesta: "Siendo todo así, no hay ningún problema, se retira dicha limitación en las salidas relativas a MARÍA ISABEL DEBÓN CHENIQUE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-05','Ana: Llamo a Cristina, Ed. Vera (681 14 39 11): Mª Ángeles, Directora del Plena Inclusión Montijo, le comunica que el próximo lunes día 9 van de visita a la vivienda del PROYECTO MI CASA - Montijo. Si todo va bien, el miércoles por la tarde ingresaría en dicho recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2023-01-09','Ana: Llamada de Minerva, TS del C.R. Cervantes (927 005 575 // 22237): Gloria, Ed. de Futuex, nos enviará las facturas de la ropa de Eugenia (Tiendas: Confecciones La Torre y Tara), con sendos nºs de cuenta para abonar mediante transferencia. ····· Lo comunico a las compañeras de la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2023-01-05','email de Francisco Garcia Vela, 1804@icaba.com: Buenos días: Le he dicho a Lorenzo que lo primero que se debe hacer es la herencia de su padre, pues solamente se ha realizado la herencia de su madre, y los bienes que se heredan son todos gananciales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2023-01-02','Ana: Llamada de Ángel Félix (643 622 174): Informa que se ha ido voluntariamente del Albergue. Dice que se le "cruzaron los cables", que le gustaría volver, pero que ya no es posible. Se lo advirtieron antes de irse. Tienen lista de espera. *Ahora está en casa de un amigo y le gustaría colaborar económicamente por su estancia. *Le indico que en este caso nos tendría que facilitar el contacto de su amigo y el nº de cuenta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-12-21','Ana: Llamada de José Manuel: *No ha vuelto a ir al centro de FEAFES, al preguntarle por el motivo expresa "no me apetece". ············ Quiere regalarle a su hermano una caja de herramientas para Reyes de unos 50€ apróx. y hacer una transferencia a cada uno de sus hijos de otros 50€. ····················· *Dice que NO QUIERE el Serv. de REVITAL. ············ *Mañana tiene que ir a la Radiografía de la rodilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-01-09','-Amalia : escribo a su hermana Anuski para averiguar porqué ha dejado el centro y para cuadrar asignación económica para este año. Quedo a la espera de la respuesta para cerrarlo con sección eco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-12-21','Ana: Llamada de Julia Durán, TS del Centro de Mayores - "Hogar Peña del Cura" de CC (22032): Ventura hoy tiene revisión de su sentencia en el Jdo. ················ De cara al viaje de la ONCE se ha comprado maleta y abrigo. ············· Va a proponerle el servicio de TAD a partir de enero, a ver si lo acepta, pues tras el último incidente le vendría muy bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2023-01-09','-Amalia ; email de juridico: Buenos días Inés, cuando este Auto de revisión de medidas del tutelado Diego Blanco Luque sea firme, pide el testimonio, y una vez te llegue acepta el cargo de curador representativo. Y guárdalo en su expediente. Pongo en copia a la parte social, para que una vez sea firme el auto puedan cumplir con lo que en el mismo se recoge: el internamiento en Aprosuba 3 y la obligación de emitir un informe cada 6 meses. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-01-09','Ana: Llamada de Emilia Almodóvar, TS del CSS-Plas: Va a solicitar la valoración de dependencia de Antonia. Me pide algunos datos de la representación legal. ··· Me enviará la solicitud cumplimentada. ········· Le envío copia de la Sentencia de Incapacitación, pues no la tienen en el expediente. ················· *Me informa también que le han comprado una buena silla de ruedas basculante. ···························· Subo al portafirmas la Solicitud de Valoración de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-12-30','Maite: he hablado con el centro para que nos comunicasen la baja de Alberto y me informaran sobre la situación. Envían un correo electrónico para notificarlo: Buenos días: Según conversación telefónica comunicar que Alberto Ramos Blanco con DNI 80095334-L abandonó de manera voluntaria el centro el día 28 de diciembre de 2022 siendo las 14:30. Atentamente, un saludo Asociación Rehabilitados Voluntarios de Camino a la Vida Edif. CID. Despacho 106 Plaza del Almendro, 7 06490 Puebla de la Calzada (Badajoz) Tfno: 924455058','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-01-09','-Amalia : emito email a Toni: Buenos días , Feliz Año compi , y para todas las demás ! Si fuera posible algún informe de salud de la cita de hoy de Paco sería genial para comunicar la situación al juzgado . Si él se niega a ingresar en ningún recurso pero está compensado y es su voluntad nada podemos hacer. Económicamente no tiene dinero para pagar un alquiler y dudo que nadie quiera alquilarle ni en el pueblo ni alrededores . He hablado con la TS del pueblo para ver si hay alguna opción habitacional para Paco en el pueblo , y me dice que no hay nada . Vamos a valorar con la sección eco ordenar esta esfera . Se le va a hacer un seguro de decesos y eso se le descontará de su pensión. De las extras se le podría dar en noviembre y junio la mitad y ahorrar la otra mitad. A ver qué valora Alberto y os lo digo. La TS del pueblo me dice que es igual lo que se haga , él no va a acceder a nada y así vive feliz. Saludos. -------------------------------------------------- Información sobre las ultimas visitas : Respecto a Francisco Casillas, el pasado martes 20 de diciembre se realizó seguimiento presencial. Previamente se le solicitó online cita médica para poder gestionar una ambulancia para la próxima cita de psiquiatría del 9 de enero. La ambulancia lo recoge en el centro de salud de Oliva de Mérida y lo lleva al Centro de salud Mérida Norte, el volante de la ambulancia es con retorno. Se realizará acompañamiento médico desde el equipo de apoyo social comunitario, lo esperaremos en el centro de salud Mérida Norte. Su doctora nos indica que cumple rigurosamente con el inyectable (cada tres meses). Francisco continúa viviendo en el solar al que accede indebidamente ya que es propiedad privada. Respecto al dinero mantiene el mismo discurso, "se ha gastado el dinero en pagar a las tiendas a las que debía por adelantarle la comida" no tenía dinero en efectivo consigo. El contacto con el tutelado se realiza a través de la policía local de Oliva de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-01-09','-Amalia : emito email a Toni: Buenos días , Feliz Año compi , y para todas las demás ! Si fuera posible algún informe de salud de la cita de hoy de Paco sería genial para comunicar la situación al juzgado . Si él se niega a ingresar en ningún recurso pero está compensado y es su voluntad nada podemos hacer. Económicamente no tiene dinero para pagar un alquiler y dudo que nadie quiera alquilarle ni en el pueblo ni alrededores . He hablado con la TS del pueblo para ver si hay alguna opción habitacional para Paco en el pueblo , y me dice que no hay nada . Vamos a valorar con la sección eco ordenar esta esfera . Se le va a hacer un seguro de decesos y eso se le descontará de su pensión. De las extras se le podría dar en noviembre y junio la mitad y ahorrar la otra mitad. A ver qué valora Alberto y os lo digo. La TS del pueblo me dice que es igual lo que se haga , él no va a acceder a nada y así vive feliz. Saludos. -------------------------------------------------- Información sobre las ultimas visitas : Respecto a Francisco Casillas, el pasado martes 20 de diciembre se realizó seguimiento presencial. Previamente se le solicitó online cita médica para poder gestionar una ambulancia para la próxima cita de psiquiatría del 9 de enero. La ambulancia lo recoge en el centro de salud de Oliva de Mérida y lo lleva al Centro de salud Mérida Norte, el volante de la ambulancia es con retorno. Se realizará acompañamiento médico desde el equipo de apoyo social comunitario, lo esperaremos en el centro de salud Mérida Norte. Su doctora nos indica que cumple rigurosamente con el inyectable (cada tres meses). Francisco continúa viviendo en el solar al que accede indebidamente ya que es propiedad privada. Respecto al dinero mantiene el mismo discurso, "se ha gastado el dinero en pagar a las tiendas a las que debía por adelantarle la comida" no tenía dinero en efectivo consigo. El contacto con el tutelado se realiza a través de la policía local de Oliva de Mérida.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2023-01-09','Buenas tardes. Comunicaros que desde la Entidad Aexpainba hemos solicitado las ayudas Reina Letizia para la inclusión a Juan José Murillo Romano y José María Rodríguez Moya. Lo que hemos solicitado para ambos es un ordenador con ratón y el maletín. Si esta ayuda es aceptada, recibirían el importe del coste de estos materiales. Cualquier duda consultarme sin problema. Saludos y buen día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-01-09','Ana: Llamo a Mila, Revital (927 22 55 30 // Nº personal: 676 593 154): Me confirma que la tarifa actual son 335€ pero que va a subir entorno a 5-7€ al mes a partir de febrero. Por tanto a José Manuel el servicio le supondría casi 200€. ······················· *Llamo a José Manuel (627 788 797): Dice que no está dispuesto a pagar 200€ por el servicio, pues él tiene más gastos. ········· *Esta mañana ha tenido cita en el ESM, con la Dra. Blanca Sánchez, pues el Dr. Goenaga está de baja. Dice que le ha dado buena impresión. ··················· Pide irse a vivir a una planta baja. ··· Le recuerdo que cuanto menos se mueva más le va a costar. Debe mantener movilidad en las articulaciones. ············· Quiere solicitar más extras. Le recuerdo que hasta marzo no puede pedir nada. ······················· *Han querido hacerle un Seguro de Hogar de Santa Lucía. Pero les ha dicho que nos llamen a nosotros. ······································································································· **Subo al portafirmas digital la NO ACEPTACIÓN DE LA PRESTACIÓN VINCULADA AL SERVICIO DE TRATAMIENTO POR PROMOCIÓN DE LA AUTONOMÍA. ·················· Una vez firmado lo remito a REGISTRO (oac.merida.san@juntaex.es) para enviar a SEPAD GERENCIA TERRITORIAL DE CÁCERES Sección de Dependencia I CODIGO BUZÓN SIREX: A11030403','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-09','Llamo a Victoria, Casa de la Misericordia (nº personal: 607 499 931): Confirma que el ingreso de Sergio fue bien. Estuvo colaborador y conforme. Entregó todo el dinero y la tarjeta de crédito. ········ De momento no ha salido, para la semana que viene ya le pondrán acompañamiento para que pueda salir. ··· De momento va todo bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-01-09','Ana: Envío a REGISTRO (oac.merida.san@juntaex.es) oficio-solicitud de las pensiones actualizadas de Antonia, para remitir a la Dirección Provincial del INSS de CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-01-09','Ana: Correo de Estrella Durán (estrella.duranc@salud-juntaex.es): "Te escribo para comunicarte que el día 3 de enero recibió el alta del Hospital Virgen del Puerto y vuelve a estar ingresada en la UHDAC."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-01-09','Ana: Correo de Felisa Custodio (trabajadora_social_alcuescar@imserso.es) al ctutelar@: "Buenos días, la residente quiere irse un mes al CAMF de Leganés, ha iniciado una relación sentimental con un antiguo novio, residente en el CAMF de Leganés y quiere ir a verlo. El señor ha estado en Alcuéscar las navidades pasándolas con Maribel. El gasto sería 600 euros, taxi adaptado Alcuéscar/Leganés/Alcuéscar. Adjunto solicitud para firma si lo estiman oportuno" ····················· Maite y yo damos el OK a la secc. ecca. ·································· **Cumplimento y subo al portafirmas digital la Solicitud de Estancia Temporal en el CAMF de Leganés para el mes de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-10','Ana: Correo de ayer por la tarde de Isabel, al ctutelar@: "Buenas tardes Ana te quería comentar una cosa tengo las muelas fatal y tengo una mucho peor y me da miedo y trauma si me las quitan sin anestesia general. Quiero operarme de una muela de arriba que la tengo muy mal no sé si cuesta dinero o no pero quiero que me pongan anestesia general porque tengo pánico a los dentistas. Que me recomiendas? Gracias un saludo espero tu respuesta" ······································· Mi respuesta, con copia a Paula y Carolina - CRR: "Buenos días Isabel, Las extracciones dentarias las realizan en el SES, las cubre la Seguridad Social y son gratuitas, las abonamos entre toda la ciudadanía a través de los impuestos. Entiendo que pueda tarde miedo, pero los Odontólogos/Dentistas, son también profesionales cualificados que velan por nuestra salud y saben lo que hacen. Normalmente, para extracciones de piezas dentarias ponen anestesia local, no general, pues ésta última suele entrañar más riesgos y no es recomendable para este tipo de procedimientos, no obstante, quienes lo valoran y deciden son los especialistas. Lo que sí creo que sería bueno que hicieras, es hablar sobre ello con Carolina, Psicóloga del centro, que seguro puede ayudarte a afrontar mejor la situación y darte estrategias para aprender a controlar los pensamientos negativos. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2023-01-10','Ana: Correo de ayer de Ceferino: "Buenos días pensando en febrero que es cuando se me va a comprar la pioneer dj800 he pensado una cosa más profesional y barata dos platos Pioneer plx 500 más una mesa de mezclas sencilla relooap remix 10 BT total : 747€ y es más profesional me lo piden gracias" ······················ Mi respuesta: "Buenos días Ceferino, A partir de ahora, todas estas peticiones, tienes que hablarlas con las profesionales del centro y desde aquí ya se tratarás los asuntos con ellas. Como sabes, sigues contando con tu asignación mensual, además de un extra anual, cuya cuantía aún está por determinar, con el que deberás afrontar la mayor parte del resto de gastos de todo el año acorde a las directrices que se den desde la Sección Económica. Desde el CRR, como siempre, te ayudarán a administrarlo. Pongo en copia a las compañeras, Paula y Carolina, para que estén al corriente. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-01-10','Ana: Me reemiten desde REGISTRO el JUSTIFICANTE SIREX de la NO ACEPTACIÓN del PIA, para el Tratamiento por Promoción de la Autonomía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-01-10','Ana: Reenvío a Ángel, Asesor Jurídico, y a Maite, Jefa Secc, el correo remitido por María Isabel Villa Naharro, Presidenta de la Asociación Femar (609 74 87 22 // residenciafemar2019@gmail.com): "Por medio del presente les comunico que tenemos sospechas que la casa de la residente de Valentina Fernández Trejo puede estar ocupada ilegalmente, ya que, se ha visto ropa tendida en el balcón y luz encendida. Creo que desde la Residencia es nuestra obligación comunicarlo para evitar perjuicios a nuestra Residente." ······················ Desconozco el procedimiento a seguir. ····························· Correo de Ángel, Asesor Jurídico: "Veo que en catastro no tiene nada a su nombre. Igual es una propiedad que viene de sus padres. En cualquier caso, si es la vivienda en la que residía antes de conseguir plaza en la residencia y de la que se ocupe en cuestiones de mantenimiento/pago de impuestos, podemos ponerlo en conocimiento de la Policía local, autorizándoles a que realicen una visita a la vivienda. Tenemos llaves de la vivienda? La tiene ella?" ···· Tras hablar con Ángel al respecto, me remite nuevo correo confirmando: "He hablado con la Policía Local de Logrosán. Van a realizar una visita al domicilio para comprobar si hay alguien. Me llaman." ································································································································································································· Conversación con Pilar, Directora de la Res. FEMAR (639 585 489): Dado que Valentina está delicada del corazón, van a intentar mantenerla, al menos de momento, ajena a esta información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2023-01-10','Ana: Correos de Jesús Manuel (jesusmanuelramosbargom@gmail.com) al ctutelar@: "Soy Jesús Manuel está noche a fallecido mi abuela que cantidad de dinero me autoriza para este caso" ········ "Yo vivo en Cáceres capital y el entierro es en zarza la mayor somos tres yo y mis dos hijos que cantidad tienen para estos casos" ················· Se le autorizan 20€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-01-10','Ana: Envío correo a REGISTRO (oac.merida.san@juntaex.es): "Adjunto Solicitud de Valoración de Dependencia, relativa a Dª. Antonia Ayuso Tena, cuyo cargo ostenta la Comisión Tutelar de Adultos, así como los siguientes documentos: • Sentencia Judicial y Aceptación del Cargo de Tutor • DNI del Presidente de la Comisión Tutelar de Adultos • Decreto de Nombramiento de Director Gerente del SEPAD • Resolución de Delegación de Competencias para registrar a: UNIDAD DE VALORACIÓN DE DEPENDENCIA DIRECCIÓN GERENCIA DEL SEPAD" ·························· Registrado hoy. Guardo Justificante SIREX en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2023-01-10','-Amalia :Ingresó en CRR Merida el dia 28 de diciembre derivado del CSS . se cuadra presupuesto con Oscar . Se le va a dar 300€/ mes que es lo que demanda . Ya tiene su cuenta propia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2023-01-10','Ana: Envío correo a Felisa Custodio (trabajadora_social_alcuescar@imserso.es): "Buenas tardes, Felisa, Tal y como hemos acordado, te envío adjunta SOLICITUD DE ESTANCIA TEMPORAL EN EL CAMF de Leganés, relativa a MARÍA ISABEL DEBÓN CHENIQUE, así como como los siguientes documentos: - Acuerdo de Aceptación del Cargo de Tutor - Acta de Aceptación del Cargo de Tutor - DNI del Presidente de la Comisión Tutelar de Adultos - Decreto de Nombramiento de Director Gerente del SEPAD - Resolución de Delegación de Competencias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2023-01-10','Ana: Envío correo a Pilar, Directora del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Comentarte que nos hemos dado cuenta que el DNI que obra en nuestro expediente de Mª CARMEN MATILLA JIMÉNEZ, está caducado desde octubre de 2022. No sé si lo habrá renovado. Si es así, por favor, hacérnoslo llegar escaneado a color. Y en caso contrario, ¿podríais por favor apoyarle en los trámites pertinentes para su renovación?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-01-10','Ana: Envío correo a Eva Álvarez, TS Plena Inclusión Montijo - Proyecto Mi casa (trabajadorasocialco@plenainclusionmontijo.org): "Me comunica mi compañero Óscar, Secc. Económica, que aún no se le ha cobrado nada por la plaza a CRISTOFER MONTERO VÁZQUEZ. Tampoco saben si se cobrará mediante cargo en cuenta, transferencia bancaria permanente o cómo. ¿Podríais informarnos al respecto? Supongo que la forma en que se le cobre será la misma para Adrián Ortigosa, no es así? Con respecto a la asignación mensual, me dice que la autorización está hecha para retirar los 90€ a lo largo de los primeros 10 días de cada mes, pero que este mes no lo habéis retirado, no sé si es que no le han hecho falta o cuál es el motivo. Ya me vas diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-10','Ana: Envío correo a Eva Álvarez, TS Plena Inclusión Montijo - Proyecto Mi casa (trabajadorasocialco@plenainclusionmontijo.org): "Justo el jueves pasado hablé con Cristina, Educadora de la Asociación Vera y me comentó que ayer lunes acudirían a la entrevista y visita al piso. Ya me ha dicho hoy que todo fue muy bien y mañana ingresará en la vivienda. Él está muy contento, creo que el cambio le va a venir muy bien. Percibe una PNC, cuya cuantía a partir de enero de 2023, asciende a 484,61 €. Actualmente tiene aprobada una asignación semanal de 10€. Los compañeros de la sección económica os confirmarán si es posible la subida de asignación a 90€/mes. La entidad bancaria en que le ingresan su pensión es UNICAJA. Tiene reconocido por el CADEX un grado de discapacidad del 65% y por el SEPAD, Grado I de DEPDENDENCIA. Dime qué documentación os han facilitado desde la Unidad de Programas Asistenciales y/o desde Asoc. Vera, para el expediente, para así facilitaros lo que no tengáis (DNI, Tarjeta Sanitaria, Cdo. CADEX, Informes...) Por otra parte, ¿podríais indicarnos la dirección física de dicha vivienda para modificarlo en nuestra base de datos?" ································································································································································································ Envío correo a Alberto y Óscar, Secc. Ecca, comunicando el cambio de recurso, el coste de la plaza y la propuesta de asignación mensual que plantean (90€) ·································································································································································································· Llamada de Cristina, Ed. Vera (681 14 39 11): ayer tuvo lugar la visita a la vivienda de Montijo. Dice que vivienda es un piso nuevo a estrenar, que está fenomenal, tiene incluso un patio y le han dicho que si podría tener un pajarito si lo cuidara bien. ······ Tiene un elevado número de personal. ··········· El CO también está muy bien. ············ *Acordamos que con el dinero en efectivo que tiene en el centro, le comprarán la maleta y el resto lo entregarán mañana a los profesionales de la vivienda nueva, pues tiene que comprar sábanas y un edredón. ···· Para dinero de bolsillo se llevará los 10€ de asignación de esta semana. ··········· Cuando se acuerde nueva asignación se enviará autorización a la sucursal correspondiente de Montijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2023-01-10','Ana: Conversación con Mª Ángeles, Directora Plena Inclusión Montijo (), la adaptación de Cristofer está siendo complicada, es difícil intervenir con él, pues presenta pocas motivaciones e intereses muy efímeros. De momento va bien porque se van anticipando a sus demandas y reacciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-11','Ana: En relación al correo de ayer de Isabel: "Buenos días Ana te quería hacer una pregunta nos podemos ir Ceferino Mariscal y yo a un piso de alquiler a vivir en Plasencia tenemos dinero y gastaríamos poco al mes estamos cansados de estar en el CRr queremos hacer una vida de pareja normalizada qué te parece y sobre la pensión para mañana te ha dicho algo Paula?" ····································································· Envío correo a Paula y Carolina, TO y Psicóloga del CRR: "Os reenvío correo de Isabel. Tanto esta cuestión, como la de querer pasar una noche en un hostal (que luego os reenvío ese otro correo) sólo lo plantea ella. Ceferino no se ha pronunciado al respecto. Él sólo envía los correos pidiendo comprar, como sabéis, más artículos de su interés. En cuanto a esta petición, entiendo que ninguno de los dos está preparado para dar un paso así. Voy a contestarle en esta línea y decirle que mientras no haya informes técnicos del centro así como de Salud Mental que indiquen que están preparados para ello, desde la CTAEX no se autorizará." ··································································································· Mi respuesta a Isabel: "Entiendo tu petición y que siendo pareja queráis tener mayor intimidad. No obstante, aclarar varias cuestiones: 1. Es una petición que debería partir de ambos, no sólo de ti, y que deberíais haber tratado primero con las profesionales del CRR. 2. Desde el equipo técnico de la Comisión Tutelar, consideramos que ninguno de los dos, a día de hoy, estáis preparados para dar un paso así. Y mientras no haya informes del equipo técnicos del centro así como de Salud Mental que indiquen que estáis preparados para ello, desde la CTAEX no se autorizará." ····························································································································································································· Tras nuevo correo de Paula, TO-CRR: "Si por vuestra parte no hay problema, se irían mañana 11 de Enero por la tarde y volverían pasado por la mañana. Cada uno pagaría una parte con el dinero que tienen en el CRR." se autoriza la pernocta en el hostal. *Se les recuerda que cada vez que lo hagan tendrán que abonarlo con sus respectivas asignaciones periódicas y/o extra anual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-11','Ana: Envío correo a Toni-Futuex, con copia a Amalia, confirmando el ingreso de Adrián en el Proyecto Mi Casa de Montijo en el día de hoy. Y especifico algunas cuestiones: "...El expediente pasará a Amalia para seguimiento tras el periodo de adaptación (un mes apróx.), de momento seguiré yo de referencia. También tenía que comentaros, tal y como hablé con Mª Ángeles, que los acompañamientos médicos, en principio, van a poder realizarlos desde la propia entienda, así que no será necesario que os encarguéis de esta cuestión. En cuanto a la familia de Adrián, se ha acorado que no habrá visitas durante el periodo de adaptación. Después, podrán acudir a visitarlo al recurso con X periodicidad, aún por determinar. Y, al menos, las primeras visitas serán supervisadas. Según evolucione todo se irán tomando decisiones al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2023-01-11','TERESA En relación a su tutelado Tomas Carvajal Cornejo se le informa que se ha recibido por parte de responsables de la entidad bancaria Liberbank quejas sobre la actuación del Sr. Carvajal en esa entidad ya que entra en la sede bancaria gritándoles que eran unos ladrones y que quería su dinero, actitud reprobable para el buen nombre de la entidad. Lo que se pone en su conocimiento para que adopte las medidas oportunas. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2022-12-23','Ana: Correo de la Psicóloga del CRR de Mérida: "Respecto a Joaquina, estuvo residiendo en el CRR de Mérida desde 2016 y durante todo este tiempo se mantuvo estable psicopatológicamente. De hecho, desde hace años, gestiona y es autónoma tanto en sus citas de salud mental como en su medicación, siendo ella misma la que se encargaba de sus tomas sin supervisión profesional. Se ha mostrado siempre responsable en este ámbito. Cuando se procedió al alta terapéutica, existió coordinación presencial y telefónica en varias ocasiones con la trabajadora social del ayuntamiento de Miajadas, por lo que a través de ella quizá se pueda facilitar la actuación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2023-01-11','-Amalia : he solicitado a Futuex informes de salud actualizados y de visitas . Voy a pasarlo a los juridicos para revisión , curatela económica y que sea el hijo el tutor. Mientras tanto , se decidira´ ya el tema del movil , se le va a dar la asignación que creamos conveniente y si el hijo no está de acuerdo que asuma el cargo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-12-23','Ana: correo de Miguel, Asesor Jurídico CTAEX: "Buenos días, adjunto la sentencia donde absuelven a Adrian, pero lo ponen la medida de seguridad de continuar con el tratamiento médico pautado por el/la psiquiatra especialista asignado/a al mismo por tiempo de dos meses"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-01-11','Ana: Guardo en el expediente el DNI ya renovado de Martín que me facilita Cruz Merino, TS Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESSA'and edp.apellido1='CARRERAS'and apellido2='PEREZ'),'2022-12-12','Ana: se autorizan un extra de 300 € para navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-12-12','Ana: se autorizan un extra de 300 € para navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2022-12-12','Ana: se autorizan un extra de 300 € para navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-01-11','Ana: llamo a María Isabel Villa Naharro, Presidenta de la Asociación Femar (609 74 87 22): Comunico que ayer Ángel lo puso en conocimiento de la Policía. ··········· Isabel ya lo sabía. De hecho la policía le ha informado que ya han acudido al domicilio en dos ocasiones, pero justo no había nadie. *Volverán a intentarlo más tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-01-11','TERESA COMUNICA PROGRAMA DE FAMILIA Buenos días Teresa, comunicar que Aitor ya no vive en Garrovillas de Alconetar. Nos ha llamado y nos dice que está viviendo en Trujillo, en la Calle Camineros, número 11 (Polígono de Trujillo). DERIVO A FUTUEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2023-01-11','TERES Comunicarte que José López Ruíz, tutelado por vosotros, regresó del Hospital Tierra de Barros el día 5/01/2023 por la noche. Se informó a su sobrino por parte del Departamento de Enfermería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-01-11','Ana: Pido a Emilia Almodovar, TS del CSS, el Informe de Salud (Anexo II) para enviarlo a Dependencia. Olvidamos pedirlo para adjuntarlo a la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-12-19','Ana: Correo de Óscar, Secc. Ecca.: "- Los enganches de luz y agua los hizo el hermano sin nuestra autorización. En principio lo iba a pagar él, pero finalmente lo pagó la madre y Saturnino sólo le ha devuelto la mitad del coste a su madre. - Sobre la deuda con su primo, según tengo entendido yo y por correos que envió su hermano en su momento, el primo no le iba a cobrar nada por la comida, extremo éste que también me confirmó el agente de Unicaja que, como le conoce de toda la vida, le invitaba a desayunar muchas veces. Además, antes de pagar esa deuda, debe abonar la que tiene con el SEPAD que, a día de hoy, asciende aún a 2.600€. Además, tiene una deuda con el OAR por multas de tráfico que siguen sumando costas e intereses (2.100€ aprox.). - En cuanto a los reintegros, hasta finales de septiembre no se pudo regularizar la situación con el banco. Desde entonces, en el banco le dan sus 50€ semanales. Del resto de reintegros puntuales extra ya hablé con el Agente de Unicaja y me dijo que, cuando lo veía muy necesitado, le daba 10 o 20 € extras porque no le llegaba para la comida y tabaco."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2023-01-11','Ana: Informo a Toni-Futuex de la situación económica actual de Saturnino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2023-01-11','Ana: Correo de Mariví Clemente, TS del CSS: " En principio el Paciente está más estable psicopatológicamente, tratándose de un trastorno mental grave de curso crónico, es a lo que más podemos aspirar. Se le compró la ropa que necesitaba, le acompañó el hermano y se facturó adecuadamente. Ahora está sufriendo infecciones en la boca, la tiene muy deteriorada, por lo que los próximos gastos serán los derivados del dentista, en todo caso ya enviaremos el presupuesto para que deis el visto bueno como CTAEX. Si necesitáis alguna información concreta del Paciente os la haremos llegar sin problema. Por ahora no hay ninguna novedad reseñable."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-01-11','Ana: Correo de Sonia Bernabé, Asindi: "te mando la propuesta para las visitas a la familia de los hermanos Hdez Castaño. Como en otras ocasiones, se lo pasas tu a la persona que lo lleva en el SEPAD y yo, en unos días, contactaré con la conductora que les suele llevar para que tenga claro los días y pueda organizarse." ················· Se lo envío a Belén Gutiérrez, TS de la Secc. Discap. y guardo el documento en sendos expedientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2023-01-11','Ana: Correo de Sonia Bernabé, Asindi: "te mando la propuesta para las visitas a la familia de los hermanos Hdez Castaño. Como en otras ocasiones, se lo pasas tu a la persona que lo lleva en el SEPAD y yo, en unos días, contactaré con la conductora que les suele llevar para que tenga claro los días y pueda organizarse." ················· Se lo envío a Belén Gutiérrez, TS de la Secc. Discap. y guardo el documento en sendos expedientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2023-01-12','Maite: Ayer hablé con Araceli ( trabajadora social de Mentalia) porque tenemos pendiente determinar la asiganción mensual de Mercedes y la compra de ropa que necesita. Me enviará correo con todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-01-12','Ana: Llamada de Paula, TO del CRR-Plas.: me informa que ayer por la tarde Mª Antonia acudió al CRR solicitando ayuda, e incluso pidiendo quedarse allí a dormir, pues, según explicó, había tenido problemas con una de las personas del piso de alquiler y le habían echado del mismo. ··· Aún tiene cosas dentro. ····· El móvil también lo dejó en el piso y no cree que se lo vayan a devolver. ····· Le dieron de comer, pues decía que no había comido en todo el día y le brindaron el apoyo que pudieron. ···· No saben con certeza si los hecho son como los narra o si obedecen a sus sensaciones /percepciones, o si pudiera ser fruto de una descompensación. ···· Le instaron a que pasara la noche en un hostal/pensión, para lo que manifestó tener dinero, al menos para algún que otro día. Y sobre todo a que a la mañana siguiente acudiera a hablar con Ana Benavente, TS del ESM. ·········· Acudió también más tarde al Piso Supervisado, donde le explicaron que tampoco podía pernoctar allí, pero estuvo un par de horas. ······························································································································································································· Comunico la situación mediante mail a Toni-Futuex, para que intenten localizarla y apoyarla desde el Programa de Apoyo Comunitario en estas circunstancias. Y le pregunto también sobre si han realizado algún otro seguimiento, la última información recibida hacía mención al 06/10. ··································································································································································································· Llamo a Ana Benavente, TS ESM-Plas. (74955 / 74924): pongo en su conocimiento la situación actual de Mª Antonia. *Hablará con el Psiquiatra y estará pendiente por si pasara por allí a lo largo de la mañana. Aunque duda un poco que acuda, ya que Antonia, al no tener conciencia de enfermedad, no quiere saber nada del ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2023-01-12','Ana: Correo de Estrella Durán (estrella.duranc@salud-juntaex.es): "Os comunico que Remedios Chaves Masero irá con taxi a Badajoz el día 18 del presente mes a visitar a su madre y hermana"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-01-12','TERESA soy Gema Educadora del CAM Francisco Pizarro de Trujillo. Te llamé ayer por teléfono para comentarte que Aitor Moreno, se había presentado en el Centro para visitarnos e informarnos que se encontraba viviendo en una casa ocupa en un lugar llamado "vivero" al lado del Centro de Menores, me comentó que ustedes tenían conocimiento de su situación, como desconozco la situación real de Aitor y por qué se encuentra en esta situación, os comunico que está actualmente según me ha comentado viviendo aquí en Trujillo, al lado del Centro en una casa ocupa con una chica la cual se presentó como su novia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-01-12','Ana: Descargo del SIDEX las RESOLUCIONES de grado de DEPENDENCIA y de la PRESTACIÓN ECCA. VINCULADA AL SERVICIO RESIDENCIAL, y las guardo en el expdte. ·········· Facilito la última a Leyre Sanz - TS Cánovas, Grupo Ciudad Jardín (t.socialcanovas@grupociudadjardin.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2023-01-12','TERESA Informarte que según hemos podido contrastar Bartolomé Colchón, está ingresado en la UHB del Hospital de Mérida, estamos intentado hablar con ellos, para que nos informen de algo más, pero por ahora nada. Parece ser, según nos han podido decir en Almendralejo, que montó algun lio en un bar y lo ingresaron...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-01-12','-Amalia : os paso varias cuestiones de este expediente : -Julio , en diciciembre dejó el Piso Supervisado y se fue a vivir con su tía : Manola Tf . 648573426 en C/ Costa Rica , 9 2ºb de Almendralejo. Creo recordar que ya lo cambiaste en la base . -Teresa , lleva ya unos meses en Almendralejo , ha pasado a vivir con la tía y está bastante adaptada . Paso el expediente a tu zona . Tienes todo anotado en la intranet , pero hablamos y te pongo al día . -Sección económica : Nuevo presupuesto fijado : Ingresos : PNC 489€ Gastos : 80€ transferencia permanente durante 3 años hasta completar financiación de tto. dental. Tiene S. decesos que abona la madre. Reintegro mensual 400€/ mes , que se dividen en los siguientes conceptos: - le entrega a su tía entre 300 y 310€ para gastos de alojamiento y manutención. - 20€ / mes para gastos de tf ( prepago ) -70 €/ mes ( resto de gastos personales ) -De las extras se le va a dar la mitad de cada una de ellas , una en diciembre ( excepcionalmente se hará en enero porque no la ha cogido 244€) y la otra mitad en junio . Se ahorra una extra íntegra anual . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2023-01-12','Ana: Llamada de José Manuel (627 788 797): Dice que está muy mal, que tiene muchos dolores de huesos y mal cuerpo. Quiere que le pongan "morfina". Tenía cita presencial con el MAP a las 10 h pero no ha ido porque dice que no ha podido moverse de casa. ············ Teresa, Ed. FUTUEX, ha llamado al C. Salud, le han dicho que le llamará el médico por teléfono. ··········· Vuelve a pedir irse a vivir a Olivenza o a otro pueblo pequeño para alejarse de su hijo" y "dar descanso" a su hermano. ············· Ha llamado también a Salud Mental, le llamará el Psiquiatra. *Ha bajado a la farmacia y le han dado 3 pastillas Trankimazín sin receta, porque tenía mucha ansiedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2023-01-12','-Amalia : os paso varias cuestiones de este expediente : -Julio , en diciciembre dejó el Piso Supervisado y se fue a vivir con su tía : Manola Tf . 648573426 en C/ Costa Rica , 9 2ºb de Almendralejo. Creo recordar que ya lo cambiaste en la base . -Teresa , lleva ya unos meses en Almendralejo , ha pasado a vivir con la tía y está bastante adaptada . Paso el expediente a tu zona . Tienes todo anotado en la intranet , pero hablamos y te pongo al día . -Sección económica : Nuevo presupuesto fijado : Ingresos : PNC 489€ Gastos : 80€ transferencia permanente durante 3 años hasta completar financiación de tto. dental. Tiene S. decesos que abona la madre. Reintegro mensual 400€/ mes , que se dividen en los siguientes conceptos: - le entrega a su tía entre 300 y 310€ para gastos de alojamiento y manutención. - 20€ / mes para gastos de tf ( prepago ) -70 €/ mes ( resto de gastos personales ) -De las extras se le va a dar la mitad de cada una de ellas , una en diciembre ( excepcionalmente se hará en enero porque no la ha cogido 244€) y la otra mitad en junio . Se ahorra una extra íntegra anual . Saludos','1');
