insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-01-12','-Amalia : Buenos días Juan , me dice mi compañero de la parte económica que ha ido a Mérida a presentar facturas, sobre ese tema lo habrá aclarado todo con ellos. Me indica que quería saber si podemos ingresar a Alberto en algún centro. Los centros de desintoxicación , como ya saben , exigen la voluntariedad del usuario , y Alberto ha decidido marcharse del centro en el que estaba . Hay otros centros de desintoxicación , a los que tiene que ser derivado por el Equipo de Conductas Adictivas , en Badajoz situado en Ronda del Pilar ( antiguo CEDEX ) siempre que él voluntariamente quisiera acceder . Si fuera el caso tiene que solicitar cita previa . No puede acceder a ningún otro tipo de recurso mientras tenga un consumo activo de drogas. Un saludo. o a su padre y hermana :','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-01-12','Ana: Correo de Paula, TO CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Hola Ana confirmo que el paso a piso de Javier Agudo será el lunes día 16 de Enero, ya os iremos contando." ··············· Envío mail a Julio, CTAEX, para que proceda al cambio de domicilio en la Base de Datos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-01-13','TERESA Ya está resuelto, os llegará próximamente la resolución de revocación del cobro indebido de PNC y junto con la nómina de enero/2023 se abonará, además de la pensión ordinaria por importe de 484,61 €, el dinero que se ingresó en la cuenta de recursos provinciales diversos en concepto de cobro indebido de PNC (4.138,26 €) Con respecto al cobro indebido reclamado en concepto de PF, ya es cuestión del INSS, pero nos hemos puesto en contacto con la unidad de impugnaciones frente a la que se ha interpuesto recurso de alzada y antes de resolverlo nos van a pedir informe, con lo cual entiendo que se mantendrá el cobro indebido de PF al haber anulado el del periodo coincidente de PNC ARCHIVO DESESTIMIENTO RECIBIDO POR LA UNIDAD DE IMPUGANACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2023-01-12','Ana: Tras hacer consulta a Toni-Futuex, envía correo informativo. Lo guardo en el expediente digital. *El día 30 de diciembre, intentaron de nuevo una visita. Habían acordado verla después de su asistencia al centro de salud, pues comunicó por teléfono que se había caído e iba a solicitar cita de fisioterapia. ··············· No consiguieron verla, ni las distintas veces que acudieron a su casa, ni en el centro de salud. Sólo consiguieron hablar con ella cuando supuestamente estaba el centro de Salud. *Evita ver a la Educadora. ·········· No quiere seguimiento ni control de ningún tipo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-01-12','Ana: Alberto, Jefe Secc. Ecca, solicita a las compañeras de la secc. ecca. que procedan a dar de baja los suministros de la vivienda lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2023-01-13','Ana: Envío correo a Julia, Casa de la Misericordia de Alcuéscar (casadelamisericordia.alcuescar@gmail.com): "No he querido “molestar” estos días. ¿Como estás? Siento mucho la perdida, un abrazo muy fuerte. Te reenvío correo relativo a una cita en el Juzgado de Doroteo Díaz Cerro. ¿Sería posible el acompañamiento por parte de algún profesional del recurso el día 17? Si no es así, confírmamelo y lo pido al Programa de a Apoyo Comunitario gestionado por Futuex." ························· Llamo a Julia, Coord. Casa Misericordia. Confirmo que la cita es presencial, Doroteo debe personarse en el Jdo. *Le acompañarán desde el centro. Pero tienen el vehículo averiado, si no dispsieran de él el día 17, acordamos que irán en taxi, y como otro residente a cargo de la CTAEX también tiene que acudir el mismo día a CC, lo abonarán entre los dos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CIRCUJANO'and apellido2='ZAMBRANO'),'2023-01-13','-Amalia : Fue derivado ayer al hospital desde el CSS Merida. Se va a poner acompañamiento hospitalario , he solicitado facturas semanales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2023-01-13','-Amalia : solicito a PNC información por email, no han hecho aún el cambio de cuenta pedido en abril. Nos indican que ellos ya han hecho el cambio , es problema de Ibercaja','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2023-01-13','Escribo a Lola Damiel del CSS , desde dependencia le piden una documentación que tienen que enviar ellos desde allí. " con respecto a la documentación a subsanar que os piden al CSS desde dependencia , solicitan : Anexo II Informe de salud firmado y Hª clinica Anexo III Guardador de hecho . Todo ello os indican un Nº directo de registro para que lo enviéis . Me reenvías la Hª Clinica , pero eso es sólo una parte de la documentación que os piden al centro. Si no te importa , indicadme fecha de registro de salida para anotar en su expediente. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2023-01-13','Escribo a Lola Damiel del CSS , desde dependencia le piden una documentación que tienen que enviar ellos desde allí. " con respecto a la documentación a subsanar que os piden al CSS desde dependencia , solicitan : Anexo II Informe de salud firmado y Hª clinica Anexo III Guardador de hecho . Todo ello os indican un Nº directo de registro para que lo enviéis . Me reenvías la Hª Clinica , pero eso es sólo una parte de la documentación que os piden al centro. Si no te importa , indicadme fecha de registro de salida para anotar en su expediente. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-01-13','Amalia , contesto a Eduardo que me ha enviado email pidiendo información sobre la prestación que es le solicitó. Le informo tanto de la denegacion de orfandad de SS , como requisitos para tramitar orfandad clases pasivas. No podria presentarla porque no estaba valorado ni por el EVI , ni por CADEX antes de los 21 años ni antes del fallecimiento del padre. Le envio los email directamente para que no desconfie . Buenas tardes Eduardo , la prestación que te solicitamos ha venido denegada , al ser tu padre beneficiario de Clases Pasivas y no de la Seguridad Social . Te voy a reenviar directamente el email para que puedas tener la información de primera mano. Cual era la profesión de tu padre ?? Para solicitar prestación por clases pasivas , tendrías que justificar que tú tenías una incapacidad anterior a la fecha de fallecimiento de tu padre . Si es así y tienes esa documentación podríamos solicitarlo. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2023-01-13','Noreply DGCPPP >no.replyDGCPPP@sepg.hacienda.gob.es> Amalia Diaz Gonzalez En respuesta a su consulta, de fecha: 29/11/2022 10:28:32, le informamos lo siguiente: En el Régimen de Clases Pasivas del Estado, las pensiones de orfandad están reguladas en el artículo 41 del Texto Refundido de la Ley de Clases Pasivas del Estado, aprobado por Real Decreto Legislativo 670/1987, de 30 de abril, según el cual, tendrán derecho a esta pensión los hijos del causante de los derechos pasivos que fueran menores de veintiún años, así como los que estuvieran incapacitados para todo trabajo antes del cumplimiento de dicha edad o de la fecha de fallecimiento del causante. A efectos de reconocimiento de pensión de orfandad del Régimen de Clases Pasivas del Estado, la declaración de “incapacitado para todo tipo de trabajo” ha de hacerse por el Equipo de Valoración de Incapacidades (EVI) del Instituto Nacional de la Seguridad Social (INSS), Órgano competente a estos efectos, para la emisión de los dictámenes médicos a efectos del reconocimiento de determinadas prestaciones Clases Pasivas. Puede ampliar la información en Internet en el Portal de Clases Pasivas en el enlace Esta respuesta es de carácter meramente informativo, y no vincula jurídicamente a la Administración. Atentamente, Servicio de Información escrita de Clases Pasivas. Texto de la consulta planteada: Buenos días , soy Trabajadora Social de la Comisión Tutelar de Adultos de Extremadura , quería plantear una consulta con respecto a las prestaciones de Orfandad, para poder solicitarlo a una persona con medidas judiciales de apoyo. - Es compatible solicitar P. Orfandad y PFHC ? su padre que es el causante estaba separado , la madre percibe P. viudedad. - El RDL 8/2015, de 30 de octubre , por el que se aprueba el texto refundido de la Ley General de la Seguridad Social , en su Disposición adicional 25 : asimilación de las personas que judicialmente hayan sido declaradas incapaces , entiende que están afectada por una discapacidad en grado igual o superior al 65% aquellas personas que judicialmente han sido declaradas incapaces. Afecta esta disposición a Clases Pasivas ?? se puede solicitar orfandad para un chico que tiene más de 25 años pero no tiene reconocida discapacidad aunque sí está incapacitado ?? Quedo pendiente de su respuesta. Un saludo . Por favor no responda a este correo. Este buzón no admite entradas. Si desea plantear alguna consulta sobre Clases Pasivas, hágalo a través del portal de clases pasivas (https://www.portalclasespasivas.gob.es//), cumplimentando el formulario que encontrará en el apartado Servicios, Buzón de consultas. Servicio de Información escrita Subdirección Gral. de Gestión de Clases Pasivas Dirección Gral. de Ordenación de la Seguridad Social Ministerio de Inclusión, Seguridad Social y Migraciones Avda. General Perón, 38 Edf. Master´s II 28020 Madrid','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO'and edp.apellido1='CABALLERO'and apellido2='PAEZ'),'2022-11-24','Denegada la Orfandad , al ser el padre de clases pasivas. De: INSS BADAJOZ SUPERVIVENCIA, BUZON >buzon.inss-badajoz.supervivencia@seg-social.es> Enviado el: lunes, 28 de noviembre de 2022 9:44 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: ORFANDAD DE EDUARDO CABALLERO PAEZ Buenos días, le informamos que con fecha de hoy hemos procedido a denegar la solicitud de orfandad de Eduardo Caballero Páez DNI 76252959R debido a que el causante de la prestación era pensionista de Clases Pasivas por lo tienen que presentar el modelo correspondiente ante este organismo. Próximamente recibirán la denegación en la dirección consignada en la solicitud. SALUDOS. SECCIÓN SUPERVIVENCIA DIRECCIÓN PROVINCIAL INSS BADAJOZ AVISO LEGAL, DE CONFIDENCIALIDAD Y RESPONSABILIDAD: El contenido de este mensaje de correo electrónico, incluidos los ficheros adjuntos, es confidencial y está protegido por el artículo 18.3 de la Constitución Española, que garantiza el secreto de las comunicaciones. Este correo está dirigido sólo a la persona o entidad a la que se remite y puede contener material confidencial y/o privilegiado. Cualquier revisión no autorizada, uso, divulgación o distribución está prohibida. Si usted no es el destinatario, por favor, póngase en contacto con el remitente por correo electrónico de respuesta y destruya todas las copias del mensaje original. Si usted es el destinatario, pero no desea recibir comunicaciones a través de este medio, por favor, notifiquelo al remitente inmediatamente.','2');
