insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-13','Ana: Conversación con Julia, Casa Misericordia: La madre de Sergio le ha dicho que le han llamado para citarle el día 17 en la Clínica Quirón en CC. ··········· Llamo a Julia, madre de Sergio (625 412 894): no sabe para qué es la cita. Al parecer cuando estaba en prisión, según su hijo, también tuvo alguna cita en la misma clínica. ······························································································································································································ Llega información del Banco Santander (un estracto), Sergio tiene un PLAN DE PENSIONES con saldo a 31/12/22 de 629,97 €, abierto en Colmenar Viejo (Madrid)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-12','Ana: correo de Isabel Cano: "Buenos días Ana mi móvil está un poco roto y necesito uno no me carga el cargador y ya he probado con varios cargadores y no carga así que necesito un móvil nuevo para cuando podría ser yo miro los precios y te digo vale gracias a ver si es posible un saludo espero tu respuesta" ··························· Más tarde habla con María, secc. ecca., le dice que que se le ha roto la pantalla del móvil y quiere uno nuevo, le ha dicho que Paula lo sabe. ························· Vuelve a enviar otro correo: "Me han dicho que lo de cargar lo tengo oxidado que necesito una limpieza y no tengo dinero y es caro y si es reparar la batería cuesta ciento y pico de euros" ··················· Más tarde otro con imagen de la pantalla de su móvil roto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2023-01-13','CONTACTO CON SU PADRE ( 619782212). Le informo de la forma de acceder a centro de rehabilitación , ellos ya conocen pq él ha pasado por Comunidades terapeúticas pero dura muy poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2023-01-13','Amalia : recibo informes del acompañamiento al ESM desde Futuex. Hola de nuevo, te cuento por aqui, sobre Francisco Casillas García: Desde el programa de apoyo social comunitario, realizamos nota para informar sobre la consulta de revisión en psiquiatría que tuvo Francisco el día pasado lunes, 9 de enero de 2023. Fue su primera consulta con la psiquiatra Virginia Gajardo (llevaba años sin ninguna revisión), la profesional consultó a Francisco su situación personal y médica. Además de corroborar los datos con las profesionales del programa, que le acompañamos a la consulta. Durante la entrevista analizó la situación de emergencia social en la que se encuentra (sin vivienda, sin medios para cocinar, para asearse…) por lo que decidió derivarle al CRR de Mérida, indicando en el informe que es un ingreso urgente por emergencia social. Francisco cree que desde diputación o la Junta le arreglarán su vivienda, pero lo único que han podido hacer del ayuntamiento es declarar su vivienda en ruinas y cabe la posibilidad de arreglarla con alguna subvención, pero solamente habilitándola como nave. Ante esta situación Francisco accede trasladarse al CRR (firmando la solicitud) hasta que pueda regresar a su domicilio. En archivo adjunto enviamos informe de seguimiento y la aceptación de la derivación a recursos residenciales comunitarios de Salud Mental (esta solicitud está firmada por Francisco y debe firmarse también por sus tutores legales). Una vez firmada nos piden que se envíe a la trabajadora social de Salud Mental (Esperanza Gallego). Hoy ha llamado también para indicar que necesitaria algún informe social, y que si se ha iniciado solicitud de dependencia, que es necesario al parecer también. Creemos que seria más cómodo, que hablaras directamente con ella, para el tema de los informes sociales,. Correo electrónico: esperanza.gallego@salud-juntaex.es En cuanto a tratamiento médico mantiene la misma pauta de inyectable trimestral y zyprexa de 15mg (0-0-1).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2023-01-13','Amalia : envio a la TS del Ap3 solicitud firmada para cambio de servicio , con la intencion de que pase a VT en la zona de San Roque.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-01-16','Ana: Correo de Paula a la sección ecca.: "como informé ayer Javier Agudo pasará a piso supervisado a partir del lunes día 16. Dentro del proceso de aumento de autonomía, hemos pensado que a partir de Febrero pueda estar autorizado a sacar él mismo el dinero mensual. Si hubiera cualquier incidencia os lo comunicaríamos para volver a acompañarle. Se le continuará apoyando en la planificación de gastos y administración de dinero, así como se custodiará el dinero de extras anuales. La cantidad mensual son 500 euros y el extra anual, en el que se incluyen unas vacaciones pensadas para abril son 1700 Euros"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2023-01-13','Ana: Correo de María, Aux. Adtvo. CTAEX: "ya esta solicitada la baja de los suministros de Valentina" ······························································································································································································ Correo de Ángel, A. Jurídico CTAEX, con copia a la Res. FEMAR: "Si, hablé con la policía loca de Logrosán y efectivamente, tras realizar visita a la vivienda, han comprobado que está ocupada, por una mujer y dos niños. Vamos a presentar la correspondiente denuncia ante la policía local para solicitar el desalojo de esas personas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-16','Ana: Solicito a Julia, Coord. Casa de la Misericordia, un certificado de ingreso en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-01-11','Ana: Correo de Mamen, TS Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te comento, la semana de la nochebuena entre el 23 y el 27 de diciembre tuvo varios consumos dentro de nuestro centro, el primero cuando lo confeso se hablo con él, se le echo una buena charla y no se produjo expulsión ya que prometió que no iba hacerlo más, pero el 27 por la tarde el monitor de turno se da cuenta que no puede casi ni hablar, y riéndose de todos y de todo, lo entra en el despacho para hablar y le confiesa que se ha fumado porro que le ha dado otro acogido, en esos momentos y debido a la aptitud tiene que ser expulsado. Con fecha de hoy le hemos vuelto a dar otra oportunidad y ha regresado al centro para continuar proceso. El día 1 de enero empezaba una localización permanente y no estaba aquí, además a venido la policía un par de veces a preguntar por él y se le ha explicado que ya no estaba aquí, voy ahora mismo a llamar ahora mismo al juzgado para informar que ha regresado. Le he preguntado si ha empezado a cobrar la PNC de invalidez y me ha dicho que no, informarme como va este tema si puedes y sabes algo. Te informo hoy de todo esto porque yo he estado de vacaciones desde el 27 de diciembre hasta ayer que me incorpore."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-01-13','Ana: Respuesta al correo del miércoles: "Gracias por informar. Tomo nota de todo. Mantenme informada, por favor. En cuanto a la PNC, le ha venido denegada… no mantienen la excepción que hacían antes con las personas incapacitadas, pero está en trámites una reforma legislativa para que se asimile a estos efectos los expedientes de Curatela Representativa. La semana que viene hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2023-01-16','Ana: Envío correo a Eva Álvarez, TS Plena Inclusión Montijo (trabajadorasocialco@plenainclusionmontijo.org): "Te adjunto el informe social de SSASB de su pueblo, es muy significativa la dinámica familiar así como la mala estructura de la misma. Adrián ha estado institucionalizado prácticamente toda su vida. Adjunto también nota evolutiva de psiquiatría, en relación a sus alteraciones conductuales y su hipersexualidad, así como la medicación pautada para ello. En cuanto a su formación, sólo cuenta con estudios primarios. NO tenemos informes ni certificados de estudio en el expediente. Si no me equivoco, de Asociación Vera sí os han facilitado los informes relativos al tiempo que ha residido allí. Aprovecho para solicitaros CERTIFICADO DE INGRESO EN EL PISO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2023-01-16','Ana: Envío correo a Toni-Futuex: "solicitaros que retoméis el contacto con la empresa de limpieza para que en cuanto sea posible procedan a la misma, ahora que Aitor no está tan cerca y seguramente pasará una temporada en su nueva ubicación. Sería bueno que Felisa comenzara a acudir y pernoctar de nuevo en su casa, en cuanto esté acondicionada para ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2023-01-16','Ana: Reenvío a Soraya Masa y Mariluz, U. PP.AA., el correo que remitió Sheila, CRR CC, con las incidencias ocurridas los días 5 y 6 de enero en una visita al CRR: "Te reenvío correo de Sheila, Directora Técnica del CRR de Cáceres, con las últimas incidencias protagonizadas por JUAN MARIO SAN ROMÁN BLÁZQUEZ, en una visita al CRR no organizada y ni coordinada previamente. La decisión de esta visita parece haber sido tomada de forma unilateral por el Psiquiatra de referencia en la UME del C. Sociosanitario de Plasencia. Con los hechos narrados, se evidencia que Juan Mario no está aún preparado para este tipo de salidas, pues desde el minuto 1 ha vuelto a consumir y a tener conductas como las que tenía con carácter previo al ingreso en UME. No sé si Mariluz estará al corriente de estos hechos, la pongo en copia por si acaso." ····················· Guardo el correo-e en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-10-22','SALIDA El 22/10/2022. Salida al centro comercial El Faro, de Badajoz. Entre las 10:30 y las 19:30. Monitor: Grupo Papirola. Transporte: Autobús Adaptado. Organiza: Grupo Papirola. Acompañantes: un auxiliar por usuario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2023-01-16','Ana: Envío a Julio, Aux. Adtvo. CTAEX, oficio + Alta de Terceros para remitir por SIREX al Serv. de Prestaciones Sociales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2023-01-16','Ana: El EXTRA ANUAL autorizado para este año es de 1.200 € ···································································· Llamada de Isabel: dice que se resbaló, se cayó y se golpeó con un radiador. Le han escayolado la mano derecha. ·········· Pregunta si se podrá comprar el móvil, está agobiada porque lo tiene roto. *Le indico que tiene que hablarlo con las profesionales del centro. Podrá adquirir uno con el extra anual de este año. ············ *Por otra parte dice que irá a Trujillo, alojándose en un hostal, del 6 al 10 de febrero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-01-16','Ana: correo de Leyre, TS de la Res. Ciudad Jardín de Cáceres (t.socialcanovas@grupociudadjardin.com): "Acabo de hablar con una sobrina de Isabel, se llama Lourdes, su teléfono es 691795544, me comunica que la vivienda de Isabel y su hermana, está siendo ocupada por unos okupas, que han debido de cambiar las cerraduras, se lo ha comunicado una vecina, que ha visto el trasiego de gente, Dime como se debe de proceder, o si te puedo llamar." ··················· Lo reenvío a Ángel, Asesor Jurídico CTAEX. ······················ Respuesta de Ángel, A. Jurídico: "...Procedemos igual que el otro caso, hablo con la policía local de Cáceres para que realicen una visita a la vivienda"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2023-01-16','Ana: Ángel, A. Jurídico CTAEX, confirma que ha solicitado el CDO. DE ÚLTIMAS VOLUNTADES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2023-01-16','Ana: Llamada de Felipe, Educador CAM Francisco Pizarro, Trujillo (61081): Aitor ha acudido hoy a centro a "visitarlos", lo han visto con "muy mala pinta", sólo quería ponerlo en nuestro conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2023-01-16','Ana: Envío a Emilio José, Unida de Acceso y Valoración de Dependencia (emiliojose.frias@salud-juntaex.es) el INFORME DE SALUD para anexar a la solicitud. ·········· Lo guardo también en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2023-01-17','Ana: Reenvío a los A. Jurídicos, CERTIFICADO DE INGRESO EN CENTRO, remitido por la Casa de la Misericordia, para que lo envíen al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2023-01-17','Ana: Envío correo a Toni-Futuex: "Quería preguntaros si habéis llegado a saber algo o a localizar a ANONIA BERNARDO PIRIS, pues por el EQUIPO DE SALUD MENTAL, según me confirma Ana Benavente, TS, no ha llegado a pasar y no hemos vuelto a saber nada de ella. Ya me dices cuando puedas." ··································· Respuesta de Toni: "Pues estuvo la compi ayer el jueves pasado, y nada la verdad que no conseguimos nada. Fue a salud mental y le dijeron que alli no habia ido, y que Ana B. no estaba. Luego en CRR pues lo que ya me habias comentado tu, que estuvo el dia anterior y en piso supervisado también y que dijo que ella tenia dinero y que iba a un hostal, desde crr se le ofreció ayuda para busqueda de hostal, pero ella declinó dijo que ya tenia uno cerca de donde tenia el piso, (por la plaza) pero no sabemos la dirección, ni el nombre. Desde crr y piso supervisado también se le intentó ayudar para que acudiera a la policia para denunciar almenos lo referente al móvil, pero no acepto ayuda alguna. Indicaron desde crr que si volvian a saber de ella que avisarian, que al no ser usuaria ya, no podian hacer mucho mas... no se si a ti te habran comunicado algo desde crr. Aique ahora mismo no sabemos exactamente donde está."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2022-12-23','EXITUS Fallece el 23/12/2022 en el Hospital San Pedro de Alcántara de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2023-01-03','EXITUS Acaecido el 03/01/2022. Informa de ello el Ctro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2023-01-16','Maite: la trabajadoa social del Ayto de Zafra, Olga,llamó para comunicar que JOsé María estaba en urgencias en el hospital pq se habia caído. A lo largo de la mañana he estado en contacto con ella y Carolina, trabajadora social del hospital. Carolina ha visto la posibilidad de solicitar plaza sociosanitaria pero sólo daría puntuación para T4 y ha comprobado que no hay plazas libres. Él no quiere ingresar en nigún sitio. Hablé con élla la pñosibildiad de solicitar desde el hospital ingreso involuntario ( tb lo habia hehco Olga), pero tras hablar con el médico deciden darle el alta pq no hay critetio clínico para ingresarlo. Olga ha enviado a fiscalía informe para comunicar la situación. Nos ha remitido este informe, y tb un escrito de la empresa de ayuda a domicilio. Va a pedir al médico de familia informe para que junto a los otros lo remitamos desde la CTAEX al juzgado y solicitar el ingreso involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2023-01-17','Ana: Correo de Ángel, A. Jurídico CTAEX a Alberto y a mí: "Nos han comunicado que en la vivienda de María Jiménez Picón, que tiene junto con la hermana, Isabel, en C/. Marqués de Oquendo, 40, hay okupas. Han cambiado las cerraduras. La curatelada reside en el Centros de Mayores Ciudad Jardín Cánovas. Vamos a interponer la denuncia ante policía local de Cáceres y a iniciar demanda de deshaucio. Mientras tanto, podemos proceder al corte de los suministros, debido a que la curatelada no va a salir del centro residencial y volver a la vivienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2023-01-17','TERESA email crps Javi esta ahora más tranquilo, la semana pasado se comprometio a acudir a las actividades, porque es muy inconstante y esta semana, ayer y hoy ha cumplido. Muy centrado en que tiene que gestionar él su dinero y va a solicitar la reincapacitación. La semana pasada estaba dandole vueltas a crear una empresa de cuidados de perros. Ya le hemos centrado y vamos a proponerle ir de voluntario a un refugio de perros que hay en Los Santos de Maimona, estamos realizando las gestiones, para luego proponerselo. ESta tomando mucho café, se le nota mucho, esta mañana casi no parpadeaba; espero que no esté tomando nada mas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2023-01-17','TERESA ME SOLICITA ANGEL CONSENTIMIENTO FIRMADO POR PABLO PARA LA VENTA DEL PORCENTAGE DE LA VIVIEDA QUE TIENE CON SUS HERMANOS PABLO AHORA MISMO NO ESTA ESTABLE, SE HA ESCAPADO DEL CENTRO Y HA VUELTO A BEBER, QUIERE IRSE A SU CASA, ESTAN INTENTANDO RETENERLO Y CONVENCERLO QUE ALLI NO PUEDE VIVIR DEJO PENDIENTE EL TEMA DE LA VENTA DE LA CASA HA STA QUE PABLO SE ENCUENTRA MAS ESTABLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-17','Ana: Hablo con Icíar, dará de baja los suministros de la vivienda. ···························· Llamo varias veces a Control de Pensiones del INSS (927 62 00 49 / 927 62 00 65): No obtengo respuesta. ······························································································································································································· Envío mail a Ángel y Maite, CTAEX: "...Os traslado una consulta de Cruz Merino, TS de la Mancomunidad Tajo-Salor, relativa a JUAN GREGORIO LOZANO VALLE: “…te comento que en estos días de Navidades ha vuelto el hijo al pueblo. Tienen intención de quedarse en Alcántara porque ha ido al ayto a empadronarse. Para realizar este trámite, necesita la autorización firmada del propietario de la casa, es decir, de su padre. ¿Cómo se actúa en estos casos? Si actualmente tiene una medida de apoyo, ¿Quién le autorizaría a su hijo Juan Mari para que se empadronase? ¿Debe solicitar a la Comisión dicha autorización?.” Yo ya he hablado con ella y le he dicho que, en principio, el empadronamiento tiene que autorizarse desde aquí, en representación de su padre. Pero claro, supongo que a su hijo le corresponde por herencia la legítima (la propiedad es de Juan Gregorio al 50% y creo que el otro 50% era de su difunta esposa). No sé si esto modifica automáticamente la situación..." ·································································································································································································· Envío respuesta a Cruz Merino, TS de Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es): "Y con respecto al empadronamiento del hijo, pues en teoría, según dice mi compañero Ángel, y de acuerdo a la nueva legislación, sería el propio Juan Gregorio quién tendría que decidir si autorizar o no a que se empadrone, antes de firmar el documento el Representante Legal (pues hay que tener muy en cuenta los derechos, voluntad y preferencias de las personas) , pero, tal y como le he dicho, Juan Gregorio no se encuentra en condiciones de tomar esa decisión dada la demencia que presenta. Por lo pronto desde aquí no se va a firmar dicha autorización."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MAURO'and apellido2='PEREZ'),'2023-01-16','Maite: he hablado con Toñi, trabajadora social del CAMP de Don Benito. Hemos decidido no continuar con el acompañamiento de Isabel en el hospital, ya que desde allí nos han dicho que por el momento no es necesario. En caso de cambiar la situación, volveriamos a contratarlo. También la han informado de que las auxilares no cumplen el horario establecido, algunos días están menos horas de las acordadas....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2023-01-17','Ana: Correo de Mamen, TS Cáritas (mcsanchez.cdcoriacaceres@caritas.es): "Te informo que con fecha de hoy nos han comunicado desde ECA que Miguel Ángel ingresa en la comunidad terapéutica LA GARROVILLA el próximo día 25 de enero."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2023-01-17','TERESA He estado hablando con M. Antonia y le he explicado las consecuencias si se traslada al Hospital de Santiago de Zafra. Ya sabe que si se va ahora puede tardar años en ingresar en Plena Inclusión o que nunca se pueda ir. También el viernes pasado informé a su prima M. Carmen y le quedé claro que si alguna vez, estando en el Hospital de Santiago quisiera irse a Plena Inclusión de inmediato, no lo va a poder hacer porque pasaría estar de las últimas en la lista. Lo ha entendido perfectamente. He intentado hacerle entender que quizás lo mejor es esperar aquí….que está la primera en la lista para entrar en Plena Inclusión pero ella no reacciona. Esta misma mañana lo ha consultado con su prima. Ha decidido solicitar traslado (a pesar de todo) por lo que cuando tú puedas lo inicias. Ella ya tiene en mente irse cuanto antes. Su prioridad es irse a Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2023-01-17','Ana: envío respuesta a Cruz Merino, TS de Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es): "...el justificantes del acompañamiento que mencionas (Declaración Jurada, supongo) no ha llegado, ni venía en el correo con el DNI ni lo han recibido los compañeros de la sección económica. Si no te importa, envíalo cuando puedas al ctutelar@salud-juntaex.es para que puedan proceder al abono del mismo. En relación a la solicitud de valoración de dependencia, tal y como planteas, solicita por favor el Informe de Salud a su MAP y nos envías la solicitud cumplimentada para recabar la firma del Representante Legal. Si necesitas los datos de éste dímelo y te los paso, o deja si quieres esa parte sin cumplimentar en el modelo autorrellenable y ya lo termino yo, como prefieras. Después, para agilizar, se podría registrar desde aquí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GREGORIO'and edp.apellido1='LOZANO'and apellido2='VALLE'),'2023-01-17','Ana: envío respuesta a Cruz Merino, TS de Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es): "Y con respecto al empadronamiento del hijo, pues en teoría, según dice mi compañero Ángel, y de acuerdo a la nueva legislación, sería el propio Juan Gregorio quién tendría que decidir si autorizar o no a que se empadrone, antes de firmar el documento el Representante Legal (pues hay que tener muy en cuenta los derechos, voluntad y preferencias de las personas) , pero, tal y como le he dicho, Juan Gregorio no se encuentra en condiciones de tomar esa decisión dada la demencia que presenta. Por lo pronto desde aquí no se va a firmar dicha autorización."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2023-01-17','Ana: Acuerdo con Cruz Merino, TS de Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es) solicitar la revisión del Grado de Dependencia. Ya está prácticamente ciega y cree que ya dará más grado. ····· Me enviará solicitud e Informe de Salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2023-01-17','Ana: Correo de Leire Sanz Gay, TS - Centro de Mayores Ciudad Jardín Cánovas (t.socialcanovas@grupociudadjardin.com / 927 223 221 / 927 214 696), adjuntando Informe del Servicio de Traumatología. Ha sufrido una caída y tiene fractura en la cadera derecha. *No la pueden operar, por lo que le dieron el alta y regresó a la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2023-01-18','Maite: la semana pasada hablé con Marta. Quiere ir a vivir a Cabeza del Buey a la casa de su abuela con su hermana Estefanía. Está teniendo problemas con su novio y ya no está bien en Peñalsordo. El lunes 16 de enero contacté con su hermana. No estaba muy receptiva ante la idea de compartir la vivienda con Marta. Quedamos en que hablaría con su tío para comentárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2023-01-18','Ana: Paso a Alberto y Óscar, presupuesto para cambio de puerta de entrada a la vivienda, con mi ok al mismo, pues la puerta está rota, le entra frío y agua cuando llueve. ··························· *Se aprueba el mismo, así como un extra de 130€ que no nos había pasado en Navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2023-01-18','-Amalia: Gestiono traslado desde CSS Meria a R. M . R. Ibarra de Villafranca. TS de la R.M.: mcarmen.garciabraza@salud-juntaex.es Le he enviado toda la documentación del usuario : sentencia , decesos , pensiones... He solicitado a sección eco Nº Cta. donde cargar el copago y a la R.M. información para hacer éste y los gastos de bolsillo. Pido a las TS de los centros que se coordinen entre ellas para fecha , hora ... Así como que me indiquen si quieren que vaya una delegada acompañandolo y si se irá en taxi o transporte del CSS .','2');
