insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-01-18','Maite: Juan José entró en la residencia de Apoyo Limitado de INCLUSIVES Villanueva de la Serena, el 5 de octubre de 2022. Se ha adaptado muy bien al centro. NO hay incidencias.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2023-01-18','Ana: Envío correo a Teresa y Julio, CTAEX: "A JUAN JOSÉ GLEZ. CASARES, le concedieron plaza en la Residencia de Apoyo Limitado y Centro Ocupacional en la Entidad INCLUSIVES de VILLANUEVA DE LA SERENA, donde reside desde hace ya unos meses. Se está adaptando bien y no ha habido ninguna incidencia hasta el momento. Así pues: - Tere! Puedes continuar con el seguimiento - Julio! Cuando puedas procede al cambio de domicilio en la base de datos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-10-05','Maite: Juan José ha ingresado en la residencia de Apoyo Limitado de INCLUSIVES de Villanueva de la Serena.','2');
